INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604009F$$, $$AFWERX$$, $$rdte_af_ba4$$, $$afwerx$$, 2026, 18499000, 97250000, 62580000, NULL, $${"ba_raw": "6.4", "source": "af_r1_fy26", "original_pe": "0604009F"}$$::jsonb, $$The AFWERX mission is to accelerate agile and affordable capability transitions by teaming innovative technology developers with Airmen and Guardian talent. AFWERX leverages Spark (the Airmen and Guardian talent base), Ventures (the dual use expanded technology base), and Prime (technology transitions) to scale and accelerate capability. Funding in this project supports AFWERX research and development, innovation hubs and infrastructure, information technology, public affairs, and marketing. SBIR/STTR execution also benefits from Operations & Support funding. The Spark mission is to inspire and enable Airmen and Guardians to harness their collective talent and ingenuity. Spark connects innovators using virtual collaboration, immersive training, and networking opportunities to inspire ideas and cultivate a more lethal force. By connecting operators closer to acquisition processes, Spark provides both a voice and a conduit to accelerate powerful ideas into game-changing operational realities. This focus helps guide technologies through transition across the valley from idea to scaled and sustained capability. The AFWERX Program reduces risk in emerging technology markets by partnering with industries through Prime investments and providing access to Government analysis, testing and certification capabilities. Prime investments focus on Government-Industry partnerships to influence and militarize emerging commercial capabilities to ensure US competitive advantage in key technology areas. This program element may include necessary civilian pay expenses required to manage, execute, and deliver Technology Transfer capabilities. The use of such programs funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY 2026, $7.878 million is budgeted in this program for 37 direct Full-Time Equivalent (FTE) civilians. This program element may include necessary expenses to support the operation and maintenance of facilities to manage, execute, and deliver science and technology capabilities. Beginning in FY 2024, funding for Program 0604317F, Technology Transfer, Project 646030, AFWERX, and Project 64317A, Technology Transfer Add, were transferred to Program 0604009F, AFWERX Prime, Project 640856 AFWERX Operations and Support per Congressional direction. This effort is in Budget Activity 4, Advanced Component Development and Prototypes (ACD&P), because efforts are necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                          Date: June 2025 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 4: Advanced PE 0604009F / AFWERX Component Development & Prototypes (ACD&P)$$, NULL, 0, 0, 0, NULL, NULL, 41, $$FY26 Air Force Research and Development Test and Evaluation Vol II.pdf$$, NULL, FALSE, 62123000, 73499000, 3589000, 3589000, 0, 3589000, 0, $$AFWERX helps the Department of the Air Force (DAF) address warfighter needs by leveraging flexible contracting pathways to accelerate the transition of disruptive commercial dual-use technologies into decisive, war-winning capabilities. AFWERX funds risk reduction efforts for technology agnostic capabilities and provides avenues for the DAF to leverage private capital funds as a resource multiplier, strengthen the domestic defense industrial base, and accelerate commercial preference. Funding for this program supports administrative and oversight functions for AFWERX and enables effective execution of the SBIR/STTR program. These functions include funding for core operations and support, research and development, front door innovation hubs, information technology infrastructure, outreach, and marketing. In FY 2027, this program has 0 FTE civilians. In order to manage, execute, and deliver innovative technology capabilities, this program element may include necessary expenses to support the operation and maintenance of facilities, as well as expenses related to travel, supplies, IT hardware, software and support, etc. This effort is in Budget Activity 4, Advanced Component Development and Prototypes (ACD&P), because efforts are necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                          Date: April 2026 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 4: Advanced PE 0604009F / AFWERX Component Development & Prototypes (ACD&P)$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume II.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604010F$$, $$Next Generation Adaptive Propulsion$$, $$rdte_af_ba4$$, $$aflcmc$$, 2026, 330270000, 573832000, 507337000, NULL, $${"ba_raw": "6.4", "source": "af_r1_fy26", "original_pe": "0604010F"}$$::jsonb, $$The Next Generation Adaptive Propulsion (NGAP) program builds upon advanced materials, technologies and manufacturing processes matured under the Adaptive Engine Transition Program (which ended in FY24) to enhance adaptive propulsion system performance and size scalability key to enabling future aircraft capabilities. Embedded adaptive propulsion systems combine the fuel efficiency of high-bypass turbofan engines used by commercial airlines with the performance demanded of military fighter engines with augmenters. Increased fuel efficiency reduces energy demand and aerial tanker dependency while increasing platform range and or time on station. During peacetime, these benefits translate to reduced aerial tanker dependency during exercises and a choice between increased aircrew readiness or cost savings due to the less fuel needed. NGAP prototyping will validate the performance and maturity of its enabling advanced technologies, platform agnostic engine architectures and designs, and manufacturing processes through prototype testing. NGAP will also drive digital transformation of the propulsion industrial base to reduce future integration risks while shortening development timelines. Prior to FY 2024, the NGAP program was reported in PE 0604004F, Advanced Engine Development, Project 643608, Advanced Engine Development. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605829F, 0605831F, 0605833F, or 0605898F. In FY 2024 $5.669 million was expended for civilian pay expenses in this program element, and in FY 2025 $7.401 million is forecasted for civilian pay expenses in this program element. This effort is in Budget Activity 4, Advanced Component Development and Prototypes (ACD&P), because efforts are necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                          Date: June 2025 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 4: Advanced PE 0604010F / Next Generation Adaptive Propulsion Component Development & Prototypes (ACD&P)$$, NULL, 905700000, 865000000, 303300000, NULL, NULL, 42, $$FY26 Air Force Research and Development Test and Evaluation Vol II.pdf$$, NULL, FALSE, 489737000, 326010000, 513681000, 513681000, 0, 513681000, 304900000, $$The Next Generation Adaptive Propulsion (NGAP) program builds upon advanced materials, technologies and manufacturing processes matured under the Adaptive Engine Transition Program (which ended in FY2024) to enhance adaptive propulsion system performance and size scalability key to enabling future aircraft capabilities. Embedded adaptive propulsion systems combine the fuel efficiency of high-bypass turbofan engines used by commercial airlines with the performance demanded of military fighter engines with augmenters. Increased fuel efficiency reduces energy demand and aerial tanker dependency while increasing platform range and or time on station. During peacetime, these benefits translate to reduced aerial tanker dependency during exercises and a choice between increased aircrew readiness or cost savings due to the less fuel needed. NGAP prototyping will validate the performance and maturity of its enabling advanced technologies, platform agnostic engine architectures and designs, and manufacturing processes through prototype testing. NGAP also drives digital transformation of the propulsion industrial base to reduce future integration risks while shortening development timelines. Program RDT&E funding may be utilized to implement innovation insertion, capability insertion, software increments, spiral upgrades, modular component swaps, and other insertions consistent with Modular Open System Architecture. Program RDT&E funding may be utilized to design, develop, integrate, and test weapon system and/or component level open architectures. Program RDT&E funding may be utilized to fund the concept refinement, design, development, integration, and testing of interdependent technologies and common architectures that underpin weapon system and portfolio-wide mission outcomes. This program element included all necessary expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 0605829F, 0605831F, 0605833F, and 0605898F This effort is in Budget Activity 4, Advanced Component Development and Prototypes (ACD&P), because efforts are necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                          Date: April 2026 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 4: Advanced PE 0604010F / Next Generation Adaptive Propulsion Component Development & Prototypes (ACD&P)$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume II.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604011D8Z$$, $$Next Generation Information Communications Technology (5G)$$, $$rdte_dw_ba7$$, $$dw_osd$$, 2026, 41815000, 120644000, 91827000, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "dw", "page_num": 71, "original_pe": "0604011D8Z", "page_header": "Defense-Wide", "fy26_v182_disc_K": 22122, "fy26_v182_supp_K": 148620, "fy26_v182_total_K": 170742, "fy26_v182_note_name": "5G CFT", "fy26_v182_source_file": "RDTE_OSW_PB_2027.txt", "fy26_v182_source_line": 46374}$$::jsonb, $$Fifth generation (5G) wireless networking is critical for U.S. defense modernization and modern warfare. The DoD is accelerating 5G adoption to operate effectively anywhere, anytime, even in contested environments, ensuring U.S. military superiority and national security. The Secretary of Defense 5G Wireless Networking Cross-Functional Team (5G CFT), mandated by Congress, accelerates 5G adoption across the DoD. The 5G CFT executes DoD's 5G policy, research, and acquisition activities, supporting the National Defense Strategy's objective to preserve command, control, and communications in a fast-paced battlefield. The DoD is leveraging 5G for military applications, from improving coverage on installations to deploying tactical communications in austere environments. The DoD will continue developing advanced 5G network architectures, implementing cybersecurity and zero trust enhancements, and investing in open radio access network (RAN) prototyping to inform secure 6G system designs, expanding RAN intelligent controller capabilities.$$, NULL, 8960000, 8162000, 21074000, NULL, NULL, 220, $$RDTE_OSD_PB_2026.pdf$$, $$OSD$$, FALSE, 10292000, 170742000, 5893000, 5893000, NULL, 5893000, 21517000, $$Fifth-generation (5G) wireless networking is critical for U.S. national security and Joint Force modernization. The DoW is increasing warfighter lethality by accelerating the adoption of advanced, scalable, and resilient 5G networking and weapons systems capabilities, ensuring Joint operational effectiveness in contested electromagnetic operational environments. The Secretary of War’s 5G Wireless Networking Cross-Functional Team (5G CFT), mandated by Congress, accelerates 5G adoption across the DoW. The 5G CFT coordinates DoW 5G policy, research, and acquisition activities, supporting National Defense Strategy objectives to defend the U.S. homeland and deter China through strength. The DoW is implementing 5G for military applications, from improving coverage on installations to deploying tactical communications capabilities in austere environments. The DoW will continue developing advanced 5G network architectures, implementing cybersecurity and zero trust enhancements, and expanding RAN intelligent controller capabilities. The military departments (MILDEPs) will continue to budget and execute investments into 5G cellular and wireless technologies within their specific program elements. The FY 2026 spend plan amount for 5G CFT includes $22,122 thousand of discretionary and $148,620 thousand of mandatory (reconciliation) for a total of $170,742 thousand. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Office of the Secretary Of Defense                                            Date: April 2026 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 7:         PE 0604011D8Z / Next Generation Information Communications Technology (5G) Operational Systems Development$$, $$Budget J-Books/FY27/DW/RDTE_OSW_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604011K$$, $$Next Generation Information Communications Technology (5G)$$, $$rdte_dw_ba7$$, $$dw_disa$$, 2026, 0, 0, 1500000, NULL, $${"act": "07", "ba_raw": "6.7", "source": "r1_fy26", "service": "dw", "page_num": 79, "original_pe": "0604011K", "page_header": "Defense-Wide"}$$::jsonb, $$5G is the 5th generation mobile network. 5G wireless technology is meant to deliver higher multi-Gbps peak data speeds, ultra-low latency, more reliability, massive network capacity, increased availability, and a more uniform user experience to more users. 5G is a unified, more capable air interface. It has been designed with an extended capacity empower new deployment models and deliver new services. With high speeds, superior reliability and negligible latency, 5G will expand the mobile ecosystem into new realms. NDAA FY21 § 224 and FY23 § 221 & 234 mandates Defense Information Systems Agency (DISA) to develop a capability for continuous independent monitoring of non- commercial government-transiting packet streams for 5G data on frequencies assigned to the Department to validate the availability, confidentiality, and integrity of the Department’s communications systems. Development of Training Materials are required for DoD 5G networks not tied to the Defense Information Systems Network (DISN).$$, NULL, NULL, NULL, NULL, NULL, NULL, 221, $$RDTE_DISA_PB_2026.pdf$$, $$DISA$$, FALSE, 1500000, 0, NULL, NULL, NULL, NULL, NULL, $$5G is the 5th generation mobile network. 5G wireless technology is meant to deliver higher multi-Gbps peak data speeds, ultra-low latency, more reliability, massive network capacity, increased availability, and a more uniform user experience to more users. 5G is a unified, more capable air interface. It has been designed with an extended capacity empower new deployment models and deliver new services. With high speeds, superior reliability and negligible latency, 5G will expand the mobile ecosystem into new realms. NDAA FY21 § 224 and FY23 § 221 & 234 mandates Defense Information Systems Agency (DISA) to develop a capability for continuous independent monitoring of non- commercial government-transiting packet streams for 5G data on frequencies assigned to the Department to validate the availability, confidentiality, and integrity of the Department’s communications systems. Development of Training Materials are required for DoW 5G networks not tied to the Defense Information Systems Network (DISN).$$, $$Budget J-Books/FY27/Remaining/RDTE_DISA_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604014N$$, $$F/A-18 Infrared Search and Track (IRST)$$, $$rdte_navy_ba4$$, $$peo_tacair$$, 2026, 0, 31220000, 8630000, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "navy", "page_num": 30, "original_pe": "0604014N", "page_header": "Department of the Navy"}$$::jsonb, $$The AN/ASG-34A(V)1 F/A-18E/F Infrared Search and Track (IRST) system is a long-wave infrared sensor that provides a passive, out-of-band, alternate fire control system capable of detecting, tracking and engaging airborne targets, at long range, in a heavy electronic attack or radar-denied environment. IRST Block II is the primary out-of-band fire-control system for the F/A-18E/F, critical to organic passive air-to-air kill-chains required to compete with peer adversaries. Enables F/A-18E/F lethality by providing a passive means to detect, track, and target aircraft in highly contested environments in support of the objectives outlined in the National Defense Strategy. IRST enhances survivability by providing a fire-control solution without the need to radiate in the RF spectrum. The IRST system can autonomously, or in combination with other sensors, support the guidance of beyond-visual-range missiles including AIM-120C/D and AIM-9X Block II. The F/A-18E/F IRST system is an evolutionary Navy acquisition program with Block I and Block II capabilities. The USN is committed to further development of this component of the passive kill chain. This budget request supports Block II development and testing of a redesigned Infrared Receiver (IRR) and processor, enabling full Capabilities Development Document (CDD) capability over a larger field of regard. This budget request also supports development and testing of a redesigned Read-Out Integrated Circuit (ROIC). The ROIC vendor is not able to sustain production of the current design. The redesign will yield a more reliable configuration with potential production cost avoidances due to less usage of higher cost materials. IRST was previously funded under Program Element 0204136N F/A-18 Squadrons and has been transferred to Program Element 0604014N F/A-18 Infrared Search and Track.$$, NULL, 0, 0, 0, NULL, NULL, 75, $$RDTEN_BA4_Book.pdf$$, NULL, FALSE, 8556000, 0, 0, 0, NULL, 0, 0, $$The AN/ASG-34A(V)1 F/A-18E/F Infrared Search and Track (IRST) system is a long-wave infrared sensor that provides a passive, out-of-band, alternate fire control system capable of detecting, tracking and engaging airborne targets, at long range, in a heavy electronic attack or radar-denied environment. IRST Block II is the primary out-of-band fire-control system for the F/A-18E/F, critical to organic passive air-to-air kill-chains required to compete with peer adversaries. Enables F/A-18E/F lethality by providing a passive means to detect, track, and target aircraft in highly contested environments in support of the objectives outlined in the National Defense Strategy. IRST enhances survivability by providing a fire-control solution without the need to radiate in the RF spectrum. The IRST system can autonomously, or in combination with other sensors, support the guidance of beyond-visual-range missiles including AIM-120C/D and AIM-9X Block II. The F/A-18E/F IRST system is an evolutionary Navy acquisition program with Block I and Block II capabilities. The USN is committed to further development of this component of the passive kill chain. This budget request supports Block II development and testing of a redesigned Infrared Receiver (IRR) and processor, enabling full Capabilities Development Document (CDD) capability over a larger field of regard. This budget request also supports development and testing of a redesigned Read-Out Integrated Circuit (ROIC). The ROIC vendor is not able to sustain production of the current design. The redesign will yield a more reliable configuration with potential production cost avoidances due to less usage of higher cost materials. FY2025 was the last year of funding due to completion of development efforts for the IRST program. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                         Date: April 2026 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 4: Advanced      PE 0604014N / F/A-18 Infrared Search and Track (IRST) Component Development & Prototypes (ACD&P)$$, $$Budget J-Books/FY27/Navy/RDTEN_BA4_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$P_1810_L053$$, $$Minesweeping System Replacement$$, $$proc_navy_1810_ba2$$, $$navsea$$, 2026, 26648000, 37652000, 26644000, NULL, $${"page": 97, "ba_num": "02", "source": "p1_fy26", "ba_name": "Communications and electronics equipment", "line_no": "53", "service": "navy", "fy24_qty": null, "fy25_qty": null, "fy27_v25": {"ba": "02", "appr": "OPN", "title": "P-1 Line 49", "applied_at": "2026-05-09", "fy27_ooc_K": 0, "source_pdf": "Budget J-Books/FY27/Navy/OPN_BA{1..5-8}_Book.pdf", "fy27_base_K": 33932, "p1_line_num": 49, "fy27_total_K": 33932}, "appr_code": "1810", "appr_name": "Other Procurement, Navy", "fy26_v179": {"disc_K": 26648, "li_num": 49, "source": "p40_fy26_v179", "supp_K": 0, "source_pdf": "uploads/Budget J-Books/FY27/Navy/OPN_BA2_Book.txt"}, "fy26t_qty": null, "fy26d_cost": 26648000, "fy26r_cost": 0, "ident_code": "B"}$$::jsonb, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, FALSE, 16808000, 16426000, 33932000, 33932000, 0, 33932000, NULL, NULL, $$Budget J-Books/FY27/Navy/OPN_BA2_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604015F$$, $$Long Range Strike - Bomber$$, $$rdte_af_ba4$$, $$afrco$$, 2026, 4739145000, 2877844000, 2654073000, NULL, $${"ba_raw": "6.4", "source": "af_r1_fy26", "original_pe": "0604015F"}$$::jsonb, $$This program is reported in accordance with Title 10, United States Code, Section 119(a)(1) in the Special Access Program Annual Report to Congress. Program overview provided below. The Long Range Strike - Bomber (B-21 Raider) is crucial to the nuclear modernization plan, forming the backbone of the Nation's future bomber force, providing both conventional and nuclear capability. The B-21 platform provides range, access, and payload to go anywhere needed, with the weapons required to deter and win our nation's wars. Its open system architecture will enable rapid integration of future capabilities, keeping the platform relevant and effective as the threat environment evolves. The Air Force requires a minimum of 100 B-21s as part of the long-term bomber force. The Engineering and Manufacturing Development (EMD) contract was awarded in 2015, followed by a Critical Design Review (CDR) completed in 2018. Test aircraft are executing the B-21 flight test campaign and an approved Milestone C decision with all statutory and regulatory documentation was completed in 2023. Subsequently, the first two production lots have been awarded. B-21 aircraft will be delivered to operational bases in the mid-2020s. The FY2026 request for the Long Range Strike - Bomber (B-21 Raider) includes 2,347.225 million of discretionary and 2,391.920 million of mandatory (reconciliation) for a total of 4,739.145 million. The mandatory funds expansion of capacity of B-21. Further information for this reconciliation request is provided in Section 20008 (Nuclear) of the Reconciliation Exhibit. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. This effort is in Budget Activity 4, Advanced Component Development and Prototypes (ACD&P), because efforts are necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                      Date: June 2025 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 4: Advanced PE 0604015F / Long Range Strike - Bomber Component Development & Prototypes (ACD&P)$$, NULL, 2291100000, 1677221000, 764925000, NULL, NULL, 43, $$FY26 Air Force Research and Development Test and Evaluation Vol II.pdf$$, NULL, FALSE, 2565533000, 2729511000, 2862677000, 2862677000, 0, 2862677000, 735771000, $$This program is reported in accordance with Title 10, United States Code, Section 119(a)(1) in the Special Access Program Annual Report to Congress. Program overview provided below. The Long Range Strike - Bomber (B-21 Raider) is crucial to the nuclear modernization plan, forming the backbone of the Nation's future bomber force, providing both conventional and nuclear capability. The B-21 platform provides range, access, and payload to go anywhere needed, with the weapons required to deter and win our nation's wars. Its open system architecture will enable rapid integration of future capabilities, keeping the platform relevant and effective as the threat environment evolves. The Air Force requires a minimum of 100 B-21s as part of the long-term bomber force. The Engineering and Manufacturing Development (EMD) contract was awarded in 2015, followed by a Critical Design Review (CDR) completed in 2018. Test aircraft are executing the B-21 flight test campaign and an approved Milestone C decision with all statutory and regulatory documentation was completed in 2023. The B-21 program is on track to deliver aircraft at Ellsworth AFB in 2027. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. This effort is in Budget Activity 4, Advanced Component Development and Prototypes (ACD&P), because efforts are necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment.$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume II.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604016D8Z$$, $$Department of Defense Corrosion Program$$, $$rdte_dw_ba4$$, $$dw$$, 2026, 2545000, 5113000, 2637000, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "dw", "page_num": 71, "original_pe": "0604016D8Z", "page_header": "Defense-Wide"}$$::jsonb, $$The DoD RDT&E corrosion prevention program, as defined in Public Law 107-314 in section 2228 of title 10 United States Code (section 2228(d)(2)), is the mechanism to change DoD’s reactive approach of corrective corrosion maintenance to a proactive approach to improve weapon system corrosion prevention reliability and maintainability through technology. The strategic goal of the DoD Corrosion Prevention Program is to demonstrate the ability to improve weapon system readiness through the implementation of targeted and effective material and nonmaterial solutions that reduce the corrosion impacts on reliability, maintainability, and cost of DoD weapon systems and infrastructure. Historically, the program’s projects have shown an opportunity to achieve a 17:1 return-on-investment. From 2001-2023, the Government Accountability Office (GAO), the Congressional Budget Office and the DoD IG have conducted multiple weapon systems and infrastructure audits and continue to find corrosion is a significant impact on availability and cost. GAO’s Aviation Sustainment Quick Look reports (GAO-18-678, GAO-21-101SP, and GAO-23-106217) consistently show that 33% of the audited aviation systems report corrosion as a factor in reduced aviation Operational Availability (Ao) rates. The F-35 program is a current example of current corrosion prevention acquisition decisions and resulting corrosion maintenance issues of the continued flawed approach to weapon system corrosion prevention. In addition, corrosion continues to be a major factor in Materiel Availability (Am) of weapon systems. Examples of the corrosion impact on materiel availability include: (a) F-22 Reliability and Maintainability Maturation Program total funding requirement increased 100% ($664 million to $1.3 billion) to correct unplanned corrosion issues (GAO-12-447, GAO-14-425) (b) The Department of the Navy is deferring shipyard corrosion repairs, allocating a 6%+ cost growth factor for future corrosion repair work. (GAO-22-105032) These materiel availability examples illustrate the continued reactive sustainment engineering approach to corrosion prevention during the operational and sustainment phase of fielded weapon systems. Furthermore, the Maintenance Availability Data Warehouse (MADW) data, maintained on DoD online data repository, shows a $20 billion total corrosion maintenance cost trend across DoD weapon systems and infrastructure. In perspective, the allocated FY 2025 budget for the DoD Corrosion Program represents an investment equivalent to 0.013% of the $20 billion annual corrosion maintenance cost of weapon systems and infrastructure. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Office of the Secretary Of Defense                                               Date: June 2025 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 4:            PE 0604016D8Z / Department of Defense Corrosion Program Advanced Component Development & Prototypes (ACD&P)$$, NULL, 2876000, 2791000, 2860000, NULL, NULL, 101, $$RDTE_OSD_PB_2026.pdf$$, $$OSD$$, FALSE, 2600000, 2545000, 2675000, 2675000, 0, 2675000, 2916000, $$The Department of War (DoW) RDT&E corrosion prevention program, as defined in Public Law 107-314 in section 2228 of title 10 United States Code (section 2228(d) (2)), is a key mechanism to directly address the National Defense Strategy to sustain our lethal force and modernize capabilities within the organic industrial base. Additionally, the corrosion program addresses DoW’s annual cost in corrosion that exceeds $20 billion across the enterprise. The strategic goal of the DoW Corrosion Prevention Program is to improve weapon system readiness through the implementation of targeted and effective material and process solutions that reduce corrosion’s impacts on reliability, maintainability, and cost of maintaining DoW weapon systems and infrastructure. Historically, the program’s high TRL tech insertion projects have yielded an average a 17:1 return-on-investment. The focus on modern technology solutions for sustainment in weapon systems, equipment, and facilities corrosion challenges requires meaningful efforts to align policies and workforce development of field and depot level maintenance to truly effect change in reducing short- and long-term costs and increasing readiness and availability in direct support of the national defense strategy. Specifically, the DoW corrosion program looks at joint applications of DoW assets, as well as those with identified high costs/low availability to make impacts across the enterprise in partnership with the public and private sectors. It also addresses the challenges of a contested logistics environment. This overarching effort breaks down organizational barriers and applies meaningful and direct support to the warfighter across the enterprise. This program fully aligns with the ODASW (MR) Corrosion Policy and Oversight program strategy. The primary areas of focus in the execution of the strategy include: testing and transitioning corrosion technologies in conjunction with the military departments; funding for education and training of the organic workforce in corrosion- related certifications; development and coordination of department corrosion policies; development and adoption of industry standards; research of quantifiable data towards identification of corrosion costs; partnerships with trades, associations, and allied partner nations; coordination of enterprise level corrosion community; and a focus on long-term solvency of systems. Corrosion accounts for a 33% reduction of operational availability in aviation consistently in Government Accountability Office, Congressional Budget Office and DoW Inspector General audits. Several aviation programs (F35/F22) without primary consideration of corrosion impacts have shown to increase program cost requirements over 100% of the initial sustainment plan to rectify unplanned corrosion challenges ($664 million to $1.3 billion, GAO-12-447, GAO-14-425). Corrosion imposes more than $20 billion in annual maintenance costs on the Department of War, according to quantitative analyses from Congress, the GAO, and the Defense enterprise across weapon systems, equipment, and facilities. Despite this massive, well documented burden, the FY 2025-FY 2026 DoW Corrosion Program budget represents only 0.013% of that yearly cost, an investment level dramatically out of proportion to the scale of the problem. This underfunding persists even though Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Office of the Secretary Of Defense                                                  Date: April 2026 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 4:             PE 0604016D8Z / Department of Defense Corrosion Program Advanced Component Development & Prototypes (ACD&P) corrosion is a leading cause of weapon system non availability, directly degrading readiness and reducing the availability of critical platforms when they are needed most.$$, $$Budget J-Books/FY27/DW/RDTE_OSW_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604017A$$, $$Robotics Development$$, $$rdte_army_ba4$$, $$asa_alt$$, 2026, 35082000, 2912000, 13039000, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "army", "page_num": 14, "original_pe": "0604017A", "page_header": "Department of the Army"}$$::jsonb, $$FD9: Robotics Development improves the autonomous robotic systems portfolio by maturing cutting edge emergent commercial technology for transition, creating a virtual test capability to support evaluation, developmental test, system safety testing and operational force-on-force execution for Concept of Operations (CONOP) and Tactics, Techniques and Procedures (TTP) development, development of prototypes and to support infrastructure needs such as cloud-based tools for development and deployment of Autonomy and Artificial Intelligence (AI) Machine Learning (ML) software and tools to support automated testing in a Development, Security and Operations (DEVSECOPS) process. FD9 will also be used in support of developing Milestone Decision activities for emerging Programs.$$, NULL, 21039000, 21144000, 21217000, NULL, NULL, 75, $$RDTE - Vol 2 - Budget Activity 4A.pdf$$, NULL, FALSE, 12563000, 36561000, 20290000, 20290000, NULL, 20290000, 21429000, $$FD9: Robotic Systems improves the autonomous robotic systems portfolio by maturing cutting edge emergent commercial technology for transition, creating a virtual test capability to support evaluation, developmental test, system safety testing and operational force-on-force execution for Concept of Operations (CONOP) and Tactics, Techniques and Procedures (TTP) development, development of prototypes and to support infrastructure needs such as cloud-based tools for development and deployment of Autonomy and Artificial Intelligence (AI) Machine Learning (ML) software and tools to support automated testing in a Development, Security and Operations (DEVSECOPS) process. FD9 will also be used in support of developing Milestone Decision activities for emerging Programs.$$, $$Budget J-Books/FY27/Army/RDTE - Vol 2 - Budget Activity 4A.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604019A$$, $$Expanded Mission Area Missile (EMAM)$$, $$rdte_army_ba4$$, $$asa_alt$$, 2026, 277137000, 109752000, 83516000, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "army", "page_num": 14, "original_pe": "0604019A", "page_header": "Department of the Army", "fy26_v182_disc_K": 58189, "fy26_v182_supp_K": 5000, "fy26_v182_total_K": 63189, "fy26_v182_note_name": "Expanded Mission Area Missile (EMAM)", "fy26_v182_source_file": "RDTE - Vol 2 - Budget Activity 4A.txt", "fy26_v182_source_line": 10890}$$::jsonb, $$These funding lines are directly aligned to the Army Air and Missile Defense Modernization Priority. Work in this PE, the Expanded Mission Area Missile (EMAM) program, supports the Integrated Air and Missile Defense (IAMD) architecture and provides Directed Energy Integrated Fires Protection Capability (DE-IFPC) systems to defeat Cruise Missiles (CM); single and swarming Unmanned Aircraft System (UAS); Rocket, Artillery, and Mortar (RAM) threats; Fixed Wing (FW); and Rotary Wing (RW) manned aircraft. This EMAM program element is made up of Joint Laser Weapon System - Army (JLWS-A), DE-IFPC, which is an Air Defense capability consisting of the High Energy Laser (IFPC-HEL) and the High Power Microwave (IFPC-HPM), as well as the Multi-Domain Artillery Cannon System (MDACS). Project B1A: JLWS is a partnered Army-Navy High Energy Laser (HEL) effort that will provide an Air Defense capability against cruise missile threats. Project BU9: IFPC-HEL will provide a ground-based weapon system designed to acquire, track, engage, and defeat the CM, UAS, RAM, FW and RW threats. The IFPC- HEL requirement consists of a standard military prime mover, high energy laser subsystem, power and thermal subsystem, and a beam control subsystem integrated with battle management command, control and communication (BMC3) software. IFPC-HEL provides much needed protection against adversarial threat systems capable of targeting U.S. and Allied forward operating bases and other critical assets. IFPC-HEL will inform Joint Laser Weapon System (JLWS), which begins in FY 2026 and represents the next step in the evolution of counter-cruise missile laser weapons. Project CO6: IFPC-HPM will provide a ground-based weapon system designed to acquire, track, engage, and defeat single and swarming UAS. The IFPC-HPM requirement consists of a HPM effector, that is interoperable with BMC3 software. IFPC-HPM provides much needed protection against adversarial single and swarming UAS. Project DJ5: MDACS will provide a cannon based Air and Missile Defense (AMD) system to complement and integrate with existing AMD systems in the IAMD architecture enabling cost-effective and flexible options to defend fixed and semi-fixed sites against attack by CM, UAS, and advanced threats and provides a capability with a high rate of fire and a deep magazine to defeat threats in raid scenarios. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                          Date: June 2025 Appropriation/Budget Activity                                               R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 4: Advanced       PE 0604019A / Expanded Mission Area Missile (EMAM) Component Development & Prototypes (ACD&P) The FY 2026 request for Expanded Mission Area Missile (EMAM) includes $178,137 thousand of discretionary and $99,000 thousand of mandatory (reconciliation) for a total of $277,137 thousand. The mandatory (reconciliation) funds support Multi-Domain Artillery Cannon System (MDACS) $48,000 thousand initial contract award, long lead hardware purchase and industrial base activation; and Joint Laser Weapon System (JLWS) $51,000 thousand initial contract award, risk reduction technology transfer and program management in support of DoD;s overarching Golden Dome for America strategy. Further information for this reconciliation request is provided in Section 20003 (Missile Defense) of the Reconciliation Exhibit.$$, NULL, 488089000, 350987000, 176359000, NULL, NULL, 76, $$RDTE - Vol 2 - Budget Activity 4A.pdf$$, NULL, FALSE, 82658000, 63189000, 235593000, 235593000, NULL, 235593000, 267036000, $$These funding lines are directly aligned to the Army Air and Missile Defense Modernization Priority. Work in this PE, the Expanded Mission Area Missile (EMAM) program, supports the Integrated Air and Missile Defense (IAMD) architecture and provides Directed Energy Integrated Fires Protection Capability (DE-IFPC) systems to defeat Cruise Missiles (CM); single and swarming Unmanned Aircraft System (UAS); Rocket, Artillery, and Mortar (RAM) threats; Fixed Wing (FW); and Rotary Wing (RW) manned aircraft. This EMAM program element is made up of Joint Laser Weapon System - Army (JLWS-A), DE-IFPC, which is an Air Defense capability consisting of the High Energy Laser (IFPC-HEL) and the High Power Microwave (IFPC-HPM), as well as the Multi-Domain Artillery Cannon System (MDACS). Project B1A: JLWS is a partnered Army-Navy High Energy Laser (HEL) effort that will provide an Air Defense capability against cruise missile threats. Project BU9: IFPC-HEL will provide a ground-based weapon system designed to acquire, track, engage, and defeat the CM, UAS, RAM, FW and RW threats. The IFPC- HEL requirement consists of a standard military prime mover, high energy laser subsystem, power and thermal subsystem, and a beam control subsystem integrated with battle management command, control and communication (BMC3) software. IFPC-HEL provides much needed protection against adversarial threat systems capable of targeting U.S. and Allied forward operating bases and other critical assets. The IFPC-HEL prototype and data will be transferred to the Joint Laser Weapon System (JLWS) program in FY 2027. Project CO6: IFPC-HPM program consists of ground-based weapon systems designed to acquire, track, engage, and defeat single and swarming small-UAS. The IFPC- HPM requirement consists of an HPM effector that is interoperable with BMC3 software. IFPC-HPM provides much needed protection against adversarial single and swarming small-UAS in a semi-fixed position, while also growing capability to provide shoot-on-the-move protection of maneuver forces. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                               Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 4: Advanced          PE 0604019A / Expanded Mission Area Missile (EMAM) Component Development & Prototypes (ACD&P) Project DJ5: MDACS will provide a cannon based Air and Missile Defense (AMD) system to complement and integrate with existing AMD systems in the IAMD architecture enabling cost-effective and flexible options to defend fixed and semi-fixed sites against attack by CM, UAS, and advanced threats and provide a capability with a high rate of fire and a deep magazine to defeat threats in raid scenarios.$$, $$Budget J-Books/FY27/Army/RDTE - Vol 2 - Budget Activity 4A.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604020A$$, $$Cross Functional Team (CFT) Advanced Development & Prototyping$$, $$rdte_army_ba4$$, $$dw_ousd_re$$, 2026, 0, 61779000, 40409000, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "army", "page_num": 14, "fy26_v180": {"note": "R1_FY26_entry_no_value_extracted_in_original_ingest", "source": "b1_null_zero_v180"}, "original_pe": "0604020A", "page_header": "Department of the Army", "fy26_v182_disc_K": 0, "fy26_v182_supp_K": 12000, "fy26_v182_total_K": 12000, "fy26_v182_note_name": "Cross Functional Team (CFT) Advanced Development & Prototyping", "fy26_v182_source_file": "RDTE - Vol 2 - Budget Activity 4B.txt", "fy26_v182_source_line": 746}$$::jsonb, $$This Program Element (PE) is the Army led scope of the Rapid Defense Experimentation Reserve (RDER) initiative. To facilitate rapid modernization of the force, the RDER initiative was established in the Defense Planning Guidance for Fiscal Year 2023-2027, to encourage multi-component experimentation through a campaign of learning. Services, Agencies, and other participating organizations are to identify "best of breed" capabilities developed among the DoD prototyping programs and execute approved projects through large-scale experiments in order to refine and/or validate the Joint Warfighting Concept (JWC). Organizations are to nominate proposals to the Office of the Under Secretary of Defense for Research and Engineering (OUSD(R&E)) that are multi-component - involving Joint Services, International partners and/or other government agencies - and link to one or more of the four key supporting concepts ("functional battles") of the Joint Warfighting Concept: Joint Concept for Fires, Joint Concept for Command and Control, Joint Concept for Contested Logistics, and Joint Concept for Information Advantage. Army lead experimentation outcomes will be designed to validate required capabilities enabling the JWC by evaluating and integrating prototyped technologies in operationally relevant, multi-domain environments. Experimentation results will facilitate Joint Staff analysis in the evaluation of the Joint Warfighting Concept, assist the Joint Requirements Oversight Counsel in requirements determination, and inform the Deputy's Management Action Group to make budget decisions that affect changes throughout the Department. The cited work is consistent with the Under Secretary of Defense, Research and Engineering science and the JWC. Work in this PE is performed by the United States (U.S.) Army and other Service laboratories and research centers, U.S. Army and Joint Program Executive Offices and Program Management Offices. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                    Date: June 2025 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 4: Advanced      PE 0604020A / Cross Functional Team (CFT) Advanced Development & Prototyping Component Development & Prototypes (ACD&P)$$, NULL, NULL, NULL, NULL, NULL, NULL, 77, $$RDTE - Vol 2 - Budget Activity 4B.pdf$$, NULL, FALSE, 38934000, 12000000, NULL, NULL, NULL, NULL, NULL, $$This Program Element (PE) is the Army led scope of the Rapid Defense Experimentation Reserve (RDER) initiative. To facilitate rapid modernization of the force, the RDER initiative was established in the Defense Planning Guidance for Fiscal Year 2023-2027, to encourage multi-component experimentation through a campaign of learning. Services, Agencies, and other participating organizations are to identify "best of breed" capabilities developed among the DoW prototyping programs and execute approved projects through large-scale experiments in order to refine and/or validate the Joint Warfighting Concept (JWC). Organizations are to nominate proposals to the Office of the Under Secretary of War for Research and Engineering (OUSW(R&E)) that are multi-component - involving Joint Services, International partners and/or other government agencies - and link to one or more of the four key supporting concepts ("functional battles") of the Joint Warfighting Concept: Joint Concept for Fires, Joint Concept for Command and Control, Joint Concept for Contested Logistics, and Joint Concept for Information Advantage. Army lead experimentation outcomes will be designed to validate required capabilities enabling the JWC by evaluating and integrating prototyped technologies in operationally relevant, multi-domain environments. Experimentation results will facilitate Joint Staff analysis in the evaluation of the Joint Warfighting Concept, assist the Joint Requirements Oversight Counsel in requirements determination, and inform the Deputy's Management Action Group to make budget decisions that affect changes throughout the Department. The cited work is consistent with the Under Secretary of War, Research and Engineering science and the JWC. Work in this PE is performed by the United States (U.S.) Army and other Service laboratories and research centers, U.S. Army and Joint Program Executive Offices and Program Management Offices. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                   Date: April 2026 Appropriation/Budget Activity                                             R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 4: Advanced     PE 0604020A / Cross Functional Team (CFT) Advanced Development & Prototyping Component Development & Prototypes (ACD&P)$$, $$Budget J-Books/FY27/Army/RDTE - Vol 2 - Budget Activity 4B.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604023D8Z$$, $$Joint Munitions Component Prototyping$$, $$rdte_dw_ba4$$, $$dw$$, 2027, 0, 0, 0, NULL, $${}$$::jsonb, NULL, NULL, 18726000, 32676000, 60114000, NULL, NULL, NULL, NULL, NULL, FALSE, 0, 0, 7893000, 7893000, NULL, 7893000, 62595000, $$This program supports the Department’s initiatives to Reestablish Deterrence, Prevail in Conflict, Defend the Homeland, and Build Sustainable and Long-Term Advantages. Joint Munitions Component Prototyping will enable advanced component technology demonstrations and munitions prototypes for promising, impactful, and disruptive technologies developed by the Department’s science and technology investments. Efforts will reduce technical, financial, integration, and schedule risk for Services and Program Offices through meaningful testing, initial qualification evaluations, and graduation of technologies from technology readiness levels 5-6 to 6-7. Warheads employing new energetics and lethality mechanisms, propulsion components providing increased range/speed, fuzing and safe/arm devices for UAVs, GPS-independent guidance, novel materials for flight bodies and control surfaces, batteries and power sources, collaborative behaviors, seekers and target identification, and other technologies will be evaluated. Successful demonstrations and prototypes will support advanced technology transition to Services and Programs and provide valuable insight into next-generation munitions technologies to inform requirements and concept writers across the Joint Force and Combatant Commands. This program is a new start in FY 2027 and will draw from munitions technology investments by the Joint Munitions Advanced Technology program, the Joint Munitions Technology program, the Joint DoW/DOE Munitions Technology Development program, and Service S&T programs. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Office of the Secretary Of Defense                                            Date: April 2026 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 4:         PE 0604023D8Z / Joint Munitions Component Prototyping Advanced Component Development & Prototypes (ACD&P)$$, $$Budget J-Books/FY27/DW/RDTE_OSW_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604025F$$, $$Rapid Defense Experimentation Reserve (RDER)$$, $$rdte_af_ba4$$, $$aflcmc$$, 2026, 0, 62595000, 75051000, NULL, $${"ba_raw": "6.4", "source": "af_r1_fy26", "original_pe": "0604025F"}$$::jsonb, $$No funds requested in the 2026 President's Budget. Experimentation Efforts supported under the Rapid Defense Experimentation Reserve (RDER) for FY 2025: -Angry Badger: experiment to develop capability for achieving force projection in highly contested environments utilizing existing aircraft fleet structure. --(previous: JRBL Cage: Consolidation of Best in Breed Podded technologies) -DEFEND Experimentation -Classified Projects (more information available in appropriate forums) This effort is in Budget Activity 4, Advanced Component Development and Prototypes (ACD&P), because efforts are necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment.$$, NULL, 0, 0, 0, NULL, NULL, 44, $$FY26 Air Force Research and Development Test and Evaluation Vol II.pdf$$, NULL, FALSE, 72448000, 0, 0, 0, 0, 0, 0, $$No funds requested in the FY 2027 President's Budget. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such programs funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898, 0606398F. This effort is in Budget Activity 4, Advanced Component Development and Prototypes (ACD&P), because efforts are necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment.$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume II.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604027N$$, $$Digital Warfare$$, $$rdte_navy_ba4$$, $$asn_rda$$, 2026, 151271000, 179327000, 128997000, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "navy", "page_num": 30, "original_pe": "0604027N", "page_header": "Department of the Navy"}$$::jsonb, $$The details of this program element are classified SECRET and are submitted annually to Congress in the classified budget justification books, congressional plus up sent over to Air Force$$, NULL, 182312000, 184690000, 186603000, NULL, NULL, 77, $$RDTEN_BA4_Book.pdf$$, NULL, FALSE, 141844000, 150033000, 182205000, 182205000, NULL, 182205000, 191182000, $$The details of this program element are classified SECRET and are submitted annually to Congress in the classified budget justification books.$$, $$Budget J-Books/FY27/Navy/RDTEN_BA4_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604028N$$, $$Small/Medium Unmanned Undersea Vehicles$$, $$rdte_navy_ba4$$, $$dw_diu$$, 2026, 142007000, 88372000, 52994000, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "navy", "page_num": 30, "original_pe": "0604028N", "page_header": "Department of the Navy", "fy26_v182_disc_K": 0, "fy26_v182_supp_K": 180252, "fy26_v182_total_K": 180252, "fy26_v182_note_name": "small/medium UUVs", "fy26_v182_source_file": "RDTEN_BA4_Book.txt", "fy26_v182_source_line": 41043}$$::jsonb, $$Small and Medium Unmanned Undersea Vehicles (UUVs) are a segment of the Navy's Family of UUVs defined as having a diameter between 3 inches and 10 inches for small UUVs and a diameter of 10 inches to 21 inches for medium UUVs. The UUVs can be launched by submarines, surface ships, or larger UUVs, and can be recovered by surface ships and submarines. This class of UUVs can have one or more types of sensors to perform multiple missions including Intelligence Preparation of the Operational Environment (IPOE), battlespace awareness, and mine warfare. Small Unmanned Undersea Vehicle program will field a light-weight, highly portable and mission configurable UUV for use by the Navy Explosive Ordnance Disposal (EOD), Naval Special Warfare (NSW), Submarine UUV Squadron (UUVRON), the Naval Oceanographic Community (NMOC), and United States Marine Corps operators. The program will deliver a baseline UUV capability and implement an incremental development approach, including phases for prototyping, integration, demonstration and fielding of Small Diameter UUVs to integrate with mission packages from each community. This Lionfish UUV system will be the first fielded UUV with cyber compliance. Funding supports the development of unmanned systems for the Navy's expeditionary unmanned underwater Explosive Ordnance Disposal (EOD) and Mine Countermeasures (MCM) capability. Specifically, it provides for development of affordable expeditionary, unmanned underwater systems to support Navy Expeditionary forces including EOD, Mobile Diving and Salvage, Underwater Construction Teams (UCT), Very Shallow Water (VSW), and Expeditionary Mine Countermeasures (ExMCM) mission operations. The equipment must be highly portable in order to support the Navy EOD technician to safely approach, render safe, recover, exploit, and dispose of underwater explosive threats to include sea mines, limpet mines, and unexploded ordnance. Provides support for the Navy's high priority missions of Maritime Homeland Defense and MCM, including clandestine reconnaissance and mine clearance in support of amphibious operations. Development of Expeditionary UUV systems to support localization render-safe and detailed intelligence gathering of unexploded ordnance (UXO) including Underwater Improvised Explosive Devices (IEDs). This project directly supports Department of the Navy Unmanned Campaign Framework promulgated in March 2021 and the requirements defined by the Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Navy                                                                                Date: June 2025 Appropriation/Budget Activity                                               R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 4: Advanced       PE 0604028N / Small/Medium Unmanned Undersea Vehicles Component Development & Prototypes (ACD&P) Maritime Expeditionary MCM UUV (MEMUUV) CDD and is being executed in accordance with approved CNO N9I Requirement #056-95-19, "Capability Development Document for Maritime Expeditionary Standoff Response Family of Systems," July 23 2019. FY 2026 will continue the development and testing of advanced technologies that will allow warfighters to detect, classify, and localize high priority threats in meeting mine and undersea warfare missions. Investments will continue in Artificial Intelligence and Machine Leaning (AI/ML) technologies, as well as continued improvements in Automated Target Recognition (ATR) algorithms, more advanced autonomy architecture and enhancements to acoustic and electro-optic sensor performance. Surface Mine Countermeasures Unmanned Undersea Vehicle (SMCM UUV) - The Knifefish program develops advanced medium class UUVs to support clandestine mine detection capability against volume, bottom, and buried mines. Equipment includes vehicles and associated systems support equipment. In parallel, Block Upgrade design efforts aligned to Fleet needs are ongoing to support insertion of incremental capability when the technology is ready. Planned Block Upgrade candidates being considered include increased detection range capability, communications upgrades, on-board sonar processing and target recognition, command and control improvements, increased operational depth, and other smaller tasks, as well as future payloads as required. Razorback is a medium class UUV capable of persistent, autonomous, ocean sensing and data collection in support of Navy Intelligence Preparation of the Operational Environment (IPOE) mission. The Razorback has two variants, the Razorback MK19, formerly referred to as Razorback Dry Deck Shelter (DDS), and the Razorback MK20, formerly referred to as Razorback Torpedo Tube Launch and Recovery (TTL&R). The Razorback MK19 variant has been procured beginning in FY17 with Fleet operational deployments beginning in FY21. Development of requirements and submarine integration efforts commenced in FY19 for the Razorback Mk20 Torpedo Tube Launch and Recover (TTL&R) variant, which was competitively sourced to industry in FY 2022. Razorback training development begins in FY25. In order to deploy Razorback, or other small or medium class UUVs from a host submarine platform with sufficient endurance to perform a desired mission, high energy density sources such as lithium-ion batteries are used. Consequently, safety is paramount, and mitigation systems must be in place to prevent or stop a high energy casualty event. Shock and Fire Enclosure Capsule (SAFECAP) is being developed as an active mitigation strategy that includes a shock qualified capsule that aides in the launch and recovery of small and medium sized UUVs through the torpedo tube, including Razorback. SAFECAP effort is being transferred from PE0604028N PU3785 to PE0604029 PU4053 beginning in FY25. Mining Expendable Delivery Unmanned Submarine Asset (MEDUSA) is a medium class UUV capable of offensive mining capabilities deployed from a submarine. MEDUSA features torpedo tube launch capability, long range, high payload placement accuracy, and can be integrated with heavy payloads. A demonstration system was developed and tested in FY21 using dummy payloads using a land-based launch facility and surface launched in-water demonstrations. Lessons learned from the demonstration informed a competitive award to Industry in FY24 to develop and produce tactical prototype systems. Tetra is an operationally relevant Remotely Operated Vehicle (ROV) that is launched, and recovered, from submarine torpedo tubes with the capacity for multiple mission payloads as a key enabler to Subsea Seabed Warfare (SSW) to locate, identify, and provide real-time payload employment to effect objects of interest. As a tethered system, Tetra will provide real-time operational data back to the platform and enable man-in-the-loop intervention to maximize the efficiency of a sortie. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Navy                                                                                Date: June 2025 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 4: Advanced           PE 0604028N / Small/Medium Unmanned Undersea Vehicles Component Development & Prototypes (ACD&P)$$, NULL, 17556000, 16327000, 15428000, NULL, NULL, 78, $$RDTEN_BA4_Book.pdf$$, NULL, FALSE, 51775000, 180252000, 24598000, 24598000, NULL, 24598000, 15703000, $$The Department encourages additional vendor participation in the design, development, and production of alternative weapons systems to meet current and future warfighting requirements. With current major weapons systems production at capacity, the nation is looking for alternative systems to fill these gaps. The Department is implementing diverse procurement strategies to enable rapid acquisition. These will include the use of Other Transaction Authorities, 'Marketplace' acquisition platforms, and alternative concepts to increase supply and suppliers in addition to traditional FAR-based procurement strategies. The FY 2026 budget for PU1036 / TETRA program funds supported the development of Lanternfish - a deep Remotely Operated Vehicle (ROV) supporting Subsea Seabed Warfare (SSW) mission areas. Funding also supports the continuation of the TETRA ROV. TETRA funding supports additional payload design and integration, as well as supporting documentation for platform integration. Bootstrap funding was allocated for system improvement and continued testing. UUVs can be launched by submarines, surface ships, or larger UUVs, and can be recovered by surface ships and submarines. This class of UUVs can have one or more types of sensors to perform multiple missions including Intelligence Preparation of the Operational Environment (IPOE), battlespace awareness, and mine warfare. Small Unmanned Undersea Vehicle program will field a light-weight, highly portable and mission configurable UUV for use by the Navy Explosive Ordnance Disposal (EOD), Naval Special Warfare (NSW), Submarine UUV Squadron (UUVRON), the Naval Oceanographic Community (NMOC), and United States Marine Corps operators. The program will deliver a baseline UUV capability and implement an incremental development approach, including phases for prototyping, integration, demonstration and fielding of Small Diameter UUVs to integrate with mission packages from each community. This Lionfish UUV system will be the first fielded UUV with cyber compliance. Funding supports the development of unmanned systems for the Navy's expeditionary unmanned underwater Explosive Ordnance Disposal (EOD) and Mine Countermeasures (MCM) capability. Specifically, it provides for development of affordable expeditionary, unmanned underwater systems to support Navy Expeditionary Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                                Date: April 2026 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 4: Advanced           PE 0604028N / Small/Medium Unmanned Undersea Vehicles Component Development & Prototypes (ACD&P) forces including EOD, Mobile Diving and Salvage, Underwater Construction Teams (UCT), Very Shallow Water (VSW), and Expeditionary Mine Countermeasures (ExMCM) mission operations. The equipment must be highly portable in order to support the Navy EOD technician to safely approach, render safe, recover, exploit, and dispose of underwater explosive threats to include sea mines, limpet mines, and unexploded ordnance. Provides support for the Navy's high priority missions of Maritime Homeland Defense and MCM, including clandestine reconnaissance and mine clearance in support of amphibious operations. Development of Expeditionary UUV systems to support localization render-safe and detailed intelligence gathering of unexploded ordnance (UXO) including Underwater Improvised Explosive Devices (IEDs). This project directly supports Department of the Navy Unmanned Campaign Framework promulgated in March 2021 and the requirements defined by the Maritime Expeditionary MCM UUV (MEMUUV) CDD and is being executed in accordance with approved CNO N95B and N97B Top Level Requirements Document for the Small Unmanned Undersea Vehicle N9I Requirement #056-95-19, "Capability Development Document for Maritime Expeditionary Standoff Response Family of Systems," July 23 2019. FY 2027 will continue the development and testing of advanced technologies that will allow warfighters to detect, classify, and localize high priority threats in meeting mine and undersea warfare missions. Investments will continue in Artificial Intelligence and Machine Leaning (AI/ML) technologies, as well as continued improvements in Automated Target Recognition (ATR) algorithms, more advanced autonomy architecture and enhancements to acoustic and electro-optic sensor performance. Surface Mine Countermeasures Unmanned Undersea Vehicle (SMCM UUV) - The Knifefish program develops advanced medium class UUVs to support clandestine mine detection capability against volume, bottom, and buried mines. Equipment includes vehicles and associated systems support equipment. In parallel, Block Upgrade design efforts aligned to Fleet needs are ongoing to support insertion of incremental capability when the technology is ready. Planned Block Upgrade candidates being considered include increased detection range capability, communications upgrades, on-board sonar processing and target recognition, command and control improvements, increased operational depth, and other smaller tasks, as well as future payloads as required. Razorback is a medium class UUV capable of persistent, autonomous, ocean sensing and data collection in support of multiple Subsea and Seabed Warfare (SSW) including missions. The Razorback originally planned to have two variants, the Razorback MK19, formerly referred to as Razorback Dry Deck Shelter (DDS), and the Razorback MK20, formerly referred to as Razorback Torpedo Tube Launch and Recovery (TTL&R). However, the MK20 variant was terminated by the Navy in 2025 and redirected the investment in the development of a Next Generation MK19 based on proven technologies of Commercial of the Shelf Solutions (COTS). Razorback MK19 In service vehicles are being upgraded to enhance TTL&R capability and the program is working with several mission sponsors to develop modular payloads for the vehicle. In FY2025, the Navy ordered two Tech Refresh EDMs to begin R&D efforts for the next generation MK19 variant. In parallel, the Navy has partnered with the Defense Innovation Unit (DIU) and will award a competitively sourced prototyping Other Transaction contract in FY26 to begin development of the Next Generation variant of MK19 (MK19 Next Gen Prototype). In order to deploy Razorback, or other small or medium class UUVs from a host submarine platform with sufficient endurance to perform a desired mission, high energy density sources such as lithium-ion batteries are used. Consequently, safety is paramount, and mitigation systems must be in place to prevent or stop a high energy casualty event. Shock and Fire Enclosure Capsule (SAFECAP) is being developed as an active mitigation strategy that includes a shock qualified capsule that aides in the launch and recovery of small and medium sized UUVs through the torpedo tube, including Razorback. SAFECAP effort was transferred from PE0604028N PU3785 to PE0604029 PU4053 in FY2025. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                             Date: April 2026 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 4: Advanced         PE 0604028N / Small/Medium Unmanned Undersea Vehicles Component Development & Prototypes (ACD&P) Mining Expendable Delivery Unmanned Submarine Asset (MEDUSA) is a medium class UUV capable of offensive mining capabilities deployed from a submarine. MEDUSA features torpedo tube launch capability, long range, high payload placement accuracy, and can be integrated with heavy payloads. A demonstration system was developed and tested in FY2021 using dummy payloads using a land-based launch facility and surface launched in-water demonstrations. Lessons learned from the demonstration informed a competitive award to Industry in FY2024 to develop and produce tactical prototype systems. Development and production of tactical prototype systems was awarded to Industry in FY2024. Award and production of tactical systems will commence in FY2027. Tetra is an operationally relevant Remotely Operated Vehicle (ROV) that is launched, and recovered, from submarine torpedo tubes with the capacity for multiple mission payloads as a key enabler to Subsea Seabed Warfare (SSW) to locate, identify, and provide real-time payload employment to effect objects of interest. As a tethered system, Tetra will provide real-time operational data back to the platform and enable man-in-the-loop intervention to maximize the efficiency of a sortie. The FY 2026 spend plan amount for small/medium UUVs includes $0 thousand of discretionary and $180,252 thousand of mandatory (reconciliation) for a total of $180,252 thousand.$$, $$Budget J-Books/FY27/Navy/RDTEN_BA4_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604029N$$, $$Unmanned Undersea Vehicle Core$$, $$rdte_navy_ba4$$, $$asn_rda$$, 2026, 47106000, 69476000, 114152000, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "navy", "page_num": 30, "original_pe": "0604029N", "page_header": "Department of the Navy", "fy27_base_v158_t7": "hygiene: base=request for disc-only RDT&E rows post v7 I-23/I-24 + v9 I-2 INSERTs"}$$::jsonb, $$The details of this program element are classified SECRET and are submitted annually to Congress in the classified budget justification books.$$, NULL, NULL, NULL, NULL, NULL, NULL, 79, $$RDTEN_BA4_Book.pdf$$, NULL, FALSE, NULL, NULL, 62460000, 62460000, NULL, 62460000, NULL, NULL, $$Budget J-Books/FY27/Remaining/FY2027_r1.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604030N$$, $$Rapid Prototyping, Experimentation & Dem$$, $$rdte_navy_ba4$$, $$dw_ousd_re$$, 2026, 0, 86417000, 106895000, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "navy", "page_num": 30, "original_pe": "0604030N", "page_header": "Department of the Navy"}$$::jsonb, $$To facilitate rapid modernization of the force, the RDER initiative was established in the Defense Planning Guidance for Fiscal Year 2023-2027, to encourage multi- component experimentation through a campaign of learning. Services, Agencies, and other participating organizations are to identify "best of breed" capabilities developed among the DoD prototyping programs, and execute approved projects through large-scale experiments in order to refine and/or validate the Joint Warfighting Concept (JWC). Organizations are to nominate proposals to the Office of the Under Secretary of Defense for Research and Engineering (OUSD(R&E)) that are multi- component involving Joint Services, International partners and/or other government agencies and link to one or more of the four key supporting concepts ("functional battles") of the Joint Warfighting Concept: Joint Concept for Fires, Joint Concept for Command and Control, Joint Concept for Contested Logistics, and Joint Concept for Information Advantage. The Department will implement multiple RDER experimentation series through Service nominated projects with execution timelines ranging from one to two years. The USD (R&E) will review project progress, and recommend new projects at least annually with the goal of quickly incorporating the most promising innovative prototypes into experiments, and promptly terminating projects that fail to achieve expectations. To incentivize a disciplined approach to rapidly identify, incorporate, and execute projects largely through the Military Services, the Department will fund approved Service projects for the upcoming fiscal year out of the Department reserves. Funding decisions on additional funds in follow-on years for new projects, and funding decrements for project terminations will be incorporated in budgets annually based on emerging requirements and periodic assessments of project viability. Services will execute these funds under oversight of the OSD in a manner consistent with the experimentation scenario for which individual projects were selected. Service experimentation outcomes will be designed to validate required capabilities enabling the JWC by evaluating and integrating prototyped technologies in operationally relevant, multi-domain environments. Experimentation results will facilitate Joint Staff analysis in the evaluation of the Joint Warfighting Concept, assist the Joint Requirements Oversight Counsel in requirements determination, and inform the Deputy's Management Action Group to make budget decisions that effect changes throughout the Department. Advanced Component Development and Prototypes (ACD&P) efforts necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment are funded in this Program Element (PE). Most of the work in this PE can be classified between Technology Readiness Level (TRL) 6 (system/subsystem model or prototype demonstration in a relevant environment) and TRL 7 (system prototype demonstration in an operational environment). Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Navy                                                                      Date: June 2025 Appropriation/Budget Activity                                               R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 4: Advanced       PE 0604030N / Rapid Prototyping, Experimentation & Dem Component Development & Prototypes (ACD&P)$$, NULL, 0, 0, 0, NULL, NULL, 80, $$RDTEN_BA4_Book.pdf$$, NULL, FALSE, 107754000, 0, 0, 0, NULL, 0, 3785000, $$To facilitate rapid modernization of the force, the RDER initiative was established in the Defense Planning Guidance for Fiscal Year 2023-2027, to encourage multi- component experimentation through a campaign of learning. Services, Agencies, and other participating organizations are to identify "best of breed" capabilities developed among the DoD prototyping programs, and execute approved projects through large-scale experiments in order to refine and/or validate the Joint Warfighting Concept (JWC). Organizations are to nominate proposals to the Office of the Under Secretary of War for Research and Engineering (OUSW(R&E)) that are multi- component involving Joint Services, International partners and/or other government agencies and link to one or more of the four key supporting concepts ("functional battles") of the Joint Warfighting Concept: Joint Concept for Fires, Joint Concept for Command and Control, Joint Concept for Contested Logistics, and Joint Concept for Information Advantage. The Department will implement multiple RDER experimentation series through Service nominated projects with execution timelines ranging from one to two years. The USD (R&E) will review project progress, and recommend new projects at least annually with the goal of quickly incorporating the most promising innovative prototypes into experiments, and promptly terminating projects that fail to achieve expectations. To incentivize a disciplined approach to rapidly identify, incorporate, and execute projects largely through the Military Services, the Department will fund approved Service projects for the upcoming fiscal year out of the Department reserves. Funding Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                                    Date: April 2026 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 4: Advanced            PE 0604030N / Rapid Prototyping, Experimentation & Dem Component Development & Prototypes (ACD&P) decisions on additional funds in follow-on years for new projects, and funding decrements for project terminations will be incorporated in budgets annually based on emerging requirements and periodic assessments of project viability. Services will execute these funds under oversight of the OSD in a manner consistent with the experimentation scenario for which individual projects were selected. Service experimentation outcomes will be designed to validate required capabilities enabling the JWC by evaluating and integrating prototyped technologies in operationally relevant, multi-domain environments. Experimentation results will facilitate Joint Staff analysis in the evaluation of the Joint Warfighting Concept, assist the Joint Requirements Oversight Counsel in requirements determination, and inform the Deputy's Management Action Group to make budget decisions that effect changes throughout the Department. Advanced Component Development and Prototypes (ACD&P) efforts necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment are funded in this Program Element (PE). Most of the work in this PE can be classified between Technology Readiness Level (TRL) 6 (system/subsystem model or prototype demonstration in a relevant environment) and TRL 7 (system prototype demonstration in an operational environment).$$, $$Budget J-Books/FY27/Navy/RDTEN_BA4_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604031N$$, $$Large Unmanned Undersea Vehicles$$, $$rdte_navy_ba4$$, $$asn_rda$$, 2026, 185000000, 40479000, 6874000, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "navy", "page_num": 30, "original_pe": "0604031N", "page_header": "Department of the Navy"}$$::jsonb, $$Large Unmanned Undersea Vehicles (UUVs) are part of the Navy's family of UUVs, in support of maintaining the Navy's undersea superiority. They are designed with mission sensors, communications, power, navigation, autonomy and target recognition, and payloads. Large UUVs provide the Navy with significantly increased endurance and payload capacity over small and medium class UUVs. They are deployed from vessels of opportunity and piers. The Snakehead Program was intended to be Navy's largest Submarine-launched UUV with a modular design, high accuracy mission sensors and communications links, as well as modular payload capabilities with well-defined interfaces for the purpose of implementing cost-effective upgrades in future increments to leverage advances in technology. The Snakehead LDUUV program was a CNO/ASN(RDA) approved Accelerated Acquisition that had a phased approach to grow capabilities at a manageable level of risk. As part of Phase I, a Government developed prototype was fabricated, subsystem-level testing began in FY 2021, and vehicle in-water testing began in FY 2022. Phase 2 efforts were stopped in FY 2022. The Snakehead Program is cancelled, starting in FY 2026. The Dragonfish LUUV is a rapid and iterative prototyping project that addresses a priority Fleet requirement for a below-water Intelligence, Surveillance, and Reconnaissance (ISR) task with classification of targets of interest and activation of a purpose-built payload. The system consists of a vehicle, a payload, and a support system. The Dragonfish LUUV is a follow-on effort to a Defense Innovation Unit (DIU) Commercial Solutions Opening (CSO) that assessed commercially available LUUVs. The project is rapidly prototyping with V1 vehicles and conducting in-water, system-level testing. This will inform prototyping for V2 vehicles, which are intended to be Minimal Viable Products (MVPs). Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Navy                                                                           Date: June 2025 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 4: Advanced        PE 0604031N / Large Unmanned Undersea Vehicles Component Development & Prototypes (ACD&P)$$, NULL, 0, 0, 0, NULL, NULL, 81, $$RDTEN_BA4_Book.pdf$$, NULL, FALSE, 6776000, 0, 0, 0, NULL, 0, 0, $$Large Unmanned Undersea Vehicles (UUVs) are part of the Navy's family of UUVs, in support of maintaining the Navy's undersea superiority. They are designed with mission sensors, communications, power, navigation, autonomy and target recognition, and payloads. Large UUVs provide the Navy with significantly increased endurance and payload capacity over small and medium class UUVs. They are deployed from vessels of opportunity and piers. The Navy initially developed the Snakehead Program to meet the requirement for large UUV. The Snakehead LUUV program was a CNO/ASN(RDA) approved Accelerated Acquisition that had a phased approach to grow capabilities at a manageable level of risk. The Snakehead Program is cancelled, starting in FY 2026. The Dragonfish LUUV program was developed to meet this requirement. The Dragonfish LUUV is a rapid and iterative prototyping project that addresses a priority Fleet requirement for a below-water Intelligence, Surveillance, and Reconnaissance (ISR) task with classification of targets of interest and activation of a purpose-built payload. The system consists of a vehicle, a payload, and a support system. The Dragonfish LUUV is a follow-on effort to a Defense Innovation Unit (DIU) Commercial Solutions Opening (CSO) that assessed commercially available LUUVs. The project is rapidly prototyping with V1 vehicles and conducting in-water, system-level testing. This will inform prototyping for V2 vehicles, which are intended to be Minimal Viable Products (MVPs). The FY 2026 spend plan for Large Unmanned Undersea Vehicles includes $0 discretionary and $360,000 thousand of mandatory funding for a total of $360,000 thousand. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                      Date: April 2026 Appropriation/Budget Activity                                               R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 4: Advanced       PE 0604031N / Large Unmanned Undersea Vehicles Component Development & Prototypes (ACD&P)$$, $$Budget J-Books/FY27/Navy/RDTEN_BA4_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604032F$$, $$Directed Energy Prototyping$$, $$rdte_af_ba4$$, $$afrl_rd$$, 2026, 0, 1246000, 1312000, NULL, $${"ba_raw": "6.4", "source": "af_r1_fy26", "original_pe": "0604032F"}$$::jsonb, $$The Air Force Life Cycle Management Center, Architecture and Integration Directorate Directed Energy Prototyping Program develops, acquires and evaluates prototype high energy laser, high power microwave and/or other electromagnetic radiation or particle beam technologies as a future integral component of Air Force missions. The Directed Energy Prototyping Program bridges the gap between lab based technology demonstration under a controlled environment, and demonstration of a system in realistic environments with the intent of establishing successful acquisition, and operation or operational capability implementation. This prototyping effort enables the ability to integrate the directed energy prototype systems with other operational systems required for the mission (e.g. radar, command and control, etc.), conduct test and evaluation activities, and mature emerging directed energy technology systems based on prototyping activities to enable rapid fielding to the warfighter. The Directed Energy Prototyping Program allows acquisition program managers (capability developers) and warfighters (capability recipients and end users) to prototype, integrate, evaluate, and demonstrate candidate weapon technologies and assess them in an operational environment with the intent of iteratively maturing directed energy technologies to a production representative design. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program's funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In Prior Year 2023, 1.046M was expended for civilian pay expenses in this program element, and in CY 2024 1.023M is forecasted for civilian pay expenses in this program element. This effort is in Budget Activity 4, Advanced Component Development and Prototypes (ACD&P), because efforts are necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                         Date: June 2025 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 4: Advanced PE 0604032F / Directed Energy Prototyping Component Development & Prototypes (ACD&P)$$, NULL, 0, 0, 0, NULL, NULL, 45, $$FY26 Air Force Research and Development Test and Evaluation Vol II.pdf$$, NULL, FALSE, 1312000, 0, 0, 0, 0, 0, 0, $$The Air Force Life Cycle Management Center, Architecture and Integration Directorate Directed Energy Prototyping Program develops, acquires and evaluates prototype high energy laser, high power microwave and/or other electromagnetic radiation or particle beam technologies as a future integral component of Air Force missions. The Directed Energy Prototyping Program bridges the gap between lab based technology demonstration under a controlled environment, and demonstration of a system in realistic environments with the intent of establishing successful acquisition, and operation or operational capability implementation. This prototyping effort enables the ability to integrate the directed energy prototype systems with other operational systems required for the mission (e.g. radar, command and control, etc.), conduct test and evaluation activities, and mature emerging directed energy technology systems based on prototyping activities to enable rapid fielding to the warfighter. The Directed Energy Prototyping Program allows acquisition program managers (capability developers) and warfighters (capability recipients and end users) to prototype, integrate, evaluate, and demonstrate candidate weapon technologies and assess them in an operational environment with the intent of iteratively maturing directed energy technologies to a production representative design. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program's funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In Prior Year 2023, 1.046M was expended for civilian pay expenses in this program element, and in CY 2024 1.023M is forecasted for civilian pay expenses in this program element. This effort is in Budget Activity 4, Advanced Component Development and Prototypes (ACD&P), because efforts are necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                       Date: April 2026 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 4: Advanced PE 0604032F / Directed Energy Prototyping Component Development & Prototypes (ACD&P)$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume II.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604033F$$, $$Hypersonics Prototyping$$, $$rdte_af_ba4$$, $$aflcmc$$, 2026, 0, 27903000, 0, NULL, $${"ba_raw": "6.4", "source": "af_r1_fy26", "original_pe": "0604033F"}$$::jsonb, $$The Hypersonics Prototyping program enabled integration and demonstration of emerging hypersonic technologies in an operational or operational-like environment to capitalize on successful laboratory hypersonic research and development efforts with high warfighter priority. Integration and demonstration of hypersonic prototypes also allowed leadership to make informed strategy and resource decisions for future programs based on the results of such hypersonic prototype demonstrations. Hypersonic Prototyping enabled a key linkage between research and development in the lab and fielding advanced technologies to the warfighter. Under this program, Air-Launched Rapid Response Weapon (ARRW) accelerated the technology transfer of hypersonic technologies to enable a responsive, long range strike capability. Throughout this program element was future hypersonic development, which incubated and matured new technologies, processes, and resources for the development and demonstration of hypersonic technology including, but not limited to, infrastructure advancements, digital engineering, open systems architecture, modeling and simulation, analytics, and high performance computing environments. Investing in hypersonics development enabled the collection of valuable data, built capacity and capability, allowing hypersonic programs to leverage and build upon each other, and projects the overall technology forward. This program element included all necessary expenses required to manage, execute, and deliver weapon system capability. The use of such programs funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY2024 $1.13 million was expended for civilian pay expenses in this program element, in FY2025 $0.00 million was forecasted for civilian pay expenses. This effort is in Budget Activity 4, Advanced Component Development and Prototypes (ACD&P), because efforts are necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                     Date: June 2025 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 4: Advanced PE 0604033F / Hypersonics Prototyping Component Development & Prototypes (ACD&P)$$, NULL, 548575000, 620454000, 242643000, NULL, NULL, 46, $$FY26 Air Force Research and Development Test and Evaluation Vol II.pdf$$, NULL, FALSE, 0, 0, 345769000, 345769000, 0, 345769000, 0, $$The Hypersonics Prototyping (Air-launched Rapid Response Weapon) program enables development, integration and demonstration of hypersonic technologies and other key technologies in an operational or operational-like environment to capitalize on successful hypersonic research and development efforts with high warfighter priority. Integration and demonstration of developed technologies and prototype technologies into a hypersonic system allows leadership to make informed strategy and resource decisions for future programs based on the results of such hypersonic demonstrations. Hypersonic Prototyping enables a key linkage between research and development in the lab and fielding advanced technologies to the warfighter. Under this program, Air-Launched Rapid Response Weapon (ARRW) accelerates the integration of technologies into a hypersonic system and the transfer of new hypersonic technologies enabling a responsive, long range strike capability. Throughout this program element is hypersonic development, which incubates and matures new technologies, processes, and resources for the development and demonstration of hypersonic technology including, but not limited to, infrastructure advancements, digital engineering, open systems architecture, modeling and simulation, analytics, and high performance computing environments. In addition, the program adapts and integrates proven technologies into a hypersonic vehicle improving and/or adding additional capabilities for the warfighter. Investing in hypersonics development and technology integration enables the collection of valuable data, builds capacity and capability, allowing hypersonic programs to leverage and build upon each other, and projects the overall technology forward. The FY 2026 spend plan amount for RDT&E includes 0 thousand of discretionary and 133,334 thousand of mandatory (reconciliation) for a total of 133,334 thousand. This program element included all necessary expenses required to manage, execute, and deliver weapon system capability. The use of such programs funds would be in addition to the civilian pay expenses budgeted in program elements 0605829F, 0605831F, 0605833F, and 0605898F. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                          Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 4: Advanced PE 0604033F / Hypersonics Prototyping Component Development & Prototypes (ACD&P) The Air-Launched Ballistic Missile (ALBM) Integrates Air Force and other system technologies to develop, design, test, manufacture, and field an air-launched, long- range strike capability that complements existing hypersonic weapons. ALBM will mature existing hypersonic weapon technologies to rapidly test, which will inform future production decisions early in the acquisition lifecycle. This effort is in Budget Activity 4, Advanced Component Development and Prototypes (ACD&P), because efforts are necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment.$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume II.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604036A$$, $$Multi-Domain Sensing System (MDSS) Adv Dev$$, $$rdte_army_ba4$$, $$asa_alt$$, 2026, 239813000, 185831000, 188228000, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "army", "page_num": 14, "original_pe": "0604036A", "page_header": "Department of the Army"}$$::jsonb, $$A. Mission Description and Budget Item Justification 604036A / Project BY9 was established in FY 2022 to support sensor prototyping for initiation of the Army's Multi Domain Sensing System (MDSS), a layered approach of the Army's Aerial Intelligence, Surveillance, and Reconnaissance (A-ISR) systems which allows for the best ability to achieve Multi-Domain Operations (MDO) capable deep sensing. The A-ISR systems, MDSS family of systems (HADES, HAP-DS, ARGOS, and HERMES) and Launched Effects (LE), is comprised of a variety of platform/sensor combinations and MDO-capable, platform agnostic, scalable sensor programs that will provide for technical insertion into LE, Unmanned Aerial Systems (UAS), high-altitude platforms (including Micro High-Altitude Balloons (mHAB)), medium altitude manned systems, and unmanned stratospheric A-ISR systems. These capabilities are enabled by emerging Artificial Intelligence/Machine Learning (AI/ML) processing and automated target recognition, autonomous sensor cross-cueing, sensor data correlation and resilient Joint All Domain Command and Control (JADC2) compliant communications which shorten the sensor to shooter kill chain. PE 0604036A / Project DD6 is the Army's first priority in the Multi-Domain Sensing System (MDSS) portfolio of systems and is the centerpiece of the A-ISR transformation strategy. High Accuracy Detection and Exploitation System (HADES) is a commercial jet modified for military use with complex Outer Mold Line (OML) aerodynamic modifications and integrated with sensors which provide Communications Intelligence (COMINT), Electronics Intelligence (ELINT), and Synthetic Aperture Radar/Moving Target Indicator (SAR/MTI) (i.e. RADAR) capabilities, Aircraft Survivability Equipment (ASE), and other military mission equipment utilizing open system standards. HADES allows the Army to fly higher, faster, and farther, which directly impacts the warfighter's ability to see and sense deeper, delivering an organic capability in line with the Army's operational imperative for deep sensing. In FY 2026 three (3) prototype aircraft are concurrently in development, up from two (2) in FY 2025. These three developmental prototypes will inform future Army procurement decisions. The FY 2026 cost of the HADES Middle Tier of Acquisition effort is $83.7 million, including RDT&E and procurement of prototype units. The Department will certify FYDP funding in a future budget submission. HADES is part of the Army Transformation Initiative (ATI). Procurement begins in FY 2026. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                              Date: June 2025 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 4: Advanced          PE 0604036A / Multi-Domain Sensing System (MDSS) Adv Dev Component Development & Prototypes (ACD&P)$$, NULL, 39824000, 1002000, 1002000, NULL, NULL, 79, $$RDTE - Vol 2 - Budget Activity 4B.pdf$$, NULL, FALSE, 188228000, 249188000, 99471000, 99471000, NULL, 99471000, 1012000, $$PE 0604036A / Project DD6 is the Army's first priority in the MDSS portfolio of systems and is the centerpiece of the A-ISR transformation strategy. HADES is a commercial jet modified for military use with complex OML aerodynamic modifications and integrated with sensors which provide COMINT, ELINT, and SAR/MTI (i.e. RADAR) capabilities, ASE, and other military mission equipment utilizing open system standards. HADES allows the Army to fly higher, faster, and farther, which directly impacts the warfighter's ability to see and sense deeper, delivering an organic capability in line with the Army's operational imperative for deep sensing. In FY 2027 Prototype #2 and #3 aircraft are concurrently being developed as prototype #1 will deliver in FY 2026. These three developmental prototypes will inform future Army procurement decisions. HADES provides advanced aerial intelligence sensing capabilities for Multidomain Operations (MDO) against peer and near-peer adversaries, addressing Army deep sensing needs in all phases of operations and throughout the depth of the future battlefield. With higher airspeed, range and endurance, HADES will facilitate A-ISR coverage for a much larger geographical area than current capability and will facilitate global deployment within days instead of the current transitional period of several weeks for legacy aircraft. This will adversely affect our adversaries' ability to plan and maneuver. This is also aligned with the Headquarters Department of the Army Deputy Chief of Staff (HQDA DCS) G2 strategy that lethality begins with intelligence. HADES provides highly mobile, long endurance converged deep sensing through the collection of COMINT, ELINT, and SAR/MTI data. Subsequent increment upgrades can host Electronic Warfare (EW), Radio Frequency (RF)-enabled Cyber, and Launched Effects (LE) as well as additional system improvements. Aircraft performance and a Modular Open Systems Approach (MOSA) increases flexibility in rapid global deployment and postures to meet emerging operational needs. The total cost of the HADES Middle Tier of Acquisition (MTA) Rapid Prototyping (RP) # 1 effort is $473.5 million RDT&E from FY 2024 to FY 2027. Details provided under separate cover. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                           Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 4: Advanced          PE 0604036A / Multi-Domain Sensing System (MDSS) Adv Dev Component Development & Prototypes (ACD&P)$$, $$Budget J-Books/FY27/Army/RDTE - Vol 2 - Budget Activity 4B.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604037A$$, $$Tactical Intel Targeting Access Node (TITAN) Adv Dev$$, $$rdte_army_ba4$$, $$peo_c3t$$, 2026, 3092000, 10626000, 4317000, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "army", "page_num": 14, "original_pe": "0604037A", "page_header": "Department of the Army"}$$::jsonb, $$The Tactical Intelligence Targeting Access Node (TITAN) is a key enabler of the Army Modernization Priorities in support of Army Cross Functional Teams. TITAN is a scalable and expeditionary intelligence ground station that supports commanders across the entire Multi-Domain Operations (MDO)/Joint All Domain Operations (JADO) battlefield framework with capabilities tailored to echelon. TITAN leverages Space, High Altitude, Aerial and Terrestrial layer sensors to provide targetable data to fires networks as well as multi-discipline intelligence support to targeting and Situation Awareness/Situation Understanding (SA/SU) in support of mission command. This funding will provide development and prototyping of Critical Radio Frequency (RF) technologies and integration of new Space-Based ISR capabilities into the TITAN POR. TITAN is the Army Intelligence, Surveillance, and Reconnaissance (ISR) ground station that consolidates the sensor processing capabilities in the current Distributed Common Ground System-Army (DCGS-A) Operational-Intelligence Ground Station (OGS), Tactical-Intelligence Ground Station (TGS), the Advanced Miniaturized Data Acquisition System Dissemination Vehicle (ADV), and the Remote Ground Terminal (RGT). Additionally, TITAN will access sensor data of Tactical Space Layer assets, National assets, the Multi-Domain Sensing Systems (MDSS) as well as commercial overhead sensors. Thus, the TITAN ground station conducts deep sensing operations with the abilities to Task, Collect, Process, Exploit, and Disseminate (TCPED) information from Space, High Altitude, Aerial, and Terrestrial Layer sensors in support of Long-Range Precision Fires (LRPF) operations. The FY 2026 cost of the Titan Intelligence Targeting Access Node (TITAN) Middle Tier of Acquisition effort is $23.7 million, including RDT&E and procurement of prototype units. The Department will certify FYDP funding in a future budget submission. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                        Date: June 2025 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 4: Advanced        PE 0604037A / Tactical Intel Targeting Access Node (TITAN) Adv Dev Component Development & Prototypes (ACD&P)$$, NULL, 4171000, 4203000, 4206000, NULL, NULL, 80, $$RDTE - Vol 2 - Budget Activity 4B.pdf$$, NULL, FALSE, 4317000, 3092000, 4123000, 4123000, NULL, 4123000, 4248000, $$TITAN is a scalable and expeditionary intelligence ground station that supports commanders across the entire Multi-Domain Operations (MDO)/Joint All Domain Operations (JADO) battlefield framework with capabilities tailored to echelon. TITAN leverages Space, High Altitude, Aerial and Terrestrial layer sensors to provide targetable data to fires networks as well as multi-discipline intelligence support to targeting and Situation Awareness/Situation Understanding (SA/SU) in support of mission command. TITAN will utilize Artificial Intelligence/Machine Learning (AI/ML) capabilities and leverage advanced Radio Frequency (RF) technologies as they become available. The FY27 RDTE Dollars in the amount of $4.123M supports advanced development of critical technologies.$$, $$Budget J-Books/FY27/Army/RDTE - Vol 2 - Budget Activity 4B.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604038N$$, $$Maritime Targeting Cell$$, $$rdte_navy_ba5$$, $$asn_rda$$, 2026, 147802000, 50879000, 43301000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "navy", "page_num": 32, "original_pe": "0604038N", "page_header": "Department of the Navy", "fy27_base_v158_t7": "hygiene: base=request for disc-only RDT&E rows post v7 I-23/I-24 + v9 I-2 INSERTs"}$$::jsonb, $$The details of this program element are classified SECRET and are submitted annually to Congress in the classified budget justification books.$$, NULL, NULL, NULL, NULL, NULL, NULL, 109, $$RDTEN_BA5_Book.pdf$$, NULL, FALSE, NULL, NULL, 216514000, 216514000, NULL, 216514000, NULL, NULL, $$Budget J-Books/FY27/Remaining/FY2027_r1.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604055D8Z$$, $$Operational Energy Capability Improvement (OECI)$$, $$rdte_dw_ba3$$, $$dw_osd$$, 2026, 0, 218246000, 155569000, NULL, $${"act": "03", "ba_raw": "6.3", "source": "r1_fy26", "service": "dw", "page_num": 70, "original_pe": "0604055D8Z", "page_header": "Defense-Wide"}$$::jsonb, $$OE innovation is the cornerstone of the future Joint Force, preserving command, control, and communications at all echelons and ensuring: • increased lethality • agile, integrated, shaping, and pulsed operations • survivable and sustainable capabilities across domains and in any environment including contested and extreme ones (i.e., Arctic and Space) • decisive information and decision advantage. OECI powers this future by investing in early-stage energy innovation for military capabilities, incentivizing the Components to achieve energy superiority for U.S. Joint Forces and missions. The OECI program accelerates the transition of pre-commercial, military-unique technologies, promoting rapid fielding to warfighters. OECI is innovating today for energy superiority tomorrow, delivering unmatched value to the DOD warfighter by: • Boosting lethality and supportability • Enhancing operational readiness and responsiveness • Extending operational capabilities and endurance for advanced platforms and weapons OECI's technical thrust areas are: • Operational Energy and Power Projection: Giving U.S. forces operational flexibility, freedom to operate at will, and a qualitative edge in all domains (including space and cyber), through implementation of advanced energy technologies. Investments include novel platform structures and power plant solutions for extended duration and enabling and enhancing maneuver without regret (including next-generation power and energy delivery (power beaming)). Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Office of the Secretary Of Defense                                                  Date: June 2025 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 3:            PE 0604055D8Z / Operational Energy Capability Improvement (OECI) Advanced Technology Development (ATD) • Operational Energy Surety: Ensuring U.S. forces, capabilities, and missions assured, robust, and resilient access to energy, including powering energy magazines (missile defense, Golden Dome, and counter-UAS) and data centers in the homeland and abroad. Technical areas include fuel fabrication processes, energy conversion, novel power generation, and energy storage and distribution technologies. • Please see higher classification for additional information. OECIF is laser-focused on accelerating solutions to critical OE capability gaps, delivering game-changing technologies that advance contested logistics, command energy resources, and electrify the battlespace. Select successes include: • TRISO Fuel Production: Reclaiming America's Nuclear Leadership: Established the only domestic, commercial TRISO nuclear fuel production capability in the US, eliminating a critical vulnerability in our nuclear infrastructure. This strategic capability is now enabling terrestrial and space RDT&E demonstrations, Service SMR initiatives at installations, and the national civilian advancement of advanced nuclear power, benefiting both utility and DOD applications and solidifying America's leadership in nuclear energy. • Revolutionary Airframe Prototyping: Redefining Airpower: Advanced oblique-angle flying wing (OAFW) technology, delivering unprecedented endurance, range, and altitude performance (greater than 40% increase) in under 12 months. These airframe advancements are applicable and scalable across multiple joint communities, advancing lift, refueling, and signature management and promising to redefine the future of airpower. • DHVPE: Securing Dominance in Space: Innovations are driving down the cost of space-qualified PV, reducing launch weight, and maturing power beaming components, enabling increased maneuverability and survivability in space and ensuring U.S. dominance in this critical domain. • Power Beaming: Projecting Power Across the Battlespace: Power beaming advancements have been made in multiple modalities (RF, Optical/Laser, mm Wave), accelerating the maturation of transmit, receive, beam forming/steering/safety capabilities and demonstrating concepts across modalities. This positions the U.S. as the undisputed leader in wireless power technology, enabling a new era of energy delivery. • Airborne Energy Delivery: Guaranteeing Resupply in Contested Environments: Innovations are increasing the standoff distance and accuracy for airborne energy delivery in contested environments, including GPS-denied environments, guaranteeing that ground forces receive the energy resupply they need to fight and win, regardless of the threat environment. • Power and Thermal management for energy magazine: Underpinning advancements for current laser technology use and scaling to support increasing future demands. The OECI program has a proven track record of successfully transitioning emerging OE capabilities, with over 80% of completed projects moving into practical application. Specifically, 117 of 132 completed projects have transitioned to: follow-on funding; equipment for CCMD exercises and demonstrations; knowledge or analytic tools supporting the Joint OE community; or commercial markets. OECI has been instrumental in advancing critical capabilities for energy-efficient shelters, ground vehicle efficiency, high-power weapons and power beaming, energy storage for unmanned systems, nuclear power, and technologies addressing key capability gaps, enabling the ability to command energy, power the force, and electrify the battlespace. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Office of the Secretary Of Defense                                            Date: June 2025 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 3:       PE 0604055D8Z / Operational Energy Capability Improvement (OECI) Advanced Technology Development (ATD)$$, NULL, NULL, NULL, NULL, NULL, NULL, 78, $$RDTE_OSD_PB_2026.pdf$$, $$OSD$$, FALSE, 152656000, 0, NULL, NULL, NULL, NULL, NULL, $$OE innovation is the cornerstone of the future Joint Force and ensuring: • Increased lethality • Agile, integrated, shaping, and pulsed operations • Survivable and sustainable capabilities across domains and in any environment including contested and extreme ones (i.e., Arctic and Space) • Decisive information and decision advantage OE Innovation projects ensure all emerging technology is prepared to share power and energy information into the broader Combined Joint All-Domain Command & Control (CJADC2) system - providing decision-quality information and is of high-value to the warfighter. OECI powers this future by investing in early-stage energy innovation for military capabilities, incentivizing the Components to achieve energy superiority for U.S. Joint Forces and missions. The OECI program accelerates the transition of pre-commercial, military-unique technologies, promoting rapid fielding to warfighters. OECI is innovating today for energy superiority tomorrow, delivering unmatched value to the DoW warfighter by: • Boosting lethality and supportability • Enhancing operational readiness and responsiveness • Extending operational capabilities and endurance for advanced platforms and weapons Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Office of the Secretary Of Defense                                                    Date: April 2026 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 3:          PE 0604055D8Z / Operational Energy Capability Improvement (OECI) Advanced Technology Development (ATD) OECI prioritizes technology development for multiple-Service use-cases, deconflicts across Service investments reducing duplication, and increases auditability of funding both within the program and community-wide from 6.2 through warfighter transition. OECI maintains and advances use of accountability tools and process development. OECI's technical thrust areas are: • Operational Energy Dominance: Providing energy capability and battlespace awareness technologies for collecting, camouflaging, and controlling power and energy data. These investments leverage Artificial Intelligence and machine learning (AI/ML) for integrating U.S., allied, and adversary energy information into the combined joint all-domain command and control (CJADC2) architecture. Additional information is available in a classified addendum for this budget exhibit. Dominance supports solutions to power and energy vulnerabilities and threat reduction at home and abroad. • Operational Energy Surety: Ensuring U.S. forces, capabilities, and missions assured, robust, and resilient access to energy, including powering energy magazines (missile defense, Golden Dome, and counter-UAS) and data centers in the homeland and abroad. Operational Energy Surety recognizes bases as warfighting capabilities and is protecting and exploiting homeland operations. Technical areas include fuel fabrication processes, energy conversion, novel power generation, and energy storage and distribution technologies. Operational Energy and Power Projection: Giving U.S. forces operational flexibility, freedom to operate at will, and a qualitative edge in all domains (including air, space, and cyber), through implementation of advanced energy technologies. Investments include novel platform structures and power plant solutions for extended duration and enabling and enhancing maneuver without regret (including next-generation power and energy delivery (power beaming)). • Nuclear Innovation: Developing power and energy solutions for the battlespace including assured power for critical missions at home, underway, and abroad. Nuclear innovations do not overlap efforts covered by the Chief of Naval Reactors (CNR) but are broadly applicable in all domains from sub-sea to space. OECI is laser-focused on accelerating solutions to critical OE capability gaps, delivering game-changing technologies that advance contested and strategic logistics, command of energy resources, and electrify the battlespace. Select successes include: • TRISO Fuel Production: Reclaiming America's Nuclear Leadership: Established the only domestic, commercial TRISO nuclear fuel production capability for DoW in the US, eliminating a critical vulnerability in our nuclear infrastructure. This strategic capability is now enabling terrestrial and space RDT&E demonstrations, Service small modular reactor (SMR) initiatives at installations, and the national civilian advancement of advanced nuclear power, benefiting both DoW and utility applications and solidifying America's leadership in nuclear energy. This effort successfully provided all nuclear fuel for Project Pele and Project VALKRE and lays the commercial infrastructure for supporting near-term nuclear reactor interests for all Services. • Revolutionary Airframe Prototyping: Redefining Airpower: Advanced oblique-angle flying wing (OAFW) technology, delivering unprecedented endurance, range, and altitude performance (greater than 40% increase) in under 12 months. These airframe advancements are applicable and scalable across multiple joint communities, advancing lift, refueling, and signature management and promising to redefine the future of airpower. • Dynamic Hydride Vapor Phased Epitaxy (DHVPE): Securing Dominance in Space: Innovations are driving down the cost of space-qualified PV, reducing launch weight, and maturing power beaming components, enabling increased maneuverability and survivability in space and ensuring U.S. dominance in this critical domain. • Power Beaming: Projecting Power Across the Battlespace: Power beaming advancements in multiple modalities (RF, Optical/Laser, mm Wave) are accelerating the maturation of transmit, receive, beam forming/steering/safety capabilities and demonstrating concepts across modalities. This positions the U.S. as the undisputed leader in wireless power technology, enabling a new era of energy delivery. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Office of the Secretary Of Defense                                                     Date: April 2026 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 3:         PE 0604055D8Z / Operational Energy Capability Improvement (OECI) Advanced Technology Development (ATD) • Airborne Energy Delivery: Guaranteeing Resupply in Contested Environments: Innovations are increasing the standoff distance and accuracy for airborne energy delivery in contested environments, including GPS-denied environments, guaranteeing ground forces receive the energy resupply they need to fight and win, regardless of the threat environment. • Power and Thermal management for energy magazine: Underpinning advancements for current laser technology use and scaling to support increasing future demands. Current/ongoing OECI investments focus on providing agile OE solutions that address insights from current operations. Technical advancements include: Advanced Algorithms & Analytics: Developing AI/ML algorithms for anomaly detection, predictive power analysis, energy optimization, and pattern-of-life analysis • Joint All-Domain Command and Control (JADC2) Integration: Developing data models, user interfaces, and communication protocols to integrate and visualize OE assets and data into the JADC2 architecture • Power Electronics & Microgrids: Designing high-efficiency power converters, inverters, and microgrid controllers for tactical applications, with a focus on vehicle-centric microgrids and integration with Joint and Coalition energy sources • Energy Storage & Generation: Developing advanced battery chemistries (Li-ion, Lithium Sulfur), fuel cells (hydrogen), and waste-to-energy systems for mobile and expeditionary power • Wireless Power Transfer Technologies: Advancing RF, mm-Wave and laser power beaming systems, including rectenna design, beam steering, and integration with UAVs and other platforms • Space-Based Solar Power: Developing low-cost, high-efficiency solar cells and arrays for space applications, including perovskite and III-V materials • Nuclear Reactor Technology: Developing small modular reactors (SMRs), TRISO fuel, and advanced nuclear reactor materials for both space and terrestrial applications • Fuel Efficiency & Hybridization: Developing hybrid-electric architectures for tactical vehicles, aircraft, and naval vessels to improve fuel efficiency and enable new capabilities The OECI program has a proven track record of successfully transitioning emerging OE capabilities, with over 80% of completed projects moving into practical application. Specifically, 117 of 132 completed projects have transitioned to: follow-on funding; equipment for Combatant Command (CCMD) exercises and demonstrations; knowledge or analytic tools supporting the Joint OE community; or commercial markets. OECI has been instrumental in advancing critical capabilities for energy-efficient shelters, ground vehicle efficiency, high-power weapons and power beaming, energy storage for uncrewed systems, nuclear power, and technologies addressing key capability gaps, enabling the ability to command energy, power the force, and electrify the battlespace. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Office of the Secretary Of Defense                                       Date: April 2026 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 3:       PE 0604055D8Z / Operational Energy Capability Improvement (OECI) Advanced Technology Development (ATD)$$, $$Budget J-Books/FY27/DW/RDTE_OSW_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604100A$$, $$Analysis Of Alternatives$$, $$rdte_army_ba4$$, $$asa_alt$$, 2026, 9865000, 10690000, 11234000, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "army", "page_num": 14, "original_pe": "0604100A", "page_header": "Department of the Army"}$$::jsonb, $$This Program Element (PE) provides funding for analytical support of Analysis of Alternatives. Analyses of Alternatives are statutory requirements for Major Defense Acquisition Programs and regulatory for all other programs. Based on Department of Defense Instruction (DoDI) 5000.02, Analyses of Alternatives are required to be completed for a new start program prior to its first Milestone Decision. The PE provides analytical capability for Pre-Milestone A programs that emerge outside the normal budget or POM cycles. Normally these programs are without program managers and require analysis to support Congressional, Defense and Army Senior Leader's requirement and acquisition needs and priorities. The Analyses of Alternatives support the preparation of the Capability Development Document, Key Performance Parameters and Thresholds values and tradeoff analysis. The cited work is consistent with the Army Science and Technology priority focus areas and the Army Modernization Strategy and Guidance. The Army is projecting to start work on multiple Analyses of Alternatives and will assess and fund the highest Congressional, Defense and Army Senior Leader's priorities during the year of execution. The FY 2026 request was reduced by $0.393 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative." The FY 2026 request was reduced by $0.058 million for civilian personnel to optimize the workforce in compliance with Executive Order 14210, "Implementing the President's Department of Government Efficiency Workforce Optimization Initiative."$$, NULL, 10263000, 10397000, 10540000, NULL, NULL, 81, $$RDTE - Vol 2 - Budget Activity 4B.pdf$$, NULL, FALSE, 10824000, 9865000, 10077000, 10077000, NULL, 10077000, 10648000, $$This Program Element (PE) provides analytical support of Analysis of Alternatives (AoAs). AoAs are statutory requirements for MDAPs and regulatory for all other programs. Based on Department of Defense Instruction (DoDI) 5000.84, AoAs are required to be initiated after the Materiel Development Decision (MDD) to identify the best value materiel solution. The project provides analytical capability for Pre-Milestone A programs that emerge outside the normal budget or POM cycles. Normally these programs are without program managers and require analysis to support Congressional, Department of War (DoW) and Army Senior Leader's requirement and acquisition needs and priorities. The AoAs support the development of requirements, Key Performance Parameters and thresholds values and tradeoff analysis. The cited work is consistent with the Army Science and Technology priority focus areas and the Army Transformation Initiative (ATI). The Army will assess and fund the highest Congressional, DoW, and Army Senior Leader's priorities during the year of execution.$$, $$Budget J-Books/FY27/Army/RDTE - Vol 2 - Budget Activity 4B.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604102C$$, $$Guam Defense Development$$, $$rdte_dw_ba4$$, $$dw_mda$$, 2026, 172985000, 554503000, 415794000, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "dw", "page_num": 71, "original_pe": "0604102C", "page_header": "Defense-Wide"}$$::jsonb, $$This program develops a Missile Defense System for the Defense of Guam (DoG) against ballistic, hypersonic, and cruise missile threats as a high priority mission for the Department of Defense. The Missile Defense System will form a key part of strategic deterrence and supports the PDI. In FY 2022, the Missile Defense Agency (MDA) initiated studies and analysis, architecture development and siting analysis. FY 2023 continued architecture development and increased the development and modification of the distributed radar, Aegis Guam System support, environmental studies, site design, activation and advanced planning. In FY 2024, the program leveraged the results of studies and analysis to continue developing and fielding of distributed land-based launchers, distributed sensors, and integrated communications across Guam. The acquisition approach is to balance costs and associated risks in order to provide increased Aegis Weapon System development for Guam integration, site activation, environmental protection, engineering, and interoperability. FY 2025 continues the advancements of FY 2024 completing an on-island flight experiment in early FY 2025, continued Environmental Studies and Mitigations, and continuation of the software development phase for the Aegis and Radar components. The activities in FY 2026 include development and integration efforts between MDA, United States (U.S.) Army (USA), U.S. Navy (USN), and U.S. Air Force (USAF) systems, which includes a 360 degree persistent integrated air and missile defense Aegis Guam System with distributed Mk-41 Vertical Launching Systems, and a single Tactical Array Unit (TAU) Army Navy/Transportable Radar Surveillance and Control-6 (AN/TPY-6) and missile uplink/downlink communications system for the DoG. Aegis Guam System will develop capability to leverage track data from Army systems, that is provided via the Joint Track Management Capability - Bridge (JTMC- B), to support Standard Missile-6 Engage on Remote (EoR) capability. The Guam Architecture will be commanded and controlled from the Joint Command Center with additional Integrated Air and Missile Defense Battle Command System; Aegis Guam System; Command and Control, Battle Management and Communications mission Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Missile Defense Agency                                                          Date: June 2025 Appropriation/Budget Activity                                                     R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 4:              PE 0604102C / Guam Defense Development Advanced Component Development & Prototypes (ACD&P) node and Tactical Operations Center - Light providing local continuity of operations. Initial Aegis Guam System capability was demonstrated on Guam in calendar year (CY) 2024. Aegis Guam System with additional Terminal Defense capability will be delivered in CY 2029.$$, NULL, 214815000, 200642000, 123405000, NULL, NULL, 102, $$RDTE_Vol2_MDA_RDTE_PB26_Justification_Book.pdf$$, $$MDA$$, FALSE, 412042000, 127742000, 212413000, 212413000, NULL, 212413000, 119357000, $$This program develops a Missile Defense System for the Defense of Guam against ballistic, hypersonic, and cruise missile threats to address the Department of War's priority theater and number one USINDOPACOM regional deterrence priority. The Missile Defense System on Guam will form a key part of strategic deterrence, is a critical component of U.S. Integrated Air and Missile Defense (IAMD) strategy and supports the Department's PDI investments in the Indo-Pacific region. In FY 2022, the MDA initiated studies and analysis, architecture development and siting analysis. FY 2023 continued architecture development and increased the development and modification of the distributed radar, AGS support, environmental studies, site design, activation and advanced planning. In FY 2024, the program leveraged the results of studies and analysis to continue developing and fielding of distributed land-based launchers, distributed sensors, and integrated communications across Guam. The acquisition approach is to balance costs and associated risks in order to provide increased Aegis Weapon System (AWS) development for Guam integration, site activation, environmental protection, engineering, and interoperability. FY 2025 continued the advancements of FY 2024 completing an on-island flight experiment in early FY 2025, continued Environmental Studies and Mitigations, and continued the software development phase for the Aegis and Radar components. FY 2026 commences cybersecurity initiatives for the Command Center, developmental efforts for operationalizing the Initial Deployment Aegis Guam System in the new Guam Defense architecture, continues environmental studies and mitigations, and continuation of the software development phase for the Aegis components. To defend Guam, the Missile Defense System mission activities are integrating systems from the MDA, U.S. Army, U.S. Navy, and U.S. Air Force. The Missile Defense System will leverage the MDA's S-band Missile Communication Radar (uplink and downlink) system, MDA's AGS, and U.S. Army Lower Tier Air and Missile Defense Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Missile Defense Agency                                                             Date: April 2026 Appropriation/Budget Activity                                                     R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 4:              PE 0604102C / Guam Defense Development Advanced Component Development & Prototypes (ACD&P) Sensor to enable a full 360-degree field of view, eliminating blind spots and providing a layered and robust IAMD capability specifically tailored to protect Guam. The AGS employs the distributed Mk-41 VLS, a AN/TPY-6, and Standard Missile uplink and downlink communications to transmit information to and from the missile during its flight. The AGS will develop capability to leverage track data from Army systems, that is provided via the Joint Track Management Capability - Bridge, to support Standard Missile-6 Engage on Remote capability. Command and control will be executed from the Joint Command Center, augmented by the IAMD Battle Command System, AGS, a C2BMC mission node, and Tactical Operations Center - Light for local continuity of operations. An initial AGS capability demonstration occurred in current year (CY) 2024. In FY27 AGS will deliver Early Operational Capability (EOC) in CY27 to further enhance operational readiness and effectiveness. Strategically supporting and promulgating AGS Baseline 1.0 Certification and USN Sailor Training as part of the Department's PDI investments in the Indo-Pacific region and Guam Defense System Joint Program Office Increment 1 and Increment 2 Deliveries; Integration and operationalization of a transportable array unit in support of GDS Increment 1 EOC and efforts supporting GDS Increment 2 Initial Operational Capability (IOC) and Equipment for the Command Center, including temporary equipment for the Access Control Facility and the X-Ray Scanner. Integration of these joint efforts will support IOC in CY 2029.$$, $$Budget J-Books/FY27/Remaining/RDTE_Vol2_MDA_RDTE_PB27_Justification_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604112N$$, $$GERALD R FORD CI NUC AIRCRAFT CARRIER CVN 78-80$$, $$rdte_navy_ba4$$, $$peo_carriers$$, 2026, 112704000, 112593000, 96670000, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "navy", "page_num": 30, "original_pe": "0604112N", "page_header": "Department of the Navy"}$$::jsonb, $$This Navy program addresses unique technologies on Ford Class carriers. The program includes: - (2208) - Development of ship hull, mechanical, propulsion, electrical, aviation, and combat support systems, subsystems and components to significantly improve aircraft carrier affordability, manpower requirements, survivability, and operational capabilities, and to meet the requirements of existing and pending regulations and statutes critical to the operation of existing and future aircraft carriers. - (4004) - The Electromagnetic Aircraft Launch System (EMALS) is an advanced technology system developed as part of, and integrated on new FORD Class Carrier ships, beginning with CVN78. EMALS provides better control of applied forces, both peak and transient dynamic loads, improved reliability and maintainability, increased operational availability, and reduced operator and maintainer workload. The EMALS program will undergo future system improvements to address safety, obsolescence, and reliability. This Program Element (PE) and associated projects represent a continuation of efforts previously funded under PE 0603512N projects 2208 and 4004 in FY 2014 and earlier and PE 0604567N projects 3179, 3180, and 4007 in FY 2023 and earlier.$$, NULL, 74359000, 61270000, 55607000, NULL, NULL, 82, $$RDTEN_BA4_Book.pdf$$, NULL, FALSE, 91597000, 112704000, 111241000, 111241000, NULL, 111241000, 56688000, $$This Navy program addresses unique technologies on Ford Class carriers. The program includes: - (2208) - Development of ship hull, mechanical, propulsion, electrical, aviation, and combat support systems, subsystems and components to significantly improve aircraft carrier affordability, manpower requirements, survivability, and operational capabilities, and to meet the requirements of existing and pending regulations and statutes critical to the operation of existing and future aircraft carriers. - (4004) - The Electromagnetic Aircraft Launch System (EMALS) is an advanced technology system developed as part of, and integrated on new FORD Class Carrier ships, beginning with CVN 78. EMALS provides better control of applied forces, both peak and transient dynamic loads, improved reliability and maintainability, increased operational availability, and reduced operator and maintainer workload. The EMALS program will undergo future system improvements to address safety, obsolescence, and reliability. This Program Element (PE) and associated projects represent a continuation of efforts previously funded under PE 0603512N projects 2208 and 4004 in FY 2014 and earlier and PE 0604567N projects 3179, 3180, and 4007 in FY 2023 and earlier. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                  Date: April 2026 Appropriation/Budget Activity                                               R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 4: Advanced       PE 0604112N / GERALD R FORD CI NUC AIRCRAFT CARRIER CVN 78-80 Component Development & Prototypes (ACD&P)$$, $$Budget J-Books/FY27/Navy/RDTEN_BA4_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604114A$$, $$Lower Tier Air Missile Defense (LTAMD) Sensor$$, $$rdte_army_ba4$$, $$peo_iews$$, 2026, 210448000, 511014000, 127428000, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "army", "page_num": 15, "original_pe": "0604114A", "page_header": "Department of the Army"}$$::jsonb, $$This funding line is directly aligned to the Army Air and Missile Defense Modernization Priority. The Lower Tier Air Missile Defense Sensor (LTAMDS) is the Army's premier next generation radar intended to sense and track Tactical Ballistic Missiles and Air Breathing Threats; expand the lower tier air and missile defense battlespace and provide 360-degree sensing capability, surveillance, and fire control quality data. The LTAMDS Radar Set (RS) replaces the baseline Patriot RS (AN/MPQ-65A) in an Integrated Air and Missile Defense Battle Command System (IBCS) enabled Patriot Battalion mitigating risk associated with threat advances and decreases Operations and Support (O&S) costs due to growing obsolescence. Additionally, the LTAMDS RS capability maximizes the inherent PAC-3 Missile Segment Enhancement (MSE) Interceptor capabilities to engage threats at greater ranges addressing critical capability gaps, providing modernized technology, and increasing reliability and maintainability. Major LTAMDS Continuous Integration/Continuous Delivery (CI/CD) efforts include tactical software and model and simulation development, integration, and testing to increase overall LTAMDS capability against novel and stressing threats, thus providing the warfighter a leading advantage in a contested environment. Combat Identification/ Discrimination (CID) Updates: This includes CID development and upgrades to improve radar classification, discrimination, and optimization of multi-function capabilities to enhance performance against current and emerging threats in stressing environments. Upgrades play a critical role in increasing operational effectiveness by providing the warfighter enhanced command and control, effective resource allocation measures, and improved situational awareness. Advanced Threat Defeat: LTAMDS will continue to counter adversary threat evolution in complexity, capability, and capacity in simultaneous combatant commands. This development effort is required to continue to provide overmatch radar capability. Support: Product Development funding in FY 2026 supports development, integration, and modifications for LTAMDS support equipment to include the Large Tactical Power System (LTPS), M870A4 trailer, and M983A4 Heavy Expanded Mobility Tactical Truck (HEMTT) Light Equipment Transporters (LET). These upgrades ensure the support equipment remains compatible with evolving system capabilities. Test and Evaluation funding in FY 2026 supports the initiation of the LTAMDS IOT&E which includes a series of tests to validate system integration and optimized capabilities. Testing will focus on performance evaluation across a range of realistic operational scenarios and against various threat types. Initiation of this event is critical for ensuring LTAMDS readiness, assessing operational suitability, validating technical maturity, and achieving key program milestones. LTAMDS will initiate Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                                 Date: June 2025 Appropriation/Budget Activity                                                     R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 4: Advanced             PE 0604114A / Lower Tier Air Missile Defense (LTAMD) Sensor Component Development & Prototypes (ACD&P) IOT&E in FY 2026, starting with training, followed by a series of increasingly complex Missile Flight Tests (MFT) against a wide range of threat representatives. Funding also enables continuous transformation to conduct theater-level experimentation at command and joint levels within Combatant Commands. The FY 2026 request for Lower Tier Air Missile Defense (LTAMD) Sensor includes $196,448 thousand of discretionary and $14,000 thousand of mandatory (reconciliation) for a total of $210,448 thousand. The mandatory funds will develop and test new signal processing techniques and waveforms to enhance Electronic Attack and Electronic Protect techniques based on the evolving threat, further enhancing radar survival and effectiveness in contested complex environments. Further information for this reconciliation request is provided in Section 20003 (Missile Defense) of the Reconciliation Exhibit.$$, NULL, 153281000, 129316000, 139100000, NULL, NULL, 85, $$RDTE - Vol 2 - Budget Activity 4B.pdf$$, NULL, FALSE, 122777000, 192045000, 162074000, 162074000, NULL, 162074000, 140334000, $$This funding line is directly aligned to the Army Air and Missile Defense Modernization Priority. The LTAMDS Radar Set (RS) replaces the baseline Patriot RS (AN/MPQ-65A) in an Integrated Air and Missile Defense Battle Command System (IBCS) enabled Patriot Battalion mitigating risk associated with threat advances and decreases Operations and Support (O&S) costs due to growing obsolescence. Additionally, the LTAMDS RS capability maximizes the inherent PAC-3 Missile Segment Enhancement (MSE) Interceptor capabilities to engage threats at greater ranges addressing critical capability gaps, providing modernized technology, and increasing reliability and maintainability. The Lower Tier Air Missile Defense Sensor (LTAMDS) is the Army's premier next generation radar intended to sense and track Tactical Ballistic Missiles and Air Breathing Threats; expand the lower tier air and missile defense battle space and provide 360-degree sensing capability, surveillance, and fire control quality data. The FY 2027 request for LTAMDS includes $162.074 million to enhance capability through LTAMDS Continuous Integration and Continuous Delivery (CI/CD) of software and hardware, complete LTAMDS Initial Operational Test & Evaluation (IOT&E) events, and continue Electronic Attack/Electronic Protect (EA/EP) capability. Major LTAMDS CI/CD efforts include tactical software development, modeling and simulation, integration, and testing to increase overall LTAMDS capability against novel and stressing threats, thus providing the war fighter a leading advantage in a contested environment. Combat Identification (CID) / Discrimination Updates: This includes CID development and upgrades to improve radar classification, discrimination, and optimization of multi-function capabilities to enhance performance against current and emerging threats in stressing environments. Upgrades play a critical role in increasing operational effectiveness by providing the war fighter enhanced command and control, effective resource allocation measures, and improved situational awareness. Advanced Threat: LTAMDS will continue to counter adversary threat evolution in complexity, capability, and capacity in simultaneous combatant commands. This development effort is required to continue to provide over match radar capability. Test and Evaluation funding will prioritize critical missile flight tests integral to the LTAMDS Initial Operational Test & Evaluation (IOT&E). These tests are essential for validating system integration, optimizing capabilities, and ensuring LTAMDS readiness for deployment. The IOT&E program will rigorously assess performance against realistic operational scenarios and diverse threat profiles, while also validating technical maturity and achieving key program milestones. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                          Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 4: Advanced          PE 0604114A / Lower Tier Air Missile Defense (LTAMD) Sensor Component Development & Prototypes (ACD&P) Funding will also support continued development and implementation of new signal processing techniques and waveforms to enhance Electronic Attack and Electronic Protect (EA/EP) techniques based on the evolving threat, further enhancing radar survival and effectiveness in contested complex environments.$$, $$Budget J-Books/FY27/Army/RDTE - Vol 2 - Budget Activity 4B.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604115A$$, $$Technology Maturation Initiatives$$, $$rdte_army_ba4$$, $$asa_alt$$, 2026, 267619000, 244710000, 252000000, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "army", "page_num": 15, "original_pe": "0604115A", "page_header": "Department of the Army", "fy26_v182_disc_K": 324432, "fy26_v182_supp_K": 29300, "fy26_v182_total_K": 353732, "fy26_v182_note_name": "Technology Maturation Initiatives", "fy26_v182_source_file": "RDTE - Vol 2 - Budget Activity 4B.txt", "fy26_v182_source_line": 2976}$$::jsonb, $$This Program Element (PE) funds the Technology Maturation Initiative (TMI), which matures and integrates component technologies into early system and sub-system experimental prototypes for demonstration in relevant environments and tactical/operational scenarios. The Technology Maturation Initiative takes emerging Science and Technology (S&T) Technology Readiness Level (TRL) 6 products to a goal of TRL 7, integrating them into technology demonstrators and experimental prototypes that meet existing Program of Record (PoR) requirements and reduce the risk of technology insertion for future acquisition programs. This Initiative streamlines the development and insertion of mature technologies that support advanced ground systems; aviation systems; command, control, communication and reconnaissance systems and equipment; precision and hypersonic weapons; navigation and situational awareness systems; and Soldier equipment. It provides the Army an improved mechanism for incorporating innovative technologies and advanced capabilities in the early stages of acquisition program planning, and more closely aligns high-priority S&T products and Programs of Record modernization plans. This PE also provides a tiered evaluation and feasibility application of innovation and disruptive technologies to Army capability gaps at any stage in a technology's lifecycle. The project will partner with academia, small, non-traditional companies, and the defense industrial base to incubate ideas, stage pilot evaluations and to ensure more rapid integration and prototyping of the best, most innovative solutions into Army systems. Project teams comprised of both Science and Technology Subject Matter Experts (SMEs) and PoR technical leads to develop the project concept, execute the program, fabricate and evaluate the prototype, and develop the acquisition plan for incorporating the technology into the PoR upon successful evaluation of the prototype. Through the Army's Technology Maturation Board, Army senior leadership approves Technology Maturation Initiative projects prior to budget year programming based on priority and opportunity, ensuring that demonstrations have a high potential for filling capability gaps, and the project's plan for transitioning to Army PoRs. Approved Technology Maturation Initiative projects are typically 1-3 years in duration and are budgeted under Project AX3. The cited work is consistent with the Under Secretary of Defense, Research and Engineering priority focus areas and the Army Modernization Strategy. Work in this Project is performed by Assistant Secretary of the Army for Acquisition, Logistics and Technology and the Army Research, Development, Test and Evaluation (RDT&E) Enterprise. The FY 2026 request was reduced by $0.775 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative." Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                            Date: June 2025 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 4: Advanced         PE 0604115A / Technology Maturation Initiatives Component Development & Prototypes (ACD&P)$$, NULL, 278209000, 283542000, 289834000, NULL, NULL, 86, $$RDTE - Vol 2 - Budget Activity 4B.pdf$$, NULL, FALSE, 256806000, 353732000, 314671000, 314671000, NULL, 314671000, 294283000, $$This Program Element (PE) funds the Technology Maturation Initiative (TMI), which matures and integrates component technologies into experimental prototypes for demonstration in relevant environments and tactical/operational scenarios. The Technology Maturation Initiative takes emerging Technology Readiness Level (TRL) 6 products to a goal of TRL 7, integrating them into technology demonstrators and experimental prototypes for Army Service Component Commands, Army Corps, Army Divisions and below. This initiative streamlines the development and insertion of mature technologies that support ground and air maneuver; fires; command and control (C2) and counter C2; agile sustainment and ammunition; and layered protection plus chemical, biological, radiological, and nuclear. It provides the Army an improved mechanism for rapidly incorporating innovative technologies and advanced capabilities to support Secretary of War and Secretary of the Army Acquisition Reform efforts. This PE also provides a tiered evaluation and feasibility application of innovative and disruptive technologies to Army capability gaps at any stage in a technology's lifecycle. The project will partner with academia, small, non-traditional companies, and the defense industrial base to incubate ideas, stage pilot evaluations and to ensure more rapid integration and prototyping of the best, most innovative solutions into Army systems. Project teams comprised of both Technology Subject Matter Experts (SMEs) and Acquisition Program leads to develop the project concept, execute the program, fabricate and evaluate the prototype, and develop the path to scale for incorporating the technology upon successful evaluation of the prototype. The FY 2026 request was reduced by $0.775 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                              Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 4: Advanced          PE 0604115A / Technology Maturation Initiatives Component Development & Prototypes (ACD&P)$$, $$Budget J-Books/FY27/Army/RDTE - Vol 2 - Budget Activity 4B.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604115C$$, $$Technology Maturation Initiatives$$, $$rdte_dw_ba4$$, $$dw_mda$$, 2026, 0, 10000000, 2500000, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "dw", "page_num": 72, "original_pe": "0604115C", "page_header": "Defense-Wide"}$$::jsonb, $$Technology Maturation Initiatives (TMI) demonstrates the utility of directed energy for missile defense. The Missile Defense Agency's (MDA) directed energy plan incrementally demonstrates and improves the constituent components required to execute a directed energy acquisition, tracking, and lethality kill chain. The directed energy effort advances the technology readiness levels of emerging and developing technologies, while simultaneously assessing the performance and contributions to the Missile Defense System architecture. TMI included analysis, development, demonstration, systems engineering and test efforts to examine, develop, and improve directed energy systems, disruptive directed energy concepts, sensors, and future missile defense technologies. Directed Energy Demonstrator Development addressed technology risk reduction and maturation for high powered strategic lasers, beam control, lethality, and related technologies. The efforts remain tightly coupled with Office of the Undersecretary of Defense Research and Engineering (OUSD(R&E)) High Energy Laser Development Road Map, and are essential to mature strategic laser technology. MDA collaborates with the Combatant Commands, Defense Advanced Research Projects Agency, Department of Energy, Joint Directed Energy Transition Office, Military Departments, National Laboratories and OUSD(R&E) in a systems engineering based strategy to research, analyze, develop and test directed energy weapons technology. MDA continues to participate in the Department's Directed Energy Reviews. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Missile Defense Agency                                                   Date: June 2025 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 4:       PE 0604115C / Technology Maturation Initiatives Advanced Component Development & Prototypes (ACD&P)$$, NULL, 71000000, 76600000, 82700000, NULL, NULL, 103, $$RDTE_Vol2_MDA_RDTE_PB26_Justification_Book.pdf$$, $$MDA$$, FALSE, 2500000, 5000000, 59700000, 59700000, NULL, 59700000, 92900000, $$Technology Maturation Initiatives (TMI) demonstrates the utility of non-kinetics for missile defense applications. This initiative advances non-kinetic science and technology for missile defense by investing in the following critical areas: - Directed energy kill chain acceleration - Increases MDA investment in Directed Energy Demonstrators and Critical Components required for kill chain closure. Projects include next-generation advancements in thermal management, electrical storage, power generation, optical sources, and effects assessments. - Electronic protection - Provides for testing and demonstration of advanced electronic protection with Missile Defense System radars. - Multi-domain directed energy - This accelerates MDA's testing and demonstration of directed energy for missile defense. Projects include concept-of-operations refinement, automation, SWaP improvements, and integrated beam director applications. To enable the operational use of non-kinetics for missile defense on land, sea, air, or space platforms, SWaP scaling involves targeted advancements in several critical areas, including: - Increasing electrical- efficiency: Developing next-generation sources which directly reduces waste heat and lessens demands on the platform's power and cooling capacity. - Advanced thermal management: Researching and maturing lightweight cooling techniques capable of dissipating waste heat from a compact system, a key enabler for sustained high-power operations. - High-density power systems: Investing in miniaturized, high-density energy storage and power generation to meet the significant electrical demands of a high-power weapon system within a constrained volume. - Ruggedized beam directors: Engineering compact beam directors that are adaptable to multi-domain environments with minimal weight and footprint for Service proliferation. The Directed Energy Demonstrator Development project incrementally demonstrates and improves the components required for the acquisition, tracking, and lethality kill chain. This effort advances the Technology Readiness Levels (TRLs) of emerging technologies while assessing their performance and potential contributions to the Missile Defense System architecture. Through an agile systems engineering cycle, TMI examines, develops, tests, and improves disruptive non-kinetic technologies. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Missile Defense Agency                                                               Date: April 2026 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 4:             PE 0604115C / Technology Maturation Initiatives Advanced Component Development & Prototypes (ACD&P) TMI supports collaboration with partners across Industry, the Office of the Under Secretary of War for Research and Engineering, Combatant Commands, the Services, Defense Advanced Research Projects Agency, Department of Energy, Other Government Agencies, and the National Laboratories to mature and conduct demonstration/rapid prototype of non-kinetic weapons technology. The funds requested in this PE provide both legacy and Global Missile Defense Capability development for the United States, its deployed forces, allies, and partners. The capabilities funded by this budget request are complementary to the architecture funded by the Golden Dome Program's separate budget request and together fulfill the President's Executive Order 14186. The President's January 27, 2025, Executive Order established a goal of protecting the U.S. citizens, safeguarding critical infrastructure, and securing second-strike capability against missile attack from any adversary. This program and budget in addition to the budget requested by the Golden Dome Program Office reflects the changes necessary to protect the U.S. against ballistic, hypersonic, cruise, and other advanced missile threats.$$, $$Budget J-Books/FY27/Remaining/RDTE_Vol2_MDA_RDTE_PB27_Justification_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604117A$$, $$Maneuver - Short Range Air Defense (M-SHORAD)$$, $$rdte_army_ba4$$, $$asa_alt$$, 2026, 298367000, 290256000, 274542000, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "army", "page_num": 15, "original_pe": "0604117A", "page_header": "Department of the Army", "fy26_v182_disc_K": 236149, "fy26_v182_supp_K": 60150, "fy26_v182_total_K": 296299, "fy26_v182_note_name": "Maneuver - Short Range Air Defense (M-SHORAD)", "fy26_v182_source_file": "RDTE - Vol 2 - Budget Activity 4B.txt", "fy26_v182_source_line": 4444}$$::jsonb, $$This funding line is directly aligned to the Army Air and Missile Defense Modernization Priority. The FY 2026 request for M-SHORAD Increment 3 includes 152,677 thousand of discretionary and 60,120 thousand of mandatory (reconciliation) for a total of 212,797 thousand. The mandatory funds each competing vendor up to the approved cost position for the engineering and delivery of developmental test missiles. Further information for this reconciliation request is provided in Section 20004 (Munitions and Supply Chain) of the Reconciliation Exhibit. The Maneuver-Short Range Air Defense (M-SHORAD) capability provides air protection to the maneuvering forces by defeating, destroying, or neutralizing Rotary-Wing (RW), Fixed-Wing (FW), Unmanned Aircraft Systems (UAS), and Rockets, Artillery and Mortar (RAM) threats. This capability will be provided through a multi-phase, Family of Systems (FoS) approach, to include the rapidly fielded SGT STOUT (formerly known as Maneuver Short Range Air Defense - M SHORAD Inc. 1) and follow- on M-SHORAD Increments Inc. 2 and Inc. 3, as well as consideration for light and heavy platform variants. The M-SHORAD increments will develop additional capability and support Army demonstration and test initiatives to increase integrated offensive and defensive capability across warfighter functions and multiple domains. Project FI4: SGT STOUT is an Air Defense weapon system consisting of multiple ground-to-air missile launchers, sensors, and a gun integrated on a Stryker Combat Vehicle. The SGT STOUT system provides the Army improved capabilities for defense of maneuver formations and other tactical echelons from low altitude air attack and surveillance. The system is in response to an adaptive suite of airborne threat capabilities, supported by an integrated mix of surface-to-air and surface-to-surface shooters that threaten the ability of maneuver forces to conduct operations. Specifically, maneuver formations require the SGT STOUT air defense identification and defeat capabilities to counter FW, RW, and UAS threats. Project CR9: Inc. 2 will integrate a High Energy Laser (HEL) capability onto a tactical platform to provide an air defense capability to defeat RW, UAS, RAM, and Intelligence, Surveillance, and Reconnaissance (ISR) threats to the maneuvering forces and to inform transition of future enduring DE capabilities. Project CS1: Inc. 3 will provide a Next Generation Short Range Interceptor (NGSRI) to replace the existing Stinger missile. The new interceptor with support equipment will improve targeting capabilities to acquire targets with increased lethality and range, providing increased protection to the maneuver formations. Additionally, the Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                              Date: June 2025 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 4: Advanced         PE 0604117A / Maneuver - Short Range Air Defense (M-SHORAD) Component Development & Prototypes (ACD&P) NGSRI will be compatible with the existing SGT STOUT platform and will provide a Soldier Portable Capability to meet the need for dismounted Air Defense. Inc. 3 will integrate the SGT STOUT platform with the NGSRI and the new 30mm Multi-Mode Proximity Airburst (MMPA) ammunition. The FY 2026 cost of the M-SHORAD Inc. 3 Middle Tier of Acquisition effort is $170.8 million, including RDT&E and procurement of prototype units. The Department will certify FYDP funding in a future budget submission. M-SHORAD is part of the Army Transformation Initiative. The FY 2026 request for Maneuver - Short Range Air Defense (M-SHORAD) includes $238,247 thousand of discretionary and $60,120 thousand of mandatory (reconciliation) for a total of $298,247 thousand. The mandatory funds each competing vendor up to the approved cost position for the engineering and delivery of developmental test missiles. Further information for this reconciliation request is provided in Section 20004 (Munitions and Supply Chain) of the Reconciliation Exhibit. The FY 2026 request was reduced by $4.239 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative."$$, NULL, 292260000, 214203000, 121555000, NULL, NULL, 87, $$RDTE - Vol 2 - Budget Activity 4B.pdf$$, NULL, FALSE, 264521000, 296299000, 460980000, 460980000, NULL, 460980000, 34424000, $$This funding line is directly aligned to the Army Air and Missile Defense Modernization Priority. The Maneuver-Short Range Air Defense (M-SHORAD) capability provides air protection to the maneuvering forces by defeating, destroying, or neutralizing Rotary- Wing (RW), Fixed-Wing (FW), Unmanned Aircraft Systems (UAS), and Rockets, Artillery and Mortar (RAM) threats. This capability will be provided through a multi- phase, Family of Systems (FoS) approach, to include the rapidly fielded SGT STOUT (formerly known as Maneuver Short Range Air Defense - M SHORAD Inc. 1) and follow-on M-SHORAD Increments 2, 3, and 4 in support of light platform variants. The M-SHORAD increments will develop additional capability and support Army demonstration and test initiatives to increase integrated offensive and defensive capability across warfighter functions and multiple domains. Project CR9: Inc. 2 will integrate a High Energy Laser (HEL) capability onto a tactical platform to provide an air defense capability to defeat RW, UAS, RAM, and Intelligence, Surveillance, and Reconnaissance (ISR) threats to the maneuvering forces and to inform future enduring DE capabilities. Project CS1: Inc. 3 will provide a Next Generation Short Range Interceptor (NGSRI) to replace the existing Stinger missile. The new interceptor will improve targeting capabilities to acquire targets with increased lethality and range, providing increased protection to the maneuver formations. Additionally, the NGSRI will be compatible with the existing SGT STOUT platform and will provide a Soldier Portable Capability to meet the need for dismounted Air Defense. Inc. 3 will integrate the SGT STOUT platform with the NGSRI and the new 30mm Multi-Mode Proximity Airburst (MMPA) ammunition. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                               Date: April 2026 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 4: Advanced        PE 0604117A / Maneuver - Short Range Air Defense (M-SHORAD) Component Development & Prototypes (ACD&P) The total cost of the M-SHORAD Increment 3 (NGSRI) Middle Tier of Acquisition effort is $816.1 million RDT&E from FY 2023 to FY 2028. M-SHORAD Inc. 3 is fully funded across the Future Years Defense Program. Project DO5: Directed Energy Enhancements will increase DE system performance and further subsystem upgrades to address counter-rockets, artillery, and mortar (C-RAM) and counter rotary wing (RW) threats. Additionally, enhancements will assess size, weight and power (SWaP) to allow integration onto smaller and light tactical platforms. Project DP7: Inc. 4 provides Short Range Air Defense capability for Joint Forcible Entry (JFE) and Mobile Brigade Combat Team (MBCT) forces. Project FI4: SGT STOUT will develop product improvements and associated Training Aids, Devices, Simulators, and Simulations (TADSS). This funding will enhance system lethality and survivability against evolving low-altitude air threats (FW, RW, UAS) and develop the essential TADSS required to ensure soldier proficiency and mission readiness for maneuver force protection. The total cost of the SGT STOUT Middle Tier of Acquisition (MTA) Rapid Fielding (RF) effort is $1,732.5 million from FY24 to FY26, including RDT&E ($41.9M) and procurement ($1,690.6M) of prototype units. The remainder of the SGT STOUT MTA RF is fully funded across the Future Years Defense Program.$$, $$Budget J-Books/FY27/Army/RDTE - Vol 2 - Budget Activity 4B.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604119A$$, $$Army Advanced Component Development &$$, $$rdte_army_ba4$$, $$asa_alt$$, 2026, 0, 204914000, 0, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "army", "page_num": 15, "fy26_v180": {"note": "R1_FY26_entry_no_value_extracted_in_original_ingest", "source": "b1_null_zero_v180"}, "original_pe": "0604119A", "page_header": "Department of the Army"}$$::jsonb, $$The Advance Component Development & Prototype budget line includes multiple efforts across the Army's Battlefield Operational Systems necessary to evaluate integrated technologies in the most high fidelity and realistic operating environment as possible to assess the performance or cost reduction potential of advanced technology. Projects focus on proving component and subsystem maturity prior to integration in major and complex systems and may involve risk reduction initiatives. Efforts also includes advanced technology demonstrations to expedite technology transition from the laboratory to operational use, with the goal of transitioning systems into the acquisition process within the FYDP.$$, NULL, NULL, NULL, NULL, NULL, NULL, 88, $$RDTE - Vol 2 - Budget Activity 4B.pdf$$, NULL, FALSE, NULL, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604120A$$, $$Assured Positioning, Navigation and Timing (PNT)$$, $$rdte_army_ba4$$, $$cft_c4isr$$, 2026, 8686000, 39223000, 24168000, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "army", "page_num": 15, "original_pe": "0604120A", "page_header": "Department of the Army"}$$::jsonb, $$This funding line is directly aligned to the Army Assured Positioning, Navigation and Timing modernization priority. The Assured Positioning, Navigation and Timing (APNT) capability provides Army ground maneuver forces access to M-Code and assured PNT in accordance with National Defense Authorization Act guidance under conditions where Global Positioning Systems (GPS) may be limited or denied (jammed and spoofed). APNT products are ruggedized tactical systems that enable Army forces the ability to shoot, move, communicate, thereby allowing forces to maneuver from operational and strategic distances to close with, destroy, and exploit the enemy with sufficient combat power, tempo, and momentum. APNT addresses two critical capability gaps: Access and Integrity. Access is the ability to retrieve accurate PNT information in a contested Electronic Warfare/Cyber environment. Integrity is the ability to trust the PNT information. PNT is a critical enabler of many Army Maneuver, Fires, Intelligence, Mission Command and communications that are dependent on accurate Position and Timing, and a foundational Multi-Domain Battle capability to support: calibrated force posture (position and maneuver across strategic distances); multi-domain formations (operate in contested spaces against near-peer adversaries); convergence (continuous integration of capabilities in all domains). APNT capabilities provide critical support to the execution of the Army's Deliberate Transformation as well as Transformation in Contact and the Next Generation Command and Control (NGC2) environment. Approved Requirements: The Army Requirements Oversight Council (AROC) approved the Alternative Navigation (ALTNAV) Abbreviated Capabilities Development Document (A-CDD) in 29 August 2022. The Joint Requirements Oversight Council (JROC) approved the Dismounted APNT System (DAPS) Capabilities Development Document (CDD) on 28 January 2022. The Army Requirements Oversight Council (AROC) approved the Mounted APNT System (MAPS) CDD on 12 September 2020. MAPS and DAPS are implementing Congressional and OSD guidance to develop and field Military Code (M-Code) Global Positioning System (GPS) Ground user Equipment. The AROC approved the Command, Control, Communications, Computers, Cyber, Intelligence, Surveillance, and Reconnaissance (C5ISR) Modular Open Suite of Standards (CMOSS) Mounted Form Factor (CMFF) Abbreviated Capabilities Development Document (A-CDD) on 04 January 2021. In support of House Report 116-442, 2020, the program will prototype modular cards and software according to the Modular Open System Approach (MOSA) standards, for future modernization and new weapons systems. Joint Requirements Oversight Council Memo (JROCM) 049-10, dated 05 April 2010, approved the PNT Assurance Initial Capabilities Document and designated the Army as the Lead Component for Assured PNT. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                             Date: June 2025 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 4: Advanced           PE 0604120A / Assured Positioning, Navigation and Timing (PNT) Component Development & Prototypes (ACD&P) (BV4) - PE 0604120/BV4 has no Base funds requested in FY 2026. The Area Protection and Alternative Navigation project line funded the Alternative Navigation (ALTNAV) Ground Control Segment (GCS) development effort. The ALTNAV GCS is a global navigation solution providing warfighters with an alternative source of positioning and timing information. In accordance with National Defense Authorization Act (NDAA) Guidance (2021 NDAA: Section 1611), ALTNAV GCS is a complementary capability to Global Positioning System. ALTNAV GCS may be used as contingency in the PNT PACE (Primary, Alternative, Contingency, Emergency) Plan that facilitates continued operations as GPS is degraded or denied. ALTNAV GCS effort formally became a Middle Tier of Acquisition - Rapid Fielding (MTA-RF) program in FY24. The total cost of the ALTNAV Middle Tier of Acquisition effort is $106.1M procurement from FY24-FY27 and is a single global alternative PNT system. The $106.1M ALTNAV requirement is fully funded across the Future Years Defense Program. (ED5) - The Assured Positioning Navigation Timing project develops APNT Modernization prototypes that will develop the next generation of PNT solutions for clients and vehicular platforms. It will fully implement a Modular Open Systems Approach (MOSA), incorporate Military GPS User Equipment (MGUE) Increment 2, and improve complimentary PNT capability that provides accurate positioning and timing in the absence of GPS for extended missions. The Assured Positioning Navigation Timing is also developing developed a Command, Control, Communications, Computers, Cyber, Intelligence, Surveillance, and Reconnaissance (C5ISR) Modular Open Suite of Standards (CMOSS) Mounted Form Factor (CMFF) APNT Card. These two efforts will enable the transition of incremental and disruptive technologies to fieldable PNT solutions to pace or overmatch current and evolving threats in accordance with National Defense Authorization Act (NDAA) Guidance (2021 NDAA: Section 1611). Starting in FY 2026 the CMFF APNT Card effort was realigned ($5.365M) to Budget Activity-5 (BA-5) DL9 Project Code APNT Cards C5ISR Mounted Form Factor (CMFF) within PE 0604805A Command, Control, Communications Systems - Eng Dev. (EH8) - PE 0604120/EH8 has no Base funds requested in FY 2026. The Dismounted APNT System (DAPS) meets congressional (10 USC 2281) and Department of Defense guidance to provide resilient and survivable M-Code Global Positioning System (GPS) capable Ground User Equipment (MGUE) receivers and Alternative Navigation (ALTNAV). The DAPS provides Soldiers Assured PNT (APNT) information utilizing various sources of PNT data to address multiple threats and ensure mission success where Global Positioning System (GPS) may be limited or denied. DAPS delivers APNT in an optimized form factor that supports mission profiles in denied environments. (EJ2) - PE 0604120/EJ2 has no Base funds requested in FY 2026. The Mounted APNT System (MAPS) meets congressional (10 USC 2281) and Department of Defense guidance to provide resilient and survivable M-Code GPS capable MGUE receivers and ALTNAV. The MAPS will deliver systems that provide the Army's combat forces access to assured PNT information under conditions where space-based GPS may be limited or denied to enable Army forces the ability to move, shoot, communicate, and provide situational awareness. The FY 2026 request was reduced by $0.27 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative." Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                              Date: June 2025 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 4: Advanced          PE 0604120A / Assured Positioning, Navigation and Timing (PNT) Component Development & Prototypes (ACD&P)$$, NULL, 17873000, 12419000, 13208000, NULL, NULL, 89, $$RDTE - Vol 2 - Budget Activity 4B.pdf$$, NULL, FALSE, 20969000, 8686000, 18993000, 18993000, NULL, 18993000, 13339000, $$This funding line is directly aligned to the Army Assured Positioning, Navigation and Timing modernization priority. The Assured Positioning, Navigation and Timing (APNT) capability provides Army ground maneuver forces access to Military Code (M-Code) and assured PNT in accordance with National Defense Authorization Act guidance under conditions where Global Positioning Systems (GPS) may be limited or denied (jammed and spoofed). APNT products are ruggedized tactical systems that enable Army forces the ability to shoot, move, communicate, thereby allowing forces to maneuver from operational and strategic distances to close with, destroy, and exploit the enemy with sufficient combat power, tempo, and momentum. APNT addresses two critical capability gaps: Access and Integrity. Access is the ability to retrieve accurate PNT information in a contested Electronic Warfare/Cyber environment. Integrity is the ability to trust the PNT information. PNT is a critical enabler of many Army Maneuver, Fires, Intelligence, Mission Command and communications that are dependent on accurate Position and Timing, and a foundational Multi-Domain Battle capability to support: calibrated force posture (position and maneuver across strategic distances); multi-domain formations (operate in contested spaces against near-peer adversaries); convergence (continuous integration of capabilities in all domains). Approved Requirements: The Alternative Navigation (ALTNAV) Abbreviated Capabilities Development Document (A-CDD) on 29 August 2022; the Dismounted APNT System (DAPS) Capabilities Development Document (CDD) on 28 January 2022; the Mounted APNT System (MAPS) CDD on 12 September 2020. MAPS and DAPS are implementing Congressional and OSW guidance to develop and field Military Code (M-Code) Global Positioning System (GPS) Ground user Equipment. The Command, Control, Communications, Computers, Cyber, Intelligence, Surveillance, and Reconnaissance (C5ISR) Modular Open Suite of Standards (CMOSS) Mounted Form Factor (CMFF) A-CDD on 04 January 2021. (ED5) - The Assured Positioning Navigation and Timing project develops APNT Modernization prototypes that will develop the next generation of PNT solutions for clients and vehicular platforms. It will fully implement a Modular Open Systems Approach (MOSA), support future integration of Military GPS User Equipment (MGUE) Increment 2, and improve complimentary PNT capability that provides accurate positioning and timing in the absence of GPS for extended missions. The Assured Positioning Navigation Timing is also developing developed a Command, Control, Communications, Computers, Cyber, Intelligence, Surveillance, and Reconnaissance (C5ISR) Modular Open Suite of Standards (CMOSS) Mounted Form Factor (CMFF) APNT Card. These two efforts will enable the transition of incremental and complimentary technologies to fieldable PNT solutions to pace or overmatch current and evolving threats in accordance with National Defense Authorization Act (NDAA) Guidance (2021 NDAA: Section 1611). Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                           Date: April 2026 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 4: Advanced            PE 0604120A / Assured Positioning, Navigation and Timing (PNT) Component Development & Prototypes (ACD&P) (EH8) - The Dismounted APNT System (DAPS) meets congressional (10 USC 2281) and Department of War guidance to provide resilient and survivable M-Code Global Positioning System (GPS) capable Ground User Equipment (MGUE) receivers and Alternative Navigation (ALTNAV). The DAPS provides Soldiers Assured PNT (APNT) information utilizing various sources of PNT data to address multiple threats and ensure mission success where Global Positioning System (GPS) may be limited or denied. DAPS delivers APNT in an optimized form factor that supports mission profiles in denied environments.$$, $$Budget J-Books/FY27/Army/RDTE - Vol 2 - Budget Activity 4B.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604121A$$, $$Synthetic Training Environment Refinement & Prototyping$$, $$rdte_army_ba4$$, $$peo_stri$$, 2026, 240899000, 115519000, 115140000, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "army", "page_num": 15, "original_pe": "0604121A", "page_header": "Department of the Army"}$$::jsonb, $$STE-Software (STE-SW) was previously referred to as STE-lnformation System (STE-IS). These funding lines are directly aligned to the Army Synthetic Training Environment (STE) Modernization Priority. STE continues to support the SECARMY and CSA's guidance on the Army's continuous transformation to become more lethal in the live, virtual and constructive training environments enabling Commanders to prioritize time and resources towards building lethality and cohesive teams. STE continues to develop and deliver capabilities that enable Soldiers to shoot, move, communicate, and be experts in their craft through tough, realistic squad to brigade level individual/collective training tasks. The Synthetic Training Environment (STE) is the next generation holistic combined arms collective training capability that will enable leaders, Soldiers, and units from Squad through Army Service Component Command to train where they will fight, with the partners they will fight with, and in complex operational environments in support of Multi-Domain Operations (MDO). STE will revolutionize Army training by providing the repetition necessary at the Point of Need (PoN) for improved proficiency prior to live training or operations- improving Soldier lethality and survivability. The STE program has multiple Other Transaction Authority (OTA) contracts awarded and will implement an incremental fielding approach leveraging the Software Acquisition pathway (SWP) and the Middle Tier of Acquisition (MTA) pathway. The STE will be available where training occurs (home station, combat training centers, armories, institutions, and deployed locations). The STE is comprised of five main signature efforts: 1) STE-Software (STE-SW); 2) Reconfigurable Virtual Collective Trainers (RVCT); 3) Squad Immersive Virtual Trainer (SiVT), in partnership with Soldier Lethality's Integrated Visual Augmentation System (IVAS) program); 4) STE Live; and 5) Soldier Virtual Trainer. STE-SW is comprised of Synthetic Training Environment training capability consisting of One World Terrain (OWT), Training Simulation Software (TSS), Training Management Tools (TMT), and Next Generation Constructive (NGC). The RVCT will allow units to collectively train, using proponent developed Combined Arms Training Strategies (CATS), on a simulated, fully interactive, real-time battlefield. Squad Immersive Virtual Trainer (SiVT) is the immersive training capability delivered as part of the IVAS for the close combat Squads that enables IVAS to be a fight, rehearse, and training platform. STE Live focuses on the development of twelve engagement types and Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                                Date: June 2025 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 4: Advanced           PE 0604121A / Synthetic Training Environment Refinement & Prototyping Component Development & Prototypes (ACD&P) five instrumentation enablers. The twelve engagement types are direct fire, counter-defilade fire, indirect fire, dropped objects, placed objects, thrown objects, guided weapons, autonomous weapons, cyber, directed energy, radiant energy, and plume; the five instrumentation enablers are calculations, networks, sensors, terrains, and transmitters. SVT will provide training to Soldiers Army wide by providing Weapons Skills Development (WSD) and Joint Fires Trainer (JFT). The FY 2026 cost of the Synthetic Training Environment-Live Training System (STE-LTS) Middle Tier of Acquisition (MTA) effort is $44.7 million, including RDT&E and procurement of prototype units. The Department will certify FYDP funding in a future budget submission. The FY 2026 cost of the Reconfigurable Virtual Collective Trainer (RVCT) Middle Tier Acquisition (MTA) effort is $7.4 million, including RDT&E and procurement of prototype units. The Department will certify FYDP funding in a future budget submission. The FY 2026 cost of the Soldier Virtual Trainer (SVT) Middle Tier of Acquisition (MTA) effort is $37.4 million, including RDT&E and procurement of prototype units. The Department will certify FYDP funding in a future budget submission. Synthetic Training Environment Refinement & Prototyping is part of the Army Transformation Initiative. The FY 2026 request was reduced by $1.165 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative."$$, NULL, 192272000, 179494000, 169156000, NULL, NULL, 90, $$RDTE - Vol 2 - Budget Activity 4B.pdf$$, NULL, FALSE, 110937000, 176657000, 219137000, 219137000, NULL, 219137000, 160747000, $$STE-Software (STE-SW) was previously referred to as STE-lnformation System (STE-IS). These funding lines are directly aligned to the Army Synthetic Training Environment (STE) Modernization Priority. STE continues to support the Army's focus to become more lethal in the live, virtual and constructive training environments enabling Commanders to prioritize time and resources towards building lethality and cohesive teams. STE continues to develop and deliver capabilities that enable Soldiers to shoot, move, communicate, and be experts in their craft through tough, realistic squad to brigade level individual/collective training tasks. The Synthetic Training Environment (STE) is the next generation holistic combined arms collective training capability that will enable leaders, Soldiers, and units from Squad through Army Service Component Command to train where they will fight, with the partners they will fight with, and in complex operational environments in support of Multi-Domain Operations (MDO). STE will revolutionize Army training by providing the repetition necessary at the Point of Need (PoN) for improved proficiency prior to live training or operations- improving Soldier lethality and survivability. The STE program has multiple Other Transaction Authority (OTA) contracts awarded and will implement an incremental fielding approach leveraging the Software Acquisition pathway (SWP) and the Middle Tier of Acquisition (MTA) pathway. The STE will be available where training occurs (home station, combat training centers, armories, institutions, and deployed locations). The STE is comprised of four main signature efforts: 1) STE-Software (STE-SW); 2) Reconfigurable Virtual Collective Trainers (RVCT); 3) STE Live; and 4) Soldier Virtual Trainer. STE-SW is comprised of Synthetic Training Environment training capability consisting of One World Terrain (OWT), Training Simulation Software (TSS), Training Management Tools (TMT), and Next Generation Constructive (NGC). The RVCT will allow units to collectively train, using proponent developed Combined Arms Training Strategies (CATS), on a simulated, fully interactive, real-time battlefield. STE Live focuses on the development of twelve engagement types and five instrumentation enablers. The twelve engagement types are direct fire, counter-defilade fire, indirect fire, dropped objects, placed objects, thrown objects, guided Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                            Date: April 2026 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 4: Advanced           PE 0604121A / Synthetic Training Environment Refinement & Prototyping Component Development & Prototypes (ACD&P) weapons, autonomous weapons, cyber, directed energy, radiant energy, and plume; the five instrumentation enablers are calculations, networks, sensors, terrains, and transmitters. SVT will provide training to Soldiers Army wide by providing Weapons Skills Development (WSD) and Joint Fires Trainer (JFT). The total cost of the STE-LTS MTA Rapid Prototyping (RP) effort is $232.0 million RDT&E from FY 2022 to FY 2026. The total cost of the RVCT MTA Rapid RP effort is $27.9 million RDT&E from FY 2022 to FY 2026. The total cost of the RVCT MTA Rapid Fielding (RF) effort is $730.1 million from FY 2023 to FY 2028, including RDT&E ($37.7M) and procurement ($692.4M) of prototype units. The total cost of the SVT MTA RP effort is $110.2 million from FY 2022 to FY 2027, including RDT&E ($102.9M) and procurement ($7.3M) of prototype units.$$, $$Budget J-Books/FY27/Army/RDTE - Vol 2 - Budget Activity 4B.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604124D8Z$$, $$Chief Digital and Artificial Intelligence Officer (CDAO) - MIP$$, $$rdte_dw_ba4$$, $$dw_cdao$$, 2026, 0, 45332000, 0, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "dw", "page_num": 72, "original_pe": "0604124D8Z", "page_header": "Defense-Wide"}$$::jsonb, $$The Chief Digital and Artificial Intelligence Officer (CDAO) supports the Department's initiatives to build enduring advantage and build a resilient Joint Force and defense ecosystem. The CDAO is responsible for strengthening and integrating data, artificial intelligence, and digital solutions in the Department in support of the interim National Defense Strategy and Section 1513 of the National Defense Authorization Act (NDAA) for FY 2023. The functions of the CDAO are as follows: lead and oversee the DoD’s strategy development and policy formulation for data, analytics, and AI; break down barriers to data and AI adoption within DoD institutional processes; create enabling digital infrastructure and services that support Components’ development and deployment of data, analytics, AI, and digital-enabled solutions; selectively scale proven digital and AI-enabled solutions focused on enterprise and joint use cases; and surge digital services for rapid response to crises and emergent challenges. The CDAO will continue priority projects that align to the mission. This includes expanding the AI integration between the DoD and Intelligence Community (IC); enterprise data repository; establishing a responsible AI ecosystem; executing the AI and Data Accelerator (ADA) initiative; and developing a Data, Analytics, and AI Adoption Strategy. These various lines of effort will support the overarching mission of accelerating the Department’s adoption of data, analytics, and AI to preserve decision advantage across the Joint Force. The CDAO’s DoD and IC Integration Division was chartered to create joint interoperability and to harness and scale AI across the DoD and IC jointly, especially within the Defense Intelligence Enterprise. The organizational purpose is to improve coordination and interoperability between DoD and the IC, minimize duplication while maximizing a common approach, and develop an innovated joint AI operational concept and capability, where appropriate. This funding is assigned to support algorithm development, data preparation, and integration experimentation to create joint DoD and IC capabilities. Further details are classified and available upon request. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Office of the Secretary Of Defense                                           Date: June 2025 Appropriation/Budget Activity                                             R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 4:      PE 0604124D8Z / Chief Digital and Artificial Intelligence Officer (CDAO) - MIP Advanced Component Development & Prototypes (ACD&P)$$, NULL, NULL, NULL, NULL, NULL, NULL, 104, $$RDTE_OSD_PB_2026.pdf$$, $$OSD$$, FALSE, 10315000, 0, NULL, NULL, NULL, NULL, NULL, $$The Chief Digital and Artificial Intelligence Officer (CDAO) supports the Department's initiatives to build enduring advantage and build a resilient Joint Force and defense ecosystem. The CDAO is responsible for strengthening and integrating data, artificial intelligence, and digital solutions in the Department in support of the interim National Defense Strategy and Section 1513 of the National Defense Authorization Act (NDAA) for FY 2023. The functions of the CDAO are as follows: lead and oversee the DoW’s strategy development and policy formulation for data, analytics, and AI; break down barriers to data and AI adoption within DoW institutional processes; create enabling digital infrastructure and services that support Components’ development and deployment of data, analytics, AI, and digital-enabled solutions; selectively scale proven digital and AI-enabled solutions focused on enterprise and joint use cases; and surge digital services for rapid response to crises and emergent challenges. The CDAO will continue priority projects that align to the mission. This includes expanding the AI integration between the DoW and Intelligence Community (IC); enterprise data repository; establishing a responsible AI ecosystem; executing the AI and Data Accelerator (ADA) initiative; and developing a Data, Analytics, and AI Adoption Strategy. These various lines of effort will support the overarching mission of accelerating the Department’s adoption of data, analytics, and AI to preserve decision advantage across the Joint Force. The CDAO’s DoW and IC Integration Division was chartered to create joint interoperability and to harness and scale AI across the DoW and IC jointly, especially within the Defense Intelligence Enterprise. The organizational purpose is to improve coordination and interoperability between DoW and the IC, minimize duplication while maximizing a common approach, and develop an innovated joint AI operational concept and capability, where appropriate. This funding is assigned to support algorithm development, data preparation, and integration experimentation to create joint DoW and IC capabilities. Further details are classified and available upon request. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Office of the Secretary Of Defense                                           Date: April 2026 Appropriation/Budget Activity                                             R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 4:      PE 0604124D8Z / Chief Digital and Artificial Intelligence Officer (CDAO) - MIP Advanced Component Development & Prototypes (ACD&P)$$, $$Budget J-Books/FY27/DW/RDTE_OSW_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$P_1810_L054$$, $$NAVSTAR GPS Receivers (Space)$$, $$proc_navy_1810_ba2$$, $$navsea$$, 2026, 7972000, 14105000, 13614000, NULL, $${"page": 98, "ba_num": "02", "source": "p1_fy26", "ba_name": "Communications and electronics equipment", "line_no": "54", "service": "navy", "fy24_qty": null, "fy25_qty": null, "fy27_v25": {"ba": "02", "appr": "OPN", "title": "P-1 Line 50", "applied_at": "2026-05-09", "fy27_ooc_K": 0, "source_pdf": "Budget J-Books/FY27/Navy/OPN_BA{1..5-8}_Book.pdf", "fy27_base_K": 10108, "p1_line_num": 50, "fy27_total_K": 10108}, "appr_code": "1810", "appr_name": "Other Procurement, Navy", "fy26_v179": {"disc_K": 7972, "li_num": 50, "source": "p40_fy26_v179", "supp_K": 0, "source_pdf": "uploads/Budget J-Books/FY27/Navy/OPN_BA2_Book.txt"}, "fy26t_qty": null, "fy26d_cost": 7972000, "fy26r_cost": 0, "ident_code": "A"}$$::jsonb, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, FALSE, 35507000, 42241000, 10108000, 10108000, 0, 10108000, NULL, NULL, $$Budget J-Books/FY27/Navy/OPN_BA2_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604125D8Z$$, $$Advanced Manufacturing Components and Prototypes$$, $$rdte_dw_ba4$$, $$dw$$, 2026, 45513000, 0, 21776000, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "dw", "page_num": 72, "original_pe": "0604125D8Z", "page_header": "Defense-Wide"}$$::jsonb, $$The Advanced Manufacturing Components and Prototypes (AMCAP) program is established to validate the build and/or expansion of advanced manufacturing infrastructure and conduct research, develop, test, and evaluation (RDT&E) to facilitate development and transition of promising advanced manufacturing technologies to higher manufacturing readiness levels (MRL) via component and prototype development. Funding for this program is focused on requirements emerging from the Defense Biomanufacturing Strategy, which is guiding the execution of the Distributed Bioindustrial Manufacturing Program (DBIMP) – formerly known as the Manufacturing Enabled by Modular and Reusable (MEMBR) assets initiative investments to scale up domestic manufacturing of bioindustrial products. The project under this program will cover the full range of technologies critical to the Department of Defense (DoD) and manufacturing technologies with dual-use commercial applications to support the industrial base that will supply the DoD.$$, NULL, 55738000, 55980000, 55568000, NULL, NULL, 105, $$RDTE_OSD_PB_2026.pdf$$, $$OSD$$, FALSE, 21193000, 64801000, 52122000, 52122000, NULL, 52122000, 56666000, $$The Advanced Manufacturing Components and Prototypes (AMCAP) program is established to validate the build and/or expansion of advanced manufacturing infrastructure and conduct research, develop, test, and evaluation (RDT&E) to facilitate development and transition of promising advanced manufacturing technologies to higher manufacturing readiness levels (MRL) via component and prototype development. Funding for this program is focused on requirements emerging from the Defense Biomanufacturing Strategy, which is guiding the execution of the Distributed Bioindustrial Manufacturing Program (DBIMP) – formerly known as the Manufacturing Enabled by Modular and Reusable (MEMBR) assets initiative investments to scale up domestic manufacturing of bioindustrial products. The project under this program will cover the full range of technologies critical to the Department of War (DoW) and manufacturing technologies with dual-use commercial applications to support the industrial base that will supply the DoW.$$, $$Budget J-Books/FY27/DW/RDTE_OSW_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604127N$$, $$Surface Mine Countermeasures$$, $$rdte_navy_ba4$$, $$navy_n9$$, 2026, 18504000, 15524000, 15271000, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "navy", "page_num": 30, "original_pe": "0604127N", "page_header": "Department of the Navy"}$$::jsonb, $$The Surface Mine Countermeasures (SMCM) Program Element (PE) provides resources in support of development of mine countermeasures systems to provide minehunting and neutralization to counter known and projected mine threats. The mine countermeasures systems provide mobile, quick reaction forces capable of land or sea-based minehunting and neutralizing operations worldwide. Resources are for developing and deploying advanced minehunting and neutralization systems and the intelligence and oceanographic capabilities that will enable mine warfare superiority. Tactics and techniques used vary across a diversity of environments and a diversity of threats, including both asymmetric and emerging. Resources provide for systems and support of mine warfare systems, maritime systems, and expeditionary systems to allow for continuous operations of the Navy's warships and support vessels, other military vessels, and commercial vessels. Increased capability includes conducting minefield reconnaissance (mine density and location) at high area search rates; improving detection capability; decreasing sensor false alarm rates; reducing or eliminating post-mission analysis detect, classify, identify, decide time; improving neutralization time; improving network communications; automatic target recognition; and achieving in-stride detect-to-engage capability. The Surface Mine Countermeasures programs are in general platform independent and will provide detection, classification, localization, identification, neutralization, and influence clearance capabilities. Programs develop: (1) Unmanned minehunting capability for surface platforms; (2) the integration and improvement of new and existing systems (3) support for systems which detect, localize, classify, identify, and neutralize all mine types across MCM Avenger Class (MCM-1), Littoral Combat Ship (LCS) Class and other platforms. 1) The AN/AQS-20 is a minehunting and identification system with sensors housed in an underwater towed body. The sensors are designed for the detection, classification and localization of bottom, close-tethered, and volume targets, and for the identification of bottom targets. The system can be deployed from the Littoral Combat Ship (LCS) as part of the MCM Mission Package or can be deployed from other Vessels of Opportunity (VOO). The MCM USV is the tow platform for the AN/ AQS-20. 2) AN/SQQ-32(V)4 High-Frequency, Wide Band (HFWB) is a technology upgrade to the AN/SQQ-32 Towed Body which incorporated HFWB technology into the detection sonar to address performance deficiencies against new mine threats in the littorals. This upgrade was installed on MCM-1 Class ships. 3) AN/SLQ-60 Mine Neutralization System (MNS) Seafox on the MCM Class ships. MNS is the replacement to the existing AN/SLQ-48 Mine Neutralization System. 4) Mine Warfare and Environmental Decision Aids Library (MEDAL) is the U.S. Navy's single Mine Warfare (MIW) tactical decision support system for integrated mission planning, evaluation, and situational awareness. MEDAL provides mine warfare planning and evaluation tools and databases to Maritime Component Commander and is employed at the unit level to perform mining and MCM planning and evaluation. The current MEDAL increment, known as MEDAL Enterprise Architecture (EA), is no Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Navy                                                                                 Date: June 2025 Appropriation/Budget Activity                                                      R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 4: Advanced              PE 0604127N / Surface Mine Countermeasures Component Development & Prototypes (ACD&P) longer dependent on Global Command and Control System - Maritime (GCCS-M) for fielding to MIW fleet users. MEDAL EA is a family of systems, comprised of the following three components: MINEnet Global, MINEnet Tactical, and Minefield Planning (MFP). MINEnet Global is a shore-based website that provides MIW waterspace awareness functionality to support Navy non-MIW forces. MINEnet Global provides downloadable reference databases, MIW reference publications and links to MIW information. The MINEnet Tactical component is a software application which provides MCM tactical planning, situational awareness and post mission evaluation capabilities. It is fielded to standard Navy networks including, Consolidated Afloat Networks and Enterprise Services (CANES), Integrated Shipboard Network System (ISNS), and Navy Marine Corps Intranet (NMCI) servers and uses common web browsers as the user interface. Minefield Planning is a tactical software application which provides commanders the ability to plan and assess offensive, defensive, and protective minefields based on oceanographic and mine performance data and user specified objectives. 5) MIW Integrated Synthetic Trainer (MIST) will provide integrated phase training for MIW staffs in end-to-end MCM scenarios. This tool will provide the capability to train MIW staffs against near peer threats.$$, NULL, 18236000, 18496000, 18564000, NULL, NULL, 83, $$RDTEN_BA4_Book.pdf$$, NULL, FALSE, 13940000, 18504000, 17762000, 17762000, NULL, 17762000, 18896000, $$The Surface Mine Countermeasures (SMCM) Program Element (PE) provides resources in support of development of mine countermeasures systems to provide minehunting and neutralization to counter known and projected mine threats. The mine countermeasures systems provide mobile, quick reaction forces capable of land or sea-based minehunting and neutralizing operations worldwide. Resources are for developing and deploying advanced minehunting and neutralization systems and the intelligence and oceanographic capabilities that will enable mine warfare superiority. Tactics and techniques used vary across a diversity of environments and a diversity of threats, including both asymmetric and emerging. Resources provide for systems and support of mine warfare systems, maritime systems, and expeditionary systems to allow for continuous operations of the Navy's warships and support vessels, other military vessels, and commercial vessels. Increased capability includes conducting minefield reconnaissance (mine density and location) at high area search rates; improving detection capability; decreasing sensor false alarm rates; reducing or eliminating post-mission analysis detect, classify, identify, decide time; improving neutralization time; improving network communications; automatic target recognition; and achieving in-stride detect-to-engage capability. The Surface Mine Countermeasures programs are in general platform independent and will provide detection, classification, localization, identification, neutralization, and influence clearance capabilities. Programs develop: (1) Unmanned minehunting capability for surface platforms; (2) the integration and improvement of new and existing systems (3) support for systems which detect, localize, classify, identify, and neutralize all mine types across MCM Avenger Class (MCM-1), Littoral Combat Ship (LCS) Class and other platforms. 1) The AN/AQS-20 is a mine hunting and identification system with sensors housed in an underwater Towed Body (TB). The sensors are designed for the detection, classification and localization of bottom, close-tethered, and volume targets, and for the identification of bottom targets. The system can be deployed from the Littoral Combat Ship (LCS) as part of the MCM Mission Package or can be deployed from other Vessels of Opportunity (VOO). The MCM USV is the tow platform for the AN/ AQS-20. 2) AN/SQQ-32(V)4 High-Frequency, Wide Band (HFWB) is a technology upgrade to the AN/SQQ-32 Towed Body which incorporated HFWB technology into the detection sonar to address performance deficiencies against new mine threats in the littorals. This upgrade was installed on MCM-1 Class ships. 3) AN/SLQ-60 Mine Neutralization System (MNS) Seafox on the MCM Class ships. MNS is the replacement to the existing AN/SLQ-48 Mine Neutralization System. 4) Mine Warfare and Environmental Decision Aids Library Enterprise Architecture (MEDAL EA) is the U.S. Navy's single Mine Warfare (MIW) tactical decision support system for integrated mission planning, evaluation, and situational awareness. It provides mine warfare planning and evaluation tools and databases to mine countermeasures (MCM) commanders and is employed at the unit level to perform MCM sortie planning and evaluation. MEDAL EA is a family of systems, comprised Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                                 Date: April 2026 Appropriation/Budget Activity                                                      R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 4: Advanced              PE 0604127N / Surface Mine Countermeasures Component Development & Prototypes (ACD&P) of the following three components: MINEnet Global (MNG), MINEnet Tactical (MNT), and Minefield Planning (MFP). MINEnet Global is a shore-based website that provides MIW waterspace awareness functionality to support Navy non-MIW forces. MINEnet Global provides downloadable reference databases, MIW reference publications and links to MIW information. The MINEnet Tactical component is a software application which provides MCM tactical planning, situational awareness and post mission evaluation capabilities. Minefield Planning is a tactical software application which provides commanders the ability to plan and assess offensive, defensive, and protective minefields based on oceanographic and mine performance data and user specified objectives. Depending on user need, MEDAL EA is networked or stand-alone and is either deployed on dedicated laptop computers or installed on the unit's/command's native computer resources. 5) MIW Integrated Synthetic Trainer (MIST) will provide integrated phase training for MIW staffs in end-to-end MCM scenarios. This tool will provide the capability to train MIW staffs against near peer threats.$$, $$Budget J-Books/FY27/Navy/RDTEN_BA4_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604133D8Z$$, $$Alpha-1 Development Activities$$, $$rdte_dw_ba5$$, $$dw_cdao$$, 2026, 582570000, 52909000, 53307000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "dw", "page_num": 74, "fy27_mand_k": 500000, "original_pe": "0604133D8Z", "page_header": "Defense-Wide", "fy27_mand_v157": "2026-05-08", "fy26_v182_disc_K": 395882, "fy26_v182_supp_K": 250000, "fy27_mand_source": "DoW_FY2027_Mandatory_Funding_Overview.txt Appendix B", "fy26_v182_total_K": 645882, "fy27_mand_section": "Next Generation Technology/Autonomy", "fy26_v182_note_name": "Alpha-1", "fy26_v182_source_file": "RDTE_OSW_PB_2027.txt", "fy26_v182_source_line": 31921}$$::jsonb, $$The Alpha-1 PE provides enterprise digital enablers and prototyping efforts to enable the Joint force to access, develop, and adopt artificial intelligence (AI) in warfighting, readiness, and business use cases more easily, securely, reliably, and responsibly. Alpha-1 funding supports AI activities associated with computer vision, generative AI (GenAI), autonomy, and Responsible AI (RAI) adoption. It also includes funding to recruit, train, educate, and enable the DoD workforce to advance AI adoption. Specific activities include enterprise data acquisition and labeling, AI development pipelines, testing and evaluation tools and processes, RAI capability development and enablement, AI and autonomy modeling and simulation, access to proven and emerging AI models, and associated compute infrastructure costs. Investments in these enterprise digital enablers allow DoD to invest centrally in common enablers to ensure interoperability and drive efficiencies, while multiple organizations and platforms can then leverage the capabilities locally in their use cases.$$, NULL, 1125988000, 1239395000, 1425842000, NULL, NULL, 142, $$RDTE_OSD_PB_2026.pdf$$, $$OSD$$, FALSE, 48506000, 645882000, 969825000, 969825000, 500000000, 1469825000, 1544191000, $$Chief Digital and Artificial Intelligence Officer (CDAO) are spearheading the Department of War's transformation into an AI-enabled enterprise by focusing on warfighting, intelligence, and enterprise-wide AI deployment. The core of this strategy revolves around a series of pioneering "Pace-Setting Projects" (PSPs). adoption, the Enterprise Agents PSP provides a playbook for deploying AI workflows. Underpinning all these efforts are two foundational enablers: the new War Data Platform (WDP) for standardized data access and the "GenAI.mil" initiative to scale AI tools across the force. In parallel, Autonomy.mil will provide similar standardization for autonomy platform development across the DoW. The CDAO will champion this transformation as a "Wartime CDAO," cutting through bureaucracy to rapidly deliver these capabilities. CDAO is also evolving its AI model assessment to evaluate future models on a wide variety of use cases including performance, testing, ethics, and security compliance. The FY 2027 request for Alpha 1 includes $969,825 thousand of discretionary and $500,000 thousand of mandatory for a total of $1,469,825. The mandatory funds Alpha 1 which is to support pace setting projects and generative AI for all government. The FY 2027 mandatory funds continue efforts from FY 2026 to support the Artificial Intelligence Strategy for the Department of War. The FY 2026 spend plan amount for Alpha-1 includes $395,882 thousand of discretionary and $250,000 thousand of mandatory for a total of $645,882 thousand. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Office of the Secretary Of Defense                                            Date: April 2026 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 5:         PE 0604133D8Z / Alpha-1 Development Activities System Development & Demonstration (SDD)$$, $$Budget J-Books/FY27/Remaining/DoW_FY2027_Mandatory_Funding_Overview.txt$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604134A$$, $$Counter Improvised-Threat Demonstration, Prototype Development, and$$, $$rdte_army_ba4$$, $$dw_dtra$$, 2026, 5491000, 15826000, 17341000, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "army", "page_num": 15, "original_pe": "0604134A", "page_header": "Department of the Army"}$$::jsonb, $$This Program Element (PE) develops prototypes and demonstrates technology for detecting and defeating Improvised Explosive Devices (IED). The goal of this Project is to mature technology to increase the ability of deployed forces to positively identify IEDs with minimal false alarms and increase the rate of advance of route clearance missions. Additionally, the objective is to positively neutralize or mitigate the effects of IEDs with minimal collateral damage. Driven by the current threat facing deployed U.S. forces, this PE enables rapid development and delivery of capabilities that enable the detection, neutralization, and risk mitigation of IEDs and their effects. These technologies are intended to be matured and demonstrated for integration onto existing Department of Defense weapon systems. This PE is coordinated with the Under Secretary of Defense for Research and Engineering (USD/R&E) and the Defense Threat Reduction Agency (DTRA). Work in this Project is managed by Command, Control, Computers, Communications, Cyber, Intelligence, Surveillance, and Reconnaissance (C5ISR) Center. Work is performed by Assistant Secretary of the Army for Acquisition, Logistics and Technology and the Army Research, Development, Test and Evaluation (RDT&E) Enterprise with oversight from Assistant Secretary of the Army for Acquisition, Logistics and Technology for Research and Technology (DASA R&T). The FY 2026 request was reduced by $1.797 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative." The FY 2026 request was reduced by $0.038 million for civilian personnel to optimize the workforce in compliance with Executive Order 14210, "Implementing the President's Department of Government Efficiency Workforce Optimization Initiative." Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                        Date: June 2025 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 4: Advanced        PE 0604134A / Counter Improvised-Threat Demonstration, Prototype Development, and Component Development & Prototypes (ACD&P)                                   Testing$$, NULL, NULL, NULL, NULL, NULL, NULL, 91, $$RDTE - Vol 2 - Budget Activity 4B.pdf$$, NULL, FALSE, 10613000, 5491000, NULL, NULL, NULL, NULL, NULL, $$This Program Element (PE) develops prototypes and demonstrates technology for detecting and defeating Improvised Explosive Devices (IED). The goal of this Project is to mature technology to increase the ability of deployed forces to positively identify IEDs with minimal false alarms and increase the rate of advance of route clearance missions. Additionally, the objective is to positively neutralize or mitigate the effects of IEDs with minimal collateral damage. Driven by the current threat facing deployed U.S. forces, this PE enables rapid development and delivery of capabilities that enable the detection, neutralization, and risk mitigation of IEDs and their effects. These technologies are intended to be matured and demonstrated for integration onto existing Department of War weapon systems. This PE is coordinated with the Under Secretary of War for Research and Engineering (USW/R&E) and the Defense Threat Reduction Agency (DTRA). Work in this Project is managed by Command, Control, Computers, Communications, Cyber, Intelligence, Surveillance, and Reconnaissance (C5ISR) Center. Work is performed by Assistant Secretary of the Army for Acquisition, Logistics and Technology and the Army Research, Development, Test and Evaluation (RDT&E) Enterprise with oversight from Assistant Secretary of the Army for Acquisition, Logistics and Technology for Research and Technology (DASA R&T).$$, $$Budget J-Books/FY27/Army/RDTE - Vol 2 - Budget Activity 4B.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604135A$$, $$Strategic Mid-Range Fires$$, $$rdte_army_ba4$$, $$cft_lrpf$$, 2026, 231401000, 25342000, 0, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "army", "page_num": 15, "original_pe": "0604135A", "page_header": "Department of the Army"}$$::jsonb, $$This program directly supports the Army's Long Range Precision Fires modernization priority by rapidly developing and fielding critical capabilities to address evolving threats, specifically advanced Anti-Access/Area Denial (A2/AD) systems employed by peer and near-peer adversaries. These threats include sophisticated integrated air defense systems, long-range precision strike capabilities, and advanced electronic warfare techniques. The FY26 budget request supports the development and prototyping of the Common Autonomous Multi-Domain Launcher (CAML), a mobile, autonomous, and versatile fires platform capable of launching a diverse range of offensive and defensive munitions across multiple domains. CAML will significantly enhance the Army's ability to penetrate contested environments, neutralize high-value targets, and provide responsive fires support to Combatant Commanders. While MRC successfully demonstrated a ground-launched capability utilizing existing missile systems, CAML represents a next-generation approach focused on autonomy, increased payload flexibility, and broader mission applicability. This funding will facilitate system design finalization, prototype material procurement (including tactical vehicles and munitions), hardware fabrication, software integration, and rigorous developmental and live fire testing. The program is transitioning from the MRC prototype to the CAML prototype, leveraging lessons learned to accelerate development and reduce risk.$$, NULL, 289015000, 293881000, 326370000, NULL, NULL, 92, $$RDTE - Vol 2 - Budget Activity 4B.pdf$$, NULL, FALSE, NULL, 226215000, 211848000, 211848000, NULL, 211848000, 433496000, $$The CAML mission is to provide elements across all echelons with a mobile, autonomous, optionally manned, versatile cross-domain fires capability and capacity far greater than current formation launcher and resupply capabilities. CAML is a mobile, autonomous, and versatile fires platform capable of launching a diverse range of offensive and defensive munitions across multiple domains. CAML will significantly enhance the Army's ability to penetrate contested environments, neutralize high- value targets, and provide responsive fires support to Combatant Commanders. The CAML prototype system will include an Autonomous Mobility Platform (AMP), launcher platform mounted on a Munitions Pallet (MP), leader vehicle with autonomy kit, and organic autonomous resupply capability. The Tomahawk Land Attack Missile (TLAM) will have one leader vehicle with autonomy kit per two CAML prototype systems. The prototype launcher platform must support cross-domain fires to include TLAMs, Patriot Missile Segment Enhancement (MSE) interceptors, Multiple Launch Rocket System (MLRS) Family of Munitions (MFOM), Indirect Fires Protection Capability (IFPC) interceptors, and interface standards to support integration of future offensive and defensive munitions, such as the Blackbeard Ground Launch (GL) advanced missile. This program element directly supports the Army's modernization priority by reducing emplacement and displacement times, provides improved crew survivability, adds cross-country mobility, increases overall effectiveness, and allows commanders to weight the force appropriately during both offensive and defensive operations - enabling the ability to mass lethal assets and further dominate the operational environment across multiple domains. Beginning FY 2027, the CAML program transitions to a new Budget Project (DP2) focused on system design finalization, prototype material procurement, hardware fabrication, software integration, and rigorous developmental and live fire testing. It delivers autonomy, increased payload flexibility and broader mission capability. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                       Date: April 2026 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 4: Advanced         PE 0604135A / Strategic Mid-Range Fires Component Development & Prototypes (ACD&P)$$, $$Budget J-Books/FY27/Army/RDTE - Vol 2 - Budget Activity 4B.pdf$$) ON CONFLICT DO NOTHING;
