INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604139D8Z_ba2$$, $$Golden Dome for America - MDA$$, $$proc_gd_ba2$$, $$dw_mda$$, 2026, 0, 0, 0, NULL, $${"ba": "02", "line": 5, "page": 82, "unit": "K", "source": "r1_fy27", "fy26_pl": 414400, "fy27_disc": 0, "fy27_mand": 1781400, "fy26_total": 414400, "fy27_total": 1781400, "appropriation": "3007D", "fy27_mand_v158": true}$$::jsonb, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, $$Budget J-Books/FY27/Remaining/FY2027_r1.txt$$, NULL, FALSE, NULL, 414400000, 0, 0, 1781400000, 1781400000, NULL, NULL, $$Budget J-Books/FY27/Remaining/FY2027_r1.txt$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604159D8Z$$, $$Golden Dome for America - SCO$$, $$rdte_gd_ba3$$, $$dw$$, 2026, 0, 0, 0, NULL, $${"ba": "03", "line": 10, "page": 82, "unit": "K", "source": "r1_fy27", "fy26_pl": 340000, "fy27_disc": 0, "fy27_mand": 200000, "fy26_total": 340000, "fy27_total": 200000, "appropriation": "3007D"}$$::jsonb, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 10, $$Budget J-Books/FY27/Remaining/FY2027_r1.txt$$, $$GDAF$$, FALSE, 0, 340000000, 0, 0, 200000000, 200000000, NULL, NULL, $$Budget J-Books/FY27/Remaining/FY2027_r1.txt$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604162D8Z$$, $$CHEMBIO WEAPONS ELIM TECH DEV$$, $$rdte_dw_ba4$$, $$dw$$, 2027, 0, 0, 0, NULL, $${}$$::jsonb, NULL, NULL, 1074000, 1893000, 1935000, NULL, NULL, NULL, NULL, NULL, FALSE, 0, 0, 945000, 945000, NULL, 945000, 1974000, $$Chemical and biological weapons (CBW)-based threats continue to evolve in response to changing geopolitics and emerging technologies. Each of the nations that are deemed as threats to United States (U.S.) national security are believed to have and/or be developing chemical and/or biological weapons. The Department of War (DoW) must be prepared to eliminate these threats during and/or after the execution of a contingency operation or in support of a diplomatic breakthrough, enabling the U.S. to achieve peace through strength and strengthen deterrence. Chemical Weapons Convention (CWC) and Biological Weapons Convention (BWC) obligations and DoW strategic guidance demand the Department maintain a complete and enduring capability to assess and destroy CBW, regardless of location or environment. In accordance with the CWC and BWC, the U.S. must be prepared to “destroy [chemical/biological] weapons…in its possession or…under its jurisdiction or control.” It is critical for the DoW to match CBW-based threats by possessing the capabilities to directly disable or defeat WMD threats prior to use. This capability must provide operational flexibility that enables early action and expedient destruction, from small-scale disablement and defeat in a non-permissive or austere environment to large-scale destruction of a foreign CBW stockpile in a post-contingency or permissive environment. These capabilities will positively influence deterrence and project Peace Through Strength. Our current capabilities are inadequate to support these requirements, and we are currently unable to invest in the development and/or improvement of capabilities to eliminate CBW on the scale required. The Department must be proactive in ensuring we are prepared to eliminate known and expected CBW threats before adversary use against U.S. military or civilian personnel at home or abroad or our allies. The Chemical and Biological Weapons Elimination (CBWE) Research and Development Activities (RDAs) support the Department’s initiatives to rebuild our military and reestablish deterrence by ensuring a complete and enduring capability to assess and destroy chemical and biological weapons (CBW), regardless of location or operational environment. This program addresses Joint Force priorities, tasks, and requirements. Fiscal Year (FY) 2027 funding is for the advanced development of chemical weapons destruction technologies in support of joint warfighter requirements. The CBWE portfolio provides material solutions that enable DoW to prevent adversary acquisition, transfer, deployment, and use of CBW as well as meet U.S. Chemical Warfare Convention (CWC) treaty obligations. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Office of the Secretary Of Defense                                                Date: April 2026 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 4:             PE 0604162D8Z / CHEMBIO WEAPONS ELIM TECH DEV Advanced Component Development & Prototypes (ACD&P) The CBWE portfolio will execute along several Lines of Effort (LOEs) to help prepare the Joint Force for a future operating environment in which adversary possession of Weapons of Mass Destruction (WMDs) pose threats ranging from tactical to existential, and limit U.S. strategic choices. These LOEs will create options for assessment and destruction of recovered chemical warfare material within the U.S., as well as chemical and biological warfare material across the continuum of conflict, including materiel solutions for the destruction of small-scale weaponized and bulk CBW agents, and solutions for the elimination of nation state CBW programs and stockpiles. The Office of the Secretary of War uses the CBWE Portfolio to invest strategically in projects to fill validated requirements from the Services, Combatant Commands, combat support agencies, and defense agencies. Funding is prioritized for projects that close Joint Force and domestic assess, disable and/or destroy capability gaps. An annual investment strategy is used to prioritize and meet capability needs. The CBWE Technology Development program invests in advanced development of systems used to assess, disable, and/or destroy chemical and biological weapons and material – foreign and domestic. Funds are used for the development and integration of operational prototypes into fielded systems, or other upgrades and enhancements, including any necessary test and evaluation. This program funds labor, materials, and travel requirements, performed by a government agency or by private individuals or organizations under a contract with the government, for activities and acquisitions including Research, Development, Test & Evaluation (RDT&E), assessments and analyses, and other activities related to capability development and fielding.$$, $$Budget J-Books/FY27/DW/RDTE_OSW_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604181C$$, $$Hypersonic Defense$$, $$rdte_dw_ba4$$, $$dw_mda$$, 2026, 447627000, 228962000, 182283000, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "dw", "page_num": 72, "original_pe": "0604181C", "page_header": "Defense-Wide"}$$::jsonb, $$Strategic competitors and both homeland and regional adversaries are heavily investing in offensive and defensive hypersonic capabilities, and currently have operational hypersonic strike and defensive systems deployed. These are challenging realities of the emerging missile threat environment that United States (U.S.) Missile Defense policy, strategy, and capabilities must address. These adversaries continue to expand the capability and capacity of their offensive and defensive hypersonic missile inventories for both strategic and regional hypersonic missiles. Near Peer/Peer nations have also demonstrated hypersonic missiles in recent flight tests. The Hypersonic Defense program element includes: execution of the systems engineering activities; upgrade of existing systems; investment in new technologies; and development of new regional defensive capabilities and maturation for delivery in 2032. The Missile Defense Agency's Hypersonic Missile Defense strategy includes leveraging existing systems, delivering an initial regional layered defense capability, and increasing defense capabilities in the future. Activities enabling this strategy are as follows: - Develop a regional Glide Phase Interceptor capability to engage hypersonic threats during the glide phase of flight and other threats in multi-mission areas. The Preliminary Design Review is planned in FY 2028, Kill Vehicle (KV) demonstration in 2029 and delivery of 12 tactical missiles in 2032. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Missile Defense Agency                                                                 Date: June 2025 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 4:            PE 0604181C / Hypersonic Defense Advanced Component Development & Prototypes (ACD&P) - Conduct early analysis and requirement to integrate into Golden Dome communications architecture. - Integrate existing overhead sensors such as the Hypersonic and Ballistic Tracking Space Sensor, as well as new technologies. - Execute systems engineering for Hypersonic Defense including architecture analysis, technology prioritization, requirements development, planning and analysis. - Partner with the Services and other agencies to leverage work on common technologies, test infrastructure, weapon development, testing, and war-gaming. - Cooperatively develop the Glide Phase Interceptor with Japan. Rapidly evolving rogue and peer missile threats have led to a change in national defense policy. The President's January 27, 2025, Executive Order established a goal of protecting the U.S. citizens, safeguarding critical infrastructure, and securing second-strike capability against missile attack from any adversary. The Missile Defense Agency is responding with speed and intensity to deliver next-generation missile defenses to protect the U.S. against ballistic, hypersonic, cruise, and other advanced missile threats. This program submission reflects changes necessary to meet this evolving mission space.$$, NULL, 248765000, 332880000, 392826000, NULL, NULL, 106, $$RDTE_Vol2_MDA_RDTE_PB26_Justification_Book.pdf$$, $$MDA$$, FALSE, 175893000, 182990000, 213783000, 213783000, NULL, 213783000, 393894000, $$Strategic competitors and both homeland and regional adversaries are heavily investing in offensive and defensive hypersonic capabilities, and currently have operational hypersonic strike and defensive systems deployed. These are challenging realities of the emerging missile threat environment that U.S. Missile Defense policy, strategy, and capabilities must address. These adversaries continue to expand the capability and capacity of their offensive and defensive hypersonic missile inventories for both strategic and regional hypersonic missiles. Near-Peer/Peer nations have also demonstrated hypersonic missiles in recent flight tests. The Hypersonic Defense program element includes: - Execution of the systems engineering activities. - Upgrade of existing systems. - Investment in new technologies. - Development of new regional and homeland defensive capabilities and maturation for delivery in 2032 (achievable with additional resources within Department of War). The Missile Defense Agency's Hypersonic Missile Defense strategy includes leveraging existing systems, delivering an initial regional and homeland layered defense capability, and increasing defense capabilities in the future. Rapidly evolving rogue and peer missile threats have led to a change in national defense policy. The President's January 27, 2025, Executive Order established a goal of protecting the U.S. citizens, safeguarding critical infrastructure, and securing second-strike capability against missile attack from any adversary. The Missile Defense Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Missile Defense Agency                                                             Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 4:           PE 0604181C / Hypersonic Defense Advanced Component Development & Prototypes (ACD&P) Agency is responding with speed and intensity to deliver Missile Defense System-Next to protect the U.S. against ballistic, hypersonic, cruise, and other advanced missile threats. This program submission reflects changes necessary to meet this evolving mission space. Activities enabling this strategy are as follows: - Develop Glide Phase Interceptor capability to engage hypersonic threats during the glide phase of flight and other threats in multi-mission areas. The Preliminary Design Review is planned in FY 2028, Kill Vehicle demonstration in FY 2029 and delivery of 12 tactical missiles in FY 2032 (achievable with additional resources within Department of War). - Conduct early analysis and establish requirement to integrate into the Missile Defense System-Next capabilities in support of the President's Executive Order 14186. - Integrate existing overhead sensors such as the Hypersonic and Ballistic Tracking Space Sensor, as well as new technologies. - Execute systems engineering for Hypersonic Defense including architecture analysis, technology prioritization, requirements development, planning and analysis. - Partner with the Services and other agencies to leverage work on common technologies, test infrastructure, weapon development, testing, and war-gaming. - Cooperatively develop the Glide Phase Interceptor with Japan.$$, $$Budget J-Books/FY27/Remaining/RDTE_Vol2_MDA_RDTE_PB27_Justification_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604182A$$, $$Hypersonics$$, $$rdte_army_ba4$$, $$cft_lrpf$$, 2026, 25000000, 201193000, 0, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "army", "page_num": 15, "fy27_mand_k": 40000, "original_pe": "0604182A", "page_header": "Department of the Army", "fy27_mand_v157": "2026-05-08", "fy27_mand_source": "DoW_FY2027_Mandatory_Funding_Overview.txt Appendix B", "fy27_mand_section": "Munitions"}$$::jsonb, $$The work in this Program Element (PE) supports the research, development, prototype, test and evaluation of technology to rapidly and efficiently procure, transition, and/or field critical enabling technologies and capabilities that address near-term and mid-term threats and is directly aligned to the Army Long Range Precision Fires modernization priority. PE 0604182A Hypersonics funded the development and prototype fielding of a Long Range Hypersonic Weapon to suppress adversary Long Range Fires and engage other high payoff/time critical targets. This effort encompassed the growth, testing and transition of Long Range Fires technologies. Additionally, the Army will leverage advancements in technology, materials, and cost-effective production methods to provide superior capabilities through fast, iterative design cycles, flexible hardware development, and modern manufacturing practices. The work in this Program Element (PE) now supports development, system flight tests, software validation, and full integration into the High Mobility Artillery Rocket System (HIMARS) platform, which will significantly expand HIMARS lethality. The $25.0 million requested in FY26 will fund continued prototype refinement, system flight testing, and key components for HIMARS integration, including the launcher pod and fire control system interface. Key milestones in FY26 include a Flight Termination System Trade Study (Q1) and an MVP Flight Test (Q4) demonstrating integration compatibility. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                         Date: June 2025 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 4: Advanced      PE 0604182A / Hypersonics Component Development & Prototypes (ACD&P)$$, NULL, 106987000, 38000000, 28000000, NULL, NULL, 93, $$RDTE - Vol 2 - Budget Activity 4B.pdf$$, NULL, FALSE, NULL, 25000000, 82939000, 82939000, 40000000, 122939000, 28000000, $$The work in this Program Element (PE) supports development, system flight tests, software validation, and full integration into the High Mobility Artillery Rocket System (HIMARS) platform, significantly expanding HIMARS lethality. PE 0604182A/Project HX3, All Up Round and Canister (AUR+C), completed its funding cycle in FY 2026 with the full integration of the AUR+C into the High Mobility Artillery Rocket System (HIMARS) platform. Efforts are now focused under Budget Project DP1: HIMARS Extended Range Demo (HERD) which will drive the program through Engineering, Development, Testing, and Fielding. The HERD project supports the Army's Long Range Precision Fires (LRPF) modernization priority by demonstrating the feasibility and performance of integrating a qualified, extended-range Blackbeard - Ground Launch (GL) advanced strike missile into the HIMARS launcher system. This demonstration will assess the potential to achieve a significantly reduced cost for high-speed strike capability complementing existing Precision Strike Missile (PrSM) capabilities. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                                 Date: April 2026 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 4: Advanced            PE 0604182A / Hypersonics Component Development & Prototypes (ACD&P)$$, $$Budget J-Books/FY27/Remaining/DoW_FY2027_Mandatory_Funding_Overview.txt$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604183F$$, $$Hypersonics Prototyping - Hypersonic Attack Cruise Missile (HACM)$$, $$rdte_af_ba4$$, $$aflcmc$$, 2026, 802810000, 333328000, 466729000, NULL, $${"ba_raw": "6.4", "source": "af_r1_fy26", "original_pe": "0604183F"}$$::jsonb, $$Hypersonic Attack Cruise Missile (HACM) is an air-launched, air breathing hypersonic weapon capable of integration on fighter and bombers and enable the U.S. to hold fixed, high value, time-sensitive targets at risk in contested environments from standoff distances. The program leverages investment from the Southern Cross Integrated Flight Research Experiment (SCIFiRE), a bi-lateral U.S./Australian air-breathing hypersonic cruise missile prototyping effort. The HACM program will integrate advanced technologies and mature designs into an All-Up Round (AUR) prototype that will demonstrate a field-able long range prompt strike capability. HACM will design, develop, manufacture, and test prototype vehicles to inform future HACM acquisition decisions. HACM will mature hypersonic technologies and processes to include: subsystem integration, infrastructure and testing advancements, Digital Engineering (DE), Weapons Open Systems Architecture (WOSA), Modeling and Simulation (M&S), analytics, and high performance computing environments. Implements Digital Acquisition tenants of Open, Agile, and Digital; builds and establishes industrial base innovation around the program's enterprise for modularity and adaptability for the life cycle of the weapons system. Leverages common component development, in collaboration with other weapon systems, to reduce redundant costs between systems with similar subsystems requirements. Invests in analytical, data management, digital environments, networks, facilities, and security infrastructure upgrades supporting development of this program's capabilities, while leveraging DoD and DAF enterprise IT solutions. Expands program office staff, facilities, and security infrastructure to support the required classification levels for this program's activities. Engages with DoD, DAF, and industry stakeholders to refine threat analysis, refine inventory requirements, and plan upgrade requirements. Capitalizes on and incorporates successful laboratory research and development efforts applicable to this program's capability. The FY 2026 cost of Middle Tier of Acquisition for HACM is reflected in the budget request, including RDT&E and procurement of prototype units. The Department will certify Future Years Defense Program (FYDP) funding in a future budget submission. The FY 2026 request was reduced by $0.624 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative.” Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                           Date: June 2025 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 4: Advanced PE 0604183F / Hypersonics Prototyping - Hypersonic Attack Cruise Missile (HACM) Component Development & Prototypes (ACD&P) This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605829F, 0605831F, 0605833F, or 0605898F. In FY 2024 8.255M was expended for civilian pay expenses in this program element, and in FY 2025 11.738M was forecasted for civilian pay expenses in this program element. This effort is in Budget Activity 4, Advanced Component Development and Prototypes (ACD&P), because efforts are necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment.$$, NULL, 513991000, 195531000, 171080000, NULL, NULL, 47, $$FY26 Air Force Research and Development Test and Evaluation Vol II.pdf$$, NULL, FALSE, 452800000, 828075000, 806142000, 806142000, 0, 806142000, 155031000, $$Hypersonic Attack Cruise Missile (HACM) is an air-launched, air breathing hypersonic weapon capable of integration on fighters and bombers that enables the U.S. to hold fixed, high value, time-sensitive targets at risk in contested environments from standoff distances. The program leverages investment from the Southern Cross Integrated Flight Research Experiment (SCIFiRE), a bi-lateral U.S./Australian air-breathing hypersonic cruise missile prototyping effort. The HACM program will integrate advanced technologies and mature designs into an All-Up Round (AUR) prototype that will demonstrate a field-able long range prompt strike capability. HACM will design, develop, manufacture, and test prototype vehicles to inform future HACM acquisition decisions. HACM will mature hypersonic technologies and processes by leveraging subsystem integration, infrastructure and testing advancements, Digital Engineering (DE), Weapons Open Systems Architecture (WOSA), Modeling and Simulation (M&S) to quickly integrate future capabilities at reduced cost. Implements Digital Acquisition tenants of Open, Agile, and Digital; builds and establishes industrial base innovation around the program's enterprise for modularity and adaptability for the life cycle of the weapons system. Leverages common component development, in collaboration with other weapon systems, to reduce redundant costs between systems with similar subsystems requirements. Invests in analytical, data management, digital environments, networks, facilities, and security infrastructure upgrades supporting development of this program's capabilities, while leveraging Department of War (DoW) and Department of the Air Force (DAF) enterprise Information Technology (IT) solutions. Expands program office staff, facilities, and security infrastructure to support the required classification levels for this program's activities. Engages with DoW, DAF, and industry stakeholders to refine threat analysis, refine inventory requirements, and plan upgrade requirements. Capitalizes on and incorporates successful laboratory research and development efforts applicable to this program's capability. In addition to the HACM Rapid Prototyping effort, there are other development efforts ongoing to include Functional Capability Advancement (FCA) to enhance system capability and produce additional prototypes, Manufacturing Capacity Enhancements (MCE) to make targeted investments into the industrial base towards full rate production, integration modifications, and operational suitability improvements to the weapon. Finally, FY27 will start HACM production to meet warfighter demands in short timelines. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                         Date: April 2026 Appropriation/Budget Activity                                                       R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 4: Advanced PE 0604183F / Hypersonics Prototyping - Hypersonic Attack Cruise Missile (HACM) Component Development & Prototypes (ACD&P) The total cost of the HACM Middle Tier of Acquisition effort is 2,077.8 million, including RDT&E and procurement of prototype units. The HACM is fully funded across the Future Years Defense Program. Acquisition Agility Act Prototyping (AAA) AAA Prototyping within a POR: 0 million AAA Prototyping separate from a POR: 1,841.7 million This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 0605829F, 0605831F, 0605833F, and 0605898F. This effort is in Budget Activity 4, Advanced Component Development and Prototypes (ACD&P), because efforts are necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment. This effort is in Budget Activity 4, Advanced Component Development and Prototypes (ACD&P), because efforts are necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment.$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume II.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$P_1810_L055$$, $$American Forces Radio and TV Service (AF...$$, $$proc_navy_1810_ba2$$, $$navy_cno$$, 2026, 58739000, 50115000, 68458000, NULL, $${"page": 98, "ba_num": "02", "source": "p1_fy26", "ba_name": "Communications and electronics equipment", "line_no": "55", "service": "navy", "fy24_qty": null, "fy25_qty": null, "fy27_v25": {"ba": "02", "appr": "OPN", "title": "P-1 Line 51", "applied_at": "2026-05-09", "fy27_ooc_K": 0, "source_pdf": "Budget J-Books/FY27/Navy/OPN_BA{1..5-8}_Book.pdf", "fy27_base_K": 52758, "p1_line_num": 51, "fy27_total_K": 52758}, "appr_code": "1810", "appr_name": "Other Procurement, Navy", "fy26_v179": {"disc_K": 58739, "li_num": 51, "source": "p40_fy26_v179", "supp_K": 0, "source_pdf": "uploads/Budget J-Books/FY27/Navy/OPN_BA2_Book.txt"}, "fy26t_qty": null, "fy26d_cost": 58739000, "fy26r_cost": 0, "ident_code": "A"}$$::jsonb, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, FALSE, 3802000, 304000, 52758000, 52758000, 0, 52758000, NULL, NULL, $$Budget J-Books/FY27/Navy/OPN_BA2_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604212N$$, $$Other Helicopter Development$$, $$rdte_navy_ba5$$, $$mc$$, 2026, 987000, 2595000, 0, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "navy", "page_num": 32, "original_pe": "0604212N", "page_header": "Department of the Navy"}$$::jsonb, $$This Program Element includes funding for the development support for improvements to current systems for CH/MH-53. The H-53 is the premier heavy lift helicopter for the Marine Corps and the only operational airborne mine sweeping platform for the Navy. H-53 RDT&E efforts focus on trade studies and risk reduction measures to identify candidate survivability, safety, avionics, cargo handling, cockpit and other airframe specific improvements to extend the service life.$$, NULL, 989000, 1005000, 485000, NULL, NULL, 111, $$RDTEN_BA5_Book.pdf$$, NULL, FALSE, 0, 987000, 976000, 976000, NULL, 976000, 494000, $$This Program Element includes funding for the development support for improvements to current systems for CH/MH-53. The H-53 is the premier heavy lift helicopter for the Marine Corps and the only operational airborne mine sweeping platform for the Navy. H-53 RDT&E efforts focus on trade studies and risk reduction measures to identify candidate survivability, safety, avionics, cargo handling, cockpit and other airframe specific improvements to extend the service life.$$, $$Budget J-Books/FY27/Navy/RDTEN_BA5_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604214M$$, $$AV-8B Aircraft - Engine Dev$$, $$rdte_navy_ba5$$, $$asn_rda$$, 2026, 0, 8215000, 5320000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "mc", "page_num": 32, "original_pe": "0604214M", "page_header": "Department of the Navy"}$$::jsonb, $$The program provides for AV-8B Design, Development, Integration, and Test of various platform improvements such as: Engine Life Management Program (ELMP), Escape Systems, Joint Mission Planning System (JMPS), and Block upgrades to various mission systems and software Operational Flight Programs (OFPs) to include JMPS integration, avionics and communications systems, navigation equipment, weapons carriage and countermeasures, and studies and analyses of future capability expansion and unique flight testing. The program also provides for addressing obsolescence and readiness of avionics structural, hydraulic, electrical, environmental and mechanical systems to include engineering activities for development and design to support aircraft safety flight clearances, concept explorations, responses to evolving threats and developments to support Program Objective Memorandum. The program's Evolutionary Acquisition Strategy includes Design, Development, Integration, and Test activities under the consolidated effort of Block Developments. Continued AV-8B combat relevance and ability to respond to evolving and emergent threats through end of service is critical to the Marine Air-Ground Task Force's ability to generate aviation combat power throughout the transition to F-35B. J-series, K-series, Tactical Targeting Network Technology, and other emerging datalink technology messages, as well as compliance with crypto modernization requirements and ability to use GPS-modernized weapons, are required to support current and future mission threats. Linked performance on par with current tactical platforms as well as design to communicate with F-35 is required for the AV-8B to remain tactically relevant to transition. H7.2, H7.3 and H7.4 will continue to build upon the evolutionary acquisition strategy for OFPs and will improve pilot situational awareness, make pilot interface and weapon selection, and Link16 functionality improvements via OFP and Mission Planning updates, and will integrate required Display Computer processing improvements to enable these functionalities. OFP and integration improvements, to include continued use of current weapons as they are upgraded to modernized GPS capability, is vital to the Harrier's continued combat relevance to the Marine Expeditionary Unit and Global Response Force Combatant Commanders. AV-8B funding also supports peculiar flight test requirements to include weapons integration/carriage and avionics, software/firmware upgrades, and avionics hardware component redesign activity. The program also provides for the AV-8B air vehicle's sustained mission availability, and safe and reliable operational readiness until end of service. Sustainment of the aircraft structure, subsystems and software requires component and system analyses, technical planning, identification, prioritization and diagnosis of emergent problems and the allocation of resources for the development, testing, and flight clearance of engineering solutions in the areas of flight, crew safety and escape systems and structural integrity, obsolescence, systems reliability and maintainability, inventory preservation, alternative mission development or other emergent material or equipment conditions affecting AV-8B systems readiness. Activities include research/analysis for system safety deficiency corrections, fuel system safety improvements, structural analyses, monitoring and integrity analysis, component compatibility, component and materials obsolescence analyses and mitigation development, explorations for aging equipment, reliability improvement analyses and design developments. The ELMP is a comprehensive plan to increase and maintain safety of flight and operational readiness of the AV-8B F402-RR-408 Engine and accessories. The program will accomplish this mission by conducting Engineering Project Description investigations to develop engineering solutions that address emergent safety, obsolescence, foreign object debris detection and prevention, fatigue life and maintenance issues. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Navy                                                                             Date: June 2025 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 5: System            PE 0604214M / AV-8B Aircraft - Engine Dev Development & Demonstration (SDD)$$, NULL, 0, 0, 0, NULL, NULL, 112, $$RDTEN_BA5_Book.pdf$$, NULL, FALSE, 5299000, 0, 0, 0, NULL, 0, 0, $$The program provides for AV-8B Design, Development, Integration, and Test of various platform improvements such as: Engine Life Management Program (ELMP), Escape Systems, Joint Mission Planning System (JMPS), and Block upgrades to various mission systems and software Operational Flight Programs (OFPs) to include JMPS integration, avionics and communications systems, navigation equipment, weapons carriage and countermeasures, and studies and analyses of future capability expansion and unique flight testing. The program also provides for addressing obsolescence and readiness of avionics structural, hydraulic, electrical, environmental and mechanical systems to include engineering activities for development and design to support aircraft safety flight clearances, concept explorations, responses to evolving threats and developments to support Program Objective Memorandum. The program's Evolutionary Acquisition Strategy includes Design, Development, Integration, and Test activities under the consolidated effort of Block Developments. Continued AV-8B combat relevance and ability to respond to evolving and emergent threats through end of service is critical to the Marine Air-Ground Task Force's ability to generate aviation combat power throughout the transition to F-35B. J-series, K-series, Tactical Targeting Network Technology, and other emerging datalink technology messages, as well as compliance with crypto modernization requirements and ability to use GPS-modernized weapons, are required to support current and future mission threats. Linked performance on par with current tactical platforms as well as design to communicate with F-35 is required for the AV-8B to remain tactically relevant to transition. H7.2, H7.3 and H7.4 will continue to build upon the evolutionary acquisition strategy for OFPs and will improve pilot situational awareness, make pilot interface and weapon selection, and Link16 functionality improvements via OFP and Mission Planning updates, and will integrate required Display Computer processing improvements to enable these functionalities. OFP and integration improvements, to include continued use of current weapons as they are upgraded to modernized GPS capability, is vital to the Harrier's continued combat relevance to the Marine Expeditionary Unit and Global Response Force Combatant Commanders. AV-8B funding also supports peculiar flight test requirements to include weapons integration/carriage and avionics, software/firmware upgrades, and avionics hardware component redesign activity. The program also provides for the AV-8B air vehicle's sustained mission availability, and safe and reliable operational readiness until end of service. Sustainment of the aircraft structure, subsystems and software requires component and system analyses, technical planning, identification, prioritization and diagnosis of emergent problems and the allocation of resources for the development, testing, and flight clearance of engineering solutions in the areas of flight, crew safety and escape systems and structural integrity, obsolescence, systems reliability and maintainability, inventory preservation, alternative mission development or other emergent material or equipment conditions affecting AV-8B systems readiness. Activities include research/analysis for system safety deficiency corrections, fuel system safety improvements, structural analyses, monitoring and integrity analysis, component compatibility, component and materials obsolescence analyses and mitigation development, explorations for aging equipment, reliability improvement analyses and design developments. The ELMP is a comprehensive plan to increase and maintain safety of flight and operational readiness of the AV-8B F402-RR-408 Engine and accessories. The program will accomplish this mission by conducting Engineering Project Description investigations to develop engineering solutions that address emergent safety, obsolescence, foreign object debris detection and prevention, fatigue life and maintenance issues. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                      Date: April 2026 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 5: System        PE 0604214M / AV-8B Aircraft - Engine Dev Development & Demonstration (SDD)$$, $$Budget J-Books/FY27/Navy/RDTEN_BA5_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604215N$$, $$Standards Development$$, $$rdte_navy_ba5$$, $$asn_rda$$, 2026, 4540000, 3880000, 5120000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "navy", "page_num": 32, "original_pe": "0604215N", "page_header": "Department of the Navy"}$$::jsonb, $$Navy-wide program which addresses Metrology related RDT&E issues for navy weapon systems, shipboard platforms, Naval Air, and Fleet Ground Marines. It supports development of calibration standards (equipment, procedures and technical data) required to resolve METCAL related safety, obsolescence, new and emerging technology support and cost reduction issues. It funds Navy unique and lead service responsibilities in DoD and Joint Services Metrology Research Programs to develop calibration solutions. The line supports development of measurement requirements to verify performance of all test systems used to validate the operation of Navy Weapon Systems with calibration standards traceable to the National Institute of Standards and Technology to calibrate, sustain and ensure performance accuracy. This program also provides benefits and efficiencies in a joint collaborative environment within the Tri-Services. Projects are identified and defined so that they will meet the universal requirement. Development efforts are integrated in order to achieve the common capabilities required at minimum cost. This is also a regular and common business practice within the Navy Metrology Community where R&D efforts are communicated and integrated into the multiple testing and Monitoring Systems. This is done in support of Program Managers, Sponsors, and Principle Executive officers. As a result, common requirements are established, duplication of efforts are eliminated, and best value, high quality METCAL products are produced for the Navy.$$, NULL, 3726000, 4587000, 3520000, NULL, NULL, 113, $$RDTEN_BA5_Book.pdf$$, NULL, FALSE, 4919000, 4540000, 4399000, 4399000, NULL, 4399000, 4675000, $$Navy-wide program which addresses Metrology related RDT&E issues for navy weapon systems, shipboard platforms, Naval Air, and Fleet Ground Marines. It supports development of calibration standards (equipment, procedures and technical data) required to resolve METCAL related safety, obsolescence, new and emerging technology support and cost reduction issues. It funds Navy unique and lead service responsibilities in DoW and Joint Services Metrology Research Programs to develop calibration solutions. The line supports development of measurement requirements to verify performance of all test systems used to validate the operation of Navy Weapon Systems with calibration standards traceable to the National Institute of Standards and Technology to calibrate, sustain and ensure performance accuracy. This program also provides benefits and efficiencies in a joint collaborative environment within the Tri-Services. Projects are identified and defined so that they will meet the universal requirement. Development efforts are integrated in order to achieve the common capabilities required at minimum cost. This is also a regular and common business practice within the Navy Metrology Community where R&D efforts are communicated and integrated into the multiple testing and Monitoring Systems. This is done in support of Program Managers, Sponsors, and Principle Executive officers. As a result, common requirements are established, duplication of efforts are eliminated, and best value, high quality METCAL products are produced for the Navy.$$, $$Budget J-Books/FY27/Navy/RDTEN_BA5_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604216N$$, $$Multi-Mission Helicopter Upgrade Dev$$, $$rdte_navy_ba5$$, $$peo_aasm$$, 2026, 64838000, 70559000, 65438000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "navy", "page_num": 32, "original_pe": "0604216N", "page_header": "Department of the Navy"}$$::jsonb, $$This Program Element funds the development and improvement of MH-60R/S systems. The MH-60R provides persistent distributed, integrated, and maneuverable capabilities in the support of the Navy's Fleet Design and Distributed Maritime Operations concepts through its primary missions: Intelligence, Surveillance, Reconnaissance & Targeting (ISR&T), Antisubmarine Warfare, Surface Warfare (SUW), Electronic Warfare, Command and Control, and Non-Combat Operations. Secondary missions include: Amphibious Warfare, Air Warfare, Health Services, Fleet Support - Operations, Logistics, and Naval Special Warfare (NSW). Primary missions of the MH-60S include Combat Logistics, SUW, NSW, Combat Search and Rescue, and Airborne Mine Countermeasures. Additional missions include ISR&T, Search and Rescue, Humanitarian Assistance and Defense Support for Civil Authorities.$$, NULL, 215473000, 179811000, 195877000, NULL, NULL, 114, $$RDTEN_BA5_Book.pdf$$, NULL, FALSE, 63906000, 114071000, 88855000, 88855000, NULL, 88855000, 151224000, $$1707: This Program Element funds the development and improvement of MH-60R/S systems. The MH-60R provides persistent distributed, integrated, and maneuverable capabilities in the support of the Navy's Fleet Design and Distributed Maritime Operations concepts through its primary missions: Intelligence, Surveillance, Reconnaissance & Targeting (ISR&T), Antisubmarine Warfare, Surface Warfare (SUW), Electronic Warfare, Command and Control, and Non-Combat Operations. Secondary missions include: Amphibious Warfare, Air Warfare, Health Services, Fleet Support - Operations, Logistics, and Naval Special Warfare (NSW). Primary missions of the MH-60S include Combat Logistics, SUW, NSW, Combat Search and Rescue, and Airborne Mine Countermeasures. Additional missions include counter-Unmanned Aerial Systems (cUAS), ISR&T, Search and Rescue, Humanitarian Assistance and Defense Support for Civil Authorities. 1709: The 25+ year old MH-60 platform is facing significant obsolescence issues that cannot be affordably addressed in a timely manner by traditional, line-by-line mitigation methods. The Service Life Modernization (SLM) plan will develop the Tailorable Architecture Leveraging Open-systems for Navy (TALON) upgrade that resolves multiple obsolescence issues within the flight critical avionics and mission systems. TALON will enable a rapid response to emerging threats and fleet requirements ensuring the MH-60 continues to be a relevant, supportable, and cost-effective platform. This approach will allow for faster replacement of obsolete equipment at less cost by increasing competition. Additionally, the intent is a for TALON to be portable to future platforms, such as the Future Vertical Lift (Maritime Strike) program, mitigating future cost and schedule. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                          Date: April 2026 Appropriation/Budget Activity                                               R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 5: System         PE 0604216N / Multi-Mission Helicopter Upgrade Dev Development & Demonstration (SDD)$$, $$Budget J-Books/FY27/Navy/RDTEN_BA5_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604221N$$, $$P-3 Modernization Program$$, $$rdte_navy_ba5$$, $$navair$$, 2026, 0, 756000, 0, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "navy", "page_num": 32, "original_pe": "0604221N", "page_header": "Department of the Navy"}$$::jsonb, $$Fatigue Life Management Program was required to manage P-3/EP-3 inventory fatigue life and included ongoing structural analysis, analyzing emergent structural issues, conducting engineering studies, assessing Fleet impact, and applying new technologies such as Non-Destructive Inspection techniques. This program was funded under SYSTEM DEVELOPMENT AND DEMONSTRATION because it included those projects that have passed Milestone B approval and are conducting engineering and manufacturing development tasks aimed at meeting validated requirement prior to full-rate production decision.$$, NULL, NULL, NULL, NULL, NULL, NULL, 115, $$RDTEN_BA5_Book.pdf$$, NULL, FALSE, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604222F$$, $$Nuclear Weapons Support$$, $$rdte_af_ba5$$, $$afnwc_nd$$, 2026, 79312000, 44219000, 70823000, NULL, $${"ba_raw": "6.5", "source": "af_r1_fy26", "original_pe": "0604222F", "fy27_base_v158_t7b": "I-3 hygiene: total=req but base held stale sibling value post v7 I-24"}$$::jsonb, $$The Air Force Nuclear Weapons Center (AFNWC), Kirtland AFB, NM, is the primary executing agency for this program. The AFNWC is tasked with supporting and supplying technical expertise on all Air Force (AF) nuclear weapons and weapon systems. This program provides resources for technical and programmatic activities which include research, development, test, and evaluation of all nuclear equipment/systems, as well as performing independent analyses on all AF nuclear weapon systems and activities. These include weapon/system development, sustainment, interoperability, compatibility, safety, security, reliability, and cyber resiliency/security, nuclear stockpile certification management for all AF nuclear weapon systems, and nuclear enterprise architecture alignment. The Air Force Safety Center (AFSEC), Kirtland AFB, NM, is the primary executing agency for nuclear weapons certificication. The AFSEC is tasked with providing safety, control, and operational policy and independent assessments and expertise used for the US nuclear enterprise, US nuclear weapons and nuclear weapon system programs as well as security of nuclear weapon design information. This program provides resources for oversight, technical and programmatic activities which include research, development, test, and evaluation of all nuclear weapon related equipment/systems, as well as performing independent analyses on all AF nuclear weapon systems and activities using the industry representative software tools, databasing and Artificial Intelligence. These include participation in early nuclear weapon/system development, system assessments, risk analysis, sustainment actions, operations, trend analysis, safety, security, and cybersecurity, supply chain risk management, nuclear stockpile assessments for all AF nuclear weapon systems, and nuclear enterprise architecture alignment. This activiity is shared with BPAC 654807 in this program element. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program's funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY 2024 0M was expended for civilian pay expenses in this program element, and in FY 2025 0M is forecasted for civilian pay expenses in this program element. The FY 2026 request was reduced by 0.294 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative.” Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                    Date: June 2025 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 5: System     PE 0604222F / Nuclear Weapons Support Development & Demonstration (SDD) This program is in Budget Activity 5, System Development and Demonstration (SDD) because it has passed Milestone B approval and is conducting engineering and manufacturing development tasks aimed at meeting validated requirements prior to full rate production.$$, NULL, 10060000, 0, 0, NULL, NULL, 86, $$FY26 Air Force Research and Development Test and Evaluation Vol II.pdf$$, NULL, FALSE, 0, 0, 86921000, 86921000, 0, 86921000, 0, $$This program executes and provides technical and programmatic support to the testing, evaluation, and mitigation of effects of nuclear weapon employment that impact Department of Air Force (DAF) systems with initial emphasis on existing nuclear weapons, their delivery systems, and associated communications systems. It includes facilities and equipment required to perform testing, risk assessments, and evaluation of the effectiveness to various mitigation strategies. It includes storage and analysis of test data for extrapolation and fleet hardness reporting/documentation. This program will recommend upgrades to existing/fielded systems as well as informing requirements for future (modernization/recapitalization) systems. Program is not a New Start and is a continuation of EMP efforts identified under Project 654807, Nuclear Effects. In FY 2027, Program 0604222F, Nuclear Weapons Support, Project 654807, Nuclear Weapon System Technology and Integration, Nuclear Weapons Effects, Electromagnetic Pulse (EMP) efforts were transferred to Program 0604222F, Nuclear Weapons Support, Project 674237, Electromagnetic Pulse (EMP), to provide better clarity and tracking for the EMP survivability program. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program's funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                      Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:              PE 0604222F / Nuclear Weapons Support Operational Systems Development$$, $$Budget J-Books/FY27/Remaining/FY2027_r1.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604222F_ba7$$, $$Nuclear Weapons Support$$, $$rdte_af_ba7$$, $$aflcmc$$, 2026, 0, 0, 0, NULL, $${"ba_raw": "6.7", "source": "af_r1_fy27", "original_pe": "0604222F", "fy27_base_v158_t7": "hygiene: base=request for disc-only RDT&E rows post v7 I-23/I-24 + v9 I-2 INSERTs"}$$::jsonb, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, 10029000, 10029000, NULL, 10029000, NULL, NULL, $$Budget J-Books/FY27/Remaining/FY2027_r1.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604230N$$, $$Warfare Support System$$, $$rdte_navy_ba5$$, $$asn_rda$$, 2026, 55078000, 132608000, 108432000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "navy", "page_num": 32, "original_pe": "0604230N", "page_header": "Department of the Navy"}$$::jsonb, $$The Rapid Capabilities Development (RCD) program supports the Naval Special Warfare (NSW) Branch by identifying and assessing available technologies that confront current and future irregular and expeditionary warfare challenges. Program development efforts focus on the enhancement/advancement of existing technologies to fill urgent and emergent capability gaps for NSW. Program funding provides for the development, integration, testing, validation, combat demonstration, and evaluation of identified technologies to meet operational requirements; service-common and NSW program technology challenges; and technology obsolescence issues of developed capabilities. The RCD program develops expeditionary/operational capabilities that enable NSW forces to conduct joint cross-domain special reconnaissance, counterterrorism, direct action, amphibious and irregular warfare, and fulfill urgent/emergent needs within a 9-36 month timeframe. As part of the Naval Coastal Warfare Surveillance program, Identity Dominance System (IDS) supports the Joint Personnel Identity (JPI) program. Maritime Expeditionary Security Force (MESF) have a mobile security mission that requires methodologies, procedures, equipment and the communications capacity to identify Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Navy                                                                                 Date: June 2025 Appropriation/Budget Activity                                                       R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 5: System                 PE 0604230N / Warfare Support System Development & Demonstration (SDD) individuals who represent a potential threat as a means to deter and eliminate individuals from conducting asymmetric/non-traditional attacks upon friendly forces, high value assets and coastal areas that Naval Coastal Warfare (NCW) is charged with protecting. The Visit, Board, Search and Seizure (VBSS) teams conducting Expanded Maritime Interception Operations also have a similar requirement to identify individuals. The development of a device to support identity functions is captured in the IDS Capability Development Document (CDD) and implemented in the IDS Capability Production Document (CPD). IDS units are used in the following environments: aboard ships, ashore at ports, the littorals, and extended inland field environments worldwide. IDS is employed in both maritime and very austere ashore environments, carried by individuals who are part of ship boarding parties and by dismounted patrols. These mission and environmental requirements demand the need for a portable, lightweight, ruggedized, and reliable system with intuitive and user friendly features. IDS biometric modalities may differ by mission profile, requiring the authoritative response to the On-Scene Commander/Boarding Officer on whether to detain or further investigate an individual of interest or engage in a more thorough search of boarded ships. Biometrically Enabled Access Control - Husbanding (BEACH) is an authentication capability to improve identity and authentication assurance for entrance to continental United States (CONUS) and outside continental (OCONUS) Navy-Controlled and non-Navy Controlled ports. The United States Navy Service Common Visual Augmentation Systems (VAS) Program of Record manages, procures, and maintains night vision devices, thermal detection devices, day/night weapons optics, and lasers in support of Navy combat capabilities with regard to the detection, recognition, classification, tracking, and destruction of hostile air and surface forces. The USN VAS Program also manages research into the future of visual augmentation systems and engages with Navy and DoD VAS stakeholders to ensure the Navy maintains competitive advantage over near-peer adversaries. Combatant Craft Replacement will provide next generation Expeditionary Multi Mission Craft that will replace in-service Expeditionary Combatant Craft. Combatant Craft replacements shall forward deploy and persistently engage in order to dominate in the Littorals and reinforce Distributed Maritime Operations Lethality, they gain access to as well as CLEAR the battlespace of unexploded ordnance and other man-made or natural hazards and SECURE and PROTECT critical infrastructure and their approaches from the sea for naval platforms as they conduct operations. These capabilities are critical to Navy employment of modern warfare concepts, including Distributed Maritime Operations (DMO), Expeditionary Advanced Base Operations (EABO), and Littoral Operations in a Contested Environment (LOCE). Specific mission and capabilities will be identified in an Initial Capabilities Document (ICD) or Letter of Requirements. RDT&E funding will fund feasibility studies and procurement of mock-ups and prototype craft and craft and mission support technology to demonstrate capabilities prior to production craft procurement. The Diesel Fuel Outboard Motor Testing project supports the transition of the FY 2015 Rapid Innovation Fund "Affordable Multi-fuel Multi-engine Advanced Combatant Craft" program to the Explosive Ordnance Disposal Force. This technology minimizes the types of fuel required to increase standardization, flexibility, and interoperability during deployment while at the same time reduces total ownership cost. Testing of this technology shall determine the operational viability and any changes required to boat design to ensure safety and suitability. DRAKE is the shipboard Counter-Unmanned Aircraft System (CUAS) to meet the CUAS Afloat Top Level Requirements (TLR). Funds will be used to develop, test, and integrate COTS-based hardware, software, and advanced techniques into DRAKE; thus improving its capability to detect, identify, and defeat UAS that threaten ships. Upgrades include hardware refresh with faster COTS processors to increase processing speed and reaction time (NextGen SDR), a COTS tablet (CDU 2.0) to improve situational awareness, and evaluation of COTS antennas to improve detection and defeat of UAS. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Navy                                                                                 Date: June 2025 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 5: System              PE 0604230N / Warfare Support System Development & Demonstration (SDD) The Expeditionary Loitering Munitions Portfolio consists of two Navy loitering munition programs (air and surface) designed to meet an urgent Geographic Combatant Command Requirement. Air and Surface Expeditionary Loitering Munitions Projects will leverage and continue prior development efforts including an Office of Naval Research (ONR) Innovative Naval Prototype (INP). The Navy is pursuing commercial-off-the-shelf solutions with autonomous government-provided software and auxiliary systems. The systems will be expeditionary and deployable by small teams to support operations in various environments. The air system has transitioned from Low-Rate Initial Production to Full-Rate Production with the initial vendor solutions and is now expanding the industrial base for this capability by integrating government- owned technology with other vendor platform solutions. The surface system has transitioned from the ONR INP and is now in production. FY23 $4M Congressional Add: The NSW Unmanned Vehicle Development project develops, prototypes, tests lowrate production hardware / software solutions for Naval, Special Warfare (NSW) Underwater Unmanned Vehicles (UUV) and host NSW submersibles, improving integration and performance for NSW UUV capability utilizing NSW's MK8 & MK11 SEAL Delivery Vehicles (SDV).$$, NULL, 39537000, 29992000, 17844000, NULL, NULL, 116, $$RDTEN_BA5_Book.pdf$$, NULL, FALSE, 105924000, 15778000, 73080000, 73080000, NULL, 73080000, 18166000, $$The Rapid Capabilities Development (RCD) program supports the Naval Special Warfare (NSW) Branch by identifying and assessing available technologies that confront current and future irregular and expeditionary warfare challenges. Program development efforts focus on the enhancement/advancement of existing technologies to fill urgent and emergent capability gaps for NSW. Program funding provides for the development, integration, testing, validation, combat demonstration, and evaluation of identified technologies to meet operational requirements; service-common and NSW program technology challenges; and technology obsolescence issues of developed capabilities. The RCD program develops expeditionary/operational capabilities that enable NSW forces to conduct joint cross-domain special reconnaissance, counterterrorism, direct action, amphibious and irregular warfare, and fulfill urgent/emergent needs within a 9-36 month timeframe. The FY 2026 budget for the RCD program included $8,618,000 thousand of discretionary funding and $2,000,000 thousand of mandatory funding for a total of $10,618,000 thousand. The mandatory funds support Cognitive Router Future Naval Capability (FNC) designed to provide an artificial intelligence-enabled routing node comprised of acoustic and optical underwater modems, RF radios, and vehicle autonomy instantiated on unmanned underwater vehicles (UUV) to create a robust and clandestine low-latency cross-domain network. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                                 Date: April 2026 Appropriation/Budget Activity                                                       R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 5: System                 PE 0604230N / Warfare Support System Development & Demonstration (SDD) As part of the Naval Coastal Warfare Surveillance program, Identity Dominance System (IDS) supports the Joint Personnel Identity (JPI) program. Maritime Expeditionary Security Force (MESF) have a mobile security mission that requires methodologies, procedures, equipment and the communications capacity to identify individuals who represent a potential threat as a means to deter and eliminate individuals from conducting asymmetric/non-traditional attacks upon friendly forces, high value assets and coastal areas that Naval Coastal Warfare (NCW) is charged with protecting. The Visit, Board, Search and Seizure (VBSS) teams conducting Expanded Maritime Interception Operations also have a similar requirement to identify individuals. The development of a device to support identity functions is captured in the IDS Capability Development Document (CDD) and implemented in the IDS Capability Production Document (CPD). IDS units are used in the following environments: aboard ships, ashore at ports, the littorals, and extended inland field environments worldwide. IDS is employed in both maritime and very austere ashore environments, carried by individuals who are part of ship boarding parties and by dismounted patrols. These mission and environmental requirements demand the need for a portable, lightweight, ruggedized, and reliable system with intuitive and user friendly features. IDS biometric modalities may differ by mission profile, requiring the authoritative response to the On-Scene Commander/Boarding Officer on whether to detain or further investigate an individual of interest or engage in a more thorough search of boarded ships. Biometrically Enabled Access Control - Husbanding (BEACH) is an authentication capability to improve identity and authentication assurance for entrance to continental United States (CONUS) and outside continental (OCONUS) Navy-Controlled and non-Navy Controlled ports. Combatant Craft Replacement will provide next generation Expeditionary Multi Mission Craft that will replace in-service Expeditionary Combatant Craft. Combatant Craft replacements shall forward deploy and persistently engage in order to dominate in the Littorals and reinforce Distributed Maritime Operations Lethality, they gain access to as well as CLEAR the battlespace of unexploded ordnance and other man-made or natural hazards and SECURE and PROTECT critical infrastructure and their approaches from the sea for naval platforms as they conduct operations. These capabilities are critical to Navy employment of modern warfare concepts, including Distributed Maritime Operations (DMO), Expeditionary Advanced Base Operations (EABO), and Littoral Operations in a Contested Environment (LOCE). Specific mission and capabilities will be identified in an Initial Capabilities Document (ICD) or Letter of Requirements. RDT&E funding will fund feasibility studies and procurement of mock-ups and prototype craft and craft and mission support technology to demonstrate capabilities prior to production craft procurement. The Diesel Fuel Outboard Motor Testing project supports the transition of the FY 2015 Rapid Innovation Fund "Affordable Multi-fuel Multi-engine Advanced Combatant Craft" program to the Explosive Ordnance Disposal Force. This technology minimizes the types of fuel required to increase standardization, flexibility, and interoperability during deployment while at the same time reduces total ownership cost. Testing of this technology shall determine the operational viability and any changes required to boat design to ensure safety and suitability. DRAKE is the shipboard Counter-Unmanned Aircraft System (CUAS) to meet the CUAS Afloat Top Level Requirements (TLR). Funds will be used to develop, test, and integrate COTS-based hardware, software, and advanced techniques into DRAKE; thus improving its capability to detect, identify, and defeat UAS that threaten ships. Upgrades include hardware refresh with faster COTS processors to increase processing speed and reaction time (NextGen SDR), a COTS tablet (CDU 2.0) to improve situational awareness, and evaluation of COTS antennas to improve detection and defeat of UAS. The Expeditionary Loitering Munitions Portfolio consists of a family of Navy loitering munition programs (air and surface) designed to meet an urgent Geographic Combatant Command Requirement. Air and Surface Expeditionary Loitering Munitions will leverage and continue prior development efforts including an Office of Naval Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                                   Date: April 2026 Appropriation/Budget Activity                                                        R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 5: System                  PE 0604230N / Warfare Support System Development & Demonstration (SDD) Research (ONR) Innovative Naval Prototype (INP). The Navy is pursuing commercial-off-the-shelf solutions with autonomous government-provided software and auxiliary systems. The systems will be expeditionary and deployable by small teams to support operations in various environments. The air system has transitioned from Low-Rate Initial Production to Full-Rate Production with the initial vendor solutions and is now expanding the industrial base for this capability by integrating government-owned technology with other vendor platform solutions. The surface system has transitioned from the ONR INP and is now in Low-Rate Initial Production. The FY 2026 budget for Expeditionary Loitering Munitions included $731,000 thousand of discretionary funding and $37,300,000 thousand of mandatory funding for a total of $38,031,000 thousand. The mandatory funds support program management and technical oversight for the air system, which included hardware and software qualification, Spiral 2 software test planning and execution, safety certification, and contract execution. This oversight will be extended to a maximum of four additional vendors to aid in the integration of Government-owned Technical Data Packages (TDPs) into their respective platforms. FY23 $4M Congressional Add: The NSW Unmanned Vehicle Development project develops, prototypes, tests lowrate production hardware / software solutions for Naval, Special Warfare (NSW) Underwater Unmanned Vehicles (UUV) and host NSW submersibles, improving integration and performance for NSW UUV capability utilizing NSW's MK8 & MK11 SEAL Delivery Vehicles (SDV).$$, $$Budget J-Books/FY27/Navy/RDTEN_BA5_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604231N$$, $$COMMAND AND CONTROL$$, $$rdte_navy_ba5$$, $$asn_rda$$, 2026, 64547000, 84804000, 144391000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "navy", "page_num": 32, "original_pe": "0604231N", "page_header": "Department of the Navy"}$$::jsonb, $$The Tactical Command System upgrades the Navy's Command, Control, Communications, Computer and Intelligence (C4I) systems and processes C4I information for all warfare mission areas including planning, direction and reconstruction of missions for peacetime, wartime and times of crises. Programs will implement digital system-of-systems engineering by using tools such as Model Based System Engineering (MBSE) and Digital Twins to create adaptable digital models to optimize system engineering from design, development and testing to operations and sustainment. Programs will use Development, Security and Operations (DevSecOps) processes for continuous development, integration, testing and deployment, along with common platform services such as Agile Core Services (ACS), for faster fielding of capability. Overall program development efforts include the investigation of emerging technologies through study, development and associated testing for feasibility of program insertion. (Proj 0486) Tactical Support Center: The Tactical Mobile program provides agile evolutionary systems and equipment upgrades to support the Maritime Patrol and Reconnaissance Force Commanders with the capability to plan, direct and control the tactical operations of Maritime Patrol and Reconnaissance Aircraft and other assigned units within their respective area of responsibility. Looking ahead, TacMobile provides critical mission planning and reach-back capabilities between the Maritime Patrol and Reconnaissance Aircraft, primarily the P-8A/Poseidon, and MQ-4C/Triton, and the Maritime Intelligence Surveillance and Reconnaissance Enterprise. These operations include littoral, open ocean, and over land long-dwell surveillance, anti-surface warfare, over-the-horizon targeting, counter-drug operations, power projection, antisubmarine warfare, mining, search and rescue, indications and warning, realtime full motion video collection and streaming/ dissemination, and special operations. The missions are supported by Tactical Operations Centers, Mobile Tactical Operations Centers, and Fly Away Kits. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Navy                                                                               Date: June 2025 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 5: System            PE 0604231N / COMMAND AND CONTROL Development & Demonstration (SDD) (Proj 2343,2345) Tactical meteorological and oceanographic (METOC) Applications and Fleet METOC Equipment: The Air/Ocean Equipment Engineering (AOEE) projects provide new capabilities to support naval combat forces. This program engineers and developmentally tests organic and remote sensors, communication interfaces, and processing and display devices. This equipment is engineered to measure, ingest, store, process, distribute and display conditions of the physical environment that are essential to the optimum employment and performance of naval warfare systems. AOEE also engineers capabilities for shipboard and shore-based tactical systems. A major area of focus for the AOEE program is to provide the engineering development of specialized equipment and measurement capabilities that are intended to monitor specific conditions of the physical environment in hostile and remote areas in response to fleet demand signals for increased sensing capability and capacity to support battlespace collections and prediction on short to intermediate time scales. With such capabilities, the war fighters' situational awareness of the operational effects of the physical environment are made more certain. Efforts include investigation of emerging technologies through study, development, and associated testing for feasibility of program insertion. Major emphasis areas include the Naval Integrated Tactical Environmental System Next Generation (NITES-Next) project (2343), Littoral Battlespace Sensors - Unmanned Undersea Vehicles (LBS-UUV) and the Environmental Satellite Receiver Processor (ESRP) project (2345). (Proj 3050) Deployable Joint Command and Control (DJC2) provides a self-contained, standardized, rapidly deployable, modular, scalable, and reconfigurable joint command and control (C2) capability to designated Geographic Combatant Commands (GCCs). DJC2 is the materiel solution to Defense Planning Guidance that called for the development of standing Joint Task Forces (JTFs) with a deployable C2 capability. DJC2 will ensure that Joint Force Commanders (JFC) are equipped, as well as trained and organized, to carry out their C2 responsibilities. DJC2 provides GCCs and JFCs a mission critical, integrated family of systems with which to plan, control, coordinate, execute, and assess operations. It is designed to deploy rapidly, set up within hours, and quickly provide necessary C2 mission and collaboration functionality across the full spectrum of JTF operations. The DJC2 has also been deployed in support of Humanitarian Assistance and Disaster Relief (HA/DR) efforts. The capability is intended for all levels of conflict and will be reconfigurable to meet specific GCC and JTF mission requirements. This capability is interoperable with higher and adjacent echelons of command (to include coalition allies) as well as with supporting elements to include joint forces. (Proj 3260) Naval Operational Business Logistics Enterprise (NOBLE) is the logistics information technology family of systems (FoS) comprised of the Naval Operational Supply System (NOSS), the Naval Maintenance, Repair, and Overhaul (N-MRO), and supporting capabilities to include a common platform hosting environment and data exchange solutions, and the Logistics Integrated Data Environment (L-IDE) which supports and align readiness data systems to ensure that trusted, critical logistics data is widely available to or accessible by mission commanders, warfighters, decision-makers, and mission partners in a real-time, useable, secure, and linked manner to enable analytics, and support broader DoD/DON data efforts. NOBLE enables combat lethality by generating and sustaining Navy and Marine Corps force readiness for operational commanders afloat and ashore, providing the foundational capability to keep ships driving, planes flying, and weapons firing from an equipment Operational Availability (Ao) perspective. NOBLE is the centerpiece of the Fleet's strategic imperative to improve Sailor, unit and group maintenance self-sufficiency combat operations in a communications and access-denied arena. NOBLE's mission is to provide the Navy and Marine Corps with an integrated, scalable, and cyber-secure capability that supports the management of logistical information, material, and funds required to maintain and operate ships, submarines, and aircraft. NOBLE FoS will provide direct support to warfighter readiness with maintenance, supply, and financial capabilities, and a federated data environment to enable information integration for decision making in contested environments, and real-time data driven operational and ashore readiness analytics. These capabilities include Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Navy                                                                                  Date: June 2025 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 5: System              PE 0604231N / COMMAND AND CONTROL Development & Demonstration (SDD) enhanced situational awareness, planning, execution, personnel administration, and management of maintenance and supply logistics and business functions to ships/ submarines, aviation squadrons, shore operational sites, and expeditionary units with a total user base exceeding 150,000. The NOBLE FoS will support Aviation and Maritime organizational, intermediate, and depot level maintenance activities and facilities. The NOBLE architecture will meet current and emerging demands for cyber security, enable Financial Improvement and Audit Readiness (FIAR), drive efficiency into Navy logistics and aviation and maritime maintenance mission requirements, enable analytics, and eliminate over 700 application/database servers. NOBLE FoS will deploy to the Consolidated Afloat Networks and Enterprise Services (CANES) afloat, Non-CANES platforms, Department of the Navy (DON) commercial cloud computing environments ashore, and US Marine Corps operating environments. NOBLE FoS will deploy to the Consolidated Afloat Networks and Enterprise Services (CANES) afloat, Non-CANES platforms, Department of the Navy (DON) commercial cloud computing environments ashore, and US Marine Corps operating environments. (Proj 3324) Navy Air Operations Command and Control (NAOC2): NAOC2 integrates and tests Air Force program of record systems that provide an integrated and scalable planning system for standardized, secure, and automated decision support for Air Force, Joint, and Allied commanders worldwide. These programs provide automated air operations planning, execution management and intelligence capabilities at the Force level to include fleet commanders, numbered fleet commanders, Commander Carrier Strike Groups, Commander Expeditionary Strike Groups, Commander Landing Forces, and Joint Task Force Commanders. NAOC2 includes Theater Battle Management Core System (TBMCS) and Kessel Run Applications Kit for Enterprise Navy (KRAKEN). KRAKEN (when fielded) will provide rapid, agile delivery of capabilities to the fleet by commercial cloud infrastructure using Development, Security, Operations (DevSecOps) cloud native applications. KRAKEN is comprised of multiple tactical software applications that will provide continuous iterate delivery of software to shipboard and shore users. It will also align with the Joint C2 Reference Architecture (JC2RA) such as Consolidated Afloat Networks and Enterprise Services (CANES). KRAKEN is not natively compatible with Navy Information Technology (IT) infrastructure, such as CANES, and requires a significant level of system integration. Continuation of Navy integration and test efforts will significantly enhance the ability of the Joint Force Air Component Commander and Combined Air Operations Center personnel to plan daily air operations including strike, airlift, offensive/defensive air, missile defense, and refueling missions in support of combat operations. Developmental Testing is continuous and operates in parallel with the DevSecOps construct. KRAKEN will be continued for new technology insertion into Navy infrastructure network and hardware in support of Naval Air C2 and Net Enabled Weapons system integration. KRAKEN addresses the requirement of war fighter distributed planning and execution processes along with significantly improving Joint interoperability. TBMCS continues a hardware transition to CANES. Currently, TBMCS is the key system that is used to conduct real world air planning in the Joint and Navy environments. KRAKEN will replace TBMCS while bringing more flexibility to the war fighter. (Proj 9123) FORCEnet: Funding supports IW Portfolio Health Assessments (PHAs) of Navy mission areas and identifies gaps in Information Warfare (IW) capabilities in the context of assessed mission areas. Funding supports vignettes, technical baselines, architecture products, and briefings developed to support sponsor decision making processes. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Navy                                                                                Date: June 2025 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 5: System             PE 0604231N / COMMAND AND CONTROL Development & Demonstration (SDD) PHA analyzes the Navy's Information Warfare port… [truncated]$$, NULL, 81291000, 79386000, 76866000, NULL, NULL, 117, $$RDTEN_BA5_Book.pdf$$, NULL, FALSE, 139697000, 64547000, 73534000, 73534000, NULL, 73534000, 74774000, $$The Tactical Command System upgrades the Navy's Command, Control, Communications, Computer and Intelligence (C4I) systems and processes C4I information for all warfare mission areas including planning, direction and reconstruction of missions for peacetime, wartime and times of crises. Programs will implement digital system-of-systems engineering by using tools such as Model Based System Engineering (MBSE) and Digital Twins to create adaptable digital models to optimize system engineering from design, development and testing to operations and sustainment. Programs will use Development, Security and Operations (DevSecOps) processes for continuous development, integration, testing and deployment, along with common platform services such as Agile Core Services (ACS), for faster fielding of capability. Overall program development efforts include the investigation of emerging technologies through study, development and associated testing for feasibility of program insertion. (Proj 0486) Tactical Support Center: The Tactical Mobile program provides agile evolutionary systems and equipment upgrades to support the Maritime Patrol and Reconnaissance Force Commanders with the capability to plan, direct and control the tactical operations of Maritime Patrol and Reconnaissance Aircraft and other assigned units within their respective area of responsibility. Looking ahead, TacMobile provides critical mission planning and reach-back capabilities between the Maritime Patrol and Reconnaissance Aircraft, primarily the P-8A/Poseidon, and MQ-4C/Triton, and the Maritime Intelligence Surveillance and Reconnaissance Enterprise. These operations include littoral, open ocean, and over land long-dwell surveillance, anti-surface warfare, over-the-horizon targeting, counter-drug operations, power projection, antisubmarine warfare, mining, search and rescue, indications and warning, realtime full motion video collection and streaming/ dissemination, and special operations. The missions are supported by Tactical Operations Centers, Mobile Tactical Operations Centers, and Fly Away Kits. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                               Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 5: System            PE 0604231N / COMMAND AND CONTROL Development & Demonstration (SDD) (Proj 2343,2345) Tactical meteorological and oceanographic (METOC) Applications and Fleet METOC Equipment: The Air/Ocean Equipment Engineering (AOEE) projects provide new capabilities to support naval combat forces. This program engineers and developmentally tests organic and remote sensors, communication interfaces, and processing and display devices. This equipment is engineered to measure, ingest, store, process, distribute and display conditions of the physical environment that are essential to the optimum employment and performance of naval warfare systems. AOEE also engineers capabilities for shipboard and shore-based tactical systems. A major area of focus for the AOEE program is to provide the engineering development of specialized equipment and measurement capabilities that are intended to monitor specific conditions of the physical environment in hostile and remote areas in response to fleet demand signals for increased sensing capability and capacity to support battlespace collections and prediction on short to intermediate time scales. With such capabilities, the war fighters' situational awareness of the operational effects of the physical environment are made more certain. Efforts include investigation of emerging technologies through study, development, and associated testing for feasibility of program insertion. Major emphasis areas include the Naval Integrated Tactical Environmental System Next Generation (NITES-Next) project (2343), Littoral Battlespace Sensors - Unmanned Undersea Vehicles (LBS-UUV) and the Environmental Satellite Receiver Processor (ESRP) project (2345). (Proj 3050) Deployable Joint Command and Control (DJC2) provides a self-contained, standardized, rapidly deployable, modular, scalable, and reconfigurable joint command and control (C2) capability to designated Geographic Combatant Commands (GCCs). DJC2 is the materiel solution to Defense Planning Guidance that called for the development of standing Joint Task Forces (JTFs) with a deployable C2 capability. DJC2 will ensure that Joint Force Commanders (JFC) are equipped, as well as trained and organized, to carry out their C2 responsibilities. DJC2 provides GCCs and JFCs a mission critical, integrated family of systems with which to plan, control, coordinate, execute, and assess operations. It is designed to deploy rapidly, set up within hours, and quickly provide necessary C2 mission and collaboration functionality across the full spectrum of JTF operations. The DJC2 has also been deployed in support of Humanitarian Assistance and Disaster Relief (HA/DR) efforts. The capability is intended for all levels of conflict and will be reconfigurable to meet specific GCC and JTF mission requirements. This capability is interoperable with higher and adjacent echelons of command (to include coalition allies) as well as with supporting elements to include joint forces. (Proj 3260) Naval Operational Business Logistics Enterprise (NOBLE) is the logistics information technology family of systems (FoS) comprised of the Naval Operational Supply System (NOSS), the Naval Maintenance, Repair, and Overhaul (N-MRO), and supporting capabilities to include a common platform hosting environment and data exchange solutions, and the Logistics Integrated Data Environment (L-IDE) which supports and align readiness data systems to ensure that trusted, critical logistics data is widely available to or accessible by mission commanders, warfighters, decision-makers, and mission partners in a real-time, useable, secure, and linked manner to enable analytics, and support broader DoW/DON data efforts. NOBLE enables combat lethality by generating and sustaining Navy and Marine Corps force readiness for operational commanders afloat and ashore, providing the foundational capability to keep ships driving, planes flying, and weapons firing from an equipment Operational Availability (Ao) perspective. NOBLE is the centerpiece of the Fleet's strategic imperative to improve Sailor, unit and group maintenance self-sufficiency combat operations in a communications and access-denied arena. NOBLE's mission is to provide the Navy and Marine Corps with an integrated, scalable, and cyber-secure capability that supports the management of logistical information, material, and funds required to maintain and operate ships, submarines, and aircraft. NOBLE FoS will provide direct support to warfighter readiness with maintenance, supply, and financial capabilities, and a federated data environment to enable information integration for decision making in contested environments, and real-time data driven operational and ashore readiness analytics. These capabilities include Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                                 Date: April 2026 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 5: System              PE 0604231N / COMMAND AND CONTROL Development & Demonstration (SDD) enhanced situational awareness, planning, execution, personnel administration, and management of maintenance and supply logistics and business functions to ships/ submarines, aviation squadrons, shore operational sites, and expeditionary units with a total user base exceeding 150,000. The NOBLE FoS will support Aviation and Maritime organizational, intermediate, and depot level maintenance activities and facilities. The NOBLE architecture will meet current and emerging demands for cyber security, enable Financial Improvement and Audit Readiness (FIAR), drive efficiency into Navy logistics and aviation and maritime maintenance mission requirements, enable analytics, and eliminate over 700 application/database servers. NOBLE FoS will deploy to the Consolidated Afloat Networks and Enterprise Services (CANES) afloat, Non-CANES platforms, Department of the Navy (DON) commercial cloud computing environments ashore, and US Marine Corps operating environments. (Proj 3324) Navy Air Operations Command and Control (NAOC2): NAOC2 integrates and tests Air Force program of record systems that provide an integrated and scalable planning system for standardized, secure, and automated decision support for Air Force, Joint, and Allied commanders worldwide. These programs provide automated air operations planning, execution management and intelligence capabilities at the Force level to include fleet commanders, numbered fleet commanders, Commander Carrier Strike Groups, Commander Expeditionary Strike Groups, Commander Landing Forces, and Joint Task Force Commanders. NAOC2 includes Theater Battle Management Core System (TBMCS) and Command and Control (C2)Core Air. C2Core Air (when fielded) will provide rapid, agile delivery of capabilities to the fleet using Development, Security, Operations (DevSecOps) Web applications. C2Core Air is comprised of multiple tactical software applications that will provide continuous iterate delivery of software to shipboard and shore users. It will also align with the Joint C2 Reference Architecture (JC2RA) such as Consolidated Afloat Networks and Enterprise Services (CANES). C2Core Air is not natively compatible with Navy Information Technology (IT) infrastructure, such as CANES, and requires system integration. Continuation of Navy integration and test efforts will significantly enhance the ability of the Joint Force Air Component Commander and Combined Air Operations Center personnel to plan daily air operations including strike, airlift, offensive/defensive air, missile defense, and refueling missions in support of combat operations. Developmental Testing is continuous and operates in parallel with the DevSecOps construct. C2Core Air addresses the requirement of war fighter distributed planning and execution processes along with significantly improving Joint interoperability. Currently, TBMCS is the key system that is used to conduct real world air planning in the Joint and Navy environments. C2Core Air will replace TBMCS while bringing more flexibility to the war fighter. (Proj 9123) FORCEnet: Program zeroed out starting in FY 2027. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                              Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 5: System            PE 0604231N / COMMAND AND CONTROL Development & Demonstration (SDD)$$, $$Budget J-Books/FY27/Navy/RDTEN_BA5_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604233F$$, $$Specialized Undergraduate Flight Training$$, $$rdte_af_ba7$$, $$aetc$$, 2026, 66200000, 26265000, 30043000, NULL, $${"ba_raw": "6.7", "source": "af_r1_fy26", "original_pe": "0604233F"}$$::jsonb, $$Supports Air Education and Training Command's (AETC) implementation of Specialized Undergraduate Pilot Training and the Department of Defense initiative for joint pilot training. Undergraduate Remotely Piloted Aircraft (RPA) Training (URT) continues development, integration, testing, and deploying activities for the new URT Fundamentals Training System. This program produces RPA pilots and Sensor Operators from accession sources to man RPA squadrons. T-6 Operational System Development continues follow on development activities to the T-6 including but not limited to studies & development efforts, instructional courseware, and logistics support to include Diminishing Manufacturing Sources & Material Shortages (DMSMS) and development activities related to DMSMS. Included is development for the Next Generation On-Board Oxygen Generation System (OBOGS), Crash Survivable Recorder (CSR), Avionics Replacement Program (ARP) and associated upgrades. There are currently 443 aircraft in the Air Force inventory with a service life through Dec 2049. The T-38 is a twin-engine, two-seat (tandem), supersonic jet trainer. The T-38C is used by AETC as an advanced trainer in Specialized Undergraduate Pilot Training and Introduction to Fighter Fundamentals, and by Air Force Materiel Command as a test bed for fighter-type aircraft capability. T-38A/B aircraft are used by Air Combat Command as a companion trainer for U-2 operational units and in Adversary Air (ADAIR) exercises supporting F-22 readiness, and by Air Force Global Strike Command as a companion trainer for B-2 operational units. There are currently 497 active T-38s in the Air Force inventory (53 T-38A, six AT-38B and 438 T-38C). T-38s first entered service in 1960 with an average service life of over 50 years. In FY 2024, this PE provided $10.0 million for a Rapid Acquisition Authority requirement. This requirement supports performance of a full financial audit as required by title 10 U.S.C. Chapter 9A, Sec 240-D. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                        Date: June 2025 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:            PE 0604233F / Specialized Undergraduate Flight Training Operational Systems Development The FY 2026 request was reduced by $0.951 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative." This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such programs funds would be in addition to the civilian pay expenses budgeted in program elements 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY 2024 $1.885 million was expended for civilian pay expenses in this program element, and in FY 2025 $3.063 million is forecast for civilian pay expenses in this program element. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, NULL, 2047000, 4185000, 4281000, NULL, NULL, 149, $$FY26 Air Force Research and Development Test and Evaluation Vol III.pdf$$, NULL, FALSE, 29132000, 56373000, 22071000, 22071000, 0, 22071000, 4368000, $$Specialized Undergraduate Flight Training program supports Air Education and Training Command's (AETC) initiative for joint pilot training. Undergraduate Remotely Piloted Aircraft Training (URT) effort continues development, integration, testing, and deploying activities for the new URT Fundamentals Training System. This program produces Remotely Piloted Aircraft (RPA) pilots and Sensor Operators from accession sources to man RPA squadrons. T-6 Operational System Development effort continues follow-on development activities for T-6 aircraft to include but not limited to the Avionics Replacement Program (ARP) and associated upgrades. Current T-6A avionics are comprised of analog and 1st generation digital components which are increasingly impacted by Diminishing Manufacturing Sources and Material Shortages (DMSMS) resulting in reduced Aircraft Availability (AA) and increased life-cycle sustainment costs. No less than 23 components are impacted by DMSMS and will be replaced by ARP to improve reliability, availability, and reduce system sustainment costs. The ARP addresses DMSMS issues, current T-6A FAA compliance issues, and fulfills outstanding safety recommendations. The solution will be incorporated into 405 AETC T-6A aircraft and 86 Ground Based Trainers. T-38 Operational System Development effort provides advanced trainers for Specialized Undergraduate Pilot Training and Introduction to Fighter Fundamentals, and is a test bed for fighter-type aircraft capability. The T-38A/B/C is a is a twin-engine, two-seat (tandem), supersonic jet trainer used by AETC, Air Combat Command and Air Force Global Strike Command as a companion trainer in Adversary Air (ADAIR) exercises supporting U-2 operational units, F-22 readiness, and B-2 operational units. There are currently 486 operational T-38s in the Air Force inventory (53 T-38A, six T-38B and 427 T-38C). This requirement supports performance of a full financial audit as required by title 10 U.S.C. Chapter 9A, Sec 240-D. This program element included all necessary expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 0605829F, 0605831F, 0605833F, and 0605898F. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                      Date: April 2026 Appropriation/Budget Activity                                                      R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:                  PE 0604233F / Specialized Undergraduate Flight Training Operational Systems Development This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume III.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604245M$$, $$H-1 UPGRADES$$, $$rdte_navy_ba5$$, $$mc$$, 2026, 62240000, 29181000, 39023000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "mc", "page_num": 32, "original_pe": "0604245M", "page_header": "Department of the Navy"}$$::jsonb, $$The mission of the AH-1 attack helicopter is to provide rotary wing close air support, counter unmanned aerial system (UAS), counter maritime, anti-armor, armed escort, armed/visual reconnaissance, survivability enhancements, and fire support coordination capabilities under day/night and adverse weather conditions. The mission of the UH-1 utility helicopter is to provide command and control and combat assault support under day/night and adverse weather conditions and special operations support; supporting arms coordination and aeromedical evacuation. Major modifications for both aircraft include 37 AH-1Ws converted to AH-1Zs, build 152 new AH-1Zs, remanufacture ten (10) H-1N helicopters and build 150 new UH-1Y models. AH-1Z and UH-1Y models include a 4-bladed, composite rotor system with semi-automatic bladefold, performance-matched transmissions, T700 Engine Digital Electronic Control Units, 4-bladed tail rotors and drive systems, more effective stabilizers, upgraded landing gear, and common, fully integrated cockpits and avionics systems. These upgrades add 10,000 flight hours to AH-1Z/UH-1Y airframes. The fully integrated cockpits reduce operator workload and improve situational awareness, thus increasing safety and reducing the rate of aircraft attrition. They provide considerable growth potential for future weapon systems and avionics to significantly increase mission effectiveness and survivability. The cockpits also include integration of onboard mission planning, communications, digital fire control, self-navigation, night navigation/targeting, air-to-ground missile and air-launched intercept missile weapon systems management in nearly identical crew stations, which significantly reduces training requirements. These upgrades maximize commonality between the two aircraft and provide needed improvements in crew and passenger survivability, payload, power available, endurance, range, airspeed, maneuverability and supportability. This budget is required for follow-on improvements to H-1 aircraft via integration of sensors and weapons, avionics, and air vehicle components that will address deficiencies, systems safety, obsolescence, readiness, reliability, supportability, and relevance in the battlespace. Improvements will include all associated System Configuration Set (SCS) updates and address hazard reports against air vehicle and engine, sensors and weapons, and avionics components, systems, and subsystems, training, and aircrew systems as well as integration and testing related to the aircraft platforms. This program is funded under SYSTEM DEVELOPMENT AND DEMONSTRATION because it includes those projects that have passed Milestone B approval and are conducting engineering and manufacturing development tasks aimed at meeting validated requirement prior to full-rate production decision. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Navy                                                                            Date: June 2025 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 5: System           PE 0604245M / H-1 UPGRADES Development & Demonstration (SDD)$$, NULL, 65889000, 55762000, 47248000, NULL, NULL, 119, $$RDTEN_BA5_Book.pdf$$, NULL, FALSE, 43732000, 62240000, 66446000, 66446000, NULL, 66446000, 45114000, $$This line item funds improvements to the UH-1Y Venom and AH-1Z Viper aircraft and related systems, collectively referred to as H-1 aircraft. H-1's belongs to the same unit, Marine Light Attack Helicopter Squadrons (HMLA), and are often flown together for complementary mission roles. The mission of the HMLA is to support the combatant commander by providing offensive air support, utility support, armed escort, and airborne supporting arms coordination day or night under all weather conditions during expeditionary, joint or combined operations. H-1s are capable of offensive air support (to include Counter Unmanned Aerial System (CUAS) and Counter Maritime), armed escort, armed/visual reconnaissance, and airborne supporting arms coordination. The UH-1Y utility helicopter is further capable of conducting combat assault transport, airborne command and control, casualty evacuation and special operations support. The UH-1Y is crewed by two pilots and two crew chiefs with maximum capacity of 12 personnel. The AH-1Z attack helicopter is the Marine Corps primary provider of air to surface fire's capable of providing volume of fires support for anti-armor, counter maritime, precision strike, CUAS, and anti-helicopter and point air defense via current armament including the Sidewinder and Hellfire missiles, Joint Air-to-Ground Missile (JAGM), Advanced Precision Kill Weapon System (APKWS), Precision Attack Strike Munition (PASM), a chin-mounted 20mm turret, and a wide variety of forward-firing and external stores. The AH-1Z is a tandem, two-seat attack helicopter crewed by two pilots. H-1's are fully delivered and are expected to fly into the 2050's as a replacement platform is developed and selected. The Marine Corps prioritized and invested in a H-1 Mid-Life Modernization strategy to cover fires gaps and bridge to an eventual replacement program. RDTE funding is a culmination of the planned mid-life modernization strategy and aligning with the Marine Corps' top three H-1 priorities of lethality, Digital Interoperability (DI), and improved survivability, while enabling future capability improvements. Funding for improvements align with the Marine Corps' top three H-1 priorities of lethality, Digital Interoperability (DI), and improved survivability, while enabling future capability improvements. Development programs seek to improve readiness, increase aircraft availability, and decrease operating costs. Reliability improvements and obsolescence management will reduce flight hour costs, maintain/increase operational capability, and increase time on wing. Improvements include software upgrades and integration of test assets to support engineering development and testing to address hazard reports against air vehicle and engine, sensors and weapons, and avionics components, systems, and subsystems, training, and aircrew systems as well as integration and testing related to the aircraft platforms. This program is funded under SYSTEM DEVELOPMENT AND DEMONSTRATION because it includes those projects that have passed Milestone B approval and are conducting engineering and manufacturing development tasks aimed at meeting validated requirements prior to full-rate production decision. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                             Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 5: System            PE 0604245M / H-1 UPGRADES Development & Demonstration (SDD)$$, $$Budget J-Books/FY27/Navy/RDTEN_BA5_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604250D8Z$$, $$Advanced Innovative Technologies$$, $$rdte_dw_ba4$$, $$dw_strato$$, 2026, 1163452000, 988235000, 940431000, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "dw", "page_num": 72, "original_pe": "0604250D8Z", "page_header": "Defense-Wide"}$$::jsonb, $$In support of the Interim National Defense Strategy, the Strategic Capabilities Office (SCO) develops, demonstrates, and transitions operationally impactful capabilities and effects to shape and counter emerging threats and increase the lethality of the Joint Force in contested environments. The SCO combines innovation with concepts of operation to develop novel capabilities solving critical national security challenges in partnership with the Services, Defense Agencies, Combatant Commands (CCMDS), Joint Chiefs of Staff, Intelligence Community, and the Office of the Secretary of Defense (OSD).$$, NULL, 2681606000, 2587022000, 2510893000, NULL, NULL, 107, $$RDTE_OSD_PB_2026.pdf$$, $$OSD$$, FALSE, 914593000, 770844000, 2626130000, 2626130000, NULL, 2626130000, 2142670000, $$In support of the Interim National Defense Strategy, the Strategic Capabilities Office (SCO) develops, demonstrates, and transitions operationally impactful capabilities and effects to shape and counter emerging threats and increase the lethality of the Joint Force in contested environments. The SCO combines innovation with concepts of operation to develop novel capabilities solving critical national security challenges in partnership with the Services, Defense Agencies, Combatant Commands (CCMDS), Joint Chiefs of Staff, Intelligence Community, and the Office of the Secretary of War (OSW). The FY 2026 spend plan amount for Advanced Innovative Technologies 0604250D8Z includes $770,844 thousand of discretionary, and $1,002,000 thousand of mandatory (reconciliation) for a total of $1,772,844 thousand.$$, $$Budget J-Books/FY27/DW/RDTE_OSW_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604256A$$, $$Threat Simulator Development$$, $$rdte_army_ba6$$, $$dw_osd$$, 2026, 74767000, 71587000, 75298000, NULL, $${"act": "06", "ba_raw": "6.6", "source": "r1_fy26", "service": "army", "page_num": 20, "original_pe": "0604256A", "page_header": "Department of the Army"}$$::jsonb, $$This Program Element (PE) supports the design, development, acquisition, integration and fielding of realistic mobile threat simulators and realistic threat simulation products utilized in Army/Department of Defense (DoD) test and evaluation (T&E) and developmental and operational tests. This PE originally funded simulators representing Soviet equipment, but scope was expanded to address emerging world threats. Army Threat Simulator and Threat Simulation products are utilized to populate test battlefields for United States (U.S.) Army Test and Evaluation Command (ATEC), to conduct developmental and operational tests, and to support Program Executive Office for Simulation, Training and Instrumentation (PEO STRI) required user testing in System Integration Laboratories (SILs) and hardware/simulation in- the-loop facilities. These battlefield simulators represent adversary systems (e.g. missile systems, command, control and communications systems, electronic warfare systems, etc.) in order to portray a realistic threat environment during testing of U.S. weapon systems. Army Threat Simulator and Threat Simulation products developed or fielded under this PE support Army-wide, non-system-specific threat product requirements. Each capability is pursued in concert and coordination with existing Army/DoD and Tri-Service capabilities to eliminate duplication of effort. Simulator development is responsive to Office of the Secretary of Defense and Government Accountability Office guidance for the Army to conduct operational testing in a realistic threat environment. Actual threat equipment is acquired when appropriate (in lieu of development) and total package fielding is still required (i.e., instrumentation, operations and maintenance, manuals, new equipment training, etc.). Threat simulator development is accomplished under the auspices of the Project Manager for Cyber Test and Training (PM CT2) and the Director, Operational Test and Evaluation (DOT&E) Threat Simulator Investment Working Group. This funding line supports testing of Army Modernization Priority Programs. The FY 2026 request was reduced by $0.258 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative." Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                               Date: June 2025 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 6: RDT&E              PE 0604256A / Threat Simulator Development Management Support$$, NULL, 59836000, 59170000, 59731000, NULL, NULL, 173, $$RDTE - Vol 4 - Budget Activity 6.pdf$$, NULL, FALSE, 72696000, 74767000, 60233000, 60233000, NULL, 60233000, 60327000, $$This Program Element (PE) supports the design, development, acquisition, integration and fielding of realistic mobile threat simulators and realistic threat simulation products utilized in Army/Department of War (DoW) test and evaluation (T&E) and developmental and operational tests. This PE originally funded simulators representing Soviet equipment, but scope was expanded to address emerging world threats. Army Threat Simulator and Threat Simulation products are utilized to populate test battlefields for United States (U.S.) Army Test and Evaluation Command (ATEC), to conduct developmental and operational tests, and to support Capability Program Executive Simulation, Training, Test and Threat (CPE ST3) (formerly Program Executive Office for Simulation, Training and Instrumentation (PEO STRI)) required user testing in System Integration Laboratories (SILs) and hardware/simulation in-the-loop facilities. These battlefield simulators represent adversary systems (e.g. missile systems, command, control and communications systems, electronic warfare systems, etc.) in order to portray a realistic threat environment during testing of U.S. weapon systems. Army Threat Simulator and Threat Simulation products developed or fielded under this PE support Army-wide, non-system-specific threat product requirements. Each capability is pursued in concert and coordination with existing Army/DoW and Tri-Service capabilities to eliminate duplication of effort. Simulator development is responsive to Office of the Secretary of War and Government Accountability Office guidance for the Army to conduct operational testing in a realistic threat environment. Actual threat equipment is acquired when appropriate (in lieu of development) and total package fielding is still required (i.e., instrumentation, operations and maintenance, manuals, new equipment training, etc.). Threat simulator development is accomplished under the auspices of the Project Manager for Cyber Test and Training (PM CT2) and the Director, Operational Test and Evaluation (DOT&E) Threat Simulator Investment Working Group. This funding line supports testing of Army Modernization Priority Programs. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                              Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 6: RDT&E             PE 0604256A / Threat Simulator Development Management Support$$, $$Budget J-Books/FY27/Army/RDTE - Vol 4 - Budget Activity 6.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604256F$$, $$Threat Simulator Development$$, $$rdte_af_ba6$$, $$afrl_rd$$, 2026, 41125000, 16418000, 17291000, NULL, $${"ba_raw": "6.6", "source": "af_r1_fy26", "original_pe": "0604256F"}$$::jsonb, $$The Air Force requires a comprehensive set of indoor and outdoor test facilities to implement the Air Force Electronic Warfare (EW) Test Process in order to test EW systems, including Directed Energy (DE). To manage program risk effectively throughout the EW weapons system acquisition process, and to conduct T&E effectively and efficiently, a broad multi-spectrum integrated set of T&E capabilities, ranging from Modeling and Simulation (M&S), to full-scale chamber testing, to flight testing on open-air ranges (OAR), is required. The EW Test Process Support task provides investment management and coordinated technical oversight of EW T&E facilities, including studies, analyses, and related documentation. Additionally, successful EW capabilities in battle are predicated upon a thorough understanding of the threat. To meet that requirement, this PE also includes funding to acquire foreign materiel, and to thoroughly test and evaluate that foreign materiel to understand how those threat systems affect and are affected by our EW systems. This program is in Budget Activity 6, RDT&E Management Support because this budget activity includes research, development, test and evaluation efforts and funds to sustain and/or modernize the installations or operations required for general research, development, test and evaluation.$$, NULL, 44077000, 44932000, 45808000, NULL, NULL, 125, $$FY26 Air Force Research and Development Test and Evaluation Vol III.pdf$$, NULL, FALSE, 17078000, 40935000, 44526000, 44526000, 0, 44526000, 46664000, $$The Air Force requires a comprehensive set of indoor and outdoor test facilities to implement the Air Force Electronic Warfare (EW) Test Process in order to test EW systems, including Directed Energy (DE). To manage program risk effectively throughout the EW weapons system acquisition process, and to conduct T&E effectively and efficiently, a broad multi-spectrum integrated set of T&E capabilities, ranging from Modeling and Simulation (M&S), to full-scale chamber testing, to flight testing on open-air ranges (OAR), is required. The EW Test Process Support task provides investment management and coordinated technical oversight of EW T&E facilities, including studies, analyses, and related documentation. Additionally, successful EW capabilities in battle are predicated upon a thorough understanding of the threat. To meet that requirement, this Program also includes funding to acquire foreign materiel, and to thoroughly test and evaluate that foreign materiel to understand how those threat systems affect and are affected by our EW systems. This program element included all necessary expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 0606398F and 0605807F. This program is in Budget Activity 6, RDT&E Management Support because this budget activity includes research, development, test and evaluation efforts and funds to sustain and/or modernize the installations or operations required for general research, development, test and evaluation. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                          Date: April 2026 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 6: RDT&E         PE 0604256F / Threat Simulator Development Management Support$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume III.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$P_2031_L017$$, $$CH-47 Helicopter$$, $$proc_army_2031_ba1$$, $$peo_aviation$$, 2026, 618798000, 423887000, 699698000, NULL, $${"page": 11, "ba_num": "01", "source": "p1_fy26", "ba_name": "Aircraft", "line_no": "17", "service": "army", "fy24_qty": 9, "fy25_qty": 10, "appr_code": "2031", "appr_name": "Aircraft Procurement, Army", "fy26_v178": {"disc_K": 628798, "li_num": 12, "source": "p40_fy26_v178", "supp_K": 0, "source_pdf": "uploads/Budget J-Books/FY27/Army/Aircraft_Procurement_Army.txt"}, "fy26t_qty": 11, "fy26d_cost": 618798000, "fy26r_cost": 0, "ident_code": "A"}$$::jsonb, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, FALSE, NULL, 628798000, 39257000, 39257000, 0, 39257000, NULL, NULL, $$Budget J-Books/FY27/Army/Aircraft_Procurement_Army.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604256N$$, $$Threat Simulator Development$$, $$rdte_navy_ba6$$, $$dw_dote$$, 2026, 25133000, 22051000, 25823000, NULL, $${"act": "06", "ba_raw": "6.6", "source": "r1_fy26", "service": "navy", "page_num": 36, "original_pe": "0604256N", "page_header": "Department of the Navy"}$$::jsonb, $$This is a continuing program that consolidates the design, fabrication and integration of Naval Electronic Warfare (EW) threat simulators for increased managerial emphasis and coordination. These simulator development efforts provide realistic Developmental and Operational Test and Evaluation environments to test EW systems and defensive tactics. These projects develop threat Anti-Air and Anti-Ship weapon system simulators in accordance with the Services' requirements. The 0602 Project, Electronic Warfare Environment Simulation, directly supports the Test and Evaluation resource requirements for all Naval Air EW development programs to include radio frequency situational awareness and countermeasures. Programs in development and future programs include: Joint Strike Fighter, EA-18G, Low Band Transmitter, Next Generation Jammer, Advanced Anti-Radiation Guided Missile (AARGM), Long Range Anti-Ship Missile (LRASM). The 0672 Project, Effectiveness of Naval Electronic Warfare Systems (ENEWS), directly supports the Test and Evaluation resource requirements for Surface Ship Electronic Warfare Systems. ENEWS provides anti-ship cruise missile seeker simulators, modeling and simulation and state of the art test facilities. Current and future Programs of Record include: Surface Electronic Warfare Improvement Program (SEWIP), Advanced Off-Board Electronic Warfare (AOEW), Nulka, Long Endurance Electronic Decoy (LEED) and advanced IR Decoys. JUSTIFICATION FOR BUDGET ACTIVITY: This program is funded under RESEARCH, DEVELOPMENT, TEST and EVALUATION MANAGEMENT SUPPORT because it supports efforts directed toward sustaining or modernizing installations or operations required for general research, development, test and evaluation. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Navy                                                                    Date: June 2025 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 6: RDT&E           PE 0604256N / Threat Simulator Development Management Support$$, NULL, 47962000, 43904000, 46727000, NULL, NULL, 186, $$RDTEN_BA6_Book.pdf$$, NULL, FALSE, 25374000, 25133000, 16453000, 16453000, NULL, 16453000, 49596000, $$This is a continuing program that consolidates the design, fabrication and integration of Naval Electronic Warfare (EW) threat simulators for increased managerial emphasis and coordination. These simulator development efforts provide realistic Developmental and Operational Test and Evaluation environments to test EW systems and defensive tactics. These projects develop threat Anti-Air and Anti-Ship weapon system simulators in accordance with the Services' requirements. The 0602 Project, Electronic Warfare Environment Simulation, directly supports the Test and Evaluation resource requirements for all Naval Air EW development programs to include radio frequency situational awareness and countermeasures. Programs in development and future programs include: Joint Strike Fighter, EA-18G, Low Band Transmitter, Next Generation Jammer, Advanced Anti-Radiation Guided Missile (AARGM), Long Range Anti-Ship Missile (LRASM). The 0672 Project, Effectiveness of Naval Electronic Warfare Systems (ENEWS), directly supports the Test and Evaluation resource requirements for Surface Ship Electronic Warfare Systems. ENEWS provides anti-ship cruise missile seeker simulators, modeling and simulation and state of the art test facilities. Current and future Programs of Record include: Surface Electronic Warfare Improvement Program (SEWIP), Advanced Off-Board Electronic Warfare (AOEW), Nulka, Long Endurance Electronic Decoy (LEED) and advanced IR Decoys. JUSTIFICATION FOR BUDGET ACTIVITY: This program is funded under RESEARCH, DEVELOPMENT, TEST and EVALUATION MANAGEMENT SUPPORT because it supports efforts directed toward sustaining or modernizing installations or operations required for general research, development, test and evaluation. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                       Date: April 2026 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 6: RDT&E            PE 0604256N / Threat Simulator Development Management Support$$, $$Budget J-Books/FY27/Navy/RDTEN_BA6_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604257F$$, $$Advanced Technology and Sensors$$, $$rdte_af_ba4$$, $$afrl_ry$$, 2026, 40779000, 22616000, 15865000, NULL, $${"ba_raw": "6.4", "source": "af_r1_fy26", "original_pe": "0604257F"}$$::jsonb, $$The Advanced Technology and Sensors (ATS) Program Element (PE) coordinates the development, validation, test, and transition of platform-agile advanced sensor technologies (sensors, processing algorithms, automated target recognition software, multi-intelligence fusion) in support of aerial platforms including, but not limited to, High-Altitude Long Endurance (HALE), crewed and uncrewed airborne reconnaissance platforms, Autonomous Collaborative Platforms, and Collaborative Combat Aircraft (CCA) as well as Other Air Force Platforms (OAFP) whose capabilities are protected at a higher level. ATS' objectives are to develop, demonstrate, and rapidly transition advanced, interoperable, multi-platform solutions to reduce the find, fix, track, and target kill chain timeline. ATS seeks out lower Technology Readiness Level (TRL) technologies that have the potential to fill Geospatial Intelligence (GEOINT) capability gaps to support CCMD plans and the future AF's future force design. ATS matures these technologies to TRL 6/7 prior to transitioning to existing programs of record or to the Airborne Reconnaissance Systems PE (0305206F) for follow-on development under Budget Authority 7 (BA-7). The PE includes two levels of effort including Next Generation Sensors - Risk Reduction (NGS-RR) and Imaging and Targeting Support (I&TS). The NGS-RR program is a platform-agile suite of sensor development and demonstration technologies designed for the best flexibility and capability for an ever- changing scale of ISR missions. NGS-RR furthers maturation and risk reduction of select technologies initiated under I&TS and other low TRL maturation efforts culminating in operational prototype demonstrations. The power behind the NGS-RR program is an open architectural system design that enables rapid third- party software and line replaceable unit insertion/replacement. NGS-RR implements foundational sensor development technologies including the MEDUSA flight demonstration platform, Digital Engineering (DE), Model-Based Systems Engineering (MBSE), and a software environment and repository (AURORA). In FY 2026, NGS-RR will continue flight tests of fully integrated podded payloads, integration of maturation of NAVAIR and other maritime automated target recognition algorithms and support collaborative teaming demonstrations. Additionally, RESOLUTE SENTRY will transition from the AF Research Laboratory to NGS-RR for technical maturation and integration into the first operational platform in FY 2026. RESOLUTE SENTRY is an AI-driven, multi-platform, sense-making tool for predictive analytics and orchestration at the tactical edge. It provides real-time, high-quality detection, identification and tracking to close kill chains and predict adversary activity. The program delivers a platform-agnostic, edge-hostable software solution to ingest and fuse multi-INT data across multiple platforms at the tactical edge. The data will then be used to generate actionable information on the highly contested environment for Blue Force commanders and national decision making. RESOLUTE SENTRY will execute in this PE from FY26 to FY27, then will transition to ARS PE 35206F in FY28. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                              Date: June 2025 Appropriation/Budget Activity                                                      R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 4: Advanced PE 0604257F / Advanced Technology and Sensors Component Development & Prototypes (ACD&P) The I&TS program funds the technical maturation of low TRL sensors and processing capabilities to rapidly fill current GEOINT sensing capability gaps. To ensure alignment with Congressional intent, urgent Combatant Command (CCMD) requirements, and departmental priorities, the Air Force (AF) established a Headquarters level working group to guide, prioritize, and synchronize these enterprise sensor technology investments The GEOINT Capabilities Working Group (GCWG) reviews developmental technologies in the fourth quarter of each FY to approve and prioritize efforts for the following year. The Program Office is specifically structured to rapidly initiate projects in the execution year to expedite technical maturation and delivery to operational platforms at the speed of technology. Additional details are available at the appropriate classification level. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605829F, 0605831F, 0605833F, or 0605898F. In FY 2024 $0.000M was expended for civilian pay expenses in this program element, and in FY 2025 $0.000M is forecast for civilian pay expenses in this program element. This effort is in Budget Activity 4, Advanced Component Development and Prototypes (ACD&P), because efforts are necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment.$$, NULL, 10700000, 8700000, 8900000, NULL, NULL, 49, $$FY26 Air Force Research and Development Test and Evaluation Vol II.pdf$$, NULL, FALSE, 15865000, 40779000, 38756000, 38756000, 0, 38756000, 8600000, $$The Advanced Technology and Sensors (ATS) Program Element (PE) coordinates the development, validation, test, and transition of platform-agile advanced sensor technologies (sensors, processing algorithms, automated target recognition software, multi-intelligence fusion). These activities support crewed and uncrewed airborne reconnaissance platforms, autonomous collaborative platforms, Collaborative Combat Aircraft (CCA), and other Air Force platforms (OAFPs) whose capabilities are protected at a higher classification. ATS' objectives are to develop, demonstrate, and rapidly transition advanced, interoperable, multi-platform solutions to reduce the find, fix, track, and target kill chain timeline. ATS seeks lower Technology Readiness Level (TRL) technologies to fill Geospatial Intelligence (GEOINT) capability gaps to support Combatant Command (CCMD) plans and the AF's future force design. ATS matures these technologies to TRL 6/7 prior to transitioning to existing programs of record or to the Airborne Reconnaissance Systems PE (0305206F) for follow-on development under Budget Authority 7 (BA-7). The PE includes two levels of effort including Next Generation Sensors - Risk Reduction (NGS-RR) and Imaging and Targeting Support (I&TS). The NGS-RR project is a platform-agile suite of sensor and software development and demonstration technologies designed to maximize flexibility and capability for an ever-changing scale of ISR missions. NGS-RR furthers maturation and risk reduction of select technologies initiated under I&TS and other low TRL maturation efforts culminating in operational prototype demonstrations. NGS-RR uses an open architecture system design that enables rapid third-party software and line replaceable unit insertion/replacement. NGS-RR implements foundational sensor development technologies including the Multi-int Environment Demonstrator for Unimpeded Sensemaking and Autonomy (MEDUSA) flight demonstration platform, Model-Based Systems Engineering (MBSE), AI-based Utility for Robust Object Recognition Architecture (AURORA) software environment and repository, and the web-based digital engineering catalog Whole-system Analysis & Simulation Portal (WASP). Also funded under the NGS-RR project is the Resolute Sentry effort. Resolute Sentry is an AI-driven, multi-platform, sense-making tool for predictive analytics and orchestration at the tactical edge. It provides real-time, high-quality detection, identification and tracking to close kill chains and predict adversary activity. The project delivers a platform-agnostic, edge-hostable software solution to ingest and fuse multi-INT data across multiple platforms at the tactical edge. The data will then be used to generate actionable information on the highly contested environment for Blue Force commanders and national decision making. Resolute Sentry will transition to ARS PE 0305206F in FY 2028. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                                Date: April 2026 Appropriation/Budget Activity                                                      R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 4: Advanced PE 0604257F / Advanced Technology and Sensors Component Development & Prototypes (ACD&P) The I&TS project matures low TRL sensors and processing capabilities to rapidly fill current GEOINT sensing capability gaps. To ensure alignment with congressional intent, urgent CCMD requirements, and departmental priorities, the Air Force established a Headquarters level working group to guide, prioritize, and synchronize these enterprise sensor technology investments. The GEOINT Capabilities Working Group (GCWG) reviews developmental technologies in the fourth quarter of each FY to approve and prioritize efforts for the following year. The Program Office is specifically structured to rapidly initiate efforts in the execution year to expedite technical maturation and delivery to operational platforms at the speed of technology. Additional details are available at the appropriate classification level. This program element included all necessary expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 0605829F, 0605831F, 0605833F, and 0605898F. This effort is in Budget Activity 4, Advanced Component Development and Prototypes (ACD&P), because efforts are necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment.$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume II.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604258A$$, $$Target Systems Development$$, $$rdte_army_ba6$$, $$asa_alt$$, 2026, 16004000, 33940000, 27788000, NULL, $${"act": "06", "ba_raw": "6.6", "source": "r1_fy26", "service": "army", "page_num": 20, "original_pe": "0604258A", "page_header": "Department of the Army"}$$::jsonb, $$This funding line supports testing of Army Modernization Priority Programs. This Program Element funds aerial and ground target hardware and software development, maintenance, and upgrades. The overall objective is to ensure validation of weapon system accuracy and reliability by developing aerial and ground targets essential for test and evaluation (T&E). These targets are economical and expendable, remotely controlled or stationary, and often destroyed in use. The Army is the Tri-Service lead under the Secretariat Reliance panel for providing rotary wing, mobile ground, towed, and designated targets for T&E. The Army executes development of some service-peculiar target requirements in support of quality assurance, lot acceptance, and training and continues development of service-peculiar and on-going target materiel upgrades to maintain continuity with current weapons technology and trends in modern and evolving Army weapons. The FY 2026 request was reduced by $0.22 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative."$$, NULL, 16685000, 16827000, 16994000, NULL, NULL, 174, $$RDTE - Vol 4 - Budget Activity 6.pdf$$, NULL, FALSE, 27212000, 26004000, 16488000, 16488000, NULL, 16488000, 17164000, $$This funding line supports testing of Army Modernization Priority Programs. This Program Element funds aerial and ground target hardware and software development, maintenance, and upgrades. The overall objective is to ensure validation of weapon system accuracy and reliability by developing aerial and ground targets essential for test and evaluation (T&E). These targets are economical and expendable, remotely controlled or stationary, and often destroyed in use. The Army is the Tri-Service lead under the Secretariat Reliance panel for providing rotary wing, mobile ground, towed, and designated targets for T&E. The Army executes development of some service-peculiar target requirements in support of quality assurance, lot acceptance, and training and continues development of service-peculiar and on-going target materiel upgrades to maintain continuity with current weapons technology and trends in modern and evolving Army weapons.$$, $$Budget J-Books/FY27/Army/RDTE - Vol 4 - Budget Activity 6.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604258N$$, $$Target Systems Development$$, $$rdte_navy_ba6$$, $$dw_dote$$, 2026, 14191000, 18183000, 17224000, NULL, $${"act": "06", "ba_raw": "6.6", "source": "r1_fy26", "service": "navy", "page_num": 36, "original_pe": "0604258N", "page_header": "Department of the Navy"}$$::jsonb, $$This program element funds the development of Aerial Target Systems, Sea Surface Targets and Undersea Warfare Targets, Target Control systems, and associated Target Mission Support Systems, Target Threat Simulation Program and Target Augmentation and Auxiliary Systems required to simulate real world threats. These capabilities are required to execute developmental/operational test and evaluation of naval combat weapon systems and to satisfy advanced fleet training requirements while ensuring the Navy continues to develop threat simulations of emerging threat capabilities. JUSTIFICATION FOR BUDGET ACTIVITY: This program is funded under RESEARCH, DEVELOPMENT, TEST AND EVALUATION MANAGEMENT SUPPORT because it supports efforts directed toward sustaining or modernizing installations or operations required for general research, development, test and evaluation.$$, NULL, 35245000, 33120000, 24679000, NULL, NULL, 187, $$RDTEN_BA6_Book.pdf$$, NULL, FALSE, 15744000, 16602000, 22653000, 22653000, NULL, 22653000, 25118000, $$This program element funds the development of Aerial Target Systems, Sea Surface Targets and Undersea Warfare Targets, Target Control systems, and associated Target Mission Support Systems, Target Threat Simulation Program and Target Augmentation and Auxiliary Systems required to simulate real world threats. These capabilities are required to execute developmental/operational test and evaluation of naval combat weapon systems and to satisfy advanced fleet training requirements while ensuring the Navy continues to develop threat simulations of emerging threat capabilities. JUSTIFICATION FOR BUDGET ACTIVITY: This program is funded under RESEARCH, DEVELOPMENT, TEST AND EVALUATION MANAGEMENT SUPPORT because it supports efforts directed toward sustaining or modernizing installations or operations required for general research, development, test and evaluation.$$, $$Budget J-Books/FY27/Navy/RDTEN_BA6_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604261N$$, $$Acoustic Search Sensors$$, $$rdte_navy_ba5$$, $$dw_dote$$, 2026, 52549000, 60075000, 53591000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "navy", "page_num": 32, "original_pe": "0604261N", "page_header": "Department of the Navy"}$$::jsonb, $$U.S. Navy Air Anti-Submarine Warfare (ASW) mission is critical to achieve maritime supremacy against peer threats. RDT&E funds for engineering development and operational test and evaluation of acoustic search sensors/systems and complementary equipment for ASW aircraft. JUSTIFICATION FOR BUDGET ACTIVITY: This program is funded under SYSTEM DEVELOPMENT AND DEMONSTRATION because it includes those projects that have passed Milestone B approval and are conducting engineering and manufacturing development tasks aimed at meeting validated requirements prior to full-rate production decision.$$, NULL, 52035000, 53458000, 53522000, NULL, NULL, 120, $$RDTEN_BA5_Book.pdf$$, NULL, FALSE, 51894000, 52549000, 48875000, 48875000, NULL, 48875000, 54551000, $$U.S. Navy Air Anti-Submarine Warfare (ASW) mission is critical to achieve maritime supremacy against peer threats. RDT&E funds for engineering development and operational test and evaluation of acoustic search sensors/systems and complementary equipment for ASW aircraft. JUSTIFICATION FOR BUDGET ACTIVITY: This program is funded under SYSTEM DEVELOPMENT AND DEMONSTRATION because it includes those projects that have passed Milestone B approval and are conducting engineering and manufacturing development tasks aimed at meeting validated requirements prior to full-rate production decision.$$, $$Budget J-Books/FY27/Navy/RDTEN_BA5_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604262N$$, $$V-22A$$, $$rdte_navy_ba5$$, $$peo_aasm$$, 2026, 124958000, 144671000, 108225000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "navy", "page_num": 32, "original_pe": "0604262N", "page_header": "Department of the Navy"}$$::jsonb, $$The V-22 Osprey is an Acquisition Category IC Joint Program led by the Department of the Navy for the purpose of developing, testing, evaluating, procuring and fielding a tilt rotor, vertical takeoff and landing aircraft for Joint Service application. The V-22 program is designed to provide an aircraft to meet the amphibious/vertical assault needs of the Marine Corps, the Carrier Onboard Delivery needs of the Navy, and the special operations needs of the Air Force and the United States Special Operations Command (USSOCOM). The MV-22 variant replaced the CH-46E in the Marine Corps and the CMV-22 variant will replace the C-2A in the Navy. The CV-22 variant replaced the MH-53J and MH-53M and augments the C-130 in the Air Force and USSOCOM. The V-22 is capable of flying over 2,100 nautical miles, with a single refueling, giving the services the advantage of a vertical/short take-off and landing aircraft that can rapidly self-deploy to any location in the world. This program is funded under Engineering Manufacturing and Development for correction of deficiencies and includes Block B upgrades which encompassed engineering and manufacturing development of new end-items prior to the production incorporation decision as well as Block C suitability and effectiveness development upgrades. Currently converting all Block B to Block C configuration. Capability Development Document interoperability requirements were addressed through a spiral upgrade acquisition strategy. It was the first spiral upgrade providing Key Enabling Department of Defense mandated open systems architecture upgrades for the mission computer hardware and software while simultaneously addressing required interoperability common avionics upgrades and current avionics obsolescence issues. Future development efforts will include pre-planned-product-improvements in the capability development document and re-design efforts to correct critical Reliability, Maintainability and Availability issues in support of readiness Operational Safety Improvement Program as prioritized by the United States Marine Corps (USMC) or an Urgent Universal Needs Statement. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Navy                                                                            Date: June 2025 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 5: System          PE 0604262N / V-22A Development & Demonstration (SDD)$$, NULL, 308943000, 219392000, 195555000, NULL, NULL, 121, $$RDTEN_BA5_Book.pdf$$, NULL, FALSE, 96469000, 144072000, 252335000, 252335000, NULL, 252335000, 137131000, $$The V-22 Osprey is an Acquisition Category IC Joint Program led by the Department of the Navy for the purpose of developing, testing, evaluating, procuring and fielding a tilt rotor, vertical takeoff and landing aircraft for Joint Service application. The V-22 program is designed to provide an aircraft to meet the amphibious/ vertical assault needs of the Marine Corps, the Carrier Onboard Delivery needs of the Navy, and the special operations needs of the Air Force and the United States Special Operations Command (USSOCOM). The MV-22 variant replaced the CH-46E in the Marine Corps and the CMV-22 variant will replace the C-2A in the Navy. The CV-22 variant replaced the MH-53J and MH-53M and augments the C-130 in the Air Force and USSOCOM. The V-22 is capable of flying over 2,100 nautical miles, with a single refueling, giving the services the advantage of a vertical/short take-off and landing aircraft that can rapidly self-deploy to any location in the world. This program is funded under Engineering Manufacturing and Development for correction of deficiencies and includes Block B upgrades which encompassed engineering and manufacturing development of new end-items prior to the production incorporation decision as well as Block C suitability and effectiveness development upgrades. Currently converting all Block B to Block C configuration. Capability Development Document interoperability requirements were addressed through a spiral upgrade acquisition strategy. It was the first spiral upgrade providing Key Enabling Department of War mandated open systems architecture upgrades for the mission computer hardware and software while simultaneously addressing required interoperability common avionics upgrades and current avionics obsolescence issues. Future development efforts will include pre-planned-product-improvements in the capability development document and re-design efforts to correct critical Reliability, Maintainability and Availability issues in support of readiness Operational Safety Improvement Program as prioritized by the United States Marine Corps (USMC) or an Urgent Universal Needs Statement. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                              Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 5: System            PE 0604262N / V-22A Development & Demonstration (SDD)$$, $$Budget J-Books/FY27/Navy/RDTEN_BA5_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604264N$$, $$Air Crew Systems Development$$, $$rdte_navy_ba5$$, $$asn_rda$$, 2026, 44297000, 33686000, 29330000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "navy", "page_num": 32, "original_pe": "0604264N", "page_header": "Department of the Navy"}$$::jsonb, $$The Aircrew Systems Development program provides Engineering and Manufacturing Development (EMD) of Aviation Life Support Systems to protect aircrew and flight deck personnel from current and future threats including: directed energy weapons, chemical/biological/radiological agents/fallout, ballistic projectiles, temperature extremes, heat/fire, low concentration oxygen environments, high dynamic forces during emergency egress, hearing loss, high "G" forces, and survivability during isolated personnel events. The program also provides development for the following capabilities: night vision, hearing and head protection, aircrew endurance, aircrew performance, man-mounted data display, communications, clothing, in-flight restraint and stability, emergency egress and descent, escape and evasion, survival and rescue, crash protection, and clothing/gear fitment for the entire range of anthropomorphic sizes. Acquisition strategies include: use of non-developmental items, the application of streamlining authorities, joint and tri-service developments, the pursuit of NATO/allied cooperative ventures, and open competition. These strategies expedite introduction of new products into Navy and Marine Corps fixed and rotary wing aircraft, reduce costs, and promote commonality. The Physiological Episodes program provides funding to assure pilot performance by developing and fielding systems that reduce physiological burden, monitor state of pilot health, warn of pending or actual performance degradation that may result in loss of consciousness, and improve overall aircrew resilience to assure the crew's ability to safely conduct flight. The Physiological Episodes Root Cause & Corrective Action (RCCA) team determined that an improved helmet, mask, and regulator system was required to mitigate physiological episodes. This program determines what improvements are needed and develops the material solutions required to minimize the likelihood of physiological episode occurrence. Department of the Navy received requirements for PSE (Parachute Survival Ensemble), CWAES (Cold Weather/Anti-Exposure Systems), and NGRWH (Next- Generation Rotary Wing Helmet). The PSE program will update the currently fielded ensemble to include modern technologies reducing size/weight and increasing accessibility for in-flight bladder relief. PSE modernization will reduce fatigue during normal missions and increase ease of egress during bailout situations. The CWAES program will design, test, and qualify improved cold weather/anti-exposure systems. System components will provide reduced thermal burden, increased mobility, and superior water intrusion resistance while maintaining protection levels. The improved system will reduce fatigue and dehydration, enable operating at optimum performance during extended missions, provide protection from exposure, and provide improved survivability during extended recoveries. The NGRWH program mitigates aircrew back and neck injury by providing a lighter-weight helmet solution with improved Center of Gravity (CG) and serves as the platform for future day/night digital HMD solutions. Funding provided for the PSE, CWAES, and NGRWH programs is intended to support the award of RDT&E contracts for these efforts in FY 2026. Additional FY 2026 funding has also been allocated to address funding wholeness deficiencies in the initial RDT&E allocation for the Recovery Locator Device (RLD) and Aircrew Hearing Protection (AHP) programs (both scheduled to commence development efforts in FY 2025). Based on refined requirements definition, this additional funding is required to fully fund these two programs. Additional FY 2026 funding has also been allocated to the Enhanced Visual Acuity (EVA) program as the Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Navy                                                                                  Date: June 2025 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 5: System             PE 0604264N / Air Crew Systems Development Development & Demonstration (SDD) initial EMD contract awarded in support of this program was terminated due to the inability of that prime vendor to resolve technical and affordability issues related to the display solution. FY 2026 funding for the EVA program is intended to support ongoing technical maturation efforts associated with the critical technologies that compose this system. Additional FY 2026 funding has also been allocated to Survival Vest Improvement (SVSI) program to support continued development efforts and Aircrew Safety Improvement Program (ASIP). Due to the large portfolio across all platforms, several Aviation Life Support Systems (ALSS) deficiencies are identified each year. JUSTIFICATION FOR BUDGET ACTIVITY: This program is funded under SYSTEM DEVELOPMENT AND DEMONSTRATION because it includes projects that have passed Milestone B approval and are conducting engineering and manufacturing development tasks aimed at meeting validated requirements prior to full-rate production decision. CONGRESSIONAL ADD PRIOR YEARS TOTAL: This Program Element (0604264N) has prior year Congressional Add funding in the amount of $6.758M that was provided in FY23 for Rotary Wing/Tilt Rotor (RW/TR) Survival Vest Systems Improvement (SVSI). This Prior Year funding is not included in the R-2 or R-3 of this budget because the Congressional Add Project Unit (9999) no longer exists.$$, NULL, 17519000, 10195000, 7994000, NULL, NULL, 122, $$RDTEN_BA5_Book.pdf$$, NULL, FALSE, 29180000, 44297000, 21582000, 21582000, NULL, 21582000, 9916000, $$The Aircrew Systems Development program (PU 0606) provides Engineering and Manufacturing Development (EMD) of Aviation Life Support Systems to protect aircrew and flight deck personnel from current and future threats including: directed energy weapons, chemical/biological/radiological agents/fallout, ballistic projectiles, temperature extremes, heat/fire, low concentration oxygen environments, high dynamic forces during emergency egress, hearing loss, high "G" forces, and survivability during isolated personnel events. The program also provides development for the following capabilities: night vision, hearing and head protection, aircrew endurance, aircrew performance, man-mounted data display, communications, clothing, in-flight restraint and stability, emergency egress and descent, escape and evasion, survival and rescue, crash protection, and clothing/gear fitment for the entire range of anthropomorphic sizes. Acquisition strategies include: use of non-developmental items, the application of streamlining authorities, joint and tri-service developments, the pursuit of NATO/allied cooperative ventures, and open competition. These strategies expedite introduction of new products into Navy and Marine Corps fixed and rotary wing aircraft, reduce costs, and promote commonality. Department of the Navy received requirements for CWAES (Cold Weather/Anti-Exposure Systems). The CWAES program will design, test, and qualify improved cold weather/anti-exposure systems. System components will provide reduced thermal burden, increased mobility, and superior water intrusion resistance while maintaining protection levels. The improved system will reduce fatigue and dehydration, enable operating at optimum performance during extended missions, provide protection from exposure, and provide improved survivability during extended recoveries. Funding provided for the CWAES is intended to support the award of RDT&E contracts for these efforts in FY 2027. Funding has also been allocated to Aircrew Safety Improvement Program (ASIP). Due to the large portfolio across all platforms, several Aviation Life Support Systems (ALSS) deficiencies are identified each year. JUSTIFICATION FOR BUDGET ACTIVITY: This program is funded under SYSTEM DEVELOPMENT AND DEMONSTRATION because it includes projects that have passed Milestone B approval and are conducting engineering and manufacturing development tasks aimed at meeting validated requirements prior to full-rate production decision. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                           Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 5: System            PE 0604264N / Air Crew Systems Development Development & Demonstration (SDD)$$, $$Budget J-Books/FY27/Navy/RDTEN_BA5_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604269N$$, $$EA-18 Squadrons$$, $$rdte_navy_ba5$$, $$peo_tacair$$, 2026, 184921000, 159787000, 167450000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "navy", "page_num": 32, "original_pe": "0604269N", "page_header": "Department of the Navy"}$$::jsonb, $$The EA-18G Growler is the primary Airborne Electronic Attack (AEA) platform supporting the Joint Force and the sole tactical AEA aircraft in the DoD inventory. The Growler is an asymmetric force multiplier that increases the survivability and lethality of the Joint Force within a non-permissive environment, while enabling all-domain superiority for the Electromagnetic Spectrum (EMS). The centrality of EMS dominance to the CNO's Maritime Strategy further necessitates EA-18G modernization as a strategic pursuit to secure EMS superiority for the Navy's Carrier Strike and Joint Expeditionary operations. Due to the rapid advancements of the adversary's capabilities, the EA-18G will be called upon in future engagements to operate at increased ranges from the threat which far exceed the current capability to effectively deliver kinetic and non-kinetic effects. The Growler Block II is a foundational spiral upgrade that will implement the incremental and innovative capability improvements required for Naval Aviation to regain and sustain an advantage in the EMS until the EA-18G is replaced. Growler Block II consists of onboard sensors of the EA-18G, namely the ALQ-218, require improved sensitivity and processing to detect, identify, and locate advanced complex threats at longer ranges. The ALQ-218 is a combination of multiple Weapons Replaceable Assemblies (WRAs), enabled by software, providing a mechanism for incremental capability improvement. The current Electronic Attack Unit (EAU) WRA will be replaced by the Next Generation Electronic Attack Unit (NGEAU), beginning the transition to Growler Block II Phase I. This upgrade, coupled with the Reactive Electronic Attack Measures (REAM) capability, greatly enhances the EA-18G's autonomous processing and response to unknown signals in an extremely dense EMS environment. Growler Block II Phase II, Beowulf, will include an advanced Multi-Function Array (MFA) in the Inboard Leading Edge Flaps (ILEF), augmenting the ALQ-218 functionality and capability. The MFA also serves as technology development and risk reduction for the incorporation of MFAs on multiple future platforms. Capabilities of the EA-18G weapon system and ancillary equipment can be upgraded to incorporate new or enhanced weapons as well as advances in technology to respond effectively to emerging and future threats. EA-18G "Flight Plan" spiral capability development is critical to the baseline of the EA-18G next generation mission system capability and to maintaining tactical relevance in support of the Air Wing of the Future. Development continues for design and integration of avionics systems, integration of Jamming Techniques Optimization (JATO) improvements, evolutionary software upgrades via Software Configuration Set (SCS) block builds and Agile software development, as well as related testing. Through FY2030, EA-18G Growler efforts will focus on developing quality components, continuing advanced development engineering; and improving reliability and maintainability. These collective efforts will enhance availability of critical assets to the fleet and maximize lifetime total cost of ownership benefits. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Navy                                                                           Date: June 2025 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 5: System          PE 0604269N / EA-18 Squadrons Development & Demonstration (SDD)$$, NULL, 112376000, 112899000, 137111000, NULL, NULL, 123, $$RDTEN_BA5_Book.pdf$$, NULL, FALSE, 164122000, 184921000, 131683000, 131683000, NULL, 131683000, 139745000, $$The EA-18G Growler is the primary Airborne Electronic Attack (AEA) platform supporting the Joint Force and the sole tactical AEA aircraft in the DoW inventory. The Growler is an asymmetric force multiplier that increases the survivability and lethality of the Joint Force within a non-permissive environment, while enabling all-domain superiority for the Electromagnetic Spectrum (EMS). The centrality of EMS dominance to the CNO's Maritime Strategy further necessitates EA-18G modernization as a strategic pursuit to secure EMS superiority for the Navy's Carrier Strike and Joint Expeditionary operations. Due to the rapid advancements of the adversary's capabilities, the EA-18G will be called upon in future engagements to operate at increased ranges from the threat which far exceed the current capability to effectively deliver kinetic and non-kinetic effects. The Growler Block II is a foundational spiral upgrade that will implement the incremental and innovative capability improvements required for Naval Aviation to regain and sustain an advantage in the EMS until the EA-18G is replaced. Growler Block II consists of onboard sensors of the EA-18G, namely the ALQ-218, require improved sensitivity and processing to detect, identify, and locate advanced complex threats at longer ranges. The ALQ-218 is a combination of multiple Weapons Replaceable Assemblies (WRAs), enabled by software, providing a mechanism for incremental capability improvement. The current Electronic Attack Unit (EAU) WRA will be replaced by the Next Generation Electronic Attack Unit (NGEAU), beginning the transition to Growler Block II Phase I. This upgrade, coupled with the Reactive Electronic Attack Measures (REAM) capability, greatly enhances the EA-18G's autonomous processing and response to unknown signals in an extremely dense EMS environment. Growler Block II Phase II, Beowulf, will include an advanced Multi-Function Array (MFA) in the Inboard Leading Edge Flaps (ILEF), augmenting the ALQ-218 functionality and capability. The MFA also serves as technology development and risk reduction for the incorporation of MFAs on multiple future platforms. Capabilities of the EA-18G weapon system and ancillary equipment can be upgraded to incorporate new or enhanced weapons as well as advances in technology to respond effectively to emerging and future threats. EA-18G "Flight Plan" spiral capability development is critical to the baseline of the EA-18G next generation mission system capability and to maintaining tactical relevance in support of the Air Wing of the Future. Development continues for design and integration of avionics systems, integration of Jamming Techniques Optimization (JATO) improvements, evolutionary software upgrades via Software Configuration Set (SCS) block builds and Agile software development, as well as related testing. Through FY2030, EA-18G Growler efforts will focus on developing quality components, continuing advanced development engineering; and improving reliability and maintainability. These collective efforts will enhance availability of critical assets to the fleet and maximize lifetime total cost of ownership benefits. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                          Date: April 2026 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 5: System          PE 0604269N / EA-18 Squadrons Development & Demonstration (SDD)$$, $$Budget J-Books/FY27/Navy/RDTEN_BA5_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604270A$$, $$Electronic Warfare Development$$, $$rdte_army_ba5$$, $$asa_alt$$, 2026, 9153000, 12310000, 33247000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "army", "page_num": 16, "original_pe": "0604270A", "page_header": "Department of the Army"}$$::jsonb, $$This Program Element (PE) encompasses engineering and manufacturing development for tactical Electronic Warfare (EW). The Integrated Electronic Warfare System (IEWS) is a capability set that integrates electronic attack, protect and support functions to dramatically improve the ability to seize, retain, and exploit an advantage within the electromagnetic spectrum (EMS). It is based on a modular, scalable and open architecture to allow Army Brigade Combat Team (BCT) and Joint Force Commander's to tailor capability responses against a variety of EW threats/scenarios. The IEWS capability set is structured along four program lines of effort: 1) Project CR8 Army Reprogramming Analysis Team (ARAT), 2) Project DX5 Electronic Warfare Planning and Management Tool (EWPMT), 3) Project DX6 Multi-Function EW (MFEW), 4) Project VS6 Counter Radio-Controlled Improvised Explosive Devices (RCIED) Electronic Warfare (CREW) which provides current defensive electronic attack capability. Project CR8 - Army Reprogramming Analysis Team (ARAT) supports the tactical Commander by providing timely rapid reprogramming of mission software and information dissemination for Army supported, Joint and allied services. ARAT supports integrated reprogramming of target acquisition, target engagement, vehicle survivability, and Aircraft Survivability Equipment (ASE). ARAT rapid-reprogramming infrastructure supports tactical requirements for deployed aircraft and ground-based (e.g., CREW) survivability systems. ARAT identifies and analyzes threat signature changes which affect EW systems; determines the impact of observed signature changes; develops new mission software to adapt the system to the changes; disseminates the mission software; and provides methods to upload the new mission Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                                Date: June 2025 Appropriation/Budget Activity                                                         R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 5: System                   PE 0604270A / Electronic Warfare Development Development & Demonstration (SDD) software into the affected EW systems. Each element within the ARAT infrastructure plays a specific role within the program's rapid reprogramming process, providing the Soldier with the capability to install mission and target identification software at the lowest possible level, thus maximizing flexibility for tactical commanders. Project DX5 - The Electronic Warfare Planning and Management Tool-X (EWPMT-X) is a software modernization effort on EWPMT Version 1 to an updated software architecture. Leveraging community contributions provides enhanced capability and features based on a government supported framework (TAKX) to enable quicker reaction to subsequent EW requirements. At end state, EWPMT-X will deliver spectrum dominance across Multi-Domain Operations (MDO) through spectrum visualization and modeling, Electromagnetic Warfare planning, sensor orchestration, fusion of intelligence, command and control (C2) that supports kinetic and non- kinetic targeting for the Commander's scheme of maneuver. Project DX6 - MFEW-AL is the Army's only program providing tactical Commanders with deep look, organic, airborne, offensive electronic warfare (EW), empowering Commanders to shape the Electromagnetic Spectrum (EMS) to their advantage. The MFEW Air Large system will provide: 1) Offensive Electronic Attack (OEA) - Non- Kinetic Fires capability with the intent of denying, degrading, or disrupting enemy communications capability and non-communications emitters; 2) Electronic Warfare Support (ES) - Capability to search, intercept, identify, and locate or localize sources of intentional and unintentional radiated electromagnetic (EM) energy for the purpose of immediate threat recognition, targeting, planning, and execution of future operations; 3) Dissemination of Military Information Support Operations (MISO) products; and 4) Support of Offensive Cyber Operations (OCO) and Multi-Domain Operations. Project VS6 - Counter Radio Controlled Improvised Explosive Device (RCIED) Electronic Warfare (CREW) provides protection of ground forces operating in vehicle convoys, single vehicles and fixed locations in operational theaters which enables freedom of movement across the depth and breadth of the operational environment. Current CREW systems are programmable with techniques to mitigate emerging threats. In order to keep pace with the threat evolution, development efforts will provide fielded CREW systems as well as other Electronic Warfare (EW) systems with techniques that mitigate the range of threats as required. These development efforts may include development of new techniques, integration of existing techniques, as well as hardware and software development and integration in order to pace the threat.$$, NULL, 2865000, 2918000, 2980000, NULL, NULL, 102, $$RDTE - Vol 3 - Budget Activity 5A.pdf$$, NULL, FALSE, 28706000, 9153000, 2807000, 2807000, NULL, 2807000, 3041000, $$This Program Element (PE) encompasses engineering and manufacturing development for tactical Electronic Warfare (EW). The Integrated Electronic Warfare System (IEWS) is a capability set that integrates electronic attack, protect and support functions to dramatically improve the ability to seize, retain, and exploit an advantage within the electromagnetic spectrum (EMS). It is based on a modular, scalable and open architecture to allow Army Brigade Combat Team (BCT) and Joint Force Commander's to tailor capability responses against a variety of EW threats/scenarios. Project DN9 - Modular Electro-Magnetic Spectrum System (MEMSS) is a Fiscal Year (FY) 26 New Start Electronic Warfare (EW) program. MEMSS is an EW capability providing Force Protection and Freedom of Maneuver through Radio Frequency (RF) Technical Effects, an overarching cover term for a classified capability. MEMSS will Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                                Date: April 2026 Appropriation/Budget Activity                                                      R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 5: System                PE 0604270A / Electronic Warfare Development Development & Demonstration (SDD) provide accelerated delivery of innovative RF technical effects solutions tailored to Army requirements. The program will prioritize iterative development, incorporating vendor Research and Development (R&D) investments and readily available Commercial-Off-The-Shelf (COTS) components. Further advocacy for MEMSS capabilities exists in support of the Joint community, Operational Needs Statements (ONS), Transformation in Contact (TiC) initiatives, Presidential Directives, and other Combatant Command requests. ** See Note for Project Codes: CR8, DX5, DX6 and VS6$$, $$Budget J-Books/FY27/Army/RDTE - Vol 3 - Budget Activity 5A.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604270F$$, $$Electronic Warfare Development$$, $$rdte_af_ba5$$, $$afrl_ry$$, 2026, 17013000, 23673000, 13754000, NULL, $${"ba_raw": "6.5", "source": "af_r1_fy26", "original_pe": "0604270F"}$$::jsonb, $$The Advanced Infrared Countermeasure (AIRCM) project contains related aircraft self-protection efforts aimed at increasing aircraft survivability against the increasing threat of sophisticated surface-to-air and air-to-air missiles. These missiles may employ sophisticated next-generation Electro-Optics (EO), Infrared (IR), Radio Frequency (RF), dual-mode (i.e. IR and RF), or multi-mode seekers. AIRCM will provide advanced expendable countermeasures and/or techniques that will be functionally compatible with existing dispenser systems and employed across multiple USAF weapons systems. This also includes any and all flare, chaff, decoy, and associated component development and testing that may be demanded or needed in current and future operations regardless of aircraft platform. Similar activities that are supplementary to this effort may be accomplished ad hoc using platform specific funding or through other activities such as joint services or NATO test groups. This program element may include necessary civilian pay expenses required manage, execute, and deliver weapons system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY 2024 $0M was expended for civilian pay expenses om this program element, and in FY 2025 $0M is forecasted for civilian pay expenses in this program element. In FY 2026 PE 0604270F, Project 653891 Electromagnetic Battle Management (EMBM) efforts were transferred to PE 0207407F and Cognitive Electromagnetic Warfare efforts were transferred to PE 0207039F. The FY 2026 request was reduced by $202 thousand for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative.” This program is in Budget Activity 5, System Development and Demonstration (SDD) because it has passed Milestone B approval and is conducting engineering and manufacturing development tasks aimed at meeting validated requirements prior to full rate production. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                        Date: June 2025 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 5: System     PE 0604270F / Electronic Warfare Development Development & Demonstration (SDD)$$, NULL, 155609000, 160414000, 134783000, NULL, NULL, 87, $$FY26 Air Force Research and Development Test and Evaluation Vol II.pdf$$, NULL, FALSE, 13648000, 18971000, 260233000, 260233000, 0, 260233000, 137491000, $$The Advanced Infrared Countermeasure (AIRCM) project contains related aircraft self-protection efforts aimed at increasing aircraft survivability against the increasing threat of sophisticated surface-to-air and air-to-air missiles. These missiles may employ sophisticated next-generation Electro-Optics (EO), Infrared (IR), Radio Frequency (RF), dual-mode (i.e. IR and RF), or multi-mode seekers. AIRCM will provide advanced expendable countermeasures and/or techniques that will be functionally compatible with existing dispenser systems and employed across multiple USAF weapons systems. This also includes any and all flare, chaff, decoy, and associated component development and testing that may be demanded or needed in current and future operations regardless of aircraft platform. Similar activities that are supplementary to this effort may be accomplished ad hoc using platform specific funding or through other activities such as joint services or NATO test groups. This program element may include necessary civilian pay expenses required manage, execute, and deliver weapons system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. This program is in Budget Activity 5, System Development and Demonstration (SDD) because it has passed Milestone B approval and is conducting engineering and manufacturing development tasks aimed at meeting validated requirements prior to full rate production. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                          Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 5: System       PE 0604270F / Electronic Warfare Development Development & Demonstration (SDD)$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume II.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604270N$$, $$Electronic Warfare (EW) Dev$$, $$rdte_navy_ba5$$, $$asn_rda$$, 2026, 185606000, 144052000, 186150000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "navy", "page_num": 32, "original_pe": "0604270N", "page_header": "Department of the Navy"}$$::jsonb, $$This program element includes development of Electronic Warfare (EW) systems for the United States Navy (USN), United States Marine Corps (USMC), and United States Army tactical aircraft, USMC helicopters, surface combatants, data link vulnerability assessments, precision targeting, USN and USMC radio frequency jammers, and development and testing of EW devices for emerging threats and emergency contingencies. This element also includes: development of hardware (HW)/software (SW) solutions that link on-board integrated Aircraft Survivability Equipment (iASE) that are compatible with mission planning information and systems; studies, analysis and evaluations of current and future aircraft threats; modeling and simulation for improved countermeasure capabilities, and development and testing to address new and emerging threats. The projects in this element improve the ability of the Joint Force to strike diverse targets inside adversary air and missile defense networks to destroy mobile power-projection platforms and enhance close combat lethality in complex terrain. This program is funded under System Development and Demonstration because it includes those projects that have passed Milestone B approval and are conducting Engineering and Manufacturing Development (EMD) tasks aimed at meeting validated requirements prior to Full-Rate Production (FRP) decision. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Navy                                                                           Date: June 2025 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 5: System          PE 0604270N / Electronic Warfare (EW) Dev Development & Demonstration (SDD)$$, NULL, 119598000, 137745000, 132698000, NULL, NULL, 124, $$RDTEN_BA5_Book.pdf$$, NULL, FALSE, 179572000, 185606000, 168985000, 168985000, NULL, 168985000, 135216000, $$This program element includes development of Electronic Warfare (EW) systems for the United States Navy (USN), United States Marine Corps (USMC), and United States Army tactical aircraft, USMC helicopters, surface combatants, data link vulnerability assessments, precision targeting, USN and USMC radio frequency jammers, and development and testing of EW devices for emerging threats and emergency contingencies. This element also includes: development of hardware (HW)/software (SW) solutions that link on-board integrated Aircraft Survivability Equipment (iASE) that are compatible with mission planning information and systems; studies, analysis and evaluations of current and future aircraft threats; modeling and simulation for improved countermeasure capabilities, and development and testing to address new and emerging threats. The projects in this element improve the ability of the Joint Force to strike diverse targets inside adversary air and missile defense networks to destroy mobile power-projection platforms and enhance close combat lethality in complex terrain. This program is funded under System Development and Demonstration because it includes those projects that have passed Milestone B approval and are conducting Engineering and Manufacturing Development (EMD) tasks aimed at meeting validated requirements prior to Full-Rate Production (FRP) decision. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                            Date: April 2026 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 5: System           PE 0604270N / Electronic Warfare (EW) Dev Development & Demonstration (SDD)$$, $$Budget J-Books/FY27/Navy/RDTEN_BA5_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604272N$$, $$Tact Air Dir Infrared CM (TADIRCM)$$, $$rdte_navy_ba4$$, $$mc$$, 2026, 14387000, 33972000, 35030000, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "navy", "page_num": 30, "original_pe": "0604272N", "page_header": "Department of the Navy"}$$::jsonb, $$This element includes development of Electronic Warfare (EW) systems for worldwide deployment of United States Navy and United States Marine Corps assault aircraft. This includes the development and testing of advanced Infrared (IR) countermeasures systems for aircraft survivability against emerging threats and for emergency contingencies. This program develops Hostile Fire Indication, and Laser Warning Sensors that integrates IR missile countermeasures with aircraft Countermeasures Dispensing Systems and expendables. Distributed Aperture Infrared Countermeasure (DAIRCM) adopts future multi-band networking capabilities to facilitate real-time transfer of threat information, off-board queuing, and control of onboard sensors. DAIRCM studies and evaluates current and future aircraft threats, makes modeling and simulation for improved countermeasure capabilities, develops, tests and provides test equipment to address new and emerging threats for improved aircraft survivability of assault aircraft in complex terrain and EW environments. Justification for budget activity: This program is funded under Advanced Component Development and Prototypes because it includes all efforts necessary to evaluate integrated technologies, representative models or prototype systems in a high fidelity and realistic operating environment.$$, NULL, 18341000, 17476000, 17681000, NULL, NULL, 84, $$RDTEN_BA4_Book.pdf$$, NULL, FALSE, 41438000, 14387000, 14974000, 14974000, NULL, 14974000, 17989000, $$This element includes development of Electronic Warfare (EW) systems for worldwide deployment of United States Navy and United States Marine Corps assault aircraft. This includes the development and testing of advanced Infrared (IR) countermeasures systems for aircraft survivability against emerging threats and for emergency contingencies. This program develops Hostile Fire Indication, and Laser Warning Sensors that integrates IR missile countermeasures with aircraft Countermeasures Dispensing Systems and expendables. Distributed Aperture Infrared Countermeasure (DAIRCM) adopts future multi-band networking capabilities to facilitate real-time transfer of threat information, off-board queuing, and control of onboard sensors. DAIRCM studies and evaluates current and future aircraft threats, makes modeling and simulation for improved countermeasure capabilities, develops, tests and provides test equipment to address new and emerging threats for improved aircraft survivability of assault aircraft in complex terrain and EW environments. Justification for budget activity: This program is funded under Advanced Component Development and Prototypes because it includes all efforts necessary to evaluate integrated technologies, representative models or prototype systems in a high fidelity and realistic operating environment.$$, $$Budget J-Books/FY27/Navy/RDTEN_BA4_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$P_1810_L056$$, $$Ashore ATC Equipment$$, $$proc_navy_1810_ba2$$, $$navsea$$, 2026, 3489000, 3915000, 3645000, NULL, $${"page": 98, "ba_num": "02", "source": "p1_fy26", "ba_name": "Communications and electronics equipment", "line_no": "56", "service": "navy", "fy24_qty": null, "fy25_qty": null, "fy27_v25": {"ba": "02", "appr": "OPN", "title": "P-1 Line 52", "applied_at": "2026-05-09", "fy27_ooc_K": 0, "source_pdf": "Budget J-Books/FY27/Navy/OPN_BA{1..5-8}_Book.pdf", "fy27_base_K": 16167, "p1_line_num": 52, "fy27_total_K": 16167}, "appr_code": "1810", "appr_name": "Other Procurement, Navy", "fy26_v179": {"disc_K": 3489, "li_num": 52, "source": "p40_fy26_v179", "supp_K": 0, "source_pdf": "uploads/Budget J-Books/FY27/Navy/OPN_BA2_Book.txt"}, "fy26t_qty": null, "fy26d_cost": 3489000, "fy26r_cost": 0, "ident_code": ""}$$::jsonb, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, FALSE, 90586000, 97262000, 16167000, 16167000, 0, 16167000, NULL, NULL, $$Budget J-Books/FY27/Navy/OPN_BA2_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604273M$$, $$Executive Helo Development$$, $$rdte_navy_ba5$$, $$asn_rda$$, 2026, 74980000, 34518000, 51366000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "mc", "page_num": 32, "original_pe": "0604273M", "page_header": "Department of the Navy"}$$::jsonb, $$The VH-92A is the replacement helicopter for the VH-3D and the VH-60N, the aircraft currently used by Marine Helicopter Squadron One (HMX-1) to transport the President, Vice President, and other distinguished officials as directed by the White House Military Office. The VH-3D and VH-60N are approaching the end of their service lives. Funding for the VH-92A program supports activities, including: integration of systems; qualification and support of test articles; development of logistics products; and demonstration of system integration, interoperability, safety, utility, and improvements/upgrades. JUSTIFICATION FOR BUDGET ACTIVITY: This program is funded under SYSTEM DEVELOPMENT AND DEMONSTRATION because it includes those projects that have passed Milestone B approval and are conducting engineering and manufacturing development tasks aimed at meeting validated requirement prior to full-rate production decision.$$, NULL, 75129000, 53740000, 34155000, NULL, NULL, 125, $$RDTEN_BA5_Book.pdf$$, NULL, FALSE, 49968000, 74980000, 69438000, 69438000, NULL, 69438000, 34750000, $$The VH-92A is the replacement helicopter for the VH-3D and the VH-60N, the aircraft currently used by Marine Helicopter Squadron One (HMX-1) to transport the President, Vice President, and other distinguished officials as directed by the White House Military Office. The VH-3D and VH-60N are approaching the end of their service lives. Funding for the VH-92A program supports activities, including integration of systems; qualification and support of test articles; development of logistics products; and demonstration of system integration, interoperability, safety, utility, and improvements/upgrades. JUSTIFICATION FOR BUDGET ACTIVITY: This program is funded under Operations and Support to integrate hardware, software, sensors, air vehicle performance improvements and communication systems upgrades to meet modern requirements. Additionally, capability increases will address emerging threats, cybersecurity vulnerabilities, and environmental compliance.$$, $$Budget J-Books/FY27/Navy/RDTEN_BA5_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604274N$$, $$Next Generation Jammer (NGJ)$$, $$rdte_navy_ba5$$, $$peo_mles$$, 2026, 64167000, 39913000, 76721000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "navy", "page_num": 32, "original_pe": "0604274N", "page_header": "Department of the Navy"}$$::jsonb, $$The Next Generation Jammer Mid-Band (NGJ-MB) (formerly known as Next Generation Jammer Increment 1) is the next step in the evolution of Airborne Electronic Attack (AEA). It is a critical capability necessary to defend against current, evolving, and developing Electronic Warfare gaps, ensures kill chain wholeness against growing threat capabilities and capacities, keeps pace with enemy threat weapon systems' advancements, and supports the continuous expansion of the AEA mission areas that exceed the capability of legacy systems. NGJ-MB utilizes enhanced techniques and tactics to deliver significantly improved radar and communications jamming effectiveness to include classified capabilities. Utilizing Modular Open Systems Architecture supporting software and hardware updates to rapidly counter emergent and evolving threats, NGJ-MB is a key enabler and force multiplier for operations across the spectrum of missions defined in the Defense Strategic Guidance, including strike warfare, projecting power in highly contested environments, and counterinsurgency/irregular warfare. NGJ-MB also addresses the shortfalls in scalability, flexibility, supportability, interoperability, availability, and capability of the existing AN/ALQ-99 Tactical Jamming System to ensure continued spectrum dominance. This Program Element (PE 0604274N) supports the AN/ALQ-249 NGJ-MB program. NGJ-MB will address AEA capability and sufficiency gaps against enemy threats operating in the middle frequency bands of the electromagnetic spectrum. In addition, this PE supports NGJ-MB Extended (MBX), which is an Engineering Change Proposal (ECP) to the current NGJ-MB system that will extend the upper frequency coverage limit to counter modern and adaptive threats. This modification will increase frequency range of the NGJ-MB system and enhance the survivability of the platform and protected entities against emerging threats. In total, NGJ-MB will provide the ability to effectively engage enemy threats from increased stand-off distances, employ increased capacity (number of jamming assignments) against enemy targets, and support agile employment by operators. The NGJ-MB system will be integrated on the EA-18G tactical aircraft and will augment and then replace the legacy AN/ALQ-99 Tactical Jamming System in the middle frequency bands. NGJ-MB (to include MBX) is a Cooperative development and production program with the Royal Australian Air Force (RAAF). Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Navy                                                                           Date: June 2025 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 5: System           PE 0604274N / Next Generation Jammer (NGJ) Development & Demonstration (SDD)$$, NULL, 24062000, 0, 0, NULL, NULL, 126, $$RDTEN_BA5_Book.pdf$$, NULL, FALSE, 74950000, 64167000, 50332000, 50332000, NULL, 50332000, 0, $$The Next Generation Jammer Mid-Band (NGJ-MB) (formerly known as Next Generation Jammer Increment 1) is the next step in the evolution of Airborne Electronic Attack (AEA). It is a critical capability necessary to defend against current, evolving, and developing Electronic Warfare gaps, ensures kill chain wholeness against growing threat capabilities and capacities, keeps pace with enemy threat weapon systems' advancements, and supports the continuous expansion of the AEA mission areas that exceed the capability of legacy systems. NGJ-MB utilizes enhanced techniques and tactics to deliver significantly improved radar and communications jamming effectiveness to include classified capabilities. Utilizing Modular Open Systems Architecture supporting software and hardware updates to rapidly counter emergent and evolving threats, NGJ-MB is a key enabler and force multiplier for operations across the spectrum of missions defined in the Defense Strategic Guidance, including strike warfare, projecting power in highly contested environments, and counterinsurgency/irregular warfare. NGJ-MB also addresses the gaps in scalability, flexibility, supportability, interoperability, availability, and capability of the existing AN/ALQ-99 Tactical Jamming System to ensure continued spectrum dominance. This Program Element (PE 0604274N) supports the AN/ALQ-249 NGJ-MB program. NGJ-MB will address AEA capability and sufficiency gaps against enemy threats operating in the middle frequency bands of the electromagnetic spectrum. In addition, this PE supports NGJ-MB Extended (MBX), which is an Engineering Change Proposal (ECP) to the current NGJ-MB system that will extend the upper frequency coverage limit to counter modern and adaptive threats. This modification will increase frequency range of the NGJ-MB system and enhance the survivability of the platform and protected entities against emerging threats. In total, NGJ-MB will provide the ability to effectively engage enemy threats from increased stand-off distances, employ increased capacity (number of jamming assignments) against enemy targets, and support agile employment by operators. The NGJ-MB system will be integrated on the EA-18G tactical aircraft and will augment and then replace the legacy AN/ALQ-99 Tactical Jamming System in the middle frequency bands. NGJ-MB (to include MBX) is a Cooperative development, production and sustainment program with the Royal Australian Air Force (RAAF). JUSTIFICATION FOR BUDGET ACTIVITY: This program is funded under SYSTEM DEVELOPMENT AND DEMONSTRATION because it includes those projects that have passed Milestone B approval and are conducting engineering and manufacturing development tasks aimed at meeting validated requirement prior to full-rate production decision. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                    Date: April 2026 Appropriation/Budget Activity                                               R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 5: System         PE 0604274N / Next Generation Jammer (NGJ) Development & Demonstration (SDD)$$, $$Budget J-Books/FY27/Navy/RDTEN_BA5_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604280N$$, $$JT TACTICAL RADIO SYSTEM (JTRS)$$, $$rdte_navy_ba5$$, $$peo_c4i$$, 2026, 289345000, 444615000, 330559000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "navy", "page_num": 32, "original_pe": "0604280N", "page_header": "Department of the Navy"}$$::jsonb, $$Programs will implement digital system-of-systems engineering by using tools such as Model Based System Engineering (MBSE) and Digital Twins to create adaptable digital models to optimize system engineering from design, development and testing to operations and sustainment. Programs will use Development, Security and Operations (DevSecOps) processes for continuous development, integration, testing and deployment, along with common platform services such as Agile Core Services (ACS), for faster fielding of capability. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Navy                                                                                Date: June 2025 Appropriation/Budget Activity                                             R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 5: System       PE 0604280N / JT TACTICAL RADIO SYSTEM (JTRS) Development & Demonstration (SDD) (0725) The details of Program Element 0604280N, Project 0725 for BFTN/BRSE are classified SECRET//NOFORN and are submitted annually to Congress in the classified budget justification books. (0728) The details of Program Element 0604280N, Project 0728 for NMT are classified SECRET//NOFORN and are submitted to Congress in the classified budget justification books. (0728/9999 C371) Open Modular Navy Multiband Terminal funds a study and design effort to construct a model for a modular open architecture satellite terminal system which could augment and replace portions of the Navy Multiband Terminal (NMT). (0728) Navy Global Broadcast System (GBS) is a member of the larger Joint C4I program, providing high speed (up to 45 Mbps per transponder)/large volume information/data delivery to forces afloat, ashore, and Naval Special Warfare Command. Leveraging the NMT antenna, GBS provides a one-way broadcast to Naval maritime forces across the spectrum of mission areas, to include land, air and naval warfare, special operations, strategic nuclear operations, strategic defense, theater missile defense, and space operations and intelligence in support of RC3. GBS Transmission Security (TRANSEC) is an operational requirement from the Joint GBS ORD and provides robust datalink protection of both uplink and downlink for the GBS broadcast. GBS is evaluating PTW solutions to meet the TRANSEC mandate. The Air Force & Army Anti-Jam Modem (A3M) and the WAMS are PTW solutions that are under consideration. Navy GBS will require extensive development activities for the new PTW modem solution and must conduct a FOT&E with Joint Services. Overall program efforts include technology insertion studies required to support satellite communications. (0729) Satellite Communications: The details of Program Element 0604280N, Project 0729 are classified SECRET//NOFORN and are submitted to Congress in the classified budget justification books. The FY 2026 cost of the Mobile Advanced EHF Terminal (MAT) Middle Tier of Acquisition effort is $69 million, including RDT&E and procurement of prototype units. The Department will certify FYDP funding in a future budget submission. (0742) Submarine Integrated Antenna System: The details of Program Element 0604280N, Project 0742 are classified SECRET//NOFORN and are submitted to Congress in the classified budget justification books. (0921) Navigation Satellite Timing & Ranging (NAVSTAR) Global Positioning System (GPS) project (0921) encompasses the Navy's efforts to pace the growing threat to GPS Navigation through the fielding of new GPS receivers, Anti-Jam (AJ) Antennas, and Assured-Positioning Navigation and Timing (A-PNT) technologies across all Navy platform types. NAVSTAR GPS is a group of A-PNT systems that provides authorized users with secure, worldwide, all weather, three dimensional position, velocity, and precise time data. NAVSTAR GPS provides A-PNT capability to Command, Control, Communications, Computer, Intelligence, Surveillance and Reconnaissance (C4ISR) and combat systems in standalone and networked architectures throughout air and maritime domains. This project is comprised of four distinct efforts: Sea Navigation Warfare (NAVWAR), GPS-based Positioning, Navigation, and Timing (PNT) Service (GPNTS), Air Navigation Warfare (NAVWAR) and GPS Modernization. Sea NAVWAR provides AJ antennas to surface and subsurface platforms; GPNTS provides GPS receivers and A-PNT technology to surface platforms; Air NAVWAR provides AJ antennas, and GPS Modernization provides GPS receivers to air platforms. Research, Development, Testing and Evaluation (RDT&E) funds are used to perform all the non-recurring GPS Surface Ship, and Aircraft Development, Integration, and Testing efforts in support of NAVSTAR GPS. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Navy                                                                             Date: June 2025 Appropriation/Budget Activity                                                       R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 5: System                 PE 0604280N / JT TACTICAL RADIO SYSTEM (JTRS) Development & Demonstration (SDD) FY2026 request will fund the following GPS Surface Ship, Submarine and Aircraft Development, Integration and Test efforts in support of NAVSTAR GPS: continue investigation of enhanced Anti-Jam (AJ) capabilities for integration into existing Sea NAVWAR antenna systems, continue efforts to develop and test a GPNTS system capable of hosting the Automated Celestial Navigation Systems (ACNS) below deck hardware, complete ground and flight testing of the Multi-Platform Anti-Jam Global Positioning System Navigation H-Antenna Integration (MAGNA-I) on the AH-1Z/UH-1Y helicopters, and integration of Military Code (M-Code) receivers into existing Embedded Global Positioning System/Inertial Navigation System (GPS/INS) (EGI); ANAV-3M and LN-251M, due to delays in development of M-Code capable Embedded GPS/INS (EGI-M). (1411) Submarine Tactical Communications System: The details of Program Element 0604280N, Project 1411 are classified SECRET//NOFORN and are submitted to Congress in the classified budget justification books. (2126/9999 C370) Tactical Data Link (TDL) systems include the Advanced Tactical Data Link Systems (ATDLS) integration programs, specifically Link 16 Network (Link 16), Command and Control Processor (C2P) and Link Monitoring and Management Tool (LMMT). FY26 JUSTIFICATION FOR BUDGET ACTIVITY: Advanced Tactical Data Link Systems (ATDLS) is the United States (US) Navy's only ship-to-ship/ship-to-aircraft tactical information solution equipping warfighters and Combatant Commanders with real-time battlespace data and extending the range of lethality. ATDLS is the backbone of Carrier Strike Group and AEGIS-Based Defense operations and is the key component in the fire control loop, providing critical track information for enabling maritime offense/defense, Joint Area Domain Command and Control (JADC2), Integrated Air and Missile Defense (IAMD), Ballistic Missile Defense (BMD), Anti-Air Warfare (AAW), Anti-Surface Warfare (ASuW), Electronic Warfare (EW), Advanced Offboard Electronic Warfare (AOEW), and Long Range Fires (LRF) missions. ATDLS Integration Program develops new and improved Tactical Data Links (TDL) networking capabilities, delivering operational and targeting support to the warfighter. ATDLS rapidly and securely connects carrier/shipboard digital combat systems to military aircraft, ground troops, coalition partners, and space assets with vital Situational Awareness, targeting, and sensor information. ATDLS also provides Joint Range Extension capability via Link 16 Network (Link 16) Terminals, Command and Control Processor (C2P), and Link Monitoring and Management Tool (LMMT). Link 16 Network (Link 16) Increment II: Link 16, enhanced by Tactical Targeting Networking Technology (TTNT), is the Military's only joint network providing secure TDL interoperability and data sharing in contested battlespace environments. The Link 16 development initiatives are in support of Joint Chiefs of Staff Joint Requirements Oversight Council Memorandum (JROCM) 075-17 for installation and integration of Multifunctional Information Distribution System (MIDS) Joint Tactical Radio System (JTRS) terminals into the Navy shipboard environment. Link 16 initiatives also include TDL Advanced Capabilities and development and testing of enhanced throughput antennas, AS-4775 and AS-4557. Command and Control Processor (C2P): The only shipboard solution that enables bi-directional exchange of tactical information across multiple TDLs within the joint operations areas. C2P processes and exchanges Link 11, Link 16, Satellite TDL J, and Joint Range Extension Applications Protocol (JREAP) tactical data among the US, North Atlantic Treaty Organization (NATO), and allied nation military platforms enabling the vital joint TDL interfaces. Additionally, C2P provides data translation services, acts as a single interface between host combat system and TDL networks, and forwards tactical data between platforms operating at extended ranges. C2P enables surface platforms capability to conduct Ballistic Missile Defense (BMD) Launch-on-Remote/Engage-on-Remote and Autonomous Vehicle missions. C2P RDT&E Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Navy                                                                               Date: June 2025 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 5: System            PE 0604280N / JT TACTICAL RADIO SYSTEM (JTRS) Development & Demonstration (SDD) initiatives include: 1) C2P Technology Refresh (TR) cybersecurity updates and C2P v3.13 software certification; and 2) C2P Modernization capability development and Link 22 integration. Link Monitoring and Management Tool (LMMT): LMMT is the Military's premier solution providing Joint Interface Control Officers (JICOs) and Maritime Operations Centers (MOCs) with effective monitoring and performance management of TDL networks in designated Areas of Responsibility (AORs). LMMT also allows Marime Component Commanders to Fight from the MOC and perform MOC in the Middle functions in support of JADC2 and BMD missions. LMMT RDT&E initiatives will deliver an improved commercial off-shelf hardware design, providing gateway functions for multiple TDL interfaces, routing and display of TDL data to include Link 16, Joint Range Extension (JRE) and Link 22. (3020) The Multifunctional Information Distribution System (MIDS) is the most widely fielded family of Tactical Data Link radio terminals in the world. The MIDS program office is the Performing Activity for the Navy (Lead Service for Department of Defense (DOD)), Link 16 capability and consists of two (2) product lines, MIDS Low Volume Terminal (LVT) (legacy hardware defined radio) and MIDS Joint Tactical Radio System (JTRS) (software defined radio). MIDS-LVT effort is a cooperative development program between France, Germany, Italy, Spain, and the United States with United States joint service participation (Navy, Army, Air Force), and has provided over 12,000 terminals to more than 50 Nations providing interoperability with North Atlantic Treaty Organization (NATO) and coalition partners. The Department of Defense (DoD) established the program to design, develop, and deliver low volume, lightweight tactical information system terminals for U.S. and allied fighter aircraft, bombers, helicopters, ships, and ground sites. MIDS-LVT significantly increases force effectiveness and minimizes hostile actions and friend-on-friend engagements. MIDS-LVT Block Upgrade 2 was executed as an Engineering Change Proposal (ECP) and provides the critical upgrades to the MIDS-LVT Terminal to enable U.S., Coalition and International partners' ability to meet the National Security Agency (NSA) mandated timelines for Cryptogra… [truncated]$$, NULL, 310189000, 300304000, 289777000, NULL, NULL, 127, $$RDTEN_BA5_Book.pdf$$, NULL, FALSE, 321150000, 330855000, 409318000, 409318000, NULL, 409318000, 269053000, $$Programs will implement digital system-of-systems engineering by using tools such as Model Based System Engineering (MBSE) and Digital Twins to create adaptable digital models to optimize system engineering from design, development and testing to operations and sustainment. Programs will use Development, Security and Operations (DevSecOps) processes for continuous development, integration, testing and deployment, along with common platform services such as Agile Core Services (ACS), for faster fielding of capability. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                                Date: April 2026 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 5: System             PE 0604280N / JT TACTICAL RADIO SYSTEM (JTRS) Development & Demonstration (SDD) (0725) The details of Program Element 0604280N, Project 0725 for BFTN/BRSE are classified SECRET//NOFORN and are submitted annually to Congress in the classified budget justification books. (0728) The details of Program Element 0604280N, Project 0728 for NMT are classified SECRET//NOFORN and are submitted to Congress in the classified budget justification books. (0728) Navy Global Broadcast System (GBS) is a member of the larger Joint C4I program, providing high speed (up to 45 Mbps per transponder)/large volume information/data delivery to forces afloat, ashore, and Naval Special Warfare Command. Leveraging the NMT antenna, GBS provides a one-way broadcast to Naval maritime forces across the spectrum of mission areas, to include land, air and naval warfare, special operations, strategic nuclear operations, strategic defense, theater missile defense, and space operations and intelligence in support of RC3. GBS Transmission Security (TRANSEC) is an operational requirement from the Joint GBS ORD and provides robust datalink protection of both uplink and downlink for the GBS broadcast. GBS is evaluating PTW solutions to meet the TRANSEC mandate. The Air Force & Army Anti-Jam Modem (A3M) and the WAMS are PTW solutions that are under consideration. Navy GBS will require extensive development activities for the new PTW modem solution and must conduct a FOT&E with Joint Services. Overall program efforts include technology insertion studies required to support satellite communications. (0728) SATCOM Technical Insertion, studies and implementation is necessary for military satellite communications systems development to support emerging technologies for Satellite Communications (SATCOM) programs. This project funds the testing and integration of the modem and processing equipment enabling a Non- Geostationary Orbit (NGSO) system to operate on Navy submarines. The project will conduct a competitive prototyping process to evaluate and down select prototypes from multiple vendors resulting in an Engineering Development Model (EDM). The FY 2027 request supports the SATCOM NGSO Technology Insertion Critical Design Review (CDR), Test Readiness Review (TRR), and Engineering Development Model (EDM) vendor design testing, preparing for Production Representative Asset (PRA) delivery in FY 2028. (0729) Satellite Communications: The details of Program Element 0604280N, Project 0729 for MAT are classified SECRET//NOFORN and are submitted to Congress in the classified budget justification books. (0742) Submarine Integrated Antenna System: The details of Program Element 0604280N, Project 0742 are classified SECRET//NOFORN and are submitted to Congress in the classified budget justification books. (0921) Navigation Satellite Timing & Ranging (NAVSTAR) Global Positioning System (GPS) project (0921) encompasses the Navy's efforts to pace the growing threat to GPS Navigation through the fielding of new GPS receivers, Anti-Jam (AJ) Antennas, and Assured-Positioning Navigation and Timing (A-PNT) technologies across all Navy platform types. NAVSTAR GPS is a group of A-PNT systems that provides authorized users with secure, worldwide, all weather, three dimensional position, velocity, and precise time data. NAVSTAR GPS provides A-PNT capability to Command, Control, Communications, Computer, Intelligence, Surveillance and Reconnaissance (C4ISR) and combat systems in standalone and networked architectures throughout air and maritime domains. This project is comprised of four distinct Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                             Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 5: System            PE 0604280N / JT TACTICAL RADIO SYSTEM (JTRS) Development & Demonstration (SDD) efforts: Sea Navigation Warfare (NAVWAR), GPS-based Positioning, Navigation, and Timing (PNT) Service (GPNTS), Air Navigation Warfare (NAVWAR) and GPS Modernization. Sea NAVWAR provides AJ antennas to surface and subsurface platforms; GPNTS provides GPS receivers and A-PNT technology to surface platforms; Air NAVWAR provides AJ antennas, and GPS Modernization provides GPS receivers to air platforms. Research, Development, Testing and Evaluation (RDT&E) funds are used to perform all the non-recurring GPS Surface Ship, and Aircraft Development, Integration, and Testing efforts in support of NAVSTAR GPS. FY 2027 request will fund the following GPS Surface Ship, Submarine and Aircraft Development, Integration and Test efforts in support of NAVSTAR GPS: continue investigation of enhanced Anti-Jam (AJ) capabilities for integration into existing Sea NAVWAR antenna systems and evaluate ADAP with FPGA prototypes, continue efforts to develop and test a GPNTS system capable of hosting the Automated Celestial Navigation Systems (ACNS) below deck hardware and support, continue support for Non-GPS Aided Positioning for Surface Ships (NoGAPSS) follow-on test and evaluation, continue to support Assured-Positioning Navigation and Timing (A- PNT) efforts by working with Navy Air platforms on navigation requirements, and continue integration of Military Code (M-Code) receivers into existing Embedded Global Positioning System/Inertial Navigation System (GPS/INS) (EGI); ANAV-3M, LN-100M, and LN-251M, and commence of LN-251M, LN-100M and ANAV-3M interim solution testing for E-2D, P-8, F/A-18E/F, MH-60R/S and EA-18G. (1411) Submarine Tactical Communications System: The details of Program Element 0604280N, Project 1411 are classified SECRET//NOFORN and are submitted to Congress in the classified budget justification books. (2126) Tactical Data Link (TDL) systems include the Advanced Tactical Data Link Systems (ATDLS) integration programs, specifically Link 16 Network (Link 16), Command and Control Processor (C2P) and Link Monitoring and Management Tool (LMMT). FY 2027 JUSTIFICATION FOR BUDGET ACTIVITY: Advanced Tactical Data Link Systems (ATDLS) is the United States (US) Navy's only ship-to-ship/ship-to-aircraft tactical information solution equipping warfighters and Combatant Commanders with real-time battlespace data and extending the range of lethality. ATDLS is the backbone of Carrier Strike Group and AEGIS-Based Defense operations and is the key component in the fire control loop, providing critical track information for enabling maritime offense/defense, Joint Area Domain Command and Control (JADC2), Integrated Air and Missile Defense (IAMD), Ballistic Missile Defense (BMD), Anti-Air Warfare (AAW), Anti-Surface Warfare (ASuW), Electronic Warfare (EW), Advanced Offboard Electronic Warfare (AOEW), and Long Range Fires (LRF) missions. ATDLS Integration Program develops new and improved Tactical Data Links (TDL) networking capabilities, delivering operational and targeting support to the warfighter. ATDLS rapidly and securely connects carrier/shipboard digital combat systems to military aircraft, ground troops, coalition partners, and space assets with vital Situational Awareness, targeting, and sensor information. ATDLS also provides Joint Range Extension capability via Link 16 Network (Link 16) Terminals, Command and Control Processor (C2P), and Link Monitoring and Management Tool (LMMT). Link 16 Network (Link 16) Increment II: Link 16, enhanced by Tactical Targeting Networking Technology (TTNT), is the Military's only joint network providing secure TDL interoperability and data sharing in contested battlespace environments. The Link 16 development initiatives are in support of Joint Chiefs of Staff Joint Requirements Oversight Council Memorandum (JROCM) 075-17 for installation and integration of Multifunctional Information Distribution System (MIDS) Joint Tactical Radio System (JTRS) terminals into the Navy shipboard environment. Link 16 initiatives also include TDL Advanced Capabilities and development and testing of enhanced throughput antennas, AS-4775A/B and AS-4557A. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                              Date: April 2026 Appropriation/Budget Activity                                                     R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 5: System               PE 0604280N / JT TACTICAL RADIO SYSTEM (JTRS) Development & Demonstration (SDD) Command and Control Processor (C2P): The only shipboard solution that enables bi-directional exchange of tactical information across multiple TDLs within the joint operations areas. C2P processes and exchanges Link 11, Link 16, Satellite TDL J, and Joint Range Extension Applications Protocol (JREAP) tactical data among the US, North Atlantic Treaty Organization (NATO), and allied nation military platforms enabling the vital joint TDL interfaces. Additionally, C2P provides data translation services, acts as a single interface between host combat system and TDL networks, and forwards tactical data between platforms operating at extended ranges. C2P enables surface platforms capability to conduct Ballistic Missile Defense (BMD) Launch-on-Remote/Engage-on-Remote and Autonomous Vehicle missions. C2P RDT&E initiatives include: 1) C2P Technology Refresh (TR) cybersecurity updates and C2P v3.13 software TTNT capability implementation and certification ; and 2) C2P Modernization capability development including Link 22 integration. Link Monitoring and Management Tool (LMMT): LMMT is the Military's premier solution providing Joint Interface Control Officers (JICOs) and Maritime Operations Centers (MOCs) with effective monitoring and performance management of TDL networks in designated Areas of Responsibility (AORs). LMMT also allows Marime Component Commanders to Fight from the MOC and perform MOC in the Middle functions in support of JADC2 and BMD missions. LMMT RDT&E initiatives will deliver an improved commercial off-shelf hardware design, providing gateway functions for multiple TDL interfaces, routing and display of TDL data to include Link 16, Joint Range Extension (JRE) and Link 22. (3020) The Multifunctional Information Distribution System (MIDS) is the most widely fielded family of Tactical Data Link radio terminals in the world. The MIDS program office is the Performing Activity for the Navy (Lead Service for Department of DWar (DOw)), Link 16 capability and consists of two (2) product lines, MIDS Low Volume Terminal (LVT) (legacy hardware defined radio) and MIDS Joint Tactical Radio System (JTRS) (software defined radio). MIDS-LVT effort is a cooperative development program between France, Germany, Italy, Spain, and the United States with United States joint service participation (Navy, Army, Air Force), and has provided over 12,000 terminals to more than 50 Nations providing interoperability with North Atlantic Treaty Organization (NATO) and coalition partners. The Department of War (DoW) established the program to design, develop, and deliver low volume, lightweight tactical information system terminals for U.S. and allied fighter aircraft, bombers, helicopters, ships, and ground sites. MIDS-LVT significantly increases force effectiveness and minimizes hostile actions and friend-on-friend engagements. MIDS-LVT Block Upgrade 2 was executed as an Engineering Change Proposal (ECP) and provides the critical upgrades to the MIDS-LVT Terminal to enable U.S., Coalition and International partners' ability to meet the National Security Agency (NSA) mandated timelines for Cryptographic Modernization (CM) and the National Telecommunications and Information Agency (NTIA) and Federal Aviation Agency (FAA) mandated timelines for Frequency Remapping (FR). Multifunctional Information Distribution System (MIDS) Joint Tactical Radio System (JTRS), designed as a Pre-Planned Product Improvement (P3I) and executed as an Engineering Change Proposal (ECP) to the production MIDS Low Volume Terminal (LVT) configuration, and is fully compatible with MIDS-LVT. The MIDS JTRS Core Terminal achieved Full Production and Fielding (FP&F) in March 2012. It facilitated the JTRS incremental approach for fielding advanced JTRS transformational networking capability and transformed the MIDS-LVT into a 4-channel, Software Communications Architecture (SCA) compliant, Joint Tactical Radio. A form-fit-function replacement to MIDS-LVT, MIDS JTRS also adds three programmable 2 Megahertz (MHz) to 2 Gigahertz (GHz) channels capable of hosting the JTRS legacy and networking waveforms. In addition to Link 16, Tactical Air Navigation (TACAN), and voice functionality found in MIDS-LVT, MIDS JTRS has four channels and adds capabilities such as Link 16 Enhanced Throughput (ET), Link 16 FR, software programmability, CM, and Four Net Concurrent Multi-Netting with Concurrent Contention Receive (CMN-4). Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                                Date: April 2026 Appropriation/Budget Activity                                                        R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 5: System                  PE 0604280N / JT TACTICAL RADIO SYSTEM (JTRS) Development & Demonstration (SDD) MIDS JTRS Tactical Targeting Network Technology (TTNT), is a block upgrade to the MIDS JTRS CMN-4 Terminal providing an Internet Protocol-based networking capability on tactical aircraft. TTNT is a low latency, high throughput waveform that has the capability to support data exchange between fast-moving tactical aircraft, weapons, and unmanned aircraft, in addition to air, land, and sea-based command and control nodes, in a variety of air-to-air and air-to-ground missions including time sensitive targeting, air warfare, close air support, non-traditional ISR, and anti-surface warfare. TTNT and MIDS JTRS CMN-4 are critical Tactical Data Link capabilities and directly supports Naval Integrated Fire Control (NIFC) capability requirements. These capabilities provide Joint Airborne Network-Tactical Edge functionality to run advanced mission applications in a cross-platform/cross-domain tactical network enterprise. The FY 2027 Budget continues Electromagnetic Compatibility Features (EMCF) test/certification for all MIDS variants, begins the Integrated Software Build 9.4, Block Cycle 3 for fleet release of various updated capabilities (specific capabilities classified), and begins the development work for new hardware and updated software capabilities. FY 2027 also continues the TACAIR initiatives. (3078) Beginning in FY 2027, the program name Digital Modular Radio (DMR) has been changed to Tactical, Resilient Communications (TRC). Tactical, Resilient Communications (TRC) with Integrated Waveform (IW) and Mobile User Objective System (MUOS) capable hardware is the Navy's technical solution for the IW/MUOS requirement. The compact, multi-channel system provides 3G, Wideband Code Division Multiple Access (WCDMA) technology, for high speed/ capacity voice and data satellite communications. TRC radios currently operate aboard U.S. Navy surface and subsurface vessels, fixed-sites and other Department of War (Dow) communication platforms using frequencies ranging from 2 MHz to 2 GHz. Certified to pass secure voice and data at Multiple Independent Levels of Security (MILS) over High Frequency (HF), Very High Frequency (VHF), Ultra High Frequency (UHF), and Satellite Communications (SATCOM) channels, the TRC system was developed to the U.S. Navy's specifications and meets all the stringent environmental, Electromagnetic Interference (EMI) and performance requirements for use in the U.S. Fleet. This system is formally specified by both Fleet Commanders as a threshold capability, for global maritime command control and communications in a Distributed Maritime Environment, to execute current warfighting plans and is required for National Command and Control capability. This program is for continued development/integration of the IW and MUOS waveforms into the system in accordance with Military Standards 188-181,2,3. Additionally, the enhancements of High Frequency Distribution Amplifier Group (HFDAG) and, HF Automated Link Establishment (ALE) and Second-Generation Anti-Jam Tactical UHF Radio for NATO (SATURN) will also be developed/integrated into the system. HFDAG is a follow-on HF solution to fulfill transmit and receive HF communication capability with various modes of operation, such as ALE, for Navy platforms. HFDAG will utilize the existing system as the exciter/receiver. Generation 3 (GEN 3) HF ALE/HF wideband provides Navy users with improved HF communications, increased transmission rates from radio to radio, and serves as a supplement to SATCOM when SATCOM networks are overloaded or unavailable. SATURN is the follow-on HAVEQUICK II anti-jamming solution in accordance with NATO Standardization Agreement 4372. SATURN capability will counter adversaries' jamming efforts and ensure Navy's Assured Command and Control UHF communications operational end-to-end capability as well as enhance interoperability within/between system users and with Allied/Coalition partners. IW uses a Time Division Multiple Access (TDMA) communication system in an attempt to improve satellite bandwidth utilization over legacy SATCOM waveforms. This enables demand assigned services on UHF SATCOM networks to support new applications that require better performance and higher channel throughput. The MUOS waveform will enable MUOS satellites to provide worldwide communication satellite coverage for DoW requirements. MUOS will provide functionality comparable to commercial mobile phone systems. In FY 2027, the program will continue the development of follow-on tactical communication radio solution that will deliver critical cryptographic compliant waveforms to the fleet. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                                Date: April 2026 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 5: System             PE 0604280N / JT TACTICAL RADIO SYSTEM (JTRS) Development & Demonstration (SDD) (3341) Network Tactical Common Data Link (NTCDL) provides the ability to transmit/receive real-time Intelligence, Surveillance, and Reconnaissance (ISR) data simultaneously from multiple sources (surface, airborne, sub-surface, man-portable), and exchange command and control information (voice, data, imagery, and Full Motion Video) across dissimilar joint, service, coalition, and civil networks. NTCDL provides warfighters with the capability to support multiple, simultaneous, networked operations with currently fielded Common Data Link (CDL)-equipped air platforms (e.g. MH-60R), in addition to next generation manned and unmanned platforms (e.g., P-8, Triton, MQ-25 (Stingray), small tactical unmanned aircraft systems (STUAS) and Fire Scout). NTCDL is an incremental capability (surface, airborne, sub-surface, and man-portable) providing modular, scalable, multiple-link networked communications. NTCDL benefits the fleet by providing a horizon extension for line-of-sight sensor systems for use in time-critical strike missions and supports tasking, collection, processing, exploitation, and dissemination (TCPED) via its ISR networking capability. NTCDL supports Resilient Command and Control (RC2) through its relay capability, and supports TCPED through its ISR networking capability. FY 2027 request is for NTCDL to continue enhancing the current system through software upgrades and bug fixes. This funding will support software enhancements that directly lead to meeting program requirements and supporting MQ-25 testing requirements. (4011) The Navy Expeditionary C4I project supports the Navy Expeditionary Combat Command (NECC) mission to detect, deter or interdict potential threats to DoN assets using agile, modular and scalable technology. NECC units have a number of current and future Command, Control, Communications, Computers & Intelligence (C4I) technological requirements for Tactical/Command Operations Center, tactical vehicles, combatant craft, and dismounted personnel. NECC operations require units to maintain effective command and control, develop and display a common tactical picture, and share intelligence and current operational information with higher headquarters, subordinate units, joint forces and coalition allies. Small, Medium, and Large Scale Communication Systems (LSCS) are the C4I hub for the NECC; Expeditionary Deployable Node (EDN) is the converged LSCS baseline. Future C4I research and development include enhanced information transport, network cyber security posture, assured communications in denied environments along with agility and mobility. Funding is required for testing and evaluation of cyber security issues associated with obsolescence of network items and if not addressed will impact the ability of the Program Office to maintain system accreditation under Risk Management Framework (RMF) revoking multiple LSCS assets authority to connectivity on the Department of War Information Network (DoWIN). Efforts are in alignment with NECC's strategic Expeditionary Warfare Improvement Program (EXWIP) Integrated Priority Capability List (IPCL) priorities and maintain alignment with greater DoW initiatives, such as Joint Information Environment (JIE), Mission Partner Environment (MPE) in order to maintain interoperability and drive down DoN enterprise costs. FY 2027 request decrease of (0.263M) is due to reduced development of an implementation strategy for the multiyear cloud adoption strategy to migrate Joint Expeditionary Cloud Services assess feasibility of migrating Tactical Entry Point (TEP) services to a cloud and/or carrier-neutral facility (CNF) in the DoW Multi-Cloud (Public) architecture. (9999) CA53 - The details of Program Element 0604280N, Project CA53 for Digital High Frequency Communication Modernization are classified SECRET//NOFORN and are submitted annually to Congress in the classified budget justification books. (9999) CA54- Integration of Global Broadcast Services (GBS) Capabilities extends GBS secure file/video capability to commercial Satellite Communications (SATCOM) constellations. This enables the development of a new secure On Demand portal at the GBS ground segment and the shipboard integration with STtNG. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                             Date: April 2026 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 5: System           PE 0604280N / JT TACTICAL RADIO SYSTEM (JTRS) Development & Demonstration (SDD) (9999) CA55 - This effort supports Radio Energies Transformed into Numerous Apertures (RETINA) through development of Advanced Radio Frequency (RF)/photonics direct conversion systems and continued development, test, demonstration and validation of enhanced capabilities to prototype a Luneberg Lens antenna system for Low Earth Orbit (LEO), Medium Earth Orbit (MEO) and Geostationary Earth Orbit (GEO) satellites, initially focusing on X-band. (9999) CA56 - The details of Program Element 0604280N, Project CA56 for Modern HF Communications Relay Stations are classified SECRET//NOFORN and are submitted annually to Congress in the classified budget justification books. (9999) CA57-The development of Network Tactical Common Data Link (NTCDL) - Phased Array Antenna Qualification will produce a fully integrated and modernized prototype configuration that serves as a foundational pathfinder for a future NTCDL system. This prototype will drive down costs for future procurements, and enable more streamlined, lower-cost shipboard installations, supporting scalable NTCDL evolution with improved long-term affordability.$$, $$Budget J-Books/FY27/Navy/RDTEN_BA5_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604283F$$, $$Battle Mgmt Com & Ctrl Sensor Development$$, $$rdte_af_ba7$$, $$pacaf$$, 2026, 17353000, 0, 69040000, NULL, $${"source": "jbook_fy26"}$$::jsonb, $$This budget line item funds the replacement of the current Hawaii Air Route Surveillance Radar Version 4 (ARSR-4) to include prototype development, test, site preparation, and installation. The replacement radar will address DoD capability gaps driven by new threats and provide dual use for Hawaii Air Traffic Control (ATC). The new system is designated the ARSR-4 Replacement Hawaii (ARSR4R-HI) Long Range Radar (LRR). It is a key component of the integrated Homeland Defense capability for the defense of Hawaii and a high priority mission for Pacific Air Forces and the United States Indo-Pacific Command. The ARSR4R-HI program addresses the following surveillance shortfalls: 1. Lack of surveillance capabilities to meet today's mission needs such as inability to characterize and classify targets or cover all required airspace. 2. Inability to scale and update capabilities to pace evolving threats. 3. Obsolescence associated with 1980s era ARSR-4 equipment and infrastructure leading to excessive sustainment, operations, and maintenance costs. To address these surveillance shortfalls, development of the ARSR4R-HI system will consist of improved detection performance for modern air threats, mitigate new interference sources, and utilize state of the art surveillance technologies and processing capabilities. The ARSR4R-HI solution is based on a non-rotating, multi-panel, phased array radar system which provides persistent surveillance with improved accuracy and detection performance supporting an advanced engagement sequence to counter modern threats with target cueing and fire control quality data. The ARSR4R-HI components include a ground based surveillance radar, radar dome, associated shelters, and other smaller Government Furnished Equipment (GFE) items. The DoD currently owns the site for the location of the installation and the FAA leases the site. The ARSR4R-HI program includes the award of two Rapid Prototype Development capability demonstration contracts (Phase I) followed by down-select (Phase II) to a single vendor for Non-Recurring Engineering (NRE), mature prototype delivery, installation, interface with Command and Control (C2) nodes, and test of the new radar at the Mt. Ka'ala site. The FY 2026 cost of the ARSR4R-HI Middle Tier of Acquisition effort is reflected in the budget request, including RDT&E and procurement of prototype units. The Department will certify FYDP funding in a future budget submission. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                           Date: June 2025 Appropriation/Budget Activity                                                      R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:                  PE 0604283F / Battle Mgmt Com & Ctrl Sensor Development Operational Systems Development The FY 2026 request for ARSR4R-HI includes 17.4 million of discretionary and 150.0 million of mandatory (reconciliation) funds for a total of 167.4 million. The mandatory (150.0 million) funds, along with 45.7 million of FY 2025 funding, enable award of the Phase II prototype system contract. Further information for this reconciliation request is provided in Section 20003 of the Reconciliation Exhibit. The FY 2026 request was reduced by 0.136 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative." This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such programs funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY 2024, 0.599 million was expended for civilian pay expenses in this program element, and in FY 2025 1.955 million is forecasted for civilian pay expenses in this program element. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, NULL, 36132000, 24067000, 16032000, NULL, NULL, 150, $$FY26 Air Force Research and Development Test and Evaluation Vol III.pdf$$, NULL, FALSE, 66717000, 47298000, 44187000, 44187000, 0, 44187000, 16357000, $$Prior to FY 2026, this budget line item funded the replacement of the current Air Route Surveillance Radar Version 4 (ARSR-4) on Mt. Ka'ala, Hawaii (ARSR4R-HI) to include prototype development, test, site preparation, and installation. The responsibility for missile defense has been consolidated under the Golden Dome for America (GDA) architecture, which supersedes the former Air Force-specific requirement in Hawaii. This budget line item now funds the remaining requirement for replacement of the legacy ARSR4 radar on Mt. Ka'ala with a dual-use material solution meeting both the Air Force, Air Domain Awareness and the FAA, Air Traffic Control (ATC) missions. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such programs funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume III.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604286N$$, $$(U)NAVY ADVANCED MANUFACTURING$$, $$rdte_navy_ba4$$, $$navair$$, 2026, 10585000, 0, 0, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "navy", "page_num": 30, "original_pe": "0604286N", "page_header": "Department of the Navy"}$$::jsonb, $$Project 0311 - NAVAIR Advanced/Additive Manufacturing provides for the development of the Advanced/Additive Manufacturing/3D printing process, material verification and qualification to support deployment of Advanced/Additive Manufacturing (AM) capability to Fleet Depot and Level II Maintenance level facilities, as well as provides for the qualification, validation, testing and incorporation of private industry Additive Manufacturing initiatives across the Naval Aviation enterprise to include NAVSUP and DLA. Additionally, Advanced/Additive Manufacturing funds Cooperative Research and Development Activities (CRADAs) support with industry partners and next generation AM. This effort will fund the development, test, and approval of additional polymer material data curves, polymer material certification for aviation applications, and system documentation/training updates of additional high strength polymers for use on deployed AM systems. This will support deployed systems in producing critical parts for aircraft, support equipment and aircraft launch and recovery equipment, while enhancing Naval Aviation readiness and lethality allowing point of need part manufacturing to mitigate supply chain gaps, dramatically decreasing Mean Logistics Delay Times (MLDT) and increasing aircraft availability. Project 0312 - The NAVSEA Additive Manufacturing (AM) program focuses on development and use of AM equipment for Naval applications in land-based and afloat environments, including system performance requirements, shipboard integration requirements and considerations, material selection, design optimization, equipment and component certification, and digital engineering integration. Efforts also include consideration of AM across a wide variety of potential applications ensuring additively manufactured components can meet mission requirements and that system/component technical requirements are updated to leverage AM. Project 0313 - NAVWAR Digital Integration Advanced Manufacturing The NAVWAR Digital Advanced Manufacturing Ecosystem (DAME) project provides Navy Advanced Manufacturing (AdvM) technology aligning to Chief of Naval operations (CNO) priorities to deliver revolutionary capabilities to improve fleet readiness. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Navy                                                                                     Date: June 2025 Appropriation/Budget Activity                                                      R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 4: Advanced              PE 0604286N / (U)NAVY ADVANCED MANUFACTURING Component Development & Prototypes (ACD&P) Project 0314 - In accordance with the National Defense Strategy (NDS), A Design for Maintaining Maritime Superiority 2.0, and Navy Facility Command (NAVFAC) Strategic Design 2.0, this program provides the Navy with new capabilities to enable resilient and agile logistics thru advanced manufacturing (AdvM). Investing in AdvM enhances the fleet's ability to conduct operational logistics in a contested environment and ensures logistics supportability across the austere distributed battlespace. AdvM technology results in increased operational availability, on demand production of critical systems, and supply chain cost savings. This effort will identify critical parts suitable for AdvM production in the field; identify AdvM systems appropriate to produce and certify critical parts in the field; analyze and identify AdvM system implications across doctrine, organization, training, materiel, leadership and education, personnel, facilities and policy (DOTMLPF-P); conduct end-user training, field experimentation, and fleet exercise technology insertion to validate AdvM system capability and systems integration issues.$$, NULL, 10459000, 10747000, 10832000, NULL, NULL, 85, $$RDTEN_BA4_Book.pdf$$, NULL, FALSE, 0, 0, 10016000, 10016000, NULL, 10016000, 11027000, $$The Maritime Industrial Base's Deployable Advanced Manufacturing (AdvM) program conducts research, development, test and evaluation into various aspects of AdvM technologies in order to enhance readiness and enhance capabilities for Navy warfighters. Specifically the program provides for the development of the AdvM, to include Additive Manufacturing (AM, or 3D printing), process, material verification, and qualification to support deployment of AdvM/AM capability to Fleet Depot and Level II Maintenance level facilities. It provides for the qualification, validation, testing and incorporation of private industry AM initiatives across the Naval Aviation Enterprise to include NAVSUP and DLA. It funds Cooperative Research and Development Activities (CRADA) support with industry partners and next generation AM. It funds the development, test, and approval of additional polymer material data curves, polymer material certification for aviation applications, and system documentation/ training updates of additional high strength polymers for use on deployed AM systems. This will support deployed systems in producing critical parts for aircraft, support equipment and aircraft launch and recovery equipment, while enhancing Naval Aviation readiness and lethality allowing point of need part manufacturing to mitigate supply chain gaps, dramatically decreasing Mean Logistics Delay Times (MLDT) and increasing aircraft availability. The program also funds investigation into the development and use of AdvM equipment for Naval applications in land-based and afloat environments, including AdvM system performance requirements, shipboard integration requirements and considerations, material selection, design optimization, equipment and component certification, and digital engineering integration. Efforts also include consideration of AM across a wide variety of potential applications ensuring additively manufactured components can meet mission requirements and that system/component technical requirements are updated to leverage AM. The program evaluates and identifies critical parts suitable for AdvM production in the field; identifies AdvM systems appropriate to produce critical parts in tactical environments ashore; analyzes and identifies AdvM system implications across doctrine, organization, training, materiel, leadership and education, personnel, facilities and policy (DOTMLPF-P); conduct end-user field training, field experimentation, and fleet exercise technology insertion to validate AdvM system capability and systems integration issues. The program will also fund development of a digital manufacturing environment that provides a scalable, secure, and Risk Management Framework (RMF)-compliant solution, transforming isolated AM capabilities into an integrated Navy Fleet-wide manufacturing network, enabling real-time support, automated updates, and comprehensive visibility across all deployed AdvM assets. The FY 2025 spend plan amount for Navy Advanced Manufacturing includes $5,192 thousand of discretionary and $186,000 thousand of mandatory (reconciliation) for a total of $191,192 thousand. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                      Date: April 2026 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 4: Advanced        PE 0604286N / (U)NAVY ADVANCED MANUFACTURING Component Development & Prototypes (ACD&P)$$, $$Budget J-Books/FY27/Navy/RDTEN_BA4_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604288F$$, $$Survivable Airborne Operations Center (SAOC)$$, $$rdte_af_ba5$$, $$afnwc_nc$$, 2026, 1826328000, 0, 0, NULL, $${"source": "jbook_fy26"}$$::jsonb, $$The Survivable Airborne Operations Center (SAOC), E-4C, replaces the aging E-4B fleet, which faces capability gaps, diminishing manufacturing sources, increased maintenance costs, and parts obsolescence as it approaches the end of its serviceable life. SAOC provides the President of the United States (POTUS), the Secretary of Defense (SECDEF), and the Joint Chiefs of Staff (JCS) a worldwide, survivable, and enduring node of the National Military Command System (NMCS) to fulfill national security requirements throughout all stages of conflict. As a command, control and communications center directing US forces, executing emergency war orders and coordinating the activities of civil authorities including national contingency plans, this capability ensures continuity of operations and continuity of government as required in a national emergency or after negation/destruction of ground command and control centers. SAOC fulfills the requirements of the AF Nuclear Mission by providing Nuclear Command, Control and Communications (NC3) capabilities to enable the exercise of authority and direction by the President to command-and control US military nuclear weapons operations. Program funding supports all activities required to execute development of the SAOC Weapon System to include system development, integration of NC3 and other DoD/AF programs into the SAOC weapon system, test activities, pre-operational product support, and Interim Contractor Support (ICS). Funds also support program office operations, management services (Federally Funded Research and Development Centers [FFRDC], Advisory and Assistance Services [A&AS], etc.), Program Management Administration (PMA), security, facilities, prototyping, equipment, implementation of digital program initiatives, and other required program office capabilities. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605829F, 0605831F, 0605833F, or 0605898F. In FY 2024, $1.540M expended for civilian pay expenses in this program element. In FY 2024, $4.000M is forecasted for civilian pay expenses in this program element. The FY 2026 request for SAOC includes $1,826,328 thousand of discretionary and $6,800 thousand of mandatory (reconciliation) for a total of $1,833,128 thousand. The mandatory funds address EMD in FY 2026. Further information for this reconciliation request is provided in Chapter 8 (Nuclear) of the Reconciliation Exhibit. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                       Date: June 2025 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 5: System     PE 0604288F / Survivable Airborne Operations Center (SAOC) Development & Demonstration (SDD) This program is in Budget Activity 5, System Development and Demonstration (SDD) because it has passed Milestone B approval and is conducting engineering and manufacturing development tasks aimed at meeting validated requirements prior to full rate production.$$, NULL, 2518824000, 2710091000, 1889266000, NULL, NULL, 90, $$FY26 Air Force Research and Development Test and Evaluation Vol II.pdf$$, NULL, FALSE, 0, 1801293000, 2218921000, 2218921000, 0, 2218921000, 1352591000, $$The Survivable Airborne Operations Center (SAOC), E-4C, replaces the aging E-4B fleet, which faces capability gaps, diminishing manufacturing sources, increased maintenance costs, and parts obsolescence as it approaches the end of its serviceable life. SAOC provides the President of the United States (POTUS), the Secretary of War (SECWAR), and the Joint Chiefs of Staff (JCS) a worldwide, survivable, and enduring node of the National Military Command System (NMCS) to fulfill national security requirements throughout all stages of conflict. As a command, control and communications center directing US forces, executing emergency war orders and coordinating the activities of civil authorities including national contingency plans, this capability ensures continuity of operations and continuity of government as required in a national emergency or after negation/destruction of ground command and control centers. SAOC fulfills the requirements of the Air Force (AF) Nuclear Mission by providing Nuclear Command, Control and Communications (NC3) capabilities to enable the exercise of authority and direction by the President to command- and control US military nuclear weapons operations. Program funding supports all activities required to execute development of the SAOC Weapon System to include system development, integration of NC3 and other Department of War (DoW) AF programs into the SAOC weapon system, test activities, pre-operational product support, and Interim Contractor Support (ICS). Funds also support program office operations, management services (Federally Funded Research and Development Centers [FFRDC], Advisory and Assistance Services [A&AS], etc.), Program Management Administration (PMA), security, facilities, prototyping, equipment, implementation of digital program initiatives, risk mitigation strategies, and other required program office capabilities. The FY 2026 spend plan amount for SAOC RDT&E includes $1,801,300 thousand of discretionary and $64,500 thousand of mandatory (reconciliation) for a total of $1,865,800 thousand. This program element included all necessary expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 0605829F, 0605831F, 0605833F, and 0605898F. This program is in Budget Activity 5, System Development and Demonstration (SDD) because it has passed Milestone B approval and is conducting engineering and manufacturing development tasks aimed at meeting validated requirements prior to full rate production. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                       Date: April 2026 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 5: System      PE 0604288F / Survivable Airborne Operations Center (SAOC) Development & Demonstration (SDD)$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume II.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604288F_ba4$$, $$Survivable Airborne Operations Center$$, $$rdte_af_ba4$$, $$aflcmc$$, 2026, 0, 717641000, 1617187000, NULL, $${"ba_raw": "6.4", "source": "af_r1_fy26", "original_pe": "0604288F"}$$::jsonb, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604288F_ba5$$, $$Survivable Airborne Operations Center$$, $$rdte_af_ba5$$, $$aflcmc$$, 2026, 1833128000, 0, 0, NULL, $${"ba_raw": "6.5", "source": "af_r1_fy26", "original_pe": "0604288F"}$$::jsonb, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604289M$$, $$Expeditionary Logistics$$, $$rdte_navy_ba4$$, $$mcsc$$, 2026, 2722000, 4875000, 8114000, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "mc", "page_num": 30, "original_pe": "0604289M", "page_header": "Department of the Navy"}$$::jsonb, $$This program element supports cost associated with the research and development of Marine Corps Systems Command policy, acquisition process modifications, and prototyping to support the USMC Additive Manufacturing (AM) Initiative. The USMC Additive Manufacturing Initiative is an initiative intended to give Marine units access to additive manufacturing techniques to allow them the opportunity to exercise innovation in the resolution of issues affecting unit combat readiness. This PE will support of the development of procedures to enable the approval and manufacturing of items requested from Marines. This involves the assistance of developing Marine Corps Policy, an approval process, engineering analysis and testing, establishment of facilities to produce prototype additive manufactured parts, and development of training to support the Marine Corps use of additive manufacturing. This initiative incorporates development of strategic partnerships with other DoN Systems Commands and field activities to develop DoN standards, processes, and other associated acquisition activities to support future use of additive manufacturing in DoN acquisition and readiness areas. The Next Generation Logistics (NexLog) project supports cost associated with the research and development, experimentation, and limited, rapid fielding of emerging logistics capabilities necessary to enable the Fleet Marine Forces to execute the Marine Corps Operating Concept and inform logistics policies. These emerging logistics capabilities include development of autonomous ground, surface, and sub-surface materiel distribution systems; development of operational and tactical, in-field digital fabrication capabilities; and, the development of sensor-driven logistics information technology. This element also supports development of strategic partnerships with DoN Systems Commands and field activities in order to leverage their capabilities and align DoN standards and processes, while furthering the use of additive manufacturing, and other emerging logistics technologies, to increase warfighter readiness, capability, survivability, and effectiveness.$$, NULL, 2257000, 0, 0, NULL, NULL, 86, $$RDTEN_BA4_Book.pdf$$, NULL, FALSE, 8058000, 2722000, 24000, 24000, NULL, 24000, 2049000, $$Advanced Manufacturing Systems (AMS) includes a transformative capability for naval warfare and expeditionary operations, harnessing the power of both additive (3D printing) and subtractive manufacturing. This technology is a strategic game-changer, equipping the Marine Corps with a decisive advantage in readiness, sustainment, and lethality. By radically compressing the design-to-production cycle, AMS empowers Marines at the forward edge of the battlefield with the autonomy to solve problems on demand. As this capability evolves, it holds the key to resolving chronic supply chain vulnerabilities like obsolescence, diminishing manufacturing sources (DMSMS), and long lead times?challenges that will become even more acute in future Expeditionary Advanced Base Operations (EABO) and Distributed Operations (DO). The ability to manufacture critical components and even entire platforms at the point of need will forge a new era of logistical resilience, creating a scalable and highly responsive supply chain that directly supports the warfighter.$$, $$Budget J-Books/FY27/Navy/RDTEN_BA4_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604292N$$, $$FUTURE VERTICAL LIFT (MARITIME STRIKE)$$, $$rdte_navy_ba4$$, $$asn_rda$$, 2026, 7125000, 4010000, 4796000, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "navy", "page_num": 30, "original_pe": "0604292N", "page_header": "Department of the Navy"}$$::jsonb, $$Future Vertical Lift (Maritime Strike) (FVL (MS)) directs a Naval Aviation initiative to close key warfighting gaps and recapitalize capabilities lost when legacy rotary wing platforms (MH-60R, MH-60S, and MQ-8C) reach service-life limits beginning in the mid 2030s. The FVL (MS) program will develop and field more capable, maintainable and reliable crewed and uncrewed rotorcraft systems to meet the needs of the Navy. FVL (MS) will be a key component of Distributed Maritime Operations (DMO) which will add warfighting capabilities in long-range Intelligence, Surveillance, Reconnaissance, and Targeting (ISR&T), Surface Warfare, Undersea Warfare (Anti- Submarine Warfare and Mine Warfare), Air Warfare, Electronic Warfare, Naval Special Warfare, Personnel Recovery, Patient Movement, Humanitarian Assistance/ Disaster Relief and Combat Logistics. The activities conducted under this program will contribute to the acquisition documentation required to support a Milestone A (MS-A) decision and Technology Maturation and Risk Reduction (TMRR) key activities. These efforts will enable timely development of a Family of Systems (FoS) that provides best value and capability to the warfighter while maintaining effective and efficient war fighting capability in support of the Navy's 15-year Aviation Plan. JUSTIFICATION FOR BUDGET ACTIVITY: This program is funded under ADVANCED COMPONENT DEVELOPMENT AND PROTOTYPES because it includes all efforts necessary to evaluate integrated technologies, representative models or prototype systems in a high fidelity and realistic operating environment.$$, NULL, 5525000, 5240000, 5177000, NULL, NULL, 87, $$RDTEN_BA4_Book.pdf$$, NULL, FALSE, 4704000, 7125000, 5314000, 5314000, NULL, 5314000, 5593000, $$Future Vertical Lift (Maritime Strike) (FVL (MS)) directs a Naval Aviation initiative to close key warfighting gaps and recapitalize capabilities lost when legacy rotary wing platforms (MH-60R, MH-60S) reach service-life limits beginning in the mid 2030s and following the divestment of MQ-8C. The FVL (MS) program will develop and field more capable, maintainable and reliable crewed and uncrewed rotorcraft systems to meet the needs of the Navy. FVL (MS) will be a key component of Distributed Maritime Operations (DMO) which will add warfighting capabilities in long-range Intelligence, Surveillance, Reconnaissance, and Targeting (ISR&T), Surface Warfare, Undersea Warfare (Anti-Submarine Warfare and Mine Warfare), Air Warfare, Electronic Warfare, Naval Special Warfare, Personnel Recovery, Patient Movement, Humanitarian Assistance/Disaster Relief and Combat Logistics. The activities conducted under this program will contribute to the acquisition documentation required to support a Milestone A (MS-A) decision and Technology Maturation and Risk Reduction (TMRR) key activities. These efforts will enable timely development of a Family of Systems (FoS) that provides best value and capability to the warfighter while maintaining effective and efficient war fighting capability in support of the Navy's 15-year Aviation Plan. JUSTIFICATION FOR BUDGET ACTIVITY: This program is funded under ADVANCED COMPONENT DEVELOPMENT AND PROTOTYPES because it includes all efforts necessary to evaluate integrated technologies, representative models or prototype systems in a high fidelity and realistic operating environment.$$, $$Budget J-Books/FY27/Navy/RDTEN_BA4_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604294D8Z$$, $$Trusted and Assured Microelectronics$$, $$rdte_dw_ba4$$, $$dw$$, 2026, 512151000, 687715000, 537169000, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "dw", "page_num": 72, "original_pe": "0604294D8Z", "page_header": "Defense-Wide"}$$::jsonb, $$This program supports microelectronics modernization activities that enable defense systems to keep pace with commercial microelectronics technological advances, reduce reliance on obsolete microelectronics, and mitigate the Department’s reliance on sole source foundries for assured state-of-the-art (SOTA) microelectronics. It addresses the challenges of 1) having enduring access to a multiplicity of modern manufacturing processes that require commercial volumes to maintain long term viability and 2) protecting the intellectual property (IP) of the microelectronic parts that are manufactured. Microelectronics technology is a critical enabler for the development of new systems and sustainment of fielded systems. In addition, this program directly supports the priority of building a resilient Joint Force and defense ecosystem through modernization of key capabilities and fostering pathways to adapt SOTA commercial and dual- use technologies to Defense needs. This program also supports the objective of Making the Right Technology Investments by supporting the domestic microelectronics innovation ecosystem and partnering with industry to quickly incorporate market-driven commercial advances with military-relevant capabilities. This program supports the OUSD(R&E) Microelectronics Modernization Roadmap. The primary areas of focus of this roadmap include the following: access to state-of- the-art microelectronics technology, access to advanced packaging and test; access to the best commercial design technology; evidence-based assurance and secure design; foundry access; policies, standards, and Joint Federated Assurance Center (JFAC) governing body; access to radiation hardened microelectronics; access to non-complementary metal oxide semiconductor state-of-the-art (SOTA) microelectronics for radio frequency and optoelectronic applications; education and workforce development; and supply chain awareness and security. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Office of the Secretary Of Defense                                                   Date: June 2025 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 4:             PE 0604294D8Z / Trusted and Assured Microelectronics Advanced Component Development & Prototypes (ACD&P) Recognizing that an assured supply of microelectronics is a U.S. Government (USG)-wide concern, this activity will interface with interagency partners and stakeholders to capture interagency requirements, opportunities for collaboration, and strategic decisions that can be made to limit the overall cost of these requirements to the USG, limit unneeded duplication, and enable technology transition and adoption. This activity is being led by the Under Secretary of Defense for Research and Engineering.$$, NULL, 153891000, 154311000, 151477000, NULL, NULL, 108, $$RDTE_OSD_PB_2026.pdf$$, $$OSD$$, FALSE, 788321000, 549186000, 156743000, 156743000, NULL, 156743000, 151376000, $$This program provides microelectronics development and prototyping activities that support the 2026 National Defense Strategy Line of Effort to supercharge the United States Defense Industrial Base through building out capacity, empowering innovators and adopting new advancements in technology, guided by the Department’s policy on Assured Access to Trusted Microelectronics, and 10 USC 4128, Joint Federated Assurance Center. Microelectronics and their supporting supply chains face unprecedented and constantly changing and evolving security risks that threaten national security and the performance of Department of War (DoW) systems and technologies. Microelectronics products and services for DoW systems are most often obtained from a global supply chain. This requires the Department to have multiple options to maintain assured access to trusted microelectronics by managing risks from supply chain disruptions and malicious activity during all phases of design, manufacturing, packaging, test, and distribution. Microelectronics are a critical enabler of military systems to ensure the Joint Force is second to none. This program delivers trusted and assured microelectronics to support the lethal force through: Providing access to state-of-the-art (SOTA) microelectronics design, emulation tools, and intellectual property (IP) libraries; advanced fabrication nodes, and advanced packaging and test capabilities; and commercial device implementation and development of devices to strengthen the lethal force of the Department. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Office of the Secretary Of Defense                                                 Date: April 2026 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 4:            PE 0604294D8Z / Trusted and Assured Microelectronics Advanced Component Development & Prototypes (ACD&P) Development of evidence-based assurance methodologies to inform decisions on microelectronics systems, technologies, services and supply chains. Development and application of analytic techniques and methods for verification and validation of microelectronics designs, 3rd party IP, physical implementations and functionality, and counterintelligence awareness of threats to DoW microelectronics supply chain. Technology transition into systems and platforms providing improvements in size, weight, power, latency, bandwidth and resilience enabled by advanced chip manufacturing, multi-chip packages, radiation hardened microelectronics, and the maturation of microelectronics for communications, radar, missiles, electronic warfare, sensors and imaging. This program’s technology investments and innovations support the U.S. domestic microelectronics ecosystem. The program fosters and leverages partnerships with industry to rapidly incorporate market-driven commercial advances within military systems. This program interfaces with interagency partners and stakeholders to collaborate on joint requirements, reduce cost of microelectronics, reduce duplication, and enable technology transition and adoption. Projects within the PE provide: access to SOTA microelectronics technology; advanced packaging and test capabilities; on shore foundries, commercial design technology; radiation hardened microelectronics; and microelectronics for radio frequency and optoelectronic applications. This PE also promotes capabilities for hardware and software assurance, trusted and assured microelectronics education and workforce development, supply chain awareness and security, and maturation of evidence-based assurance methods, guidance, standards, and the Joint Federated Assurance Center (JFAC) governing body. This activity is led by the Under Secretary of War for Research and Engineering. The FY 2025 spend plan amount for Trusted and Assured Microelectronic includes $638,321 thousand of discretionary and $150,000 thousand of mandatory for a total of $788,321 thousand.$$, $$Budget J-Books/FY27/DW/RDTE_OSW_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604295M$$, $$(U)MARINE AVIATION DEMONSTRATION/VALIDATION$$, $$rdte_navy_ba4$$, $$dw_osd$$, 2026, 38873000, 0, 55805000, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "mc", "page_num": 30, "original_pe": "0604295M", "page_header": "Department of the Navy"}$$::jsonb, $$Marine Aviation Demonstration/Validation supports the development of Marine Aviation's future capability concepts as part of Marine Corps Force Design and Marine Corps Aviation's Project Eagle, progressing these concepts through development, demonstration and ultimately transition into fieldable capabilities This Program Element (PE) funds development of United States Marine Corps (USMC) Vertical Take-Off and Landing (VTOL) capabilities, including manned and unmanned air vehicles, and associated and requisite capabilities. Through development and prototyping, this PE matures and/or rapidly inserts industry and government technologies into lethality gaps, enabling a cohesive, warfighter-centric approach towards a future lethality-based portfolio for Marine Aviation. JUSTIFICATION FOR BUDGET ACTIVITY: This program is funded under ADVANCED COMPONENT DEVELOPMENT AND PROTOTYPES because it includes all efforts necessary to evaluate integrated technologies, and representative models or prototype systems in a high fidelity and realistic operating environment.$$, NULL, 52086000, 61984000, 62610000, NULL, NULL, 88, $$RDTEN_BA4_Book.pdf$$, NULL, FALSE, 54091000, 38873000, 47152000, 47152000, NULL, 47152000, 63698000, $$Marine Aviation Demonstration/Validation supports the development of Marine Aviation's future capability concepts as part of Marine Corps Force Design and Marine Corps Aviation's Project Eagle, progressing these concepts through development, demonstration and ultimately transition into fieldable capabilities This PE funds development of USMC Vertical Take-Off and Landing (VTOL) capabilities, including manned and unmanned air vehicles, and associated and requisite capabilities. Through development and prototyping, this PE matures and/or rapidly inserts industry and Government technologies into lethality gaps, enabling a cohesive, warfighter- centric approach towards a future lethality-based portfolio for Marine Aviation. JUSTIFICATION FOR BUDGET ACTIVITY: This program is funded under ADVANCED COMPONENT DEVELOPMENT AND PROTOTYPES because it includes all efforts necessary to evaluate integrated technologies, and representative models or prototype systems in a high fidelity and realistic operating environment.$$, $$Budget J-Books/FY27/Navy/RDTEN_BA4_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604307N$$, $$Surface Combatant Cmbt Sys Eng$$, $$rdte_navy_ba5$$, $$peo_ships$$, 2026, 527481000, 425017000, 528234000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "navy", "page_num": 33, "original_pe": "0604307N", "page_header": "Department of the Navy", "fy26_v182_disc_K": 524135, "fy26_v182_supp_K": 65000, "fy26_v182_total_K": 589135, "fy26_v182_note_name": "Surface Combatant Combat System Engineering", "fy26_v182_source_file": "RDTEN_BA5_Book.txt", "fy26_v182_source_line": 22450}$$::jsonb, $$Project 1111: Support the Integrated Combat System development effort to standardize hardware and refactor existing software on Surface Combatants and Large Deck platforms into a common computer program in support of DDG 51, DD(X), FFG 62, CVN, LHA, and LPD Class ships with a target initial delivery date in 2029 timeframe. Projects 1447 & 3357: Supports delivery of AEGIS Combat System (ACS) upgrades and integrates new capabilities to rapidly enhance the combat effectiveness of Arleigh Burke class destroyers (DDG 51) in order to confront an increasing array of strategic, operational, training, and tactical challenges. These efforts will be leveraged by the Constellation Class Frigates (FFG 62).$$, NULL, 417707000, 391718000, 315029000, NULL, NULL, 129, $$RDTEN_BA5_Book.pdf$$, NULL, FALSE, 512559000, 589135000, 425060000, 425060000, NULL, 425060000, 318018000, $$Project 1111: Support the Integrated Combat System development effort to standardize hardware and refactor existing software on Surface Combatants and Large Deck platforms into a common computer program in support of DDG 51, DD(X), CVN, LHA, and LPD Class ships with incremental deliveries starting in FY26 and full ICS delivering in 2029 timeframe. Projects 1447 & 3357: Supports delivery of AEGIS Combat System (ACS) upgrades and integrates new capabilities to rapidly enhance the combat effectiveness of Arleigh Burke class destroyers (DDG 51) in order to confront an increasing array of strategic, operational, training, and tactical challenges. The FY 2026 spend plan amount for Surface Combatant Combat System Engineering includes $524,135 thousand of discretionary and $65,000 thousand of mandatory (reconciliation) for a total of $589,135 thousand. The mandatory funds support the start of development, integration and test of Patriot Advanced Capability-3 (PAC-3) Missile. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                          Date: April 2026 Appropriation/Budget Activity                                               R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 5: System         PE 0604307N / Surface Combatant Cmbt Sys Eng Development & Demonstration (SDD)$$, $$Budget J-Books/FY27/Navy/RDTEN_BA5_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604317F$$, $$Technology Transfer$$, $$rdte_af_ba4$$, $$saf_aq$$, 2026, 3558000, 35952000, 10485000, NULL, $${"ba_raw": "6.4", "source": "af_r1_fy26", "original_pe": "0604317F"}$$::jsonb, $$Technology Transfer is a critical strategy for the NDS and DoD that makes the best possible use of national scientific, technical resources and information to enhance the effectiveness of DoD forces and warfighting capability systems. The Air Force Technology Transfer and Transition (T3) program oversees all Air Force inventions/ patents and technology transfer agreements (CRADAs, EPAs, CTAs, MTAs, etc). Over its history, Tech Transfer has provided a great return on investment (over 100 to 1), as the agreements themselves do not provide DoD funding to companies/non-traditionals, but serve as a way for the DoD to partner together and with industry to achieve a common goal. The only major costs to increasing this force multiplier are staff and legal support resources (they are not contracts). Since 2012 the Air Force Tech Transfer & Transition Program Office has managed two OSD-level Partnership Intermediaries (PIAs), TechLink & Miltech (Montana State University), as well as helped the Office of the Deputy Assistant Secretary of the Air Force for Science, Technology, and Engineering (SAF/AQR) in the management and oversight of the 16 Air Force PIAs (as of FY25). The 646003 project resources the management of DoD/AF PIAs, the development of data to support the Defense Technology Transfer Information System (DTTIS), invention disclosure & patent processing, program management activities, training, and support to the Technology Executive Officer (TEO). This program impacts virtually all technology fields, including the DoD Critical Technology Areas, and facilitates mechanisms to help achieve the operational imperatives via Tech Transfer as captured in the Annual DoD Technology Transfer Report. The AFWERX mission (relevant to Projects 64317A and 646030) is to accelerate agile and affordable capability transitions by teaming innovative technology developers with Airmen and Guardian talent. AFWERX leverages Spark (the Airmen and Guardian talent base), AFVentures (the dual-use expanded technology base), and Prime (technology transitions) to scale and accelerate the capability. Funding in this project supports AFWERX research and development, innovation hubs, and information technology, public affairs, and marketing. In FY 2025, the entirety of Project 646030, AFWERX efforts and Project 64317A, Technology Transfer Add in PE 0604317F, Technology Transfer, were transferred to PE 0604009F, AFWERX Prime, Project 640856 AFWERX Operations and Support. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                       Date: June 2025 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 4: Advanced PE 0604317F / Technology Transfer Component Development & Prototypes (ACD&P) This program element may include necessary civilian pay expenses required to manage, execute, and deliver Technology Transfer capabilities. The use of such programs funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. This program element may include necessary expenses to support the operation and maintenance of facilities to manage, execute, and deliver science and technology capabilities. This effort is in Budget Activity 4, Advanced Component Development and Prototypes (ACD&P), because efforts are necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment.$$, NULL, 2274000, 2317000, 2362000, NULL, NULL, 52, $$FY26 Air Force Research and Development Test and Evaluation Vol II.pdf$$, NULL, FALSE, 10151000, 37529000, 2196000, 2196000, 0, 2196000, 2410000, $$Technology Transfer is a critical part of the National Defense Strategy (NDS) and Department of War (DoW) that makes the best possible use of national scientific, technical resources and information to enhance the effectiveness of DoW forces and warfighting capability systems. The Department of the Air Force (DAF) Technology Transfer and Transition (T3) program oversees all of the DAF inventions/patents and technology transfer agreements, such as Cooperative Research and Development agreements (CRADAs), Material Transfer Agreements (MTAs), Confidential Disclosure Agreements (CDAs), etc. Over its history, Tech Transfer has provided a great return on investment (over 100 to one), as the agreements themselves do not provide DoW funding to companies/non-traditionals, but serve as a way for the DoW to partner together and with industry to achieve a common goal. The DAF Tech Transfer & Transition Program Office manages two DoW-level Partnership Intermediaries (PIAs), TechLink & MilTech (Montana State University) and assists the Office of the Deputy Assistant Secretary for Technology, Engineering & Product Support (SAF/AQT) in the management and oversight of the 14 DAF PIAs. This program element resources the management of DoW/DAF PIAs; the development of data to support the Defense Technology Transfer Information System (DTTIS); invention disclosure & patent processing; program management activities; and support to the Air Force Research Laboratory's (AFRL) Technology Executive Officer (TEO). This program impacts virtually all technology fields, including the DoW Critical Technology Areas, and facilitates mechanisms to help achieve the operational imperatives via Tech Transfer as captured in the Annual DoW Technology Transfer Report. In order to manage, execute, and deliver technology transfer capabilities, this program element may include: necessary civilian pay expenses; expenses to support the operation and maintenance of facilities; as well as expenses related to travel, supplies, IT hardware, software and support, etc. This effort is in Budget Activity 4, Advanced Component Development and Prototypes (ACD&P), because efforts are necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                        Date: April 2026 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 4: Advanced PE 0604317F / Technology Transfer Component Development & Prototypes (ACD&P)$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume II.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604320M$$, $$Rapid Technology Capability Prototype$$, $$rdte_navy_ba4$$, $$asn_rda$$, 2026, 16316000, 50681000, 86215000, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "mc", "page_num": 30, "original_pe": "0604320M", "page_header": "Department of the Navy", "fy26_v182_deferred": true, "fy26_v182_source_file": "RDTEN_BA4_Book.txt", "fy26_v182_source_line": 48274, "fy26_v182_supp_K_skipped": 18500, "fy26_v182_deferred_reason": "parser_disc_does_not_match_db_disc"}$$::jsonb, $$The Marine Corps Rapid Capabilities Office (MCRCO) is established under the direction of the Commandant of the Marine Corps (CMC) to identify, develop, and transition emergent and disruptive capabilities that significantly enhance survivability, lethality, and effectiveness for the Fleet Marine Forces (FMF). MCRCO focuses on rapid prototype development, testing, and integration of cutting-edge technologies at Technology Readiness Level 7 or higher, ensuring seamless and efficient transition to the FMF. Leveraging both government and commercial off-the-shelf solutions, as well as developmental items, MCRCO plays a critical role in maintaining the Marine Corps' strategic readiness and technological edge.$$, NULL, 150658000, 18390000, 13028000, NULL, NULL, 89, $$RDTEN_BA4_Book.pdf$$, NULL, FALSE, 82173000, 89007000, 125999000, 125999000, NULL, 125999000, 13396000, $$The Marine Corps Rapid Capabilities Office (MCRCO) focuses on the accelerating technological changes the battlefield has been met with and the constant evolution of threats. Established under the direct authority of the Commandant of the Marine Corps, the MCRCO operates with a singular, urgent purpose: to cut through bureaucratic inertia and rapidly deliver game-changing capabilities directly into the hands of the Fleet Marine Forces. Its mission is to identify, develop, and transition emergent and disruptive technologies that provide a decisive edge, significantly enhancing the survivability, lethality, and overall effectiveness of every Marine on the battlefield. Unlike traditional, multi-year acquisition programs, the MCRCO is built for speed, focusing on mature, cutting-edge technologies that can be fielded in months, not years. The office specifically targets solutions that have reached a Technology Readiness Level (TRL) of 7 or higher. This is a critical distinction. A TRL 7 designation signifies that a system is well beyond the conceptual or laboratory stage; it is a functioning prototype that has been successfully demonstrated in a realistic, operational environment. By concentrating on this level of maturity, the MCRCO minimizes developmental risk and drastically shortens the timeline from initial concept to combat- ready capability. Their process is a relentless cycle of rapid prototype development, rigorous testing, and seamless integration, all designed to ensure that when a new piece of gear arrives, it works as promised and integrates flawlessly with existing systems. To achieve this velocity, the MCRCO employs an agile and pragmatic sourcing strategy. It is not limited to a single development pipeline; rather, it leverages the best solutions available, regardless of their origin. This includes harnessing proven government-developed systems, adapting Commercial Off-the-Shelf (COTS) products from the private sector, and advancing promising developmental items that are on the cusp of a breakthrough. This flexible approach allows the MCRCO to act as a critical bridge, pulling technology from a wide array of innovators and pushing it to the warfighter who needs it most. Ultimately, the MCRCO plays an indispensable role in maintaining the Marine Corps' strategic readiness and technological superiority. It functions as the leading edge of modernization, ensuring that the Fleet Marine Forces are not just prepared for the conflicts of today, but are armed with the disruptive tools necessary to dominate the battlefields of tomorrow. By providing this accelerated pathway for innovation, the MCRCO guarantees that the Marine Corps can adapt faster than its adversaries and continue its legacy as the nation's premier expeditionary force in readiness. The FY 2026 spend plan amount for Rapid Prototype Development; Marine Corps Rapid Capabilities Office (MCRCO) includes $72,519 thousands of discretionary and $18,500 thousands of mandatory (reconciliation) for a total of $91,019 thousands. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                              Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 4: Advanced          PE 0604320M / Rapid Technology Capability Prototype Component Development & Prototypes (ACD&P)$$, $$Budget J-Books/FY27/Navy/RDTEN_BA4_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604327F$$, $$Hard and Deeply Buried Target Defeat System (HDBTDS) Program$$, $$rdte_af_ba4$$, $$ssc_milcom$$, 2026, 144143000, 14866000, 139408000, NULL, $${"ba_raw": "6.4", "source": "af_r1_fy26", "original_pe": "0604327F"}$$::jsonb, $$The Direct Strike Penetrator Systems program develops and modifies a family of advanced precision-guided penetrator munitions to include evaluation of integrated technologies for the development/integration of advanced position, navigation, and timing (PNT) capabilities (i.e., Global Positioning System (GPS), non-GPS, optical, passive, active, etc.) and smart fuze systems, and all penetrator components, that will provide the Air Force with improved ability to attack Hard and Deeply Buried Targets (HDBT), such as bunker and tunnel facilities, using air-to-surface conventional munitions. Systems developed include, but are not limited to Massive Ordnance Penetrator (MOP), GBU-72 Advanced 5,000-lb Penetrator Weapon System (A5K), and Section 804 Rapid Prototype/Rapid Fielding activities. Systems developed will be integrated onto current and future platforms to reduce the number of weapons required to hold HDBTs at risk and will result in more targets engaged per mission flown. Direct Strike Penetrators will provide critical global strike capability not met by inventory conventional weapons and will hold at risk the best protected high value assets essential to an enemy's war fighting ability. The project also provides an opportunity to quickly insert emerging technologies into existing and developing aircraft munitions and fuzes. A Hard Target Munitions (HTM) Analysis-of-Alternatives (AoA) was conducted in 2014 to determine the best weapons and/or development efforts for addressing the HDBT mission area. The HTM AoA determined that it was necessary to develop a family of HTMs in order to apply effects to the entire range of HDBT sets. The Air Force is using the AoA to develop, produce and modify HDBT weapons identified as the most effective and affordable. Modeling and simulation is used to assess and characterize current inventory and to drive design and explore the utility of new classes of penetrator munitions. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605829F, 0605831F, 0605833F, or 0605898F. In FY 2024 0.0M was expended for civilian pay expenses in this program element. In FY 2025 and FY 2026, $1.5M each is forecasted for civilian pay expenses in this program element. This program leverages digital acquisition tenets of open, agile, and digital. Common component development, in collaboration with other weapon systems, to reduce redundant costs between systems with similar subsystems requirements. Invests in analytical, information management, data management, digital environments, networks, facilities, and security infrastructure upgrades directly supporting development and sustainment of this program's capabilities, while leveraging DoD and DAF enterprise IT solutions. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                         Date: June 2025 Appropriation/Budget Activity                                                         R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 4: Advanced PE 0604327F / Hard and Deeply Buried Target Defeat System (HDBTDS) Program Component Development & Prototypes (ACD&P) This effort includes design, development, test, integration, and implementation of appropriate modular open systems approach, related components, and efforts, such as, but not limited to electrical, logical, and physical interfaces defined in relevant Open System Architecture (OSA) standards. This approach allows modular and severable subsystems, to include those that are software-defined, at the appropriate level to be incrementally added, removed, or replaced throughout the life cycle. The FY 2026 request was reduced by $0.131 million for civilian personnel to optimize the workforce in compliance with Executive Order 14210, "Implementing the President's Department of Government Efficiency Workforce Optimization Initiative.” This requirement supports performance of a full financial audit as required by title 10 U.S.C. Chapter 9A, Sec 240-D. This effort is in Budget Activity 4, Advanced Component Development and Prototypes (ACD&P), because efforts are necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment.$$, NULL, 126923000, 39575000, 1000, NULL, NULL, 53, $$FY26 Air Force Research and Development Test and Evaluation Vol II.pdf$$, NULL, FALSE, 120184000, 142661000, 186385000, 186385000, 0, 186385000, 1000, $$The Direct Strike Penetrator Systems program develops and modifies a family of advanced precision-guided penetrator munitions to include evaluation of integrated technologies for the development/integration of advanced position, navigation, and timing (PNT) capabilities (i.e., Global Positioning System (GPS), non-GPS, optical, passive, active, etc.) and smart fuze systems, and all penetrator components, that will provide the Air Force with improved ability to attack Hard and Deeply Buried Targets (HDBT), such as bunker and tunnel facilities, using air-to-surface conventional munitions. Systems developed include but are not limited to Massive Ordnance Penetrator (MOP), GBU-72 Advanced 5,000-lb Penetrator Weapon System (A5K), and Section 804 Rapid Prototype/Rapid Fielding activities. Systems developed will be integrated onto current and future platforms to reduce the number of weapons required to hold HDBTs at risk and will result in more targets engaged per mission flown. Direct Strike Penetrators will provide critical global strike capability not met by inventory conventional weapons and will hold at risk the best protected high value assets essential to an enemy's war fighting ability. The project also provides an opportunity to quickly insert emerging technologies into existing and developing aircraft munitions and fuzes. A Hard Target Munitions (HTM) Analysis-of-Alternatives (AoA) was conducted in 2014 to determine the best weapons and/or development efforts for addressing the HDBT mission area. The HTM AoA determined that it was necessary to develop a family of HTMs in order to apply effects to the entire range of HDBT sets. The Air Force is using the AoA to develop, produce and modify HDBT weapons identified as the most effective and affordable. Modeling and simulation is used to assess and characterize current inventory and to drive design and explore the utility of new classes of penetrator munitions. This program element included all necessary expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 0605829F, 0605831F, 0605833F, and 0605898F. This program leverages digital acquisition tenets of open, agile, and digital. Common component development, in collaboration with other weapon systems, to reduce redundant costs between systems with similar subsystems requirements. Invests in analytical, information management, data management, digital environments, networks, facilities, and security infrastructure upgrades directly supporting development and sustainment of this program's capabilities, while leveraging DoW and DAF enterprise IT solutions. This effort includes design, development, test, integration, and implementation of appropriate modular open systems approach, related components, and efforts, such as, but not limited to electrical, logical, and physical interfaces defined in relevant Open System Architecture (OSA) standards. This approach allows modular and severable subsystems, to include those that are software-defined, at the appropriate level to be incrementally added, removed, or replaced throughout the life cycle. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                      Date: April 2026 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 4: Advanced PE 0604327F / Hard and Deeply Buried Target Defeat System (HDBTDS) Program Component Development & Prototypes (ACD&P) This requirement supports performance of a full financial audit as required by title 10 U.S.C. Chapter 9A, Sec 240-D. The FY 2026 spend plan amount for RDT&E, Air Force includes $120,184 thousand of discretionary and $154,000 thousand of mandatory (reconciliation) for a total of $274,184 thousand. FY 2025 was rescinded $39.055 million and is not reflected in this budget documentation. This effort is in Budget Activity 4, Advanced Component Development and Prototypes (ACD&P), because efforts are necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment.$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume II.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604329N$$, $$Small Diameter Bomb (SDB)$$, $$rdte_navy_ba5$$, $$asn_rda$$, 2026, 23836000, 50208000, 19744000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "navy", "page_num": 33, "original_pe": "0604329N", "page_header": "Department of the Navy"}$$::jsonb, $$Small Diameter Bomb Increment II (SDB II) is an ACAT 1C joint Department of the Air Force (USAF) and Department of the Navy (DON) program, with the USAF as the lead service. The SDB II increases joint lethality in contested environments. The SDB II can strike a diverse set of targets inside an adversary's air and missile defense networks to destroy mobile platforms through the weather. With increased loadout, range, and munitions effect the network enabled SDB II enhances close combat lethality in complex terrain and provides a net-centric operations capability. BRU-61C/A is a modification of the USAF BRU-61B/A upgraded for DON and F-35 environmental requirements. The BRU-61C/A is Universal Armament Interface (UAI) capable, pneumatic rack capable of carrying four SDB II's at once. The threshold aircraft for the USAF is the F-15E and F-35B and F-35C for the DON. F/A-18 E/F is an objective platform for the DON. The DON has adjusted the platform integration strategy through the inclusion of F/A-18 E/F using BRU-55 to deliver the capability to the warfighter aligned to the adjusted F-35 program's schedule. BUDGET ACTIVITY JUSTIFICATION: This program is funded under SYSTEM DEVELOPMENT AND DEMONSTRATION because it includes those projects that have passed Milestone B approval and are conducting engineering and manufacturing development tasks aimed at meeting validated requirement prior to full-rate production decision.$$, NULL, 17360000, 10245000, 9764000, NULL, NULL, 130, $$RDTEN_BA5_Book.pdf$$, NULL, FALSE, 21234000, 23836000, 64428000, 64428000, NULL, 64428000, 9941000, $$Small Diameter Bomb Increment II (SDB II) is an ACAT 1C joint Department of the Air Force (USAF) and Department of the Navy (DON) program, with the USAF as the lead service. The SDB II increases joint lethality in contested environments. The SDB II can strike a diverse set of targets inside an adversary's air and missile defense networks to destroy mobile platforms through the weather. With increased loadout, range, and munitions effect the network enabled SDB II enhances close combat lethality in complex terrain and provides a net-centric operations capability. BRU-61C/A is a modification of the USAF BRU-61B/A upgraded for DON and F-35 environmental requirements. The BRU-61C/A is Universal Armament Interface (UAI) capable, pneumatic rack capable of carrying four SDB II's at once. The threshold aircraft for the USAF is the F-15E, and for the DON is F-35B and F-35C. F/A-18 E/F is an objective platform for the DON. The DON has adjusted the platform integration strategy through the inclusion of F/A-18 E/F using BRU-55 to deliver the capability to the warfighter aligned to the adjusted F-35 program's schedule. BUDGET ACTIVITY JUSTIFICATION: This program is funded under SYSTEM DEVELOPMENT AND DEMONSTRATION because it includes those projects that have passed Milestone B approval and are conducting engineering and manufacturing development tasks aimed at meeting validated requirement prior to full-rate production decision.$$, $$Budget J-Books/FY27/Navy/RDTEN_BA5_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604331D8Z$$, $$Rapid Prototyping Program$$, $$rdte_dw_ba4$$, $$dw_strato$$, 2026, 274892000, 76871000, 69471000, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "dw", "page_num": 72, "fy27_mand_k": 1394000, "original_pe": "0604331D8Z", "page_header": "Defense-Wide", "fy27_mand_v157": "2026-05-08", "fy27_mand_source": "DoW_FY2027_Mandatory_Funding_Overview.txt Appendix B", "fy27_mand_section": "Munitions"}$$::jsonb, $$The Rapid Prototyping Program supports the Department's initiatives to Defend the Homeland, Build Sustainable and Long-Term Advantage, and Build a Resilient Joint Force and Defense Ecosystem. RPP supports the rapid development of prototypes within 12-to-24 months (technical maturation TRL 7-9) to address joint urgent needs identified through ideation with the Joint Staff, Combatant Commands, or Secretary of Defense guidance. Prototype requirements are developed using threat-informed physics-based mission analyses and are evaluated under the Office of the Assistant Secretary of Defense for Mission Capabilities’ (OASD(MC)) campaign of experimentation, resulting in military utility assessments. RPP supports the maturation of joint prototypes across the Department (including those developed by the Strategic Capabilities Office (SCO), Defense Innovation Unit (DIU), Defense Advanced Research Projects Agency (DARPA), and the Services (TRL 5-6)) that have successfully demonstrated a required capability but have not been independently assessed in an interoperable, system of systems architecture. Overarching program goals include modernization of cross-cutting joint technology areas, providing fieldable end-to-end mission capabilities for joint application, informing disparate programs of record, and delivering capabilities more quickly than traditional acquisition. RPP develops prototypes that reduce technical and integration risk across the Services and accelerate capabilities to programs of record and future Joint, rapid experimentation. RPP project selection aligns to strategic guidance including priority joint mission threads and the Under Secretary of Defense for Research and Engineering’s (USD(R&E)) critical technology areas. RPP rapidly develops and fields cross-cutting, joint prototype capabilities demonstrated in an operational environment to inform DoD and Service leadership. In FY 2026, RPP organized projects by focus areas aligned to specific, persistent capability gaps. Aligning the program to Secretary of Defense priorities, the following focus areas will allow Prototyping and Experimentation to rapidly respond to urgent and emergent requirements at the speed of relevance. Focus areas include: Kill Web Interoperability: The processes by which Joint Force Commanders plan, direct, coordinate, and control forces to accomplish assigned missions and enable Joint kill webs. Resilient Communications: The ability to maintain hardened mission-capable systems that allow for secure freedom of communications in contested electromagnetic spectrum environments. This includes alternate position, navigation, and timing. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Office of the Secretary Of Defense                                                  Date: June 2025 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 4:            PE 0604331D8Z / Rapid Prototyping Program Advanced Component Development & Prototypes (ACD&P) Sensors and Data Analytics: Networks of sensors and data collection assets, data analysis, and dissemination resources used to provide information to the joint force about strategic and tactical threats. Collaborative Multi-Domain Autonomy: The use of multi-domain uncrewed systems and autonomy to increase warfighting capabilities and to mitigate/negate risk to warfighters. Contested Logistics / Sustainment: The coordinated use, synchronization, and often sharing of logistics resources to deploy, support, and sustain highly dispersed joint forces in highly contested environments. This also includes other sustainment areas such as supply chain reduction efforts; additive manufacturing; operational/tactical water purification; and sustainment and transportation innovations. Weapons Kinetic/Non-Kinetic Effects: The delivery of weapon systems and long-range kinetic and non-kinetic effects in support of Joint offensive and defensive tasks to create specific lethal effects on a target. This area includes counter position, navigation, and timing; and techniques designed to deceive enemy observers and/or mitigate, disrupt, or negate adversary capabilities. Emerging Prototypes and Enablers: Supports the acceleration of DoD, CCMD, and Service priority efforts which provide unique capability and/or address critical gaps. This focus area incorporates Combat Support/Combat Enablers; Special Forces Capabilities; Medical Technologies/Devices; Special Access Program assimilation and operational management; prototyping through small business and non-traditional pathways; and the rapid development of technologies for inclusion in experimentation venues.$$, NULL, 339362000, 336696000, 254890000, NULL, NULL, 109, $$RDTE_OSD_PB_2026.pdf$$, $$OSD$$, FALSE, 67434000, 232635000, 238800000, 238800000, 1394000000, 1632800000, 274135000, $$The Rapid Prototyping Program (RPP) supports the Department's initiatives to Defend the Homeland, Build Sustainable and Long-Term Advantage, and Build a Resilient Joint Force and Defense Ecosystem. RPP supports the rapid development of prototypes within 12-to-24 months to address joint urgent and emergent needs identified through ideation with the Joint Staff, Combatant Commands, or Secretary of War guidance. Prototype requirements are developed using threat-informed physics-based mission analyses and are evaluated under the Office of the Assistant Secretary of War for Mission Capabilities’ (OASW(MC)) campaign of experimentation, resulting in military utility assessments. RPP supports the maturation of joint prototypes across the Department (including those developed by the Strategic Capabilities Office (SCO), Defense Innovation Unit (DIU), Defense Advanced Research Projects Agency (DARPA), and the Services (TRL 5-6)) that have successfully demonstrated a required capability but have not been independently assessed in an interoperable, system of systems architecture. Overarching program goals include modernization of cross-cutting joint technology areas, providing fieldable end-to-end mission capabilities for joint application, informing disparate programs of record, and delivering capabilities more quickly than traditional acquisition. RPP develops prototypes that reduce technical and integration risk across the Services and accelerate capabilities to programs of record and joint, rapid experimentation. RPP project selection aligns to strategic guidance including priority joint mission threads and the Under Secretary of War for Research and Engineering’s (USW(R&E)) critical technology areas. RPP rapidly develops and fields cross-cutting, joint prototype capabilities demonstrated in an operational environment to inform DoW and Service leadership. In FY 2026, RPP organized projects by focus areas aligned to specific, persistent capability gaps. Aligning the program to Secretary of War priorities, the following focus areas will allow Prototyping and Experimentation to rapidly respond to urgent and emergent requirements at the speed of relevance. Focus areas include: Kill Web Interoperability: The processes by which Joint Force Commanders plan, direct, coordinate, and control forces to accomplish assigned missions and enable joint kill webs. Resilient Communications: The ability to maintain hardened mission-capable systems that allow for secure freedom of communications in contested electromagnetic spectrum environments. This includes alternate position, navigation, and timing. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Office of the Secretary Of Defense                                                  Date: April 2026 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 4:          PE 0604331D8Z / Rapid Prototyping Program Advanced Component Development & Prototypes (ACD&P) Sensors and Data Analytics: Networks of sensors and data collection assets, data analysis, and dissemination resources used to provide information to the joint force about strategic and tactical threats. Collaborative Multi-Domain Autonomy: The use of multi-domain uncrewed systems and autonomy to increase warfighting capabilities and to mitigate/negate risk to warfighters. Contested Logistics / Sustainment: The coordinated use, synchronization, and often sharing of logistics resources to deploy, support, and sustain highly dispersed joint forces in highly contested environments. This also includes other sustainment areas such as supply chain reduction efforts; additive manufacturing; operational/tactical water purification; and sustainment and transportation innovations. Weapons Kinetic/Non-Kinetic Effects: The delivery of weapon systems and long-range kinetic and non-kinetic effects in support of joint offensive and defensive tasks to create specific lethal effects on a target. This area includes counter position, navigation, and timing; and techniques designed to deceive enemy observers and/or mitigate, disrupt, or negate adversary capabilities. Emerging Prototypes and Enablers: Supports the acceleration of DoW, Combatant Command, and Service priority efforts which provide unique capability and/or address critical gaps. This focus area incorporates Combat Support/Combat Enablers; Special Forces Capabilities; Medical Technologies/Devices; Special Access Program assimilation and operational management; prototyping through small business and non-traditional pathways; and the rapid development of technologies for inclusion in experimentation venues. The FY 2027 request for the Rapid Prototyping Program includes $238,800 thousands of discretionary and $1,394,000 thousands of mandatory for a total of $1,632,800 thousands. The mandatory funds the Low-Cost Containerized Munition - Ground Launch (LCCM-GL) effort, which is a rapid, competitive prototyping effort to support critical munitions acceleration. The FY 2027 mandatory funds continue efforts from FY 2026 to deliver integrated and resilient munitions for ground launch applications. The FY 2026 spend plan amount includes $232,635 thousand of discretionary and $706,200 thousand of mandatory (reconciliation) for a total of $938,835 thousand. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Office of the Secretary Of Defense                                            Date: April 2026 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 4:         PE 0604331D8Z / Rapid Prototyping Program Advanced Component Development & Prototypes (ACD&P)$$, $$Budget J-Books/FY27/Remaining/DoW_FY2027_Mandatory_Funding_Overview.txt$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604336F$$, $$Nuclear Delivery Systems Prototyping$$, $$rdte_af_ba4$$, $$aflcmc_wa$$, 2026, 56926000, 0, 39079000, NULL, $${"ba_raw": "6.4", "source": "af_r1_fy26", "original_pe": "0604336F"}$$::jsonb, $$The Air-delivered Nuclear Delivery System project addresses a United States Strategic Command capability gap resulting from a congressionally directed study which led to endorsement of the Department of Defense's Deputy's Management Action Group and initiation of this project. The Department of Air Force is working with the Department of Energy's National Nuclear Security Administration and its National Laboratories to quickly develop and demonstrate a prototype Air-Delivered system based on fielded technologies to close this gap in the near term. The project requires close Department of Air Force and Department of Energy interagency coordination to produce a prototype that will enable rapid transition to a fielded system. Early development will include Modeling and Simulation analysis of several Nuclear Explosive Package options to refine the proposed Nuclear Explosive Package. The Air-Delivered Nuclear Delivery System must meet nuclear weapon's environmental standards from storage to weapon detonation, while meeting reliability and target defeat requirements. The Air Force will provide test resources to include ground test facilities, F-15E test aircraft, and B-2 test aircraft, and will work with the aircraft Program Offices to identify aircraft integration requirements including any potential Operational Flight Program software and hardware changes. The Air Force will procure and provide the National Nuclear Security Administration with the components necessary to produce Prototype Weapon Assemblies for capturing environments and demonstrating functionality in high-fidelity ground and air tests. Ground tests may include static ejection, vibration and thermal, cable pull-down, sled tests, and other environments testing. Flight tests will be performed by Air Force F-15E developmental flight test aircraft, with final prototype demonstrations planned to fly on B-2 aircraft. Considerations in the development of the prototype include nuclear surety, maintenance and logistics, refinement of requirements (Military Characteristics), and producibility. After successful flight test demonstration of the prototype, the program will mature developmental hardware to nuclear system "diamond stamp” quality, ensure nuclear surety standards are met, and mature aircraft interfaces including Aircraft Monitor and Control functions. The Air Force Research Laboratory is focused on high-impact, multi-domain science, technology, and prototyping solutions that drive innovation now while laying the groundwork for the Air and Space Force to win the future fight. The Air Force Research Laboratory effectively synchronizes the Department of Air Force science and Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                        Date: June 2025 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 4: Advanced PE 0604336F / Nuclear Delivery Systems Prototyping Component Development & Prototypes (ACD&P) technology enterprise and workforce to align towards the most consequential DAF priorities and accelerate the delivery of game-changing science, technology, and prototypes. In order to manage, execute, and deliver capabilities, this program element may include necessary civilian pay expenses; expenses to support the operation and maintenance of facilities; as well as expenses related to travel, supplies, IT hardware, software and support, and administrative contractor services. This effort is in Budget Activity 4, Advanced Component Development and Prototypes (ACD&P), because efforts are necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment.$$, NULL, 71389000, 94425000, 96224000, NULL, NULL, 54, $$FY26 Air Force Research and Development Test and Evaluation Vol II.pdf$$, NULL, FALSE, 37709000, 42538000, 91550000, 91550000, 0, 91550000, 98172000, $$The Air-delivered Nuclear Delivery System project addresses a United States Strategic Command capability gap resulting from a Congressionally-directed study which led to endorsement of the Department of War's Deputy's Management Action Group and initiation of this project. The Department of Air Force is working with the Department of Energy's National Nuclear Security Administration and its National Laboratories to quickly develop and demonstrate a prototype air-delivered system based on fielded technologies to close this gap in the near term. The project requires close Department of Air Force and Department of Energy interagency coordination to produce a prototype that will enable rapid transition to a fielded system. Early development will include modeling and simulation analysis of several Nuclear Explosive Package options to refine the proposed Nuclear Explosive Package. The Air-Delivered Nuclear Delivery System must meet nuclear weapon's environmental standards from storage to weapon detonation, while meeting reliability and target defeat requirements. The Air Force, via cross-agency partnerships, will provide test resources to include ground test facilities, F-15E test aircraft, and B-2 test aircraft, and will work with the aircraft Program Offices to identify aircraft integration requirements including any potential Operational Flight Program software and hardware changes. The Air Force will procure and provide the National Nuclear Security Administration with the components necessary to produce Prototype Weapon Assemblies for capturing environments and demonstrating functionality in high-fidelity ground and air tests. Ground tests may include static ejection, vibration and thermal, linear acceleration subscale tests, Davis Gun tests, sled tests, and other environments testing. Flight tests will be performed by Air Force F-15E developmental flight test aircraft, with final prototype demonstrations planned to fly on B-2 aircraft. Considerations in the development of the prototype include nuclear surety, maintenance and logistics, refinement of requirements (Military Characteristics), and producibility. After successful flight test demonstration of the prototype, the program will explore maturation of developmental hardware to achieve nuclear system "diamond stamp” quality, ensure nuclear surety standards are met, inform future capabilities, and mature aircraft interfaces including Aircraft Monitor and Control functions. This program element included all necessary expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 0605829F, 0605831F, 0605833F, and 0605898F. The FY 2026 funding request was reduced by 14.300 million to account for the availability of prior year execution balances. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                              Date: April 2026 Appropriation/Budget Activity                                                     R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 4: Advanced PE 0604336F / Nuclear Delivery Systems Prototyping Component Development & Prototypes (ACD&P) This effort is in Budget Activity 4, Advanced Component Development and Prototypes (ACD&P), because efforts are necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment.$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume II.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604343F$$, $$Advanced Tanker Systems$$, $$rdte_af_ba4$$, $$aflcmc$$, 2027, 0, 0, 0, NULL, $${}$$::jsonb, NULL, NULL, 13030000, 13019000, 13009000, NULL, NULL, NULL, NULL, NULL, FALSE, 0, 0, 13036000, 13036000, 0, 13036000, 13272000, $$Advanced Tanker Systems (ATS) is a continuation of the efforts previously started in PE 0605057F, Next Generation Air-refueling System (NGAS). Developing future tanker capability and recapitalizing the Air Force's aging tanker fleet is a top priority for the Department of the Air Force, in direct support of the National Defense Strategy's vision of ‘Peace Through Strength.' The pacing challenge and the operational realities of the Indo-Pacific theater demand a paradigm shift in aerial refueling. The current tanker fleet, designed for uncontested airspace, presents a critical vulnerability. Its reliance on large, centralized basing and its significant electronic and physical signature make it a high-value target, jeopardizing the Joint Force's ability to project power and sustain high-tempo operations over vast distances. ATS directly addresses this capability gap, evolving aerial refueling from a simple logistics function into a resilient, combat-enabling capability. The FY 2024 NGAS Analysis of Alternatives (AoA) provided conclusions that tankers will need to be more survivable to operate in a contested environment. ATS is a modernization program designed to improve the connectivity, survivability, and overall viability of the Department of War's current and future tanker fleets. The program directly addresses the challenges of operating in highly-contested, near-peer environments by ensuring the tanker fleet can effectively support the Joint Force's global reach, power projection, and persistence. ATS will focus on developing and integrating platform-agnostic systems that comply with military open-source architecture standards, ensuring rapid adaptability and interoperability across platforms. Program activities will be executed using a modern, digital acquisition framework. This includes the extensive use of digital engineering and modeling, rapid prototyping, and iterative requirements refinement based on continuous market research and post-AoA studies. This agile approach is designed to mature and de-risk critical technologies before they are integrated, accelerating development timelines while reducing lifecycle costs. ATS program funding provides for technology transfer, maturation, and prototyping across four main lines of effort, all of which are critical to the long-term viability of the tanker enterprise. These efforts include 1) Connectivity will ensure the tanker serves as a critical node in the Joint All-Domain Command & Control (JADC2) architecture by implementing secure, multi-level communication suites, 2) Survivability will mature advanced defensive systems and threat detection capabilities to increase the ability to operate and persist in contested airspace, 3) Autonomy will be explored to reduce crew workload and enhance mission efficiency through capabilities like Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                              Date: April 2026 Appropriation/Budget Activity                                                        R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 4: Advanced PE 0604343F / Advanced Tanker Systems Component Development & Prototypes (ACD&P) autonomous refueling. Funding provides for operational concept exploration, technology studies, industry integration assessments and strategic planning, and system architecture development, and 4) Advanced Air Refueling Systems will mature novel concepts for air refueling and explore next-generation boom designs to improve reliability and compatibility with a wide range of receiver aircraft. The technologies developed are intended for spiral integration onto the KC-135, KC-46, as well as future tanker platforms through requirements maturation. Program management support costs include, but are not limited to, systems engineering, contractor support services, and civilian pay. Program support cost efforts consist of, but are not limited to, contract services and government costs. This requirement supports performance of a full financial audit as required by title 10 U.S.C. Chapter 9A, Sec 240-D. This program element included all necessary expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 0605829F, 0605831F, 0605833F, and 0605898F. This effort is in Budget Activity 4, Advanced Component Development and Prototypes (ACD&P), because efforts are necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment.$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume II.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604366N$$, $$Standard Missile Improvements$$, $$rdte_navy_ba5$$, $$peo_iws$$, 2026, 412964000, 366181000, 288297000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "navy", "page_num": 33, "original_pe": "0604366N", "page_header": "Department of the Navy"}$$::jsonb, $$STANDARD Missile (SM) is Navy's premier Integrated Air and Missile Defense (IAMD) capability providing ship's self-defense and Fleet area-defense against great power competition advanced threats. The SM active family of missiles (FoM) includes Medium Range (MR) SM-2 BLK IIIC, Extended Range (ER) SM-6 BLK I, IA, IAU and Long-range (LR) SM-6 BLK IB. This SM active FoM evolution improves primary mission areas for IAMD and evolved to include additional multi-mission defensive and offensive hypersonic kinetic capabilities. Today the SM-2 BLK IIICU, SM-6 BLK IAU and SM-6 BLK IB are aligned with the Joint Warfare Concept (JWC), Joint Concept for Fires (JCF), the Navy's Navigation Plan Implementation Framework (NIF), and Navy Distributed Maritime Operations (DMO) to deliver the Navy and the Joint Force transformative capabilities addressing Combatant Commander and Chairman of the Joint Chief of Staff (JCS) highest capability gaps and capability requirements to support the Joint Operating Environment (JOE) for 2030 and 2045. The Standard Missile 2 BLK IIIC (SM-2 Block IIIC) is a transformation from medium range (MR) semi-active to MR active capability incorporating the SM-6 BLK I active seeker and delivering improved capabilities against the most challenging Air Warfare (AW) threats. The program was designated an Accelerated Acquisition (AA) program by the CNO/ASN RDA on November 14, 2017. The SM-2 Block IIIC Middle Tier Acquisition (MTA) program (previously known as accelerated acquisition program) delivered Initial Capability in 1Q FY 2023. The SM-2 BLK IIIC is transitioning from an MTA program into a Major Capability Acquisition (MCA) program for SM-2 BLK IIICU upon approval of the Acquisition Program Baseline (APB). As part of the SM-6 Family of Missiles, SM-2 Block IIICU will provide the fleet with a Medium Range (MR) active missile capability. SM-2 Block IIICU is intended to project power, provide area defense, and contribute to raid annihilation. The SM-2 Block IIICU combines the tested legacy of SM-2 propulsion stack and ordnance with capability improvements developed in the SM-6 Block I Program to improve overall missile performance via an ECP to the existing SM-6. The SM-2 Block IIICU Program was designated an ACAT II Program on 18 April 2022. The Standard Missile-6 (SM-6) BLK IB is an upgrade of the SM-6 BLK IAU, which provides long-range fires capability by implementing improved software and replacing the existing Mk 104 Dual-Thrust Rocket Motor (DTRM) with a new 21-inch rocket motor to extend the range. The SM-6 BLK IB delivers to the Navy and Joint Force a transformative multi-domain, multi-mission offensive hypersonic kinetic capability. As a result of internal deliberations, the SM-6 Blk IB program is currently on a strategic pause and only efforts to develop the 21-inch rocket motor are currently active. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Navy                                                                           Date: June 2025 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 5: System           PE 0604366N / Standard Missile Improvements Development & Demonstration (SDD)$$, NULL, 86640000, 67750000, 73286000, NULL, NULL, 131, $$RDTEN_BA5_Book.pdf$$, NULL, FALSE, 248688000, 511712000, 539279000, 539279000, NULL, 539279000, 74683000, $$The Department encourages additional vendor participation in the design, development, and production of alternative weapons systems to meet current and future warfighting requirements. With current major weapons systems production at capacity, the nation is looking for alternative systems to fill these gaps. The Department is implementing diverse procurement strategies to enable rapid acquisition. These will include the use of Other Transaction Authorities, 'Marketplace' acquisition platforms, and alternative concepts to increase supply and suppliers in addition to traditional FAR-based procurement strategies. STANDARD Missile (SM) is Navy's premier Integrated Air and Missile Defense (IAMD) capability providing ship's self-defense and Fleet area-defense against great power competition advanced threats. The SM active family of missiles (FoM) includes Medium Range (MR) SM-2 BLK IIIC, Extended Range (ER) SM-6 BLK I, IA, IAU and Long-range (LR) SM-6 BLK IB. This SM active FoM evolution improves primary mission areas for IAMD and evolved to include additional multi-mission defensive and offensive hypersonic kinetic capabilities. Today the SM-2 BLK IIICU, SM-6 BLK IAU and SM-6 BLK IB are aligned with the Joint Warfare Concept (JWC), Joint Concept for Fires (JCF), the Navy's Navigation Plan Implementation Framework (NIF), and Navy Distributed Maritime Operations (DMO) to deliver the Navy and the Joint Force transformative capabilities addressing Combatant Commander and Chairman of the Joint Chief of Staff (JCS) highest capability gaps and capability requirements to support the Joint Operating Environment (JOE) for 2030 and 2045. The Standard Missile 2 BLK IIIC (SM-2 Block IIIC) is a transformation from medium range (MR) semi-active to MR active capability incorporating the SM-6 BLK I active seeker and delivering improved capabilities against the most challenging Air Warfare (AW) threats. The program was designated an Accelerated Acquisition (AA) program by the CNO/ASN RDA on November 14, 2017. As part of the SM-6 Family of Missiles, SM-2 Block IIICU will provide the fleet with a Medium Range (MR) active missile capability. SM-2 Block IIICU is intended to project power, provide area defense, and contribute to raid annihilation. The SM-2 Block IIICU combines the tested Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                                   Date: April 2026 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 5: System          PE 0604366N / Standard Missile Improvements Development & Demonstration (SDD) legacy of SM-2 propulsion stack and ordnance with capability improvements developed in the SM-6 Block I Program to improve overall missile performance via an ECP to the existing SM-6. The Standard Missile-6 (SM-6) BLK IB is focused on long-range fires capability by replacing the existing Mk 104 Dual-Thrust Rocket Motor (DTRM) with a new 21- inch rocket motor to extend the range. The SM-6 BLK IB delivers to the Navy and Joint Force a transformative multi-domain, multi-mission offensive hypersonic kinetic capability. As a result of internal deliberations, SM-6 Blk IB development is currently on a strategic pause and only efforts to develop the 21-inch rocket motor for future hypersonic capabilities are currently active. The Naval Modular Missile (NMM) is the next generation family of surface and sub-surface launched kinetic hard-kill interceptors that serve as a competitive follow- on to the Standard Missile family of missiles. NMM variants align to the Joint Warfighting Concept (JWC), Joint Concept for Fires (JCF), the JCF Supporting Concept Development Guide, and the Joint concept for Joint Integrated Air and Missile Defense (JIAMD). It will provide the US Navy, Joint Force, Allies and Partners with advanced defensive and offensive capability to out-pace the threat. As the effective range, capability and capacity of adversary anti-access/area denial (A2/AD) systems have increased, the US Navy and Joint and Allied forces are at increased risk. Additionally, adversary capacity and expected large raid engagement tactics will demand US and Allied forces increase their platforms' defensive capacity (depth of magazine) or be forced to resupply frequently in the midst of combat operations. The adversary's increased capacity comes with increased capability in the form of highly-maneuverable, complex threats that will stress the current US weapon systems capabilities. The NMM program will tackle all of these challenges through a family of weapons approach.$$, $$Budget J-Books/FY27/Navy/RDTEN_BA5_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604373N$$, $$Airborne Mine Countermeasures$$, $$rdte_navy_ba5$$, $$navy_n9$$, 2026, 8372000, 10921000, 11066000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "navy", "page_num": 33, "original_pe": "0604373N", "page_header": "Department of the Navy"}$$::jsonb, $$The Airborne Mine Countermeasures (AMCM) Program Element (PE) previously provided resources to develop advanced Mine Countermeasures (MCM) systems, which are now in production. It currently funds post mission analysis software, integrated tactics and tactics training for mine warfare operations, and post mission analysis proficiency training. The MCM systems provide mobile, quick reaction forces capable of land or sea-based minehunting and mines countermeasures operations worldwide. Resources are for developing and deploying advanced mine-sweeping systems and the intelligence and oceanographic capabilities that will enable mine warfare superiority. Tactics and techniques used vary across a diversity of environments and threats, including both asymmetric and emerging. Resources provide for systems and support of mine warfare systems and expeditionary systems to allow for continuous operations of the Navy's warships and support vessels, other military vessels, and commercial vessels. Core capabilities include forward presence, deterrence, sea control, power projection, maritime security, humanitarian assistance and disaster response to maintain freedom of the seas. Capability improvements include: reducing post-mission analysis time; reducing detect, classify, and identify decision time; improving neutralization time; improving network communications; automatic target recognition; and achieving in-stride detect-to-engage capability. Concept- of-operations include development of cooperative, modular systems with a common post mission analysis system providing advanced tools to automate the complex problem of contact management for the thousands of recorded detections and the establishment of capable networked command and control systems. Efforts benefit the MCM force by transforming the Navy from the platform-centered legacy set of systems to a capability-centered force that is distributed, networked, and able to provide unique maritime influence and access across the entire maritime domain. The Airborne Mine Countermeasures (AMCM) programs will provide detection, classification, localization, identification, neutralization, influence sweep, and post mission analysis capabilities. This capability will be of critical importance in littoral zones, confined straits, choke points, and the Amphibious Objective Area (AOA). Project 4026 Net-Centric Sensor Analysis for Mine Warfare (NSAM) also includes the Integrated Tactics project. NSAM is the next generation post mission analysis (PMA) system which replaced the legacy Organic Post Mission Analysis (OPMA) system. NSAM will be the single tactical and environmental PMA system for all Mine Warfare (MIW) sensor data and will provide integrated contact management capabilities. NSAM creates a collaborative, multi-data set, multi-user environment with the goal of reducing the mission timeline and increasing mission effectiveness. NSAM is designed with an extensible architecture to ease integration of additional sensors and advanced algorithms including incorporation of artificial intelligence capabilities to reduce the time and burden of target recognition during mission analysis on the warfighter. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Navy                                                                              Date: June 2025 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 5: System             PE 0604373N / Airborne Mine Countermeasures Development & Demonstration (SDD) The Integrated Tactics project develops tactics at the MIW Staff and MCM Scenario level. Project provides new MIW tactics theory and Fleet tactics training for MIW Staffs. Theory and tactics are documented and published into doctrine for Fleet users. Project 9179, Surface Navy Integrated Undersea Tactical Technology (SNIUTT) is a software training tool which provides contact recognition training modules for Mine Countermeasures (MCM) sensor systems and runs on existing PMA and training systems.$$, NULL, 8465000, 11034000, 11088000, NULL, NULL, 132, $$RDTEN_BA5_Book.pdf$$, NULL, FALSE, 9422000, 8372000, 8567000, 8567000, NULL, 8567000, 11285000, $$The Airborne Mine Countermeasures (AMCM) Program Element (PE) previously provided resources to develop advanced Mine Countermeasures (MCM) systems, which are now in production. It currently funds post mission analysis (PMA) software, Mine Warfare Tactics and tactics training for mine warfare operations, and post mission analysis proficiency training. The MCM systems provide mobile, quick reaction forces capable of land or sea-based minehunting and mines countermeasures operations worldwide. Resources are for developing and deploying advanced mine-sweeping systems and the intelligence and oceanographic capabilities that will enable mine warfare superiority. Tactics and techniques used vary across a diversity of environments and threats, including both asymmetric and emerging. Resources provide for systems and support of mine warfare systems and expeditionary systems to allow for continuous operations of the Navy's warships and support vessels, other military vessels, and commercial vessels. Core capabilities include forward presence, deterrence, sea control, power projection, maritime security, humanitarian assistance and disaster response to maintain freedom of the seas. Capability improvements include: reducing post-mission analysis time; reducing detect, classify, and identify decision time; improving neutralization time; improving network communications; automatic target recognition; adding additional sensor PMA capability to provide a common PMA system, and achieving detect-to-engage capability. Concept-of-operations include development of cooperative, modular systems with a common post mission analysis system providing advanced tools to automate the complex problem of contact management for the thousands of recorded detections and the establishment of capable networked command and control systems. Efforts benefit the MCM force by transforming the Navy from the platform-centered legacy set of systems to a capability-centered force that is distributed, networked, and able to provide unique maritime influence and access across the entire maritime domain. The Airborne Mine Countermeasures (AMCM) programs will provide detection, classification, localization, identification, neutralization, influence sweep, and post mission analysis capabilities. This capability will be of critical importance in littoral zones, confined straits, choke points, and the Amphibious Objective Area (AOA). Project 4026 Net-Centric Sensor Analysis for Mine Warfare (NSAM) also includes the Mine Warfare Tactics project. NSAM is the next generation post mission analysis (PMA) system which replaced the legacy Organic Post Mission Analysis (OPMA) system. NSAM will be the single tactical and environmental PMA system for all Mine Warfare (MIW) sensor data and will provide integrated contact management capabilities. NSAM creates a collaborative, multi-data set, multi-user environment with the goal of reducing the mission timeline and increasing mission effectiveness. NSAM is designed with an extensible architecture to ease integration of additional sensors and integrate generalized Automatic Target Recognition (GATR) advanced algorithms including incorporation of artificial intelligence capabilities to reduce the time and burden of target recognition during mission analysis on the warfighter. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                             Date: April 2026 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 5: System             PE 0604373N / Airborne Mine Countermeasures Development & Demonstration (SDD) The Mine Warfare Tactics project develops tactics at the MIW Staff and MCM Scenario level. Project provides new MIW tactics theory and Fleet tactics training for MIW Staffs. Theory and tactics are documented and published into doctrine for Fleet users. Project 9179, Surface Navy Integrated Undersea Tactical Technology (SNIUTT) is a software training tool which provides contact recognition training modules for Mine Countermeasures (MCM) sensor systems and runs on existing PMA and training systems.$$, $$Budget J-Books/FY27/Navy/RDTEN_BA5_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604378N$$, $$Nav Integrated Fire Control - Counter Air Sys E$$, $$rdte_navy_ba5$$, $$asn_rda$$, 2026, 39878000, 78061000, 41419000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "navy", "page_num": 33, "original_pe": "0604378N", "page_header": "Department of the Navy"}$$::jsonb, $$PU 2757 All domain Long Range Networked Fires (LRNF) is a cross organizational Systems Engineering, Integration and Test (SEIT) project to coordinate and align the acquisition enterprise for the delivery of effective and interoperable long range kill chains. This effort will coordinate development and validation of all kill chain components across key enabler programs that include sensors, networks, transport architectures, radios, weapons, platforms, and combat systems across warfighting domains. The project will include joint architecture and Battle Management Command and Control (BMC2) development and maturation, including integration of the key enabler programs to optimize current and emerging capabilities across Navy and other mission partners. Development and execution of the LRNF integrated System of Systems (SoS) acquisition approach will prioritize nearer term fielding of effective capabilities, while continuing to mature solutions and informing investments across the portfolio. 3159 Naval Integrated Fire Control (NIFC) SEI&T project is a systems engineering effort to extend the Naval Integrated Air and Missile Defense battlespace out to the maximum kinematic range of our weapons for the air, surface, and strike warfare missions. This includes targets beyond the detection range of the shooter. The NIFC project exploits capabilities inherent in existing systems, optimizes current and emerging technologies in component system upgrades, integrates them together, and performs kill chain tests, forming an interoperable System of Systems (SoS) to maximize future defense capabilities. As directed by OPNAV, the project is focused on SEI&T efforts to integrate the From The Sea (FTS) family of kill chains which includes an elevated sensor, platform, fire control system, and missile, along with introducing other networks and sensors coordinating with other DOD activities as appropriate. Along with executing NIFC Inc 2 developmental test & fielding the SEIT supports the design of the current kill chain and system configuration and architectures. Future NIFC efforts (e.g. NIFC Inc 3) includes SEIT activities across a broad range of systems and architectures. 3242 Naval Integrated Fire Control (NIFC) From the Air (FTA) SEI&T project is a systems engineering effort to integrate NIFC FTA capabilities within "Pillar Programs" (F/A-18 & EA-18G, E-2D, F-35, Link-16 and Tactical Targeting Network Technology Data Links, and all USN air launched Air-to-Air and Air-to-Surface weapons). Based on the advancing threat, there remains an imperative to improve lethality, survivability and interoperability by extending the battlespace out to the Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Navy                                                                             Date: June 2025 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 5: System             PE 0604378N / Nav Integrated Fire Control - Counter Air Sys E Development & Demonstration (SDD) maximum kinematic range of our weapons for the air, surface, and strike warfare missions. The NIFC FTA project leverages capabilities inherent in existing systems, optimizes current and emerging technologies in platform system upgrades, and integrates them together to form interoperable System of Systems (SoS) to maximize offensive and defensive FTA integrated capabilities. As directed from OPNAV, the project is focused on development of Air Warfare, Surface Warfare, and Strike Warfare FTA effects chains. This PU will support efforts that include decomposing SoS requirements into Mission Technical Baselines (MTBs) and Integrated Capability Technical Baselines (ICTBs) for requirement allocation to Pillar Programs. Additionally, this PU will support NIFC pillar program coordination to provide performance predictions, performance assessments, and SoS risk reduction activities through Live, Virtual, and Constructive (LVC) events, SoS exercises, and development of Requirements Test and Verification Matrices (RTVMs) to support Developmental and Operational Test for the individual platforms. In lieu of a traditional Test and Evaluation Master Plan (TEMP), NIFC FTA test strategies will be developed to identify resources required to evaluate NIFC FTA capabilities, and describe how NIFC FTA capabilities will be evaluated prior to fleet delivery. JUSTIFICATION FOR BUDGET ACTIVITY: This program is funded under SYSTEM DEVELOPMENT AND DEMONSTRATION because it includes those projects that have passed Milestone B approval and are conducting engineering and manufacturing development tasks aimed at meeting validated requirement prior to full-rate production decision.$$, NULL, 40171000, 39393000, 39322000, NULL, NULL, 133, $$RDTEN_BA5_Book.pdf$$, NULL, FALSE, 40618000, 39878000, 42177000, 42177000, NULL, 42177000, 40082000, $$3159 Naval Integrated Fire Control (NIFC) SEI&T project is a systems engineering effort to extend the Naval Integrated Air and Missile Defense battlespace out to the maximum kinematic range of our weapons for the air, surface, and strike warfare missions. This includes targets beyond the detection range of the shooter. The NIFC project exploits capabilities inherent in existing systems, optimizes current and emerging technologies in component system upgrades, integrates them together, and performs kill chain tests, forming an interoperable System of Systems (SoS) to maximize future defense capabilities. As directed by OPNAV, the project is focused on SEI&T efforts to integrate the From The Sea (FTS) family of kill chains which includes an elevated sensor, platform, fire control system, and missile, along with introducing other networks and sensors coordinating with other DOW activities as appropriate. Along with executing NIFC Inc 2 developmental test & fielding the SEIT supports the design of the current kill chain and system configuration and architectures. Future NIFC efforts (e.g. NIFC Inc 3) includes SEIT activities across a broad range of systems and architectures. 3242 Naval Integrated Fire Control (NIFC) From the Air (FTA) SEI&T project is a systems engineering effort to integrate NIFC FTA capabilities within "Pillar Programs" (F/A-18 & EA-18G, E-2D, F-35, Link-16 and Tactical Targeting Network Technology Data Links, and all USN air launched Air-to-Air and Air-to-Surface weapons). Based on the advancing threat, there remains an imperative to improve lethality, survivability and interoperability by extending the battlespace out to the maximum kinematic range of our weapons for the air, surface, and strike warfare missions. The NIFC FTA project leverages capabilities inherent in existing systems, optimizes current and emerging technologies in platform system upgrades, and integrates them together to form interoperable System of Systems (SoS) to maximize offensive and defensive FTA integrated capabilities. As directed from OPNAV, the project is focused on development of Air Warfare, Surface Warfare, and Strike Warfare FTA effects chains. This PU will support efforts that include decomposing SoS requirements into Mission Technical Baselines (MTBs) and Integrated Capability Technical Baselines (ICTBs) for requirement allocation to Pillar Programs. Additionally, this PU will support NIFC pillar program coordination to provide performance predictions, performance assessments, and SoS risk reduction activities through Live, Virtual, and Constructive (LVC) events, SoS exercises, and development of Requirements Test and Verification Matrices (RTVMs) to support Developmental and Operational Test for the individual platforms. In lieu of a traditional Test and Evaluation Master Plan (TEMP), NIFC FTA test strategies will be developed to identify resources required to evaluate NIFC FTA capabilities, and describe how NIFC FTA capabilities will be evaluated prior to fleet delivery. JUSTIFICATION FOR BUDGET ACTIVITY: This program is funded under SYSTEM DEVELOPMENT AND DEMONSTRATION because it includes those projects that have passed Milestone B approval and are conducting engineering and manufacturing development tasks aimed at meeting validated requirement prior to full-rate production decision. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                         Date: April 2026 Appropriation/Budget Activity                                               R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 5: System         PE 0604378N / Nav Integrated Fire Control - Counter Air Sys E Development & Demonstration (SDD)$$, $$Budget J-Books/FY27/Navy/RDTEN_BA5_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604384BP$$, $$Chemical and Biological Defense Program - EMD$$, $$rdte_dw_ba5$$, $$dw_cbdp$$, 2026, 255630000, 331879000, 257725000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "dw", "page_num": 74, "original_pe": "0604384BP", "page_header": "Defense-Wide"}$$::jsonb, NULL, NULL, 255622000, 207843000, 188595000, NULL, NULL, NULL, NULL, NULL, FALSE, 251407000, 231539000, 261947000, 261947000, 0, 261947000, 190798000, $$This program element (PE) resources System Development & Demonstration across the Understand, Protect, Mitigate, and Enabling Investments portfolios. Chemical and Biological Defense Program (CBDP) investments provide an integrated, layered capability to enable Department of War (DoW) missions in a chemical and biological environment, ranging from combat operations to domestic incident prevention and response. The projects in this PE support the development, build, and test of products to verify that all operational and derived requirements have been met and to support production or deployment decisions. The activities include mature system development, integration, and demonstration to support Milestone C decisions, and conducting operational tests and evaluation of production representative articles. FY 2027 funding accelerates characterization and situational awareness of emerging biothreats and accelerates delivery of improved protection from and mitigation of biothreats, including rapid repurposing of available therapeutics and development of new vaccines. Individual Projects include: - Understand (UN5): Provides the Joint Force the ability to detect and identify hazards from traditional and emerging chemical and biological threats to improve the timeliness and confidence of information for decision-makers. Supports freedom of maneuver and informs commanders' decisions by predicting, locating, identifying, analyzing, and warning of chemical and biological (CB) hazards. - Protect (PT5): Provides the Joint Force the ability to prevent the effects of exposure to chemical and biological hazards. Protects personnel against chemical and biological liquid, vapor, and aerosol hazards through next-generation prototypes of masks, filters, and ensembles to reduce physiological, psychological, and logistical burdens to the warfighter. Medical countermeasure efforts conducted during this phase include the development of a large-scale manufacturing process and validation of that process, nonclinical studies, demonstration of manufacturing consistency, and expanded clinical human safety studies. Focuses on platform-based approaches to accelerate the development of prophylactic medical countermeasures that rapidly and durably protect against Biological Warfare Agents (BWAs), toxins, non- traditional and emerging chemical threats with minimal doses. The results of these efforts will be used to submit a Biologics License Application (BLA) to the U.S. Food & Drug Administration (FDA) for product licensure. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Chemical and Biological Defense Program                                              Date: April 2026 Appropriation/Budget Activity                                                        R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 5:                 PE 0604384BP / Chemical and Biological Defense Program - EMD System Development & Demonstration (SDD) - Mitigate (MT5): Preserves combat power by mitigating exposure to CB hazards and restoring combat readiness of critical personnel and platforms. Enables Joint Force lethality by providing capabilities for warfighters to rapidly respond to and mitigate the adverse effects of CB hazards. Fields mitigation capabilities against engineered biological agents, opioids and other Pharmaceutical-Based Agents, and Fourth Generation Agents (FGAs). - Enabling Investments (EN5): Provides fundamental knowledge and technology demonstrations as key portfolio enablers integral to responding to emerging threats. Dedicated funding for this Project supports National and Departmental incident response and preparedness regarding CB threats. The total cost of the Next Generation Individual Protection (NG IP) Middle Tier of Acquisition effort is $308.6 million, including RDT&E and procurement of prototype units. The NG IP is fully funded across the Future Years Defense Program.$$, $$Budget J-Books/FY27/DW/RDTE_CBDP_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604386A$$, $$Biotechnology for Materials - Dem/Val$$, $$rdte_army_ba4$$, $$asa_alt$$, 2026, 0, 0, 10651000, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "army", "page_num": 15, "fy26_v180": {"note": "R1_FY26_entry_no_value_extracted_in_original_ingest", "source": "b1_null_zero_v180"}, "original_pe": "0604386A", "page_header": "Department of the Army"}$$::jsonb, $$This Project will create a pipeline to down-select promising biotechnology capabilities towards fielded novel solutions for warfighter needs by enabling prototyping at an efficiency and speed greater than is currently possible, through integration of "cutting-edge" instrumentation and robotics in laboratory and armament/warfare centers/ depots testing & evaluation systems. T-BRSC will deliver biotechnology advanced evaluations that exhibit Defense supply chain resiliency by providing alternative means of sourcing critical materials (e.g. jet fuel precursors, energetic precursors, lubricants, epoxies, anti-fouling compounds, recovery of rare earth elements) for transition into service acquisition programs. T-BRSC's comprehensive DoD investment strategy will develop the necessary biotechnology pipeline from demonstration and prototyping to manufacture and fielding, to reduce the risk of technological overmatch by adversaries and enable U.S. military and national security objectives for the future. This will provide Supply Chain Resiliency to the U.S. military, while enabling U.S. industry to support military and national security objectives, as well as de- risking cross-cutting and dual-use technologies necessary to drive commercialization and promote the U.S. Bioeconomy to compete with adversaries. Work in this Project complements PE 0603386A (Biotechnology for Materials - Advanced Research) / CP7 (Biotechnology Demonstration and Evaluation). The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army Modernization Strategy. Work in this Project is performed by Assistant Secretary of the Army for Acquisition, Logistics and Technology and the Army Research, Development, Test and Evaluation (RDT&E) Enterprise.$$, NULL, NULL, NULL, NULL, NULL, NULL, 94, $$RDTE - Vol 2 - Budget Activity 4B.pdf$$, NULL, FALSE, 10262000, 0, NULL, NULL, NULL, NULL, NULL, $$This Project will create a pipeline to down-select promising biotechnology capabilities towards fielded novel solutions for warfighter needs by enabling prototyping at an efficiency and speed greater than is currently possible, through integration of "cutting-edge" instrumentation and robotics in laboratory and armament/warfare centers/ depots testing & evaluation systems. T-BRSC will deliver biotechnology advanced evaluations that exhibit Defense supply chain resiliency by providing alternative means of sourcing critical materials (e.g. jet fuel precursors, energetic precursors, lubricants, epoxies, anti-fouling compounds, recovery of rare earth elements) for transition into service acquisition programs. T-BRSC's comprehensive DoW investment strategy will develop the necessary biotechnology pipeline from demonstration and prototyping to manufacture and fielding, to reduce the risk of technological overmatch by adversaries and enable U.S. military and national security objectives for the future. This will provide Supply Chain Resiliency to the U.S. military, while enabling U.S. industry to support military and national security objectives, as well as de- risking cross-cutting and dual-use technologies necessary to drive commercialization and promote the U.S. Bioeconomy to compete with adversaries. Work in this Project complements PE 0603386A (Biotechnology for Materials - Advanced Research) / CP7 (Biotechnology Demonstration and Evaluation). The cited work is consistent with the Under Secretary of War for Research and Engineering priority focus areas and the Army Modernization Strategy. Work in this Project is performed by Assistant Secretary of the Army for Acquisition, Logistics and Technology and the Army Research, Development, Test and Evaluation (RDT&E) Enterprise.$$, $$Budget J-Books/FY27/Army/RDTE - Vol 2 - Budget Activity 4B.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604400D8Z$$, $$Department of Defense (DoD) Unmanned Systems Common Develo$$, $$rdte_dw_ba4$$, $$dw_ousd_as$$, 2026, 2142000, 41338000, 9527000, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "dw", "page_num": 72, "fy27_mand_k": 34627, "original_pe": "0604400D8Z", "page_header": "Defense-Wide", "fy27_mand_v157": "2026-05-08", "fy26_v182_disc_K": 11971, "fy26_v182_supp_K": 1000000, "fy27_mand_source": "DoW_FY2027_Mandatory_Funding_Overview.txt Appendix B", "fy26_v182_total_K": 1011971, "fy27_mand_section": "Defense Industrial Base", "fy26_v182_note_name": "Department of War (DoW) Unmanned Systems Common Development", "fy26_v182_source_file": "RDTE_OSW_PB_2027.txt", "fy26_v182_source_line": 26760}$$::jsonb, $$The Department of Defense (DoD) Unmanned System Common Development Program allows the Office of the Under Secretary of Defense for Acquisition and Sustainment (OUSD(A&S)) to support both the near-term and long-term advancement of DoD unmanned systems capabilities. This includes the development of common technologies, standards, concepts, and guidance that can be applied across all Military Services. Currently, this effort is primarily focused on the development of technologies and concepts that support the operation of DoD Small Unmanned Aerial System (UAS) both in the U.S. National Airspace and in an expeditionary environment. While the initial focus is on Small UAS, supporting unmanned systems of all sizes and modalities is the long-term goal. Key aspects of the initial Small UAS effort include (1) making available unmanned systems and components for DoD procurement and operation that are safe, secure, interoperable, and effective on the modern battle field, (2) facilitating access and integration of unmanned systems into military and civilian environments in a safe and effective manner, and (3) establishing and overseeing coordination, agreements, guidance, and standards that enable the DoD’s operation of unmanned systems in military and civilian environments. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Office of the Secretary Of Defense                                               Date: June 2025 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 4:           PE 0604400D8Z / Department of Defense (DoD) Unmanned Systems Common Develo Advanced Component Development & Prototypes (ACD&P)                            pment$$, NULL, 1922000, 1927000, 2190000, NULL, NULL, 112, $$RDTE_OSD_PB_2026.pdf$$, $$OSD$$, FALSE, 9178000, 1011971000, 2024000, 2024000, 34627000, 36651000, 2233000, $$FY 2027 request for Department of War (DoW) Unmanned Systems Common Development includes $2,024 thousands of discretionary and $34,627 thousands of mandatory for a total of $36.651 thousand. The mandatory funds will provide additional support for Unmanned Systems Development, Integration, and Integration Support missions, allowing OUSW(A&S) to implement the Acquisition Transformation Strategy for unmanned systems across the department. Funds will also support the blue list marketplace that supports industries in development of UAS systems and warfighter procurement of secure systems. The FY 2027 funds are different from the FY 2026 mandatory funds that support continued development of multiple unmanned air systems, Task Force Baker operationalization activities, and test range and target costs. Results from these development efforts drive appropriate LRIP decisions as platform designs are iterated. These funds are executed in close coordination with service POR strategies and budgets. The FY 2026 spend plan amount for Department of War (DoW) Unmanned Systems Common Development includes $11,971 thousands of discretionary and $1,000,000 thousands of mandatory (reconciliation) for a total of $1,011,971 thousands. This program supports the Department's initiatives to Restoring Warrior Ethos, Rebuilding Military Capabilities and Re-establishing Deterrence. The Department of War (DoW) Unmanned System Common Development Program allows the Office of the Under Secretary of War for Acquisition and Sustainment (OUSW(A&S)) to support both the near-term and long-term advancement of DoW unmanned systems capabilities. These efforts are in direct support of both the letter and the intent of the following directives (1) Executive Order 14307 on Unleashing Drone Dominance signed on June 6, 2025 to enhance the capabilities of U.S. warfighters and support the American drone industry and (2) the Secretary of War memorandum on Unleashing Drone Dominance signed on July 10, 2025 to rebuild our military Unmanned Aerial Systems capabilities. This includes the development of common technologies, standards, concepts, and guidance that can be applied across all Military Services. This effort focuses on the development of technologies and concepts that support unmanned systems of all sizes and modalities to include the operation of DoW Small Unmanned Aerial Systems (UAS) both in the U.S. National Airspace and in an expeditionary environment. Key aspects of this effort includes (1) Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Office of the Secretary Of Defense                                                Date: April 2026 Appropriation/Budget Activity                                                     R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 4:              PE 0604400D8Z / Department of Defense (DoD) Unmanned Systems Common Develo Advanced Component Development & Prototypes (ACD&P)                               pment making available unmanned systems and components for DoW procurement and operation that are safe, secure, interoperable, and effective on the modern battle field, (2) facilitating access and integration of unmanned systems into military and civilian environments in a safe and effective manner, and (3) establishing and overseeing coordination, agreements, guidance, and standards that enable the DoW’s operation of unmanned systems in military and civilian environments.$$, $$Budget J-Books/FY27/Remaining/DoW_FY2027_Mandatory_Funding_Overview.txt$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604403A$$, $$Future Interceptor$$, $$rdte_army_ba4$$, $$asa_alt$$, 2026, 152019000, 3899000, 8058000, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "army", "page_num": 15, "fy26_v180": {"note": "R1_FY26_entry_no_value_extracted_in_original_ingest", "source": "b1_null_zero_v180"}, "original_pe": "0604403A", "page_header": "Department of the Army"}$$::jsonb, $$This funding line is directly aligned to the Army Air and Missile Defense Modernization Priority. The Future Interceptor will defend against current and emerging air, missile, and hypersonic threats in the lower tier of the ballistic missile defense battlespace. The Future Interceptor increases Air and Missile Defense (AMD) capability through improved velocity, altitude, and maneuverability characteristics. Requested funding continues Virtual Missile Model (VMM) development to support and establish concept definitions. Products from the Future Interceptor concept definitions phase supports advanced technology efforts for maturation that may be implemented in the Future Interceptor. The FY 2026 request for Future Interceptor includes $8,019 thousand of discretionary and $144,000 thousand of mandatory (reconciliation) for a total of $152,019 thousand. The mandatory funds execute competitive contracts with industry to begin capability maturation to achieve a Total Effector Rapid Prototyping to deliver to the Warfighter in the shortest time possible. Number of competitive contracts will be determined by responses received to RFI for interest in Future Interceptor development. Further information for this reconciliation request is provided in Section 20003 of the Reconciliation Exhibit. The FY 2026 request for Future Interceptor includes $8,019 thousand of discretionary and $144,000 thousand of mandatory (reconciliation) for a total of $152,019 thousand. The mandatory funds execute competitive contracts with industry to begin capability maturation to achieve a Total Effector Rapid Prototyping to deliver to the Warfighter in the shortest time possible. Number of competitive contracts will be determined by responses received to RFI for interest in Future Interceptor development. Further information for this reconciliation request is provided in Section 20003 (Missile Defense) of the Reconciliation Exhibit. The FY 2026 request was reduced by $0.015 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative." Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                               Date: June 2025 Appropriation/Budget Activity                                             R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 4: Advanced     PE 0604403A / Future Interceptor Component Development & Prototypes (ACD&P)$$, NULL, 332769000, 431053000, 470055000, NULL, NULL, 95, $$RDTE - Vol 2 - Budget Activity 4B.pdf$$, NULL, FALSE, 7764000, 0, NULL, NULL, NULL, NULL, 475291000, $$This funding line is directly aligned to the Army Air and Missile Defense Modernization Priority. The Future Interceptor will defend against current and emerging missile, and hypersonic threats in the ballistic missile defense battlespace. The Future Interceptor increases Air and Missile Defense (AMD) capability through improved velocity, altitude, and maneuverability characteristics. Requested funding will be used to continue hardware/software design and development and procurement of parts of qualified vendors to begin building and testing of critical component prototypes.$$, $$Budget J-Books/FY27/Army/RDTE - Vol 2 - Budget Activity 4B.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604414F$$, $$Cyber Resiliency of Weapon Systems-ACS$$, $$rdte_af_ba4$$, $$afrl_ri$$, 2026, 46148000, 35712000, 45555000, NULL, $${"ba_raw": "6.4", "source": "af_r1_fy26", "original_pe": "0604414F"}$$::jsonb, $$This program funds activities at the Cyber Resiliency Office for Weapon Systems (CROWS). The CROWS is the sole organization tasked to enhance and enable Department of the Air Force (DAF) Program Executive Office (PEOs) and Program Management Offices (PMOs) to understand, engineer, and integrate cyber resiliency into emerging and fielded weapon systems to mitigate critical cyber-based vulnerabilities and preserve mission effectiveness in contested environments. The CROWS' mission directly aligns with the National Defense Strategy (NDS).The NDS specifically emphasizes integrated deterrence as vital to safeguarding U.S. national interests from aggression and strategic attacks by building a resilient, survivable Joint Force in the cyber domain, which requires the Department of Defense to prioritize investments in cyber defense, resilience, and the continued integration of cyber capabilities into the full spectrum of military operations. This program addresses weapon system cyber resiliency through two primary activities. The first activity is to develop systems security engineering tools, techniques, and procedures, with associated training and education, to integrate cyber expertise into the acquisition workforce. Notably this includes embedding knowledgeable personnel - aka Cyber Focus Teams - within DAF PEOs and PMOs,and equipping them with expertise and resources to enhance the cyber posture of DAF weapon systems. This activity also includes funding capabilities to enable effective sharing of classified cyber intelligence and vulnerability information across multiple acquisition programs, identifying technologies, tactics, and policies for further development, prototyping, and operational exercises to posture DAF weapon systems to counter emerging threats. Furthermore, this activity includes organization and analysis of the DAF's cyber risk and mitigations landscape to inform senior leaders and investment strategies. The second activity enables the CROWS to centralize and consolidate DAF and Department of Defense acquisition cyber needs and conduct threat-informed weapon systems solution analysis, identify and prioritize vulnerabilities, and deliver courses of action to mature the material and non-material solutions for mitigated vulnerabilities. This effort is in Budget Activity 4, Advanced Component Development and Prototypes (ACD&P), because efforts are necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                        Date: June 2025 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 4: Advanced PE 0604414F / Cyber Resiliency of Weapon Systems-ACS Component Development & Prototypes (ACD&P)$$, NULL, 43548000, 51790000, 51899000, NULL, NULL, 55, $$FY26 Air Force Research and Development Test and Evaluation Vol II.pdf$$, NULL, FALSE, 44191000, 45642000, 44377000, 44377000, 0, 44377000, 52266000, $$This program funds activities at the Cyber Resiliency Office for Weapon Systems (CROWS). The CROWS is the sole organization tasked to enhance and enable Department of the Air Force (DAF) Program Acquisition Executives (PAEs) and Program Management Offices (PMOs) to understand, engineer, and integrate cyber resiliency into emerging and fielded weapon systems, to mitigate critical cyber-based vulnerabilities, and preserve mission effectiveness in contested environments. The CROWS' mission directly aligns with the National Defense Strategy (NDS). The NDS specifically emphasizes deterring and defending against cyber threats as vital to safeguarding the U.S. homeland and military from aggression and strategic attacks by building a resilient, survivable Joint Force in the cyber domain, which requires the Department of War to prioritize investments in cyber defense, resilience, and the continued integration of cyber capabilities into the full spectrum of military operations. This program addresses weapon system cyber resiliency through several system security engineering focused activities. A notable activity is to develop systems security engineering tools, techniques, and procedures, with associated training and education, to integrate cyber expertise into the acquisition workforce. This includes embedding knowledgeable personnel - aka Cyber Focus Teams - within DAF PAE Offices and PMOs, and equipping them with expertise and resources to enhance the cyber posture of DAF weapon systems. The activity also includes funding capabilities to enable effective sharing of classified cyber intelligence and vulnerability information across multiple acquisition programs, identifying technologies, tactics, and policies for further development, prototyping, and supporting operational exercises to posture DAF weapon systems to counter emerging threats. Furthermore, this activity includes organization and analysis of the DAF's cyber risk and mitigations landscape to equip senior leaders with the most up to date knowledge of force posture and inform investment strategies. Another noteworthy activity enables the CROWS to centralize and consolidate DAF and Department of War acquisition cyber needs and conduct threat-informed weapon systems solution analysis, identify and prioritize vulnerabilities, and deliver courses of action to mature the materiel and non-materiel solutions for mitigated vulnerabilities. In FY 2027, the entirety of project 642834, Mitigations, was transferred to project 642812, Acquisitions/System Security Engineering. This is an administrative realignment to better highlight the synergy between the two activities and does not represent an increase or decrease in priority relative to the overall program. This program element included all necessary expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 0605829F, 0605831F, 0605833F, and 0605898F. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                     Date: April 2026 Appropriation/Budget Activity                                                     R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 4: Advanced PE 0604414F / Cyber Resiliency of Weapon Systems-ACS Component Development & Prototypes (ACD&P) This effort is in Budget Activity 4, Advanced Component Development and Prototypes (ACD&P), because efforts are necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment.$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume II.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604419N$$, $$Advanced Sensors Application Program$$, $$rdte_navy_ba5$$, $$asn_rda$$, 2026, 0, 10000000, 0, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "navy", "page_num": 33, "original_pe": "0604419N", "page_header": "Department of the Navy"}$$::jsonb, $$The details of this program element are classified SECRET and are submitted annually to Congress in the classified budget justification books.$$, NULL, NULL, NULL, NULL, NULL, NULL, 134, $$RDTEN_BA5_Book.pdf$$, NULL, FALSE, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604445F$$, $$Wide Area Surveillance$$, $$rdte_af_ba7$$, $$aflcmc$$, 2026, 0, 9269000, 21443000, NULL, $${"ba_raw": "6.7", "source": "af_r1_fy26", "original_pe": "0604445F"}$$::jsonb, $$Wide Area Surveillance (WAS) consists of two advanced sensor systems, the Stateside Affordable Radar System (STARS) and Scorpion. Based on existing technological capabilities, WAS detects/tracks low, slow and other asymmetrical threats in the airspace and meets the user needs by sensing airborne targets in complex environments with affordable sensors. The sensor outputs will be incorporated into the Battle Control Systems-Fixed (BCS-F) air picture and utilized as the North American Aerospace Defense Command/ Northern Command (NORAD/NORTHCOM) Command and Control (C2) air surveillance system of record. Some aspects of the WAS program are classified and will be provided on a need-to-know basis. This program element may include necessary civilian pay expenses required to manage, execute, and deliver Wide Area Surveillance capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY24 $0.000 million was expended for civilian pay expenses in this program element, and in FY25 $0.000 million is forecasted for civilian pay expenses in this program element. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, NULL, 0, 0, 0, NULL, NULL, 151, $$FY26 Air Force Research and Development Test and Evaluation Vol III.pdf$$, NULL, FALSE, 20722000, 0, 0, 0, 0, 0, 0, $$Wide Area Surveillance (WAS) consists of three advanced sensor systems, the Stateside Affordable Radar System (STARS), Scorpion, and Affordable Long Range Persistent Systems (ALPS). Based on existing technological capabilities, WAS detects/tracks low, slow and other asymmetrical threats in the airspace and meets the user needs by sensing airborne targets in complex environments with affordable sensors. The sensor outputs will be incorporated into the Battle Control Systems-Fixed (BCS-F) air picture and utilized as the North American Aerospace Defense Command/ Northern Command (NORAD/NORTHCOM) Command and Control (C2) air surveillance system of record. Some aspects of the WAS program are classified and will be provided on a need-to-know basis. This program element included all necessary expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 0605829F, 0605831F, 0605833F, and 0605898F. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume III.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604454N$$, $$LX (R)$$, $$rdte_navy_ba4$$, $$peo_ships$$, 2026, 26709000, 21186000, 9767000, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "navy", "page_num": 30, "original_pe": "0604454N", "page_header": "Department of the Navy"}$$::jsonb, $$LPD 17 Flight II will replace LSD 41 Class ships and LSD 49 Class ships for embark, transport, control, insert, sustainment, and extract of Marine Air-Ground Task Force elements and supporting forces by helicopters, landing craft, and amphibious vehicles. This project includes efforts to reduce the cost of building and repairing ships, resolving obsolescence issues, and improving shipbuilding industry productivity through: advanced technology and processes with emphasis towards developing ship hull, mechanical, propulsion, electrical, aviation, warfare system, combat support system, sub-systems and components to maintain manpower, survivability, operational capabilities, and pursue affordability initiatives. This program element includes the planning & documentation for Developmental Test and Evaluation (DT&E), Live Fire Test & Evaluation (LFT&E), Operational Evaluation (OPEVAL), and Follow-on Operational Test and Evaluation (FOT&E) tests required for LPD 17 Flight II. These test events will be conducted on the lead Flight II Ship (LPD 30) or where configuration supports capabilities on earlier ships (LPD 28 or LPD 29). The test events will be conducted as needed on Flight II Follow Ship (LPD 31) for verification of correction of deficiencies (VCD) from the lead Flight II Ship (LPD 30). Per signed Acquisition Decision Memorandum, LPD 17 Flight II will meet the Capabilities Development Document for LX(R) and shall subsume all previous LX(R) efforts. Name change endorsed in JROCM 093-21, from "Amphibious Ship Replacement LX(R)" to "LPD 17 San Antonio Class Amphibious Transport Dock FLT II." LPD 30 is the first ship of LPD 17 Flight II.$$, NULL, 20720000, 14034000, 13151000, NULL, NULL, 90, $$RDTEN_BA4_Book.pdf$$, NULL, FALSE, 9677000, 26709000, 18574000, 18574000, NULL, 18574000, 13395000, $$LPD 17 Flight II will replace LSD 41 Class ships and LSD 49 Class ships for embark, transport, control, insert, sustainment, and extract of Marine Air-Ground Task Force elements and supporting forces by helicopters, landing craft, and amphibious vehicles. This project includes efforts to reduce the cost of building and repairing ships, resolving obsolescence issues, and improving shipbuilding industry productivity through: advanced technology and processes with emphasis towards developing ship hull, mechanical, propulsion, electrical, aviation, warfare system, combat support system, sub-systems and components to maintain manpower, survivability, operational capabilities, and pursue affordability initiatives. This program element includes the planning & documentation for Developmental Test and Evaluation (DT&E), Live Fire Test & Evaluation (LFT&E), Operational Evaluation (OPEVAL), and Follow-on Operational Test and Evaluation (FOT&E) tests required for LPD 17 Flight II. These test events will be conducted on the lead Flight II Ship (LPD 30) or where configuration supports capabilities on LPD 29. The test events will be conducted as needed on Flight II follow ships (LPD 31/32) for verification of correction of deficiencies (VCD) from the lead Flight II Ship (LPD 30) as well as design/system changes. Per signed Acquisition Decision Memorandum, LPD 17 Flight II will meet the Capabilities Development Document for LX(R) and shall subsume all previous LX(R) efforts. Name change endorsed in JROCM 093-21, from "Amphibious Ship Replacement LX(R)" to "LPD 17 San Antonio Class Amphibious Transport Dock FLT II." LPD 30 is the first ship of LPD 17 Flight II.$$, $$Budget J-Books/FY27/Navy/RDTEN_BA4_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604501N$$, $$Advanced Above Water Sensors$$, $$rdte_navy_ba5$$, $$peo_ships$$, 2026, 67881000, 106609000, 112231000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "navy", "page_num": 33, "original_pe": "0604501N", "page_header": "Department of the Navy"}$$::jsonb, $$Multi-Mission Signal Processor (MMSP): The development of MMSP provides simultaneous Anti-Air Warfare (AAW)/Ballistic Missile Defense (BMD) multi-mission capability for DDG 51 class ships as part of the Aegis Modernization Program. This capability is utilized for DDG 113 and follow new construction and Aegis Ashore. Modifies SPY-1D transmitters to enable dual beam for reduced frame times and better reaction time, provides stability for all D(V) waveforms, and avoids operational degradation. The SPY-1 radar system detects, tracks, and supports engagements of a broader range of threats. MMSP improves performance in littoral, ducted clutter, electronic attack (EA), and chaff environments and provides greater commonality in computer programs and equipment. This effort also provides for the development of MMSP on Destroyers Commercial Off The Shelf (COTS) refresh and MMSP technology refresh. MMSP/AEGIS Linear Processing System (ALPS) integration provides adjunct processing for data collection. Starting in FY25, funding has been realigned within PE 0604501N from PU 3232 to 3301 to gain contractual efficiencies and program flexibility. Shipboard Passive Electro-Optical/ Infrared (SPEIR) Block I provide surface ships a common 360-degree EO/IR Electronic Support (ES) capability that will passively find, fix, track, and target current/emerging threats in support of the following warfare missions: Anti-Ship Cruise Missile (ASCM) Defense, Counter-Unmanned Aircraft Systems (UAS), Counter-Fast Attack Craft / Fast Inshore Attack Craft (FAC/FIAC), and Mobility. SPEIR Block I will consist of a passive Wide Field of View (WFOV) capability with a persistent 360-degree field-of-view optical sensors for autonomous detection and tracking for 24/7 situational awareness. SPEIR Block I will also include an enhanced, high-resolution Narrow-Medium Field of View (NFOV) and laser range-finding capability to provide 3D target tracking, identification, and threat assessment. SPEIR Block II will be a future program that will build on the modular open systems architecture of Block I with an expanded spatial coverage envelope and will add the capability for Periscope Detection and Discrimination (PDD), Mine Like Object (MLO) avoidance, networked operations, and full integration with the Future Integrated Combat System. Status of SPEIR Block I Major Milestones: Milestone B completed 3QFY22, procurement of Low Rate Initial Production (LRIP) Lot 1 Long Lead Material (LLM) (2QFY25), and Milestone C LRIP (2QFY26). Improved Capabilities for SPY-1 Radar: These Reliability, Maintainability, and Availability (RM&A) improvements and solid state technology insertions are intended to reduce cascading failures, mitigate obsolescence issues, and improve reliability in support of Anti-Air Warfare (AAW) and Ballistic Missile Defense (BMD) missions while still providing AN/ SPY-1 Radar Total Ownership Cost Reductions. Improvements, such as Solid State Insertion to address Diminishing Manufacturing Sources Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Navy                                                                               Date: June 2025 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 5: System              PE 0604501N / Advanced Above Water Sensors Development & Demonstration (SDD) and Material Shortages (DMSMS), will yield reductions in annual fleet maintenance costs and is a top fleet requirement as part of the AEGIS Wholeness initiative. In addition to RM&A improvements, warfighting improvements funded in this line includes the following: Transmitter Noise Cancellation (TNC) development includes hardware/software to counter low radar cross section, low altitude threats. Side Lobe Blanking (SLB) addresses shortfalls in mixed electronic attack environment while in an Integrated Air and Missile Defense (IAMD) mode. The Ship-Based Non-Cooperative Target Recognition (SBNCTR) program Phase 2A will develop algorithms to provide classification for targets. Advanced Calibration Experiment (ACE) Phase 2 is being incorporated into Baseline 9. Elevated Radar Advanced Calibration Experiment (ERACE) Phases 1/2 and 3 will incorporate into Baseline 9. Electronic Attack (EA) and Rapid Radar Capability Improvement Program (R2CIP) develop solutions for evolving EA threats. The development of MMSP provides simultaneous Anti-Air Warfare (AAW)/Ballistic Missile Defense (BMD) multi-mission capability for DDG 51 class ships as part of the Aegis Modernization Program. This capability is utilized for DDG 113 and follow new construction and Aegis Ashore. Modifies SPY-1D transmitters to enable dual beam for reduced frame times and better reaction times, provides stability for all D(V) waveforms, and avoids operational degradation. The SPY-1 radar system detects, tracks, and supports engagements of a broader range of threats. MMSP improves performance in littoral, ducted clutter, electronic attack (EA), and chaff environments and provides greater commonality in computer programs and equipment. This effort also provides for the development of MMSP-Restoration (MMSP-R) to support system security requirements on Destroyers Commercial Off The Shelf (COTS) refresh and MMSP/MMSP-R technology refresh. The FY26 budget request continues the development efforts of ACE Phase 2, SBNCTR Phase 2A, TNC Phase 1/2, SLB Integration and Test (I&T), and EA improvements, and commences ERACE Phase 3. In addition, the FY26 budget request continues efforts realigned from PU 3232, AEGIS Capability Build (ACB) 16 Radar Requirements and Analysis and MMSP Technology Refresh/Diminishing Manufacturing Sources and Material Shortages (DMSMS) Solutions, continues ACB 16 COTS Refresh, MMSP Engineering Change Proposals (ECP) and software updates, and DMSMS Tech Solutions and completes Future Signal Processor (FSP) Analysis of Alternatives (AoA). MMSP-R includes software updates required on new computer platforms. Engineering efforts will be required to assess alternate technologies and determine optimal MMSP architectural solutions, which will include system security requirements. AN/SPS-49 Technology Refresh: FY22 was the last year of funding for this program. AN/SPS-49 is the only Air Surveillance Radar on the LSD 41/49 class ships. Continued degradation and increasingly low radar availability of the AN/SPS-49 Radar is greatly impacting deployed missions, impacting safety of flight and affecting LSD Air Warfare capability and operations and as a result, AN/SPS-49 Technology Refresh is required. This AN/,SPS-49 Technology Refresh will include Reliability, Maintainability, and Availability (RM&A) improvements and solid state technology insertions which will reduce cascading failures and mitigate obsolescence issues. In addition, this effort replaces key components to include: transmitter, receiver, exciter, antenna elevation servo control, radar system control, display and signal data processor (SDP). A digital receiver/exciter (DREX) with high-performance computing technology will be a key component in the new system. The current SPS-49 radar has no software so new software is being developed to mimic the current radar functions to maintain compatibility with internal and external interfaces. This effort will improve SPS-49 electronic protection, have increased surveillance range and increased slow moving small target detection, as well as reduce total ownership cost with lower unit cost and smaller size/weight/power requirements. Funding is also to complete development, test and evaluation, validation and integration of a technology refresh of the below deck hardware for the AN/ SPS-49A(V)1 Long Range Air Surveillance Radar. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Navy                                                                           Date: June 2025 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 5: System          PE 0604501N / Advanced Above Water Sensors Development & Demonstration (SDD)$$, NULL, 42906000, 41704000, 40862000, NULL, NULL, 135, $$RDTEN_BA5_Book.pdf$$, NULL, FALSE, 108585000, 67881000, 67900000, 67900000, NULL, 67900000, 41816000, $$Multi-Mission Signal Processor (MMSP): The development of MMSP provides simultaneous Anti-Air Warfare (AAW)/Ballistic Missile Defense (BMD) multi-mission capability for DDG 51 class ships as part of the Aegis Modernization Program. This capability is utilized for DDG 113 and follow new construction and Aegis Ashore. Modifies SPY-1D transmitters to enable dual beam for reduced frame times and better reaction time, provides stability for all D(V) waveforms, and avoids operational degradation. The SPY-1 radar system detects, tracks, and supports engagements of a broader range of threats. MMSP improves performance in littoral, ducted clutter, electronic attack (EA), and chaff environments and provides greater commonality in computer programs and equipment. This effort also provides for the development of MMSP on Destroyers Commercial Off The Shelf (COTS) refresh and MMSP technology refresh. MMSP/AEGIS Linear Processing System (ALPS) integration provides adjunct processing for data collection. Starting in FY25, funding has been realigned within PE 0604501N from PU 3232 to 3301 to gain contractual efficiencies and program flexibility. Shipboard Passive Electro-Optical/ Infrared (SPEIR) Block I provide surface ships a common 360-degree EO/IR Electronic Support (ES) capability that will passively find, fix, track, and target current/emerging threats in support of the following warfare missions: Anti-Ship Cruise Missile (ASCM) Defense, Counter-Unmanned Aircraft Systems (UAS), Counter-Fast Attack Craft / Fast Inshore Attack Craft (FAC/FIAC), and Mobility. SPEIR Block I will consist of a passive Wide Field of View (WFOV) capability with a persistent 360-degree field-of-view optical sensors for autonomous detection and tracking for 24/7 situational awareness. SPEIR Block I will also include an enhanced, high-resolution Narrow-Medium Field of View (NFOV) and laser range-finding capability to provide 3D target tracking, identification, and threat assessment. SPEIR Block II will be a future program that will build on the modular open systems architecture of Block I with an expanded spatial coverage envelope and will add the capability for Periscope Detection and Discrimination (PDD), Mine Like Object (MLO) avoidance, networked operations, and full integration with the Future Integrated Combat System. Status of SPEIR Block I Major Milestones: Milestone B completed 3QFY22, procurement of Low Rate Initial Production (LRIP) Lot 1 Long Lead Material (LLM) (2QFY25) and LRIP (3QFY26). The FY27 budget request supports software upgrades and the associated integration effort, and program testing. Scope also includes LRIP Delivery, training curriculum development, commencement of Land Based Testing and continuing the Engineering & Manufacturing Development phase. Additionally, the completion of Modeling and Simulation (M&S) development and maturation, and completion of SPEIR Test and Certification are also planned in FY27. FY26 to FY27 funding decreases are due to the ramp down of developmental activities. Efforts will also include development of capability to integrate SPEIR with the AEGIS Combat System. RDT&E costs are ramping down in FY27 as a result of completion of Integration & Development Test planning, the majority of core software development, EDM material procurements, and all three (3) EDMs are assembled and integrated to support the execution of developmental test events prior to program transition to the Production phase. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                               Date: April 2026 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 5: System             PE 0604501N / Advanced Above Water Sensors Development & Demonstration (SDD) Improved Capabilities for SPY-1 Radar: These Reliability, Maintainability, and Availability (RM&A) improvements and solid state technology insertions are intended to reduce cascading failures, mitigate obsolescence issues, and improve reliability in support of Anti-Air Warfare (AAW) and Ballistic Missile Defense (BMD) missions while still providing AN/ SPY-1 Radar Total Ownership Cost Reductions. Improvements, such as Solid State Insertion to address Diminishing Manufacturing Sources and Material Shortages (DMSMS), will yield reductions in annual fleet maintenance costs and is a top fleet requirement as part of the AEGIS Wholeness initiative. In addition to RM&A improvements, warfighting improvements funded in this line includes the following: Transmitter Noise Cancellation (TNC) development includes hardware/ software to counter low radar cross section, low altitude threats. The Ship-Based Non-Cooperative Target Recognition (SBNCTR) program Phase 2A will develop algorithms to provide classification for targets. Advanced Calibration Experiment (ACE) Phase 2 is being incorporated into Baseline 9. Elevated Radar Advanced Calibration Experiment (ERACE) Backfits and Phase 3 will incorporate into Baseline 9. Electronic Attack (EA) and Rapid Radar Capability Improvement Program (R2CIP) develop solutions for evolving EA threats. The development of MMSP provides simultaneous Anti-Air Warfare (AAW)/Ballistic Missile Defense (BMD) multi- mission capability for DDG 51 class ships as part of the Aegis Modernization Program. This capability is utilized for DDG 113 and follow new construction and Aegis Ashore. Modifies SPY-1D transmitters to enable dual beam for reduced frame times and better reaction times, provides stability for all D(V) waveforms, and avoids operational degradation. The SPY-1 radar system detects, tracks, and supports engagements of a broader range of threats. MMSP improves performance in littoral, ducted clutter, electronic attack (EA), and chaff environments and provides greater commonality in computer programs and equipment. This effort also provides for the development of MMSP-Restoration (MMSP-R) to support system security requirements on Destroyers Commercial Off The Shelf (COTS) refresh and MMSP/MMSP- R technology refresh. The FY27 budget request continues the development efforts of ACE Phase 2, SBNCTR Phase 2A, TNC Phase 1/2, EA improvements, ERACE Backfit, and ERACE Phase 3. In addition, the FY27 budget request continues efforts realigned from PU 3232, AEGIS Capability Build (ACB) 16 Radar Requirements and Analysis and MMSP Technology Refresh/Diminishing Manufacturing Sources and Material Shortages (DMSMS) Solutions, continues MMSP Engineering Change Proposals (ECP) and software updates, and MMSP Next Generation requirements definition, and commences DMSMS Redesign/COTS Replacement. MMSP-R includes software updates required on new computer platforms. Engineering efforts will be required to assess alternate technologies and determine optimal MMSP architectural solutions, which will include system security requirements. AN/SPS-49 Technology Refresh: FY22 was the last year of funding for this program. AN/SPS-49 is the only Air Surveillance Radar on the LSD 41/49 class ships. Continued degradation and increasingly low radar availability of the AN/SPS-49 Radar is greatly impacting deployed missions, impacting safety of flight and affecting LSD Air Warfare capability and operations and as a result, AN/SPS-49 Technology Refresh is required. This AN/,SPS-49 Technology Refresh will include Reliability, Maintainability, and Availability (RM&A) improvements and solid state technology insertions which will reduce cascading failures and mitigate obsolescence issues. In addition, this effort replaces key components to include: transmitter, receiver, exciter, antenna elevation servo control, radar system control, display and signal data processor (SDP). A digital receiver/exciter (DREX) with high-performance computing technology will be a key component in the new system. The current SPS-49 radar has no software so new software is being developed to mimic the current radar functions to maintain compatibility with internal and external interfaces. This effort will improve SPS-49 electronic protection, have increased surveillance range and increased slow moving small target detection, as well as reduce total ownership cost with lower unit cost and smaller size/weight/power requirements. Funding is also to complete development, test and evaluation, validation and integration of a technology refresh of the below deck hardware for the AN/ SPS-49A(V)1 Long Range Air Surveillance Radar. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                          Date: April 2026 Appropriation/Budget Activity                                               R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 5: System         PE 0604501N / Advanced Above Water Sensors Development & Demonstration (SDD)$$, $$Budget J-Books/FY27/Navy/RDTEN_BA5_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604503N$$, $$Submarine SWFTS Modernization$$, $$rdte_navy_ba5$$, $$peo_subs$$, 2026, 204158000, 90130000, 97953000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "navy", "page_num": 33, "original_pe": "0604503N", "page_header": "Department of the Navy"}$$::jsonb, $$Submarine Warfare Federated Tactical Systems(SWFTS) is a family of interdependent systems that conduct cooperative system development, procurement, and installations. The SWFTS Participating Acquisition Resource Managers (PARMs) are comprised of PMS401 Acoustic Rapid Commercial Off The Shelf (COTS) Insertion (A-RCI), PMS425 Combat Control (BYG-1), and PMS 435 Integrated Submarine Imaging System (ISIS) and Electronic Warfare (EW BLQ-10). SWFTS Technical Insertion (IT) shipsets must be procured and installed in like quantities (Except EW SSBN (OHIO)) across all PARMs to maintain the SWFTS model. Project 0219 (PMS 401): The AN/BQQ-10(V) Acoustic Rapid COTS Insertion (A-RCI) Submarine SONAR system will continue to add new capabilities via Technical Insertion (TI)/Advanced Processing Build (APB) process while working across Submarine Warfare Federated Tactical System (SWFTS) programs to transition to Development Security Operations (DevSecOps) software processes and migrate to a cloud-based architecture. Sensor Efforts provide increased operational capabilities for littoral operations, situational awareness, and reliability improvements. This program delivers block updates to Sonar Systems installed on SSN 688i, SSN 21, VIRGINIA, SSBN, and SSGN Class Submarines to maintain clear acoustical, tactical, and operational superiority over Submarines and Surface Combatants in all scenarios through detection, classification, localization, and contact following. Project 0236 (PMS 425): The AN/BYG-1 is the combat control system common across all submarine platforms which incorporates tactical control, weapon/payload control and Tactical Local Area Network (TacLAN) functions into a single procurement program. AN/BYG-1 allows the submarine to rapidly update the ship-safety tactical picture, integrates the common tactical picture into the battlegroup, improves torpedo interfaces, and provides tactical TOMAHAWK, Harpoon, and future payload capability. AN/BYG-1 systems will be continuously updated with hardware enhancements to address Commercial Off The Shelf (COTS) obsolescence and provide Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Navy                                                                                Date: June 2025 Appropriation/Budget Activity                                                      R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 5: System                PE 0604503N / Submarine SWFTS Modernization Development & Demonstration (SDD) capability improvements through software upgrades. Hardware updates are referred to as Tech Insertion (TI) kits and are differentiated by year of development (i.e. TI-22, TI-24, TI-26, etc.). The TI upgrades provide the baseline for all future AN/BYG-1 procurements. AN/BYG-1 is part of the Submarine Warfare Federated Tactical Systems (SWFTS), a family of interdependent systems that conduct cooperative system development and installations. Project 0253 (PMS 435): The Navigation and Electro-Optical Support Program is responsible for the development and improvement of low-profile masts and Integrated Submarine Imaging System (ISIS) to support safe and effective operations in high density environments, state of the art visual intelligence gathering, and employment of surveillance and weapons systems. Project 0775 (PMS 435): The Submarine Support Equipment Program is responsible for the development and improvement of submarine Electronic Warfare (EW) systems in support of effective operations in the areas of Joint Littoral Warfare, Joint Intelligence Surveillance Reconnaissance, Indications and Warning, Electronic Warfare, Information Operations, including Cyber, and Special Operations Force support. Sustained and significant improvements to submarine EW systems are required to maintain tactical ship safety and operational effectiveness. Beginning in FY26, funding for the following projects will realign to this PE 0604503N: PE 0604562N Project 0236 - SSN Comb Cont Sys Imprvmnt (ENG) PE 0604777N Project 0253 - Nav & Electro-Optical Supt$$, NULL, 211611000, 216833000, 214049000, NULL, NULL, 136, $$RDTEN_BA5_Book.pdf$$, NULL, FALSE, 94484000, 213804000, 195361000, 195361000, NULL, 195361000, 218247000, $$Submarine Warfare Federated Tactical Systems (SWFTS) is a family of interdependent systems that conduct cooperative system development, procurement, and installations. The SWFTS Participating Acquisition Resource Managers (PARMs) are comprised of PMS401 Acoustic Rapid Commercial Off The Shelf (COTS) Insertion (A-RCI), PMS425 Combat Control (BYG-1), and PMS 435 Integrated Submarine Imaging System (ISIS) and Electronic Warfare (EW BLQ-10). SWFTS Technical Insertion (IT) shipsets must be procured and installed in like quantities (Except EW SSBN (OHIO)) across all PARMs to maintain the SWFTS model. Project 0219 (PMS 401): The AN/BQQ-10(V) Acoustic Rapid COTS Insertion (A-RCI) Submarine SONAR system will continue to add new capabilities via Technical Insertion (TI)/Advanced Processing Build (APB) process while working across Submarine Warfare Federated Tactical System (SWFTS) programs to transition to Development Security Operations (DevSecOps) software processes and migrate to a cloud-based architecture. Sensor Efforts provide increased operational capabilities for littoral operations, situational awareness, and reliability improvements. This program delivers block updates to Sonar Systems installed on SSN 688i, SSN 21, VIRGINIA, SSBN, and SSGN Class Submarines to maintain clear acoustical, tactical, and operational superiority over Submarines and Surface Combatants in all scenarios through detection, classification, localization, and contact following. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                                Date: April 2026 Appropriation/Budget Activity                                                       R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 5: System                 PE 0604503N / Submarine SWFTS Modernization Development & Demonstration (SDD) Project 0236 (PMS 425): The AN/BYG-1 is the combat control system common across all submarine platforms which incorporates tactical control, weapon/payload control and Tactical Local Area Network (TacLAN) functions into a single procurement program. AN/BYG-1 allows the submarine to rapidly update the ship-safety tactical picture, integrates the common tactical picture into the battlegroup, improves torpedo interfaces, and provides tactical TOMAHAWK, Harpoon, and future payload capability. AN/BYG-1 systems will be continuously updated with hardware enhancements to address Commercial Off The Shelf (COTS) obsolescence and provide capability improvements through software upgrades. Hardware updates are referred to as Tech Insertion (TI) kits and are differentiated by year of development (i.e. TI-22, TI-24, TI-26, etc.). The TI upgrades provide the baseline for all future AN/BYG-1 procurements. AN/BYG-1 is part of the Submarine Warfare Federated Tactical Systems (SWFTS), a family of interdependent systems that conduct cooperative system development and installations. Project 0253 (PMS 435): The Navigation and Electro-Optical Support Program is responsible for the development and improvement of low-profile masts and Integrated Submarine Imaging System (ISIS) to support safe and effective operations in high density environments, state of the art visual intelligence gathering, and employment of surveillance and weapons systems. Project 0775 (PMS 435): The Submarine Support Equipment Program is responsible for the development and improvement of submarine Electronic Warfare (EW) and AN/BPS Radio Detection and Ranging (RADAR) systems in support of effective operations in the areas of Joint Littoral Warfare, Joint Intelligence Surveillance Reconnaissance, Indications and Warning, Electronic Warfare, Information Operations, including Cyber, and Special Operations Force support. Sustained and significant improvements to submarine EW and RADAR systems are required to maintain tactical ship safety and operational effectiveness. Project 9999 (PMS 401): Submarine Thin Line Towed Array Enhanced Capabilities funding is responsible for new tasking to design and develop TB-29C Thin-line Extended Length Array modules that include dual tier power components compatible with updated, proven Compact Towed Array (CTA) technology. New design would reinforce TB-29C performance and high reliability minimizing changes to TB-29C modules by integrating power components in every module and retaining proven, high performing, fielded CTA design. This will leverage current power supply and signal path. It will support future configurations (current length and extended length - up to six additional modules). Beginning in FY26, funding for the following projects realigned to this PE 0604503N: PE 0604562N Project 0236 - SSN Comb Cont Sys Imprvmnt (ENG) PE 0604777N Project 0253 - Nav & Electro-Optical Supt PE 0604777N Project 9999 - Congressional Adds (Submarine Thin Line Towed Array Enhanced Capabilities) Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                             Date: April 2026 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 5: System          PE 0604503N / Submarine SWFTS Modernization Development & Demonstration (SDD)$$, $$Budget J-Books/FY27/Navy/RDTEN_BA5_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604504N$$, $$Air Control$$, $$rdte_navy_ba5$$, $$peo_carriers$$, 2026, 23930000, 42059000, 64458000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "navy", "page_num": 33, "original_pe": "0604504N", "page_header": "Department of the Navy"}$$::jsonb, $$This program element provides for the development, integration, and testing of Automated Air Traffic Control (ATC) hardware and software required to provide improved flight safety and more reliable all-weather ATC and landing system capabilities at Naval Air Stations (NASs) and Marine Corps Air Stations (MCASs) and Fleet Area Control and Surveillance Facilities (FACSFAC) worldwide. Programs are required to upgrade or replace aging ATC and landing system equipment on aircraft, aircraft carriers, amphibious ships, NASs, MCASs and Navy/Marine Corps tactical/expeditionary airfields and remote landing sites. These upgrades include addressing broadened CyberSecurity requirements to remain compliant with software CyberSecurity directives and Information Assurance mandates. This program is funded under System Development and Demonstration because it includes projects that have passed Milestone B approval and are conducting engineering and manufacturing development tasks aimed at meeting validated requirement prior to full-rate production decision.$$, NULL, 37496000, 36604000, 29756000, NULL, NULL, 137, $$RDTEN_BA5_Book.pdf$$, NULL, FALSE, 60478000, 23930000, 41610000, 41610000, NULL, 41610000, 22148000, $$This program element provides for the development, integration, and testing of Automated Air Traffic Control (ATC) hardware and software required to provide improved flight safety and more reliable all-weather ATC and landing system capabilities at Naval Air Stations (NASs) and Marine Corps Air Stations (MCASs) and Fleet Area Control and Surveillance Facilities (FACSFAC) worldwide. Programs are required to upgrade or replace aging ATC and landing system equipment on aircraft, aircraft carriers, amphibious ships, NASs, MCASs and Navy/Marine Corps tactical/expeditionary airfields and remote landing sites. These upgrades include addressing broadened CyberSecurity requirements to remain compliant with software CyberSecurity directives and Information Assurance mandates. JUSTIFICATION FOR BUDGET ACTIVITY: This program is funded under System Development and Demonstration because it includes projects that have passed Milestone B approval and are conducting engineering and manufacturing development tasks aimed at meeting validated requirement prior to full-rate production decision.$$, $$Budget J-Books/FY27/Navy/RDTEN_BA5_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604512N$$, $$Shipboard Aviation Systems$$, $$rdte_navy_ba5$$, $$peo_carriers$$, 2026, 33704000, 10160000, 10742000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "navy", "page_num": 33, "original_pe": "0604512N", "page_header": "Department of the Navy"}$$::jsonb, $$CV Launch & Recover System - This Navy unique project addresses the System Development and Demonstration (SDD) of systems required to recover and launch Navy/Marine Corps Aircraft (Fixed/Rotary Wing and Vertical/Short Take Off and Landing) operating aboard aircraft carriers, amphibious assault ships, and air capable ships. This program element includes the following: (1) Aircraft Launch & Recovery Equipment Modernization (2) Aircraft Launch and Recovery Equipment Service Life Management program This program is funded under System Development and Demonstration because it includes projects that have passed Milestone B approval and conducting engineering and manufacturing development tasks aimed at meeting validated requirement prior to full-rate production decision.$$, NULL, 20741000, 22406000, 12524000, NULL, NULL, 138, $$RDTEN_BA5_Book.pdf$$, NULL, FALSE, 12597000, 33704000, 30970000, 30970000, NULL, 30970000, 11624000, $$CV Launch & Recover System - This Navy unique project addresses the System Development and Demonstration (SDD) of systems required to recover and launch Navy/Marine Corps Aircraft (Fixed/Rotary Wing and Vertical/Short Take Off and Landing) operating aboard aircraft carriers, amphibious assault ships, and air capable ships. This program element includes the following: (1) Aircraft Launch & Recovery Equipment Modernization (2) Aircraft Launch and Recovery Equipment Service Life Management program This program is funded under System Development and Demonstration because it includes projects that have passed Milestone B approval and conducting engineering and manufacturing development tasks aimed at meeting validated requirement prior to full-rate production decision.$$, $$Budget J-Books/FY27/Navy/RDTEN_BA5_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604516N$$, $$Ship Survivability$$, $$rdte_navy_ba5$$, $$asn_rda$$, 2026, 4364000, 0, 0, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "navy", "page_num": 33, "original_pe": "0604516N", "page_header": "Department of the Navy"}$$::jsonb, $$This program is a new start in FY 2026. Research and develop solutions to Damage Control and Firefighting issues to include developing environmentally friendly and effective alternatives to existing firefighting systems. This program funds critical efforts in shipboard fire detection/suppression systems, fire prevention features, damage control, personnel protection, and advanced firefighting equipment.$$, NULL, 5722000, 2829000, 2379000, NULL, NULL, 139, $$RDTEN_BA5_Book.pdf$$, NULL, FALSE, 0, 4364000, 7861000, 7861000, NULL, 7861000, 2423000, $$This program is initiated in FY 2026. Research and develop solutions to Damage Control and Firefighting issues to include developing environmentally friendly and effective alternatives to existing firefighting systems. This program funds critical efforts in shipboard fire detection/suppression systems, fire prevention features, damage control, personnel protection, and advanced firefighting equipment.$$, $$Budget J-Books/FY27/Navy/RDTEN_BA5_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604518N$$, $$Combat Information Center Conv$$, $$rdte_navy_ba5$$, $$onr$$, 2026, 0, 11179000, 10621000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "navy", "page_num": 33, "original_pe": "0604518N", "page_header": "Department of the Navy"}$$::jsonb, $$Effective FY 2026, Projects 3094 and 3439 move from PE 0604518N to PE 0603561N as part of the PE/BLI consolidation effort in the DoD Implementation Plan from the Commission on Planning, Programming, Budgeting, and Execution (PPBE) Reform Final Report in an effort to rapidly increase Navy Lethality in the Submarine and Surface Fleet. This Program Element (PE) addresses the development and integration of new and improved technologies into the Anti-Submarine Warfare (ASW) and Theater Undersea Warfare (TUSW) Command & Control (C2) systems supporting the warfighter. PROJECT 3094: Undersea Warfare Decision Support System (USW-DSS) is the Navy Program of Record Net-Centric ASW/TUSW C2 system supporting the warfighter. USW-DSS continues to develop and test the software changes and perform the certification testing necessary to address end-of-life (EOL) support issues impacting USW-DSS Build 3, as well as address emerging mandated cybersecurity requirements. USW-DSS has shifted to a Continuous Improvement / Continuous Deployment (CI/CD) model leveraging multiple Development and Secure cloud Operational environments (DevSecOps) which produces baseline software upgrades twice annually. Within this CI/CD process, this project develops, designs, integrates, and tests additional tools/capabilities for USW-DSS Build 3 including, but not limited to: Waterspace Management (WSM) and Prevention of Mutual Interference (PMI), Common Track Manager, Link 16 Connectivity, Common Tactical Picture (CTP), Platform Data Fusion Integration, Cross-Platform Data Fusion, Automated Asset Allocation, Asset/Threat State Information, Vulnerability Analysis enhancement, ASW Track Management, Automated Re-planning, Engagement Target Pairing, improved Theater ASW (TASW) capabilities, Data-Focused Navy Tactical Cloud Integration, and virtualization of the electronic Master Tactical Plot (eMTP) visualization/display service as 'Web USW-DSS' on which to render the CTP/Common Operational Picture (COP). These improvements address requirements from the Commander U.S. Fleet Forces endorsement of "Theater ASW Capability Requirements" letter (dated 24 February 2017). Future USW-DSS Build 3 Fleet Capability Releases (FCRs) will focus on required system re-architecture to keep pace with the latest network and system hardware obsolescence as well as expanded processing and user interface capacity requirements that are driven by expanded multi-system and multi-level security inputs. These FCRs will also achieve commonality between afloat and ashore USW-DSS systems, such that continuous development improvements impact both shipboard and TUSW Command Headquarters (TUSWCHQ) watch floors, as well as training and Fleet support installations uniformly. FCR 3 will focus on expanding and sharing Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Navy                                                                                 Date: June 2025 Appropriation/Budget Activity                                                     R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 5: System               PE 0604518N / Combat Information Center Conv Development & Demonstration (SDD) operational data and artifacts between systems across multiple security classification and releasability standards to support system to system and allied and coalition interoperability. This effort complements parallel Foreign Military Sales (FMS) efforts that expand cooperative TUSW operations. PROJECT 3439: The Networked Architecture for Undersea Theater Integrated C2 Advantage (NAUTICA) Project provides Theater ASW (TASW) architecture development, systems engineering, and design, and continues the system engineering effort required to design, develop, and deliver an integrated TASW battle management suite in accordance with the 2007 ASW Initial Capabilities Document (ICD). The plan prioritizes NAUTICA investments in accordance with the Commander U.S. Fleet Forces endorsement of "Theater ASW Capability Requirements" letter (dated 24 February 2017) and Center for Security Forces (CSF) letter "Criticality of Sustaining PMI and WSM Capability and Meeting Emerging Requirements for Great Competition" submitted to OPNAV N2N6. The design of the integrated TASW battle management suite will include a system-of-systems TASW architecture to enable the existing Programs of Record under development from the Program Executive Office (PEO) for Integrated Warfare Systems (IWS), PEO Command, Controls, Communications, Computers and Intelligence (C4I), PEO AIR, PEO Submarines, and N9SP to exploit a common framework. The common architecture will define the key data exchanges, common displays and processing, data models, cross domain interfaces, and multi-level security software to fuse TUSW C2 data within USW-DSS and an ever-increasing number of C4I tactical data sources into a CTP. This development will include tactical dissemination of USW tactical picture and targeting data to the submarine, allied system-to-system interoperability, Unmanned Undersea Vehicle (UUV), and Sub-surface and Seabed Warfare (SSW) situational awareness. NAUTICA will focus on closing seams issues across the multi-program system-of-systems that provides C2 tools for TUSW and will support the curation of tactical picture, targeting, and cueing data to allow for transmission to ships and submarines in emission control (EMCON) status to support USW and Anti-Surface Warfare (ASuW).$$, NULL, 0, 0, 0, NULL, NULL, 140, $$RDTEN_BA5_Book.pdf$$, NULL, FALSE, 10458000, 0, 0, 0, NULL, 0, 0, $$This Program Element (PE) addresses the development and integration of new and improved technologies into the Anti-Submarine Warfare (ASW) and Theater Undersea Warfare (TUSW) Command & Control (C2) systems supporting the warfighter. PROJECT 3094: Undersea Warfare Decision Support System (USW-DSS) is the Navy Program of Record Net-Centric ASW/TUSW C2 system supporting the warfighter. USW-DSS continues to develop and test the software changes and perform the certification testing necessary to address end-of-life (EOL) support issues impacting USW-DSS Build 3, as well as address emerging mandated cybersecurity requirements. USW-DSS has shifted to a Continuous Improvement / Continuous Deployment (CI/CD) model leveraging multiple Development and Secure cloud Operational environments (DevSecOps) which produces baseline software upgrades twice annually. Within this CI/CD process, this project develops, designs, integrates, and tests additional tools/capabilities for USW-DSS Build 3 including, but not limited to: Waterspace Management (WSM) and Prevention of Mutual Interference (PMI), Common Track Manager, Link 16 Connectivity, Common Tactical Picture (CTP), Platform Data Fusion Integration, Cross-Platform Data Fusion, Automated Asset Allocation, Asset/Threat State Information, Vulnerability Analysis enhancement, ASW Track Management, Automated Re-planning, Engagement Target Pairing, improved Theater ASW (TASW) capabilities, Data-Focused Navy Tactical Cloud Integration, and virtualization of the electronic Master Tactical Plot (eMTP) visualization/display service as 'Web USW-DSS' on which to render the CTP/Common Operational Picture (COP). These improvements address requirements from the Commander U.S. Fleet Forces endorsement of "Theater ASW Capability Requirements" letter (dated 24 February 2017). Future USW-DSS Build 3 Fleet Capability Releases (FCRs) will focus on required system re-architecture to keep pace with the latest network and system hardware obsolescence as well as expanded processing and user interface capacity requirements that are driven by expanded multi-system and multi-level security inputs. These FCRs will also achieve commonality between afloat and ashore USW-DSS systems, such that continuous development improvements impact both shipboard and TUSW Command Headquarters (TUSWCHQ) watch floors, as well as training and Fleet support installations uniformly. FCR 3 will focus on expanding and sharing operational data and artifacts between systems across multiple security classification and releasability standards to support system to system and allied and coalition interoperability. This effort complements parallel Foreign Military Sales (FMS) efforts that expand cooperative TUSW operations. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                            Date: April 2026 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 5: System              PE 0604518N / Combat Information Center Conv Development & Demonstration (SDD) PROJECT 3439: The Networked Architecture for Undersea Theater Integrated C2 Advantage (NAUTICA) Project provides Theater ASW (TASW) architecture development, systems engineering, and design, and continues the system engineering effort required to design, develop, and deliver an integrated TASW battle management suite in accordance with the 2007 ASW Initial Capabilities Document (ICD). The plan prioritizes NAUTICA investments in accordance with the Commander U.S. Fleet Forces endorsement of "Theater ASW Capability Requirements" letter (dated 24 February 2017) and Center for Security Forces (CSF) letter "Criticality of Sustaining PMI and WSM Capability and Meeting Emerging Requirements for Great Competition" submitted to OPNAV N2N6. The design of the integrated TASW battle management suite will include a system-of-systems TASW architecture to enable the existing Programs of Record under development from the Program Executive Office (PEO) for Integrated Warfare Systems (IWS), PEO Command, Controls, Communications, Computers and Intelligence (C4I), PEO AIR, PEO Submarines, and N9SP to exploit a common framework. The common architecture will define the key data exchanges, common displays and processing, data models, cross domain interfaces, and multi-level security software to fuse TUSW C2 data within USW-DSS and an ever-increasing number of C4I tactical data sources into a CTP. This development will include tactical dissemination of USW tactical picture and targeting data to the submarine, allied system-to-system interoperability, Unmanned Undersea Vehicle (UUV), and Sub-surface and Seabed Warfare (SSW) situational awareness. NAUTICA will focus on closing seams issues across the multi-program system-of-systems that provides C2 tools for TUSW and will support the curation of tactical picture, targeting, and cueing data to allow for transmission to ships and submarines in emission control (EMCON) status to support USW and Anti-Surface Warfare (ASuW).$$, $$Budget J-Books/FY27/Navy/RDTEN_BA5_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604522N$$, $$Air & Missile Defense Radar (AMDR) System$$, $$rdte_navy_ba5$$, $$peo_iws$$, 2026, 87937000, 87175000, 107924000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "navy", "page_num": 33, "original_pe": "0604522N", "page_header": "Department of the Navy"}$$::jsonb, $$The Air and Missile Defense Radar (AMDR) program consists of the AN/SPY-6(V) Family Of Radars (FoR): - AN/SPY-6(V)1 (DDG 51 Arleigh Burke class Flight III guided missile destroyer) - AN/SPY-6(V)2 (Nimitz class CVN, America class LHA, and San Antonio class LPD) - AN/SPY-6(V)3 (Ford class CVN, Constellation class FFG) - AN/SPY-6(V)4 (DDG 51 Arleigh Burke class Flight IIA guided missile destroyer backfit) AN/SPY-6(V)1 will provide multi-mission capabilities, simultaneously supporting both long range, exoatmospheric detection, tracking and discrimination of ballistic missiles, as well as Area and Self Defense against air and surface threats. For the Ballistic Missile Defense (BMD) capability, increased radar sensitivity and bandwidth over current radar systems are needed to detect, track and support engagements of advanced ballistic missile threats at the required ranges, concurrent with Area and Self Defense against Air and Surface threats. For the Area Air Defense and Self Defense capability, increased sensitivity and clutter capabilities are needed to detect, react to, and engage stressing Very Low Observable/Very Low Flyer (VLO/VLF) threats in the presence of heavy land, sea, and rain clutter. This effort provides for the development of an active phased array radar with the required capabilities to address the evolving threat. The AN/SPY-6(V) FoR will obtain performance and technology enhancements throughout their service life based upon an approach that includes modularity of hardware and software, a scalable design and Open Architecture (OA). AN/SPY-6(V)2 and (V)3 (Enterprise Air Surveillance Radar (EASR) will provide multi-mission capabilities, simultaneously supporting Air Traffic Control (ATC), situational awareness, and ship self-defense against Air and Surface threats. For these missions, increased clutter capability, short-range detection and tracking, and special weather waveforms are needed. AN/SPY-6(V)3 is the primary air surveillance radar supporting ship self-defense, situational awareness and Air Traffic Control (ATC) for Ford class CVNs. For other ship classes, AN/SPY-6(V)2 is the primary radar for self-defense and situational awareness with the ancillary role of supporting ATC by resolving SPN-50 mast blockage for ATC. AN/SPY-6(V)4 will provide Active Electronically-Scanned Array (AESA) and digital beamforming technology for backfit to Flight IIA DDG. Backfit of SPY-6 technology on DDG 51 FLT IIA commences with non-recurring engineering efforts to scale the radar hardware and software; perform modeling and simulation to update the Concept of Operations (CONOPS), and enable SPY-6 Integrated Air and Missile Defense (IAMD) performance capabilities on FLT IIA DDGs. AN/SPY-6 Enhancements include Advanced Distributed Radar (ADR), High Efficiency High Powered Amplifier (HPA), Agnostic Signal Processing for Increased Radar Efficiency (ASPIRE) hardware development, second-source Radio Frequency (RF) Head, and Modeling and Simulation (M&S) in support of Combat System Test Beds, pivoting from software to hardware upgrades in FY25. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Navy                                                                              Date: June 2025 Appropriation/Budget Activity                                                         R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 5: System                   PE 0604522N / Air & Missile Defense Radar (AMDR) System Development & Demonstration (SDD) ADR includes software enhancements that will enable multi-ship cooperative radar operations in order to support Distributed Maritime Operations (DMO) for the SPY-6 FoR. ADR transitions Receive Only Cooperative Radar (ROCR), Networked Cooperative Radar (NCR), and EMPIRE software capabilities from Office of Naval Research (ONR) to tactical development, implementation and testing. ADR software enhancements will increase radar detection performance for IAMD capabilities and enable operations with radars in receive-only mode in cooperation with other AN/SPY-6(V) radars. Agnostic Signal Processing for Increased Radar Efficiency (ASPIRE) effort will transition from ONR to address hardware options for more flexible digital beamforming, advanced signal processing, signal synthesizer architecture, and smaller digital receiver-exciter systems, resulting in efficiencies in radar size, weight, and power requirements as a key enabler to further enhance radar capabilities. HPA development will proceed and improve manufacturability and efficiency second source development to drive down costs. M&S efforts include support of Combat System and Enterprise Test Beds. The FY26 funding request supports the following efforts: SPY-6(V)1 integration efforts and associated development to support AEGIS Baseline 10 integration, advanced radar capability testing at the Advanced Radar Development Evaluation Laboratory (ARDEL), and integration with the AEGIS Virtual Test Environment (VTE). Integration efforts and associated development for AN/SPY-6(V)2 and (V)3 (Enterprise Air Surveillance Radar (EASR)) to integrate with Ship Self Defense System (SSDS) Baseline 12 and meet the performance requirements contained in the Battlespace Awareness Interface Control Document/Drawing (ICD). This includes continued testing at the Land Based Test Site and integration efforts with the SYY-1 Air Traffic Control System and Cooperative Engagement Capability. AN/SPY-6(V)4 FLT IIA backfit efforts will continue with land-based system testing at Advanced Radar Development Laboratory (ARDEL), combat system integration testing at Combat System Engineering Development Site (CSEDS), system-level requirements updates, software defect correction, SPY-6(V)4 power and hardware integration risk reduction testing, and developmental efforts leading to delivery of SPY-6(V)4 radar equipment to DDG 91 in FY26. SPY-6 enhancement efforts include integration and testing of second-source RF Heads, testing of the high efficiency HPA, and continued M&S efforts to support Combat System Test Beds.$$, NULL, 100419000, 69531000, 54986000, NULL, NULL, 141, $$RDTEN_BA5_Book.pdf$$, NULL, FALSE, 104171000, 74937000, 96642000, 96642000, NULL, 96642000, 53623000, $$The Air and Missile Defense Radar (AMDR) program consists of the AN/SPY-6(V) Family Of Radars (FoR): - AN/SPY-6(V)1 (DDG 51 Flight III destroyer) - AN/SPY-6(V)2 (Nimitz Aircraft Carrier (CVN), America Amphibious Assault Ship (LHA), San Antonio Landing Platform Dock (LPD)) - AN/SPY-6(V)3 (Ford CVN) - AN/SPY-6(V)4 (DDG 51 Flight IIA destroyer backfit) AN/SPY-6(V)1 provides multi-mission capabilities, supporting long range ballistic missile detection, tracking and discrimination, plus Area and Self Defense against air/ surface threats. For Ballistic Missile Defense (BMD), increased sensitivity and bandwidth detect advanced threats at required ranges, concurrent with Area and Self Defense. For Area Air Defense, enhanced clutter capabilities are required to detect Very Low Observable/Very Low Flyer (VLO/VLF) threats in heavy clutter. This active phased array radar addresses evolving threats. The SPY-6 FoR obtains performance enhancements through modular hardware (HW)/software (SW), scalable design and Open Architecture (OA). AN/SPY-6(V)2/3 (Enterprise Air Surveillance Radar (EASR)) provide multi-mission capabilities supporting Air Traffic Control (ATC), situational awareness, and ship self-defense against Air and Surface threats. Enhanced clutter capability, short-range detection/tracking, and weather waveforms are needed. SPY-6(V)3 is primary air surveillance for Ford CVNs supporting self-defense, awareness and ATC. SPY-6(V)2 provides primary radar for other ships with ancillary ATC support. AN/SPY-6(V)4 provides Active Electronically-Scanned Array (AESA) and digital beamforming for Flight IIA backfit. Includes non-recurring engineering to scale HW/SW, modeling/simulation to update Concept of Operations (CONOPS), and enable Integrated Air and Missile Defense (IAMD) capabilities on FLT IIA DDGs. Enhancements include Advanced Distributed Radar (ADR), High Efficiency High Powered Amplifier (HPA), Agnostic Signal Processing for Increased Radar Efficiency (ASPIRE) HW development, second-source Radio Frequency (RF) Head, and Modeling and Simulation (M&S) supporting test beds, pivoting from SW to HW upgrades in FY25. ADR includes SW enhancements enabling multi-ship cooperative operations for Distributed Maritime Operations (DMO). Transitions Receive Only Cooperative Radar (ROCR), Networked Cooperative Radar (NCR), and Electronic Multi-Input Multi-Output Protection for Ensured Radar Effect (EMPIRE) SW capabilities from Office of Naval Research (ONR) to tactical development. Increases detection performance and enables receive-only mode cooperation. ASPIRE provides HW options addressing Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                                    Date: April 2026 Appropriation/Budget Activity                                                      R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 5: System                PE 0604522N / Air & Missile Defense Radar (AMDR) System Development & Demonstration (SDD) flexible digital beamforming, signal processing, signal synthesizer architecture, and smaller digital receiver-exciter systems, resulting in smaller systems for size/weight/ power efficiencies. HPA development improves manufacturability and reduces costs. FY27 funding supports: SPY-6(V)1 integration with AEGIS Baseline 10, testing at Advanced Radar Development Evaluation Laboratory (ARDEL), and Virtual Test Environment (VTE) integration. SPY-6(V)2/3 integration with Ship Self Defense System (SSDS) Baseline 12 meeting the Battlespace Awareness Interface Control Document (ICD) requirements, including Land Based Test Site testing and SYY-1 Air Traffic Control System and Cooperative Engagement Capability (CEC) integration. SPY-6(V)4 continues testing at ARDEL/Combat System Engineering Development Site (CSEDS), requirements updates, and defect correction. SPY-6 enhancements include second-source RF Head testing, HPA testing, and M&S support. Commence R&D transition of ASPIRE, ROCR, Radar Advanced Signal Processing (RASP), EMPIRE Future Naval Capabilities (FNC) Technology Deployment Agreements (TDAs) plus Subarray Transmit Orthogonality for Receive Multiplexing (STORM). Complete SPY-6(V)1 testing and declare Initial Operational Capability (IOC).$$, $$Budget J-Books/FY27/Navy/RDTEN_BA5_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604530N$$, $$Advanced Arresting Gear (AAG)$$, $$rdte_navy_ba5$$, $$peo_carriers$$, 2026, 32037000, 10028000, 9142000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "navy", "page_num": 33, "original_pe": "0604530N", "page_header": "Department of the Navy"}$$::jsonb, $$The Advanced Arresting Gear (AAG) program designed, developed, tested and fielded an aircraft arrestment system to replace the legacy Mark 7 arresting gear. AAG systems are being installed on all new construction aircraft carriers. AAG will provide the U.S. Navy with improved operational capability, while reducing operating and support costs. The AAG system will recover all existing and projected carrier-based tail hook-equipped air vehicles well into the 21st century. The AAG program will undergo future system improvements to address safety, obsolescence, and reliability, to include but not limited to AAG Software Stability, AAG Depot Planning, AAG Software Support Activity (SSA), and Reliability Improvement ECPs. The Software Stability development efforts will address software deficiencies, stability and reliability issues documented in a System Safety Risk Assessment (SSRA) for AAG software, and in a separate investigative report by a NAVAIR Independent Review Team (IRT). Development efforts will mitigate specific findings related to non- deterministic behavior and latency of the software that contribute to the SSRA Hazard rating (1D-Serious). Per IRT report recommendations, these efforts will address findings via software modernization and re-architecture, with new software adhering to improved Level or Rigor (LOR) standards and processes. AAG Depot Planning efforts will include analysis of test bench and depot repair Support Equipment, final updates to logistics product information and maintenance task analysis, and develop Overhaul work instruction, repair procedures, and overhaul intervals. AAG SSA funding provides development and execution of a high-level hybrid SSA planning document to ensure software test activities and procedures are implemented for AAG. Reliability improvements will be accomplished with the development of ECPs including but not limited to ECP-0120 Charging Power Supply, and pECP-027 AAG Water Twister Drain & Fill Kit. The Ford Class AAG Fourth Engine Low-Cost Alternative Using Super Capacitor Hardware (FLASH) provides for the development and fielding of an alternative to forced retrofit of the 4th Engine Energy Absorption Subsystem (EAS) on all Ford Class CVNs. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Navy                                                                           Date: June 2025 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 5: System          PE 0604530N / Advanced Arresting Gear (AAG) Development & Demonstration (SDD) This program is funded under System Development and Demonstration because it includes projects passed Milestone B approval and conducting engineering and manufacturing development tasks aimed at meeting validated requirement prior to full-rate production decision.$$, NULL, 50542000, 28837000, 5842000, NULL, NULL, 142, $$RDTEN_BA5_Book.pdf$$, NULL, FALSE, 10744000, 34933000, 60518000, 60518000, NULL, 60518000, 5448000, $$The Advanced Arresting Gear (AAG) program designed, developed, tested and fielded an aircraft arrestment system to replace the legacy Mark 7 arresting gear. AAG systems are being installed on all new construction aircraft carriers. AAG will provide the U.S. Navy with improved operational capability, while reducing operating and support costs. The AAG system will recover all existing and projected carrier-based tail hook-equipped air vehicles well into the 21st century. The AAG program will undergo future system improvements to address safety, obsolescence, reliability, and cyber security to include but not limited to AAG Software Stability, AAG Depot Planning, AAG Software Support Activity (SSA), Reliability Improvement and Obsolescence ECPs, and Ford Class AAG Fourth Engine Low-Cost Alternative Using Super Capacitor Hardware (FLASH). The Software Stability development efforts will address software deficiencies, stability and reliability issues documented in a System Safety Risk Assessment (SSRA) for AAG software, and in a separate investigative report by a NAVAIR Independent Review Team (IRT). Development efforts will mitigate specific findings related to non- deterministic behavior and latency of the software that contribute to the SSRA Hazard rating (1D-Serious). Per IRT report recommendations, these efforts will address findings via software modernization and re-architecture, with new software adhering to improved Level or Rigor (LOR) standards and processes. Development efforts include enhancing the AAG software development laboratory. AAG Depot Planning efforts will include analysis of test bench and depot repair Support Equipment, final updates to logistics product information and maintenance task analysis, and develop Overhaul work instruction, repair procedures, and overhaul intervals. AAG SSA funding provides development and execution of a high-level hybrid SSA planning document to ensure software test activities and procedures are implemented for AAG. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                             Date: April 2026 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 5: System           PE 0604530N / Advanced Arresting Gear (AAG) Development & Demonstration (SDD) Reliability improvements will be accomplished with the development of ECPs including but not limited to ECP-0120 Charging Power Supply, and pECP-027 AAG Water Twister Drain & Fill Kit. Obsolescence solutions will be accomplished with the development of ECPs including but not limited to Rugged Servers, Half Bridges, Workstation PC-104, and UIC-600 Universal Inverter Controllers. Planned AAG ECPs are subject to change in the year of execution due to urgent and compelling fleet requirements in support of Ford Class carrier operational commitments. FLASH provides for the development and fielding of a lower-cost alternative to forced retrofit of the 4th Engine Energy Absorption Subsystem (EAS) on all Ford Class CVNs, increasing safety, reliability, and maintainability. The solution includes re-design of the Power Conditioning Subsystem (PCS) with technological advances in capacitor design and high-power switch capability, along with Engine 2 back-up barricade. This program is funded under System Development and Demonstration because it includes those projects that have passed Milestone B approval and are conducting engineering and manufacturing development tasks aimed at meeting validated requirement prior to full-rate production decision.$$, $$Budget J-Books/FY27/Navy/RDTEN_BA5_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604531A$$, $$Counter - Small Unmanned Aircraft Systems Advanced Development$$, $$rdte_army_ba4$$, $$rccto$$, 2026, 45281000, 54854000, 79983000, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "army", "page_num": 15, "original_pe": "0604531A", "page_header": "Department of the Army"}$$::jsonb, $$The Secretary of Defense (SecDef) designated the Secretary of the Army (SA) as the Department of Defense's (DoD) Executive Agent (EA) for Counter-small Unmanned Aircraft Systems (C-sUAS). The EA is tasked with leading, directing, and synchronizing DoD efforts to counter small Unmanned Aircraft System (sUAS) threats while minimizing unnecessary duplication and redundancy. C-sUAS efforts are aligned to DoD Joint Requirements Oversight Council Memorandums (JROC-M) requirements for identification, development, testing, evaluation, and integration of technologies to defeat sUAS threats. C-sUAS efforts provide warfighters the ability to comprehensively detect, track, identify, and defeat enemy Group 1, 2 and 3 sUAS platforms. Finally, these efforts include joint development efforts, industry demonstrations, and system operational assessments that provide integrated solutions to meet the needs of the Military Services and DoD Agencies against emerging threats.$$, NULL, NULL, NULL, NULL, NULL, NULL, 97, $$RDTE - Vol 2 - Budget Activity 4B.pdf$$, NULL, FALSE, 77794000, 45281000, NULL, NULL, NULL, NULL, NULL, $$The Secretary of War designated the Secretary of the Army (SA) as the Department of War's (DoW) Executive Agent (EA) for Counter-small Unmanned Aircraft Systems (C-sUAS). The EA is tasked with leading, directing, and synchronizing DoW efforts to counter small Unmanned Aircraft System (sUAS) threats while minimizing unnecessary duplication and redundancy. C-sUAS efforts are aligned to DoW Joint Requirements Oversight Council Memorandums (JROC-M) requirements for identification, development, testing, evaluation, and integration of technologies to defeat sUAS threats. C-sUAS efforts provide warfighters the ability to comprehensively detect, track, identify, and defeat enemy Group 1, 2 and 3 sUAS platforms. Finally, these efforts include joint development efforts, industry demonstrations, and system operational assessments that provide integrated solutions to meet the needs of the Military Services and DoW Agencies against emerging threats.$$, $$Budget J-Books/FY27/Army/RDTE - Vol 2 - Budget Activity 4B.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604536N$$, $$Advanced Undersea Prototyping$$, $$rdte_navy_ba4$$, $$navy_cno$$, 2026, 293351000, 67318000, 21466000, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "navy", "page_num": 30, "original_pe": "0604536N", "page_header": "Department of the Navy"}$$::jsonb, $$The Orca Extra Large Unmanned Undersea Vehicle (XLUUV) is the Navy's initial Extra Large UUV effort that falls under the UUV Family of Systems. The Orca XLUUV effort was established to address a Joint Emergent Operational Need (JEON) and is multi-phased accelerated acquisition effort to rapidly deliver capability to the Fleet. Phase 1 was a competitively sourced design effort. Phase 2 down selected to one of the Phase 1 vendors in FY 2019 for fabrication and testing of the vehicle and support elements. Testing and delivery of the vehicles and support elements were delayed to FY23-26 due to contractor challenges and supplier issues. The Navy is working with the OEM to mitigate schedule delays by continuing to execute risk reduction testing and training through the addition of a designated test and training asset (Vehicle 0) which was delivered in FY24. The Navy is updating facilities at Naval Base Ventura County and Naval Base Kitsap to support testing, training, and workups, in coordination with large, unmanned surface vessel testing for cost efficiencies. The Navy is also updating facilities at a Forward Operating Base (FOB) to support future UUV operation in theater. Design and fabrication of a single Hunter payload will be initiated in FY26 with a planned integration to the XLUUVs at the forwarding operating base. The XLUUV has a modular payload bay, with defined interfaces, to support quick integration with future payloads/sensors. The Orca XLUUV efforts include integrating potential future payloads and capabilities which will be developed, evaluated, and preliminarily integrated leveraging the Core Technologies Program Element 0604029N. In addition, the Combat Autonomous Maritime Platform (CAMP) project will conduct competitive Extra Large Unmanned Undersea Vehicle capability demonstrations leveraging commercial sources and non-developmental prototypes in accordance with FY25 NDAA section 1032. The project will use the Defense Innovation Unit's (DIU) Commercial Solution Opening (CSO) process, prototyping, and spiral development. Systems will be assessed on vehicle range, payload capacities, and technical maturity to meet Indo-Pacific Command requirements$$, NULL, 69246000, 55384000, 53430000, NULL, NULL, 91, $$RDTEN_BA4_Book.pdf$$, NULL, FALSE, 20859000, 60480000, 164512000, 164512000, NULL, 164512000, 54428000, $$The Department encourages additional vendor participation in the design, development, and production of alternative weapons systems to meet current and future warfighting requirements. With current major weapons systems production at capacity, the nation is looking for alternative systems to fill these gaps. The Department is implementing diverse procurement strategies to enable rapid acquisition. These will include the use of Other Transaction Authorities, 'Marketplace' acquisition platforms, and alternative concepts to increase supply and suppliers in addition to traditional FAR-based procurement strategies. The United States Navy is executing a significant strategic pivot towards ensuring and advancing its dominance in the undersea domain by consolidating all of its Unmanned Undersea Vehicle (UUV) efforts under a single, unified portfolio. Known as the Advanced Undersea Prototyping (AUP) Program Element, this initiative centralizes all Research, Development, Testing, and Evaluation (RDT&E) for the UUV Family of Systems. This portfolio approach is a direct manifestation of the Chief of Naval Operations' broader "hedge strategy," which is focused on creating a more agile and adaptable force by integrating, experimenting with, and maturing new technologies to counter emerging threats. At its core, the AUP portfolio is designed to incubate a diverse range of capabilities, allowing the Navy to pursue multiple technology pathways simultaneously. By developing platforms in various sizes and configurations, the Navy is systematically examining and closing capability gaps, such as counter-UxS warfare, while building the capacity needed for future requirements. This strategy allows the Navy to deliver a variety of critical capabilities to the warfighter, reinforcing goals of undersea dominance, seabed control, and non-traditional sea denial through a hedge fleet of manned and unmanned systems. As a result of this portfolio there will a more survivable, lethal force in theater, assured control of the strategic seabed, protecting friendly C5ISR links while holding adversary infrastructure at risk, and a scalable, on-demand capability to shape the battlespace, gain or deny access to key maritime areas, and impose prohibitive costs on an adversary. This strategic focus on integration and experimentation is evident in the diverse projects managed within the portfolio. For instance, Project 3394, the "Adv Undersea Prototyping-Vehicles, Propulsion & Navigation," includes the Extra Large Unmanned Undersea Vehicle (XLUUV) known as Orca. The Orca features a modular payload bay, showcasing the focus on integrating new systems. In parallel, the Combat Autonomous Maritime Platform (CAMP) project leverages commercial prototypes for Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                             Date: April 2026 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 4: Advanced            PE 0604536N / Advanced Undersea Prototyping Component Development & Prototypes (ACD&P) rapid capability demonstrations to meet specific INDOPACOM requirements, highlighting the emphasis on experimentation, this is the next-gen XLUUV system. Other innovative approaches include the Liberator program, a stationary system placed on the seabed to launch various payloads. The Hunter program is a modular payload designed to support multiple XL platforms based. The Dragonfish 2094 project is a UUV designed to attack surface targets and infrastructure. To modernize existing capabilities, Project 4023 includes the Lionfish small UUV and its deep-water variant, the Viperfish medium UUV, to enhance mine countermeasures and other undersea missions. This domain-centered portfolio of unmanned systems will support the development and integration of mission specific sensors and payloads to support current and future mission requirements. Ultimately, all of these individual programs and technologies are unified under the Undersea Fleet Operations and Testing program. This crucial element of the portfolio manages the government-led development, rigorous operational testing, and final Fleet integration for the entire UUV Family of Systems. This ensures that the advanced technologies being matured within the AUP portfolio are not merely experimental concepts but are effectively transitioned into fully operational systems that provide a tangible advantage to the warfighter. The FY 2026 spend plan for Orca Extra Large Unmanned Undersea Vehicle (XLUUV) includes $143,943 Thousand of discretionary funding and $199,408 thousand of mandatory for a total of $343,351 thousand.$$, $$Budget J-Books/FY27/Navy/RDTEN_BA4_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604539D8Z$$, $$Defense Autonomous Warfare Group$$, $$rdte_dw_ba4$$, $$dw$$, 2027, 0, 0, 0, NULL, $${"fy27_mand_k": 53599650, "fy27_mand_v157": "2026-05-08", "fy26_v182_disc_K": 0, "fy26_v182_supp_K": 225900, "fy27_mand_source": "DoW_FY2027_Mandatory_Funding_Overview.txt Appendix B", "fy26_v182_total_K": 225900, "fy27_mand_section": "Next Generation Technology/Autonomy", "fy26_v182_note_name": "Research, Development, Test and Evaluation, DAWG", "fy26_v182_source_file": "RDTE_OSW_PB_2027.txt", "fy26_v182_source_line": 27466}$$::jsonb, NULL, NULL, 0, 0, 0, NULL, NULL, NULL, NULL, NULL, FALSE, 0, 225900000, 1000000000, 1000000000, 53599650000, 54599650000, 0, $$The FY 2027 request for Drone Dominance includes $1,000,000 thousand of discretionary and $53,599,650 thousand of mandatory for a total of $54,599,650 thousand. The mandatory funds Drone Dominance which is in support of the Secretary’s Drone Dominance initiative for autonomous systems procurement, domestic production capacity, and advanced capabilities. The Drone Dominance initiative will provide investment for: 1) Contested Logistics initiatives – providing support to establish a commercially integrated logistics network capable of sustaining autonomous operations under contested conditions. 2) Collaborative Autonomy initiatives – providing support to the software, control layers, interfaces, and integration rigor required for autonomous systems to operate collaboratively at scale. 3) Force Generation initiatives – providing support for the institutions, personnel pipelines, and other resources required to operate autonomous systems at scale. 4) Counter-Unmanned Systems initiatives – providing support for defense against unmanned threats to the enterprise. 5) Asset Purchase and Industrial Demand Signal initiatives – to support the procurement of unmanned systems required to generate operational mass across air, surface, subsurface, and ground domains. The FY 2027 mandatory funds continue efforts from FY 2026 to accelerate the development and deployment of cost-effective, expendable autonomous systems for the United States Forces. The FY 2026 spend plan amount for Research, Development, Test and Evaluation, DAWG includes $0 thousand of discretionary and $225,900 thousand of mandatory for a total of $225,900 thousand.$$, $$Budget J-Books/FY27/Remaining/DoW_FY2027_Mandatory_Funding_Overview.txt$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604541A$$, $$Unified Network Transport$$, $$rdte_army_ba4$$, $$dw_sda$$, 2026, 29191000, 47233000, 31837000, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "army", "page_num": 15, "original_pe": "0604541A", "page_header": "Department of the Army"}$$::jsonb, $$This funding supports the Army's Next Generation Command and Control (NGC2) initiative to modernize Command and Control (C2) systems, Infrastructure, Applications, and Transport Layers. The Program Executive Office Command, Control, Communications-Network (PEO C3N) is responsible for programming, managing and executing these projects and ensuring these funds are aligned to advanced component development activities supporting the Army's Network Modernization requirements. PEO C3N, in partnership with the Command and Control Cross-Functional Team (C2-CFT), prioritizes technology demonstrations, focused evaluations, and expert analyses to inform future requirements, mature technologies, and deliver new capabilities. Efforts funded from these projects will inform technology transitions, research and development, and user assessments, and then rapidly transition to appropriate Programs of Record or be established as a new program. Unified Network Transport provides the ground domain network connectivity of Joint All Domain Command and Control (JADC2) and enables Unified Action Partner interoperability through integration with the Mission Partner Environment (MPE). Interoperability is the ability to routinely act together coherently, effectively and efficiently to achieve tactical, operational, and strategic objectives. Interoperability between disparate forces allows coalitions to produce greater combat power than the sum of their parts by leveraging relative strengths while mitigating relative weaknesses. FY 2026 funds will support identification, maturation, demonstration, and evaluation of Technology Readiness Level (TRL) 6+ systems and subsystem components including, but not limited to, resilient Line of Sight (LOS) and beyond Line of Sight (BLOS) communications, information management systems, cyber electromagnetic activities (CEMA) situational understanding and operations, intelligent and threat-informed networking, cloud technologies, virtual augmentation, artificial intelligence/ machine learning (AI/ML), and data convergence and analytics in the Common Operating Environment to achieve modernized Unified Network capabilities required for the Army's Command Control (C2) strategy for Infrastructure, Applications, and Transport. Successful solutions identified through evaluation in a high fidelity and realistic operating environment will be transitioned to Programs of Record for integration and fielding. Funds will also support integration with solutions identified in other Army network priorities to ensure network dependencies are addressed. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                             Date: June 2025 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 4: Advanced        PE 0604541A / Unified Network Transport Component Development & Prototypes (ACD&P) The FY 2026 request was reduced by $2.553 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative."$$, NULL, NULL, NULL, NULL, NULL, NULL, 99, $$RDTE - Vol 2 - Budget Activity 4B.pdf$$, NULL, FALSE, 30675000, 29191000, NULL, NULL, NULL, NULL, NULL, $$Program Element (PE) 0604541A Unified Network Transport in FY 2027 and beyond was realigned as part of a new funding structure for the Next Generation Command and Control (NGC2) investment to modernize Command and Control (C2) systems for the Infrastructure Layer, the Applications Layer, and the Transport Layer. - Project BT2: Command Post Mobility/Survivability in FY 2027 and beyond was realigned to PE 0605333A/C2 Infrastructure, Project C2H, C2 Systems Engineering as part of a new funding structure for the Next Generation Command and Control (NGC2) investment to modernize Command and Control (C2) systems for the Infrastructure Layer. - Project BT3: Common Operating Environment (COE) in FY 2027 and beyond was realigned to PE 0605331A/C2 Applications, Project C2C, Common C2 Applications as part of a new funding structure for the Next Generation Command and Control (NGC2) investment to modernize Command and Control (C2) systems for the Applications Layer. - Project BT5: Integrated Tactical Network/Enterprise Network in FY 2027 and beyond was realigned to PE 0605330A/C2 Transport, Project C2B, Radio Modernization as part of a new funding structure for the Next Generation Command and Control (NGC2) investment to modernize Command and Control (C2) systems for the Transport Layer. The Program Executive Office Command, Control, Communications-Network (PEO C3N) is responsible for programming, managing and executing these projects and ensuring these funds are aligned to advanced component development activities supporting the Army's Network Modernization requirements. PEO C3N, in partnership with the Command and Control Cross-Functional Team (C2-CFT), prioritizes technology demonstrations, focused evaluations, and expert analyses to inform future requirements, mature technologies, and deliver new capabilities. Efforts funded from these projects will inform technology transitions, research and development, and user assessments, and then rapidly transition to appropriate Programs of Record or be established as a new program. Unified Network Transport provides the ground domain network connectivity of Next Generation Command and Control (NGC2) and enables Unified Action Partner interoperability through integration with the Mission Partner Environment (MPE). Interoperability is the ability to routinely act together coherently, effectively and Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                                   Date: April 2026 Appropriation/Budget Activity                                                         R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 4: Advanced                 PE 0604541A / Unified Network Transport Component Development & Prototypes (ACD&P) efficiently to achieve tactical, operational, and strategic objectives. Interoperability between disparate forces allows coalitions to produce greater combat power than the sum of their parts by leveraging relative strengths while mitigating relative weaknesses. Funding has been realigned out of this line to support the Army's Next Generation Command and Control (NGC2) initiative.$$, $$Budget J-Books/FY27/Army/RDTE - Vol 2 - Budget Activity 4B.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604545N$$, $$Advanced Ship Building Industrial Base$$, $$rdte_navy_ba4$$, $$asn_rda$$, 2026, 0, 0, 0, NULL, $${"fy27_mand_k": 1850000, "fy27_mand_v157": "2026-05-08", "fy27_mand_source": "DoW_FY2027_Mandatory_Funding_Overview.txt Appendix B", "fy27_mand_section": "Maritime Superiority"}$$::jsonb, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 91, $$Budget J-Books/FY27/Remaining/FY2027_r1.pdf$$, NULL, FALSE, 0, 0, 0, 0, 1850000000, 1850000000, NULL, NULL, $$Budget J-Books/FY27/Remaining/DoW_FY2027_Mandatory_Funding_Overview.txt$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604551BR$$, $$CATAPULT INFORMATION SYSTEM$$, $$rdte_dw_ba4$$, $$dw_dtra$$, 2026, 4161000, 8117000, 7475000, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "dw", "page_num": 72, "original_pe": "0604551BR", "page_header": "Defense-Wide"}$$::jsonb, $$Catapult is a private cloud technology-based data analytics platform that provides a continuously augmented, real-time repository of data ingested from a variety of sources including government agencies, combatant commands, intelligence reports and open sources. The Catapult data lake and Attack the Network Tools Suite are adaptable to any National Defense Strategy mission problem set and provide national-level capabilities for data and information discovery, access, aggregation, correlation, visualization, analysis, sharing, and distribution for users from the strategic level to the tactical edge.$$, NULL, 7653000, 7809000, 7973000, NULL, NULL, 113, $$RDTE_DTRA_PB_2026.pdf$$, $$DTRA$$, FALSE, 7290000, 3992000, 7500000, 7500000, 0, 7500000, 8132000, $$Catapult is a private cloud technology-based data analytics platform that provides a continuously augmented, real-time repository of data ingested from a variety of sources including government agencies, combatant commands, intelligence reports and open sources. The Catapult data lake and web-based software tool suite are adaptable to any National Defense Strategy (NDS) mission problem set and provide leading-edge capabilities for data and information discovery, access, aggregation, correlation, visualization, analysis, sharing, and distribution for users across the Whole-of-Government - DOW, Interagency, and Intelligence Community (IC) Partners - with Secret Internet Protocol Router Network (SIPRNet) or Joint World-Wide Intelligence Communications System (JWICS) access at no cost to end users.$$, $$Budget J-Books/FY27/Remaining/RDTE_DTRA_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604558N$$, $$New Design SSN$$, $$rdte_navy_ba5$$, $$peo_subs$$, 2026, 247293000, 232778000, 273848000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "navy", "page_num": 33, "original_pe": "0604558N", "page_header": "Department of the Navy"}$$::jsonb, $$FY 2026 funding provides for the continued execution of Virginia Class Submarine Undersea Dominance Payload Integration (UDPI) (i.e., Advanced Payloads), Advanced Acoustic Sensors, and future Blocks concept designs. FY 2026 continues the evaluation and development of capabilities/technologies for inclusion in Virginia Class Block VI, as well as initial development for Virginia Class Block VII. Funds will be executed at the Virginia Class design yard and numerous sub-vendors and warfare centers designing and developing critical, complex ship components necessary for integrating advanced Block VI capabilities into the baseline class design. The U.S. Navy must maintain a submarine fleet that is of sufficient capability and numbers to defend American interests. The VIRGINIA Class Submarine, formerly the New Attack Submarine (New SSN), is being designed to fulfill this need. It will counter potential threats in a multi- mission capable submarine that has the ability to provide covert, sustained combat presence in denied waters. The primary goal of the program is to develop an affordable yet capable submarine by evaluating a broad range of system and technology alternatives, and pursuing significant capability and improved performance enhancements while managing technical risk. This Program Element (PE) provides the technology, prototype components, and systems engineering needed to design and construct the VIRGINIA Class Submarine and build its Hull, Mechanical and Electrical (HM&E) systems and Command, Control, Communications, and Intelligence (C3I) System. This PE directly supports the following VIRGINIA Class Submarine missions: (1) covert strike warfare (STRIKE); (2) anti-submarine warfare (ASW); (3) covert intelligence collection/surveillance (ISR), indication and warning (I&W), and electronic warfare (EW); (4) anti-surface ship warfare (ASUW); (5) special warfare; (6) covert mine warfare; and (7) battle group support. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Navy                                                                            Date: June 2025 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 5: System           PE 0604558N / New Design SSN Development & Demonstration (SDD)$$, NULL, 265416000, 273637000, 278463000, NULL, NULL, 143, $$RDTEN_BA5_Book.pdf$$, NULL, FALSE, 264102000, 255010000, 237103000, 237103000, NULL, 237103000, 273546000, $$FY 2027 funding provides for the continued execution of Virginia Class Submarine Undersea Dominance Payload Integration (UDPI) (i.e., Advanced Payloads), Advanced Acoustic Sensors, and future Blocks concept designs. FY 2027 continues the detailed design of Virginia Class Block VI technical baseline established efforts, preliminary design for Virginia Class Block VII, and initial concept design studies for Block VIII. Funds will be executed at the Virginia Class design yard and numerous sub-vendors and warfare centers designing and developing critical, complex ship components necessary for integrating advanced Block VI capabilities into the baseline class design. The U.S. Navy must maintain a submarine fleet that is of sufficient capability and numbers to defend American interests. The VIRGINIA Class Submarine, formerly the New Attack Submarine (New SSN), is being designed to fulfill this need. It will counter potential threats in a multi- mission capable submarine that has the ability to provide covert, sustained combat presence in denied waters. The primary goal of the program is to develop an affordable yet capable submarine by evaluating a broad range of system and technology alternatives, and pursuing significant capability and improved performance enhancements while managing technical risk. This Program Element (PE) provides the technology, prototype components, and systems engineering needed to design and construct the VIRGINIA Class Submarine and build its Hull, Mechanical and Electrical (HM&E) systems and Command, Control, Communications, and Intelligence (C3I) System. This PE directly supports the following VIRGINIA Class Submarine missions: (1) covert strike warfare (STRIKE); (2) anti-submarine warfare (ASW); (3) covert intelligence collection/surveillance (ISR), indication and warning (I&W), and electronic warfare (EW); (4) anti-surface ship warfare (ASUW); (5) special warfare; (6) covert mine warfare; and (7) battle group support. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                          Date: April 2026 Appropriation/Budget Activity                                               R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 5: System         PE 0604558N / New Design SSN Development & Demonstration (SDD)$$, $$Budget J-Books/FY27/Navy/RDTEN_BA5_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$P_1810_L057$$, $$Afloat ATC Equipment$$, $$proc_navy_1810_ba2$$, $$navsea$$, 2026, 16426000, 16803000, 16812000, NULL, $${"page": 98, "ba_num": "02", "source": "p1_fy26", "ba_name": "Communications and electronics equipment", "line_no": "57", "service": "navy", "fy24_qty": null, "fy25_qty": null, "fy27_v25": {"ba": "02", "appr": "OPN", "title": "P-1 Line 53", "applied_at": "2026-05-09", "fy27_ooc_K": 0, "source_pdf": "Budget J-Books/FY27/Navy/OPN_BA{1..5-8}_Book.pdf", "fy27_base_K": 14879, "p1_line_num": 53, "fy27_total_K": 14879}, "appr_code": "1810", "appr_name": "Other Procurement, Navy", "fy26_v179": {"disc_K": 16426, "li_num": 53, "source": "p40_fy26_v179", "supp_K": 0, "source_pdf": "uploads/Budget J-Books/FY27/Navy/OPN_BA2_Book.txt"}, "fy26t_qty": null, "fy26d_cost": 16426000, "fy26r_cost": 0, "ident_code": "A"}$$::jsonb, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, FALSE, 74458000, 72104000, 14879000, 14879000, 0, 14879000, NULL, NULL, $$Budget J-Books/FY27/Navy/OPN_BA2_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$P_2031_L018$$, $$UH-60 Blackhawk M Model (MYP)$$, $$proc_army_2031_ba1$$, $$peo_aviation$$, 2026, 61421000, 18936000, 0, NULL, $${"page": 11, "ba_num": "01", "source": "p1_fy26", "ba_name": "Aircraft", "line_no": "18", "service": "army", "fy24_qty": null, "fy25_qty": null, "appr_code": "2031", "appr_name": "Aircraft Procurement, Army", "fy26_v178": {"disc_K": 61421, "li_num": 13, "source": "p40_fy26_v178", "supp_K": 0, "source_pdf": "uploads/Budget J-Books/FY27/Army/Aircraft_Procurement_Army.txt"}, "fy26t_qty": null, "fy26d_cost": 61421000, "fy26r_cost": 0, "ident_code": ""}$$::jsonb, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, FALSE, 58170000, 65000000, 0, 0, 0, 0, NULL, NULL, $$Budget J-Books/FY27/Army/Aircraft_Procurement_Army.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604562N$$, $$Submarine Tactical Warfare System$$, $$rdte_navy_ba5$$, $$peo_uw$$, 2026, 0, 69746000, 71982000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "navy", "page_num": 33, "original_pe": "0604562N", "page_header": "Department of the Navy"}$$::jsonb, $$Effective FY 2026, Project 0236 is moving from PE 0604562N to PE 0604503N as part of the PE/BLI consolidation effort in the DoD Implementation Plan from the Commission on Planning, Programming, Budgeting, and Execution (PPBE) Reform Final Report in an effort to rapidly increase Navy Lethality in the Submarine and Surface Fleet. The AN/BYG-1 is the combat control system common across all submarine platforms which incorporates tactical control, weapon/payload control and Tactical Local Area Network (TacLAN) functions into a single procurement program. AN/BYG-1 allows the submarine to rapidly update the ship-safety tactical picture, integrates the common tactical picture into the battlegroup, improves torpedo interfaces, and provides tactical TOMAHAWK, Harpoon, and future payload capability. AN/BYG-1 systems will be continuously updated with hardware enhancements to address Commercial Off The Shelf (COTS) obsolescence and provide capability improvements through software upgrades. Hardware updates are referred to as Tech Insertion (TI) kits and are differentiated by year of development (i.e. TI-22, TI-24, TI-26, etc.). The TI upgrades provide the baseline for all future AN/BYG-1 procurements. AN/BYG-1 is part of the Submarine Warfare Federated Tactical Systems (SWFTS), a family of interdependent systems that conduct cooperative system development and installations. Project Unit 0236: This program develops Commercial-Off-The-Shelf (COTS) based software and hardware upgrades for AN/BYG-1, the Multi-tube Weapons Simulator (MTWS), and the Common Weapon Launcher (CWL) in order to integrate improved tactical and payload control capabilities for all submarine classes. Provides funding for the development of Legacy Launchers; MTWS; Information Assurance (IA) system; Onboard Team Trainer (OBTT); and Common Infrastructure Services (CIS) subsystem. This includes integration of OBTT - Master Controller (OBTT - MC) & Inter-Subsystem Monitoring Tool (ISMT) efforts as well as other common services within SWFTS. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Navy                                                                             Date: June 2025 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 5: System            PE 0604562N / Submarine Tactical Warfare System Development & Demonstration (SDD)$$, NULL, 0, 0, 0, NULL, NULL, 144, $$RDTEN_BA5_Book.pdf$$, NULL, FALSE, 70147000, 0, 0, 0, NULL, 0, 0, $$Effective FY 2026, Project 0236 is moving from PE 0604562N to PE 0604503N as part of the PE/BLI consolidation effort in the DoD Implementation Plan from the Commission on Planning, Programming, Budgeting, and Execution (PPBE) Reform Final Report in an effort to rapidly increase Navy Lethality in the Submarine and Surface Fleet. The AN/BYG-1 is the combat control system common across all submarine platforms which incorporates tactical control, weapon/payload control and Tactical Local Area Network (TacLAN) functions into a single procurement program. AN/BYG-1 allows the submarine to rapidly update the ship-safety tactical picture, integrates the common tactical picture into the battlegroup, improves torpedo interfaces, and provides tactical TOMAHAWK, Harpoon, and future payload capability. AN/BYG-1 systems will be continuously updated with hardware enhancements to address Commercial Off The Shelf (COTS) obsolescence and provide capability improvements through software upgrades. Hardware updates are referred to as Tech Insertion (TI) kits and are differentiated by year of development (i.e. TI-22, TI-24, TI-26, etc.). The TI upgrades provide the baseline for all future AN/BYG-1 procurements. AN/BYG-1 is part of the Submarine Warfare Federated Tactical Systems (SWFTS), a family of interdependent systems that conduct cooperative system development and installations. Project Unit 0236: This program develops Commercial-Off-The-Shelf (COTS) based software and hardware upgrades for AN/BYG-1, the Multi-tube Weapons Simulator (MTWS), and the Common Weapon Launcher (CWL) in order to integrate improved tactical and payload control capabilities for all submarine classes. Provides funding for the development of Legacy Launchers; MTWS; Information Assurance (IA) system; Onboard Team Trainer (OBTT); and Common Infrastructure Services (CIS) subsystem. This includes integration of OBTT - Master Controller (OBTT - MC) & Inter-Subsystem Monitoring Tool (ISMT) efforts as well as other common services within SWFTS. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                        Date: April 2026 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 5: System             PE 0604562N / Submarine Tactical Warfare System Development & Demonstration (SDD)$$, $$Budget J-Books/FY27/Navy/RDTEN_BA5_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604567N$$, $$Ship Contract Design/ Live Fire T&E$$, $$rdte_navy_ba5$$, $$peo_ships$$, 2026, 28400000, 22302000, 13675000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "navy", "page_num": 33, "original_pe": "0604567N", "page_header": "Department of the Navy"}$$::jsonb, $$This Program Element (PE) directly supports the Navy's Shipbuilding Plan by providing for the development of engineering, programmatic and acquisition documentation including ship specifications (including performance specifications) and contractual documentation associated with acquisition of Navy ships. This PE also supports the Congressionally mandated Live Fire Test and Evaluation (LFT&E) program for new ship designs. Contract Design has traditionally been the engineering development of the technical and contractual definition of the ship design (including ship specifications and drawings) to a level of detail sufficient for shipbuilders to make a sound estimate of the construction cost and schedule. Additionally, the contract design package developed under this PE has provided the technical baseline from which the Navy selects the shipbuilder who then develops the detail design package required to support the construction and eventual delivery of the ship. This PE also supports the development of design methodologies/tools which facilitate and optimize the transition from ship design documents to efficient production of new ships and ship conversions, and supports engineering planning and ship affordability studies. Under Acquisition Reform for new design ships, traditional distinct phasing of the design process has been replaced with a continuous concurrent engineering Integrated Product and Process Development (IPPD) process extending through and after contract award. This serves to maintain the focus of multi-discipline teams consisting of the government, shipbuilder, system programs, and suppliers. Government/Industry Integrated Product Team(s) (IPTs) will utilize the IPPD process to develop the design in an Integrated Product and Data Environment (IPDE). The design approach is part of an acquisition strategy that is based on commercial practices and incorporates a phased technical definition. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Navy                                                                           Date: June 2025 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 5: System           PE 0604567N / Ship Contract Design/ Live Fire T&E Development & Demonstration (SDD)$$, NULL, 22012000, 3866000, 3863000, NULL, NULL, 145, $$RDTEN_BA5_Book.pdf$$, NULL, FALSE, 13191000, 35634000, 19429000, 19429000, NULL, 19429000, 3930000, $$This Program Element (PE) directly supports the Navy's Shipbuilding Plan by providing for the development of engineering, programmatic and acquisition documentation including ship specifications (including performance specifications) and contractual documentation associated with acquisition of Navy ships. This PE also supports the Congressionally mandated Live Fire Test and Evaluation (LFT&E) program for new ship designs. Contract Design has traditionally been the engineering development of the technical and contractual definition of the ship design (including ship specifications and drawings) to a level of detail sufficient for shipbuilders to make a sound estimate of the construction cost and schedule. Additionally, the contract design package developed under this PE has provided the technical baseline from which the Navy selects the shipbuilder who then develops the detail design package required to support the construction and eventual delivery of the ship. This PE also supports the development of design methodologies/tools which facilitate and optimize the transition from ship design documents to efficient production of new ships and ship conversions, and supports engineering planning and ship affordability studies. Under Acquisition Reform for new design ships, traditional distinct phasing of the design process has been replaced with a continuous concurrent engineering Integrated Product and Process Development (IPPD) process extending through and after contract award. This serves to maintain the focus of multi-discipline teams consisting of the government, shipbuilder, system programs, and suppliers. Government/Industry Integrated Product Team(s) (IPTs) will utilize the IPPD process to develop the design in an Integrated Product and Data Environment (IPDE). The design approach is part of an acquisition strategy that is based on commercial practices and incorporates a phased technical definition. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                           Date: April 2026 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 5: System          PE 0604567N / Ship Contract Design/ Live Fire T&E Development & Demonstration (SDD)$$, $$Budget J-Books/FY27/Navy/RDTEN_BA5_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604574N$$, $$Navy Tactical Computer Resources$$, $$rdte_navy_ba5$$, $$peo_iws$$, 2026, 3552000, 4259000, 3921000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "navy", "page_num": 33, "original_pe": "0604574N", "page_header": "Department of the Navy"}$$::jsonb, $$Common Processing System (CPS) and Common Display System (CDS) programs support developing computing infrastructure in a competitively sourced environment. The Common Display System (CDS) and Common Processing System (CPS) provide technical replacements for obsolete display and processing equipment (such as AN/UYQ-70) for multiple warfare systems aboard Surface Combatants and Large Deck class ships. CPS equipment suite provides computer processing and memory, data storage and extraction, network systems, and Input/Output (I/O) interfaces to host software applications of Navy combat systems. These upgrades support AEGIS Modernization, AEGIS new construction, AEGIS Ashore, Ship Self Defense System (SSDS) MK2 modernization and new construction for all large deck platforms, Surface Electronic Warfare Improvement Program (SEWIP), and other Navy programs. Funding provides for technical management and Engineering Change Proposals (ECP) development for the common baseline. Funding also supports future tech refresh development efforts. Procurement and development funds provided by user programs support program unique requirements. CDS suite consists of the Technology Insertion (TI) 16 MOD 1 configuration, a follow-on to previous designs beginning with the TI 12 variant. The Navy's TI 16 MOD 1 display and peripheral solutions include Common Display System (CDS) consoles, Thin Client Displays (TCDs), Multi-Mission Displays (MMDs), and peripheral equipment. Upgrades that include these support AEGIS modernization, AEGIS new construction, AEGIS Ashore, DDG-1000, Ship Self Defense System (SSDS) MK 2, Gun Weapon System (GWS), SEWIP, and other Navy programs. Funding provides for technical management and Engineering Change Proposals (ECP) development for the common baseline along with future tech refresh development efforts. Procurement and development funds provided by user programs support program unique requirements. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Navy                                                                           Date: June 2025 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 5: System           PE 0604574N / Navy Tactical Computer Resources Development & Demonstration (SDD)$$, NULL, 3506000, 3552000, 3599000, NULL, NULL, 146, $$RDTEN_BA5_Book.pdf$$, NULL, FALSE, 3898000, 3552000, 3415000, 3415000, NULL, 3415000, 3663000, $$Common Processing System (CPS) and Common Display System (CDS) programs support developing computing infrastructure in a competitively sourced environment. The Common Display System (CDS) and Common Processing System (CPS) provide technical replacements for obsolete display and processing equipment (such as AN/UYQ-70) for multiple warfare systems aboard Surface Combatants and Large Deck class ships. CPS equipment suite provides computer processing and memory, data storage and extraction, network systems, and Input/Output (I/O) interfaces to host software applications of Navy combat systems. These upgrades support AEGIS Modernization, AEGIS new construction, AEGIS Ashore, Ship Self Defense System (SSDS) MK2 modernization and new construction for all large deck platforms, Surface Electronic Warfare Improvement Program (SEWIP), and other Navy programs. Funding provides for technical management and Engineering Change Proposals (ECP) development for the common baseline. Funding also supports future tech refresh development efforts. Procurement and development funds provided by user programs support program unique requirements. CDS suite consists of the Technology Insertion (TI) 16 MOD 1 configuration, a follow-on to previous designs beginning with the TI 12 variant. The Navy's TI 16 MOD 1 display and peripheral solutions include Common Display System (CDS) consoles, Thin Client Displays (TCDs), Multi-Mission Displays (MMDs), and peripheral equipment. Upgrades that include these support AEGIS modernization, AEGIS new construction, AEGIS Ashore, DDG-1000, Ship Self Defense System (SSDS) MK 2, Gun Weapon System (GWS), SEWIP, and other Navy programs. Funding provides for technical management and Engineering Change Proposals (ECP) development for the common baseline along with future tech refresh development efforts. Procurement and development funds provided by user programs support program unique requirements. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                   Date: April 2026 Appropriation/Budget Activity                                               R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 5: System         PE 0604574N / Navy Tactical Computer Resources Development & Demonstration (SDD)$$, $$Budget J-Books/FY27/Navy/RDTEN_BA5_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604601A$$, $$Infantry Support Weapons$$, $$rdte_army_ba5$$, $$asa_alt$$, 2026, 56553000, 80777000, 57686000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "army", "page_num": 16, "original_pe": "0604601A", "page_header": "Department of the Army"}$$::jsonb, $$A portion of this funding line directly aligns to the Soldier Lethality Army Modernization Priority. This Program Element (PE) Engineering and Manufacturing Development (EMD) manages the Soldier as a system, with the goal of increasing Soldiers' combat effectiveness, increasing survivability, and improving the Soldiers' quality of life. It develops and tests prototypes of weapons, clothing, equipment, and other items useful to support the Soldier. Project CF3 (Integrated Soldier Systems (SL CFT)) test, maintain and evolve a Soldier/squad equipment configuration baseline, the Architecture Assessment Tool and conduct configuration management at the system level. The Adaptive Squad Architecture (ASA) and the Soldier Integration Facility (SIF) are Program Executive Soldier Office - Soldier (PEO-S) led efforts to support the Close Combat Integration Enterprise. These efforts support maturing and evaluating technologies for Squad as a System (SaaS). The focus is a system of systems approach that includes updating Formations Based Architecture, evaluation of interoperability of systems on the soldier and squad and updating the Architecture Assessment Tool (AAT). Maturing digital models, algorithms, integrating with virtual, constructive and live outdoor evaluation and digital tools across the Army, other Services, and Allies allows the PEO-S to act as the Leading Systems Integrator for SaaS. Funding for this project aligns with the Army's Digital Engineering and Digital Transformation Strategy and is a Soldier Lethality Cross Functional Team priority. Project ES9 (Advanced Tactical Parachute System) improves personnel parachute systems and associated equipment for low and high altitude operations to include canopy improvements based on integration of new technology with the goal of enhancing the insertion capability and safety of the airborne Soldier and increasing the performance, reliability, and durability of personnel airdrop equipment. Project EW4 (Crew Served Weapons Engineering Development) Funding support Crew Served Weapons systems include small and medium caliber weapons ranging up to 40 millimeter and remote weapon stations. These efforts focus on system improvements designed to enhance lethality, target acquisition, fire control, usability, training effectiveness and reliability of weapons to include ammunition and counter UAS when developing and/or evaluating standard, non-standard weapons and remote weapon station enhancements. Focus areas include system development, integration (to include human-systems), demonstration, test and evaluate components, prototypes and operational system prototypes of small arms weapon systems and/or enhancements. Benefits include continuous improvements to small arms weapon systems, fire control equipment, optics, gun barrels, ancillary equipment, training devices, component mounts, weapon mounts, and weapon/ammunition interface of current small arms fleet or new weapon systems. Project FF2 (Small Arms Fire Control) supports the development of an advanced fire control for the Next Generation Automatic Rifle (NGSW-AR) and Rifle (NGSW-R). The Next Generation Fire Control will increase the probability of hit and decrease the time to engage through a variable powered direct view optic with integrated range finder, ballistic calculator, and digital display capable of providing an adjusted aim point. Project FL8 (84mm MAAWS Ammunition) supports test, evaluation and quality up to seven types of 84 millimeter (mm) munitions for the U.S. Army use with the M3/ M3A1 Multi-Role Anti-Personnel Weapon Systems (MAAWS). Project FM4 (Next Generation Squad Weapons) supports the rapid prototyping and development of a NGSW-AR, NGSW-R and common cartridge to provide capability improvements in accuracy, range and lethality, in order to maintain overmatch and meet future warfighter requirements. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                                 Date: June 2025 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 5: System             PE 0604601A / Infantry Support Weapons Development & Demonstration (SDD) Project GM1 (Future Medium Machine Gun) is intended to replace M240s inside the Closed Combat Force (CCF). The FMMG will increase Squad survivability and lethality in large scale combat operations. The FMMG is a belt fed crew served direct fire weapon system that will enable the rifle platoon to organically suppress and destroy enemy personnel targets and maintain operational tempo. The FMMG will provide increased lethality and capability to the warfighter compared to present Machine Gun technologies fielded to Operational Units. Project S58 (Soldier Enhancement Program) supports accelerated integration, modernization, and enhancement efforts of lighter, more lethal weapons, and improved Soldier items including lighter, more comfortable load-bearing equipment, field gear, survivability items, communications equipment, and navigational aids. Project S60 (Clothing & Equipment) supports pre-production development of state-of-the-art individual clothing and equipment to improve the survivability, mobility and sustainment affecting the quality of life of the individual Soldier. Project S61 (Acis Engineering Development) provides System Development programs with improved aircrew safety, survivability, and human performance that amplify the warfighting effectiveness and facilitates full-spectrum dominance of the Army aircraft including the AH-64 Apache/Longbow, CH-47 Chinook, UH/HH-60 Blackhawk, Light Utility Helicopter, and Future Vertical Lift (FVL) platforms. Project S63 (Individual Weapons Engineering Development) demonstrates engineering development models or integrated commercial items designed to enhance lethality, target acquisition, fire control, training effectiveness, and reliability for small arms weapon systems and ammunition. Programs include Improved Weapons Coatings, Personal Defense Weapon, 30 Round 5.56mm Magazine, Modular Handgun System (MHS), Precision Sniper Rifle (PSR), Sub Compact, Interim Combat Service Rifle (ICR) and Precision Grenadier System (PGS). Project S70 (Personnel Recovery Support System (PRSS)) provides system research, development and testing of the Personal Recovery Support System/Personnel Recovery Support Equipment supporting operations to report and locate isolated, missing, detained or captured Soldiers. Project VS5 (Soldier Protective Equipment) supports engineering and manufacturing development of Individual Soldier Ballistic Protection equipment. It will leverage advancements in technology to continue incremental improvements to body armor (to include improved outer tactical vests, plate carriers, and helmets) and other personal protective equipment. The FY 2026 request was reduced by $4.166 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative." Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                        Date: June 2025 Appropriation/Budget Activity                                               R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 5: System         PE 0604601A / Infantry Support Weapons Development & Demonstration (SDD)$$, NULL, 117436000, 108548000, 102522000, NULL, NULL, 103, $$RDTE - Vol 3 - Budget Activity 5A.pdf$$, NULL, FALSE, 55767000, 77653000, 55296000, 55296000, NULL, 55296000, 103859000, $$This Engineering and Manufacturing Development (EMD) PE manages the Soldier as a system, with the goal of increasing Soldiers' combat effectiveness, increasing survivability, and improving the Soldiers' quality of life. It develops and tests prototypes of weapons, clothing, equipment, and other items useful to support the Soldier. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                                    Date: April 2026 Appropriation/Budget Activity                                                      R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 5: System                PE 0604601A / Infantry Support Weapons Development & Demonstration (SDD) Project CF3 (Integrated Soldier Systems (SL CFT)) test, maintain and evolve a Soldier/squad equipment configuration baseline, the Architecture Assessment Tool and conduct configuration management at the system level. The Adaptive Squad Architecture (ASA) and the Soldier Integration Facility (SIF) are Capability Program Executive Ground (CPE Ground) led efforts to support the Close Combat Integration Enterprise. These efforts support maturing and evaluating technologies for Squad as a System (SaaS). The focus is a system of systems approach that includes updating Formations Based Architecture, evaluation of interoperability of systems on the soldier and squad and updating the Architecture Assessment Tool (AAT). Maturing digital models, algorithms, integrating with virtual, constructive and live outdoor evaluation and digital tools across the Army, other Services, and Allies allows the CPE Ground to act as the Leading Systems Integrator for SaaS. Funding for this project aligns with the Army's Digital Engineering and Digital Transformation Strategy. Project DO4 (Arctic Mobility Sustainment System (AMSS)) provides a complete solution providing Warfighter with equipment for up to 72hr sustainment operations in the Arctic and/or Extreme Cold Weather environments. Project ES9 (Advanced Tactical Parachute System) improves personnel parachute systems and associated equipment for low and high-altitude operations to include canopy improvements based on integration of new technology with the goal of enhancing the insertion capability and safety of the airborne Soldier and increasing the performance, reliability, and durability of personnel airdrop equipment. Project EW4 (Crew Served Weapons Engineering Development) Funding support Crew Served Weapons systems include small and medium caliber weapons ranging up to 40 millimeter and remote weapon stations. These efforts focus on system improvements designed to enhance lethality, target acquisition, fire control, usability, training effectiveness and reliability of weapons to include ammunition and counter UAS when developing and/or evaluating standard, non-standard weapons and remote weapon station enhancements. Focus areas include system development, integration (to include human-systems), demonstration, test and evaluate components, prototypes and operational system prototypes of small arms weapon systems and/or enhancements. Benefits include continuous improvements to small arms weapon systems, fire control equipment, optics, gun barrels, ancillary equipment, training devices, component mounts, weapon mounts, and weapon/ammunition interface of current small arms fleet or new weapon systems. Project FF2 (Small Arms Fire Control) supports the development of an advanced fire control for current and advanced small arms. This advanced fire control will increase the probability of hit and decrease the time to engage through a variable powered direct view optic with integrated range finder, ballistic calculator, and digital display capable of providing an adjusted aim point. Project FL8 (84mm MAAWS Ammunition) supports test, evaluation and quality up to seven types of 84 millimeter (mm) munitions for the U.S. Army use with the M3/ M3A1 Multi-Role Anti-Personnel Weapon Systems (MAAWS). Project FM4 (Next Generation Squad Weapons) supports the rapid prototyping and development of weapons and common cartridge to provide capability improvements in accuracy, range and lethality, in order to maintain overmatch and meet future warfighter requirements. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                               Date: April 2026 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 5: System              PE 0604601A / Infantry Support Weapons Development & Demonstration (SDD) Project S58 (Soldier Enhancement Program) supports accelerated integration, modernization, and enhancement efforts of lighter, more lethal weapons, and improved Soldier items including lighter, more comfortable load-bearing equipment, field gear, survivability items, communications equipment, and navigational aids. Project S60 (Clothing & Equipment) supports pre-production development of state-of-the-art individual clothing and equipment to improve the survivability, mobility and sustainment affecting the quality of life of the individual Soldier. Project S61 (Acis Engineering Development) provides System Development programs with improved aircrew safety, survivability, and human performance that amplify the warfighting effectiveness and facilitates full-spectrum dominance of the Army aircraft including the AH-64 Apache/Longbow, CH-47 Chinook, UH/HH-60 Blackhawk, Light Utility Helicopter, and Future Vertical Lift (FVL) platforms. Project S63 (Individual Weapons Engineering Development) demonstrates engineering development models or integrated commercial items designed to enhance lethality, target acquisition, fire control, training effectiveness, and reliability for small arms weapon systems and ammunition. Programs include Improved Weapons Coatings, Personal Defense Weapon, 30 Round 5.56mm Magazine, Modular Handgun System (MHS), Precision Sniper Rifle (PSR), Sub Compact, and Precision Grenadier System (PGS). Project S70 (Personnel Recovery Support System (PRSS)) provides system research, development and testing of the Personal Recovery Support System/Personnel Recovery Support Equipment supporting operations to report and locate isolated, missing, detained or captured Soldiers. Project VS5 (Soldier Protective Equipment) supports engineering and manufacturing development of Individual Soldier Ballistic Protection equipment. It will leverage advancements in technology to continue incremental improvements to body armor (to include improved outer tactical vests, plate carriers, and helmets) and other personal protective equipment.$$, $$Budget J-Books/FY27/Army/RDTE - Vol 3 - Budget Activity 5A.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604601N$$, $$Mine Development$$, $$rdte_navy_ba5$$, $$asn_rda$$, 2026, 61456000, 101274000, 84411000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "navy", "page_num": 33, "original_pe": "0604601N", "page_header": "Department of the Navy"}$$::jsonb, $$Project 0267 funds the Quickstrike MOD 3, Quickstrike-Extended Range (ER), and Clandestine Delivered Mine (CDM) MK68 programs. Project 2993 adjustments are associated with sensor upgrades to allow the Hammerhead system to prosecute additional targets. The Mines Improvement PE provides resources to develop naval mine systems used to establish and maintain control of essential sea areas. Naval mines are used to deny sea areas or inflict damage on adversary shipping to hinder, disrupt, and deny adversary operations. Naval mining is employed to reduce the adversary's threat to friendly forces and preserve access. Mining complements and performs an essential part of other warfare areas; particularly strike, anti-submarine, and anti-surface warfare. Resources are utilized for developing and deploying improvements to the portfolio of naval mines.$$, NULL, 53855000, 52677000, 52408000, NULL, NULL, 147, $$RDTEN_BA5_Book.pdf$$, NULL, FALSE, 83393000, 130000, 158666000, 158666000, NULL, 158666000, 53410000, $$Project 0267: Funds development efforts for programs in the Quickstrike (QS) Family of Mines, to include QS MOD 3, QS Extended Range (ER) and QS Long Range (LR), as well as the MK 68 Clandestine Delivered Mine (CDM) program and its associated mine launching system. Project 0605: Long Range Aerial Delivery Maritime Mine (LRADMM) is a series of development, integration, and test efforts for the QS Family of Mines that support greater precision mine placement, increased warhead lethality, new mine component development, expanded launch-platform integration and increasingly greater stand- off delivery ranges enabled by the use of extended-range wing kits and long-range powered delivery vehicles. Project 2993: Funds are associated with sensor upgrades to allow the Hammerhead system to prosecute additional targets. Project 9999: FY25 Congressional Add funds effort to demonstrate an air-delivered, long-range, powered, maritime mine solution for the Quickstrike Family of Mines. The Mines Improvement PE provides resources to develop naval mine systems used to establish and maintain control of essential sea areas. Naval mines are used to deny sea areas or inflict damage on adversary shipping to hinder, disrupt, and deny adversary operations. Naval mining is employed to reduce the adversary's threat to friendly forces and preserve access. Mining complements and performs an essential part of other warfare areas; particularly strike, anti-submarine, and anti-surface warfare. Resources are utilized for developing and deploying improvements to the portfolio of naval mines. The FY 2026 spend plan for Mine Development includes $0.130M of discretionary and $178.326M of mandatory for a total of $178.456M. Mandatory funding supported QS-ER, CDM, QS MOD 3 development efforts. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                          Date: April 2026 Appropriation/Budget Activity                                               R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 5: System         PE 0604601N / Mine Development Development & Demonstration (SDD)$$, $$Budget J-Books/FY27/Navy/RDTEN_BA5_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604602F$$, $$Armament/Ordnance Development$$, $$rdte_af_ba5$$, $$afrl_rw$$, 2026, 7253000, 5036000, 5417000, NULL, $${"ba_raw": "6.5", "source": "af_r1_fy26", "original_pe": "0604602F"}$$::jsonb, $$The Armament Ordnance Development program funds open standards development and maturation for adoption by USAF, Joint, and Coalition weapon systems for rapid integration, support, and operational use of the full range of armament capabilities. Weapons and weapon systems implementation of open armament interface standards provides rapid integration of software-defined capabilities, reduces development timelines, lowers life-cycle cost, and ensures interoperability with emerging capabilities. This budget funds the Universal Armament Interface (UAI), a matured DAF-owned standard, that provides the continuous development, characterization, and improvements required to ensure integration for current, future, and legacy munitions, ammunitions, delivery systems, and subsystems. The UAI delivers the standards needed to integrate new weapon capabilities on platforms at the speed of software, independent of aircraft Operational Flight Program (OFPs) cycles; thus, reducing costly regression testing for flight safety critical aircraft software. Planned implementations include Joint Strike Fighter (JSF/F-35), F-15EX, F-16 F-47, CCA, B-21, B-1, B-2, B-52, MQ-9, Advanced Anti-Radiation Guided Missile - Extended Range (AARGM-ER), Joint Air-to-Surface Standoff Missile (JASSM), Joint Direct Attack Munition (JDAM), SDB I & II, Stand-in Attack Weapon (SiAW), Long Range Anti-Ship Missile (LRASM), Grey Wolf, Select Precision Effects At Range Capability 3 (SPEAR3), Joint Strike Missile (JSM), and Next-Generation Open Mission Services (NOMS) for mission planning. Funding directly supports the development, enhancement, and sustainment of open armament standards to support the emerging needs of the above adopting platforms. That ensures technical currency, support to coalition/joint interoperability efforts for weapons-platform interface, certification tools, and implementation support to aircraft and weapons. Funding also supports innovation activities to include studies, analyses, requirements definition, and quick-reaction capability prototypes/demonstrations to accelerate planning for technology transition, technology insertion and future acquisition programs. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605829F, 0605831F, 0605833F, or 0605898F. The FY2026 request was reduced by $.061 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, Implementing the President's Department of Government Efficiency Cost Efficiency Initiative. This program is in Budget Activity 5, System Development and Demonstration (SDD) because it has passed Milestone B approval and is conducting engineering and manufacturing development tasks aimed at meeting validated requirements prior to full rate production. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                      Date: June 2025 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 5: System      PE 0604602F / Armament/Ordnance Development Development & Demonstration (SDD)$$, NULL, 48338000, 38087000, 8039000, NULL, NULL, 91, $$FY26 Air Force Research and Development Test and Evaluation Vol II.pdf$$, NULL, FALSE, 5304000, 7174000, 96762000, 96762000, 0, 96762000, 8202000, $$The Armament Ordnance Development program funds open standards development and maturation for adoption by USAF, Joint, and Coalition weapon systems for rapid integration, support, and operational use of the full range of armament capabilities. Weapons and weapon systems implementation of open armament interface standards provides rapid integration of software-defined capabilities, reduces development timelines, lowers life-cycle cost, and ensures interoperability with emerging capabilities. This budget funds the Universal Armament Interface (UAI), a matured DAF-owned standard, that provides the continuous development, characterization, and improvements required to ensure integration for current, future, and legacy munitions, ammunitions, delivery systems, and subsystems. The UAI delivers the standards needed to integrate new weapon capabilities on platforms at the speed of software, independent of aircraft Operational Flight Program (OFPs) cycles; thus, reducing costly regression testing for flight safety critical aircraft software. Planned implementations include Joint Strike Fighter (JSF/F-35), F-15EX, F-16 F-47, CCA, B-21, B-1, B-2, B-52, MQ-9, Advanced Anti-Radiation Guided Missile - Extended Range (AARGM-ER), Joint Air-to-Surface Standoff Missile (JASSM), Joint Direct Attack Munition (JDAM), SDB I & II, Stand-in Attack Weapon (SiAW), Long Range Anti-Ship Missile (LRASM), Grey Wolf, Select Precision Effects At Range Capability 3 (SPEAR3), Joint Strike Missile (JSM), and Next-Generation Open Mission Services (NOMS) for mission planning. Funding may be utilized to design, develop, integrate, and test weapon system and/or component level architectures. Funding may be utilized to fund the concept refinement, design, development, integration, and testing of interdependent technologies and common architectures that underpin weapon system and portfolio-wide outcomes. Funding directly supports the development, enhancement, and sustainment of open armament standards to support the emerging needs of the above adopting platforms. That ensures technical currency, support to coalition/joint interoperability efforts for weapons-platform interface, certification tools, and implementation support to aircraft and weapons. Funding also supports innovation activities to include studies, analyses, requirements definition, and quick-reaction capability prototypes/demonstrations to accelerate planning for technology transition, technology insertion and future acquisition programs. This program element included all necessary expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 0605829F, 0605831F, 0605833F, and 0605898F Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                   Date: April 2026 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 5: System     PE 0604602F / Armament/Ordnance Development Development & Demonstration (SDD) This program is in Budget Activity 5, System Development and Demonstration (SDD) because it has passed Milestone B approval and is conducting engineering and manufacturing development tasks aimed at meeting validated requirements prior to full rate production.$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume II.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604604A$$, $$Medium Tactical Vehicles$$, $$rdte_army_ba5$$, $$peo_cscss$$, 2026, 18503000, 17561000, 3565000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "army", "page_num": 16, "original_pe": "0604604A", "page_header": "Department of the Army"}$$::jsonb, $$This Program Element (PE) supports continued modernization of the Army's Family of Medium Tactical Wheeled Vehicle (FMTV) fleet: 4x4 and 6x6 Cargo, Tractor, Load Handling System (LHS), Wrecker, Expandable Van, Shop Van, and Dump Truck variants with payloads ranging from 2.5-tons to 10-tons and associated companion trailers. Modernization includes upgrades in survivability, safety, modularity, fuel efficiency, power generation, reliability, maintainability, mobility, autonomous operation, and other emerging technologies that enhance warfighter capability. The Family of Medium Tactical Wheeled Vehicles perform the majority of the Army's local haul, line haul, and unit resupply missions throughout theater as multi-purpose transportation vehicles in combat, combat support, and combat service support units. The FMTV also serves as a host platform for Long Range Precision Fires (LRPF), Air and Missile Defense (AMD), and Counter - Unmanned Aerial Systems (C-UAS) supporting Fire Control and Communication modules, Engagement Operation Centers (EOC), Electronic Control Systems (EOS), and other support areas for maintenance/ personnel. This PE supports development and integration of export power capability for AMD units: PM THAAD (Terminal High Altitude Area Defense), Patriot Missile System, Sentinel Integrated Fire Protection Capability (IFPC), and Integrated Battle Command System (IBCS)/Integrated Fire Control Network (IFCN). Furthermore, this PE supports prototyping to enable soldier demonstration in Transformation in Contact units. FY 2026 Project H07 Base funds in the amount of $3.503 million will be used for development and integration of Improved Vehicle Safety Technologies, including active safety technologies such as front collision warning, collision mitigation, lane keeping assist, adaptive cruise control, and 360-degree situational awareness. FY 2026 Project H07 Base funds in the amount of $15.000 million will be used for development and integration of Vehicle Integrated Power Kits (VIPK) that provide exportable power generated by FMTV platforms to improve mobility and agility for rapid emplacement/displacement of dismount operations and fire support. The FY 2026 request was reduced by $0.018 million for civilian personnel to optimize the workforce in compliance with Executive Order 14210, "Implementing the President's Department of Government Efficiency Workforce Optimization Initiative." Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                    Date: June 2025 Appropriation/Budget Activity                                               R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 5: System         PE 0604604A / Medium Tactical Vehicles Development & Demonstration (SDD)$$, NULL, 37833000, 13664000, 5623000, NULL, NULL, 104, $$RDTE - Vol 3 - Budget Activity 5A.pdf$$, NULL, FALSE, 3435000, 18503000, 23763000, 23763000, NULL, 23763000, 5679000, $$This PE supports continued modernization of the Army's Family of Medium Tactical Wheeled Vehicle (FMTV) fleet: 4x4 and 6x6 Cargo, Tractor, Load Handling System (LHS), Wrecker, Expandable Van, Shop Van, and Dump Truck variants with payloads ranging from 2.5-tons to 10-tons and associated companion trailers. Modernization includes upgrades in survivability, safety, modularity, fuel efficiency, power generation, reliability, maintainability, mobility, autonomous operation, and other emerging technologies that enhance warfighter capability. The Family of Medium Tactical Wheeled Vehicles perform the majority of the Army's local haul, line haul, and unit resupply missions throughout theater as multi-purpose transportation vehicles in combat, combat support, and combat service support units. The FMTV also serves as a host platform for Long Range Precision Fires (LRPF), Air and Missile Defense (AMD), and Counter - Unmanned Aerial Systems (C-UAS) supporting Fire Control and Communication modules, and other support areas for maintenance/personnel. This PE supports development and integration of export power capability for AMD units: PM THAAD (Terminal High Altitude Area Defense), Patriot Missile System, Sentinel Integrated Fire Protection Capability (IFPC), and Integrated Battle Command System (IBCS)/Integrated Fire Control Network (IFCN). The Vehicle Integrated Power Kit (VIPK) will provide 20kW on the move and up to 120 kW of exportable power from the vehicle that will be utilized for command and control, directed energy weapons, radar systems, and missile launchers.$$, $$Budget J-Books/FY27/Army/RDTE - Vol 3 - Budget Activity 5A.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604604F$$, $$Submunitions$$, $$rdte_af_ba5$$, $$afrl_rd$$, 2026, 3502000, 3345000, 3427000, NULL, $${"ba_raw": "6.5", "source": "af_r1_fy26", "original_pe": "0604604F"}$$::jsonb, $$Project Chicken Little (PCL) continues providing superior rapid reaction signature exploitation capabilities for use on both the traditional and the asymmetrical battlefield. PCL delivers vital one-of-a-kind research, development, test, and evaluation (RDT&E) expertise directly to the warfighter, capability developer, and allied/coalition forces. From its inception in 1985, PCL constantly advances the state-of-the-art for developmental smart munitions, seekers/sensors, and their platforms. PCL also focuses its capability against today's networked weapons, emerging weapon concepts, and assists development of innovative targeting technologies to be employed against a wide variety of vehicle targets, theater air defense units, and an extensive array of associated equipment. Combat systems and support equipment exhibit physical characteristics (i.e. signatures) and present certain vulnerabilities, which can be exploited by various targeting technologies leading to the elimination or incapacitation of the threat through the application of force (e.g. smart munitions or directed energy) or application of intelligence, surveillance, reconnaissance (ISR) methods. PCL collects physical, functional, and signature attributes of real foreign threat systems and related equipment; this data feeds high-fidelity models used to predict detection, classification, vulnerability, and effectiveness performance for ISR sensor and weapon system design. PCL collects high resolution signature data using a variety of ground, air, and space-based sensors against both new and existing (obtained, sustained, and maintained to be signature representative) foreign targets; with and without the presence of camouflage, concealment, and deception materials; and operated using enemy tactics/Concept of Operations (CONOPS). The resulting highly reliable, realistic data directly support munitions/targeting development programs and helps mitigate overall acquisition risk. PCL serves as a major focal point for joint signature exploitation, collection, and dissemination within the DoD. PCL is a prime contributor in the time critical process to rapidly exploit, assess, and determine US and allied weapon/targeting performance against high value targets. Customers include: the major Defense and Service Intelligence Centers, all Services, the Joint Technical Coordinating Group (JTCG) who develop the Joint Munitions Effectiveness Manuals (JMEMs), Combatant Commands, AF Major Commands, US Air Force Weapons School curriculum support, and others. Current projects include, but are not limited to: target signature exploitation, target geometric modeling (for identifying vulnerabilities), improving air capabilities against protected structures (specifically hard and deeply buried targets), and the testing of multiple seekers, sensors, and targeting technologies in representative environments against Combatant Command/Major Command/Intelligence Community high value targets. This program is in Budget Activity 5, System Development and Demonstration (SDD) because it has passed Milestone B approval and is conducting engineering and manufacturing development tasks aimed at meeting validated requirements prior to full rate production. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                          Date: June 2025 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 5: System        PE 0604604F / Submunitions Development & Demonstration (SDD)$$, NULL, 3726000, 3798000, 3871000, NULL, NULL, 92, $$FY26 Air Force Research and Development Test and Evaluation Vol II.pdf$$, NULL, FALSE, 3427000, 3502000, 3599000, 3599000, 0, 3599000, 3950000, $$Project Chicken Little (PCL) continues providing superior rapid reaction signature exploitation capabilities for use on both the traditional and the asymmetrical battlefield. PCL delivers vital one-of-a-kind research, development, test, and evaluation (RDT&E) expertise directly to the warfighter, capability developer, and allied/coalition forces. From its inception in 1985, PCL constantly advances the state-of-the-art for developmental smart munitions, seekers/sensors, and their platforms. PCL also focuses its capability against today's networked weapons, emerging weapon concepts, and assists development of innovative targeting technologies to be employed against a wide variety of vehicle targets, theater air defense units, and an extensive array of associated equipment. Combat systems and support equipment exhibit physical characteristics (i.e. signatures) and present certain vulnerabilities, which can be exploited by various targeting technologies leading to the elimination or incapacitation of the threat through the application of force (e.g. smart munitions or directed energy) or application of intelligence, surveillance, reconnaissance (ISR) methods. PCL collects physical, functional, and signature attributes of real foreign threat systems and related equipment; this data feeds high-fidelity models used to predict detection, classification, vulnerability, and effectiveness performance for ISR sensor and weapon system design. PCL collects high resolution signature data using a variety of ground, air, and space-based sensors against both new and existing (obtained, sustained, and maintained to be signature representative) foreign targets; with and without the presence of camouflage, concealment, and deception materials; and operated using enemy tactics/Concept of Operations (CONOPS). The resulting highly reliable, realistic data directly support munitions/targeting development programs and helps mitigate overall acquisition risk. PCL serves as a major focal point for joint signature exploitation, collection, and dissemination within the DoD. PCL is a prime contributor in the time critical process to rapidly exploit, assess, and determine US and allied weapon/targeting performance against high value targets. Customers include: the major Defense and Service Intelligence Centers, all Services, the Joint Technical Coordinating Group (JTCG) who develop the Joint Munitions Effectiveness Manuals (JMEMs), Combatant Commands, AF Major Commands, US Air Force Weapons School curriculum support, and others. Current projects include, but are not limited to: target signature exploitation, target geometric modeling (for identifying vulnerabilities), improving air capabilities against protected structures (specifically hard and deeply buried targets), and the testing of multiple seekers, sensors, and targeting technologies in representative environments against Combatant Command/Major Command/Intelligence Community high value targets. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                        Date: April 2026 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 5: System     PE 0604604F / Submunitions Development & Demonstration (SDD) This program is in Budget Activity 5, System Development and Demonstration (SDD) because it has passed Milestone B approval and is conducting engineering and manufacturing development tasks aimed at meeting validated requirements prior to full rate production.$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume II.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604609F$$, $$Requirements Analysis & Concept Maturation$$, $$rdte_af_ba4$$, $$aflcmc$$, 2026, 22754000, 0, 12622000, NULL, $${"ba_raw": "6.4", "source": "af_r1_fy26", "original_pe": "0604609F"}$$::jsonb, $$Capability development provides the analytic, technical, and programmatic rigor necessary to address capability gaps and opportunities to refine and mature future programs of record, prioritizing and accelerating transition of capabilities in collaboration with operational stakeholders. The Capability Development Enterprise is focused on maturing and transitioning high-impact warfighting capabilities aligned to Air Force Future Force Design through robust capability development. The Requirements Analysis and Concept Maturation (RACM) program element performs concept refinement and acquisition activities for the Capability Development Enterprise (CDE) through Planning for Development. RACM achieves this through focus on the late-stage capability development, technology maturation and risk reduction, industry planning analysis, pre-program of record development, open system designs, and Analysis of Alternatives (AoA) support. This will include the development of contracting structures that prepare for a competitive industrial base environment. These activities provide the technical basis for acquisition planning, technology transition, and Program of Record (PoR) establishment or integration of a new capability into an existing PoR. RACM provides robust, mission- and threat- informed characterization of systems and capabilities at multiple security levels, working with various appropriate Services, Agencies, and Test organizations to fully define the military utility of, and enhancements to, the USAF Force Design. RACM provides timely, data-driven decision support to senior leaders, fostering effective, affordable, and supportable systems on a path to successful programs of record. RACM supports capability and requirements analysis in support of the CDE, such as Capability Based Assessments (CBA), capability gap analysis/decomposition, Integrated Development Campaigns (IDC), and other activities as needed. Stakeholder coordination as well as acquisition enterprise alignment and advocacy occur in these foundational activities, which are critical for technology advancement and transition. This program element may include necessary civilian pay expenses required to manage, execute, and deliver RACM capabilities. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 0605829F, 0605831F, 0605833F, and 0605898F. This requirement supports performance of a full financial audit as required by title 10 U.S.C. Chapter 9A, Sec 240-D. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                     Date: June 2025 Appropriation/Budget Activity                                                     R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 4: Advanced PE 0604609F / Requirements Analysis & Concept Maturation Component Development & Prototypes (ACD&P) This effort is in Budget Activity 4, Advanced Component Development and Prototypes (ACD&P), because efforts are necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment.$$, NULL, 68618000, 92565000, 132602000, NULL, NULL, 56, $$FY26 Air Force Research and Development Test and Evaluation Vol II.pdf$$, NULL, FALSE, 12230000, 17264000, 57575000, 57575000, 0, 57575000, 172958000, $$Capability Development activities are directed and prioritized by the Air Force's Chief Modernization Officer to be responsive to Air Force priorities and Force Design. It provides the analytic, technical, and programmatic rigor necessary to address capability gaps and opportunities to refine, mature, and prepare future programs of record, thereby prioritizing and accelerating the transition of capabilities in collaboration with operational stakeholders. The Capability Development Enterprise (CDE) is focused on maturing and transitioning high-impact warfighting capabilities aligned to Air Force Future Force Design. The Requirements Analysis & Concept Maturation (RACM) Program Element performs late-stage capability development, concept refinement, and early acquisition activities for the CDE. RACM achieves this through focus on Planning for Development, rapid experimentation/prototyping, technology maturation and risk reduction, industry planning analysis, pre-Program of Record (PoR) development, open system designs, and analytic refinement support. This includes the development of contracting structures that prepare for a competitive industrial base environment. These activities provide the technical basis for acquisition planning, technology transition, and PoR establishment or integration of a new capability into an existing PoR. Additionally, RACM provides robust, mission- and threat- informed characterization of systems and capabilities at multiple security levels, working with various appropriate Services, agencies, and test organizations to fully define the military utility of, and enhancements to, the USAF Force Design. RACM provides timely, data-driven decision support to senior leaders, fostering effective, affordable, scalable, and supportable systems toward successful PoRs. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                             Date: April 2026 Appropriation/Budget Activity                                                     R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 4: Advanced PE 0604609F / Requirements Analysis & Concept Maturation Component Development & Prototypes (ACD&P) RACM provides capability and requirements analysis in support of the CDE, such as Capability Based Assessments (CBA), capability gap analysis/decomposition, and other activities as needed. Stakeholder coordination as well as acquisition enterprise alignment and advocacy occur in these foundational activities, which are critical for capability advancement and transition. In addition to traditional hardware and software, high-impact capabilities could include autonomy and Artificial Intelligence technologies that are stand-alone or embedded into new or existing systems. They could also include broad enablers such as open architectures, digital infrastructure, test infrastructure, or simulation environments. Program management support costs including, but not limited to, hardware, software, travel, contractor support services, civilian pay, supplies, facilities, and infrastructure This requirement supports performance of a full financial audit as required by title 10 U.S.C. Chapter 9A, Sec 240-D. This program element included all necessary expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 0605829F, 0605831F, 0605833F, and 0605898F. The FY 2026 funding request was reduced by 5.259 million to account for the availability of prior year execution balances. This effort is in Budget Activity 4, Advanced Component Development and Prototypes (ACD&P), because efforts are necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment.$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume II.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604610N$$, $$Lightweight Torpedo Development$$, $$rdte_navy_ba5$$, $$dw_dote$$, 2026, 100744000, 172572000, 94465000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "navy", "page_num": 33, "original_pe": "0604610N", "page_header": "Department of the Navy"}$$::jsonb, $$The Lightweight Torpedo (LWT) program designs, integrates and tests the MK 54 LWT and supports an incremental developmental acquisition approach combining hardware and Advanced Processor Build (APB) operational software upgrades to enable rapid fielding of improvements to the fleet. The program will focus on common LWT hardware and software architecture enhancements that will provide improvements to the array, warhead, propulsion, and APB software to address capability gaps against challenging adversary submarines and environments. Future APB software builds will utilize common torpedo software to deliver capability and tactics improvements to the MK 54 LWT. The program will also support development of enhanced weapon delivery methods, including the high-altitude launch of the MK 54 from the P-8A Maritime Patrol and Reconnaissance Aircraft (MPRA). The HAAWC development program provides the P-8A MPRA with the ability to release LWTs from high altitude to prosecute enemy submarine threats. Operational Testing (OT) was conducted at the end of FY 2020, and the Commander Operational Test & Evaluation Force (COMOPTEVFOR) report was issued in FY 2021, recommending fielding. Follow-on T&E (FOT&E) was conducted in FY 2022 with updated flight control software and the program delivered the HAAWC capability to the fleet in Q3 FY 2022 with Commander Patrol and Reconnaissance Group (CPRG) declaring Initial Operating Capability (IOC) in Q1 FY 2023. The current HAAWC design was developed to deploy the MK 54 MOD 0/1. The MK 54 MOD 2 is not compatible with HAAWC due to having different mass properties and outer mold line from the MK 54 MOD 0/1 LWT. The HAAWC development program was cancelled due to the restructuring of the MK 54 MOD 2 program to an incremental approach. The MK 54 MOD 1 provides significant performance improvements compared to MK 54 MOD 0 for challenging littoral, shallow water environments and adversary countermeasures. The MOD 1 program is split into 2 increments: Increment 1 focusing on the updated sonar hardware and associated APB 5 common software to provide an improved LWT to the Fleet to replace the MK 54 MOD 0s; Increment 2 is the APB 6 software (SW) only upgrade to fully take advantage of the improved sonar hardware developed under Increment 1, update the platform interface to reduce Fleet Operator workload, and provide new capabilities such as Salvo, terminal homing and Hammerhead improvements. MK 54 MOD 0 weapons will also be upgraded with APB 6 improvements compatible with MOD 0 hardware. The MK 54 MOD 2 program is continuing development to provide lethality against challenging adversary submarines. The MK 54 MOD 2 development program has transitioned to an incremental approach to reduce annual costs, delivering lethality via Increment 1 (INC 1) via a Mid-Tier Acquisition process beginning in FY 2026, followed by significantly improved speed, depth and endurance via Increment 2 (INC 2). The MK 54 MOD 2 development program will complete the Phase I Proof of Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Navy                                                                             Date: June 2025 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 5: System           PE 0604610N / Lightweight Torpedo Development Development & Demonstration (SDD) Design (POD) designs and award a contract funding the Rapid Prototyping of the INC 1 All-Up-Round (AUR), which combines the MOD 2 Forebody with the legacy MK 54 MOD 0/1 Afterbody. The program will continue derisking efforts for INC 2, ensuring the MOD 2 Stored Chemical Energy Propulsion System (SCEPS) Afterbody design is mature and ready for Rapid Prototyping at the commencement of the INC 2 phase.$$, NULL, 157749000, 160992000, 138216000, NULL, NULL, 148, $$RDTEN_BA5_Book.pdf$$, NULL, FALSE, 92266000, 5065000, 102159000, 102159000, NULL, 102159000, 130657000, $$The MK 54 provides the Navy's only lightweight ASW weapon capable of countering quiet diesel & electric submarines in contested littoral environments. The Lightweight Torpedo (LWT) program designs, integrates and tests the MK 54 LWT and supports an incremental developmental acquisition approach combining hardware and Advanced Processor Build (APB) operational software upgrades to enable rapid fielding of improvements to the fleet. The program will focus on common LWT hardware and software architecture enhancements that will provide improvements to the array, warhead, propulsion, and APB software to address capability gaps against challenging adversary submarines and environments. Future APB software builds will utilize common torpedo software to deliver capability and tactics improvements to the MK 54 LWT. The program will also support development of enhanced weapon delivery methods, including the high-altitude launch of the MK 54 from the P-8A Maritime Patrol and Reconnaissance Aircraft (MPRA). The MK 54 MOD 1 provides significant performance improvements compared to MK 54 MOD 0 for challenging littoral, shallow water environments and adversary countermeasures. The MOD 1 program is split into 2 increments: Increment 1 focusing on the updated sonar hardware and associated APB 5 common software to provide an improved LWT to the Fleet to replace the MK 54 MOD 0s; Increment 2 is the APB 6 software (SW) only upgrade to fully take advantage of the improved sonar hardware developed under Increment 1 (MK 54 MOD 1 P1/APB 5), update the platform interface to reduce Fleet Operator workload (enhanced Digital Fire Control Interface (eDFCI), and provide new capabilities such as Salvo, terminal homing (required for MK 54 MOD 2 INC 1), MK 54 Torpedo Defense Hard Kill (TDHK) (MK 54 Anti-Torpedo Torpedo) capability, and Hammerhead improvements. MK 54 MOD 0 weapons will also be upgraded with APB 6 improvements compatible with MOD 0 hardware, to provide MK 54 TDHK capability. The APB 6 SW baseline is a common software development effort that will meet the combined requirements, enabling these requirements in MK 54 MOD 0 FY11/FY16, MK 54 MOD 1 P1/P2 and MK 54 MOD 2 INC 1 hardware configurations. Long-Range Anti-Submarine Warfare Weapon (LRAW) Development will provide capability that extends range past the range of the current VLA systems. LRAW will provide future surface combatants with organic ASW capability. CRUDES capability for offensive ASW is limited to the current VLA ranges which may not be adequate for all scenarios. Current VLA inventory is rapidly diminishing and will only be sustained at minimum quantities based on maintenance funding. In FY 2027 the program Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                                  Date: April 2026 Appropriation/Budget Activity                                                      R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 5: System                PE 0604610N / Lightweight Torpedo Development Development & Demonstration (SDD) will begin development consisting of modification to existing VLA rocket, initiate design, design containers and test equipment, build test articles, and conduct an Engineering, qualification, DT, and OT test program. The MK 54 MOD 2 program is continuing development to provide lethality against challenging adversary submarines. The MK 54 MOD 2 development program has transitioned to an incremental approach to reduce annual costs, delivering lethality via Increment 1 (INC 1) via a Mid-Tier Acquisition process beginning in FY 2026, followed by significantly improved speed, depth endurance, and detection range via Increment 2 (INC 2). The MK 54 MOD 2 development program will complete the Phase I Proof of Design (POD) designs and award a contract funding the Rapid Prototyping of the INC 1 All-Up-Round (AUR), which combines the MOD 2 Forebody with the legacy MK 54 MOD 0/1 Afterbody. The program will continue de-risking efforts for INC 2, ensuring the MOD 2 Stored Chemical Energy Propulsion System (SCEPS) Afterbody design is mature and ready for Rapid Prototyping at the commencement of the INC 2 phase. The FY 2026 spend plan includes $5,065 thousand discretionary and $88,179 thousand mandatory (reconciliation) for a total of $93,244 thousand. The mandatory funds support the development, testing, and evaluation of the Advanced Lightweight Torpedo including Proof of Manufacturing, Afterbody, Warhead, and All-Up-Round Other Transactional Authority (OTA) Contracts.$$, $$Budget J-Books/FY27/Navy/RDTEN_BA5_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604617F$$, $$Agile Combat Support$$, $$rdte_af_ba5$$, $$aflcmc_az$$, 2026, 23474000, 0, 23635000, NULL, $${"source": "jbook_fy26"}$$::jsonb, $$This program provides lighter, leaner, rapidly-deployable and technologically-advanced material, and capabilities to the warfighter. Current projects in this program include Civil Engineering Readiness (Project 652895) and Aeromedical Readiness (Project 654910). Civil Engineering Readiness projects enable airfield protection, and airfield damage recovery for sustainment, and increased resiliency of airfield operations anywhere in the world. Aeromedical Readiness projects provide aerospace medical systems and treatment equipment to improve casualty care and meet worldwide warfighter medical operational requirements. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, and 0606398F. In FY25 $0.000 was expended for civilian pay expenses in this program element, and in FY26 $0.000 is forecast for civilian pay expenses in this program element. This program is in Budget Activity 5, System Development and Demonstration (SDD) because it has passed Milestone B approval and is conducting engineering and manufacturing development tasks aimed at meeting validated requirements prior to full rate production.$$, NULL, 20124000, 20536000, 20925000, NULL, NULL, 93, $$FY26 Air Force Research and Development Test and Evaluation Vol II.pdf$$, NULL, FALSE, 22977000, 23235000, 19348000, 19348000, 0, 19348000, 21348000, $$This program provides lighter, leaner, rapidly-deployable and technologically-advanced material, and capabilities to the warfighter. Current projects in this program include Civil Engineering Readiness (Project 652895) and Aeromedical Readiness (Project 654910). Civil Engineering Readiness projects enable airfield protection, and airfield damage recovery for sustainment, and increased resiliency of airfield operations anywhere in the world. Aeromedical Readiness projects provide aerospace medical systems and treatment equipment to improve casualty care and meet worldwide warfighter medical operational requirements. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, and 0606398F. This program is in Budget Activity 5, System Development and Demonstration (SDD) because it has passed Milestone B approval and is conducting engineering and manufacturing development tasks aimed at meeting validated requirements prior to full rate production.$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume II.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604617F_ba7$$, $$Agile Combat Support$$, $$rdte_af_ba7$$, $$aflcmc_az$$, 2026, 0, 5446000, 0, NULL, $${"ba_raw": "6.7", "source": "af_r1_fy26", "original_pe": "0604617F"}$$::jsonb, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604633A$$, $$Air Traffic Control$$, $$rdte_army_ba5$$, $$asa_alt$$, 2026, 0, 11093000, 982000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "army", "page_num": 16, "fy26_v180": {"note": "R1_FY26_entry_no_value_extracted_in_original_ingest", "source": "b1_null_zero_v180"}, "original_pe": "0604633A", "page_header": "Department of the Army"}$$::jsonb, $$Program Element (PE) 0604633A Air Traffic Control funds continuous efforts in the development of modernized tactical Air Traffic Control (ATC) systems that enable safety of aircraft operations. ATC systems are required to achieve or maintain compliance with civil, military, domestic and international ATC mandates and combat identification requirements. The Tactical Airspace Integration System (TAIS) is the Army's program of record for Airspace Control (AC) and enroute Air Traffic Services (ATS). TAIS provides Airspace Management, planning, and dynamic execution capabilities at all echelons above Brigade, and enroute flight following air traffic services. TAIS is the only Army system with direct interface to the U.S. Air Force Air Operations Center (AOC) Weapon System for submission of the Army's requests for airspace from the Battlefield Coordination Detachment (BCD). Airspace Coordinating Measure Requests (ACMREQs) received from other mission command systems are passed to TAIS for approval or higher coordination. TAIS software supports U.S. Army commanders, airspace users, airspace managers, Army air traffic controllers, Joint organizations, and Unified Action Partners (UAP) by providing digitized, multi-echelon planning and execution of airspace management and Air Traffic Services. TAIS provides AC planning and enhanced AC execution; improved theater, intra-, and inter-Corps/Division Air Traffic Services (ATS) support; effective battlespace synchronization; and direct links to the Theater Air Ground System (TAGS) through interface with the automated airspace planning and communications systems of the Joint Force Air Component Commander (JFACC). TAIS Common Operating Environment (COE) convergence to Integrated Mission Planning and Airspace Control Tools (IMPACT) will provide interoperability with Army Mission Command, Joint, and UAP systems. This will facilitate AC capabilities, enhance situational understanding, reduce risks, and provide more effective Air-Ground Integration to enable Next Generation Command and Control (NGC2), Multi-Domain Operations (MDO), Joint All Domain Operations (JADO), and Joint All Domain Command and Control (JADC2). IMPACT will be instantiated across Command Post Computing Environment (CE), Mounted CE, and Mobile/Handheld CE and will extend AC services to the tactical edge. TAIS/IMPACT will leverage Air Space Total Awareness for Rapid Tactical Execution (ASTARTE) technology. ASTARTE provides artificial intelligence and machine learning algorithms which will allow IMPACT to achieve more rapid synchronization of airspace planning and dynamic execution. This will enable commanders to maximize airspace usage, increase freedom of maneuver in the 3rd dimension, enhance safety and fratricide prevention, and enable seamless integration / deconfliction of fires and aviation operations in highly congested and complex environments during Large Scale Combat Operations (LSCO). The Air Traffic Navigation Integration and Coordination System (ATNAVICS) is a highly mobile Airport Surveillance Radar and Precision Approach Radar system that provides Air Traffic Services at Army airfields and landing sites at Division, Corps, and Echelons above Corps to include services for Joint and Allied aircraft. ATNAVICS integrates capabilities to control aircraft both Outside of the Continental United States and in the Continental United States. ATNAVICS is upgrading the Interrogation Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                                     Date: June 2025 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 5: System              PE 0604633A / Air Traffic Control Development & Demonstration (SDD) Identification Friend-or-Foe (IFF) system to maintain international airspace compatibility, capture flight information through the reception of aircraft self-reporting data broadcasts, and process into an interconnected air picture. This funding supports the Army's Next Generation Command and Control (NGC2) initiative to modernize Command and Control (C2) systems.$$, NULL, NULL, NULL, NULL, NULL, NULL, 107, $$RDTE - Vol 3 - Budget Activity 5A.pdf$$, NULL, FALSE, 946000, 0, NULL, NULL, NULL, NULL, NULL, $$Program Element (PE) 0604633A Air Traffic Control funds continuous efforts in the development of modernized tactical Air Traffic Control (ATC) systems that enable safety of aircraft operations. ATC systems are required to achieve or maintain compliance with civil, military, domestic and international ATC mandates and combat identification requirements. This PE supports the development of hardware and the continuous integration and continuous development/delivery of software to support modernized tactical Air Traffic Control (ATC) requirements. The Tactical Airspace Integration System (TAIS) is the Army's program of record for Airspace Control (AC) and enroute Air Traffic Services (ATS). The Integrated Mission Planning and Airspace Control Tools (IMPACT) hardware agnostic software effort was the software convergence product for TAIS AC requirements to inform/support the transition of TAIS AC to the Next Generation Command and Control (NGC2) Airspace Management, planning, and dynamic execution capability. IMPACT planned to leverage Air Space Total Awareness for Rapid Tactical Execution (ASTARTE) technology. These efforts are to enable commanders the ability to maximize airspace usage, increase freedom of maneuver in the 3rd dimension, enhance safety and fratricide prevention, and enable seamless integration / deconfliction of fires and aviation operations in highly congested and complex environments during Large Scale Combat Operations (LSCO).$$, $$Budget J-Books/FY27/Army/RDTE - Vol 3 - Budget Activity 5A.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604636N$$, $$Counter Unmanned Aircraft System (C-UAS)$$, $$rdte_navy_ba4$$, $$asn_rda$$, 2026, 23189000, 23661000, 14185000, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "navy", "page_num": 31, "original_pe": "0604636N", "page_header": "Department of the Navy"}$$::jsonb, $$The Counter Unmanned Aircraft System (C-UAS) program employs integrated C-UAS solution sets designed to protect high value or critical Naval assets from surveillance, or hostile threats posed from the inadvertent or unlawful misuse of unmanned aircraft systems (UAS). The C-UAS program provides an integrated Family of Systems (FoS) employing advanced target discrimination and defeat capabilities to meet fleet requirements. More details available at a higher classification level. FY 2026 funding is requested to continue management and implementation of system assessment. Provide program management and systems engineering support for the technology development and acquisition strategy for fielding material solution. Funding provides for refinement of material solutions, threat assessments, identification and development of advanced target discrimination, defeat capabilities, and prototype development for integration into the C-UAS FoS. Continues refinement of open architecture solution and interoperability standards for a C-UAS FoS. In partnership with the Joint C-UAS Office (JCO), will identify or develop additional detect and deter capabilities to integrate into the C-UAS FoS. As the JCO designated CORIAN Acquisition Lead, continued development, implementation and integration of additional sensor modalities to improve system detect/ID/track/defeat capabilities. Continues efforts to improve interoperability between ashore and afloat C-UAS systems.$$, NULL, 21501000, 21832000, 22098000, NULL, NULL, 92, $$RDTEN_BA4_Book.pdf$$, NULL, FALSE, 15422000, 16689000, 20833000, 20833000, NULL, 20833000, 22488000, $$The Counter Unmanned Aircraft System (C-UAS) program employs integrated C-UAS solution sets designed to protect high value or critical Naval assets from surveillance, or hostile threats posed from the inadvertent or unlawful misuse of unmanned aircraft systems (UAS). The C-UAS program provides an integrated Family of Systems (FoS) employing advanced target discrimination and defeat capabilities to meet fleet requirements. More details available at a higher classification level. FY 2027 funding is requested to continue management and implementation of system assessment. Provide program management and systems engineering support for the technology development and acquisition strategy for fielding material solution. Funding provides for refinement of material solutions, threat assessments, identification and development of advanced target discrimination, defeat capabilities, and prototype development for integration into the C-UAS FoS. Continues refinement of open architecture solution and interoperability standards for a C-UAS FoS. In partnership with the Joint C-UAS Office (JCO), will identify or develop additional detect and deter capabilities to integrate into the C-UAS FoS. As the JCO designated CORIAN Acquisition Lead, continued development, implementation and integration of additional sensor modalities to improve system detect/ID/track/defeat capabilities. Continues efforts to improve interoperability between ashore and afloat C-UAS systems.$$, $$Budget J-Books/FY27/Navy/RDTEN_BA4_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604641A$$, $$Tactical Unmanned Ground Vehicle (TUGV)$$, $$rdte_army_ba5$$, $$cft_ngcv$$, 2026, 0, 136937000, 92540000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "army", "page_num": 16, "fy26_v180": {"note": "R1_FY26_entry_no_value_extracted_in_original_ingest", "source": "b1_null_zero_v180"}, "original_pe": "0604641A", "page_header": "Department of the Army"}$$::jsonb, $$This funding line is directly aligned to the Next Generation Combat Vehicle Army Modernization Priority. The Robotic Combat Vehicle (RCV) is a transformational capability that will forever change ground maneuver warfare. The RCV enables commanders to dictate the terms of the first human engagement by leveraging the RCV to shape and degrade threats across the multi-domain battlefield. The RCV will operate as a system of systems including a Manned Control Vehicle (MCV) outfitted with multiple Control Stations and unmanned RCV platforms outfitted with Modular Mission Payloads (MMPS) that commanders can tailor to their mission requirements. The Robotic Combat Vehicle (RCV) Middle Tier Acquisition-Rapid Prototype (MTA-RP) program was funded through RDT&E appropriation via lines 643645EV7, 644107CF4 and 654641CF5. The total investment of the program prior to Army Transformation Initiative (ATI) Executive Order (EXORD) directing to cease development of RCV Hardware was $225M Base-Year 2025 (BY25) dollars. Future development efforts focused on Software Pathway (SWP), as well as autonomous and unmanned system initiatives, will be funded under RDT&E lines 644017FD9 and 655053FB3.$$, NULL, NULL, NULL, NULL, NULL, NULL, 108, $$RDTE - Vol 3 - Budget Activity 5A.pdf$$, NULL, FALSE, 89162000, 0, NULL, NULL, NULL, NULL, NULL, $$This funding line is directly aligned to the Next Generation Combat Vehicle Army Modernization Priority. The Robotic Combat Vehicle (RCV) is a transformational capability that will forever change ground maneuver warfare. The RCV enables commanders to dictate the terms of the first human engagement by leveraging the RCV to shape and degrade threats across the multi-domain battlefield. The RCV will operate as a system of systems including a Manned Control Vehicle (MCV) outfitted with multiple Control Stations and unmanned RCV platforms outfitted with Modular Mission Payloads (MMPS) that commanders can tailor to their mission requirements.$$, $$Budget J-Books/FY27/Army/RDTE - Vol 3 - Budget Activity 5A.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604645A$$, $$Armored Systems Modernization (ASM) - Eng Dev$$, $$rdte_army_ba5$$, $$asa_alt_alt$$, 2026, 16593000, 95580000, 48097000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "army", "page_num": 16, "fy26_v180": {"note": "R1_FY26_entry_no_value_extracted_in_original_ingest", "source": "b1_null_zero_v180"}, "original_pe": "0604645A", "page_header": "Department of the Army"}$$::jsonb, $$Infantry Brigade Combat Teams (IBCTs) currently lack the mobile, protected firepower capability necessary to defeat enemy prepared positions, destroy enemy armored vehicles, close with the enemy through fire and maneuver, and ensure freedom of maneuver and action in close contact with the enemy. The M10 Booker (formerly, Mobile Protected Firepower (MPF)) will provide the Army's IBCTs a protected, long range, precision direct-fire capability to ensure freedom of movement during offensive operations and defeat attacking enemy during defensive operations. The FY 2026 request was reduced by $0.394 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative."$$, NULL, NULL, NULL, NULL, NULL, NULL, 110, $$RDTE - Vol 3 - Budget Activity 5A.pdf$$, NULL, FALSE, 46341000, 0, NULL, NULL, NULL, NULL, NULL, $$Infantry Brigade Combat Teams (IBCTs) currently lack the mobile, protected firepower capability necessary to defeat enemy prepared positions, destroy enemy armored vehicles, close with the enemy through fire and maneuver, and ensure freedom of maneuver and action in close contact with the enemy. The M10 Booker (formerly, Mobile Protected Firepower (MPF)) will provide the Army's IBCTs a protected, long range, precision direct-fire capability to ensure freedom of movement during offensive operations and defeat attacking enemy during defensive operations.$$, $$Budget J-Books/FY27/Army/RDTE - Vol 3 - Budget Activity 5A.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604654N$$, $$JNT Service EOD$$, $$rdte_navy_ba5$$, $$asn_rda$$, 2026, 8740000, 8707000, 8810000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "navy", "page_num": 34, "original_pe": "0604654N", "page_header": "Department of the Navy"}$$::jsonb, $$This program, aligned with the National Defense Strategy, provides Joint Service Explosive Ordnance Disposal (EOD) and the supported Combatant Commanders with information superiority by providing for the development of Unexploded Explosive Ordnance (UXO), Improvised Explosive Devices (IED), Weapons of Mass Destruction (WMD), and weapons systems Technical Manuals (TMs). TMs, which provide key identification features, hazardous materials, and safety information, are paramount to the success of EOD Mission to detect, locate, access, identify, Render Safe/Neutralize, and dispose or recover both foreign and domestic explosive threats that pose a threat to military operations, installations, personnel, and materials. In addition, EOD Render Safe Procedures (RSP) and Disposal Procedures must be developed prior to fielding in the case of U.S. weapons and ordnance and as soon as possible after gaining knowledge of existence as it pertains to foreign ordnance and other explosive threats. These efforts require collection, exploitation, and analysis of the ordnance items and associated components, e.g., fuzing, prior to the development of EOD procedures. As defined in DOD Directive 5160.62, assigns the Secretary of the Navy (SECNAV) the responsibility of Executive Agent for Explosive Ordnance Disposal (EOD) Technology and Training (T&T). The Executive Agent for EOD T&T is to provide for the preparation, technical development, validation, Joint Service approval, and distribution of all EOD procedures and countermeasures to include publications, manuals, bulletins, texts, and graphic aids. This program is a non-acquisition program (without traditional acquisition milestones) with on-going, continuous delivery of urgent and periodic documented procedures and publications for mines, ordnance items, weapons systems, Improvised Explosive Devices, Weapons of Mass Destruction, and related explosive hazards.$$, NULL, 8730000, 8854000, 8872000, NULL, NULL, 149, $$RDTEN_BA5_Book.pdf$$, NULL, FALSE, 8774000, 8740000, 8509000, 8509000, NULL, 8509000, 9031000, $$This program, aligned with the National Defense Strategy, provides Joint Service Explosive Ordnance Disposal (EOD) and the supported Combatant Commanders with information superiority by providing for the development of Unexploded Explosive Ordnance (UXO), Improvised Explosive Devices (IED), Weapons of Mass Destruction (WMD), and weapons systems Technical Manuals (TMs). TMs, which provide key identification features, hazardous materials, and safety information, are paramount to the success of EOD Mission to detect, locate, access, identify, Render Safe/Neutralize, and dispose or recover both foreign and domestic explosive threats that pose a threat to military operations, installations, personnel, and materials. In addition, EOD Render Safe Procedures (RSP) and Disposal Procedures must be developed prior to fielding in the case of U.S. weapons and ordnance and as soon as possible after gaining knowledge of existence as it pertains to foreign ordnance and other explosive threats. These efforts require collection, exploitation, and analysis of the ordnance items and associated components, e.g., fuzing, prior to the development of EOD procedures. As defined in DOD Directive 5160.62, assigns the Secretary of the Navy (SECNAV) the responsibility of Executive Agent for Explosive Ordnance Disposal (EOD) Technology and Training (T&T). The Executive Agent for EOD T&T is to provide for the preparation, technical development, validation, Joint Service approval, and distribution of all EOD procedures and countermeasures to include publications, manuals, bulletins, texts, and graphic aids. This program is a non-acquisition program (without traditional acquisition milestones) with on-going, continuous delivery of urgent and periodic documented procedures and publications for mines, ordnance items, weapons systems, Improvised Explosive Devices, Weapons of Mass Destruction, and related explosive hazards.$$, $$Budget J-Books/FY27/Navy/RDTEN_BA5_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604657M$$, $$MARINE CORPS GROUND COMBAT/SUPPORTING ARMS SYST$$, $$rdte_navy_ba5$$, $$mc$$, 2026, 17377000, 33610000, 33880000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "mc", "page_num": 34, "original_pe": "0604657M", "page_header": "Department of the Navy"}$$::jsonb, $$Organic Precision Fires (OPF) is a Service Force Design priority and will provide multiple echelons of the Fleet Marine Force with an organic, loitering, beyond-line-of- sight precision strike capability. OPF will be employed at the tactical level to allow Marines to rapidly engage the enemy beyond the range of direct fire weapons while minimizing collateral damage and exposure to enemy direct and indirect fires. OPF has demonstrated through extensive war-gaming and simulation, combined with experience gained in real world operations, that it will significantly improve the organic lethality of infantry and reconnaissance formations.$$, NULL, 23536000, 918000, 932000, NULL, NULL, 150, $$RDTEN_BA5_Book.pdf$$, NULL, FALSE, 32576000, 17377000, 69478000, 69478000, NULL, 69478000, 948000, $$The Organic Precision Fires (OPF) program supports the Commandant of the Marine Corps' (CMC) Force Design initiative, and is in direct response to the Secretary of War's mandate for a more lethal and distributed Joint Force. This program equips multiple levels of command within the Fleet Marine Force with an organic, loitering, and precise "over-the-horizon" strike capability, fundamentally changing the tactical equation at all levels from the squad to the battalion. By placing this capability directly into the hands of our infantry and reconnaissance Marines, OPF empowers them to engage the enemy immediately upon detection, well beyond the range of their direct-fire weapons. This increases the lethality while simultaneously enhancing the survivability by minimizing exposure to enemy fire. Extensive war-gaming, simulation, and real-world operational experience have validated that OPF is not merely an incremental improvement; it is a transformational leap in combat effectiveness. It provides the small-unit leader with the tools to create dilemmas for our adversaries, hold key maritime terrain, and thrive in complex, distributed environments where traditional fire support may be unavailable or too slow to respond. This program is essential to building the agile, highly lethal force required to win in the contested battlefields of the future.$$, $$Budget J-Books/FY27/Navy/RDTEN_BA5_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604668F$$, $$Joint Transportation Management System (JTMS)$$, $$rdte_af_ba4$$, $$aflcmc$$, 2026, 129626000, 26036000, 74103000, NULL, $${"ba_raw": "6.4", "source": "af_r1_fy26", "original_pe": "0604668F"}$$::jsonb, $$This initiative fields a commercial-off-the-shelf (COTS) Enterprise Resource Planning (ERP) solution that will fuse the transportation and financial domains throughout the Joint Deployment and Distribution Enterprise (JDDE) to achieve auditability, transparency, and optimized resource allocation. The program will deliver integrated, streamlined transportation and financial data and processes, supporting the Joint Deployment and Distribution Enterprise (JDDE). Services and DoD agencies will have a system to automate the linkage between transportation action tasks and transportation business related tasks across the full spectrum of financial activity, from obligations through general ledger accounting. It will also close all major gaps that prevent auditability within the transportation spend across DoD and achieve significant gains in two of the focus areas of the Department of Defense's Data Strategy: Senior Leader Decision Support and Business Analytics. Through the JTMS's ability to seamlessly integrate financial data and information with transportation operations in the joint domain, it will give JDDE users the ability to see to the transactional level in a resilient transportation network while reducing duplicate capabilities. This requirement supports performance of a full financial audit as required by title 10 U.S.C. Chapter 9A, Sec 240-D. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system like capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY 2024 the program expended $6.7 million for civilian pay in this program element, and in FY25 the program forecasts $8.92 million for civilian pay expenses in this program element. This effort is in Budget Activity 4, Advanced Component Development and Prototypes (ACD&P), because efforts are necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                       Date: June 2025 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 4: Advanced PE 0604668F / Joint Transportation Management System (JTMS) Component Development & Prototypes (ACD&P)$$, NULL, 96499000, 150148000, 122683000, NULL, NULL, 57, $$FY26 Air Force Research and Development Test and Evaluation Vol II.pdf$$, NULL, FALSE, 71552000, 124787000, 57802000, 57802000, 0, 57802000, 105052000, $$This initiative fields a commercial-off-the-shelf (COTS) Enterprise Resource Planning (ERP) solution that will fuse the transportation and financial domains throughout the Joint Deployment and Distribution Enterprise (JDDE) to achieve auditability, transparency, and optimized resource allocation. The program will deliver integrated, streamlined transportation and financial data and processes, supporting the Joint Deployment and Distribution Enterprise (JDDE). Services and Department of War (DoW) agencies will have a system to automate the linkage between transportation action tasks and transportation business related tasks across the full spectrum of financial activity, from obligations through general ledger accounting. It will also close all major gaps that prevent auditability within the transportation spend across DoW and achieve significant gains in two of the focus areas of the DoW's Data Strategy: Senior Leader Decision Support and Business Analytics. Through the JTMS's ability to seamlessly integrate financial data and information with transportation operations in the joint domain, it will give JDDE users the ability to see to the transactional level in a resilient transportation network while reducing duplicate capabilities. This requirement supports performance of a full financial audit as required by title 10 U.S.C. Chapter 9A, Sec 240-D. This program element included all necessary expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 0605829F, 0605831F, 0605833F, and 0605898F. FY 2025 was rescinded $27.916 million and is not reflected in this budget documentation. This effort is in Budget Activity 4, Advanced Component Development and Prototypes (ACD&P), because efforts are necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                   Date: April 2026 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 4: Advanced PE 0604668F / Joint Transportation Management System (JTMS) Component Development & Prototypes (ACD&P)$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume II.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604669D8Z$$, $$Microelectronics Commons - 0400D$$, $$rdte_dw_ba4$$, $$dw_ousd_re$$, 2026, 0, 65682000, 0, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "dw", "page_num": 72, "original_pe": "0604669D8Z", "page_header": "Defense-Wide"}$$::jsonb, $$This Program Element supports the Department's initiatives to Build Sustainable and Long-Term Advantage, Defend the Homeland, and Deter Aggression. The Office of the Under Secretary of Defense for Research and Engineering (OUSD(R&E)) is executing the Microelectronics Commons (the Commons) activity pursuant to the Fiscal Year (FY) 2021 National Defense Authorization Act (NDAA) (Pub. L. 116-283), including the CHIPS for America Act, and funded through the CHIPS for America Defense Fund established by the CHIPS Act of 2022. The FY 2021 NDAA legislation significantly emphasized solutions that promote the domestic on-shoring of capabilities to address economic and technology security concerns. Under FY 2021 NDAA Sec. 9903(b), the DOD was directed to establish a National Network for Microelectronics Research and Development (NNMRD) to enable the laboratory-to-fabrication transition of microelectronics innovations in the United States and to expand the global leadership in microelectronics of the United States. Specifically, the DOD is addressing a component of the NNMRD, the Commons, through a public- private partnership consisting of regional innovation hubs distributed across the U.S. to foster a pipeline of innovative ideas and talent residing in, for example, university labs and small business R&D teams. Background U.S. technological dominance in microelectronics materials, processes, devices, and architectural designs can only be sustained through the development of a robust domestic innovation ecosystem that fosters the rapid development and transition of novel concepts into commercially viable manufacturing processes. The U.S. innovation ecosystem has long been the driver of our nation’s technology leadership throughout the world. U.S. R&D kick-started the enormous semiconductor industry and continues to lead the world in developing the next generation of disruptive technologies including new materials, devices, circuits, architectures, and design tools. In recent years, the efficient domestic adoption of U.S. chip innovation has been threatened as emerging hardware technologies have become increasingly reliant on offshore sources for State of the Art (SOTA) manufacturing, prototyping, and investment. There are several significant hurdles that hardware startups face, including limited or expensive access to necessary facilities and design infrastructure, high costs of design intellectual property, limited expertise with hardware engineering, and Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Office of the Secretary Of Defense                                                   Date: June 2025 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 4:            PE 0604669D8Z / Microelectronics Commons - 0400D Advanced Component Development & Prototypes (ACD&P) high costs of prototyping. As a result, the number of U.S. hardware startups has dropped significantly and foreign investment in U.S.-based technology startups has enabled offshore fabrication and maturation of emerging technologies. To address these needs, OUSD(R&E) is standing up the Commons as a public private partnership, consisting of regional innovation hubs distributed across the U.S. to foster a pipeline of innovative ideas and talent residing in university labs and small business R&D teams. The partnership will provide resources for and access to specialized lab equipment, technical expertise, and connections to existing or upgraded prototyping facilities. Fabrication facilities (fabs) will help mature promising technologies and demonstrate the manufacturing and economic benefits of these innovations for dual-use application for defense and commercial sectors. The Commons focuses on critical, on-shore prototyping to transition innovation from universities, start-ups, and small companies to fabrication facilities (lab-to-fab transition). Key features include: • Creates and connects “Lab-to-Fab” testing/prototyping hubs to form a network focused on maturing emerging microelectronics technologies • Provides broad access to these prototyping hubs, potentially by augmenting facilities and enabling access to facilities within local semiconductor companies or FFRDCs. • Facilitates microelectronics education and training of students at local colleges and universities and grows a talent pipeline to bolster local semiconductor economies and contribute more broadly to the growth of a domestic semiconductor workforce. This program element focuses on the advanced component development and advanced prototyping activities of the Commons, including staffing at Commons Hub facilities, prototype development, and the establishment and development of a path for successful Lab-to-Fab technology transition. The Commons will establish early and sustained engagement with industry and academic stakeholders to build consensus on technology roadmaps to guide maturation and delivery of innovation into a given commercial fab’s pilot line and production plans.$$, 0, 0, NULL, NULL, NULL, NULL, 115, $$RDTE_OSD_PB_2026.pdf$$, $$OSD$$, FALSE, 62704000, 0, 0, 0, NULL, 0, NULL, $$This Program Element supports the Department's initiatives to Build Sustainable and Long-Term Advantage, Defend the Homeland, and Deter Aggression. The Office of the Under Secretary of War for Research and Engineering (OUSW(R&E)) is executing the Microelectronics Commons (the Commons) activity pursuant to the Fiscal Year (FY) 2021 National Defense Authorization Act (NDAA) (Pub. L. 116-283), including the CHIPS for America Act, and funded through the CHIPS for America Defense Fund established by the CHIPS Act of 2022. The FY 2021 NDAA legislation significantly emphasized solutions that promote the domestic on-shoring of capabilities to address economic and technology security concerns. Under FY 2021 NDAA Sec. 9903(b), the DoW was directed to establish a National Network for Microelectronics Research and Development (NNMRD) to enable the laboratory-to-fabrication transition of microelectronics innovations in the United States and to expand the global leadership in microelectronics of the United States. Specifically, the DoW is addressing a component of the NNMRD, the Commons, through a public- private partnership consisting of regional innovation hubs distributed across the U.S. to foster a pipeline of innovative ideas and talent residing in, for example, university labs and small business R&D teams. Background U.S. technological dominance in microelectronics materials, processes, devices, and architectural designs can only be sustained through the development of a robust domestic innovation ecosystem that fosters the rapid development and transition of novel concepts into commercially viable manufacturing processes. The U.S. innovation ecosystem has long been the driver of our nation’s technology leadership throughout the world. U.S. R&D kick-started the enormous semiconductor industry and continues to lead the world in developing the next generation of disruptive technologies including new materials, devices, circuits, architectures, and design tools. In recent years, the efficient domestic adoption of U.S. chip innovation has been threatened as emerging hardware technologies have become increasingly reliant on offshore sources for State of the Art (SOTA) manufacturing, prototyping, and investment. There are several significant hurdles that hardware startups face, including limited or expensive access to necessary facilities and design infrastructure, high costs of design intellectual property, limited expertise with hardware engineering, and Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Office of the Secretary Of Defense                                                  Date: April 2026 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 4:            PE 0604669D8Z / Microelectronics Commons - 0400D Advanced Component Development & Prototypes (ACD&P) high costs of prototyping. As a result, the number of U.S. hardware startups has dropped significantly and foreign investment in U.S.-based technology startups has enabled offshore fabrication and maturation of emerging technologies. To address these needs, OUSW(R&E) is standing up the Commons as a public private partnership, consisting of regional innovation hubs distributed across the U.S. to foster a pipeline of innovative ideas and talent residing in university labs and small business R&D teams. The partnership will provide resources for and access to specialized lab equipment, technical expertise, and connections to existing or upgraded prototyping facilities. Fabrication facilities (fabs) will help mature promising technologies and demonstrate the manufacturing and economic benefits of these innovations for dual-use application for defense and commercial sectors. The Commons focuses on critical, on-shore prototyping to transition innovation from universities, start-ups, and small companies to fabrication facilities (lab-to-fab transition). Key features include: • Creates and connects “Lab-to-Fab” testing/prototyping hubs to form a network focused on maturing emerging microelectronics technologies • Provides broad access to these prototyping hubs, potentially by augmenting facilities and enabling access to facilities within local semiconductor companies or FFRDCs. • Facilitates microelectronics education and training of students at local colleges and universities and grows a talent pipeline to bolster local semiconductor economies and contribute more broadly to the growth of a domestic semiconductor workforce. This program element focuses on the advanced component development and advanced prototyping activities of the Commons, including staffing at Commons Hub facilities, prototype development, and the establishment and development of a path for successful Lab-to-Fab technology transition. The Commons will establish early and sustained engagement with industry and academic stakeholders to build consensus on technology roadmaps to guide maturation and delivery of innovation into a given commercial fab’s pilot line and production plans.$$, $$Budget J-Books/FY27/DW/RDTE_OSW_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604679D8Z$$, $$Office of Strategic Capital (OSC)$$, $$rdte_dw_ba4$$, $$dw$$, 2026, 21318000, 0, 0, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "dw", "page_num": 72, "original_pe": "0604679D8Z", "page_header": "Defense-Wide"}$$::jsonb, $$In support of the Department of Defense, Office of Strategic Capital’s (OSC) mission is to attract and scale private capital to technologies critical to the national and economic security of the United States. The National Defense Authorization Act for Fiscal Year 2024 (FY2024 NDAA) states OSC shall: • Develop, integrate, and implement capital investment strategies proven in the commercial sector to shape and scale investment in critical technologies and assets; • Identify and prioritize promising critical technologies and assets that require funding and have the potential to benefit DoD; and • Make eligible investments in such technologies and assets, such as supply chain technologies, not always supported through direct investment. To accomplish its mission, OSC uses loans, loan guarantees, and technical assistance – an efficient use of taxpayer dollars – to crowd in investment by aligning government and private sector incentives. The office’s tools take advantage of the power of markets and competition to support DoD needs. OSC’s investments are guided by its FY2025 Investment Strategy, which describes that competition between the United States and its adversaries occurs over the: (i) control of economic chokepoints; (ii) scaling of key industries, and (iii) commercialization of critical technologies. OSC investments will provide the Department of Defense advantages in all these competitive arenas, especially by securing critical supply chains and rebuilding the industrial base. These activities directly align with the administration’s priorities communicated through the Interim National Defense Strategic Guidance (INDSG), and other forthcoming authoritative documents such as the National Security Strategy of the United States (NSS), Interim National Defense Strategy (NDS) and Defense Planning Guidance (DPG). Specifically, the program will: • Develop new financial products, such as direct equipment finance loans for manufacturers, project finance loans to support capital intensive projects, working capital loans for businesses in need of short-term financing, and loan guarantees through private banks. • Provide loans, loan guarantees and technical assistance to businesses, funds, and other entities within the 33 Covered Technology Categories prescribed by Congress in line with the objectives described by the FY25 Investment Strategy, INDSG, NSS, NDS, and DPG. • Identify and prioritize areas for investment through engagements with the Services, Combatant Commands, National Security Council, and other interagency partners. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Office of the Secretary Of Defense                                                 Date: June 2025 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 4:           PE 0604679D8Z / Office of Strategic Capital (OSC) Advanced Component Development & Prototypes (ACD&P) • Create new data tools to map economic networks to determine chokepoints that impact U.S. national and economic security. • Increase private capital investment to enhance the commercialization of DoD and United States Government (USG) science & technology investments.$$, NULL, 30029000, 30802000, 31619000, NULL, NULL, 116, $$RDTE_OSD_PB_2026.pdf$$, $$OSD$$, FALSE, 0, 2000000, 18955000, 18955000, NULL, 18955000, 32996000, $$The Office of Strategic Capital's (OSC) mission is to attract and scale capital in technology and assets that support national security. Specifically, the OSC employs unique Title 10 federal credit authorities and appropriations to crowd investment through loans, loan guarantees, and technical assistance, efficiently using taxpayer dollars that support Department of War needs. Since its authorization, the OSC has begun developing and rapidly deploying new financial products to accelerate private investment in the industrial base across Covered Technology Categories prescribed by Congress. These tools will crowd capital to secure critical supply chains and rebuild the industrial base, enhancing the U.S. competitive advantage. The FY 2027 President's Budget request supports the creation of new financial products to address a range of priorities, including greenfield projects, project finance, acquisition capital, investment fund subscription lines, and fund-level leverage to increase assets under management. These strategic capital solutions will enable the office to address key Presidential and Departmental priorities such as critical minerals, shipbuilding, infrastructure, and U.S. supply chain chokepoints.$$, $$Budget J-Books/FY27/DW/RDTE_OSW_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$P_2031_L020$$, $$Spectrum Army SUAS$$, $$proc_army_2031_ba1$$, $$peo_aviation$$, 2026, 0, 1741000, 0, NULL, $${"page": 12, "ba_num": "01", "source": "p1_fy26", "ba_name": "Aircraft", "line_no": "20", "service": "army", "fy24_qty": null, "fy25_qty": null, "appr_code": "2031", "appr_name": "Aircraft Procurement, Army", "fy26_v178": {"note": "no_parser_pair", "source": "p40_fy26_v178"}, "fy26t_qty": null, "fy26d_cost": 0, "fy26r_cost": 0, "ident_code": "A"}$$::jsonb, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, FALSE, NULL, 0, 210645000, 210645000, 0, 210645000, NULL, NULL, $$Budget J-Books/FY27/Army/Aircraft_Procurement_Army.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604703N$$, $$Personnel, Trng, Sim, & Human Factors$$, $$rdte_navy_ba5$$, $$onr$$, 2026, 6703000, 8960000, 10011000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "navy", "page_num": 34, "original_pe": "0604703N", "page_header": "Department of the Navy"}$$::jsonb, $$This program is funded under RDT&E operational systems development because it encompasses engineering and development of new end-items prior to production approval decision along with the enhancement and upgrading of existing Manpower, Personnel, Training, and Education decision support systems, tools, and models. This non-acquisition category program provides funds for continued R&D for broader application of advanced technologies to transition successful research proof-of- concept demonstrations into operational use. This PE provides funding to support the transition of models and decision support tools from RDT&E funded to production and into the hands of analysts and program managers throughout the MyNavyHR enterprise. The PE also supports the application and adaptation of proven industry models, tools, and technologies to Navy Military Personnel, Training and Education (MPTE) problems where GOTS solutions are insufficient or non-existent. The second goal of the PE is to successfully implement 90% of the industry-standard tools that are attempted to be used in Navy applications. In FY26, there is a continued need to advance the engineering development of emerging MyNavyHR business systems, technologies, and models from the Navy War Centers, coordinate with other Navy Labs and Research Institutions, and fiscally participate in the transition of MyNavyHR-domain products out of the S&T research environments (e.g. ONR). Per FNC guidance, the S&T programs are to have funding split among resource sponsors and stakeholders using a shared cost model (i.e. 30/50/100%) over the engineering development timeline.$$, NULL, 9127000, 8519000, 8429000, NULL, NULL, 151, $$RDTEN_BA5_Book.pdf$$, NULL, FALSE, 9626000, 6703000, 8316000, 8316000, NULL, 8316000, 8589000, $$This program is funded under RDT&E operational systems development because it encompasses engineering and development of new end-items prior to production approval decision along with the enhancement and upgrading of existing Manpower, Personnel, Training, and Education decision support systems, tools, and models. This non-acquisition category program provides funds for continued R&D for broader application of advanced technologies to transition successful research proof-of- concept demonstrations into operational use. This PE provides funding to support the transition of models and decision support tools from RDT&E funded to production and into the hands of analysts and program managers throughout the MyNavyHR enterprise. The PE also supports the application and adaptation of proven industry models, tools, and technologies to Navy Military Personnel, Training and Education (MPTE) problems where GOTS solutions are insufficient or non-existent. The second goal of the PE is to successfully implement 90% of the industry-standard tools that are attempted to be used in Navy applications. In FY27, there is a continued need to advance the engineering development of emerging MyNavyHR business systems, technologies, and models from the Navy War Centers, coordinate with other Navy Labs and Research Institutions, and fiscally participate in the transition of MyNavyHR-domain products out of the S&T research environments (e.g. ONR). Per FNC guidance, the S&T (Science and Technology) programs are to have funding split among resource sponsors and stakeholders using a shared cost model (i.e. 30/50/100%) over the engineering development timeline.$$, $$Budget J-Books/FY27/Navy/RDTEN_BA5_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604706F$$, $$Life Support Systems$$, $$rdte_af_ba5$$, $$aflcmc_az$$, 2026, 20542000, 37578000, 24502000, NULL, $${"ba_raw": "6.5", "source": "af_r1_fy26", "original_pe": "0604706F"}$$::jsonb, $$This program develops aircrew flight equipment and other combat support equipment required for safe effective execution. Air Force acquisition teams lead the upgrade and fielding of new equipment and systems by assessing deficiencies in existing equipment, identifying and assessing existing products or developing new technology, and conducting required Safe-to-Fly tests, certifications, and studies. Program efforts include, but are not limited to, the following projects: directed energy protective equipment; flight helmets and visors; oxygen breathing systems for aircrew; radios and locator beacons; support equipment; nuclear flash blindness protection; night vision devices; noise reduction devices; all types of flight suits and ensembles to protect aircrew against environmental threats; anti-gravity (anti-G) suits; flame resistant, retardant and blast/ballistic protective gear; aircraft seating; impact protection equipment; flotation devices; parachutes; ejection systems; post-ejection survival systems; physiological monitoring devices and other aircrew, life support, and ground crew systems required by the warfighter. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605829F, 0605831F, 0605833F, or 0605898F. In FY24 1.5M was expended for civilian pay expenses in this program element, and in FY25 2.4M is forecasted for civilian pay expenses in this program element. The FY 2026 request was reduced by $.509M for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative.” This program is in Budget Activity 5, System Development and Demonstration (SDD) because it has passed Milestone B approval and is conducting engineering and manufacturing development tasks aimed at meeting validated requirements prior to full rate production. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                            Date: June 2025 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 5: System         PE 0604706F / Life Support Systems Development & Demonstration (SDD)$$, NULL, 22173000, 22669000, 23030000, NULL, NULL, 94, $$FY26 Air Force Research and Development Test and Evaluation Vol II.pdf$$, NULL, FALSE, 23741000, 20302000, 21328000, 21328000, 0, 21328000, 23496000, $$This program develops aircrew flight equipment and other combat support equipment required for safe effective mission execution. Air Force acquisition teams lead the upgrade and fielding of new equipment and systems by assessing deficiencies in existing equipment, identifying and assessing existing products or developing new technology, and conducting required Safe-to-Fly tests, certifications, and studies. Program efforts include, but are not limited to, the following projects: directed energy protective equipment; flight helmets and visors; oxygen breathing systems for aircrew; radios and locator beacons; support equipment; nuclear flash blindness protection; night vision devices; noise reduction devices; all types of flight suits and ensembles to protect aircrew against environmental threats; flame resistant, retardant and blast/ballistic protective gear; aircraft seating; impact protection equipment; flotation devices; parachutes; ejection systems; post-ejection survival systems; physiological monitoring devices and other aircrew, life support, and ground crew systems required by the warfighter. This program element included all necessary expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 0605829F, 0605831F, 0605833F, and 0605898F. In direct support of Secretary of War direction to increase readiness across the DoW, efforts within this program element will be prioritized based on the National Defense Authorization Act (NDAA), USAF Force Design, Agile Combat Employment (ACE), and the Defense Planning Guide (DPG). These efforts will support work and collaboration efforts across the Combat Readiness Directorate in PE's 780651F, 71212F, 72833F, 64706F, 65827F, 22834F, 52834F, 28031F, 41135F and 27521F to increase readiness across the Air Force Enterprise This program is in Budget Activity 5, System Development and Demonstration (SDD) because it has passed Milestone B approval and is conducting engineering and manufacturing development tasks aimed at meeting validated requirements prior to full rate production. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                           Date: April 2026 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 5: System        PE 0604706F / Life Support Systems Development & Demonstration (SDD)$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume II.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604707N$$, $$SEW Architecture/Eng Support$$, $$rdte_navy_ba4$$, $$asn_rda$$, 2026, 6866000, 9608000, 8896000, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "navy", "page_num": 31, "original_pe": "0604707N", "page_header": "Department of the Navy"}$$::jsonb, $$The Maritime Concept Generation & Development (MCGD) project focuses on the generation, development and validation of warfighting concepts, Concept of Operations (CONOPS) and doctrine in order to eliminate war fighting gaps. Navy Warfare Development Center (NWDC) also manages the Fleet Experimentation (FLEX) program (formerly Sea Trial). The FY26 project will execute new experiments in the areas of Countering-C5ISRT, C5ISR, Naval Operational Architecture (NOA), Maritime Fires, Unmanned systems, Artificial Intelligence / Machine Learning (AI/ML), Naval integration, and Allied / Partner Nation Integration as well as conduct experiments (war simulations, Modeling & Simulation (M&S), at-sea events) to develop emerging Naval concepts.$$, NULL, 8947000, 8625000, 8680000, NULL, NULL, 94, $$RDTEN_BA4_Book.pdf$$, NULL, FALSE, 8554000, 6605000, 8657000, 8657000, NULL, 8657000, 8844000, $$The Maritime Concept Generation & Development (MCGD) project focuses on the generation, development and validation of warfighting concepts, Concept of Operations (CONOPS) and doctrine in order to eliminate war fighting gaps. Navy Warfare Development Center (NWDC) also manages the Fleet Experimentation (FLEX) program (formerly Sea Trial). The project will execute new experiments in the areas of Countering-C5ISRT, C5ISR, Naval Operational Architecture (NOA), Maritime Fires, Unmanned systems, Artificial Intelligence / Machine Learning (AI/ML), Naval integration, and Allied / Partner Nation Integration as well as conduct experiments (war simulations, Modeling & Simulation (M&S), at-sea events) to develop emerging Naval concepts.$$, $$Budget J-Books/FY27/Navy/RDTEN_BA4_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604713A$$, $$Combat Feeding, Clothing, and Equipment$$, $$rdte_army_ba5$$, $$asa_alt$$, 2026, 5654000, 2170000, 3286000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "army", "page_num": 16, "original_pe": "0604713A", "page_header": "Department of the Army"}$$::jsonb, $$This Program Element supports the development, demonstration and Non-Developmental Item (NDI) Commercial Off The-Shelf (COTS) evaluation of combat feeding equipment to enhance soldier efficiency, improve soldier survivability, reduce food service logistics requirements, and supports Field Feeding programs for all the services. Line items within this PE support multi-fuel, rapidly deployable field food service equipment initiatives. Efforts also support the Engineering and Manufacturing Development (EMD) phase of programs to improve equipment, enhance safety in food service, and decrease fuel and water requirements. Activities within Project 548 / Mil Subsistence Sys, develop critical enablers that support the Joint Future Capabilities and Joint Expeditionary mindset, by maintaining readiness through integrating new equipment, enhancing the field soldier's well-being, and providing soldiers usable equipment. It also reduces sustainment requirements, related Combat Support/ Combat Service Support (CS/CSS) demands on lift, the combat zone footprint, and costs for logistical support. FY 2026 funding supports the development of test-ready RU (refrigeration unit) prototypes and the subsequent conduct of performance, qualification, and MTRCS (Multi- Temperature Refrigerated Container System) Integration testing and following assessment. Funds will also be used to continue integration and demonstration to mature Joint Service combat ration systems that enable warfighter maneuver, readiness and effectiveness during highly mobile, dispersed operations. The FY 2026 request was reduced by $0.009 million for civilian personnel to optimize the workforce in compliance with Executive Order 14210, "Implementing the President's Department of Government Efficiency Workforce Optimization Initiative." Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                             Date: June 2025 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 5: System            PE 0604713A / Combat Feeding, Clothing, and Equipment Development & Demonstration (SDD)$$, NULL, 3008000, 2415000, 2418000, NULL, NULL, 112, $$RDTE - Vol 3 - Budget Activity 5A.pdf$$, NULL, FALSE, 3195000, 5654000, 6701000, 6701000, NULL, 6701000, 2443000, $$This Program Element supports the development, demonstration and Non-Developmental Item (NDI) Commercial Off The-Shelf (COTS) evaluation of combat feeding equipment to enhance soldier efficiency, improve soldier survivability, reduce food service logistics requirements, and supports Field Feeding programs for all the services. Line items within this PE support multi-fuel, rapidly deployable field food service equipment initiatives. Efforts also support the Engineering and Manufacturing Development (EMD) phase of programs to improve equipment, enhance safety in food service, and decrease fuel and water requirements. Activities within Project 548 / Mil Subsistence Sys, develop critical enablers that support the Joint Future Capabilities and Joint Expeditionary mindset, by maintaining readiness through integrating new equipment, enhancing the field soldier's well-being, and providing soldiers usable equipment. It also reduces sustainment requirements, related Combat Support/ Combat Service Support (CS/CSS) demands on lift, the combat zone footprint, and costs for logistical support. FY 2027 funding supports the continued development of test-ready RU (refrigeration unit) prototypes and the subsequent conduct of performance, qualification, and MTRCS (Multi- Temperature Refrigerated Container System) Integration testing and following assessment. Funds will also be used to continue integration and demonstration to mature Joint Service combat ration systems that enable warfighter maneuver, readiness and effectiveness during highly mobile, dispersed operations. Key Deliverables will be final Testing, Finalized Test Reports, Final Configuration Prototype, completion of TDP and BOM, and all other supporting documentation. FY 2027 also provides funding to support the test program and assessment of the Mobile Kitchen Trailer (MKT). Funds will be utilized to update existing Technical Data Package (TDP) and approve an Engineering Change Proposal (ECP) to reflect the technical change for the MKT trailer upgrades and additional Heat and Serve Capability. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                           Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 5: System            PE 0604713A / Combat Feeding, Clothing, and Equipment Development & Demonstration (SDD)$$, $$Budget J-Books/FY27/Army/RDTE - Vol 3 - Budget Activity 5A.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604715A$$, $$Non-System Training Devices - Eng Dev$$, $$rdte_army_ba5$$, $$asa_alt$$, 2026, 19063000, 20585000, 28427000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "army", "page_num": 16, "original_pe": "0604715A", "page_header": "Department of the Army"}$$::jsonb, $$Program Element funds development of Non-System Training Devices to support force-on-force and force-on-target training at the Combat Training Centers (CTC), general military training, and training on more than one item/system, as compared with system devices which are developed in support of a specific item/weapon system. Army training devices and training simulations contribute to the modernization of the forces by enabling readiness and strengthening combat effectiveness through realistic training solutions for the Warfighter. Training devices maximize the transfer of knowledge, skills, and experience from the training situation to a combat situation. Force-on-force training and force-on-target at the National Training Center (NTC), Ft. Irwin, CA; Joint Readiness Training Center (JRTC), Ft. Johnson, LA, Joint Multinational Readiness Center (JMRC), Hohenfels, Germany; Home Stations and deployed locations around the world; and battle staff training in Battle Command Training Program (BCTP) provide increased combat readiness through realistic collective training in low, mid, and high intensity scenarios. Project 241, Non-System Training Devices-Combined Arms, develops simulation training devices for Army-wide use, including the CTCs. FY 2026 Project 241 funds significant development efforts in support of U.S. Army Training and Readiness on the Combat Training Center Instrumentation Systems (CTC-IS), Instrumentable-Multiple Integrated Laser Engagement System (I-MILES), Common Training Instrumentation Architecture (CTIA), Future Army System of Integrated Targets (FASIT), Home Station Instrumentation Training System (HITS), Unmanned Aerial Systems (UAS) Swarm, and Opposing Forces Mechanized Vehicle Replacement (OMVR). FY 2026 funding in the amount of $5.477 Million is in support of the Pacific Defense Initiative. The FY 2026 request was reduced by $2.797 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative." Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                              Date: June 2025 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 5: System            PE 0604715A / Non-System Training Devices - Eng Dev Development & Demonstration (SDD)$$, NULL, 17628000, 17913000, 22205000, NULL, NULL, 113, $$RDTE - Vol 3 - Budget Activity 5A.pdf$$, NULL, FALSE, 23337000, 19063000, 29685000, 29685000, NULL, 29685000, 19824000, $$This PE funds development of Non-System Training Devices to support force-on-force and force-on-target training at the Combat Training Centers (CTC), general military training, and training on more than one item/system, as compared with system devices which are developed in support of a specific item/weapon system. Army training devices and training simulations contribute to the modernization of the forces by enabling readiness and strengthening combat effectiveness through realistic training solutions for the Warfighter. Training devices maximize the transfer of knowledge, skills, and experience from the training situation to a combat situation. Force- on-force training and force-on-target at the National Training Center (NTC), Ft. Irwin, CA; Joint Readiness Training Center (JRTC), Ft. Polk, LA, Joint Multinational Readiness Center (JMRC), Hohenfels, Germany; Home Stations and deployed locations around the world; and battle staff training in Battle Command Training Program (BCTP) provide increased combat readiness through realistic collective training in low, mid, and high intensity scenarios. Project 241, Non-System Training Devices- Combined Arms, develops simulation training devices for Army-wide use, including the CTCs. FY 2027 Project 241 funds significant development efforts in support of U.S. Army Training and Readiness on the Combat Training Center Instrumentation Systems (CTC-IS), Instrumentable-Multiple Integrated Laser Engagement System (I-MILES), Common Training Instrumentation Architecture (CTIA), Future Army System of Integrated Targets (FASIT), Home Station Instrumentation Training System (HITS), Unmanned Aerial Systems (UAS) Swarm, and Opposing Forces Mechanized Vehicle Replacement (OMVR). Of the total amount requested in FY 2027, $6.200 million is in support of the Pacific Deterrence Initiative.$$, $$Budget J-Books/FY27/Army/RDTE - Vol 3 - Budget Activity 5A.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604727N$$, $$JNT Standoff Weapon Systems$$, $$rdte_navy_ba5$$, $$asn_rda$$, 2026, 895000, 1895000, 1516000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "navy", "page_num": 34, "original_pe": "0604727N", "page_header": "Department of the Navy"}$$::jsonb, $$The Joint Standoff Weapon (JSOW) is an air-to-ground weapon designed to attack a variety of targets during day, night, and adverse weather conditions. JSOW enhances aircraft survivability by providing the capability for launch aircraft to standoff outside the range of most target area surface-to-air threat systems. The JSOW launch-and-leave capability will allow several target kills per aircraft sortie. The JSOW program first developed a baseline weapon for use against fixed area targets. JSOW is a Navy led joint Navy/Air Force program. JSOW utilizes a "common truck" for both AGM-154A and AGM-154C variants. Through adherence to international standards for weapons interfaces, weight, and dimension considerations, JSOW is compatible with Air Force and North Atlantic Treaty Organization aircraft. The JSOW Unitary (AGM-154C-1) variant includes a Network Enabled Weapon moving maritime target capability. The AGM-154C-1 capability enables the weapon to be integrated with the network and attack sea moving maritime targets via real-time pre-and post-launch targeting updates. JSOW will continue to conduct analysis and development of solutions to system integration challenges, and continual enhancement of warfighter effectiveness in the employment of the JSOW weapon system. The FY 2019 funding included the integration of new functionality into the joint mission planning systems and precision guided munitions planning system. JSOW C-1 Initial Operational Capability was achieved in June 2016. JSOW C-1 Full Operational Capability was achieved in August 2017. JSOW development provides continuing upgrades to mission planning software to maintain relevance. This program is funded under SYSTEM DEVELOPMENT AND DEMONSTRATION because it includes those projects that have passed Milestone B approval and are conducting engineering and manufacturing development tasks aimed at meeting validated requirement prior to full-rate production decision. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Navy                                                                           Date: June 2025 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 5: System          PE 0604727N / JNT Standoff Weapon Systems Development & Demonstration (SDD)$$, NULL, 1786000, 1550000, 1471000, NULL, NULL, 152, $$RDTEN_BA5_Book.pdf$$, NULL, FALSE, 1510000, 895000, 1447000, 1447000, NULL, 1447000, 1497000, $$The Joint Standoff Weapon (JSOW) is an air-to-ground weapon designed to attack a variety of targets during day, night, and adverse weather conditions. JSOW enhances aircraft survivability by providing the capability for launch aircraft to standoff outside the range of most target area surface-to-air threat systems. The JSOW launch-and-leave capability will allow several target kills per aircraft sortie. The JSOW program first developed a baseline weapon for use against fixed area targets. JSOW is a Navy led joint Navy/Air Force program. JSOW utilizes a "common truck" for both AGM-154A and AGM-154C variants. Through adherence to international standards for weapons interfaces, weight, and dimension considerations, JSOW is compatible with Air Force and North Atlantic Treaty Organization aircraft. The JSOW Unitary (AGM-154C-1) variant includes a Network Enabled Weapon moving maritime target capability. The AGM-154C-1 capability enables the weapon to be integrated with the network and attack sea moving maritime targets via real-time pre-and post-launch targeting updates. JSOW will continue to conduct analysis and development of solutions to system integration challenges, and continual enhancement of warfighter effectiveness in the employment of the JSOW weapon system. The FY 2019 funding included the integration of new functionality into the joint mission planning systems and precision guided munitions planning system. JSOW C-1 Initial Operational Capability was achieved in June 2016. JSOW C-1 Full Operational Capability was achieved in August 2017. JSOW development provides continuing upgrades to mission planning software to maintain relevance. This program is funded under SYSTEM DEVELOPMENT AND DEMONSTRATION because it includes those projects that have passed Milestone B approval and are conducting engineering and manufacturing development tasks aimed at meeting validated requirement prior to full-rate production decision. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                          Date: April 2026 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 5: System          PE 0604727N / JNT Standoff Weapon Systems Development & Demonstration (SDD)$$, $$Budget J-Books/FY27/Navy/RDTEN_BA5_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604741A$$, $$Air Defense Command, Control and Intelligence - Eng Dev$$, $$rdte_army_ba5$$, $$dw_mda$$, 2026, 13892000, 86990000, 73653000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "army", "page_num": 16, "original_pe": "0604741A", "page_header": "Department of the Army", "fy26_v182_disc_K": 13892, "fy26_v182_supp_K": 43300, "fy26_v182_total_K": 57192, "fy26_v182_note_name": "Air Defense Command, Control and Intelligence - Eng Dev", "fy26_v182_source_file": "RDTE - Vol 3 - Budget Activity 5A.txt", "fy26_v182_source_line": 10276}$$::jsonb, $$The Air Missile Defense Planning and Control System (AMDPCS) FY 2026 funding request of $13.892 million provides integration of air and missile defense operations at all echelons. Specifically, the Air and Missile Defense Work Station (AMDWS) provides a correlated air picture using local radars, allowing the Commander the visibility and situational understanding of the airspace; automated defense design and staff planning tools in AMDWS allow Soldiers horizontal and vertical collaborative planning with adjacent units. Common Data Link Interface-Module (CDLI-M) serves as a joint tactical datalink gateway/air picture, and when correlated by the Forward Area Air Defense (FAAD) and displayed on AMDWS, provides a near real-time, three-dimensional air picture for the Commander. Joint Tactical Terminal (JTT) provides soldiers Theater Ballistic Missile (TBM) early warning, allowing them to take appropriate actions. AMDPCS is fielded to Army Air and Missile Defense Commands (AAMDC), Air Defense Artillery Brigades (ADA BDE), Air and Missile Defense Battalions (AMD BN), and Terminal High Altitude Area Air Defense Batteries (THAAD BTRY). Air Defense Airspace Management (ADAM), a variant of AMDPCS with similar capabilities, is fielded to Corps, Divisions, Brigade Combat Teams (BCT), and multi-functional support brigades. As part of the capability and technology reuse, AMDWS external interfaces are being leveraged by Integrated Battle Command System (IBCS) to avoid redevelopment of existing capabilities. AMDWS and FAAD are core components of the Air and Missile Defense system-of-systems currently deployed in combat zones. Counter Small Unmanned Aircraft Systems (C-sUAS) funding supports ongoing efforts to provide forces at all echelons with cross-domain capabilities to identify, classify, track, and defeat Groups 1-3 UAS threats, while supporting joint operational requirements. These combined arms solutions support the full kill-chain and result in solutions addressing fixed/semi-fixed, mounted/mobile, dismounted, and handheld missions. Development efforts are aligned with the C-sUAS Capability Development Document (CDD) and Annexes, which codify the threshold and objective capability requirements for C-sUAS development. C-sUAS is part of the Department of Defense Capability Based (Agile) Funding Pilot. Agile funding supports the Army Transformation Initiative, which provides enhanced force protection capabilities by fostering innovation and accelerated deployment of promising technology. Beginning FY 2026, C-sUAS RDTE funding has been realigned to new PE 0609135A/A33, Counter Unmanned Aerial Systems (UAS) Agile Development. This funding supports the Army's Next Generation Command and Control (NGC2) initiative to modernize Command and Control (C2) systems. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                          Date: June 2025 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 5: System          PE 0604741A / Air Defense Command, Control and Intelligence - Eng Dev Development & Demonstration (SDD)$$, NULL, 14542000, 14673000, 14680000, NULL, NULL, 114, $$RDTE - Vol 3 - Budget Activity 5A.pdf$$, NULL, FALSE, 71111000, 57192000, 14276000, 14276000, NULL, 14276000, NULL, $$The Air Missile Defense Planning and Control System (AMDPCS) FY 2027 funding request of $14.276 million provides integration of air and missile defense operations at all echelons. Specifically, the Air and Missile Defense Work Station (AMDWS) provides a correlated air picture using local radars, allowing the Commander the visibility and situational understanding of the airspace; automated defense design and staff planning tools in AMDWS allow Soldiers horizontal and vertical collaborative planning with adjacent units. Common Data Link Interface-Module (CDLI-M) serves as a joint tactical datalink gateway/air picture, and when correlated by the Forward Area Air Defense (FAAD) and displayed on AMDWS, provides a near real-time, three-dimensional air picture for the Commander. Joint Tactical Terminal (JTT) provides soldiers Theater Ballistic Missile (TBM) early warning, allowing them to take appropriate actions. AMDPCS is fielded to Army Air and Missile Defense Commands (AAMDC), Air Defense Artillery Brigades (ADA BDE), Air and Missile Defense Battalions (AMD BN), and Terminal High Altitude Area Air Defense Batteries (THAAD BTRY). Air Defense Airspace Management (ADAM), a variant of AMDPCS with similar capabilities, is fielded to Corps, Divisions, Brigade Combat Teams (BCT), and multi-functional support brigades. As part of the capability and technology reuse, AMDWS external interfaces are being leveraged by Integrated Battle Command System (IBCS) to avoid redevelopment of existing capabilities. AMDWS and FAAD are core components of the Air and Missile Defense system-of-systems currently deployed in combat zones. Counter-small Unmanned Aircraft Systems (C-sUAS) funding supports ongoing efforts to provide forces at all echelons with cross-domain capabilities to identify, classify, track, and defeat Groups 1-3 UAS threats, while supporting joint operational requirements. These combined arms solutions support the full kill-chain and result in solutions addressing fixed/semi-fixed, mounted/mobile, dismounted, and handheld missions. Development efforts are aligned with the C-sUAS Capability Development Document (CDD) and Annexes, which codify the threshold and objective capability requirements for C-sUAS development. This funding supports the Army's Next Generation Command and Control (NGC2) initiative to modernize Command and Control (C2) systems. Beginning FY 2026, C-sUAS funding was transferred from 0604741A/FG5 COUNTER UNMANNED AERIAL SYSTEMS (UAS) to PE 0605347A/A34 COUNTER UNMANNED AERIAL SYSTEMS (UAS) DEVELOPMENT. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                              Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 5: System            PE 0604741A / Air Defense Command, Control and Intelligence - Eng Dev Development & Demonstration (SDD)$$, $$Budget J-Books/FY27/Army/RDTE - Vol 3 - Budget Activity 5A.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604746A$$, $$Automatic Test Equipment Development$$, $$rdte_army_ba5$$, $$tradoc$$, 2026, 9512000, 13129000, 12927000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "army", "page_num": 16, "original_pe": "0604746A", "page_header": "Department of the Army"}$$::jsonb, $$This program element (PE) supports the development and testing of automatic test equipment, precision calibration instruments, general-purpose test equipment, state of-the-art diagnostics and prognostics technologies, and software and systems to support the increasingly complex electronic components of the Army's new and upgraded weapon systems focused on joint operations in a sophisticated multi-domain area of operation. It focuses on standardization and implementation of commercial test and diagnostic technologies across multiple weapon platforms to minimize the cost of troubleshooting and maintenance of Army equipment in the field. Funding supports modernization of the test equipment fleets by investigating technology insertions including, but not limited to, predictive and prognostic maintenance automated troubleshooting, Electronic Intermittent Fault Detection, instrument reduction/miniaturization, electro-mechanical, electro-optics (EO), radio frequency (RF), physical, radiological, chemical, and biological warfare sensor calibration support capabilities, and other emerging technologies. Funding also supports development of initial prototypes to enable refinement of Operational Requirements documented by Combatant Commands (COCOM), Program Executive Offices (PEO), Army Futures Command (AFC), Army Staff, US Army Training and Doctrine Command (TRADOC), and early user feedback to support future sustainment and testing capabilities required for emerging weapons platforms. This PE also supports continued development and improvement of general-purpose test equipment and calibration standards with emphasis on the incorporation of digital electronics and tailoring of configurations to improve deployability, mobility and survivability of the support equipment. It includes development, demonstration and testing of calibration standards and techniques to support new Army test equipment requirements; and it provides for feasibility studies, market research, inventory analyses, bid sample testing and prototyping to support acquisition of calibration systems and general-purpose test and diagnostics equipment. The Department of Defense (DoD) has designated the Integrated Family of Test Equipment (IFTE), comprised of the Maintenance Support Device (MSD) and the Next Generation Automatic Test System (NGATS), as the authorized Army standard for field and sustainment maintenance. The MSD provides at-system automatic test and diagnostic support and the NGATS consolidates off-system automatic test and diagnostic equipment requirements. The IFTE systems being developed under this PE provide electronic fault isolation, diagnostic and repair capabilities at all levels of maintenance and do it more cost effectively than system-specific testers. They provide state-of-the-art test and diagnostic capabilities, reducing costs and logistics footprints while providing the Warfighter fix-forward capability for current and future weapon systems in multi-domain operations. The systems are designed to support the Cross-Functional Teams (CFT) in the Army Futures Command (AFC) as they mature in accordance with the DoD Automatic Test Systems strategy. The MSD is employed by more than thirty military occupational specialties to perform field level maintenance on approximately 70 weapon systems, including Abrams, Bradley, Stryker, aviation platforms, missile systems, and the Army's wheeled vehicle fleet. FY 2026 base funding continues incremental development of the Army's standard At-Platform Automatic Test System, MSD, which will enhance testing and diagnostic capability required by supported weapon systems. Funding supports tactical vehicle sustainment concepts, evaluates evolving weapon system diagnostic testing Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                                 Date: June 2025 Appropriation/Budget Activity                                                     R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 5: System               PE 0604746A / Automatic Test Equipment Development Development & Demonstration (SDD) requirements, incorporates additional organic diagnostic software capabilities to troubleshoot weapon systems, and ensures data bus compatibility and readability with commercial technology. It evaluates and incorporates cyber security enhancements, including wireless capability, into at-platform diagnostic hardware and software. Funding also provides for market research, feasibility assessment, and interaction with supported weapon systems to determine most effective methodology for diagnostic software pathway to incorporate emerging At-Platform Predictive Logistics requirements. The FY 2026 funding will develop or significantly modify test equipment to satisfy modular force and homeland security support requirements that cannot be accommodated with test equipment currently available in the commercial marketplace such as RF and EO testing capability. It will also develop and test general-purpose test equipment and calibration standards to meet Army weapon system support requirements, and initiate development of enhanced diagnostic software and interfaces to support emerging maintenance concepts for Long Range Precision Fires, Next Generation Combat Vehicle, Future Vertical Lift, and Air and Missile Defense. The funding will provide prototype test and evaluation of field level calibration and repair support for the Radiation Detection System (RDS) in response to Operational Needs Statement ONS 17-22580. The project resolves significant radiation measurement accuracy gaps throughout the Department of the Army operational areas and CONUS, and it provides for analysis of courses of action to incorporate additional intrinsic calibration instruments and general-purpose test equipment to reduce the maintenance hierarchy, increase calibration intervals, extend lifecycle reliability, and increase supportability across generational changes in weapon systems and weapon support systems technology. The FY 2026 request was reduced by $0.017 million for civilian personnel to optimize the workforce in compliance with Executive Order 14210, "Implementing the President's Department of Government Efficiency Workforce Optimization Initiative."$$, NULL, 4656000, 4692000, 4695000, NULL, NULL, 116, $$RDTE - Vol 3 - Budget Activity 5B.pdf$$, NULL, FALSE, 12455000, 9512000, 9625000, 9625000, NULL, 9625000, 4741000, $$This PE supports the development and testing of automatic test equipment, precision calibration instruments, general-purpose test equipment, state of-the-art diagnostics and prognostics technologies, and software and systems to support the increasingly complex electronic components of the Army's new and upgraded weapon systems focused on joint operations in a sophisticated multi-domain area of operation. It focuses on standardization and implementation of commercial test and diagnostic technologies across multiple weapon platforms to minimize the cost of troubleshooting and maintenance of Army equipment in the field. Funding supports modernization of the test equipment fleets by investigating technology insertions including, but not limited to, predictive and prognostic maintenance automated troubleshooting, Electronic Intermittent Fault Detection, instrument reduction/miniaturization, electro-mechanical, electro-optics (EO), radio frequency (RF), physical, radiological, chemical, and biological warfare sensor calibration support capabilities, and other emerging technologies. Funding also supports development of initial prototypes to enable refinement of Operational Requirements documented by the Army Transformation Initiative (ATI), Combatant Commands (COCOM), Capability Portfolio Executive (CPE), U.S. Army Transformation and Training Command, and early user feedback to support future sustainment and testing capabilities required for emerging weapons platforms. This PE also supports continued development and improvement of general-purpose test equipment and calibration standards with emphasis on the incorporation of digital electronics and tailoring of configurations to improve deployability, mobility and survivability of the support equipment. It includes development, demonstration and testing of calibration standards and techniques to support new Army test equipment requirements; and it provides for feasibility studies, market research, inventory analyses, bid sample testing and prototyping to support acquisition of calibration systems and general-purpose test and diagnostics equipment. The Department of War (DoW) has designated the Integrated Family of Test Equipment (IFTE), comprised of the Maintenance Support Device (MSD) and the Next Generation Automatic Test System (NGATS), as the authorized Army standard for field and sustainment maintenance. The MSD provides at-system automatic test and diagnostic support and the NGATS consolidates off-system automatic test and diagnostic equipment requirements. The IFTE systems being developed under this PE provide electronic fault isolation, diagnostic and repair capabilities at all levels of maintenance and do it more cost effectively than system-specific testers. They provide state-of-the-art test and diagnostic capabilities, reducing costs and logistics footprints while providing the Warfighter fix-forward capability for current and future weapon systems in multi-domain operations. The systems are designed to support the Cross-Functional Teams (CFT) in the U.S. Army Transformation and Training Command as they mature in accordance with the DoW Automatic Test Systems strategy. The MSD is employed by more than thirty military occupational specialties to perform field level maintenance on approximately 70 weapon systems, including Abrams, Bradley, Stryker, aviation platforms, missile systems, and the Army's wheeled vehicle fleet. FY 2027 funding continues incremental development of the Army's standard At-Platform Automatic Test System, MSD, which will enhance testing and diagnostic capability required by supported weapon systems. Funding supports tactical vehicle sustainment concepts, evaluates evolving weapon system diagnostic testing Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                                Date: April 2026 Appropriation/Budget Activity                                                        R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 5: System                  PE 0604746A / Automatic Test Equipment Development Development & Demonstration (SDD) requirements, incorporates additional organic diagnostic software capabilities to troubleshoot weapon systems, and ensures data bus compatibility and readability with commercial technology. It evaluates and incorporates cyber security enhancements, including wireless capability, into at-platform diagnostic hardware and software. Funding also provides for market research, feasibility assessment, and interaction with supported weapon systems to determine most effective methodology for diagnostic software pathway to incorporate emerging At-Platform Predictive Logistics requirements. Funding will develop or significantly modify test equipment to satisfy modular force and homeland security support requirements that cannot be accommodated with test equipment currently available in the commercial marketplace such as RF and EO testing capability. It will also develop and test general-purpose test equipment and calibration standards to meet Army weapon system support requirements, and initiate development of enhanced diagnostic software and interfaces to support emerging maintenance concepts for Long Range Precision Fires, Next Generation Combat Vehicle, Future Vertical Lift, and Air and Missile Defense including the golden dome for America, Cyber, electronic warfare, and counterspace capabilities. The funding will provide prototype test and evaluation of field level calibration and repair support for the Radiation Detection System (RDS) in response to Operational Needs Statement ONS 17-22580. The project resolves significant radiation measurement accuracy gaps throughout the Department of the Army operational areas and CONUS, and it provides for analysis of courses of action to incorporate additional intrinsic calibration instruments and general-purpose test equipment to reduce the maintenance hierarchy, increase calibration intervals, extend lifecycle reliability, and increase supportability across generational changes in weapon systems and weapon support systems technology.$$, $$Budget J-Books/FY27/Army/RDTE - Vol 3 - Budget Activity 5A.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604755N$$, $$Ship Self Def (Detect & Cntrl)$$, $$rdte_navy_ba5$$, $$peo_carriers$$, 2026, 167711000, 150253000, 170080000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "navy", "page_num": 34, "original_pe": "0604755N", "page_header": "Department of the Navy"}$$::jsonb, $$This program element provides Aircraft Carriers and Amphibious Class ships Ship Self Defense System (SSDS) MK 2 Combat System upgrades and integrates new equipment and systems to pace the threat and capture advances in technology. Examples of captured advanced technologies are: advanced information assurance and cyber defense; Fire Control Loop Improvement Project (FCLIP); Identification Friend or Foe (IFF) Mode 5 to include Far-Term Interoperability Improvement Project (FTIIP); and other command and control systems, advanced sensors, and weapon integration, all of which require corresponding SSDS MK 2 changes. Quick Reaction Combat Capability (QRCC) project (PU 2178) - implements an evolutionary acquisition of improved ship self-defense capabilities against Anti-Ship Cruise Missiles (ASCMs) and improved multi-warfare capabilities for Aircraft carriers and Amphibious Class ships. SSDS MK 2 integrates a diverse set of fire control loop sensors and weapons (SPY-6(V)2, SPY-6(V)3, SLQ-32(V)6 SEWIP BLK 2, starting in FY 2026 SLQ-32(V)7 SEWIP BK 3, RAM Block 2A/2B, ESSM Block 2, CIWS) and C4I systems (CANES) for each ship class (CVN68/78, LHA 6, LHD 1, LPD 17, and LSD 41/49). SSDS MK 2 provides combat direction, and joint interoperability via the Cooperative Engagement Capability (CEC) Increment 1 and 2 (CG 2/3), starting in FY 2026 CEC Increment 2 (CG 4/5), Tactical Digital Information Link (TADIL)- J/Link 16. System design emphasizes commonality and a single source software library that are major mechanisms for cost control and avoidances. SSDS uses a physically distributed, open system architecture computer network consisting of common hardware such as the Common Processor System (CPS), the Common Display System (CDS) and the common Computing Infrastructure configuration. SSDS MK 2 integrates new combat system war-fighting capabilities and improvements, as well as DoD and Navy-mandated enhanced cybersecurity capabilities via incremental capability packages and computing infrastructure (previously Technology Insertion (TI)) improvement deliveries. Capabilities beyond SSDS Build 12 will transition to development by third party software developers and a common Software construct. PU 2178 efforts are divided into two major functional areas: SSDS Product Development/Combat Systems Integration, and Test and Evaluation/Certification. Joint Non-Lethal Weapons (PU 3172) - provides a long range laser warning and dazzle system, maritime vessel stopper (MVS) system, and combined effects (light, laser, and sound) system for use in the maritime environment. Optical warning and distraction has been identified by the services as a possible technology solution to mitigate and/or address several known joint nonlethal capability gaps. Visual Augmentation Systems (VAS) supports research, development, and testing of material solutions for VAS capability gaps encountered during missions in combat zones. Expeditionary force lacks the ability to detect and recognize potential threat craft at the maximum possible range and at the earliest time in all-weather environments during day and night. In addition, the warfighter needs the ability to record both audio/video encounters and incidents for after action reporting Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Navy                                                                                 Date: June 2025 Appropriation/Budget Activity                                                      R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 5: System                PE 0604755N / Ship Self Def (Detect & Cntrl) Development & Demonstration (SDD) SSDS Training Improvement Program (PU 3358) - provides enhancements and upgrades to the SSDS Total Ship Training Capability (TSTC) components within the combat system, combat system elements, Battle-Force Tactical Training (BFTT), and Advanced Training Domain (ATD), to address needs for increased training capability and functionality in conjunction with SSDS MK 2 capability improvements, IFF Mode 5 (to include FTIIP), Task Force Cyber Awakening (TFCA) Boundary Defense Capability (BDC), and Technical Insertion efforts under PU 2178 (QRCC). These enhancements will address current and future training requirements by implementing new functionality to enable the individual warfighter, through distributed battle group events, to engage in more complex training scenarios to support fleet required training certification events. Capability Development and integration are related to Self Defense, Underwater, Surface, and other warfare areas. Capability enhancements and upgrades include development of re-useable common components that can be leveraged by other combat systems, and/or integration of re- usable common components developed by the TSTC/BFTT Program and AEGIS Advanced Training Domain (ATD)/Total Ship Training Capability (TSTC) projects to meet AEGIS combat system training requirements. TSTC continues to integrate and update, as new tactical capabilities are being introduced, to enable crew operator proficiency training for basic and sustainment level training events, through distributed strike group certification, fleet synthetic training (FST) events, and including COMPTUEX FST at sea integration into a Live, Virtual and Constructive (LVC) environment. Continued development is required to integrate new capabilities and interfaces to provide training for SSDS combat system capability upgrades, and to address the Fleet's LVC Fleet Training Wholeness initiative. Additionally, modernization is needed to support the DoD Training Transformation Plan, the Chief of Naval Operations Fleet Response Plan and Commander United States Fleet Forces Command Fleet Readiness Training Plan.$$, NULL, 156656000, 129341000, 123044000, NULL, NULL, 153, $$RDTEN_BA5_Book.pdf$$, NULL, FALSE, 166701000, 167711000, 156167000, 156167000, NULL, 156167000, 123754000, $$This program element provides Aircraft Carriers and Amphibious Class ships Ship Self Defense System (SSDS) MK 2 Combat System upgrades and integrates new equipment and systems to pace the threat and capture advances in technology. Examples of captured advanced technologies are: advanced information assurance and cyber defense; Fire Control Loop Improvement Project (FCLIP); Identification Friend or Foe (IFF) Mode 5 to include Far-Term Interoperability Improvement Project (FTIIP); and other command and control systems, advanced sensors, and weapon integration, all of which require corresponding SSDS MK 2 changes. Quick Reaction Combat Capability (QRCC) project (PU 2178) - implements an evolutionary acquisition of improved ship self-defense capabilities against Anti-Ship Cruise Missiles (ASCMs) and improved multi-warfare capabilities for Aircraft carriers and Amphibious Class ships. SSDS MK 2 integrates a diverse set of fire control loop sensors and weapons (SPY-6(V)2, SPY-6(V)3, SLQ-32(V)6 SEWIP BLK 2, starting in FY 2026 SLQ-32(V)7 SEWIP BK 3, RAM Block 2A/2B, ESSM Block 2, CIWS) and C4I systems (CANES) for each ship class (CVN68/78, LHA 6, LHD 1, LPD 17, and LSD 41/49). SSDS MK 2 provides combat direction, and joint interoperability via the Cooperative Engagement Capability (CEC) software builds 11.10 and 11.16 (previously Increment 1 and 2 (CG 2/3)), starting in FY 2026 CEC software builds 11.26 and 11.28 (previously Increment 2 (CG 4/5)), Tactical Digital Information Link (TADIL)-J/Link 16. System design emphasizes commonality and a single source software library that are major mechanisms for cost control and avoidances. SSDS uses a physically distributed, open system architecture computer network consisting of common hardware such as the Common Processor System (CPS), the Common Display System (CDS) and the common Computing Infrastructure configuration. SSDS MK 2 integrates new combat system war-fighting capabilities and improvements, as well as DoW and Navy-mandated enhanced cybersecurity capabilities via incremental capability packages and computing infrastructure (previously Technology Insertion (TI)) improvement deliveries. Capabilities beyond SSDS Build 12 will transition to development by third party software developers and a common Software construct. PU 2178 efforts are divided into two major functional areas: SSDS Product Development/Combat Systems Integration, and Test and Evaluation/Certification. Joint Non-Lethal Weapons (PU 3172) - provides a long range laser warning and dazzle system, maritime vessel stopper (MVS) system, and combined effects (light, laser, and sound) system for use in the maritime environment. Optical warning and distraction have been identified by the services as a possible technology solution to mitigate and/or address several known joint nonlethal capability gaps. Visual Augmentation Systems (VAS) supports research, development, and testing of material solutions for VAS capability gaps encountered during missions in combat zones. Expeditionary force lacks the ability to detect and recognize potential threat craft at the maximum possible range and at the earliest time in all-weather environments during day and night. In addition, the warfighter needs the ability to record both audio/video encounters and incidents for after action reporting Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                                 Date: April 2026 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 5: System              PE 0604755N / Ship Self Def (Detect & Cntrl) Development & Demonstration (SDD) SSDS Training Improvement Program (PU 3358) - provides enhancements and upgrades to the SSDS Total Ship Training Capability (TSTC) components within the combat system, combat system elements, Battle-Force Tactical Training (BFTT), and Advanced Training Domain (ATD), to address needs for increased training capability and functionality in conjunction with SSDS MK 2 capability improvements, IFF Mode 5 (to include FTIIP), Task Force Cyber Awakening (TFCA) Boundary Defense Capability (BDC), and Technical Insertion efforts under PU 2178 (QRCC). These enhancements will address current and future training requirements by implementing new functionality to enable the individual warfighter, through distributed battle group events, to engage in more complex training scenarios to support fleet required training certification events. Capability Development and integration are related to Self Defense, Underwater, Surface, and other warfare areas. Capability enhancements and upgrades include development of re-useable common components that can be leveraged by other combat systems, and/or integration of re- usable common components developed by the TSTC/BFTT Program and AEGIS Advanced Training Domain (ATD)/Total Ship Training Capability (TSTC) projects to meet AEGIS combat system training requirements. TSTC continues to integrate and update, as new tactical capabilities are being introduced, to enable crew operator proficiency training for basic and sustainment level training events, through distributed strike group certification, fleet synthetic training (FST) events, and including COMPTUEX FST at sea integration into a Live, Virtual and Constructive (LVC) environment. Continued development is required to integrate new capabilities and interfaces to provide training for SSDS combat system capability upgrades, and to address the Fleet's LVC Fleet Training Wholeness initiative. Additionally, modernization is needed to support the DoW Training Transformation Plan, the Chief of Naval Operations Fleet Response Plan and Commander United States Fleet Forces Command Fleet Readiness Training Plan.$$, $$Budget J-Books/FY27/Navy/RDTEN_BA5_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604756N$$, $$Ship Self Def (Engage: Hard Kill)$$, $$rdte_navy_ba5$$, $$asn_rda$$, 2026, 345007000, 46724000, 59614000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "navy", "page_num": 34, "original_pe": "0604756N", "page_header": "Department of the Navy"}$$::jsonb, $$This program element provides funding for the development of systems that fulfill a portion of the third phase of the Ship Self Defense: Engage Hard Kill. Development in this line will focus on hard kill capabilities in which missiles and other munitions are used to intercept incoming Anti-Ship Cruise Missiles (ASCM), as well as a Surface-to Surface Strike weapon system. System improvements are being addressed via Rolling Airframe Missile (RAM) (0167), NATO SEASPARROW Missile System (NSSMS) (0173), Over-The-Horizon (OTH) missile (2070), Afloat Counter-Unmanned Aerial Systems (C-UAS) (2077), and MK-15 Close-In Weapon System (CIWS) (9081).$$, NULL, 273978000, 264719000, 270582000, NULL, NULL, 154, $$RDTEN_BA5_Book.pdf$$, NULL, FALSE, 57754000, 145007000, 296261000, 296261000, NULL, 296261000, 272536000, $$The Department encourages additional vendor participation in the design, development, and production of alternative weapons systems to meet current and future warfighting requirements. With current major weapons systems production at capacity, the nation is looking for alternative systems to fill these gaps. The Department is implementing diverse procurement strategies to enable rapid acquisition. These will include the use of Other Transaction Authorities, 'Marketplace' acquisition platforms, and alternative concepts to increase supply and suppliers in addition to traditional FAR-based procurement strategies. This program element provides funding for the development of systems that fulfill a portion of the third phase of the Ship Self Defense: Engage Hard Kill. Development in this line will focus on hard kill capabilities in which missiles and other munitions are used to intercept incoming Anti-Ship Cruise Missiles (ASCM), as well as a Surface-to Surface Strike weapon system. System improvements are being addressed via Rolling Airframe Missile (RAM) (0167), NATO SEASPARROW Missile System (NSSMS) (0173), Over-The-Horizon (OTH) missile (2070), Afloat Counter-Unmanned Aerial Systems (C-UAS) (2077), and MK-15 Close-In Weapon System (CIWS) (9081). The FY 2026 budget for Afloat C-UAS (2077) includes $39,407 thousand of discretionary and $200,000 thousand of mandatory (reconciliation) for a total of $239,407 thousand. The mandatory funds enables the acquisition of the prototype systems identified through the testing that occurred in FY 2024 and FY 2025. In FY 2026, the program continued developing and testing C-UAS systems to pace the evolving threat. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                           Date: April 2026 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 5: System          PE 0604756N / Ship Self Def (Engage: Hard Kill) Development & Demonstration (SDD)$$, $$Budget J-Books/FY27/Navy/RDTEN_BA5_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604757N$$, $$Ship Self Def (Engage: Soft Kill/EW)$$, $$rdte_navy_ba5$$, $$peo_mles$$, 2026, 232368000, 121212000, 146791000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "navy", "page_num": 34, "original_pe": "0604757N", "page_header": "Department of the Navy"}$$::jsonb, $$PU 0954 - EW Rapid Capability Insertion Process (RCIP) identifies system and mission capability gaps by analyzing EW baseline and fleet requirements, prioritizes those gaps based on fleet input and critical technology maturity, and develops upgrades to the AN/SLQ-32(V) product line to address those gaps. RCIP also integrates Future Naval Capability (FNC) programs into SEWIP. The Surface Electronic Warfare Improvement Program (SEWIP) provides incremental upgrades to the AN/ SLQ-32 and consists of Blocks 1A, 1B, 2, and 3, the Soft Kill Coordination System (SKCS), SEWIP Lite, and Scaled Onboard Electronic Attack (SOEA). Scaled Onboard Electronic Attack (SOEA) is an incremental development program added under PU 0954 in FY 2024 to provide an advanced Electronic Attack (EA) capability against anti-ship missiles. PU 3469 was added in FY 2025, SOEA will fall under this new PU in FY 2025 and out. The FY 2026 budget request supports continued development, test, and integration of SKCS with AEGIS Baseline (BL) 9 and BL 10, continues RCIP #8 to improve anti-ship missile defense capability of SLQ-32(V)6/7 when operating with other netted EW sensors and effectors, continues RCIP #6 efforts to implement Built In Test, and Signal Processing and continues RCIP #10, #11, and #12 Measurement Based Adaptive Response, the Electronic Warfare (EW) Planning Aid, and the Tactical Simulator (TACSIM) Technology Refresh. PU 2190 - The Offboard Active Decoy (Nulka) is a joint cooperative program between the United States and Australia that developed an active offboard decoy that utilizes a broadband radio frequency repeater mounted atop a hovering rocket. Nulka counters a wide variety of present and future radar guided Anti-Ship Missiles (ASMs) by radiating a large radar cross section while flying a ship-like trajectory. The United States developed the electronic payload and fire control system, while Australia developed the hovering rocket. The FY 2-26 budget request includes Decoy Launcher Processor (DLP) Nulka Objective Architecture, Decoy Launch Message Converter (DLMC) backward compatibility technology with Soft Kill Coordination System (SKCS). The Objective Architecture development will continue which provides improved Nulka decoy deployment as well as SKCS integration. PU 3068 - The Long Endurance Electronic Decoy (LEED) program will deliver an expendable long endurance autonomous off-board decoy Countermeasure system, comprised of a flight vehicle and Radio Frequency (RF) payload with modular capability allowing for rapid modification of the Electronic Warfare (EW) payload. LEED Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Navy                                                                                Date: June 2025 Appropriation/Budget Activity                                                       R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 5: System                 PE 0604757N / Ship Self Def (Engage: Soft Kill/EW) Development & Demonstration (SDD) development executes under a middle tier rapid prototyping acquisition strategy pursuant to Section 804 of the FY 2016 National Defense Authorization Act. LEED will integrate with SLQ-32 and address EW gaps in response to a fleet requirement to counter Anti-Ship Missile (ASM) threats. LEED will provide the fleet with enhanced EW coordination and capability, including the ability to stretch engagement timelines and counter heterogeneous missile attacks. The overarching LEED strategy consists of two phases including a Middle Tier of Acquisition Rapid Prototyping (MTA RP) phase followed by Major Capability Acquisition. The MTA RP phase will include Preliminary and Integrated Countermeasure Prototype Development (FY 2021-FY 2025) and Integrated System Testing (FY 2025-FY 2026). The MTA RP phase includes the development and test of operational-level Countermeasure prototypes, launch systems, and control software that demonstrate and validate critical capabilities, including flight performance, control, and payload functionality. Data collected from the initial prototypes will be used to develop Engineering Development Models (EDMs) for Qualification Testing to support a Milestone C decision for Low Rate Initial Production (LRIP) as LEED enters the Major Capability Acquisition phase. LEED will be developed alongside the Office of Naval Research (ONR) Long Endurance Airborne Platform (LEAP) Project, which began in FY21. LEED will leverage technologies developed and matured under the ONR LEAP Project. FY 2026 funding request supports continued LEED integrated countermeasure development at the prime contractor, including material purchases, system/subsystem integration, integrated system demonstration testing and system performance testing, system of systems interoperability integration and testing, training and maintenance curriculum development, and cybersecurity advancement. Funding request also includes material purchases and integration of prototype shipset(s) (each shipset consists of 24 countermeasure, 4 launchers, and all supporting equipment). The funding request also supports development of the LEED Block 2 All-Up Round (AUR) payload in line with the program's required insertion of rapid EW capability and modularity concept. PU 3316 - The Advanced Offboard EW (AOEW) program was for the development of long duration off-board decoys integrated with onboard systems for EW coordination to counter identified EW gaps (additional details classified) in response to an urgent operational need. Divestment of AOEW is starting in FY 2026. AOEW Capability Development Document (CDD) was cancelled and requirements were transferred to other programs. PU 3321 - SEWIP Block 3 is developing an advanced Electronic Attack (EA) capability to keep pace with the evolving Anti-Ship Missile (ASM) threat and counter- targeting required for the AN/SLQ-32(V) system. SEWIP Block 3 will provide the AN/SLQ-32(V)7 system for all surface ships (CVN, DDG, LHD) outfitted with the active variant of the AN/SLQ-32, mainly the (V)3 and (V)4, as well as select new construction platforms. The SEWIP Block 3 Acquisition leverages technology developed under the Office of Naval Research's (ONR) Integrated Topside (InTop) Science and Technology (S&T) effort. SEWIP Block 3 will continue to expand the integrated shipboard combat system by providing new integrated EA transmitters, arrays, and associated EA techniques. The AN/SLQ-32(V)7 integrates the new EA countermeasure (SEWIP Block 3) with the AN/SLQ-32(V)6. The AN/SLQ-32(V)6 includes an Electronic Support (ES) receiver (SEWIP Block 2), a High Gain High Sensitivity (HGHS) receiver (SEWIP Block 1B3), a Specific Emitter Identifier (SEI) receiver (SEWIP Block 1B2), display console, and backend electronics. SEWIP Block 3 includes the government software development and integration effort for a SoftKill Coordinator (SKC) to manage EA engagements. SEWIP Block 3 is developing an Electronic Warfare Test Bed (EWTB) to validate system performance via modeling and simulation. SEWIP Block 3 is also investigating higher efficiency Gallium Nitride (GaN) High Power Amplifiers (HPA). GaN HPAs are used in maritime advanced technology radar and surface electronic warfare systems. For radar and electronic warfare systems, this will yield technology to incorporate and integrate into radar and electronic warfare Transmit/Receive Module designs, with a beneficial impact of improved Power Added Efficiency (PAE) for the systems resulting in a reduction in power draw from ship's service electrical power for the same radar and electronic warfare system performance. To keep pace with evolving ASM threats and counter-targeting, SEWIP Block 3 will incorporate capability improvements via a technology insertion plan. This capability improvement plan will mature and develop technologies and software/firmware to expand and improve capability for insertion into SEWIP Block 3. Technology solutions will result in technical data packages and tactical software with Government-owned data rights. Solutions will be incorporated into the SEWIP Block 3 technical data packages and tactical software for incorporation into future production and/or back-fit of fielded systems. The FY 2026 funding request for SEWIP Block 3 will focus on Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Navy                                                                               Date: June 2025 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 5: System          PE 0604757N / Ship Self Def (Engage: Soft Kill/EW) Development & Demonstration (SDD) the conduct of Full Rate Production Decision Review (FRP DR), continued Software and Hardware baseline upgrades, capability improvement design and development and associated testing, training curriculum development and EW Testbed model upgrades. PU 3469 - Scaled Onboard Electronic Attack (SOEA) is an incremental development program that initiated under PU 0954 in FY 2024 and added under PU 3469 in FY 2025 and out to provide an advanced Electronic Attack (EA) capability against anti-ship missiles. SOEA will assimilate into the Surface Electronic Warfare Improvement Program (SEWIP) family of shipboard Electronic Warfare systems. The program is intended to be scalable for Surface Combatants with size, weight, power, and cooling (SWaP-C) constraints that cannot support AN/SLQ-32(V)7 installation; however, it is not meant as a replacement for AN/SLQ-32(V)7. SOEA development executes under a Middle Tier Rapid Prototyping acquisition strategy pursuant to Section 804 of the FY 2016 National Defense Authorization Act. The SOEA Middle Tier of Acquisition (MTA) leverages technology developed by the Office of Naval Research (ONR) and Naval Research Laboratory (NRL). SOEA's acquisition strategy consists of two phases: Rapid Prototyping and Rapid Fielding. SOEA Phase 1 includes prototyping of critical technology elements (CTEs) via Defense Microelectronics Agency (DMEA) contract agreements to prove out and validate critical performance capability, system architecture functionality, supportability requirements and improvements that build on the CTEs. SOEA Phase 2 will focus on fielding initial capability through the producibility of the Phase 1 prototype, continuing hardware and software improvements to meet full capability objectives, continuing external interfaces for system and platform integration, continuing training module development via the Surface Electronic Warfare Tactical Trainer (SEWTT) and completing Modeling & Simulation (M&S) to support further testing. SOEA will continue to expand the integrated shipboard combat system by providing new integrated EA capability and will be integrated with AN/SLQ-32(V)6. SOEA also includes a government software development and integration effort for a Soft-Kill Coordinator System (SKCS) to manage EA engagements. The FY 2026 budget request for SOEA supports Phase 1 Rapid Prototyping, including rapid prototype development, qualification and performance testing. The FY 2026 budget request also supports the initiation of SOEA Phase 2 Rapid Fielding which continues platform integration activities, SEWTT training module development, Modeling & Simulation (M&S) to support further testing, SKCS integration and to acquire additional prototype units if required.$$, NULL, 137356000, 103687000, 68748000, NULL, NULL, 155, $$RDTEN_BA5_Book.pdf$$, NULL, FALSE, 144970000, 232368000, 196761000, 196761000, NULL, 196761000, 70071000, $$PU 0954 - EW Rapid Capability Insertion Process (RCIP) identifies system and mission capability gaps by analyzing EW baseline and fleet requirements, prioritizes those gaps based on fleet input and critical technology maturity, and develops upgrades to the AN/SLQ-32(V) product line to address those gaps. RCIP also integrates Future Naval Capability (FNC) programs into SEWIP. The Surface Electronic Warfare Improvement Program (SEWIP) provides incremental upgrades to the AN/SLQ-32 and consists of Blocks 1A, 1B, 2, and 3, the Soft Kill Coordination System (SKCS), SEWIP Lite, and Scaled Onboard Electronic Attack (SOEA). The FY27 budget request supports continued development, test, and integration of SKCS with AEGIS Baseline (BL) 9 and BL 10, continues RCIP #8 to improve anti-ship missile defense capability of SLQ-32(V)6/7 when operating with other netted EW sensors and effectors, continues RCIP #6 efforts to implement Built In Test, and Signal Processing and continues RCIP #10, #11, #12 and #13 Measurement Based Adaptive Response, the Electronic Warfare (EW) Planning Aid, the Tactical Simulator (TACSIM) Technology Refresh, and MK-59, SLQ-32(V)6 and (V)7 Integration. PU 2190 - The Offboard Active Decoy (Nulka) is a joint cooperative program between the United States and Australia that developed an active offboard decoy that utilizes a broadband radio frequency repeater mounted atop a hovering rocket. Nulka counters a wide variety of present and future radar guided Anti-Ship Missiles (ASMs) by radiating a large radar cross section while flying a ship-like trajectory. The United States developed the electronic payload and fire control system, while Australia developed the hovering rocket. The FY27 budget request includes Decoy Launcher Processor (DLP) Nulka Objective Architecture, Decoy Launch Message Converter (DLMC) backward compatibility technology with Soft Kill Coordination System (SKCS), as well as funding to commence Nulka Payload Improvements for EW capability. The Objective Architecture development will continue which provides improved Nulka decoy deployment as well as SKCS integration. PU 3068 - The Long Endurance Electronic Decoy (LEED) program will deliver an expendable long endurance autonomous off-board decoy Countermeasure system, comprised of a flight vehicle and Radio Frequency (RF) payload with modular capability allowing for rapid modification of the Electronic Warfare (EW) capability. LEED development executes under a Middle Tier of Acquisition Rapid Prototyping (MTA RP) strategy pursuant to Section 804 of the FY 2016 National Defense Authorization Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                                  Date: April 2026 Appropriation/Budget Activity                                                       R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 5: System                 PE 0604757N / Ship Self Def (Engage: Soft Kill/EW) Development & Demonstration (SDD) Act. LEED will integrate with SLQ-32 and address EW gaps in response to a fleet requirement to counter legacy, modern, and future Anti-Ship Missile (ASM) threats. LEED will provide the fleet with enhanced EW coordination and capability, including the ability to stretch engagement timelines and counter heterogeneous missile attacks. The overarching LEED strategy consists of two phases including a MTA RP phase followed by Major Capability Acquisition. The MTA RP phase will include Preliminary and Integrated Countermeasure Prototype Development (FY 2021-FY 2025) and Integrated System Testing (FY 2025-FY 2026). The MTA RP phase includes the development and test of operational-level Countermeasure prototypes, launch systems, and control software that demonstrate and validate critical capabilities; including flight performance, control, and payload functionality. Data collected from the initial prototypes will be used to develop Engineering Development Models (EDMs) for Qualification Testing to support a Milestone C decision for Low Rate Initial Production (LRIP) as LEED enters the Major Capability Acquisition phase. FY 2027 funding requests supports planned improvements and subsequent testing of the LEED prototype system to include technique advancement, software updates, tactic updates, system effectiveness assessments, improvements in targeted technical performance measurements, necessary material purchases for test and evaluation activities, cybersecurity advancement, and development of a countermeasure model to support system of systems modeling and simulation activities. Funding also supports further integration with shipboard EW and combat systems and advancement of systems of systems interoperability, testing, and subsequent curriculum updates. Funding request supports prototype shipset hardware completion and installation aboard a US ship. FY 2027 funding request also supports the continued development of the Block 2 payload and countermeasure which will integrate with the LEED's Decoy Launching System in line with the program's required insertion of rapid EW capability and modularity concept. PU 3316 - The Advanced Offboard EW (AOEW) program was for the development of long duration off-board decoys integrated with onboard systems for EW coordination to counter identified EW gaps (additional details classified) in response to an urgent operational need. Divestment of AOEW is starting in FY 2026. AOEW Capability Development Document (CDD) was cancelled and requirements were transferred to other programs. PU 3321 - SEWIP Block 3 is developing an advanced Electronic Attack (EA) capability to keep pace with the evolving Anti-Ship Missile (ASM) threat and counter- targeting required for the AN/SLQ-32(V) system. SEWIP Block 3 will provide the AN/SLQ-32(V)7 system for all surface ships (CVN, DDG, LHD) outfitted with the active variant of the AN/SLQ-32, mainly the (V)3 and (V)4, as well as select new construction platforms. The SEWIP Block 3 Acquisition leverages technology developed under the Office of Naval Research's (ONR) Integrated Topside (InTop) Science and Technology (S&T) effort. SEWIP Block 3 will continue to expand the integrated shipboard combat system by providing new integrated EA transmitters, arrays, and associated EA techniques. The AN/SLQ-32(V)7 integrates the new EA countermeasure (SEWIP Block 3) with the AN/SLQ-32(V)6. The AN/SLQ-32(V)6 includes an Electronic Support (ES) receiver (SEWIP Block 2), a display console, and backend electronics. SEWIP Block 3 includes the government software development and integration effort for a SoftKill Coordinator (SKC) to manage EA engagements. SEWIP Block 3 is developing an Electronic Warfare Test Bed (EWTB) to validate system performance via modeling and simulation. SEWIP Block 3 is also investigating higher efficiency Gallium Nitride (GaN) High Power Amplifiers (HPA). GaN HPAs are used in maritime advanced technology radar and surface electronic warfare systems. For radar and electronic warfare systems, this will yield technology to incorporate and integrate into radar and electronic warfare Transmit/Receive Module designs, with a beneficial impact of improved Power Added Efficiency (PAE) for the systems resulting in a reduction in power draw from ship's service electrical power for the same radar and electronic warfare system performance. To keep pace with evolving ASM threats and counter-targeting, SEWIP Block 3 will incorporate capability improvements via a technology insertion plan. This capability improvement plan will mature and develop technologies and software/firmware to expand and improve capability for insertion into SEWIP Block 3. Technology solutions will result in technical data packages and tactical software with Government-owned data rights. Solutions will be incorporated into the SEWIP Block 3 technical data packages and tactical software for incorporation into future production and/or back-fit of fielded systems. The FY27 funding Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                               Date: April 2026 Appropriation/Budget Activity                                               R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 5: System         PE 0604757N / Ship Self Def (Engage: Soft Kill/EW) Development & Demonstration (SDD) request for SEWIP Block 3 will focus on continued Software and Hardware baseline upgrades, capability improvement design and development, training curriculum development and EW Testbed model upgrades. 3469 - Scaled Onboard Electronic Attack (SOEA) is an incremental development program executing under PU 3469 by the USN to provide an advanced Electronic Attack (EA) capability against anti-ship missiles. The program is intended to be scalable for Surface Combatants with size, weight, power, and cooling (SWaP-C) constraints that cannot support AN/SLQ-32(V)7; however, it is not intended to replace AN/SLQ-32(V)7. SOEA development executes under a Middle Tier of Acquisition Rapid Prototyping acquisition strategy pursuant to Section 804 of the FY16 National Defense Authorization Act. The SOEA Middle Tier of Acquisition (MTA) leverages technology developed by the Office of Naval Research (ONR) and Naval Research Laboratory (NRL). SOEA's acquisition strategy consists of two phases: Rapid Prototyping and Rapid Fielding. SOEA Phase 1 includes prototyping of critical technology elements (CTEs) via Defense Microelectronics Agency (DMEA) contract agreements to prove out and validate critical performance capability, system architecture functionality, supportability requirements and improvements that build on the CTEs. SOEA Phase 2 will focus on fielding initial capability through the producibility of the Phase 1 prototype, continuing hardware and software improvements to meet full capability objectives, continuing external interfaces for system and platform integration, continuing training module development via the Surface Electronic Warfare Tactical Trainer (SEWTT) and completing Modeling & Simulation (M&S) to support further testing. SOEA will continue to expand the integrated shipboard combat system by providing new integrated EA capability and will be integrated with AN/SLQ-32(V)6. SOEA also includes a government software development and integration effort for a Soft-Kill Coordinator System (SKCS) to manage EA engagements. The FY27 budget request for SOEA supports the continuation of Phase 1 Rapid Prototyping, including developmental/performance testing, SEWTT training module development, Modeling & Simulation (M&S) and SKCS integration. The FY27 budget request continues Phase 1 activities and also supports the initiation of SOEA Phase 2 Rapid Fielding which supports further land-based and environmental testing, initiates software and hardware baseline upgrades, and supports acquisition of additional prototype units if required.$$, $$Budget J-Books/FY27/Navy/RDTEN_BA5_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604759A$$, $$Major T&E Investment$$, $$rdte_army_ba6$$, $$devcom_avmc$$, 2026, 101027000, 87687000, 98613000, NULL, $${"act": "06", "ba_raw": "6.6", "source": "r1_fy26", "service": "army", "page_num": 20, "original_pe": "0604759A", "page_header": "Department of the Army", "fy26_v182_disc_K": 129527, "fy26_v182_supp_K": 184200, "fy26_v182_total_K": 313727, "fy26_v182_note_name": "Major T&E Investment", "fy26_v182_source_file": "RDTE - Vol 4 - Budget Activity 6.txt", "fy26_v182_source_line": 1676}$$::jsonb, $$This Program Element (PE) funds the development and acquisition of major developmental test instrumentation for the United States (U.S.) Army Test and Evaluation Command's (ATEC) test activities: White Sands Test Center (WSTC), New Mexico; Yuma Test Center (YTC), Arizona; Aberdeen Test Center (ATC), Maryland; Electronic Proving Ground (EPG), Arizona; Redstone Test Center (RTC), Alabama; and for the Reagan Test Site (RTS) at the United States Army Kwajalein Atoll (USAKA), which is managed by the Space and Missile Defense Command. This PE also funds development and acquisition of Operational Test Command's (OTC) major field instrumentation, management of the Cyber Acquisition Blue Teams (CABT) certification standards. Requirements for instrumentation and cyber certifications are identified through a long range survey of project managers, Research Development and Engineering Centers (RDECs), and Battle Laboratories developing future weapon systems and the test programs that support these systems. Army testing facilities are also surveyed to determine major testing capability shortfalls. This funding line supports testing of Army Modernization Priority Programs. FY25 funding in the amount of $3.269 million is in support of the Pacific Defense Initiative. The FY 2026 request was reduced by $0.394 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative." Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                             Date: June 2025 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 6: RDT&E            PE 0604759A / Major T&E Investment Management Support$$, NULL, 105938000, 107373000, 108417000, NULL, NULL, 175, $$RDTE - Vol 4 - Budget Activity 6.pdf$$, NULL, FALSE, 100235000, 313727000, 106140000, 106140000, NULL, 106140000, 109499000, $$This Program Element (PE) funds the development and acquisition of major developmental test instrumentation for the United States (U.S.) Army Test and Evaluation Command's (ATEC) test activities: White Sands Test Center (WSTC), New Mexico; Yuma Test Center (YTC), Arizona; Aberdeen Test Center (ATC), Maryland; Electronic Proving Ground (EPG), Arizona; Redstone Test Center (RTC), Alabama; and for the Reagan Test Site (RTS) at the United States Army Kwajalein Atoll (USAKA), which is managed by the Space and Missile Defense Command. This PE also funds development and acquisition of Operational Test Command's (OTC) major field instrumentation, management of the Cyber Acquisition Blue Teams (CABT) certification standards. Requirements for instrumentation and cyber certifications are identified through a long range survey of project managers, Research Development and Engineering Centers (RDECs), and Battle Laboratories developing future weapon systems and the test programs that support these systems. Army testing facilities are also surveyed to determine major testing capability shortfalls. This funding line supports testing of Army Modernization Priority Programs. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                              Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 6: RDT&E             PE 0604759A / Major T&E Investment Management Support$$, $$Budget J-Books/FY27/Army/RDTE - Vol 4 - Budget Activity 6.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604759F$$, $$Major T&E Investment$$, $$rdte_af_ba6$$, $$aftc$$, 2026, 156915000, 30758000, 74228000, NULL, $${"ba_raw": "6.6", "source": "af_r1_fy26", "original_pe": "0604759F"}$$::jsonb, $$This PE provides planning, improvements, and modernization for test capabilities within Air Force Test Center (AFTC) Major Range and Test Facility Base (MRTFB) organizations: 96 Test Wing (TW) at Eglin AFB FL, the 412TW at Edwards AFB CA, and Arnold Engineering Development Complex (AEDC) at Arnold AFB TN. The 704th Test Group (TG) at Holloman AFB NM is aligned under AEDC as part of the management consolidation of Ground test capabilities. The Improvement and Modernization (I&M) requirements are defined through the AF Test Investment Planning & Programming (TIPP) Process. All projects have been reviewed through the Tri-Service Reliance Process (to communicate AF efforts to the other services and avoid unwarranted duplication of effort) and are documented in the Technology Development Acquisition Program (TDAP) database. Each project has its own planning, development, equipment acquisition, equipment installation, and checkout phases which often require significant differences in funding from one year to the next. As such, the changes in category funding from year-to-year does not necessarily indicate program growth, but rather a planned phasing of I&M efforts. The test capabilities at these locations enable testing through all phases of weapon system acquisition, from system concept exploration through component and full-scale integrated weapon system test to operational test. The 96TW conducts and supports Developmental Test and Evaluation (DT&E) of non-nuclear air armaments; Command, Control, Communications, Computers, Cyber, Intelligence, Surveillance, Reconnaissance (C5ISR) systems; target acquisition and weapon delivery systems; determines target/test item spectral signatures; and provides cyber testing capabilities as part of the Avionics Cyber Range (ACR). The 412TW conducts and supports DT&E and Operational Test and Evaluation (OT&E) of aircraft and aircraft systems, aerospace research vehicles, unmanned aerial vehicles, cruise missiles, parachute delivery/recovery/systems, and cargo handling systems. AEDC provides pre-flight reliability environmental test support for DoD aero propulsion, flight systems, and space and missile programs. AEDC has 72 test facilities providing: aerodynamic testing of scale model aircraft, missiles, and space systems; testing of large and full-scale satellites, sensors, and space vehicles in a simulated space environment; altitude environmental testing for aircraft, missile, and spacecraft propulsion systems; testing of large-scale models such as space boosters together with their propulsion systems. The 704TG provides flight test and test support for joint, international and commercial customers in advanced avionics and weapons, inertial navigation systems, Global Positioning System (GPS) and other integrated aircraft and missile navigation systems. They test subsonic through hypersonic ground performance of aircraft and missiles in a flight-representative, highly instrumented environment while also coordinating and scheduling all USAF test operations at White Sands Missile Range. The 704TG OL-AC at Wright-Patterson AFB, OH provides independent DT&E in support of aircraft survivability and evaluation of full- scale aircraft landing gear, tires and brakes. They also provide an independent capability for component qualification. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                                Date: June 2025 Appropriation/Budget Activity                                                        R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 6: RDT&E              PE 0604759F / Major T&E Investment Management Support In order to align the strategic capability goals set forth in the National Defense Strategy and the mission of the AFTC, funding has been assigned to these five mission area categories: T&E Range Asset Modernization, Hypersonics, Directed Energy, Cyberspace and Avionics Cyber, and Autonomy. 1) T&E Range and Test Asset Modernization refers to those capabilities required to acquire the ability to test long range, high-speed, highly instrumented, high-data rate weapons in a crowded and restricted spectrum, while operating at multiple classification and cybersecurity levels. Also included in this mission area is the ability to collect, analyze and store big data and the ability to do multi-domain testing across the enterprise with realistic threat scenarios at multiple classification level up to Special Access Program (SAP). 2) Hypersonics refers to the ability to test and evaluate flight-representative hypersonic engines, materials, warheads and fuses in all portions of the employment envelope and conduct flight testing both in simulation and open-air ranges with sufficient space, telemetry, photo-optics and Time Space Position Information (TSPI) to appropriately inform decision-makers fielding such systems. 3) Directed Energy/Electronic Combat acquires the ability to characterize irradiance and beam properties on aircraft, small UAVs and ground targets and create realistic environments to simulate adversary air defense capabilities in the year 2030. Enables 5th-6th generation weapon testing/tactics development in a threat-realistic Anti- Access Area Denial (A2AD) environment using a combination of indoor and open-air ranges. 4) Cyberspace and Avionics Cyber is the advancement of cybersecurity/resiliency test capability for network, C5ISR, and airborne weapon platforms and includes development of tools, techniques and hardware-in-the-loop capabilities focused on cybersecurity and cyber-resiliency. 5) Autonomy refers to the ability to test autonomous aerial and ground systems with hundreds of independent vehicles. Must be able to monitor system-under-test locations and states with the ability for soft and hard termination. Must develop techniques and processes to test systems with artificial intelligence. This program is in Budget Activity 6, RDT&E Management Support because this budget activity includes research, development, test and evaluation efforts and funds to sustain and/or modernize the installations or operations required for general research, development, test and evaluation. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                            Date: June 2025 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 6: RDT&E          PE 0604759F / Major T&E Investment Management Support$$, NULL, 239201000, 228106000, 232407000, NULL, NULL, 126, $$FY26 Air Force Research and Development Test and Evaluation Vol III.pdf$$, NULL, FALSE, 65962000, 157959000, 235405000, 235405000, 0, 235405000, 240045000, $$This Program provides planning, improvements, and modernization for test capabilities within Air Force Test Center (AFTC) Major Range and Test Facility Base (MRTFB) organizations. This Program annually resources 10-30 unique, time-phased projects across the Center, changing from year to year as projects complete and others are started. Funding varies year to year based on project phases (planning, acquisition, installation, etc.), requiring significant differences in funding from one year to the next. As such, the changes in category funding from year-to-year does not necessarily indicate program growth, but rather a planned phasing of I&M efforts across the following sites: - 96 TW (Eglin AFB, FL): Non-nuclear weapons, C5ISR systems, target systems, spectral signatures, and cyber capabilities (Avionics Cyber Range - ACR). - 412 TW (Edwards AFB, CA): Aircraft, aerospace vehicles, UAVs, cruise missiles, parachute systems, and cargo handling. - AEDC (Arnold AFB, TN): Aero propulsion, flight systems, space and missile programs, providing simulated environments for testing satellites, sensors, space vehicles, and large-scale models. - 704 TG (Holloman AFB, NM): (Aligned under AEDC) Flight testing and support for advanced avionics, navigation systems, and aircraft/missile performance. Also coordinates USAF tests at White Sands. The 704TG OL-AC (Wright-Patterson AFB, OH) supports aircraft survivability, landing gear, tires and brakes testing, and component qualification. The Improvement and Modernization (I&M) program is managed as follows: - Requirements defined through the AF Test Investment Planning & Programming (TIPP) Process. - Projects are reviewed through the Tri-Service Reliance Process to avoid duplication with other branches. - Projects are documented in the Technology Development Acquisition Program (TDAP) database. - Test capabilities at AFTC locations enable testing through all phases of weapon system acquisition, from system concept exploration through component and full-scale integrated weapon system test to operational test. Funding is allocated to the following five key mission areas: 1. T&E Range and Test Asset Modernization: Testing long-range, high-speed weapons in complex environments, handling big data, and multi-domain testing with realistic threats. 2. Hypersonics: Testing hypersonic engines, materials, and flight testing capabilities (simulation and open-air). 3. Directed Energy/Electronic Combat: Characterizing beam properties and simulating adversary air defense capabilities for 5th/6th generation weapon testing. 4. Cyberspace and Avionics Cyber: Improving cybersecurity/resiliency testing for networks, C5ISR, and airborne weapons. 5. Autonomy: Testing autonomous aerial and ground systems with many vehicles, focusing on monitoring, termination, and testing systems with artificial intelligence. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                            Date: April 2026 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 6: RDT&E          PE 0604759F / Major T&E Investment Management Support This program element included all necessary expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 0606398F and 0605807F. This program is in Budget Activity 6, RDT&E Management Support because this budget activity includes research, development, test and evaluation efforts and funds to sustain and/or modernize the installations or operations required for general research, development, test and evaluation.$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume III.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604759N$$, $$Major T&E Investment$$, $$rdte_navy_ba6$$, $$asn_rda$$, 2026, 61946000, 88193000, 65672000, NULL, $${"act": "06", "ba_raw": "6.6", "source": "r1_fy26", "service": "navy", "page_num": 36, "original_pe": "0604759N", "page_header": "Department of the Navy"}$$::jsonb, $$This project corrects major deficiencies, improves Test & Evaluation (T&E) capabilities, and increases T&E support effectiveness at Navy Major Range and Test Facility Base ranges and facilities. The T&E Investment project improves, modernizes and adds new test capabilities at the following test facilities: the Naval Undersea Warfare Center Division Newport Atlantic Undersea Test and Evaluation Center, Andros Island, Bahamas; the Nanoose and Dabob ranges of the Naval Undersea Warfare Center Division Keyport, Keyport, WA; the Sea Range, Land Ranges, Target Operations, Ordnance T&E Facility, Test Wing Pacific located at the Naval Air Warfare Center Weapons Division, Point Mugu, CA and China Lake, CA; and the Atlantic Test Range, Air Combat Environment T&E Facility, Electromagnetic Environmental Effects, Air Vehicle Modification and Instrumentation facility, Test Wing Atlantic, Target Operations, and the Propulsion Systems Evaluation Facility located at the Naval Air Warfare Center Aircraft Division, Patuxent River, MD and the test and evaluation capabilities located at the Pacific Missile Range Facility, Kauai, HI. JUSTIFICATION FOR BUDGET ACTIVITY: This program is funded under RESEARCH, DEVELOPMENT, TEST and EVALUATION MANAGEMENT SUPPORT because it supports efforts directed toward sustaining or modernizing installations or operations required for general research, development, test and evaluation.$$, NULL, 153532000, 151025000, 135598000, NULL, NULL, 188, $$RDTEN_BA6_Book.pdf$$, NULL, FALSE, 65039000, 64842000, 112458000, 112458000, NULL, 112458000, 137980000, $$This project corrects major deficiencies, improves Test & Evaluation (T&E) capabilities, and increases T&E support effectiveness at Navy Major Range and Test Facility Base (MRTFB) ranges and facilities. The T&E Investment project improves, modernizes and adds new test capabilities at the following test facilities: the Naval Undersea Warfare Center Division Newport Atlantic Undersea Test and Evaluation Center, Andros Island, Bahamas; the Nanoose and Dabob ranges of the Naval Undersea Warfare Center Division Keyport, Keyport, WA; the Sea Range, Land Ranges, Target Operations, Ordnance T&E Facility, Test Wing Pacific located at the Naval Air Warfare Center Weapons Division, Point Mugu, CA and China Lake, CA; and the Atlantic Test Range, Air Combat Environment T&E Facility, Electromagnetic Environmental Effects, Air Vehicle Modification and Instrumentation facility, Test Wing Atlantic, Target Operations, and the Propulsion Systems Evaluation Facility located at the Naval Air Warfare Center Aircraft Division, Patuxent River, MD and the test and evaluation capabilities located at the Pacific Missile Range Facility, Kauai, HI. JUSTIFICATION FOR BUDGET ACTIVITY: This program is funded under RESEARCH, DEVELOPMENT, TEST and EVALUATION MANAGEMENT SUPPORT because it supports efforts directed toward sustaining or modernizing installations or operations required for general research, development, test and evaluation.$$, $$Budget J-Books/FY27/Navy/RDTEN_BA6_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604760A$$, $$Distributive Interactive Simulations (DIS) - Eng Dev$$, $$rdte_army_ba5$$, $$asa_alt$$, 2026, 7724000, 8481000, 8914000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "army", "page_num": 16, "original_pe": "0604760A", "page_header": "Department of the Army"}$$::jsonb, $$The program element applies to the Army's Advanced Simulation Program, which enables operational readiness and the development of concepts and systems for the Future Force through the application of new simulation technology and techniques. The development and application of simulation technology will provide the means to link electronically a range of various simulation tools in a manner that is transparent to the user. The amalgam of simulations and tools is linked together to enable execution of an event; to verify the scenarios, tactics/techniques and procedures; to train testers on new hardware/software; and to conduct trial test runs before costly live field tests. The tools developed are available for reuse by developers and users of simulations throughout the Army. Project C74, Devel Simulation tech, funds the Headquarters Department of the Army-chartered mission of the Simulation-to-Mission Command Interoperability (SIMCI) Overarching Integrated Product Team (OIPT) in support of Army Training and Readiness. The SIMCI OIPT mission is to provide policy recommendations to Army senior leadership to improve organizations by allowing Soldiers to fight in the same manner in which they train. This is accomplished by interoperability between Mission Command (MC) systems and the Modeling and Simulation (M&S) systems that the Army uses to stimulate MC systems for training Soldiers and their Leaders. SIMCI also invests in targeted solutions to critical problem areas that exist between MC and Simulations. The SIMCI OIPT uses focused collaborative processes among its 30+ Army organizations to identify key/critical interoperability shortfalls and the required materiel solutions. Project C77, Army Geospatial Data Master Plan, focuses on activities that start with data acquisition from multiple sources and culminate in (1) accurate, robust and timely geospatial data and data management and (2) integration and conversion tools that support multiple battle command, training and mission-rehearsal applications. Project C77 continues development efforts associated with the Ground-Warfighter Geospatial Data Model (GGDM) and Geospatial Data Standards. Project C78, One Semi-Automated Forces (OneSAF), develops and delivers a software application that represents activities of units and forces in simulation to support Army Training and Readiness. The application is used by Army agencies to support the concept evaluation, experimentation, materiel acquisition and training throughout the communities. The focus of this project is systems/software engineering and design for development and evolution of the architecture and software tools for a universal system of Army computer-generated forces -- OneSAF. OneSAF is a high fidelity brigade-and-below SAF that represents a full range of operations, systems and control processes in support of stand-alone and embedded training and Research, Development and Acquisition (RDA) simulation applications. OneSAF is fully interoperable with the Army's emerging virtual, live, and division-and-above constructive simulations and provides next-generation simulation products. OneSAF replaces a variety of legacy simulations used within the Army to support analytic and training simulation activities. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                                Date: June 2025 Appropriation/Budget Activity                                                     R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 5: System               PE 0604760A / Distributive Interactive Simulations (DIS) - Eng Dev Development & Demonstration (SDD) Distributive Interactive Simulations (DIS) - Eng Dev program is part of the Army Transformation Initiative. The FY 2026 request was reduced by $0.316 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative."$$, NULL, 7970000, 8032000, 8118000, NULL, NULL, 117, $$RDTE - Vol 3 - Budget Activity 5B.pdf$$, NULL, FALSE, 8589000, 7724000, 7883000, 7883000, NULL, 7883000, 8199000, $$The PE applies to the Army's Advanced Simulation Program, which enables operational readiness and the development of concepts and systems for the Future Force through the application of new simulation technology and techniques. The development and application of simulation technology will provide the means to link electronically a range of various simulation tools in a manner that is transparent to the user. The amalgam of simulations and tools is linked together to enable execution of an event; to verify the scenarios, tactics/techniques and procedures; to train testers on new hardware/software; and to conduct trial test runs before costly live field tests. The tools developed are available for reuse by developers and users of simulations throughout the Army. Project C74, Devel Simulation tech, funds the Headquarters Department of the Army-chartered mission of the Simulation-to-Mission Command Interoperability (SIMCI) Overarching Integrated Product Team (OIPT) in support of Army Training and Readiness. The SIMCI OIPT mission is to provide policy recommendations to Army senior leadership to improve organizations by allowing Soldiers to fight in the same manner in which they train. This is accomplished by interoperability between Mission Command (MC) systems and the Modeling and Simulation (M&S) systems that the Army uses to stimulate MC systems for training Soldiers and their Leaders. SIMCI also invests in targeted solutions to critical problem areas that exist between MC and Simulations. The SIMCI OIPT uses focused collaborative processes among its 30+ Army organizations to identify key/critical interoperability shortfalls and the required materiel solutions. Project C77, Army Geospatial Data Master Plan, focuses on activities that start with data acquisition from multiple sources and culminate in (1) accurate, robust and timely geospatial data and data management and (2) integration and conversion tools that support multiple battle command, training and mission-rehearsal applications. Project C77 continues development efforts associated with the Ground-Warfighter Geospatial Data Model (GGDM) and Geospatial Data Standards. Project C78, One Semi-Automated Forces (OneSAF), develops and delivers a software application that represents activities of units and forces in simulation to support Army Training and Readiness. The application is used by Army agencies to support the concept evaluation, experimentation, materiel acquisition and training throughout the communities. The focus of this project is systems/software engineering and design for development and evolution of the architecture and software tools for a universal system of Army computer-generated forces -- OneSAF. OneSAF is a high-fidelity brigade-and-below SAF that represents a full range of operations, systems and control processes in support of stand-alone for embedded training and Research, Development and Acquisition (RDA) simulation applications. OneSAF is fully interoperable with the Army's emerging virtual, live, and division-and-above constructive simulations and provides next-generation simulation products. OneSAF replaces a variety of legacy simulations used within the Army to support analytic and training simulation activities. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                              Date: April 2026 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 5: System             PE 0604760A / Distributive Interactive Simulations (DIS) - Eng Dev Development & Demonstration (SDD)$$, $$Budget J-Books/FY27/Army/RDTE - Vol 3 - Budget Activity 5A.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604761N$$, $$Intelligence Engineering$$, $$rdte_navy_ba5$$, $$asn_rda$$, 2026, 7023000, 21095000, 23810000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "navy", "page_num": 34, "original_pe": "0604761N", "page_header": "Department of the Navy", "fy27_base_v158_t7": "hygiene: base=request for disc-only RDT&E rows post v7 I-23/I-24 + v9 I-2 INSERTs"}$$::jsonb, $$The details of this program element are classified SECRET and are submitted annually to Congress in the classified budget justification books.$$, NULL, NULL, NULL, NULL, NULL, NULL, 156, $$RDTEN_BA5_Book.pdf$$, NULL, FALSE, NULL, NULL, 6426000, 6426000, NULL, 6426000, NULL, NULL, $$Budget J-Books/FY27/Remaining/FY2027_r1.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604771D8Z$$, $$Joint Tactical Information Distribution System (JTIDS)$$, $$rdte_dw_ba5$$, $$dw$$, 2026, 10527000, 9406000, 12893000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "dw", "page_num": 74, "fy27_mand_k": 23129, "original_pe": "0604771D8Z", "page_header": "Defense-Wide", "fy27_mand_v157": "2026-05-08", "fy27_mand_source": "DoW_FY2027_Mandatory_Funding_Overview.txt Appendix B", "fy27_mand_section": "Defense Industrial Base"}$$::jsonb, $$This program supports the Department's initiatives to Defend the Homeland, Provide Nuclear Deterrence, and Build Sustainable and Long-Term Advantage. This program provides in-depth technical, engineering, integration support, to manage, analyze, and inform acquisition and resourcing decisions in information and integration portfolios, to include nuclear weapons systems; nuclear command, control, and communications (NC3); missile defense; command, control, communications, computers, intelligence, surveillance, and reconnaissance (C4/ISR); and space systems - C4ISR: Develop and maintain a roadmap to improve data link interoperability, data link waveform standards, and global enterprise capabilities, enabling resilient, survivable, federated networks. - NC3 and Strategic Deterrence: Execute NC3 Enterprise Capability Portfolio Management on behalf of the Office of the Under Secretary of Defense for Acquisition and Sustainment (USD(A&S)). Provides acquisition expertise to recapitalize the nation's nuclear deterrent and reduce risk in nuclear modernization programs. - Space and Missile Defense (SMD): Provides acquisition expertise to inform synchronized modernization and fielding of space and missile defense systems, including Space Control, Remote Sensing, Satellite Communication (SATCOM), Position, Navigation and Timing (PNT), launch, and homeland and regional missile defense capabilities. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Office of the Secretary Of Defense                                              Date: June 2025 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 5:           PE 0604771D8Z / Joint Tactical Information Distribution System (JTIDS) System Development & Demonstration (SDD)$$, NULL, 9971000, 10101000, 10321000, NULL, NULL, 145, $$RDTE_OSD_PB_2026.pdf$$, $$OSD$$, FALSE, 12426000, 10380000, 10200000, 10200000, 23129000, 33329000, 10527000, $$The FY 2027 request for Joint Tactical Information Distribution System (JTIDS) includes $10,200 thousand of discretionary and $23,129 thousand of mandatory for a total of $33,329. The mandatory funds acquisition support of Combined Joint All-Domain Command and Control (CJADC2) to establish the Joint Fires Network ACAT ID program; establish a Golden Dome program office and associated program plans to deliver a national Integrated Air and Missile Defense system and accelerate acquisition of Standard Missile 3. Funds support the increasing National Intelligence major system acquisition programs. Increase in funding allows the Deputy Assistant Secretary of War Strategic, Space, and Intelligence Portfolio Management (DASW SSIPM) to fully support Presidential, Deputy Secretary of War and USW(A&S) initiatives Executive Order (EO) 14186, “The Iron (Golden) Dome for America, EO 14625 “, Modernizing Defense Acquisitions and Spurring Innovation in the Defense Industrial Base,“ Secure Enclave, Key Management Infrastructure Capability Increment 3, and Congressional direction and achieve the desired outcomes, such as strengthening program execution. This program supports the Department's initiatives to Restoring Warrior Ethos, Rebuilding Military Capabilities and Re-establishing Deterrence. This program Manages, analyzes, and informs acquisition and resourcing decisions in the nuclear modernization/acquisition; nuclear command, control, and communications (NC3); space and national intelligence (SNI); and command, control, communications, computers, and missile defense (C4MD) portfolios - C4MD: Inform synchronized modernization and delivery of new command, control, communications, and computer systems. Supports defending the homeland, paced to the growing multi-domain threat posed by China and deterring aggression while being prepared to prevail in conflict, when necessary; prioritizing the challenge posed by China in the Indo-Pacific region the Russia challenge in Europe. - SNI: Inform synchronized modernization and fielding of space and national intelligence systems, including Space Control, Remote Sensing (e.g., Missile Warning), and National Security Space Launch. Supports defending the homeland, paced to the growing multi-domain threat posed by China and deterring aggression while being prepared to prevail in conflict, when necessary; prioritizing the challenge posed by China in the Indo-Pacific region the Russia challenge in Europe. - NC3: Execute an NC3 Capability Portfolio Management per Title 10 U.S. Code §133b and Dow Directive 3730.02. Supports Deterring strategic attacks against the United States, allies, and partners per 2022 NDS, pg. 9, Section IV, Integrated Deterrence. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Office of the Secretary Of Defense                                             Date: April 2026 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 5:          PE 0604771D8Z / Joint Tactical Information Distribution System (JTIDS) System Development & Demonstration (SDD)$$, $$Budget J-Books/FY27/Remaining/DoW_FY2027_Mandatory_Funding_Overview.txt$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604771N$$, $$Medical Development$$, $$rdte_navy_ba5$$, $$navsea$$, 2026, 7629000, 17475000, 8371000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "navy", "page_num": 34, "original_pe": "0604771N", "page_header": "Department of the Navy"}$$::jsonb, $$The purpose of this program is to develop biomedical equipment and related techniques to reduce morbidity; to enhance the logistic feasibility of modern medical care for combat casualties; to sustain casualties for evacuation to fixed medical facilities for definitive care; and to ensure that personnel are medically qualified for military duty. Each work unit undertaken in this project has a military requirement. Efforts are justified based upon military payoff and cost benefit. There is a strong potential for dual use, technology transfer, and biotechnology firm/industry participation in the projects.$$, NULL, 7098000, 7219000, 7266000, NULL, NULL, 157, $$RDTEN_BA5_Book.pdf$$, NULL, FALSE, 8110000, 11487000, 6900000, 6900000, NULL, 6900000, 7403000, $$The purpose of this program is to develop biomedical equipment and related techniques to reduce morbidity; to enhance the logistic feasibility of modern medical care for combat casualties; to sustain casualties for evacuation to fixed medical facilities for definitive care; and to ensure that personnel are medically qualified for military duty. Each work unit undertaken in this project has a military requirement. Efforts are justified based upon military payoff and cost benefit. There is a strong potential for dual use, technology transfer, and biotechnology firm/industry participation in the projects.$$, $$Budget J-Books/FY27/Navy/RDTEN_BA5_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604774D8Z$$, $$Defense Readiness Reporting System (DRRS)$$, $$rdte_dw_ba6$$, $$dw$$, 2026, 8552000, 12512000, 11415000, NULL, $${"act": "06", "ba_raw": "6.6", "source": "r1_fy26", "service": "dw", "page_num": 75, "original_pe": "0604774D8Z", "page_header": "Defense-Wide"}$$::jsonb, $$This program supports the Department's initiatives to Defend the Nation, Take Care of People and Build Sustainable and Long-Term Advantage. This funding supports the Defense Readiness Reporting System - Strategic (DRRS-S), the comprehensive readiness reporting system for the Department of Defense mandated under Title 10 U.S. Code. The system measures, in an objective, accurate, and timely manner, the capability of the armed forces to carry out the National Security Strategy prescribed by the President, as well as, the defense planning guidance provided by the Secretary of Defense, and the National Military Strategy prescribed by the Chairman of the Joint Chiefs of Staff. DRRS-S hosts information and applications used to support the Geographic and Functional Combatant Commanders, the Services, Combat Support Agencies, the Joint Staff and the Office of the Secretary of Defense. DRRS-S is the evolution of readiness reporting to a more comprehensive system, better able to meet the Department’s current and future readiness information challenges. Included in these challenges is the expansion in scope of the entities who can and do report readiness. Shifting from solely resource centric readiness reporting to a resource informed mission and capabilities-based reporting system, oriented towards the National Military Strategy (NMS), makes substantially more complex demands on readiness reporting, but portrays a far more relevant and holistic picture of readiness. The challenges associated with sourcing and evaluating the readiness of our forces engaged in on-going real operations, mean that force managers need applications that will query the entire Department for suitable, available organizations to meet current needs. DRRS-S continues to incorporate more data and develop more capable functionality to meet the evolving needs of both the operational employers of the Force, but also those responsible for Force Generation. The National Defense Authorization Act for FY 2019 revised Title 10 U.S. Code and provided the Department of Defense direction requiring growth in the DRRS-S program and identified the program’s need to maintain the technical currency necessary to quickly meet future challenges associated with providing senior leaders with relevant and timely information. Such initiatives include implementing the complex data structures and visualization tools needed to operationalize the Department’s Enterprise Force Structure, (formerly referred to as Global Force Management - Data Initiative, (GFM DI)) and reporting at lower organizational levels consistent with how Forces are employed. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Office of the Secretary Of Defense                                             Date: June 2025 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 6:         PE 0604774D8Z / Defense Readiness Reporting System (DRRS) RDT&E Management Support$$, NULL, 9273000, 9365000, 9606000, NULL, NULL, 165, $$RDTE_OSD_PB_2026.pdf$$, $$OSD$$, FALSE, 11205000, 8492000, 8921000, 8921000, NULL, 8921000, 9605000, $$This program supports the Secretary of War priorities of rebuilding the military and reestablishing deterrence by optimizing core readiness functions to achieve peace through strength. The National Defense Strategy (NDS) for 2026 emphasizes innovation to enhance U.S. military capabilities and deter potential adversaries. This program supports the Defense Readiness Reporting System (DRRS), the single, comprehensive readiness reporting system for the Department of War mandated under Section 117, Title 10 U.S. Code. The system measures, in an objective, accurate, and timely manner, the capability of the armed forces to carry out the National Security Strategy prescribed by the President, as well as, the defense planning guidance provided by the Secretary of War, and the National Military Strategy (NMS) prescribed by the Chairman of the Joint Chiefs of Staff. DRRS hosts information and applications used to support the Geographic and Functional Combatant Commanders, the Services, Combat Support Agencies, the Joint Staff and the Office of the Secretary of War. DRRS is the evolution of readiness reporting to a more comprehensive system, better able to meet the Department’s current and future readiness information challenges. Included in these challenges is the expansion in scope of the entities who can and do report readiness. Shifting from solely resource centric readiness reporting to a resource informed mission and capabilities-based reporting system, oriented towards the NMS, makes substantially more complex demands on readiness reporting, but portrays a far more relevant and holistic picture of readiness. The challenges associated with sourcing and evaluating the readiness of our forces engaged in on-going real operations, mean that force managers need applications that will query the entire Department for suitable, available organizations to meet current needs. DRRS continues to incorporate more data and develop more capable functionality to meet the evolving needs of both the operational employers of the Force, but also those responsible for Force Generation. The National Defense Authorization Act for FY 2019 revised Title 10 of U.S. Code and provided the Department direction requiring growth in the DRRS program and identified the program’s need to maintain the technical currency necessary to quickly meet future challenges associated with providing senior leaders with relevant and timely information. Such initiatives include implementing the complex data structures and visualization tools needed to operationalize the Department’s Enterprise Force Structure, reporting at lower organizational levels consistent with how Forces are employed. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Office of the Secretary Of Defense                                            Date: April 2026 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 6:         PE 0604774D8Z / Defense Readiness Reporting System (DRRS) RDT&E Management Support$$, $$Budget J-Books/FY27/DW/RDTE_OSW_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604776F$$, $$Deployment & Distribution Enterprise R&D$$, $$rdte_af_ba3$$, $$dw_osd$$, 2026, 28316000, 0, 19441000, NULL, $${"source": "jbook_fy26", "fy27_base_v158_t7b": "I-3 hygiene: total=req but base held stale sibling value post v7 I-24"}$$::jsonb, $$In partnership with Services, Combatant Commands, OSD, select Defense Agencies, industry, and academia, this program collaboratively pursues the development, integration, field demonstration and assessment of contested logistics Joint Deployment and Distribution Enterprise (JDDE) and Joint Petroleum (JPE) capabilities. Contested logistics challenges include innovative projection and sustainment capabilities, seaport and airfield improvements, inventory/cargo management, materiel handling, cargo/container security, secure collaboration with commercial/interagency/coalition partners, and distributed global mobility C4. Intent is to improve the efficiency and effectiveness of logistics operations in support of the joint warfighter. This program is in Budget Activity 3, Advanced Technology Development because this budget activity includes development of subsystems and components and efforts to integrate subsystems and components into system prototypes for field experiments and/or tests in a simulated environment. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                            Date: June 2025 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 3: Advanced PE 0604776F / Deployment & Distribution Enterprise R&D Technology Development (ATD)$$, NULL, 5319000, 5419000, 5522000, NULL, NULL, 30, $$FY26 Air Force Research and Development Test and Evaluation Vol I.pdf$$, NULL, FALSE, 4840000, 4996000, 29109000, 29109000, 0, 29109000, 5634000, $$In partnership with the Services, Combatant Commands, Department of War , select Defense Agencies, industry and academia, this program collaboratively pursues the development, integration, field demonstration and assessment of contested logistics Joint Deployment and Distribution Enterprise (JDDE) and Joint Petroleum Enterprise (JPE) capabilities. Contested logistics challenges include innovative projection and sustainment capabilities, seaport and airfield improvements, inventory/ cargo management, materiel handling, cargo/container security, secure collaboration with commercial/interagency/coalition partners, and distributed global mobility C4. Intent is to improve the efficiency and effectiveness of logistics operations in support of the joint warfighter. This effort is in Budget Activity 4, Advanced Component Development and Prototypes (ACD&P), because efforts are necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment.$$, $$Budget J-Books/FY27/Remaining/FY2027_r1.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604777N$$, $$Navigation/Id System$$, $$rdte_navy_ba5$$, $$dw_osd$$, 2026, 3724000, 50863000, 44326000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "navy", "page_num": 34, "original_pe": "0604777N", "page_header": "Department of the Navy"}$$::jsonb, $$Reliable and secure navigation and positive identification (ID) systems are essential elements of battle management in the naval environment. The Photonics Imaging System (0253) is a non-hull penetrating replacement for existing optical periscopes. The Photonics Imaging System exploits a wide portion of the electro-magnetic spectrum utilizing advanced Electro-Optic/thermal imaging, and communications intercept/Electronic Warfare Support (ES). The Integrated Submarine Imaging System (ISIS) (0253) is a back fit system to integrate all imaging capabilities on existing submarine classes. Starting in FY26, funding for Project 0253 will move from PE 0604777N to PE 0604503N. The Combat Identification System (CIS) project (1253) for Mark XIIA, and Improved Identification Development (0676) for AN/UPX-29(V), covers the Mark XIIA Mode 5 upgrade to the existing Mark XII family of systems that is Joint and North Atlantic Treaty Organization (NATO) interoperable. Per Office Secretary of Defense (OSD) direction, NATO participation is encouraged, and performance data is exchanged to ensure the opportunity for interoperability with allied identification systems is maximized. In addition to distinguishing friend from foe for weapons employment, the Navy requires secure, jam resistant Identification Friend or Foe (IFF) systems for battle group air defense management and air traffic control. Identification is multifaceted and includes information received from several sensors (both cooperative and non-cooperative systems). Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Navy                                                                            Date: June 2025 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 5: System           PE 0604777N / Navigation/Id System Development & Demonstration (SDD)$$, NULL, 4384000, 4346000, 4178000, NULL, NULL, 158, $$RDTEN_BA5_Book.pdf$$, NULL, FALSE, 42932000, 3724000, 3388000, 3388000, NULL, 3388000, 4250000, $$Reliable and secure navigation and positive identification (ID) systems are essential elements of battle management in the naval environment. The Photonics Imaging System (Proj 0253) is a non-hull penetrating replacement for existing optical periscopes. The Photonics Imaging System exploits a wide portion of the electro-magnetic spectrum utilizing advanced Electro-Optic/thermal imaging, and communications intercept/Electronic Warfare Support (ES). The Integrated Submarine Imaging System (ISIS) (Proj 0253) is a back fit system to integrate all imaging capabilities on existing submarine classes. The Combat Identification System (CIS) project (Proj 1253) for Mark XIIA, and Improved Identification Development (Proj 0676) for AN/UPX-29(V), covers the Mark XIIA Mode 5 upgrade to the existing Mark XII family of systems that is Joint and North Atlantic Treaty Organization (NATO) interoperable. In addition to distinguishing friend from foe for weapons employment, the Navy requires secure, jam resistant Identification Friend or Foe (IFF) systems for battle group air defense management and air traffic control. Identification is multifaceted and includes information received from several sensors (both cooperative and non-cooperative systems). Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                 Date: April 2026 Appropriation/Budget Activity                                               R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 5: System         PE 0604777N / Navigation/Id System Development & Demonstration (SDD)$$, $$Budget J-Books/FY27/Navy/RDTEN_BA5_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604786N$$, $$Offensive Anti-Surface Warfare Weapon Dev$$, $$rdte_navy_ba4$$, $$asn_rda$$, 2026, 225773000, 253134000, 286407000, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "navy", "page_num": 31, "original_pe": "0604786N", "page_header": "Department of the Navy"}$$::jsonb, $$Offensive Anti-Surface Warfare (OASuW) is an offensive weapon system that is a vital component of the Joint Force Anti-Surface Warfare capability and incorporates new and emergent technologies to support an increased offensive strike capability utilizing multiple weapons. OASuW Increment 2 is a national imperative to maturing hypersonic capabilities. The program will provide the Navy a necessary weapon to address evolving long range high speed threats from near peer competitors. The OASuW program is part of the Navy's Long Range Fires (LRF) approach to address advanced threat capabilities in the Anti-Access/Area-Denial (A2AD) environment. LRF solutions enable individual system capabilities to be leveraged across an effects chain, placing the full spectrum of tactical capability in the hands of the warfighter. LRF solutions that push engagement distances beyond the launch platform's radar horizon and allows the U.S. Navy to operate in, and control, contested battle space in littoral waters and A2/AD environments are increasingly critical as more and more scenarios require compressed and coordinated fire control timelines. OASuW strategy pursues capability across multiple weapon systems to enhance warfighting capabilities. Project 3337 - Due to emerging threats, the fleet issued an Urgent Operational Needs Statement (UONS) that identified a capability gap for a long-range anti-ship missile to be filled by 2018. Directly supporting this UONS and significantly reducing Joint Force warfighting risks, the U.S. Navy initiated OASuW Increment 1 (OASuW-1), which leverages the Defense Advanced Research Projects Agency (DARPA)/Office of Naval Research Long Range Anti-Ship Missile (LRASM) demonstration program to deliver an Early Operational Capability (EOC) in the required timeframe. LRASM fills the most urgent air-launched capability gap to complement existing ASuW weapon systems and positions the Department of Defense to address evolving surface warfare threats. LRASM is integral to realizing the National Defense Strategy of combat-credible military forces to deter war, protect the security of our nation and to enable the Joint Force to win should deterrence fail. The development and acquisition of LRASM has been structured to be fielded at a pace relevant to maintain overmatch against long-term strategic competition. Specifically, LRASM directly contributes to building a more lethal force and is a critical enabler for joint lethality in contested environments; deterring adversaries from aggression; ensuring common domains remain open and maintaining favorable regional balances of power. Project 3343 - The Department of the Navy is developing OASuW Increment 2 to address weapon system requirements based on the OASuW Analysis of Alternatives (AoA). OASuW Inc. 2 will be a carrier-suitable, higher-speed, longer-range, air-launched weapon system providing superior Anti Surface Warfare capabilities. The program is part of the Navy's Long Range Fires investment approach to meet objectives of the National Defense Strategy. As a key component of this strategy, OASuW Inc. 2 will address advanced threats from engagement distances that allow the Navy to operate in, and control, contested battle space in littoral waters and Anti-Access/ Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Navy                                                                                    Date: June 2025 Appropriation/Budget Activity                                                     R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 4: Advanced             PE 0604786N / Offensive Anti-Surface Warfare Weapon Dev Component Development & Prototypes (ACD&P) Area Denial (A2/AD) environments. The program will leverage and further advance foundational achievements in the joint Science and Technology (S&T) enterprise, making targeted investments in Navy integration of critical system attributes. User priorities, in the form of pacing the evolving maritime threat, will be the centerpiece of the system requirements and the associated development and fielding schedule. Additional details are classified. Project 3466 - The LRASM C-3 program is established to improve OASuW and incorporate a long range strike capability into the Navy's arsenal derived from the Navy's AGM-158C-1 LRASM and the Air Force's AGM-158 JASSM-ER. The Navy will integrate an AGM-158 derived weapon onto F/A-18 E/F aircraft. This funding line resources requirements for Navy increased LRASM capabilities and strike mission integration by upgrading the existing AGM-158C product to respond to rapidly changing threats. Budget Item Justification: This program is funded under ADVANCED COMPONENT DEVELOPMENT AND PROTOTYPES because it includes all efforts necessary to evaluate integrated technologies, representative models or prototype systems in a high fidelity and realistic operating environment.$$, NULL, 125543000, 102877000, 73359000, NULL, NULL, 95, $$RDTEN_BA4_Book.pdf$$, NULL, FALSE, 273393000, 183023000, 104527000, 104527000, NULL, 104527000, 62715000, $$The Department encourages additional vendor participation in the design, development, and production of alternative weapons systems to meet current and future warfighting requirements. With current major weapons systems production at capacity, the nation is looking for alternative systems to fill these gaps. The Department is implementing diverse procurement strategies to enable rapid acquisition. These will include the use of Other Transaction Authorities, 'Marketplace' acquisition platforms, and alternative concepts to increase supply and suppliers in addition to traditional FAR-based procurement strategies. Offensive Anti-Surface Warfare (OASuW) is an offensive weapon system that is a vital component of the Joint Force Anti-Surface Warfare capability and incorporates new and emergent technologies to support an increased offensive strike capability utilizing multiple weapons. The OASuW program is part of the Navy's Long Range Fires (LRF) approach to address advanced threat capabilities in the Anti-Access/Area-Denial (A2AD) environment. LRF solutions enable individual system capabilities to be leveraged across an effects chain, placing the full spectrum of tactical capability in the hands of the warfighter. LRF solutions that push engagement distances beyond the launch platform's radar horizon and allows the U.S. Navy to operate in, and control, contested battle space in littoral waters and A2/AD environments are increasingly critical as more and more scenarios require compressed and coordinated fire control timelines. OASuW strategy pursues capability across multiple weapon systems to enhance warfighting capabilities. Project 3337 - Due to emerging threats, the fleet issued an Urgent Operational Needs Statement (UONS) that identified a capability gap for a long-range anti-ship missile to be filled by 2018. Directly supporting this UONS and significantly reducing Joint Force warfighting risks, the U.S. Navy initiated OASuW Increment 1 (OASuW-1), which leverages the Defense Advanced Research Projects Agency (DARPA)/Office of Naval Research Long Range Anti-Ship Missile (LRASM) demonstration program to deliver an Early Operational Capability (EOC) in the required timeframe. LRASM fills the most urgent air-launched capability gap to complement existing ASuW weapon systems and positions the Department of War to address evolving surface warfare threats. LRASM is integral to realizing the National Defense Strategy of combat-credible military forces to deter war, protect the security of our nation and to enable the Joint Force to win should deterrence fail. The development and acquisition of LRASM has been structured to be fielded at a pace relevant to maintain overmatch against long-term strategic competition. Specifically, LRASM directly Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                                  Date: April 2026 Appropriation/Budget Activity                                                          R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 4: Advanced                  PE 0604786N / Offensive Anti-Surface Warfare Weapon Dev Component Development & Prototypes (ACD&P) contributes to building a more lethal force and is a critical enabler for joint lethality in contested environments; deterring adversaries from aggression; ensuring common domains remain open and maintaining favorable regional balances of power. Project 3343 - The Department of the Navy is developing OASuW Increment 2 to address weapon system requirements based on the OASuW Analysis of Alternatives (AoA) and informed by forecast progression in peer competitor naval capabilities. OASuW Inc 2 will be a carrier-suitable, higher-speed, longer-range, air-launched weapon system providing superior Anti Surface Warfare capabilities. The program is part of the Navy's Long Range Fires investment approach to meet objectives of the National Defense Strategy. As a key component of this strategy, OASuW Inc 2 will address advanced threats from engagement distances that allow the Navy to operate in, and control, contested battle space in littoral waters and Anti-Access/Area Denial (A2/AD) environments. The program will leverage and further advance foundational achievements in the joint Science and Technology (S&T) enterprise, making targeted investments in Navy integration of critical system attributes. User priorities, in the form of pacing the evolving maritime threat, will be the centerpiece of the system requirements and the associated development and fielding schedule. Additional details are classified. FY 2027 reduces OASuW Inc 2 based on other Navy priorities. Project 3466 - The LRASM C-3 program is established to improve OASuW and incorporate a long range strike capability into the Navy's arsenal derived from the Navy's AGM-158C-1 LRASM and the Air Force's AGM-158 JASSM-ER. The Navy will integrate an AGM-158 derived weapon onto F/A-18 E/F aircraft. This funding line resources requirements for Navy increased LRASM capabilities and strike mission integration by upgrading the existing AGM-158C product to respond to rapidly changing threats. The FY 2026 request for LRASM C-3 includes $129,596 thousand of discretionary and $118,000 thousand of mandatory (reconciliation) for a total of $247,596 thousand. FY 2026 total funding supports LRASM C-3 development program. The discretionary provides for prime contractor as well as all other support, test and evaluation, and program management LRASM C-3 development efforts. The mandatory funds are provided for prime contractor LRASM C-3 development and second source fuel tank efforts only. Budget Item Justification: This program is funded under ADVANCED COMPONENT DEVELOPMENT AND PROTOTYPES because it includes all efforts necessary to evaluate integrated technologies, representative models or prototype systems in a high fidelity and realistic operating environment. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                          Date: April 2026 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 4: Advanced        PE 0604786N / Offensive Anti-Surface Warfare Weapon Dev Component Development & Prototypes (ACD&P)$$, $$Budget J-Books/FY27/Navy/RDTEN_BA4_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604791D8Z$$, $$Multi-Domain Joint Operations (MDJO)$$, $$rdte_dw_ba4$$, $$dw_osd$$, 2026, 20343000, 0, 0, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "dw", "page_num": 72, "fy27_mand_k": 2400000, "original_pe": "0604791D8Z", "page_header": "Defense-Wide", "fy27_mand_v157": "2026-05-08", "fy26_v182_disc_K": 2310, "fy26_v182_supp_K": 1000, "fy27_mand_source": "DoW_FY2027_Mandatory_Funding_Overview.txt Appendix B", "fy26_v182_total_K": 3310, "fy27_mand_section": "Next Generation Technology/Autonomy", "fy26_v182_note_name": "Multi-Domain Joint Operations (MDJO)", "fy26_v182_source_file": "RDTE_OSW_PB_2027.txt", "fy26_v182_source_line": 29346}$$::jsonb, $$MDJO facilitates identification and transition of priority joint capabilities to the Military Services and Agencies. MDJO completes this through persistent, proactive stakeholder engagement with continuous transition risk assessment, development of technology transition plans, and coordination across the Department of Defense. Ensuring transition begins in the project identification phase, MDJO guides project selection for major Assistant Secretary of Defense for Mission Capabilities [ASD(MC)] programs. MDJO drives project selection toward interim National Defense Strategy priorities by leveraging warfighter input captured through its role as the official Research and Engineering (R&E) representative to the Joint Staff’s Joint Capabilities Integration and Development System (JCIDS) process and its engagements with the COCOMs and SGFs. In the JCIDS process representative role MDJO provides technical expertise to the Joint Requirements Oversight Council (JROC) Functional Capability Boards (FCBs)within the supporting areas of Force Development and Design, Force Application, Protection, C4/Cyber, Battlespace Awareness, and Logistics and Sustainment. MDJO actively participates in Joint Staff FCBs bringing awareness of potential gap filling technologies to the JROC. MDJO’s participation in Cost Assessment and Program Evaluation (CAPE) reviews, Warfighter Senior Integration Groups (W-SIG), and other Senior Governance Forums enables these organizations to incorporate innovative technologies into their decision processes. MDJO leverages its technical expertise across interim National Defense Strategy priorities to conduct TMTRs, which serve as R&E's integrated contribution to CPM across the Department. This program provides funding necessary for MDJO to fulfill its project identification, Joint Staff coordination, Senior Governance Forum directive, technology modernization efforts, and transition support roles. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Office of the Secretary Of Defense                                           Date: June 2025 Appropriation/Budget Activity                                               R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 4:        PE 0604791D8Z / Multi-Domain Joint Operations (MDJO) Advanced Component Development & Prototypes (ACD&P)$$, NULL, 48238000, 52143000, 57734000, NULL, NULL, 119, $$RDTE_OSD_PB_2026.pdf$$, $$OSD$$, FALSE, 0, 3310000, 32001000, 32001000, 2400000000, 2432001000, 59997000, $$The Office of the Deputy Assistant Secretary of War (DASW) for Multi-Domain Joint Operations (MDJO) serves as the primary driver for identifying, developing, and transitioning high-priority joint capabilities to the warfighter. In accordance with Public Law 116-283 and DoD Directive 7045.20, MDJO collaborates across the Department of War to ensure the seamless integration of cutting-edge technologies into operational use. Key efforts executed include: •Mission Engineering and Integration Activity (MEIA): Plans and supports the execution of mission engineering, industry engagement, experimentation, and capability assessments to address priority Joint Operational Problems (JOPs). Establishes Mission Capability and Analysis Teams (MCATs) and informs the Requirements and Resourcing Alignment Board (RRAB). •JROC Representation: Serves as the official Research and Engineering (R&E) representative to the Joint Requirements Oversight Council (JROC), providing technical expertise to shape requirements, concepts of operation, and solutions for urgent operational needs. •Senior Governance Engagement: Actively participates in senior governance forums, including Cost Assessment and Program Evaluation (CAPE) reviews and Warfighter Senior Integration Groups (W-SIGs), to ensure the integration of innovative technologies into decision-making processes. •Technology Modernization Transition Reviews (TMTRs): Executes TMTRs in collaboration with the Joint Staff, Acquisition and Sustainment (A&S), and other stakeholders to accelerate technology options for JROC-designated high-priority operational problems. •Joint Lethality Engineering (JLE): Conducts critical research and analysis to address the nation's most pressing military challenges. By enhancing the lethality and survivability of our systems against advanced adversarial threats, JLE directly contributes to the Department's investment decisions and the overall effectiveness of the joint force. This program element spans all security levels and warfighting domains, ensuring a comprehensive approach to bolstering our military capabilities. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Office of the Secretary Of Defense                                                  Date: April 2026 Appropriation/Budget Activity                                                      R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 4:               PE 0604791D8Z / Multi-Domain Joint Operations (MDJO) Advanced Component Development & Prototypes (ACD&P) The FY 2027 request for MDJO includes $32,001 thousands of discretionary and $2,400,000 thousands of mandatory for a total of $2,432,001 thousand. The FY 2027 mandatory funds are for next generation technologies / autonomy, directed toward integrating mature technologies that are ready for fielding now (next 24 months). It accelerates delivery mission-ready capabilities to the warfighter aligned with the Department’s six critical technology areas to deter adversaries and enhance Joint Force operational advantage. The FY 2026 spend plan amount for Multi-Domain Joint Operations (MDJO) includes $2,310 thousands of discretionary and $1,000 thousands of mandatory (reconciliation) for a total of $3,310 thousand.$$, $$Budget J-Books/FY27/Remaining/DoW_FY2027_Mandatory_Funding_Overview.txt$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604797D8Z$$, $$Joint Energetics Transition Office (JETO)$$, $$rdte_dw_ba4$$, $$dw_osd$$, 2026, 3000000, 0, 0, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "dw", "page_num": 72, "fy27_mand_k": 500000, "original_pe": "0604797D8Z", "page_header": "Defense-Wide", "fy27_mand_v157": "2026-05-08", "fy26_v182_disc_K": 2986, "fy26_v182_supp_K": 1000, "fy27_mand_source": "DoW_FY2027_Mandatory_Funding_Overview.txt Appendix B", "fy26_v182_total_K": 3986, "fy27_mand_section": "Defense Industrial Base", "fy26_v182_note_name": "Joint Energetics Transition Office (JETO)", "fy26_v182_source_file": "RDTE_OSW_PB_2027.txt", "fy26_v182_source_line": 29664}$$::jsonb, $$The FY 2024 National Defense Authorizations Act (NDAA) directs The Under Secretary of Defense for Acquisition and Sustainment (USD(A&S)) and Under Secretary of Defense for Research and Engineering (USD(R&E)) to select the Head and Deputy Head of Joint Energetics Transition Office (JETO), respectively. JETO will establish and manage a DoD field activity dedicated to systems engineering associated with energetic materials. Additionally, JETO has been assigned strategic roles, tactical roles, coordination responsibilities, and directed studies. This new joint office is intended to improve the transition of energetic materials and technologies to programs of record. It will also result in cost savings through economies of scale and lower barriers for additional suppliers entering the market. Roles and responsibilities of include: DoD Field Office: The establishment and management of a Department of Defense field activity will be dedicated to systems engineering associated with energetic materials. The field activity mission will be to reduce technical risk; integrate research; develop, test, and evaluate energetic materials; and perform Department of Defense system demonstration programs on novel energetic materials for use in weapon systems. This field office will execute studies to inform the Energetic Materials Strategic Plan and Investment Strategy. Per NDAA language, these activities must be funded under budget activity 3 (advanced technology development) or budget activity 4 (advanced component development and prototypes). Strategic Roles: JETO will create an Energetic Materials Strategic Plan and Investment Strategy and report on changes and progress annually. Tactical Roles: JETO will identify and develop plans to alleviate any shortfalls in the supply chain for energetic materials. It will determine targets which would be better addressed with advanced energetics materials. It will also conduct studies which inform the Program Objective Memorandum (POM) process. Coordination: JETO will identify promising new energetic materials and technologies. It will mature, integrate, prototype, test, and demonstrate novel energetic materials and technologies. It will also expedite the transition of energetic materials and technologies from the research and development phase to production and operational use. Finally, it will identify or establish prototyping demonstration venues. Directed Studies: JETO will oversee processes, including recommending changes to regulations to (1) expedite the validation, verification, and accreditation of modeling and simulation, and (2) expedite the qualification process for energetic materials, from discovery through integration. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Office of the Secretary Of Defense                                                Date: June 2025 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 4:           PE 0604797D8Z / Joint Energetics Transition Office (JETO) Advanced Component Development & Prototypes (ACD&P) Additionally, the NDAA generated a requirement for three standalone reports and one annual report to be fulfilled by JETO.$$, NULL, 6778000, 7067000, 7322000, NULL, NULL, 120, $$RDTE_OSD_PB_2026.pdf$$, $$OSD$$, FALSE, 0, 3986000, 6278000, 6278000, 500000000, 506278000, 7589000, $$The FY 2027 request for Joint Energetics Transition Office (JETO) includes $6,278 thousand of discretionary and $500,000 thousand of mandatory for a total of $506,278 thousand. The FY 2027 $500,000 thousand of mandatory funds continue efforts from FY 2026 to conduct systems engineering and rapid, full-scale prototyping of weapons systems and supporting components to demonstrate the technical maturity of new energetic materials technologies. It will sponsor the expedited maturation, validation, verification, and accreditation of Modeling and Simulation tools. It will conduct modernized Test and Evaluation activities to support the systems engineering and modeling and simulation missions, ultimately encouraging the development of increased fidelity and enhanced throughput for future qualification work. The FY 2026 spend plan amount for Joint Energetics Transition Office (JETO) includes $2,986 thousand of discretionary and $1,000 thousand of mandatory (reconciliation) for a total of $3,986 thousand. The FY 2024 National Defense Authorizations Act (NDAA) directs The Under Secretary of War for Acquisition and Sustainment (USW(A&S)) and Under Secretary of War for Research and Engineering (USW(R&E)) to select the Head and Deputy Head of Joint Energetics Transition Office (JETO), respectively. JETO will establish and manage a DoW field activity dedicated to systems engineering associated with energetic materials. Additionally, JETO has been assigned strategic roles, tactical roles, coordination responsibilities, and directed studies. This new joint office is intended to improve the transition of energetic materials and technologies to programs of record. It will also result in cost savings through economies of scale and lower barriers for additional suppliers entering the market. Roles and responsibilities of include: DoW Field Office: The establishment and management of a Department of War field activity will be dedicated to systems engineering associated with energetic materials. The field activity mission will be to reduce technical risk; integrate research; develop, test, and evaluate energetic materials; and perform Department of War system demonstration programs on novel energetic materials for use in weapon systems. This field office will execute studies to inform the Energetic Materials Strategic Plan and Investment Strategy. Per NDAA language, these activities must be funded under budget activity 3 (advanced technology development) or budget activity 4 (advanced component development and prototypes). Strategic Roles: JETO will create an Energetic Materials Strategic Plan and Investment Strategy and report on changes and progress annually. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Office of the Secretary Of Defense                                                     Date: April 2026 Appropriation/Budget Activity                                                       R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 4:                PE 0604797D8Z / Joint Energetics Transition Office (JETO) Advanced Component Development & Prototypes (ACD&P) Tactical Roles: JETO will identify and develop plans to alleviate any shortfalls in the supply chain for energetic materials. It will determine targets which would be better addressed with advanced energetics materials. Coordination: JETO will identify promising new energetic materials and technologies. It will mature, integrate, prototype, test, and demonstrate novel energetic materials and technologies. It will also expedite the transition of energetic materials and technologies from the research and development phase to production and operational use. Finally, it will identify or establish prototyping demonstration venues. Directed Studies: JETO will oversee processes, including recommending changes to regulations to (1) expedite the validation, verification, and accreditation of modeling and simulation, and (2) expedite the qualification process for energetic materials, from discovery through integration. Additionally, the NDAA generated a requirement for three standalone reports and one annual report to be fulfilled by JETO.$$, $$Budget J-Books/FY27/Remaining/DoW_FY2027_Mandatory_Funding_Overview.txt$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604798A$$, $$Brigade Analysis, Integration and Evaluation$$, $$rdte_army_ba5$$, $$asa_alt$$, 2026, 24318000, 21750000, 26352000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "army", "page_num": 16, "original_pe": "0604798A", "page_header": "Department of the Army"}$$::jsonb, $$This program element is comprised of four initiatives: Technology Accelerators, Acquisition Reform, Commercial Innovation, and Digital Engineering Initiatives. These efforts directly support the SECDEF Memorandum, "Directing Modern Software Acquisition to Maximize Lethality", DoD Software Modernization Implementation Plan, and the Army's strategic priorities for emerging technology insertion. These initiatives are foundational to achieving the Army's digital transformation goals and ensuring operational superiority in an increasingly complex and contested environment. Project DY7: Provides the Army's leadership and materiel developers with essential tools and methodologies to modernize software acquisition and engineering processes. This project delivers comprehensive capabilities including,, System of Systems (SoS) engineering and analysis, technical risk analysis, architectural frameworks, critical path analysis, cybersecurity and interoperability risk analysis; all designed to optimize the Army's materiel portfolio and accelerate modernization. Aligned with the DoD and Army digital transformation and modernization goals, this project emphasizes the implementation of Continuous Integration/ Continuous Delivery (CI/CD) pipelines to streamline and modernize the software acquisition process. By leveraging CI/CD, the Army can rapidly field minimal viable products (MVPs) that address mission-critical needs while maintaining flexibility to adapt to evolving threats. This approach integrates continuous Soldier feedback into a unified engineering construct, ensuring that capabilities are both operationally relevant and responsive to the dynamic needs of the force. Key focus areas include: * Implementing open architecture frameworks. Establishing cohesive data, software, hardware open architecture frameworks to enable decision dominance and enhance interoperability, interchangeability, and integrateability across the Army's digital and physical ecosystem. * Adaptable Systems and Digital Engineering: Developing flexible engineering processes that integrate SoS risk analysis, architectural products, and mitigation planning to deliver MVPs for rapid fielding. * Modern Software Practices: Removing institutional barriers to CI/CD adoption and delivering secure, resilient software solutions designed to meet the Army's mission requirements. * Portfolio Optimization: Conducting engineering analysis, portfolio assessments, and systems security evaluations to ensure alignment with the Army's modernization priorities. Additionally, this project supports the Army Futures Command by streamlining processes through broad Capability Needs Statements (CNS). This enables agile development of concepts, requirements generation, resource allocation, experimentation, acquisition, logistics, and technology integration. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                             Date: June 2025 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 5: System             PE 0604798A / Brigade Analysis, Integration and Evaluation Development & Demonstration (SDD) Key deliverables include the development of integrated architecture products to drive modernization, engineering analysis and design to enhance system performance and interoperability, and independent technical risk assessments to address vulnerabilities. Additionally, the project ensures cybersecurity compliance and policy alignment for secure operations while coordinating ASA(ALT) data stewardship and governance activities to enable data-driven decision-making across the Army's modernization efforts. The FY 2026 request was reduced by $1.338 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative."$$, NULL, 26819000, 27151000, 27420000, NULL, NULL, 118, $$RDTE - Vol 3 - Budget Activity 5B.pdf$$, NULL, FALSE, 26584000, 24318000, 26602000, 26602000, NULL, 26602000, 27728000, $$This PE encompasses three key initiatives: Army's Systems-of-Systems Architecture, Digital Engineering, and Modernization Protection. These initiatives synergize legislated requirements (e.g. information security, modular open-system design) that are strategically aligned with the Army Transformation Initiative by prioritizing data- centric and software-driven capabilities as the foundation for modernizing formations. The program focuses on providing Army implementation guidance on designing open, modular, secure, and interoperable architectures that enhance agility, adaptability, and speed in acquisition processes. Project DY7: Provides the Army's leadership and materiel developers with essential tools and methodologies to modernize software acquisition and engineering processes. This project delivers comprehensive capabilities including, System of Systems (SoS) engineering and analysis, technical risk analysis, architectural frameworks, critical path analysis, cybersecurity and interoperability risk analysis; all designed to optimize the Army's materiel portfolio and accelerate modernization. Aligned with the DoW and Army digital transformation and modernization goals, this project emphasizes the implementation of Continuous Integration/ Continuous Delivery (CI/CD) pipelines to streamline and modernize the software acquisition process. By leveraging CI/CD, the Army can rapidly field minimal viable products (MVPs) that address mission-critical needs while maintaining flexibility to adapt to evolving threats. This approach integrates continuous Soldier feedback into a unified engineering construct, ensuring that capabilities are both operationally relevant and responsive to the dynamic needs of the force. Key focus areas include: * Implementing open architecture frameworks. Establishing cohesive data, software, hardware open architecture frameworks to enable decision dominance and enhance interoperability, interchangeability, and integrate ability across the Army's digital and physical ecosystem. * Adaptable Systems and Digital Engineering: Developing flexible engineering processes that integrate SoS risk analysis, architectural products, and mitigation planning to deliver MVPs for rapid fielding. * Modern Software Practices: Removing institutional barriers to CI/CD adoption and delivering secure, resilient software solutions designed to meet the Army's mission requirements. * Portfolio Optimization: Conducting engineering analysis, portfolio assessments, and systems security evaluations to ensure alignment with the Army's modernization priorities. * Automating Testing: Continue modernizing Army Interoperability Certification cloud based automated testing to provide Portfolio Acquisition Executives capability to ensure interoperability of their portfolio system of system architectures in their DEVSECOPS pipelines. Additionally, this project supports the Army Transformation and Training Command (T2COM) by streamlining processes through broad Capability Needs Statements (CNS). This enables agile development of concepts, requirements generation, resource allocation, experimentation, acquisition, logistics, and technology integration. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                               Date: April 2026 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 5: System             PE 0604798A / Brigade Analysis, Integration and Evaluation Development & Demonstration (SDD) Key deliverables include the development of integrated architecture products to drive modernization, engineering analysis and design to enhance system performance and interoperability, and independent technical risk assessments to address vulnerabilities and a modernized Digital Interoperability Certification Ecosystem that supports interoperability certification of modern Application Program Interfaces using Agentic AI and other techniques. Additionally, the project ensures cybersecurity compliance and policy alignment for secure operations while coordinating data stewardship and governance activities to enable data-driven decision-making across the Army's modernization efforts.$$, $$Budget J-Books/FY27/Army/RDTE - Vol 3 - Budget Activity 5A.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604802A$$, $$Weapons and Munitions - Eng Dev$$, $$rdte_army_ba5$$, $$cft_ngcv$$, 2026, 150344000, 270231000, 251949000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "army", "page_num": 16, "original_pe": "0604802A", "page_header": "Department of the Army"}$$::jsonb, $$Multiple Projects within Program Element Weapons and Munitions - Eng Dev, are key enablers of the Army's Cannon Transformation Priorities: 155mm Artillery Propulsion Modernization (Project DK8), 155mm High Explosive Rocket Assisted Projectile Extended Range (Project EU6) and Precision Guidance Kit (Project S36). Project BQ3, 155MM Artillery Propulsion Supercharge funding will support the Army's Cannon Transformation Strategy, which includes Paladin Integrated Management (PIM) Armament Upgrade and Next Generation Cannon, and all utilized cannons that are 52-calibers or longer; such as the future 58-caliber Extended Range Cannon Artillery (ERCA). Supercharge is a stand-alone top-zone 155 millimeter (mm) propelling charge required to achieve maximum range requirements beyond 50 kilometers (km) from Self-Propelled Howitzer (SPH) equipped with cannon length greater than 52-calibers. Supercharge will achieve lethality overmatch out to 70km from future US-developed and produced Long Range Precision Fires Weapon Systems using both existing and developmental extended range projectiles and will potentially increase range with compatible legacy projectiles up to thirty percent. Supercharge is composed of an earlier bag variant and later combustible cartridge case, integral metal stub case, electrically initiated primer, and advanced artillery propellant. This Project supports the Urgent Materiel Release (UMR) Supercharge (bag configuration) qualification required for fielding an initial capability of two battalions, and also supports the development of the Full Materiel Release (FMR) Supercharge that will address high technology and integration risks unique to achieving extended range to include improved design opportunities for pressure temperature curve, cannon tube wear and ensure fielding robustness. This Project does not have an FY 2026 budget request. Project BY1, Next Generation Combat Vehicle Ammunition: 50x228 millimeter (mm) family of ammunition is a critical technology development in response to the Next Generation Combat Vehicle (NGCV) Abbreviated Capability Development Document for weapon qualification, platform integration, and fielding of the XM30 Mechanized Infantry Combat Vehicle (MICV) primary weapon system (XM913). This effort includes the development of three capabilities: The XM1202 Target Practice with Tracer (TP-T); the XM1203 Armor Piercing Fin Stabilized Discarding Sabot with Tracer (APFSDS-T); and the XM1204 High Explosive Airburst with Trace (HEAB-T). The training cartridge will allow the Warfighter to train in a cost-effective manner and the tactical cartridges will provide enhanced lethality at increased ranges when engaging personnel threats in the open, defilade, and under the cover of urban structures, Anti-Tank Guided Missiles (ATGM) teams, and current and projected future peer armored materiel threats. This effort is operating under Middle Tier Acquisition authority for rapid prototyping to qualify the three munitions in order to support the NGCV Cross Functional Team (CFT) timeline for First Unit Equipped (FUE). Fiscal Year (FY) 2026 funding supports Developmental Test and Evaluation (DT&E) and Milestone C documentation. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                               Date: June 2025 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 5: System            PE 0604802A / Weapons and Munitions - Eng Dev Development & Demonstration (SDD) Project CE3, Precision Munition (Sniper): The Precision Munition (Sniper) project is a critical technology development in response to the Precision Munition Capabilities Development Documents (CDD) for the ammunition required to support the Precision Sniper Rifle (PSR) / sniper weapons systems. The objective is to transfer the latest lethality technology into the suite of ammunition used by snipers. The Precision Munition improvement is split into three capability areas: Anti-Materiel (AM), Improved Performance Round (IPR), and Subsonic. The AM and IPR capabilities will enhance lethal effects at greater distances. The Subsonic capability will increase soldier survivability at close range by providing a low-sound signature munition that is undetectable to the enemy. FY 2026 will continue Engineering and Manufacturing Development activities to include a user assessment, Production Qualification Test build and the commencement of Production Qualification Testing (PQT). In FY 2024, Project CE3 / Precision Munition (Sniper) was a Skip-Year. Project DC9, 30mm Multi-Mode Proximity Airburst (MMPA) Maneuver Short Range Air Defense Increment 3 (M-SHORAD INC 3): The 30mm MMPA M-SHORAD INC 3 / Project DC9 funds the development of the 30mm XM1223 MMPA munition and respective weapon contact setter under the Middle Tier of Acquisition (MTA) authority for rapid prototyping. The objective is to enhance the operational effectiveness of the M-SHORAD Inc 3 platform, Mobile-Low, Slow, Small Unmanned Aircraft Integrated Defeat System (M-LIDS) and any other Joint Force platforms that are equipped with a 30mm weapon system and have a Counter Unmanned Aerial Systems (C-UAS) mission. The programmable fuze modes in the munition include proximity airburst to defeat personnel in the open and small Unmanned Aerial System (UAS) targets, proximity airburst delay to defeat personnel in defilade, gated proximity airburst to minimize collateral damage in cluttered environments, mechanical point detonate to defeat light materiel targets, and self-destruct to minimize collateral damage. The XM1223 will allow the platforms to conduct counter-UAS missions while retaining the ability to quickly transition to ground targets without having to swap ammunition. FY 2026 funds support conducting a Critical Design Review (CDR) and initiating the ammunition build for Developmental Test and Evaluation (DT&E). Project DK8, 155mm Artillery Propulsion Modernization (System Demonstration) supports the US Army's Cannon Transformation Strategy and system demonstration as well as modernization of propulsion systems for multiple platforms. The propulsion systems under development and modernization include propelling charge, modular charge, propellant, ignition system, and packaging solutions. The propulsion solutions will be integrated into a system of systems capability to ensure interoperability closing fires capability gaps to destroy or neutralize artillery target out to 70 kilometers. The propulsion system program(s) combined with cannon/projectile/fuze enhancements will enable the next generation of propelling charge and ignition systems to extend firing range, improve rate-of-fire and resupply, improve ammunition suitability, enhance lethality of current and future conventional munitions, and enable artillery units to be safe, effective, suitable, and survivable. Novel propulsion technologies will be developed, matured, integrated, and tested into the components of the propelling charges and ignition systems to advance and innovate artillery firing performance and enhance manufacturability of the industrial base. Fiscal Year (FY) 2026 funding will support system demonstration to integrate, verify maturity and iterate enhancement of propelling charge and ignition systems for improvement of the propellant effectiveness, cannon life, primer and charge ignition performance, system-level handling and rates-of-fire, and overall propulsion suitability and survivability. Project EC4, Non-Standard Simulator Munitions will standardize various pyrotechnics that simulate battlefield effects, develop, demonstrate, and qualify various screening effects in grenades, vehicle launched effects, smoke pots, and signals. The Army's Combat Training Centers (CTCs) are currently using non-standard munitions to replicate both conventional and asymmetric warfare battlefield effects. These modified commercial-off-the-shelf products have not been type-classified or material released and are not safe or sustainable for use by Soldiers. This effort will develop and demonstrate various pyrotechnic simulators and replicate both conventional, asymmetric warfare battlefield effects and munitions such as: Black smoke signature (burning vehicles, buildings, and equipment); Yellow smoke signature Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                                        Date: June 2025 Appropriation/Budget Activity                                                          R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 5: System                    PE 0604802A / Weapons and Munitions - Eng Dev Development & Demonstration (SDD) (chemical, biological or nuclear effects); Mini Blast to simulate hostile fire and small Improvised Explosive Devices (IEDs) during mounted operations in urban terrain; Micro pyrotechnics to simulate indoor hostile fire and IED effects that are capable of being integrated into existing facilities; Rocket Propelled Grenade (RPG) simulators to replicate the flight of a Rocket Propelled Grenade; Macro Pyro to simulate hostile fire, booby trap and IED Simulations indoor and outdoors; High Order Blast Effect (HiOBE) used to replicate a Vehicle Borne Improvised Explosive Device (VBIED), building explosions, and other significant explosive events; Artillery airburst simulator to replicate indirect fire; Antitank Guided Missile and Rocket (AGMR) simulator to replicate surface to air missile or shoulder launched rocket; Tracer Fire-back simulator to replicate enemy small arms fire and anti-aircraft fire; Electrically initiated smoke pots and smoke grenades of various colors; Multi-spectral and screening effects of grenades, vehicle launched effects, smoke pots, and signals. Standardization will reduce training costs, eliminate redundancies between systems, mitigate environmental concerns and safety risks associated with realistic scenario-based training and improve screening effects. Project EL9, Ammunition Logistics Prototyping: This Project supports the future force by maturing and integrating prototypes and commercial off the shelf technologies fully endorsed by the warfighter and associated Combat developers following a system of systems approach. The selected capabilities for continued investment have been proven through warfighter exercises and Soldier touch points to materially improve elements of tactical Ammo transportation, distribution, inventory management, availability and survivability as logistics system enablers within the formation. These enablers will improve the efficiency and effectiveness of ammunition operations, to include retrograde, while reducing the logistics footprint on the battlefield. This project enhances the operational effectiveness of the ammunition logistics system to ensure the distribution of reliable ammunition to the warfighter. Funding will be focused on integrating mature technologies into ammunition resupply enablers and developing interfaces with applicable Program of Records as recommended by the Contested Logistics, Long Range Precision Fires, Next-Generation Combat Vehicles, Soldier Lethality Cross Functional Teams. Project EP2, Shoulder-Launched Munitions: The XM919 Individual Assault Munitions (IAM) effort will combine the capabilities of the existing M141 Bunker Defeat Munition (BDM) and the M136 Anti-Tank 4 Confined Space - Reduced Sensitivity (AT4CS RS), eliminating the mission risk associated with having to choose between two different capability Shoulder-Launched Munitions (SLMs), reducing the logistics and training burdens associated with multiple systems. IAM consists of the tactical XM919 IAM munition and training devices including the XM922 sub-caliber trainer (SCT), sub-caliber tracer ammunition (SCT Ammo), Field H… [truncated]$$, NULL, 88149000, 153054000, 142003000, NULL, NULL, 119, $$RDTE - Vol 3 - Budget Activity 5B.pdf$$, NULL, FALSE, 232181000, 156844000, 124881000, 124881000, NULL, 124881000, 209649000, $$Multiple projects within Program Element Weapons and Munitions - Eng Dev, are key enablers of the Army's Field Artillery modernization priorities: 155mm Artillery Propulsion Modernization (Project DK8), 155mm High Explosive Rocket Assisted Projectile Extended Range (Project EU6) and Precision Guidance Kit (Project S36). Project BY1, Next Generation Combat Vehicle Ammunition: 50x228 millimeter (mm) family of ammunition is a critical technology development in response to the Next Generation Combat Vehicle (NGCV) Abbreviated Capability Development Document for weapon qualification, platform integration, and fielding of the XM30 Mechanized Infantry Combat Vehicle (MICV) primary weapon system (XM913). This effort includes the development of three capabilities: The XM1202 Target Practice with Tracer (TP-T); the XM1203 Armor Piercing Fin Stabilized Discarding Sabot with Tracer (APFSDS-T); and the XM1204 High Explosive Airburst with Trace (HEAB-T). The training cartridge will allow the Warfighter to train in a cost-effective manner and the tactical cartridges will provide enhanced lethality at increased ranges when engaging personnel threats in the open, defilade, and under the cover of urban structures, Anti-Tank Guided Missiles (ATGM) teams, and current and projected future peer armored materiel threats. This effort is operating under Middle Tier Acquisition authority for rapid prototyping to qualify the three munitions in order to support the NGCV Cross Functional Team (CFT) timeline for First Unit Equipped (FUE). Fiscal Year (FY) 2027 funding supports Developmental Test and Evaluation (DT&E), Milestone C documentation, design optimization, and preparation activities for prototype fielding. Project CE3, Precision Munition (Sniper): The Precision Munition (Sniper) project is a critical technology development in response to the Precision Munition Capabilities Development Documents (CDD) for the ammunition required to support the Precision Sniper Rifle (PSR) / sniper weapons systems. The objective is to transfer the latest lethality technology into the suite of ammunition used by snipers. The Precision Munition improvement is split into three capability areas: Anti-Materiel (AM), Improved Performance Round (IPR), and Subsonic. The AM and IPR capabilities will enhance lethal effects at greater distances. The Subsonic capability will increase soldier survivability at close range by providing a low-sound signature munition that is undetectable to the enemy. Fiscal Year (FY) 2027 will conclude both Engineering and Manufacturing Development (EMD) activities and the Production Qualification Test (PQT) with the culmination of Milestone C. Project DC9, 30mm Multi-Mode Proximity Airburst (MMPA) Maneuver Short Range Air Defense Increment 3 (M-SHORAD INC 3): The 30mm MMPA M-SHORAD INC 3 / Project DC9 funds the development of the 30mm XM1223 MMPA munition and respective weapon contact setter under the Middle Tier of Acquisition (MTA) authority for rapid prototyping. The objective is to enhance the operational effectiveness of the M-SHORAD Inc 3 platform, Mobile-Low, Slow, Small Unmanned Aircraft Integrated Defeat System (M-LIDS) and any other Joint Force platforms that are equipped with a 30mm weapon system and have a Counter Unmanned Aerial Systems (C-UAS) Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                                    Date: April 2026 Appropriation/Budget Activity                                                      R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 5: System                PE 0604802A / Weapons and Munitions - Eng Dev Development & Demonstration (SDD) mission. The programmable fuze modes in the munition include proximity airburst to defeat personnel in the open and small Unmanned Aerial System (UAS) targets, proximity airburst delay to defeat personnel in defilade, gated proximity airburst to minimize collateral damage in cluttered environments, mechanical point detonate to defeat light materiel targets, and self-destruct to minimize collateral damage. The XM1223 will allow the platforms to conduct counter-UAS missions while retaining the ability to quickly transition to ground targets without having to swap ammunition. Fiscal Year (FY) 2027 funds support conducting Developmental Test & Evaluation (DT&E), Operational Assessment, and Milestone C preparation. The total cost of the MMPA Middle Tier of Acquisition (MTA) effort is $54.4 million RDT&E from FY24 to FY28. The remainder of the MMPA MTA is fully funded across the Future Years Defense Program. Project DK8, The 155mm Artillery Propulsion Modernization (System Demonstration) project develops and qualifies advanced propulsion systems, to include propelling charge, modular charge, ignition systems, propellant, and packaging solutions in support of the Army's Field artillery modernization objectives. Novel propulsion technologies will be matured and tested into the propelling charges and ignition systems to advance and innovate artillery firing performance and enhance manufacturability of the industrial base. Solutions will be integrated into a system of systems capability to ensure interoperability, closing fires capability gaps to destroy or neutralize artillery targets out to 70 kilometers. Fiscal Year (FY) 2027 funding will support system demonstration and integration with down selected Mobile Tactical Cannon (MTC), verify performance of propelling charge and ignition systems, and evaluate integration with handling and stowage systems. Project EC4, Non-Standard Simulator Munitions will standardize various pyrotechnics that simulate battlefield effects, develop, demonstrate, and qualify various screening effects in grenades, vehicle launched effects, unmanned aerial vehicles, smoke pots, signals, counter sensors, and countermeasures. The Army's Combat Training Centers (CTCs) are currently using non-standard munitions to replicate both conventional and asymmetric warfare battlefield effects. These modified commercial-off-the-shelf products have not been type-classified or material released and are not safe or sustainable for use by Soldiers. This effort will develop and demonstrate various pyrotechnic simulators, replicating both conventional and asymmetric warfare effects and munitions such as: Black smoke signature (burning vehicles, buildings, and equipment); Yellow smoke signature (chemical, biological or nuclear effects); Mini Blast to simulate hostile fire and small Improvised Explosive Devices (IEDs) during mounted operations in urban terrain; Micro pyrotechnics to simulate indoor hostile fire and IED effects that are capable of being integrated into existing facilities; Rocket Propelled Grenade (RPG) simulators to replicate the flight of a Rocket Propelled Grenade; Macro Pyro to simulate hostile fire, booby trap, and IED simulations both indoor and outdoors; High Order Blast Effect (HiOBE) used to replicate a Vehicle Borne Improvised Explosive Device (VBIED), building explosions, and other significant explosive events; Artillery airburst simulator to replicate indirect fire; Antitank Guided Missile and Rocket (AGMR) simulator to replicate surface to air missile or shoulder launched rocket; Tracer Fire-back simulator to replicate enemy small arms fire and anti-aircraft fire; Electrically initiated smoke pots and smoke grenades of various colors; Multi-spectral and screening effects of grenades, vehicle launched effects, smoke pots, chaff, signals for unmanned systems, unmanned aerial vehicles, and ground vehicles; Counter sensor effects; Pyrotechnic and other effects for increased lethality against robotic targets. Standardization will reduce training costs, eliminate redundancies between systems, mitigate environmental concerns and safety risks associated with realistic scenario based training and improve screening effects. Project EL9, Ammunition Logistics Prototyping: This Project supports the future force by maturing and integrating prototypes and commercial off the shelf technologies fully endorsed by the warfighter and associated Combat developers following a system of systems approach. The selected capabilities for continued investment have been proven through warfighter exercises and Soldier touch points to materially improve elements of tactical Ammo transportation, distribution, inventory management, availability and survivability as logistics system enablers within the formation. These enablers will improve the efficiency and effectiveness of ammunition operations, to include retrograde, while reducing the logistics footprint on the battlefield. This project enhances the operational effectiveness of the ammunition logistics system Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                              Date: April 2026 Appropriation/Budget Activity                                                       R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 5: System                 PE 0604802A / Weapons and Munitions - Eng Dev Development & Demonstration (SDD) to ensure the distribution of reliable ammunition to the warfighter. Funding will be focused on integrating mature technologies into ammunition resupply enablers and developing interfaces with applicable Program of Records as recommended by the Contested Logistics, Long Range Precision Fires, Next-Generation Combat Vehicles, Soldier Lethality Cross Functional Teams. Project EP7, Aviation Airborne Expendable Countermeasures (AAECM) will support Integrated System Design (ISD), System Capability (SC) and Manufacturing Process Demonstrations (MPD) on expendable countermeasure flares and decoys to include the XM215 Infrared (IR) countermeasure Flare, XM20 and M1A1/M1E2 Radio Frequency (RF) expendables. These expendable countermeasures systems are an essential part of survivability equipment for Army aircraft. Army Research Development Technology & Evaluation (RDT&E) efforts are coordinated with Program Executive Office (PEO) Aviation to address the AAECM capability, a critical enabler for enduring aircraft and the Future Vertical Lift (FVL) - Aircraft Survivability Equipment (ASE) Cross Functional Team (CFT) within Army's Top modernization priorities. Project EU4, 40 millimeter (mm) High Velocity (HV) High Explosive Dual Purpose - Air burst (HEDP-AB): 40 millimeter (mm) High Velocity (HV) High Explosive Dual Purpose - Air burst (HEDP-AB) is a new capability identified as a Warfighter counter-defilade requirement in the 40mm High Velocity Improved High Explosive Dual Purpose Cartridge Capability Development Document (CDD) and will provide the Mk19 Mod 3 Grenade Machine Gun (GMG) an airburst capable cartridge with the ability of achieving required lethal effects against enemy targets in the open and in defilade while maintaining the capability to defeat unarmored and lightly armored vehicles. XM1176 HEDP-AB cartridges are manufactured by de-fuzing legacy M430A1 cartridges and installing a new airburst capable fuze onto the M430A1 warhead. In FY 2024, Project EU4 / 40mm HV Improved High Explosive Dual Purpose program funding had strategic pause to ensure schedule and funding requirements are in alignment. In FY 2027 there is no funding request. Project EU6, The 155 millimeter (mm) High Explosive (HE) Rocket Assisted Projectile Extended Range supports the modernization priorities identified in the Army's Field Artillery modernization objectives. This venture develops an innovative rocket design with a lethal warhead that is compatible with unguided and guided fuzes to meet extended range and accuracy requirements. The Next Generation Rocket Assisted Projectile (NGRAP) development effort will first deliver a solution to increase ranges from 30km to 40km in current 39 caliber systems and will also improve accuracy, lethality, and ranges utilizing 39 caliber and Extended Range Cannons. Fiscal Year (FY) 2027 funding will support critical verification testing and qualification activities required to achieve Critical Design Review (CDR). Project EW1, 40 millimeter (mm) Low Velocity High Explosive Air Burst (LV-HEAB): The 40 millimeter (mm) Low Velocity High Explosive Air Burst (HEAB) is a new capability identified as a Warfighter counter-defilade requirement in the Capability Development Document (CDD), 40mm Low Velocity (LV) Family of Ammunition Annex. The HEAB tactical cartridge allows the Warfighter to engage targets at increased effective ranges using the 40mm M320 Grenade Launcher. The HEAB cartridge provides the grenadier with a higher probability of achieving a first shot kill against enemy personnel, coupled with the ability to defeat personnel targets in defilade positions. When deployed against point and area targets, the cartridge inflicts incapacitating effects against personnel beyond those offered by the current M433 High Explosive Dual Purpose (HEDP) cartridge. The cartridge provides lethal effects against targets with improved accuracy and greater standoff ranges resulting in increased soldier survivability. In FY 2027 there is no funding request. Project FA6, 30mm Lethality: The 30 millimeter (mm) Lethality project funds the development of the family of 30mm cartridges, to provide anti-personnel effects, counter defilade, anti-materiel and counter unmanned aerial systems (C-UAS). This ammunition will increase the effectiveness and lethality for all platforms equipped with a Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                                Date: April 2026 Appropriation/Budget Activity                                                        R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 5: System                  PE 0604802A / Weapons and Munitions - Eng Dev Development & Demonstration (SDD) medium caliber 30mm weapon system to include the Stryker Infantry Carrier Vehicle (ICV) and proposed Next Generation Combat Vehicle (NGCV) variants. The tactical Armor Piercing cartridge will provide an organic direct fire capability to support infantry at a greater range and will improve lethality when engaging light-to-medium armored vehicles. The airburst cartridge will provide the Warfighter with increased lethality against troops in the open, counter defilade, Anti-Tank Guided Missile (ATGM) teams, troops behind urban structures and counter unmanned aerial systems . The training cartridges will be ballistically matched to the tactical cartridges, allowing the Warfighter to train in a cost-effective manner, and on CONUS and OCONUS training ranges. In Fiscal Year (FY) 2027, this project FA6 / 30mm Lethality will transition to production. Project FJ4, Cannon-Delivered Area Effects Munitions (C-DAEM): The C-DAEM project will provide United States (U.S.) ground forces with the capability to engage area personnel through armored targets, while denying threat forces full operational freedom within the targeted area. An Analysis of Alternatives (AoA) was completed in January 2018 to inform Army acquisition and investment decisions regarding replacement of the current stockpile of 155 millimeter (mm) Dual Purpose Improved Conventional Munitions (DPICM) with Department of War (DoW) policy compliant munitions and address anti-armor and extended range capability requirements. The Army validated two materiel solutions for C-DAEM to be pursued in parallel to support the Army's modernization priorities: C-DAEM Armor and C-DAEM DPICM Replacement. C-DAEM Armor will destroy moved and moving self-propelled howitzers, infantry fighting vehicles and tanks. C-DAEM DPICM Replacement will destroy personnel through soft-skinned targets. This project does not have a Fiscal Year (FY) 2027 budget request. Project FL4, Small Caliber Ammo for Next Gen Squad Weapons: The Small Caliber Ammo for Next Gen Squad Weapons project is a critical technology development in response to the Soldier Lethality Cross Functional Team (SL CFT) Initial Capability Document (ICD) for the ammunition required to support the rapid prototyping, development, and fielding of the Next Generation Squad Weapons (NGSW) under the Middle Tier of Acquisition (MTA) authority for rapid prototyping/rapid fielding. The objective is to develop and Full Materiel Release (FMR) the new 6.8mm ammunition in parallel with the NGSW rifle and automatic rifle. The 6.8mm ammunition is split into multiple ammunition variants, the General Purpose (GP), the Special Purpose (SP), the Reduced Range Ammunition (RRA), Tracer Ammunition, Blank Ammunition, the Close Combat Mission Capability Kit (CCMCK) training ammunition, Drill Dummy Inert (DDI) cartridge, and High-Pressure Test (HPT) cartridge. FY 2027 funding will support CCMCK developmental tests, SP Complex Target Terminal Characterization (CTTC), SP Live Fire Test and Evaluation (LFT&E), SP Full Material Release (FMR), SP Persistent Design Optimization and develop prototypes for Limited Lethality Assessment. FY 2027 funding for SP will also support initiation of detailed design activities for a facility that enables prototyping of new concepts for the Persistent Design Optimization effort. Fiscal Year (FY) 2027 funding will support activities for transition from Middle Tier of Acquisition (MTA) to Major Capability Acquisition (MCA). Project MS1, Battalion Mortar System Modernization: The Battalion Mortar System Modernization project supports the development of modernized Mortar Weapon Systems to support Mobile Brigade Combat Teams (MBCTs), Infantry Brigade Combat Teams (IBCTs), Stryker Brigade Combat Teams (SBCTs), and Armored Brigade Combat Teams (ABCTs). Efforts include development and qualification of modernized mortar systems and their required components to include fire control and ammunition that will increase range, lethality, survivability, mobility and readiness. The weapon and fire control will be used as a standalone man-portable system with digital fire control capability or as a modular system that can be hosted onto light tactical vehicles such as the High Mobility Multipurpose Wheeled Vehicle (HMMWV), the Infantry Squad Vehicle (ISV) and/or Joint Lightweight Tactical Vehicle (JLTV) when a mobility kit is utilized. This modernized system will increase survivability, maneuverability, and provide tactical advantage to the Warfighter when matched with pacing threat for direct and indirect fire and will provide overmatching capabilities. Initial characterization efforts will establish a firm foundation for proposed advanced indirect fire systems while allowing for incremental improvements and updates as technologies continue to mature, which will maintain and enhance performance, improve lethality, responsiveness, and reliability of indirect fire systems across the Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                                    Date: April 2026 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 5: System              PE 0604802A / Weapons and Munitions - Eng Dev Development & Demonstration (SDD) required spectrum of military operations. Fiscal Year (FY) 2027 funding will support the design and development of a next generation 81mm mortar weapon, fire control system, and mobility kit that can be hosted on a light tactical vehicle. Project S36, The Precision Guidance Kit (PGK): The Precision Guidance Kit (PGK) project supports development efforts that will qualify state of the art technologies for a course correcting fuze that provides precision accuracy at extended ranges for current and future 155-millimeter (mm) High Explosive (HE) projectiles by eliminating a portion of the inherent errors associated with ballistic firing solutions, which effectively reduces the number of projectiles required to execute fire missions. The precision course correcting fuze will support projectile operation in Global Positioning System (GPS) degraded environments in support of the Army's Field Artillery modernization objectives. All 39-caliber weapon systems and modernized Self-Propelled and Towed Howitzer weapon systems with cannon lengths greater than or equal to 52-caliber and new long-range projectiles require the precision course correcting fuze to meet lethality requirements. This project does not have a Fiscal Year (FY) 2027 budget request. Project XT6, Medium Caliber Anti-Personnel and Counter UAS: The Anti-Personnel and Counter Unmanned Aerial Systems (UAS) munitions provide increased lethality through proximity airburst effects against personnel, small Unmanned Aerial Systems (UAS), and small boats without requiring modification to the platform. Airburst capability is identified as a threshold Key System Attribute (KSA) in Apache Block 3 Capability Production Document (CPD) - Approved 14 June 2017, and counter- UAS capability is identified in other cannon caliber Operational Need Statements (ONSs) and Capability Development Documents (CDDs). Fiscal Year (FY) 2027 funds support completing the prototype build for Developmental Test and Evaluation (DT&E) and conducting DT&E test for 30x113mm Aviation Proximity Explosive (APEX) munition in support of Full Materiel Release and completing the prototype build and conducting Developmental Test and Evaluation (DT&E) for 25mm Bradley Aerial Defeat Ground Enhanced Round (BADGER) munition in support of Urgent Materiel Release, and achievement of Milestone B (MS-B). Fiscal Year (FY) 2027 funding will support prototype build for Developmental Test and Evaluation (DT&E) and DT&E testing.$$, $$Budget J-Books/FY27/Army/RDTE - Vol 3 - Budget Activity 5B.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604807A$$, $$Medical Materiel/Medical Biological Defense Equipment - Eng Dev$$, $$rdte_army_ba5$$, $$asa_alt$$, 2026, 6252000, 10984000, 7143000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "army", "page_num": 17, "original_pe": "0604807A", "page_header": "Department of the Army"}$$::jsonb, $$This Program Element (PE) funds advanced development of medical materiel within the System Demonstration and Low Rate Initial Production portions of the acquisition life cycle using Budget Activity 6.5 (System Development and Demonstration) funding. It supports products successfully developed in the Systems Integration portion of the Systems Development and Demonstration phases through completion of the Milestone C Decision Review. Commercially-off-the-shelf (COTS) medical products are also tested and evaluated for military use, when available. This PE primarily includes pivotal (conclusive) human clinical trials necessary for licensure by the Food and Drug Administration (FDA). Projects in this PE include the following: Project 832 funds the engineering and manufacturing development of medical products for enhanced combat casualty care and follow-on care, including rehabilitation. Mature COTS medical products are also evaluated for military use. Consideration will also be given to reduce the medical sustainment footprint through smaller weight and cube volume, or equipment independence from supporting materiel. Products from this project will normally transition to OPA Funds. The FY 2026 request was reduced by $0.344 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative." The FY 2026 request was reduced by $0.049 million for civilian personnel to optimize the workforce in compliance with Executive Order 14210, "Implementing the President's Department of Government Efficiency Workforce Optimization Initiative." Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                         Date: June 2025 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 5: System        PE 0604807A / Medical Materiel/Medical Biological Defense Equipment - Eng Dev Development & Demonstration (SDD)$$, NULL, 13047000, 11367000, 8801000, NULL, NULL, 122, $$RDTE - Vol 3 - Budget Activity 5B.pdf$$, NULL, FALSE, 6955000, 16252000, 9744000, 9744000, NULL, 9744000, 8359000, $$This Program Element enhances the advanced development efforts is to address emerging requirements and capabilities for deployable medical equipment and sets. These efforts focus on transitioning mature technologies into operational systems that enhance medical readiness and support Large-Scale Combat Operations (LSCO). By leveraging advanced development funding, the Army aims to integrate innovative solutions, improve system performance, and ensure deployable medical capabilities meet the evolving needs of the force. This includes the refinement, testing, and fielding of medical equipment and sets that provide life-saving care in austere and high- intensity environments. Projects in this PE include the following: Project 832 funds the engineering and manufacturing development of medical products for enhanced combat casualty care and follow-on care, including rehabilitation. Mature COTS medical products are also evaluated for military use. Consideration will also be given to reduce the medical sustainment footprint through smaller weight and cube volume, or equipment independence from supporting materiel. Products from this project will normally transition to OPA Funds.$$, $$Budget J-Books/FY27/Army/RDTE - Vol 3 - Budget Activity 5B.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604808A$$, $$Landmine Warfare/Barrier - Eng Dev$$, $$rdte_army_ba5$$, $$asa_alt$$, 2026, 9862000, 33085000, 54134000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "army", "page_num": 17, "original_pe": "0604808A", "page_header": "Department of the Army"}$$::jsonb, $$This Program Element (PE) provides for the Engineering and Manufacturing Development (EMD) and demonstration of countermine systems, Explosive Ordnance Disposal (EOD) render safe, and counter improvised explosive device capabilities. Project 016: Close Combat Capabilities, covers multiple programs: Prototype Integration for Multi-Domain Operations, Enhanced Robotics Payload - Render Safe (ERPRS), Mine Clearing Line Charge (MICLIC) Wireless Initiation, and the Arresting Cable Release Mechanism (ACRM). Enhanced Robotics Payload - Render Safe (ERP-RS) will enable EOD teams to access, render safe, and dispose of explosive ordnances (EO) while removing Soldiers from the direct effects of explosive blast and fragmentation. ERP-RS consists of three modules that will mount on existing Host Unmanned Ground Vehicles (HUGVs) in EOD units: (1) Highly Dexterous Manipulation System (HDMS) that has increased lift capacity and dexterity over current manipulators, using dual arm manipulation, will contribute to access, render safe, and disposal of sensitive EO, (2) a Multi-Shot Disruptor (MSD) module that provides remote selectable and precise disruption of surface laid or suspended EO, and (3) a Precision Aim Module (PAM) to provide accurate disruption of surface laid or suspended EO with the Multi-Shot Disrupter Module. These ERP-RS capabilities will provide a level of access, render safe, and disposal of EO that would currently require a Soldier to expose themselves to explosive hazards. Mine Clearing Line Charge (MICLIC) Wireless Initiation effort is a reliability enhancement to the current MICLIC system. The MICLIC is a legacy heavy minefield breaching capability consisting of a trailer mounted launcher that deploys the M58A4 Linear Demolition Charge via the MK22 Mod 4 Rocket. The system has historically suffered from poor detonation reliability traced primarily to the fuze or command wires leading to it. By eliminating the wired connections and replacing the fuze with a system based on the fielded M152 Remote Activation Munition System (RAMS), system reliability in command detonation mode will be maximized. Wireless initiation is also a key enabler for remote/robotic employment of current and future breaching systems to remove Soldiers from the breach as described in emerging breaching Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                                 Date: June 2025 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 5: System        PE 0604808A / Landmine Warfare/Barrier - Eng Dev Development & Demonstration (SDD) requirements such as the Common Engineer Chassis. If emerging requirement(s) is approved, effort will pivot to initiation system, development and integration activities on that replacement program. The Arresting Cable Release Mechanism (ACRM) is a derived requirement of the M1150 Assault Breacher Vehicle (ABV) which employs the MICLIC ammo components. The arresting cable of the M58A4 Linear Demolition Charge is an entanglement hazard to the M1150. Currently a crew member must dismount the vehicle to remove it after M58A4 detonation which violates the crew protection requirements of the ABV. The ACRM will automatically disconnect the arresting cable while under tension, throwing the cable clear of the vehicle immediately prior to M58A4 detonation. This functionality is critical to the ABV-Remote Control System program as no vehicle operator will be available to remove the arresting cable. ACRM capability will also be a requirement for robotic breaching concepts as described in emerging requirements such as the Common Engineer Chassis. Project CS2: Explosive Ordnance Disposal Render Safe - Sets Kits and Outfits (EOD RS-SKO) provides for the demonstration and evaluation of emerging technologies within requirements trade-space and capabilities needed for Explosive Ordnance Disposal (EOD) teams to Render Safe (RS) US and foreign ordnance and improvised explosive devices. Technical refresh of capabilities ensures Army 2030 formations maintain overmatch capability. EOD RS-SKO equips EOD teams with a suite of 11 capabilities needed to safely and effectively render safe explosive threats. Lessons learned from the Ukraine conflict show that the enemy/threat changes constantly so EOD RS-SKO capabilities must keep pace to ensure overmatch. Near term technical refresh priorities include improved load sets for the Electronic Countermeasures (Modi and AN/PLT-6(v)1) to ensure the most current threats are being countered allowing EOD Techs to safely approach/render safe explosive threats and enhanced deep-buried explosive hazard detection to allow EOD Techs to quickly and effectively clear their pathway and/or identify threats for render safe missions. This project will continue to support cross-service initiatives to increase commonality among information reporting and control systems. Project CS3: NGABS will increase the Warfighter lethality and mobility by optimizing Soldier protection for EOD personnel, while effectively managing all life cycle aspects of Personal Protective Equipment (PPE). Warfighter lethality is increased through bomb suit weight reduction utilizing extensive investments in protective material research and development. The result is material solutions that are lighter and are pieced together in a manner which increases Soldier mobility and longevity. EOD Soldier situational awareness and exposure to ballistic threats is enhanced through the NGABS HUD which allows the Soldier increased visibility under various obscurants and low/no-light situations. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                         Date: June 2025 Appropriation/Budget Activity                                               R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 5: System         PE 0604808A / Landmine Warfare/Barrier - Eng Dev Development & Demonstration (SDD)$$, NULL, 5683000, 5733000, 5291000, NULL, NULL, 123, $$RDTE - Vol 3 - Budget Activity 5B.pdf$$, NULL, FALSE, 49348000, 72532000, 17586000, 17586000, NULL, 17586000, 5310000, $$This PE provides for the Engineering and Manufacturing Development (EMD) and demonstration of countermine systems, Explosive Ordnance Disposal (EOD) render safe, and counter improvised explosive device capabilities. Project 016: Close Combat Capabilities, covers multiple programs: Prototype Integration for Multi-Domain Operations, Enhanced Robotics Payload - Render Safe (ERPRS), Mine Clearing Line Charge (MICLIC) Wireless Initiation, the Arresting Cable Release Mechanism (ACRM), and Counter-Unmanned Aerial Systems (c-UAS). Enhanced Robotics Payload - Render Safe (ERP-RS) will enable Explosive Ordnance Disposal (EOD) teams to access, render safe, and dispose of explosive hazards (EH) while removing Soldiers from the direct effects of explosive blast and fragmentation. ERP-RS consists of three modules that will mount on existing (MTRS Inc. II and CRS-H) and future robotic platforms in EOD units: (1) Highly Dexterous Manipulation System (HDMS) that has increased lift capacity and dexterity over current manipulators, using dual arm manipulation, will contribute to access, render safe, and disposal of sensitive EH, (2) a Multi-Shot Disruptor (MSD) module that provides remote selectable and precise disruption of surface laid or suspended EH, and (3) a Precision Aim Module (PAM) to provide accurate disruption of surface laid or suspended EH with the Multi-Shot Disrupter Module. These ERP-RS capabilities will provide a level of access, render safe, and disposal of EH. Mine Clearing Line Charge (MICLIC) Wireless Initiation effort is a reliability enhancement to the current MICLIC system. The MICLIC is a legacy heavy minefield breaching capability consisting of a trailer mounted launcher that deploys the M58A4 Linear Demolition Charge via the MK22 Mod 4 Rocket. The system has historically suffered from poor detonation reliability traced primarily to the fuze or command wires leading to it. By eliminating the wired connections and replacing the fuze with a system based on the fielded M152 Remote Activation Munition System (RAMS), system reliability in command detonation mode will be maximized. Wireless initiation is also a key enabler for remote/robotic employment of current and future breaching systems to remove Soldiers from the breach as described in emerging breaching requirements such as the Autonomous Breaching System. If emerging requirement(s) is approved, effort will pivot to initiation system, development and integration activities on that replacement program. The Arresting Cable Release Mechanism (ACRM) is a derived requirement of the M1150 Assault Breacher Vehicle (ABV) which employs the MICLIC ammo components. The arresting cable of the M58A4 Linear Demolition Charge is an entanglement hazard to the M1150. Currently a crew member must dismount the vehicle Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                                  Date: April 2026 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 5: System              PE 0604808A / Landmine Warfare/Barrier - Eng Dev Development & Demonstration (SDD) to remove it after M58A4 detonation which violates the crew protection requirements of the ABV. The ACRM will automatically disconnect the arresting cable while under tension, throwing the cable clear of the vehicle immediately prior to M58A4 detonation. This functionality is critical to the ABV-Remote Control System program as no vehicle operator will be available to remove the arresting cable. ACRM capability may also be a requirement for autonomous breaching concepts as described in emerging requirements. Project CS2: Explosive Ordnance Disposal Render Safe - Sets Kits and Outfits (EOD RS-SKO) provides for the demonstration and evaluation of emerging technologies within requirements trade-space and capabilities needed for Explosive Ordnance Disposal (EOD) teams to Render Safe (RS) US and foreign ordnance and explosive hazards. Technical refresh of capabilities ensures Army EOD formations maintain overmatch capability. EOD RS-SKO equips EOD teams with a suite of 11 capabilities needed to safely and effectively render safe explosive threats. Lessons learned from Ukraine and Israeli conflict show that the enemy/threat changes constantly-- UAS and ground robotics tactics, techniques and procedures (TTPs), countermeasures, long range fires, trench warfare, obstacles and electronic countermeasures continue to evolve, so EOD RSSKO capabilities must keep pace to ensure overmatch. Near term technical refresh priorities include improved load sets for the Electronic Countermeasures (Modi and AN/PLT-6(v)1) to ensure the most current threats are being countered allowing EOD Techs to safely approach/render safe explosive threats and enhanced buried explosive hazard detection to allow EOD Techs to quickly and effectively clear their pathway and/or identify threats for render safe missions. This project will continue to support cross-service initiatives to increase commonality among information reporting and control systems. Project DO6: Lethal & Protective Payloads for sUAS The Army has immediate need for lethal effects delivered by uncrewed systems to maintain overmatch against competitors that have unprecedented access to lethal, low-cost autonomous systems. The Lethal & Protective Payloads project will enable sUAS delivered effects through the Picatinny Common Lethality Integration Kit (CLIK) which consists of physical, electrical, and data interface design standards and an ecosystem of compliant hardware modules to enable rapid integration of an sUAS delivered munition suite. The Picatinny CLIK ecosystem consists of a Weapon Release System (WRS), Fire Control Module, Fuze Module, Radio Module, Power Module, and adapters for various common platforms and payload types. The munition suite will consist of legacy and commercial munitions to sUAS delivered lethality (e.g, dropped, launched, fired, or emplaced). The resulting lethal & protective capabilities delivered from sUAS will be anti-personnel, anti-materiel, obscuration, hazard neutralization, and deception. The use of Picatinny CLIK ensures that the Army does not procure and field one-off proprietary solutions that reduce sUAS platform and payload modularity and interoperability which would reduce operational effectiveness and increase sustainment costs. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                              Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 5: System            PE 0604808A / Landmine Warfare/Barrier - Eng Dev Development & Demonstration (SDD)$$, $$Budget J-Books/FY27/Army/RDTE - Vol 3 - Budget Activity 5B.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604818A$$, $$Army Tactical Command & Control Hardware & Software$$, $$rdte_army_ba5$$, $$army_reserve$$, 2026, 433325000, 154317000, 134162000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "army", "page_num": 17, "original_pe": "0604818A", "page_header": "Department of the Army", "fy26_v182_disc_K": 429164, "fy26_v182_supp_K": 3450, "fy26_v182_total_K": 432614, "fy26_v182_note_name": "Army Tactical Command & Control Hardware & Software", "fy26_v182_source_file": "RDTE - Vol 3 - Budget Activity 5B.txt", "fy26_v182_source_line": 10018}$$::jsonb, $$Project 323, Common Hardware Systems (CHS) is a mandated Army Strategic Source, as annotated in AR 25-1 that acquires and sustains highly flexible, cost-effective, and simplified non-developmental solutions that integrate the latest and emerging commercial information technology onto the Converged Mission Command Network. This funding line also supports network solution procurement and sustainment for U.S. Army Reserves, U.S. Army National Guard, U.S. Navy, U.S. Air Force, U.S. Marine Corps, and other Federal agencies. Project C29, the Central Technical Support Facility (CTSF), is the Army's single strategic facility responsible for executing Army Interoperability Certification (AIC) system of system verification/validation checkout, testing, and configuration management for the Army's LandWarNet Baseline. The Centralized Technical Support Facility (CTSF) funding line supports the Army's Network Modernization Strategy Line of Effort LOE 1B Network Enabling Functions. Project C34, the Army Tac C2 Sys Eng project funds the PEO Command, Control, Communications-Network (PEO C3N) System of Systems engineering, Enterprise and Integration efforts. The system engineering efforts are to facilitate overall network interoperability of all the various programs that must be able to seamlessly connect together while addressing their individual distinct requirements. Efforts address continuing evolution of the network within the PEO C3N portfolio of technology across capability enhancement packages to deliver efficient and effective cross-domain technical solution. Project DD1, Unified Network Technology Transition and Integration (UNTTI) is an RDT&E initiative enabling transport of agnostic, high-capacity and resilient tactical communications for expeditionary operations. UNTTI efforts support system/subsystem development and demonstration, aimed at integration, maturation, evaluation and testing to validate system prototypes meet requirements. In FY 2026, UNTTI efforts includes Secure Cellular, Technical Exchange Meeting (TEM) Project - Gateway Automation, Non-Traditional Waveforms Millimeter Wave, Transport Modernization, and Training Start Guides. Project DL8, Predictive Logistics (PL) is a new start in FY26. The FY 2026 funding will support modeling and simulation efforts to inform the development of fuel, ammunition, and critical maintenance requirements for PL Capability Needs Statement. Project DK3, Sensor Computing Environment (SCE), this funding is realigned to Projects EJ6 and EK9 in support of the Army Next Generation Command and Control (NGC2) initiative to modernize command and control (C2) systems, as detailed in the R2 B Program Change Summary (Change Summary Explanation) of this form. Project EJ4, COMMAND POST COMPUTING ENVIRONMENT (CPCE), this funding is realigned to Projects EJ6 and EK9 in support of the Army NGC2 initiative to modernize C2 systems, as detailed in the R2 B Program Change Summary (Change Summary Explanation) of this form. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                                 Date: June 2025 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 5: System             PE 0604818A / Army Tactical Command & Control Hardware & Software Development & Demonstration (SDD) Project EJ6, TACTICAL ENHANCEMENT, supports the Army Next Generation Command and Control (NGC2) initiative, Data Layer effort. Project conducts prototyping of the integrated data layer, including operating system and common core services in support of the Army's data-centric transformation and Command and Control (C2) strategy. The Data Layer strategy delivers standardization and provides seamless data access across warfighting function applications by leveraging industry best practices for iterative development and Development, Security, and Operations (DevSecOps) with an emphasis on artificial intelligence/machine learning strategies. Project EK9, TACTICAL NETWORK OPERATIONS AND MANAGEMENT, supports the Army's Next Generation Command and Control (NGC2) initiative, Applications Layer effort. Project conducts the prototyping of warfighting functions applications to be delivered to the specifications defined by the Data Layer (Project EJ6) and consolidates and further refines Network Operations (NetOps) Applications that are key to enabling warfighting function applications in a data-centric network with increased efficiency in overall network management. The Applications Layer strategy ensures that warfighting function applications will operate in conjunction with the Data Layer to provide seamless mission command from the enterprise to the tactical edge, leveraging cutting edge available commercial technologies. Project EQ8, Mobile/Handheld Computing Environment (M/HHCE) enables situational awareness (SA) and command and control (C2) for dismounted combat forces through the Nett Warrior (NW) system. M/HH CE utilizes Government-owned Tactical Assault Kit (TAK) as a foundation for integrating a wide array of functional software, such as UAV planning/control, casualty care and logistics. Future versions of NW and TAK will form the SA/C2 baseline for Next Gen C2 dismounted forces. The NW system provides leaders electronic real-time information on friendly positions; information about enemy activity and movement; navigational data and map imagery; a collaborative planning tool; and other mission related graphics which effectively puts the power of the entire Army tactical network in the hands of the dismounted leader. Project ER9, Expeditionary Army Command Post: This funding line supports Army Next Generation Command and Control (NGC2) initiative to modernize Command and Control Systems (C2), Infrastructure layer. Will deliver capability to enhance the survivability and mobility of command post formations. Will replace selected elements of the legacy command post to provide improved expeditionary capability, survivability, agility, and scalability for command post formations at all echelons. By integrating mission command warfighting functions on to vehicle platforms, a dispersed command post construct will enable the battle staff to blend in with the overall maneuver formation while giving the commander the ability to synchronize the close fight on the move. The FY 2026 request for Army Tactical Command & Control Hardware & Software includes $410,263 thousand of discretionary and $2,430 thousand of mandatory (reconciliation) for a total of $412,693 thousand. The mandatory funds include integration, test and evaluation support of Joint Fires Network (JFN) tools and capabilities. Further information for this reconciliation request is provided in Section 20005 (Low-Cost Weapons) of the Reconciliation Exhibit. The FY 2026 request was reduced by $3.574 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative." Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                              Date: June 2025 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 5: System            PE 0604818A / Army Tactical Command & Control Hardware & Software Development & Demonstration (SDD)$$, NULL, 47436000, 48266000, 49193000, NULL, NULL, 124, $$RDTE - Vol 3 - Budget Activity 5C.pdf$$, NULL, FALSE, 129265000, 432614000, 42584000, 42584000, NULL, 42584000, 49683000, $$Project 323, Common Hardware Systems (CHS) is a mandated Army Strategic Source, as annotated in AR 25-1 that acquires and sustains highly flexible, cost-effective, and simplified non-developmental solutions that integrate the latest and emerging commercial information technology onto the Converged Mission Command Network. Also supports network solution procurement and sustainment for U.S. Army Reserves, U.S. Army National Guard, U.S. Navy, U.S. Air Force, U.S. Marine Corps, and other Federal agencies. Beginning in FY 2027, Project 323 funding has been realigned to PE 0605333A/C2 Infrastructure, Project C2G Modular C2 Infrastructure, as part of a new funding structure for the Next Generation Command and Control (NGC2) investment to modernize Command and Control (C2) systems for the Infrastructure Layer. Project C29, Central Technical Support Facility (CTSF), is the Army's single strategic facility responsible for executing Army Interoperability Certification (AIC) system of system verification/validation checkout, testing, and configuration management for the Army's LandWarNet Baseline. Beginning in FY 2027, Project C29 funding was removed due to transfer of the Army Interoperability Certification Mission Functions to ASA(ALT). Project C34, Army Tac C2 Sys Eng, supports the CPE Command, Control, Communications-Network (CPE C3N) System of Systems engineering, Enterprise and Integration efforts. The system engineering efforts are to facilitate overall network interoperability of all the various programs that must be able to seamlessly connect together while addressing their individual distinct requirements. Efforts address continuing evolution of the network within the CPE C3N portfolio of technology across capability enhancement packages to deliver efficient and effective cross-domain technical solution. Beginning in FY 2027, Project C34 funding was realigned to PE 0605333A/C2 Infrastructure, Project C2H C2 Systems Engineering, as part of a new funding structure for the NGC2 investment to modernize C2 systems for the Infrastructure Layer. Project DD1, Unified Network Technology Transition and Integration (UNTTI) is an RDT&E initiative enabling transport of agnostic, high-capacity and resilient tactical communications for expeditionary operations. UNTTI efforts support system/subsystem development and demonstration, aimed at integration, maturation, evaluation and testing to validate system prototypes meet requirements. In FY 2026, UNTTI efforts includes Secure Cellular, Technical Exchange Meeting (TEM) Project - Gateway Automation, Non-Traditional Waveforms Millimeter Wave, Transport Modernization, and Training Start Guides. Beginning in FY 2027, Project DD1 funding was realigned to PE 0605330A/C2 Transport, Project C2A Satellite and Network Modernization, as part of a new funding structure for the NGC2 investment to modernize C2 systems for the Transport Layer. Project DL8, Predictive Logistics (PL) is the Army's initiative to incorporate combat platform-based sensor data inclusive of fuel, ammunition and maintenance status into command decision tools. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                                  Date: April 2026 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 5: System          PE 0604818A / Army Tactical Command & Control Hardware & Software Development & Demonstration (SDD) Beginning in FY 2027, Project DL8 funding was realigned to PE 0605331A/C2 Applications, Project C2D Warfighter C2 Applications, as part of a new funding structure for the NGC2 investment to modernize C2 systems for the Applications Layer. Project DK3, Sensor Computing Environment (SCE), provides interoperability for sensors and systems across the Army. Capabilities include common sensor data model, definition of standard, interface specification, architecture definition, Mature Software Development Kit (SDK), and compliance verifications & validation tools. In FY 2026, Project DK3 funding was realigned to Projects EJ6 and EK9. Project EJ4, COMMAND POST COMPUTING ENVIRONMENT (CPCE), provides an available, reliable and resilient infrastructure which unifies data and services within the Command Post. Capabilities include self-service capabilities, collaboration tools, data analytics and C2 core capabilities, such as data visualization/management and command post Common Operational Picture (COP). In FY 2026 Project EJ4 funding was realigned to Projects EJ6 and EK9. Project EJ6, TACTICAL ENHANCEMENT, supports the Army NGC2 initiative, Data Layer effort. Project conducts prototyping of the integrated data layer, including operating system and common core services in support of the Army's data-centric transformation and C2 strategy. The Data Layer strategy delivers standardization and provides seamless data access across warfighting function applications by leveraging industry best practices for iterative development and Development, Security, and Operations (DevSecOps) with an emphasis on artificial intelligence/machine learning strategies. Beginning in FY 2027, Project EJ6 funding is realigned to PE 0605332A/C2 Data, Projects C2E C2 Data and C2F Artificial Intelligence/Machine Learning, as part of a new funding structure for the NGC2 investment to modernize C2 systems for the Data Layer. Project EK9, TACTICAL NETWORK OPERATIONS AND MANAGEMENT, supports the Army's NGC2 initiative, Applications Layer effort. Project delivers modernized warfighting functions applications in accordance with the specifications defined by the Data Layer. It consolidates and further refines Network Operations (NetOps) Applications that are key to enabling warfighting function applications in a data-centric network with increased efficiency in overall network management. The Applications Layer strategy ensures that warfighting function applications will operate in conjunction with the Data Layer to provide seamless mission command from the enterprise to the tactical edge, leveraging cutting edge available commercial technologies. Beginning in FY 2027, Project EK9 funding was realigned to PE 0605331A/C2 Applications, Project C2D Warfighter C2 Applications, as part of a new funding structure for the NGC2 investment to modernize C2 systems for the Applications Layer. Project EQ8, Mobile/Handheld Computing Environment (M/HHCE) enables situational awareness (SA) and command and control (C2) for dismounted combat forces through the Nett Warrior (NW) system. M/HH CE utilizes Government-owned Tactical Assault Kit (TAK) as a foundation for integrating a wide array of functional software, such as UAV planning/control, casualty care and logistics. Future versions of NW and TAK will form the SA/C2 baseline for Next Gen C2 dismounted forces. The NW system provides leaders electronic real-time information on friendly positions; information about enemy activity and movement; navigational data and map Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                                  Date: April 2026 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 5: System              PE 0604818A / Army Tactical Command & Control Hardware & Software Development & Demonstration (SDD) imagery; a collaborative planning tool; and other mission related graphics which effectively puts the power of the entire Army tactical network in the hands of the dismounted leader. Project ER9, Expeditionary Army Command Post, delivers capability to enhance the survivability and mobility of command post formations. Replaces elements of the legacy command post to provide improved expeditionary capability, survivability, agility, and scalability for command post formations at all echelons. By integrating mission command warfighting functions on to vehicle platforms, a dispersed command post construct will enable the battle staff to blend in with the overall maneuver formation while giving the commander the ability to synchronize the close fight on the move. Beginning in FY 2027, Project ER9 funding was realigned to PE 0655333A/C2 Infrastructure, Project C2I Mounted C2 Development, as part of a new funding structure for the NGC2 investment to modernize C2 systems for the Infrastructure Layer. Funding has been realigned out of this line to support the Army's Next Generation Command and Control (NGC2) initiative.$$, $$Budget J-Books/FY27/Army/RDTE - Vol 3 - Budget Activity 5B.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604820A$$, $$Radar Development$$, $$rdte_army_ba5$$, $$asa_alt_alt$$, 2026, 71226000, 78363000, 41584000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "army", "page_num": 17, "original_pe": "0604820A", "page_header": "Department of the Army", "fy26_v182_disc_K": 53226, "fy26_v182_supp_K": 14000, "fy26_v182_total_K": 67226, "fy26_v182_note_name": "Radar Development", "fy26_v182_source_file": "RDTE - Vol 3 - Budget Activity 5B.txt", "fy26_v182_source_line": 13137}$$::jsonb, $$Project E10: The FY2026 request for Sentinel includes $18,853 thousand of discretionary and $14,000 thousand of mandatory (reconciliation) for a total of $32,853 thousand. The discretionary funds will support enhancements, upgrades, and continued testing of the Army Modernization Priorities in support of the Sentinel Radar programs and will provide for an incrementally fielded Integrated Air and Missile Defense Fire Control System/capability for the composite Army Air and Missile Defense Brigades. The mandatory funds will develop and implement new signal processing techniques and waveforms to enhance Electronic Attack and Electronic Protect techniques based on the evolving threat, further enhancing radar survival and effectiveness in contested environments. Further information for this reconciliation request is provided in Section 20003 (Missile Defense) of the Reconciliation Exhibit. The Sentinel systems are a key component of the Army Integrated Air and Missile Defense (AIAMD) architecture, providing critical air surveillance of the forward areas. Project PS1: The FY2026 request for the Army Long-Range Persistent Surveillance (ALPS) includes $34,373 thousand of discretionary and $4,000 thousand of mandatory (reconciliation) for a total of $38,373 thousand. The discretionary funds will support the Army Long-Range Persistent Surveillance (ALPS) sensor, which is a persistent, passive air surveillance sensor system. ALPS capabilities include long-range, 360-degree surveillance against conventional fixed wing and rotary wing aircraft, UAS, and cruise missiles. ALPS supports tactical to strategic operations via its capability to connect with multiple Army and Joint Command and Control systems including the Integrated Fire Control Network (IFCN). The mandatory funds will develop Fixed Site capability for defense of the homeland. Further information for this reconciliation request is provided in Section 20003 (Missile Defense) of the Reconciliation Exhibit. The ALPS program tasks include all programmatic and engineering activities needed to modernize systems currently supporting multiple Combatant Commands and design/development effort to provide a passive capability to Army Air and Missile Defense forces in accordance with the requirements in the Capability Development Document (CDD). The total program element FY2026 request is $53,226 thousand of discretionary and $18,000 thousand of mandatory reconciliation for a total of $71,226 thousand. Further information for this reconciliation request is provided in Section 20003 (Missile Defense) of the Reconciliation Exhibit. The FY 2026 request was reduced by $0.117 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative." Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                 Date: June 2025 Appropriation/Budget Activity                                               R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 5: System         PE 0604820A / Radar Development Development & Demonstration (SDD)$$, NULL, 188054000, 60354000, 60389000, NULL, NULL, 125, $$RDTE - Vol 3 - Budget Activity 5C.pdf$$, NULL, FALSE, 40066000, 67226000, 58260000, 58260000, NULL, 58260000, 60991000, $$Project E10: Supports enhancements, upgrades and continued testing of the Army Modernization Priorities in support of the Sentinel Radar programs and will provide for an incrementally fielded Integrated Air and Missile Defense Fire Control System/capability for the composite Army Air and Missile Defense Brigades. The Sentinel systems are a key component of the Army Integrated Air and Missile Defense (AIAMD) architecture, providing critical air surveillance of the forward areas. Project PS1: Supports the Army Long-Range Persistent Surveillance (ALPS) sensor, which is a persistent, passive air surveillance sensor system. ALPS capabilities include long-range, 360-degree surveillance against conventional fixed wing and rotary wing aircraft, UAS, and cruise missiles. ALPS supports tactical to strategic operations via its capability to connect with multiple Army and Joint Command and Control systems including the Integrated Fire Control Network (IFCN).$$, $$Budget J-Books/FY27/Army/RDTE - Vol 3 - Budget Activity 5B.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604822A$$, $$General Fund Enterprise Business System (GFEBS)$$, $$rdte_army_ba5$$, $$peo_eis$$, 2026, 0, 16011000, 1995000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "army", "page_num": 17, "fy26_v180": {"note": "R1_FY26_entry_no_value_extracted_in_original_ingest", "source": "b1_null_zero_v180"}, "original_pe": "0604822A", "page_header": "Department of the Army"}$$::jsonb, $$This Program Element (PE) supports the General Fund Enterprise Business System-Sensitive Activities (GFEBS-SA): GFEBS-SA is a National Security System (NSS) leveraging the GFEBS base system as the Army's core financial management system, certified by the Chief Financial Officer Council, to provide the same financial capabilities of GFEBS but on SIPR, with additional security features to protect national security information. GFEBS-SA was implemented to protect sensitive information and enable clean auditability, allowing the Army to process sensitive and classified financial transactions that cannot be processed in the fully-fielded GFEBS base system without compromising classified information, missions, or endangering soldiers. GFEBS-SA was developed and deployed as an essential financial program designed to enable the auditability that is needed to comply with the Chief Financial Officers (CFO) Act, the Federal Financial Management Improvement Act (FFMIA), and prevent compromise of data that could cause grave harm to U.S. forces. GFEBS-SA was fully deployed in 2020 to 3,000 users across 100 locations worldwide and processes Secret Collateral and below information. Services are capable of being upgraded throughout the life of the program in order to incorporate advances in best business practices and technology, and will modify capability to maintain a synchronized software baseline with the GFEBS base system to maintain efficiencies in capability enhancements, training documentation, and sustainment support. In FY 2021, GFEBS-SA received approval to proceed with entry into capability support (sustainment) and application capability support transitioned to Army Shared Services Center (ASSC). FY 2023 RDT&E funding supported continuous enhancements to the GFEBS-SA SIPR capabilities to ensure appropriate security measures are in place to protect sensitive financial data. GFEBS-SA RDT&E efforts have been rolled into GFEBS (GF5) therefore DV6 has no funding request beyond FY 2023. General Fund Enterprise Business System (GFEBS): GFEBS is the Army's core financial management system for administering its General Fund. Full Deployment was reached in 2012 and the system is currently in the Capability Support (sustainment) phase of the Business Capability Acquisition Cycle, focused on modernization, cyber security, and system enhancements while also conducting capability enhancements to meet policy and deliver accurate Army financial information. GFEBS was implemented to fulfill the needs and enable the Army to comply with the Federal Financial Management Improvement Act, deployed to over 35,000 users across 200 locations worldwide. GFEBS was developed using a commercial off-the-shelf Enterprise Resource Planning system that is certified by the Chief, Financial Officer Council and provides six core financial functions (United States General Ledger (USGL), Cost Management, Funds Control, Payable Management, Real Property, Receivable Management and Reports). FY 2025 Base dollars in the amount of $1.995 million will continue to support enhancements, such as system upgrade in support interfaces to improve system performance, accountability, and auditability efforts. These funds will be used to meet OSD and Army data exchange, and interface requirements. The additional capability will support both compliancy to meet audit requirements and updated interfaces to replace sun-setting systems. GFEBS RDT&E funds capability enhancements designed to meet audit readiness standards and system changes as prioritized by the functional sponsor and user community through the Tactical Financial Information Council, a Senior Executive Service/General Officer-level board. The RDT&E funding will support the increase in mission performance and improvement of automated system processes and continue to support modernization efforts aligned with the Original Equipment Manufacturer's Systems Applications Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                               Date: June 2025 Appropriation/Budget Activity                                                     R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 5: System               PE 0604822A / General Fund Enterprise Business System (GFEBS) Development & Demonstration (SDD) and Products (SAP) next generation capability. Activities include code de-customization, data enablement, and improved automated data access to prevent end of support for the current database and platform. Funds will also support acquisition trades and market research on alternatives for SAP based finance/logistics consolidation to evaluate potential efficiencies by reducing platforms and licenses. GFEBS must take critical steps towards integration and implementation of the next generation of Enterprise Business Systems capabilities. This effort will address the obsolescence of existing SAP Enterprise Resource Planning (ERP) real property and financial management platforms that the vendor plans to sunset around FY 2032. GFEBS modernization work sets the conditions for development of a converged, post-modern Defense Business System that streamlines and integrates the Army's core business functions. The effort on the individual programs must consider benefits of consolidation. GFEBS must identify redundant processes as candidates for business process re-engineering. Funding will support the 1) market research of Industry best practices, 2) Initiation of an Army Enterprise Development Environment to enable prototyping which reduces risk by aiding the requirements development. This environment includes: Cloud-hosted infrastructure, applications, and programs and tools, 3) government Program Management and Technical Service contractors needed to plan for and manage the initiation of the post-modern system implementation effort. FY 2026 GFEBS has no RDT&E funding request.$$, NULL, NULL, NULL, NULL, NULL, NULL, 126, $$RDTE - Vol 3 - Budget Activity 5C.pdf$$, NULL, FALSE, 1922000, 0, NULL, NULL, NULL, NULL, NULL, $$This Program Element (PE) supports the General Fund Enterprise Business System-Sensitive Activities (GFEBS-SA): GFEBS-SA is a National Security System (NSS) leveraging the GFEBS base system as the Army's core financial management system, certified by the Chief Financial Officer Council, to provide the same financial capabilities of GFEBS but on SIPR, with additional security features to protect national security information. GFEBS-SA was implemented to protect sensitive information and enable clean auditability, allowing the Army to process sensitive and classified financial transactions that cannot be processed in the fully-fielded GFEBS base system without compromising classified information, missions, or endangering soldiers. GFEBS-SA was developed and deployed as an essential financial program designed to enable the auditability that is needed to comply with the Chief Financial Officers (CFO) Act, the Federal Financial Management Improvement Act (FFMIA), and prevent compromise of data that could cause grave harm to U.S. forces. GFEBS-SA was fully deployed in 2020 to 3,000 users across 100 locations worldwide and processes Secret Collateral and below information. Services are capable of being upgraded throughout the life of the program in order to incorporate advances in best business practices and technology, and will modify capability to maintain a synchronized software baseline with the GFEBS base system to maintain efficiencies in capability enhancements, training documentation, and sustainment support. In FY 2021, GFEBS-SA received approval to proceed with entry into capability support (sustainment) and application capability support transitioned to Army Shared Services Center (ASSC). FY 2023 RDT&E funding supported continuous enhancements to the GFEBS-SA SIPR capabilities to ensure appropriate security measures are in place to protect sensitive financial data. GFEBS-SA RDT&E efforts have been rolled into GFEBS (GF5) therefore DV6 has no funding request beyond FY 2023. General Fund Enterprise Business System (GFEBS): GFEBS is the Army's core financial management system for administering its General Fund. Full Deployment was reached in 2012 and the system is currently in the Capability Support (sustainment) phase of the Business Capability Acquisition Cycle, focused on modernization, cyber security, and system enhancements while also conducting capability enhancements to meet policy and deliver accurate Army financial information. GFEBS was implemented to fulfill the needs and enable the Army to comply with the Federal Financial Management Improvement Act, deployed to over 35,000 users across 200 locations worldwide. GFEBS was developed using a commercial off-the-shelf Enterprise Resource Planning system that is certified by the Chief, Financial Officer Council and provides six core financial functions (United States General Ledger (USGL), Cost Management, Funds Control, Payable Management, Real Property, Receivable Management and Reports). GFEBS must take critical steps towards integration and implementation of the next generation of Enterprise Business Systems capabilities. This effort will address the obsolescence of existing SAP Enterprise Resource Planning (ERP) real property and financial management platforms that the vendor plans to sunset around FY 2032. GFEBS modernization work sets the conditions for development of a converged, post-modern Defense Business System that streamlines and integrates the Army's core business functions. The effort on the individual programs must consider benefits of consolidation. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                            Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 5: System            PE 0604822A / General Fund Enterprise Business System (GFEBS) Development & Demonstration (SDD) GFEBS must identify redundant processes as candidates for business process re-engineering. Funding will support the 1) market research of Industry best practices, 2) Initiation of an Army Enterprise Development Environment to enable prototyping which reduces risk by aiding the requirements development. This environment includes: Cloud-hosted infrastructure, applications, and programs and tools, 3) government Program Management and Technical Service contractors needed to plan for and manage the initiation of the post-modern system implementation effort. GFEBS has no RDT&E funding request beyond FY2025.$$, $$Budget J-Books/FY27/Army/RDTE - Vol 3 - Budget Activity 5B.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604826J$$, $$Joint C5 Capability Development, Integration, and Interoperability Asses$$, $$rdte_dw_ba4$$, $$dw_js$$, 2026, 25889000, 18991000, 29706000, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "dw", "page_num": 73, "original_pe": "0604826J", "page_header": "Defense-Wide"}$$::jsonb, NULL, NULL, 29647000, 31753000, 32961000, NULL, NULL, NULL, NULL, NULL, FALSE, 28897000, 25706000, 28314000, 28314000, NULL, 28314000, 33624000, $$Joint C5 Capability Development, Integration, and Interoperability Assessments program leads Command, Control, Communications, Computers, and Cyber (C5) assessments, analyses, capability development, and Joint Fires Command and Control (C2) interoperability efforts required to achieve an effective, integrated, and interoperable combined joint force. Efforts include C5 requirements determination, architectures development and integration, data and standards, integration, Allies and coalition integration and interoperability assessments, and Joint Fires C2 interoperability coordinating firepower compatibility. The Joint Staff leads the Department of War’s effort to develop and integrate the Combined Joint All-Domain Command and Control (CJADC2) across the Department. The Joint C5 program is the Joint Staff focal point for this responsibility. Its projects provide the research, analysis, and execution needed to make the CJADC2 strategy a reality.$$, $$Budget J-Books/FY27/Remaining/RDTE_TJS_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604827A$$, $$Soldier Systems - Warrior Dem/Val$$, $$rdte_army_ba5$$, $$devcom_c5isr$$, 2026, 4137000, 18892000, 29132000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "army", "page_num": 17, "original_pe": "0604827A", "page_header": "Department of the Army", "fy26_v182_disc_K": 4137, "fy26_v182_supp_K": 22587, "fy26_v182_total_K": 26724, "fy26_v182_note_name": "Soldier Systems - Warrior Dem/Val", "fy26_v182_source_file": "RDTE - Vol 3 - Budget Activity 5B.txt", "fy26_v182_source_line": 13863}$$::jsonb, $$A portion of this funding line is a key enabler of the Army Modernization Priorities in support of the Small Unit Power (SUP) program. Project EY2 - Integrated Soldier Power Data System - Core (ISPDS-C): Includes power and data managing/distribution devices, cutting-edge energy storage solutions, and power scavenging devices. These capabilities fill the power and energy gaps created by the increase in mission essential, Soldier portable power consumers, such as heads up displays, situational awareness displays, global positioning systems, weapon sensors, radios, night vision systems, and other devices. This project line develops power sources and power management solutions for the individual Soldier and squad for use in all operating environments. This project develops and evaluates capabilities to fill the power and energy requirements for critical Network Baseline 4.0 Soldier worn systems to include tactical radios, assured position navigation and timing, Next Generation Squad Weapon, Nett Warrior, Enhanced Night Vision Goggle (all variants, including Binocular), and the Integrated Visual Augmentation System. ISPDS-C systems will enable dismounted Soldiers and squads to execute their missions more efficiently, independently, for longer durations and with fewer battery resupplies while reducing the logistical and physical burden associated with moving fuel and batteries. This project also develops and integrates vehicular on-the-move charging. Project EY4 - Universal Battery Charger (UBC): Fills the power and energy gap created by the increase in mission essential, Soldier portable power consumers, by providing a variety of charging solutions capable of providing power to handheld communication devices and military batteries to support mounted and dismounted formations. The UBC is suited for mounted and dismounted operations at the company level and below in multi-domain and austere operating environments. The system can draw power from wall outlets, vehicle power, generators, and solar power sources. The UBC enables dismounted Soldiers to execute their missions with fewer battery resupplies, thus reducing the logistical burden associated with moving fuel and batteries. The UBC capability allows dismounted Soldiers to operate independently for longer missions. The UBC fills the power and energy gap associated with bulk charging. Project FK4 - Soldier Borne Sensor (SBS): The SBS is a small unmanned aerial vehicle. The SBS provides a near term solution to three Army War-fighting Challenges at the Infantry Squad level: develop situational understanding, conduct air-ground reconnaissance, and conduct joint combined arms maneuver. The system is simple Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                                     Date: June 2025 Appropriation/Budget Activity                                                       R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 5: System                 PE 0604827A / Soldier Systems - Warrior Dem/Val Development & Demonstration (SDD) to deploy and use to support the squad leader's decision-making process. The system allows Soldiers to obtain local situational awareness and understanding of their immediate surroundings while remaining in covered or concealed positions. The SBS program will be procured through multiple phases. We will use the funding in this project to develop, integrate, and qualify additional capabilities for each phase. Funding in this project aligns with the Army's priorities in support of the National Defense Strategy. Project LS2 - Lethal Semi-Autonomous Aerial Unmanned System - Engineering Development: This project focuses on engineering and material development in support of the acquisition program for an enduring capability with Low Altitude Strike and Stalk Ordnance (LASSO) CDD which was approved in AUG24. Infantry Brigade Combat Teams (IBCTs) lack adequate organic capabilities at echelon to apply immediate, point, long range, and direct fire effects to destroy tanks, light armored vehicles, hardened targets, defilade, and personnel targets, while producing minimal collateral damage in complex terrain in all environmental conditions. Development will focus on the Fire Control Stations (FCS), All-Up Round (AUR), and System Architecture. Develop technology for incorporation into the CDD update for the Program of Record and conduct tech enhancements from current global conflicts. The funding contained within this budget line and project will be used to conduct evaluations of technologies and capabilities in the loitering munitions capability space, hardware and system architecture engineering and integration activities, and testing and evaluation activities. Realignment starting FY 2026 to Lethal Semi-Autonomous Aerial Unmanned Sys-Eng Dev (0609345A/A49) funding line. S65 - Soldier Power: Soldier Power enables dismounted Soldiers to efficiently execute missions for longer durations by reducing the logistical burden associated with fuel and primary (disposable) batteries. Platoon Power Generation (PPG) - PM E2S2: This project supports the demonstration and development of a PPG. The Small Unit Power (SUP) PPG will provide small units with sufficient portable power to sustain Modified Table of Organizational Equipment (MTOE) unit power demand in support of 48 to 72 hour missions. It will be used for charging batteries and powering various types of Army communications and electronics devices. The FY 2026 request was reduced by $1.427 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative."$$, NULL, 5727000, 5771000, 5774000, NULL, NULL, 127, $$RDTE - Vol 3 - Budget Activity 5C.pdf$$, NULL, FALSE, 28069000, 26724000, 5663000, 5663000, NULL, 5663000, 5831000, $$A portion of this funding line is a key enabler of the Army Modernization Priorities in support of the Small Unit Power (SUP) program. Project EY2 - Integrated Soldier Power Data System - Core (ISPDS-C): Includes power and data managing/distribution devices, cutting-edge energy storage solutions, and power scavenging devices. These capabilities fill the power and energy gaps created by the increase in mission essential, Soldier portable power consumers, such as heads up displays, situational awareness displays, global positioning systems, weapon sensors, radios, night vision systems, and other devices. This project line develops power sources and power management solutions for the individual Soldier and squad for use in all operating environments. This project develops and evaluates capabilities to fill the power and energy requirements for critical Network Baseline 4.0 Soldier worn systems to include tactical radios, assured position navigation and timing, Next Generation Squad Weapon, Nett Warrior, Enhanced Night Vision Goggle (all variants, including Binocular), and the Integrated Visual Augmentation System. ISPDS-C systems will enable dismounted Soldiers and squads to execute their missions more efficiently, independently, for longer durations and with fewer battery resupplies while reducing the logistical and physical burden associated with moving fuel and batteries. This project also develops and integrates vehicular on-the-move charging. Project EY4 - Universal Battery Charger (UBC): Fills the power and energy gap created by the increase in mission essential, Soldier portable power consumers, by providing a variety of charging solutions capable of providing power to handheld communication devices and military batteries to support mounted and dismounted formations. The UBC is suited for mounted and dismounted operations at the company level and below in multi-domain and austere operating environments. The system can draw power from wall outlets, vehicle power, generators, and solar power sources. The UBC enables dismounted Soldiers to execute their missions with Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                                     Date: April 2026 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 5: System              PE 0604827A / Soldier Systems - Warrior Dem/Val Development & Demonstration (SDD) fewer battery resupplies, thus reducing the logistical burden associated with moving fuel and batteries. The UBC capability allows dismounted Soldiers to operate independently for longer missions. The UBC fills the power and energy gap associated with bulk charging. Project FK4 - Soldier Borne Sensor (SBS): The SBS is a small unmanned aerial vehicle. The SBS provides a near term solution to three Army War-fighting Challenges at the Infantry Squad level: develop situational understanding, conduct air-ground reconnaissance, and conduct joint combined arms maneuver. The system is simple to deploy and use to support the squad leader's decision-making process. The system allows Soldiers to obtain local situational awareness and understanding of their immediate surroundings while remaining in covered or concealed positions. The SBS program will be procured through multiple phases. We will use the funding in this project to develop, integrate, and qualify additional capabilities for each phase. Funding in this project aligns with the Army's priorities in support of the National Defense Strategy. Project LS2 - Lethal Semi-Autonomous Aerial Unmanned System - Engineering Development (LSAUS - Eng Dev): This project focuses on engineering and material development in support of the acquisition program for an enduring capability with Low Altitude Stalking and Strike Ordnance (LASSO) CDD which was approved in AUG24. Mobile Brigade Combat Teams (MBCTs) lack adequate organic capabilities at echelon to apply immediate, point, long range, and direct fire effects to destroy tanks, light armored vehicles, hardened targets, targets in defilade, and personnel targets, while producing minimal collateral damage in complex terrain in all environmental conditions. Development will focus on the Fire Control Stations (FCS), All-Up Round (AUR), and System Architecture. System Architecture will include integrating with Soldier Borne Mission command (SBMC), Next Generation Command and Control (NGC2) and complete Universal Vehicle Control (UVC) compliance and integration. Develop technology for incorporation into the CDD update, for the enduring program, and conduct tech enhancements from current global conflicts. The funding contained within this budget line and project will be used to conduct evaluations of technologies and capabilities in the loitering munitions capability space, hardware and system architecture engineering and integration activities, and testing and evaluation activities. LASSO is awarding up to four hardware contacts to modernize the industrial base and generate domestic ammunition stockpiles. In addition, LASSO is supporting OSW Replicator and Transformation in Contact (TiC) in support of Indo-Pacific efforts to expand prepositioned stocks and increase deployments and exercises to support strategic presence in the region. The LASSO program will use Other Transaction Authority (OTA) and Federal Acquisition Regulation (FAR) contracts to field critical technologies quickly. The total cost of the LSAUS - Eng Dev Middle Tier of Acquisition effort is $209M RDT&E from FY25 to FY29. The remainder of the LSAUS - Eng Dev is fully funded across the Future Years Defense Program. Realignment starting FY 2026 to Lethal Semi-Autonomous Aerial Unmanned Sys-Eng Dev (0609345A/A49) funding line. Continuation starting FY 2027 to Lethal Semi-Autonomous Aerial Unmanned Sys-Eng Dev (0609345A/A58) funding line. S65 - Soldier Power: Soldier Power enables dismounted Soldiers to efficiently execute missions for longer durations by reducing the logistical burden associated with fuel and primary (disposable) batteries. Platoon Power Generation (PPG) - PM E2S2: This project supports the demonstration and development of a PPG. The Small Unit Power (SUP) PPG will provide small units with sufficient portable power to sustain Modified Table of Organizational Equipment (MTOE) unit power demand in support of 48 to 72 hour missions. It will be used for charging batteries and powering various types of Army communications and electronics devices. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                           Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 5: System            PE 0604827A / Soldier Systems - Warrior Dem/Val Development & Demonstration (SDD)$$, $$Budget J-Books/FY27/Army/RDTE - Vol 3 - Budget Activity 5B.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604834D8Z$$, $$Biosurveillance Program Development & Prototyping$$, $$rdte_dw_ba4$$, $$dw$$, 2027, 0, 0, 0, NULL, $${}$$::jsonb, NULL, NULL, 12640000, 8000000, 7500000, NULL, NULL, NULL, NULL, NULL, FALSE, 0, 0, 7000000, 7000000, NULL, 7000000, 7500000, $$This program exploits advances in technology to develop, improve and implement detection, information processing and decision support for biosurveillance. The mission of this program is to create a fit-for-purpose biosurveillance capability with federated collection, processing, analysis, production, and dissemination capabilities to enable strategic, anticipatory, and operational decision-making for deterrence and risk mitigation. To accomplish this mission, the Biosurveillance Program will: 1) Implement agile planning and response processes through a cross-functional biosurveillance organizational architecture—with the structure, function, and authorities —to support time-sensitive needs of DoW leaders; 2) Expand physical and digital detection capabilities and capacity—infused with intelligence collection—to enable early warning, sustained awareness, and agile response focusing on advanced technological capabilities; 3) Enhance biosurveillance insights by increasing data value, knowledge generation and accelerating processing of existing health and biodefense repositories into a fit-for purpose analytic capability; 4) Communicate the full range of analytic products necessary for leadership decision-making across the continuum of conflict. This budget is justified by the critical gap, identified in the 2023 Biodefense Posture Review, in the Department's ability to gather and analyze timely biothreat information to protect the Joint Force and enhance national security. The funding will establish this necessary capability by operationalizing a Biosurveillance Information Platform (BIP), expanding next-generation sequencing, and improving data sharing. These investments are essential for enhancing readiness and resilience against a dynamic landscape of natural, accidental, and deliberate biological threats. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Office of the Secretary Of Defense                                            Date: April 2026 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 4:         PE 0604834D8Z / Biosurveillance Program Development & Prototyping Advanced Component Development & Prototypes (ACD&P)$$, $$Budget J-Books/FY27/DW/RDTE_OSW_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604840F$$, $$F-35 C2D2$$, $$rdte_af_ba7$$, $$aflcmc_wa$$, 2026, 1182094000, 1236710000, 1134207000, NULL, $${"ba_raw": "6.7", "source": "af_r1_fy26", "fy27_mand_k": 939586, "original_pe": "0604840F", "fy27_mand_v157": "2026-05-08", "fy27_mand_source": "DoW_FY2027_Mandatory_Funding_Overview.txt Appendix B", "fy27_mand_section": "Air Superiority"}$$::jsonb, $$The F-35 Joint Strike Fighter (JSF) Program will develop and field an affordable, highly common family of next generation strike aircraft for the United States Air Force, United States Navy, United States Marine Corps and International Partners countries. There are three variants: the F-35A Conventional Takeoff and Landing (CTOL), F-35B Short Take Off and Vertical Landing (STOVL), and the F-35C Carrier Variant (CV). Maximum commonality among the variants, consistent with National Disclosure Policy, will minimize total air system life cycle costs. Planning, systems engineering, development, and testing for Block 4 continues across the F-35 Air Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                            Date: June 2025 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:              PE 0604840F / F-35 C2D2 Operational Systems Development System to include the air vehicle, propulsion system, combat data systems, maintenance systems, and training systems as Initial Operational Capability (IOC) has been met for each variant. The JSF Continuous Capability Development & Delivery (C2D2) efforts provide incremental warfighting capability improvements to maintain joint air dominance against evolving threats. Block 4 capability requirements were initiated through ongoing Service-led operational analysis of warfighting gaps identified in the Fifth Generation Fighter Modernization Initial Capabilities Document (ICD), and through F-35 JSF Block 4 Mission Decomposition analysis completed in FY 2014. These analyses served as the basis for the Block 4 Capability Development Document (CDD), staffed through the Air Force Requirements Oversight Council (AFROC) and signed by the USAF Chief of Staff in January 2015. Joint Requirements Oversight Council (JROC) approved the CDD on 21 March 2017. Modernization activities in FY 2026 continue with the incremental releases of Block 4 capabilities. Block 4 efforts include a robust weapons integration portfolio and provide new opportunities for International Partners to assess, integrate, and field unique capabilities based on global sovereign requirements. The United Kingdom, Italy, Netherlands, Canada, Australia, Denmark and Norway are participants in F-35 modernization. The program shown here reflects United States Air Force funding. Foreign Military Sales are ongoing separately. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY 2024, $79.4M was expended for civilian pay expenses in this project element, and in FY 2025, $66.7M is forecasted for civilian pay expenses in this project element. The FY 2026 request was reduced by $1.7M million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative.” This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                      Date: June 2025 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:              PE 0604840F / F-35 C2D2 Operational Systems Development$$, NULL, 1600572000, 1638243000, 1481482000, NULL, NULL, 153, $$FY26 Air Force Research and Development Test and Evaluation Vol III.pdf$$, NULL, FALSE, 1099328000, 960621000, 1128748000, 1128748000, 939586000, 2068334000, 1298001000, $$The F-35 Joint Strike Fighter (JSF) Program will develop and field an affordable, highly common family of next generation strike aircraft for the United States Air Force, United States Navy, United States Marine Corps and International Partners countries. There are three variants: the F-35A Conventional Takeoff and Landing (CTOL), F-35B Short Take Off and Vertical Landing (STOVL), and the F-35C Carrier Variant (CV). Maximum commonality among the variants, consistent with National Disclosure Policy, will minimize total air system life cycle costs. Planning, systems engineering, development, and testing for Block 4 continues across the F-35 Air Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                            Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:              PE 0604840F / F-35 C2D2 Operational Systems Development System to include the air vehicle, propulsion system, combat data systems, maintenance systems, and training systems as Initial Operational Capability (IOC) has been met for each variant. The JSF Continuous Capability Development & Delivery (C2D2) efforts provide incremental warfighting capability improvements to maintain joint air dominance against evolving threats. Block 4 capability requirements were initiated through ongoing Service-led operational analysis of warfighting gaps identified in the Fifth Generation Fighter Modernization Initial Capabilities Document (ICD), and through F-35 JSF Block 4 Mission Decomposition analysis completed in FY 2014. These analyses served as the basis for the Block 4 Capability Development Document (CDD), staffed through the Air Force Requirements Oversight Council (AFROC) and signed by the USAF Chief of Staff in January 2015. Joint Requirements Oversight Council (JROC) approved the CDD on 21 March 2017. Modernization activities in FY 2027 continue with the incremental releases of Block 4 capabilities. Block 4 efforts include a robust weapons integration portfolio and provide new opportunities for International Partners to assess, integrate, and field unique capabilities based on global sovereign requirements. The United Kingdom, Italy, Netherlands, Canada, Australia, Denmark and Norway are participants in F-35 modernization. The program shown here reflects United States Air Force funding. Foreign Military Sales are ongoing separately. This program element included all necessary expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 0605829F, 0605831F, 0605833F, and 0605898F. Funding allocations at the project level have historically been subject to change due to the complexity of the F-35 budget structure and cost share ratios. The program will ensure any within-PE adjustments during execution year are reflected in future budget submissions. The FY 2027 request for C2D2 F-35A includes $1,128,748 thousand of discretionary and $939,586 thousand of mandatory for a total of $2,068,334 thousand. FY 2027 total funding supports Block 4 capability development and acceleration of Engine & Power Thermal Management delivery timelines. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                    Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:              PE 0604840F / F-35 C2D2 Operational Systems Development$$, $$Budget J-Books/FY27/Remaining/DoW_FY2027_Mandatory_Funding_Overview.txt$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604840M$$, $$F-35B C2D2$$, $$rdte_navy_ba7$$, $$asn_rda$$, 2026, 494034000, 462241000, 480759000, NULL, $${"act": "07", "ba_raw": "6.7", "source": "r1_fy26", "service": "mc", "page_num": 37, "fy27_mand_k": 857241, "original_pe": "0604840M", "page_header": "Department of the Navy", "fy27_mand_v157": "2026-05-08", "fy27_mand_source": "DoW_FY2027_Mandatory_Funding_Overview.txt Appendix B", "fy27_mand_section": "Air Superiority"}$$::jsonb, NULL, NULL, 821248000, 812102000, 736916000, NULL, NULL, NULL, NULL, NULL, FALSE, 465005000, 418084000, 469779000, 469779000, 1476698000, 1946477000, 645196000, $$The F-35 Joint Strike Fighter (JSF) Program will develop and field an affordable, highly common family of next generation strike aircraft for the United States Navy, United States Air Force, United States Marine Corps and International Partners countries. There are three variants the F-35A Conventional Takeoff and Landing variant; F-35B Short Take Off and Vertical Landing; and the F-35C Aircraft Carrier suitable variant. Maximum commonality among the variants, consistent with National Disclosure Policy, will minimize total air system life cycle costs. Planning, systems engineering, development, and testing for Block 4 and additional capabilities as part of the C2D2 acquisition strategy continues across the F-35 Air System to include the air vehicle, propulsion system, combat data systems, maintenance systems, and training systems as Initial Operational Capability (IOC) has been met for each variant. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                                 Date: April 2026 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 7: Operational         PE 0604840M / F-35B C2D2 Systems Development The JSF Continuous Capability Development & Delivery (C2D2) efforts provide incremental warfighting capability improvements to maintain joint air dominance against evolving threats. Block 4 capability requirements were initiated through ongoing Service-led operational analysis of warfighting gaps identified in the Fifth Generation Fighter Modernization Initial Capabilities Document (ICD), and through F-35 JSF Block 4 Mission Decomposition analysis completed in FY2014. These analyses served as the basis for the Block 4 Capability Development Document (CDD), staffed through the Air Force Requirements Oversight Council (AFROC) and signed by the USAF Chief of Staff in January 2015. Joint Requirements Oversight Council (JROC) approved the CDD 21 March 2017. Modernization activities in FY2027 continue with the incremental releases of capabilities & execution of continuous development efforts as part of the C2D2 acquisition strategy. Block 4 efforts include a robust weapons integration portfolio and provide new opportunities for International Partners to assess, integrate, and field unique capabilities based on global sovereign requirements. The United Kingdom, Italy, Netherlands, Canada, Australia, Denmark and Norway are participants in F-35 modernization. The program shown here reflects United States Navy funding. Total funding for all Service and International Partners is reported at the accomplishment/planned program level since activities support all aircraft variants. Foreign Military Sales are ongoing separately. PE 0604840M/N replaced PE 0604810M/N beginning in FY2019 due to budget being moved from BA05 to BA07. Beginning in FY2022, separate, distinct project units were established within the Continuous Capability Development & Delivery (C2D2) Program Element, per Congressional direction, to provide traceability between execution and budget requests. Efforts are continued from initial C2D2 Project Unit 2936. The C2D2 structure and budget submissions mirror the Joint Strike Fighters Program Management Office organizational structure in order to provide more transparency and visibility to development efforts across the F-35 enterprise. JUSTIFICATION FOR BUDGET ACTIVITY: This program is funded under OPERATIONAL SYSTEMS DEVELOPMENT because it includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate funding in the current or subsequent fiscal year. Funding allocations at the project level have historically been subject to change due to the complexity of the F-35 budget structure and cost share ratios. The program will ensure any within-PE adjustments during execution year are reflected in future budget submissions. The FY 2027 request for C2D2 F-35B includes $469,779 thousand of discretionary and $787,779 thousand of mandatory (reconciliation) for a total of $1,257,558 thousand. FY 2027 total funding supports Block 4 capability development and acceleration of Engine & Power Thermal Management delivery timelines. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                        Date: April 2026 Appropriation/Budget Activity                                               R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 7: Operational    PE 0604840M / F-35B C2D2 Systems Development$$, $$Budget J-Books/FY27/Remaining/DoW_FY2027_Mandatory_Funding_Overview.txt$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604840N$$, $$F-35C C2D2$$, $$rdte_navy_ba7$$, $$asn_rda$$, 2026, 475710000, 482795000, 466186000, NULL, $${"act": "07", "ba_raw": "6.7", "source": "r1_fy26", "service": "navy", "page_num": 37, "fy27_mand_k": 619457, "original_pe": "0604840N", "page_header": "Department of the Navy", "fy27_mand_v157": "2026-05-08", "fy27_mand_source": "DoW_FY2027_Mandatory_Funding_Overview.txt Appendix B", "fy27_mand_section": "Air Superiority"}$$::jsonb, NULL, NULL, 799376000, 801911000, 724044000, NULL, NULL, NULL, NULL, NULL, FALSE, 451143000, 401262000, 428545000, 428545000, 0, 428545000, 632837000, $$The F-35 Joint Strike Fighter (JSF) Program will develop and field an affordable, highly common family of next generation strike aircraft for the United States Navy, United States Air Force, United States Marine Corps and International Partners countries. There are three variants the F-35A Conventional Takeoff and Landing variant; F-35B Short Take Off and Vertical Landing; and the F-35C Aircraft Carrier suitable variant. Maximum commonality among the variants, consistent with National Disclosure Policy, will minimize total air system life cycle costs. Planning, systems engineering, development, and testing for Block 4 and additional capabilities as part Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                                 Date: April 2026 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 7: Operational         PE 0604840N / F-35C C2D2 Systems Development of the C2D2 acquisition strategy continues across the F-35 Air System to include the air vehicle, propulsion system, combat data systems, maintenance systems, and training systems as Initial Operational Capability (IOC) has been met for each variant. The JSF Continuous Capability Development & Delivery (C2D2) efforts provide incremental warfighting capability improvements to maintain joint air dominance against evolving threats. Block 4 capability requirements were initiated through ongoing Service-led operational analysis of warfighting gaps identified in the Fifth Generation Fighter Modernization Initial Capabilities Document (ICD), and through F-35 JSF Block 4 Mission Decomposition analysis completed in FY2014. These analyses served as the basis for the Block 4 Capability Development Document (CDD), staffed through the Air Force Requirements Oversight Council (AFROC) and signed by the USAF Chief of Staff in January 2015. Joint Requirements Oversight Council (JROC) approved the CDD 21 March 2017. Modernization activities in FY2027 continue with the incremental releases of capabilities & execution of continuous development efforts as part of the C2D2 acquisition strategy. Block 4 efforts include a robust weapons integration portfolio and provide new opportunities for International Partners to assess, integrate, and field unique capabilities based on global sovereign requirements. The United Kingdom, Italy, Netherlands, Canada, Australia, Denmark and Norway are participants in F-35 modernization. The program shown here reflects United States Navy funding. Total funding for all Service and International Partners is reported at the accomplishment/planned program level since activities support all aircraft variants. Foreign Military Sales are ongoing separately. PE 0604840M/N replaced PE 0604810M/N beginning in FY2019 due to budget being moved from BA05 to BA07. Beginning in FY2022, separate, distinct project units were established within the Continuous Capability Development & Delivery (C2D2) Program Element, per Congressional direction, to provide traceability between execution and budget requests. Efforts are continued from initial C2D2 Project Unit 2936. The C2D2 structure and budget submissions mirror the Joint Strike Fighters Program Management Office organizational structure in order to provide more transparency and visibility to development efforts across the F-35 enterprise. JUSTIFICATION FOR BUDGET ACTIVITY: This program is funded under OPERATIONAL SYSTEMS DEVELOPMENT because it includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate funding in the current or subsequent fiscal year. Funding allocations at the project level have historically been subject to change due to the complexity of the F-35 budget structure and cost share ratios. The program will ensure any within-PE adjustments during execution year are reflected in future budget submissions. The FY 2027 request for C2D2 F-35C includes $428,545 thousand of discretionary and $688,919 thousand of mandatory (reconciliation) for a total of $1,117,464 thousand. FY 2027 total funding supports Block 4 capability development and acceleration of Engine & Power Thermal Management delivery timelines. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                            Date: April 2026 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 7: Operational      PE 0604840N / F-35C C2D2 Systems Development$$, $$Budget J-Books/FY27/Remaining/DoW_FY2027_Mandatory_Funding_Overview.txt$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604850N$$, $$SSN(X)$$, $$rdte_navy_ba5$$, $$asn_rda$$, 2026, 365987000, 313444000, 333788000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "navy", "page_num": 34, "original_pe": "0604850N", "page_header": "Department of the Navy"}$$::jsonb, $$The U.S. Navy must protect the security of the American people by defending against great powers, regional adversaries, and transnational threats. Near peer adversaries are increasing the demand on the U.S. Navy submarine force. The 2025 Interim National Defense Strategy directs the DoD to deter aggression by China in the Indo-Pacific reiterating the need for attack submarines in the pacing scenario. The U.S. Navy must meet the rising challenge by delivering a new attack submarine. SSN(X) will significantly contribute to rebuilding our military, reinforcing deterrence in the undersea, and building lethality in the Joint Force. It will provide greater speed, increased horizontal payload capacity, improved signatures, higher operational availability, and flexibility to adapt to uncertain future threats. SSN(X) will conduct full spectrum undersea warfare and employ and coordinate with a larger contingent of off-hull remote autonomous systems (RAS) and sensors as a force multiplier. It will retain and improve multi-mission (Anti-Surface Warfare (ASuW), Anti-Submarine Warfare (ASW), Subsea Seabed Warfare (SSW), Strike, Special Operating Forces (SOF), Mine, and Intelligence, Surveillance and Reconnaissance (ISR)) capability and sustained combat presence in denied waters. SSN(X) will operate independently or be integrated within a Task Force. The formal acquisition strategy for SSN(X) is being developed and will be informed by requirements post the Analysis of Alternatives (AoA). Preliminary Design for SSN(X) will be accomplished through a collaborative Navy-Industry effort to maximize the benefits of industry and the potential shipbuilders. The SSN(X) program initiated the AoA in FY 2024 to determine the preferred capability solution. The approved Material Development Decision (MDD) designated the SSN(X) a pre-Major Defense Acquisition Program (MDAP), Acquistion Category (ACAT) IB in FY 2025. PB26 provides the required technology development efforts and ramp to support Lead Ship Authorization as early as 2040. FY 2025 focused on technology development efforts started in FY 2024 and completion of the AoA. The SSN(X) program completed the Digital Engineering Strategy to establish the tailored implementation of digital engineering practices across the acquisition life cycle. The SSN(X) program aligns with the Virginia Class Block VIII efforts to support maintaining the design base for SSN(X) as well as provide risk reduction for technology development. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Navy                                                                             Date: June 2025 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 5: System              PE 0604850N / SSN(X) Development & Demonstration (SDD) FY 2026 will be focused on supporting the Office of the Secretary of Defense's Cost Assessment and Program Evaluation (OSD CAPE) sufficiency review of the AoA, continued technology efforts, and concept refinement to inform requirements. Targeted technology development with Virginia Class Block VIII will continue to reduce risk. SSN(X) will incorporate the best practices and lessons learned from the Virginia Class. FY 2026 funding levels support continued shipbuilder design studies, concept/technology development, completing Gate 2, and initial Capability Development Document (CDD) development.$$, NULL, 308424000, 366060000, 402907000, NULL, NULL, 159, $$RDTEN_BA5_Book.pdf$$, NULL, FALSE, 327385000, 335987000, 315914000, 315914000, NULL, 315914000, 410276000, $$The National Defense Strategy (NDS) requires the United States to have the most lethal and capable military in the world. The U.S. Navy must meet the rising challenge by delivering a new attack submarine to maintain superiority in the undersea domain. SSN(X) will significantly contribute to rebuilding our military, reinforcing deterrence in the undersea, and building lethality in the Joint Force. It will provide enhanced lethality, survivability, speed and operational availability to maintain undersea supremacy against growing threats. SSN(X) will conduct full spectrum undersea warfare and employ and coordinate with Robotic and Autonomous Systems (RAS) and sensors as a force multiplier. It will retain and improve multi-mission (Anti-Surface Warfare (ASuW), Anti-Submarine Warfare (ASW), Subsea Seabed Warfare (SSW), Strike, Special Operating Forces (SOF), Mine, and Intelligence, Surveillance and Reconnaissance (ISR)) capability and sustained combat presence in denied waters. SSN(X) will operate independently or be integrated within a Task Force. The formal acquisition strategy for SSN(X) will be drafted following Milestone A. The approved Material Development Decision (MDD) designated the SSN(X) a pre- Major Defense Acquisition Program (MDAP), Acquisition Category (ACAT) IB in FY 2025. Preliminary Design for SSN(X) will be accomplished through a proven, collaborative Navy-Industry effort to maximize the benefits of industry and the potential shipbuilders. The Future Attack Submarine Analysis of Alternatives (AoA) concluded in November 2025 and determined a clean sheet design is required to respond to the high-end threat. FY 2027 budget will help deliver increased warfighting performance through larger payload volume, improved lethality and survivability, and organic hosting RAS for Lead Ship Authorization as early as 2040. FY 2026 completed the AoA, which was extended due to additional analysis efforts; continued technology development efforts; and shipbuilder design studies. Targeted technology development with Virginia Class Block VII and VIII will continue to reduce risk. SSN(X) will incorporate the best practices and lessons learned from the VIRGINIA Class. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                                 Date: April 2026 Appropriation/Budget Activity                                                         R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 5: System                   PE 0604850N / SSN(X) Development & Demonstration (SDD) FY 2027 will drive warfighting capabilities improvements highlighted in AoA for design development and long-lead time technologies maturation (lethality, survivability, autonomous system integration, etc.), Capability Development Document (CDD) development, and Ship Specification development. Continued common technology development with Virginia Class Block VII and VIII to reduce risk for lead ship SSN(X). FY2027 supports executing the R&D plan Revision 2, continued shipbuilder concepts, prototyping, modifications to existing test facilities, and preparing all required acquisition documentation.$$, $$Budget J-Books/FY27/Navy/RDTEN_BA5_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604852A$$, $$Suite of Survivability Enhancement Systems - EMD$$, $$rdte_army_ba5$$, $$peo_gcs$$, 2026, 76903000, 70384000, 77864000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "army", "page_num": 17, "original_pe": "0604852A", "page_header": "Department of the Army"}$$::jsonb, $$This funding line is a key enabler of the Army Modernization Priorities in support of the Vehicle Protection Suite (VPS) program. Current ground combat vehicle platforms and tactical wheeled vehicles lack the ability to effectively detect, track, divert, disrupt, neutralize, or destroy incoming direct or indirect fired threat munitions. Current solutions to defeat these threats, Explosive Reactive Armor (ERA) and Slat armor, do not provide preemptive or active protection and impose secondary blast hazards to crew, dismounted soldiers, and adjacent vehicles and equipment. The Suite of Vehicle Protection Systems will develop, mature and integrate solutions onto multiple ground combat vehicles and tactical vehicles to increase the protection of the Army's ground systems from both current and next generation direct or indirect fired threat munitions. The Vehicle Protection Suite (VPS) Project (FE8) will design, mature, integrate, evaluate and field combinations of active, reactive, and passive protection capabilities and leverage both Horizontal Technology Integration (HTI) principles and the Modular Open System Architecture with the Army's Vehicle Protection System Base Kit (VBK) to develop tailored vehicle Survivability Sets specific to platforms that will mitigate existing protection gaps, allow for future technology insertion to mitigate and defeat evolving threats, and minimize the impact to the current capabilities hosted on Army ground combat and tactical vehicles. The protection capabilities will leverage technologies across a spectrum of survivability mechanisms including detection avoidance, threat detection, threat intercept and threat mitigation. The FY 2026 request was reduced by $0.183 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative."$$, NULL, 79275000, 79935000, 79463000, NULL, NULL, 128, $$RDTE - Vol 3 - Budget Activity 5C.pdf$$, NULL, FALSE, 75022000, 75180000, 78331000, 78331000, NULL, 78331000, 80259000, $$Current ground combat vehicle platforms and tactical wheeled vehicles lack the ability to effectively detect, track, divert, disrupt, neutralize, or destroy incoming direct or indirect fired threat munitions. Current solutions to defeat these threats, Explosive Reactive Armor (ERA) and Slat armor, do not provide preemptive or active protection and impose secondary blast hazards to crew, dismounted soldiers, and adjacent vehicles and equipment. The Suite of Vehicle Protection Systems will develop, mature and integrate solutions onto multiple ground combat vehicles and tactical vehicles to increase the protection of the Army's ground systems from both current and next generation direct or indirect fired threat munitions. The Vehicle Protection Suite (VPS) Project (FE8) will design, mature, integrate, update, evaluate and field combinations of active, reactive, and passive protection capabilities. VPS leverage both Horizontal Technology Integration (HTI) principles and the Modular Open System Architecture (MOSA) with the Army's Vehicle Protection System Base Kit (VBK) and VPS Intelligent Protection Engagement Response Software (VIPERS) to develop tailored vehicle Survivability Sets specific to platforms. VPS Survivability Sets will mitigate existing protection gaps and allow for rapid future technology insertion that mitigates and defeats evolving threats while minimizing the impact to the current capabilities hosted on Army ground combat and tactical vehicles. The protection capabilities will leverage technologies across a spectrum of survivability mechanisms including detection avoidance, threat detection, threat intercept and threat mitigation. The total cost of the Soft Kill Active Protection System (APS) Middle Tier of Acquisition effort is $134.28 million RDT&E from FY25 to FY28, which is a subset of the Project FE8 Vehicle Protection Suite funding.$$, $$Budget J-Books/FY27/Army/RDTEVol3BudgetActivity5C.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604854A$$, $$Artillery Systems - EMD$$, $$rdte_army_ba5$$, $$peo_gcs$$, 2026, 80862000, 45939000, 42479000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "army", "page_num": 17, "original_pe": "0604854A", "page_header": "Department of the Army"}$$::jsonb, $$This program element encompasses engineering and manufacturing development for artillery weapons systems. Project 516 is to modernize the field artillery to address obsolesce, improve performance and address emerging threats. The Self-Propelled Howitzer is an indirect fire weapon system with the ability of delivering accurate, long range, lethal and non-lethal cannon fires in support of both Combined Arms Maneuver (CAM) and Wide Area Security (WAS) operations. The Self-Propelled Howitzer and Ammunition Resupply Vehicle can be employed within any Brigade Combat Team formation to neutralize, suppress, or destroy enemy forces, while providing protected transport of a field artillery howitzer section on the modern battlefield. This effort will include system usage and optimization studies, simulations, development engineering, Line Replacement Unit (LRU) prototype development and procurement and validation for incremental upgrades of field artillery. Project DH7 supports the Howitzer Modernization. The US Army modernized howitzer will provide highly mobile, survivable, versatile, transportable, long range, lethal fires in support of Army Transformation Initiative. This project supports the Mobile Tactical Cannon Directed Requirement (MTC-DR) to provide an enhanced capability reducing emplacement and displacement times, increasing crew survivability and protection, providing greater mobility, and affords improved fire support capability for Field Artillery formations well beyond the capability of the current howitzer systems. Fiscal Year (FY) 2026 funding supports the enhancements, integration, and testing of system of systems to include, but not limited to, artillery weapon system, ammunition, and fire control systems to achieve desired firing range and lethal fires effects on targets, as necessary for Artillery unit operations. Project HB6 supports the mobile howitzer program. The Mobile 155mm Howitzer is a Self-Propelled, 155mm Wheeled Howitzer that provides lethal, proactive counter- fire essential for the survivability of the maneuver formations and other close support fires as required. The Mobile Howitzer improves the Field Artillery Battalion's ability to maintain pace with its supporting maneuver formations and survive against responsive, counter-fire from near-peer threats with rapid displacement and emplacement times. The mobile howitzer will improve tactical mobility and system survivability compared to existing towed howitzer systems. Development efforts, prototyping and evaluations will focus on attributes such as improved emplacement and displacement times, driving speed, and crew protection capabilities, all without sacrificing lethality versus existing towed howitzer systems. Program activities focused on evaluation of multiple vendor mobile howitzer systems at United States proving grounds against system requirements. Evaluation will include safety testing, US ammunition compatibility testing, and assessment of mobility, survivability and transportability. Artillery Systems - EMD is part of the Army Transformation Initiative. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                          Date: June 2025 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 5: System          PE 0604854A / Artillery Systems - EMD Development & Demonstration (SDD)$$, NULL, 161898000, 82554000, 110549000, NULL, NULL, 129, $$RDTE - Vol 3 - Budget Activity 5C.pdf$$, NULL, FALSE, 40929000, 76767000, 709192000, 709192000, NULL, 709192000, 111652000, $$This program element encompasses engineering and manufacturing development for artillery weapons systems. Project 516 is to modernize the field artillery to address obsolesce, improve performance and address emerging threats. The Self-Propelled Howitzer is an indirect fire weapon system with the ability of delivering accurate, long range, lethal and non-lethal cannon fires in support of both Combined Arms Maneuver (CAM) and Wide Area Security (WAS) operations. The Self-Propelled Howitzer and Ammunition Resupply Vehicle can be employed within any Brigade Combat Team formation to neutralize, suppress, or destroy enemy forces, while providing protected transport of a field artillery howitzer section on the modern battlefield. This effort will include system usage and optimization studies, simulations, development engineering, Line Replacement Unit (LRU) prototype development and procurement and validation for incremental upgrades of field artillery. Project DH7 supports howitzer efforts required to achieve highly mobile, survivable, versatile, transportable, long range, lethal fires in support of the Army's Field Artillery modernization objectives. These critical development efforts provide an enhanced capability reducing emplacement and displacement times, increasing crew survivability and protection, providing greater mobility, and affords improved fire support capability for Field Artillery formations well beyond the capability of the current howitzer systems. Fiscal Year (FY) 2027 funding will continue to support the enhancements, integration, and testing of system of systems to include, but not limited to, artillery weapon system, ammunition, and fire control systems required to achieve desired firing range and lethal fires effects on targets, as necessary for Artillery unit operations. Project DP3 supports the mission of the Mobile Tactical Cannon (MTC) program which is to acquire an improved, mature, and available self-propelled artillery system and associated Resupply Vehicle (RSV) to replace legacy artillery systems. These systems will enable artillery formations to shape the deep fight and dominate the close fight during Multi-Domain Operations. Collectively, the MTC and RSV will provide a decisive advantage by delivering massed lethal effects at extended ranges with increased rates of fire, enhanced mobility, reduced mission cycle and resupply times, and provide a high level of survivability on the modern battlefield. To respond to current and emerging threats, these systems will have margin for growth and be able to integrate current and future technologies, such as, but not limited to counter-small unmanned arial system capabilities, armament and mobility enhancements, human-machine and human-factors modifications, partial-to-fully automated ammunition handling, and partial-to-full autonomy for the MTC and RSV. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                             Date: April 2026 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 5: System           PE 0604854A / Artillery Systems - EMD Development & Demonstration (SDD)$$, $$Budget J-Books/FY27/Army/RDTEVol3BudgetActivity5C.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604858F$$, $$Tech Transition Program$$, $$rdte_af_ba4$$, $$dw_osd$$, 2026, 298833000, 232375000, 239342000, NULL, $${"ba_raw": "6.4", "source": "af_r1_fy26", "original_pe": "0604858F"}$$::jsonb, $$Capability development provides the analytic, technical, and programmatic rigor necessary to address capability gaps and opportunities to refine and mature future programs of record, prioritizing and accelerating transition of capabilities in collaboration with operational stakeholders. The Capability Development Enterprise is focused on maturing and transitioning high-impact warfighting capabilities aligned to Air Force Future Force Design through robust capability development. The Tech Transition Program addresses the gap between initial system-level technology or concept development and demonstration, and successful acquisition and operational capability implementation. The Tech Transition Program matures new warfighting concepts, rapidly develops fieldable prototypes, and performs operational experimentation to assess military utility innovative concepts. This program utilizes multiple approaches and integrated activities to field technology for the warfighter focusing on efforts that are directly tied the USAF Force Design and OSD's Joint Warfighting Concept. The Tech Transition Program allows acquisition program managers (the capability developers) and warfighters (the capability recipients and end users) to prototype, integrate, and demonstrate candidate technologies and assess them in an operational system of systems environment in partnership with ICC, Warfighter & Combatant Commanders, Major and Field Commands, Program Executive Officers, schoolhouses, simulation facilities, and development planning organizations. Operational experimentation activities explore new concepts and their applications in relevant operating environments within a system-of-systems context taking risks early in the acquisition process to drive optimized and efficient acquisition approach warfighter capability delivery to fully assess operationalization requirements, to include but not limited to suitability, supportability, maintainability, and logistics. Prototyping enables integration and demonstration of emerging technologies to quickly move them into warfighting capability, allowing for iterative development and increased use of commercial technology. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                           Date: June 2025 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 4: Advanced PE 0604858F / Tech Transition Program Component Development & Prototypes (ACD&P) Tech Maturation and Risk Reduction/Development competitively assesses commercial solutions to identify transitionable system components for rapid insertion and delivery. Architecture Design and Evaluation is executed by the Department of the Air Force (DAF) Program Executive Office (PEO), and Command, Control, Communications and Battle Management (C3BM) with oversight by the Secretary of the Air Force along with the Chief of Staff of the Air Force, Chief of Space Operations, and Senior Acquisition Executive. This activity is supported by the Air Force Research Laboratory. The rapidly evolving technology landscape requires this program to pivot technical areas and solutions as requirements and the warfighting and resource environments change. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605829F, 0605831F, 0605833F, or 0605898F. The FY 2026 request for the Tech Transition Program includes $134.833 million of discretionary and $164.000 million of mandatory (reconciliation) for a total of $298.833 million. The mandatory funds focuses efforts on low-cost munitions and supply chain. This effort is in Budget Activity 4, Advanced Component Development and Prototypes (ACD&P), because efforts are necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment.$$, NULL, 225117000, 195388000, 208221000, NULL, NULL, 59, $$FY26 Air Force Research and Development Test and Evaluation Vol II.pdf$$, NULL, FALSE, 246279000, 159756000, 166061000, 166061000, 0, 166061000, 227659000, $$Capability development provides the analytic, technical, and programmatic rigor necessary to address operational gaps and opportunities to refine and mature future programs of record, prioritizing and accelerating transition of capabilities in collaboration with operational stakeholders. The Capability Development Enterprise is focused on maturing and transitioning high-impact warfighting capabilities aligned to Air Force Future Force Design through robust concept development, prototyping, and experimentation. The Tech Transition Program addresses the gap between initial system-level technology or concept development and demonstration, and successful acquisition and operational capability implementation. The Tech Transition Program matures new warfighting concepts, rapidly develops fieldable prototypes, and performs experimentation to assess military utility, innovative concepts, and weapon systems with potential for transition. This program utilizes multiple approaches and integrated activities to field technology for the warfighter focusing on efforts that are directly tied to the Air Force Force Design and Joint Warfighting Concept. The Tech Transition Program allows acquisition program managers (the capability developers) and warfighters (the capability recipients and end users) to prototype, integrate, experiment, and demonstrate candidate technologies to assess them in an operational system of systems environment in partnership with the warfighter, Combatant Commanders, Major and Field Commands, Portfolio Acquisition Executives (PAEs), schoolhouses, simulation facilities, and development planning organizations. Experimentation activities explore new concepts and their applications in relevant operating environments within a system-of-systems context taking risks early in the acquisition process to drive optimized and efficient acquisition approach in support of technology transition to deliver capabilities to the warfighter. This includes, but is not limited to, suitability, supportability, maintainability, and logistics necessary to employ and sustain those capabilities. In addition to traditional hardware and software, high-impact capabilities could include autonomy and Artificial Intelligence technologies that are stand-alone or embedded into existing systems. They could also include broad enablers such as open architectures, digital infrastructure, test infrastructure, or simulation environments. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                              Date: April 2026 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 4: Advanced PE 0604858F / Tech Transition Program Component Development & Prototypes (ACD&P) Prototyping enables integration and demonstration of emerging technologies to quickly move them into warfighting capability, allowing for iterative development and increased use of the latest technology, including commercial. Tech Maturation and Risk Reduction/Development competitively assess commercial solutions to identify system components for rapid insertion and delivery. Architecture Design and Evaluation is executed by the Department of the Air Force (DAF) PAE for Command, Control, Communications and Battle Management (C3BM) with oversight by the Secretary of the Air Force along with the Chief of Staff of the Air Force, Chief of Space Operations, and Senior Acquisition Executive. This activity is supported by the Air Force Research Laboratory. The rapidly evolving technology landscape requires this program to remain flexible across multiple technology areas and solution spaces as requirements and the warfighting and resource environments change. The FY 2026 spend plan amount for Research, Development, Testing and Evaluation includes $159,756 thousand of discretionary and $296,000 thousand of mandatory (reconciliation) for a total of $455,756 thousand in support of Family of Affordable Mass Missiles (FAMM), Enterprise Test Vehicle (ETV), and Palletized Effects. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605829F, 0605831F, 0605833F, or 0605898F. In FY 2027, 8.503 million is budgeted for this program for 41 direct Full Time Equivalent civilians. This effort is in Budget Activity 4, Advanced Component Development and Prototypes (ACD&P), because efforts are necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment.$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume II.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604860F$$, $$Operational Energy and Installation Resilience$$, $$rdte_af_ba4$$, $$aflcmc$$, 2026, 49460000, 23270000, 25395000, NULL, $${"ba_raw": "6.4", "source": "af_r1_fy26", "original_pe": "0604860F"}$$::jsonb, $$The Operational Energy and Installation Resilience program develops, matures, prototypes, demonstrates, and assesses technologies, software, and processes for decreasing operational energy risk and increasing installation resilience. Energy is a cross-cutting pervasive need across every weapon system, platform, installation, and austere operating location. The objective of this program is to prioritize, validate performance in a relevant environment, and facilitate implementation of the validated solutions that increase weapon system and platform capabilities (range, endurance, number of sorties refueled, etc.), mitigate supply chain risk, and enhance resilience of supporting infrastructure for increased readiness and lethality. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY 2024 $0.688 million was expended for civilian pay expenses in this program element, and in FY 2025 $0.790 million is forecasted for civilian pay expenses in this program element. This effort is in Budget Activity 4, Advanced Component Development and Prototypes (ACD&P), because efforts are necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                       Date: June 2025 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 4: Advanced PE 0604860F / Operational Energy and Installation Resilience Component Development & Prototypes (ACD&P)$$, NULL, 59000000, 60000000, 60000000, NULL, NULL, 60, $$FY26 Air Force Research and Development Test and Evaluation Vol II.pdf$$, NULL, FALSE, 24597000, 81419000, 61000000, 61000000, 0, 61000000, 60000000, $$The Operational Energy and Installation Resilience program develops, matures, prototypes, demonstrates, and assesses technologies, software, and processes to create an energy-optimized force that maximizes combat capability in response to Department of the Air Force warfighters needs. Energy is a cross-cutting pervasive need across every weapon system, platform, installation, and austere operating location. The Operational Energy projects conduct the necessary prototyping and technology validation to increase weapon system range and time on station, reduce tanker dependency, optimize mobility air force utilization, maximize force projection with available fuel, and mitigate supply chain risk to provide increased readiness and lethality. The Installation Resilience projects conduct the necessary prototyping and technology validation to ensure energy availability sufficient to provide for mission assurance by developing cybersecure power generation capabilities (including advanced nuclear and alternative energy sources) and improving the control and distribution to critical assets; provides both fixed installation mission assurance and maximizes agile combat effectiveness with limited resources. This program element included all necessary expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 0605829F, 0605831F, 0605833F, and 0605898F. The FY 2026 spend plan amount for Operational Energy includes $34,909 thousand of discretionary and $102,000 thousand of mandatory (reconciliation) for a total of $136,909 thousand. The FY 2026 funding request was reduced by 1.428 million to account for the availability of prior year execution balances. This effort is in Budget Activity 4, Advanced Component Development and Prototypes (ACD&P), because efforts are necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                        Date: April 2026 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 4: Advanced PE 0604860F / Operational Energy and Installation Resilience Component Development & Prototypes (ACD&P)$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume II.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604873C$$, $$Long Range Discrimination Radar (LRDR)$$, $$rdte_dw_ba4$$, $$dw_mda$$, 2026, 60443000, 99943000, 98183000, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "dw", "page_num": 73, "original_pe": "0604873C", "page_header": "Defense-Wide"}$$::jsonb, $$The Long Range Discrimination Radar (LRDR) program is a crucial component of the Missile Defense Agency (MDA) mission, playing a significant role in the development and deployment of a layered Missile Defense System. This system is designed to defend the homeland from missile attacks of all ranges, in all phases of flight. The LRDR's contribution provides persistent long-range midcourse discrimination, precision tracking and hit assessment, thereby enhancing the Missile Defense System Homeland Defense Capability. Additionally, the LRDR program supports the United States Space Force's (USSF) Space Domain Awareness (SDA) and Space Object Identification (SOI) mission area, further underlining its importance. The LRDR Program Element includes the requirements to design, develop, integrate, deliver, field, and sustain the LRDR. The LRDR operates in the S-band frequency with a scalable and open systems architecture to mitigate evolving threats and integrates into the Missile Defense System through the Command and Control, Battle Management, and Communications system. This Program Element includes Missile Defense System threat discrimination improvements to enhance effectiveness against the evolving threat environment. The result will be a Missile Defense System architecture more capable of discriminating against and interpreting re-entry vehicles with a higher degree of confidence to improve the warfighter engagement doctrine, and conserve ground-based interceptor inventory. The LRDR comprises an equipment shelter, two radar array faces, a mission control facility for radar operations, and supporting facilities and infrastructure. The Secretary of the Air Force approved Clear Space Force Station, formerly known as Clear Air Force Station, AK, as the LRDR site. The USSF Space Operations Command is the designated Lead Major Command. The initial fielding of LRDR was completed on December 6, 2021. MDA pursued an incremental fielding approach in cooperation with the United States Northern Command, the United States Space Command, and the USSF. The early use fielding of the LRDR SDA capability occurred on March 27, 2024. LRDR was added to the Missile Defense System Operational Capability List (OCL) for SDA on December 20, 2024. LRDR homeland defense is planned to be incorporated into the OCL in 3Q FY 2025. The LRDR Program Element also supports the fielding of the LRDR capabilities described below: - The LRDR capability that will be added to the Missile Defense System in 2026 includes software upgrades to LRDR to improve bias monitoring and reporting, increased discrimination capability that is expanded to a broader spectrum of threats and Resident Space Object scenes, increased support to the SDA/SOI mission Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Missile Defense Agency                                                               Date: June 2025 Appropriation/Budget Activity                                                       R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 4:                PE 0604873C / Long Range Discrimination Radar (LRDR) Advanced Component Development & Prototypes (ACD&P) with additional reporting, expanded threat loading and threat type including addition of hypersonic threat requirements, cybersecurity upgrades, reliability upgrades, cost reduction initiatives to reduce life cycle operating costs, and characterization testing and improvements to Electronic Protection capability. - Further LRDR capability additions include software upgrades to LRDR to improve its capabilities against advanced threats.$$, NULL, 208030000, 204057000, 182764000, NULL, NULL, 122, $$RDTE_Vol2_MDA_RDTE_PB26_Justification_Book.pdf$$, $$MDA$$, FALSE, 95584000, 55856000, 125074000, 125074000, NULL, 125074000, 144929000, $$The LRDR program is a crucial component of the Missile Defense Agency (MDA) mission, playing a significant role in the development and deployment of a layered Missile Defense System. This system is designed to defend the homeland from missile attacks of all ranges, in all phases of flight. The LRDR's contribution provides persistent long-range midcourse discrimination, precision tracking and hit assessment, thereby enhancing the Missile Defense System Homeland Defense Capability. Additionally, the LRDR program supports the United States Space Force's (USSF) Space Domain Awareness (SDA) and Space Object Identification (SOI) mission area, further underlining its importance. The LRDR Program Element includes the requirements to design, develop, integrate, deliver, field, and sustain the LRDR. The LRDR operates in the S-band frequency with a scalable and open systems architecture to mitigate evolving threats and integrates into the Missile Defense System through the Command and Control, Battle Management, and Communications (C2BMC) system. This Program Element includes Missile Defense System threat discrimination improvements to enhance effectiveness against the evolving threat environment. The result will be a Missile Defense System architecture more capable of discriminating against and interpreting re-entry vehicles with a higher degree of confidence to improve the warfighter engagement doctrine, and conserve ground-based interceptor inventory. The LRDR comprises an equipment shelter, two radar array faces, a mission control facility for radar operations, and supporting facilities and infrastructure. The Secretary of the Air Force approved Clear Space Force Station, formerly known as Clear Air Force Station, AK, as the LRDR site. The USSF Space Operations Command is the designated Lead Major Command. The initial fielding of LRDR was completed on December 6, 2021. MDA pursued an incremental fielding approach in cooperation with the United States Northern Command, the United States Space Command, and the USSF. The early use fielding of the LRDR SDA capability occurred on March 27, 2024. LRDR was added to the Missile Defense System Operational Capability List (OCL) for SDA on December 20, 2024. LRDR Homeland Defense capability was added to the OCL Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Missile Defense Agency                                                               Date: April 2026 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 4:         PE 0604873C / Long Range Discrimination Radar (LRDR) Advanced Component Development & Prototypes (ACD&P) on May 29, 2025. Operational Acceptance by the USSF is scheduled for fiscal year (FY) 2026 following the completion of the LRDR Homeland Defense trial period and the operational Flight Test Other (FTX)-26a. The LRDR Program Element also supports the fielding of the LRDR capabilities described below: - The LRDR capability that was added to the Missile Defense System OCL on May 29, 2025 increased system raid handling capability, conventional and advanced discrimination capabilities, implementation of mitigation techniques in denied environments, Missile Defense System integration and remote ops via C2BMC, including cyber protection/interoperability, autonomous and cued acquisition capabilities, initial sensor bias reporting, inherent SDA capability, and EP capabilities. - The LRDR capability that will be added to the Missile Defense System in 2026 includes software upgrades to LRDR to improve bias monitoring and reporting, increased discrimination capability that is expanded to a broader spectrum of threats and Resident Space Object scenes, increased support to the SDA/SOI mission with additional reporting, expanded threat loading and threat type including addition of hypersonic threat requirements, cybersecurity upgrades, reliability upgrades, cost reduction initiatives to reduce life cycle operating costs, and characterization testing and improvements to EP capability. - Further LRDR capability additions include software and hardware upgrades to LRDR to improve its capabilities against advanced threats. The funds requested in this PE provide both legacy and Global Missile Defense Capability development for the United States, its deployed forces, allies, and partners. The capabilities funded by this budget request are complementary to the architecture funded by the Golden Dome Program's separate budget request and together fulfill the President's Executive Order 14186. The President's January 27, 2025, Executive Order established a goal of protecting the U.S. citizens, safeguarding critical infrastructure, and securing second-strike capability against missile attack from any adversary. This program and budget in addition to the budget requested by the Golden Dome Program Office reflects the changes necessary to protect the U.S. against ballistic, hypersonic, cruise, and other advanced missile threats.$$, $$Budget J-Books/FY27/Remaining/RDTE_Vol2_MDA_RDTE_PB27_Justification_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604875D8Z$$, $$Joint Systems Architecture Development$$, $$rdte_dw_ba6$$, $$dw_ousd_as$$, 2026, 8627000, 8155000, 9690000, NULL, $${"act": "06", "ba_raw": "6.6", "source": "r1_fy26", "service": "dw", "page_num": 75, "original_pe": "0604875D8Z", "page_header": "Defense-Wide"}$$::jsonb, $$The Joint Systems Architecture Development (JSAD) program element supports the Office of the Under Secretary of Defense, Acquisition and Sustainment (OUSD A&S), Office of the Deputy Under Secretary Defense Platform Weapons and Portfolio Management (DASD PWPM) mission to use Capability Portfolio Management (CPM) to analyze, manage, and inform acquisition and resourcing decisions in platform and weapon portfolios, to include air, surface, electronic, and cyber warfare systems. The program is broken up into two focus areas: Portfolio Systems Acquisition (PSA), supporting air, land, sea, and undersea warfare programs and munitions; and Electromagnetic Warfare (EW), supporting the statutory responsibilities of the EXCOM. All efforts DASD PWPM strive to deliver the warfighter the best equipment and systems, and to do so by performing top down, national security strategy-driven, capabilities-based planning by fully leveraging Department and acquisition reform initiatives. The JSAD program enables collaborative efforts to achieve these goals with a focus on Major Defense Acquisition Programs (MDAPs) and integrated acquisition portfolio management. These efforts entail integrated roadmaps to support acquisition investment decisions, and assessments of MDAPs and other linchpin acquisition efforts in a capability area context. Activities in the JSAD project are focused on three areas:(1) integrated acquisition portfolio analysis; (2) acquisition roadmaps; and (3) acquisition decision support. These efforts guide the development and fielding of integrated acquisition systems in order to achieve Joint mission capabilities across the operational domain to defend against any global threats. The Department uses enterprise-wide approaches which include:(1) horizontal integration within the Department and unity of effort through greater interagency collaboration; (2) engaging in a coordinated and portfolio-based approach to planning, programming, budgeting and execution; and (3) significant reforms at the governance, management and execution levels. To accomplish this intent, there needs to be a focused goal and concerted emphasis on shifting from systems acquisition to portfolio systems acquisition. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Office of the Secretary Of Defense                                             Date: June 2025 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 6:          PE 0604875D8Z / Joint Systems Architecture Development RDT&E Management Support$$, NULL, 11295000, 11479000, 11663000, NULL, NULL, 166, $$RDTE_OSD_PB_2026.pdf$$, $$OSD$$, FALSE, 9371000, 8510000, 11094000, 11094000, NULL, 11094000, 11837000, $$This program supports the Department's initiatives to Restoring Warrior Ethos, Rebuilding Military Capabilities and Re-establishing Deterrence. The Joint Systems Architecture Development (JSAD) program element supports the Office of the Under Secretary of War, Acquisition and Sustainment (OUSW (A&S)), Office of the Deputy Under Secretary of War for Platform and Weapon Portfolio Management (DASW PWPM) mission to use Capability Portfolio Management (CPM) to analyze, manage, and inform acquisition and resourcing decisions in platform and weapon portfolios, to include air, surface, electronic, and cyber warfare systems. The program is broken up into two focus areas: Portfolio Systems Acquisition (PSA), supporting air, land, sea, and undersea warfare portfolios, programs, and associated munitions, including munitions acceleration efforts in support of the Deputy Secretary-chaired Munitions Acceleration Council, and Electromagnetic Warfare (EW), supporting the statutory responsibilities of the EXCOM. All efforts support DASW PWPM’s goal to deliver the best equipment and systems to the warfighter, and to do so by performing top down, national security strategy- driven, capabilities-based acquisition planning by fully leveraging Department and acquisition transformation initiatives. The JSAD program enables collaborative efforts to achieve these goals with a focus on Major Defense Acquisition Programs (MDAPs) and integrated acquisition portfolio management. These efforts entail integrated roadmaps to support acquisition investment decisions, and assessments of MDAPs and other linchpin acquisition efforts in a capability area context. Such activities in the JSAD project are focused on three areas:(1) integrated acquisition portfolio analysis; (2) acquisition roadmaps; and (3) acquisition decision support. These efforts guide the development and fielding of integrated acquisition systems in order to achieve Joint mission capabilities across the operational domain to defend against global threats. The Department uses enterprise-wide approaches which include:(1) horizontal integration within the Department and unity of effort through greater interagency collaboration; (2) engaging in a coordinated and portfolio-based approach to planning, programming, budgeting and execution; and (3) implementation of significant Department reforms at the governance, management and execution levels. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Office of the Secretary Of Defense                                            Date: April 2026 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 6:         PE 0604875D8Z / Joint Systems Architecture Development RDT&E Management Support$$, $$Budget J-Books/FY27/DW/RDTE_OSW_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604876C$$, $$Ballistic Missile Defense Terminal Defense Segment Test$$, $$rdte_dw_ba4$$, $$dw_mda$$, 2026, 37784000, 16708000, 25673000, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "dw", "page_num": 73, "original_pe": "0604876C", "page_header": "Defense-Wide"}$$::jsonb, $$Ballistic Missile Defense Terminal Defense Segment Test provides the Terminal High Altitude Area Defense (THAAD) program's participation in Missile Defense System Flight Tests and Ground Tests in accordance with the IMTP. THAAD Test coordinates with Operational Test Agencies, conducts pretest planning, coordination and analysis, conducts flight test operations, performs post-flight test reporting, and performs data distribution and storage.$$, NULL, 0, 0, 0, NULL, NULL, 124, $$RDTE_Vol2_MDA_RDTE_PB26_Justification_Book.pdf$$, $$MDA$$, FALSE, 25323000, 37784000, 0, 0, NULL, 0, 0, $$Ballistic Missile Defense Terminal Defense Segment Test provides the Terminal High Altitude Area Defense (THAAD) program's participation in Missile Defense System Flight Tests and Ground Tests in accordance with the Integrated Master Test Plan. THAAD Test coordinates with Operational Test Agencies, conducts pretest planning, coordination and analysis, conducts flight test operations, performs post-flight test reporting, and performs data distribution and storage. Beginning in FY 2027, the responsibility for THAAD Research, Development, Test and Evaluation funding will transfer to the Army.$$, $$Budget J-Books/FY27/Remaining/RDTE_Vol2_MDA_RDTE_PB27_Justification_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$P_2031_L023$$, $$MQ-1 PAYLOAD$$, $$proc_army_2031_ba2$$, $$peo_aviation$$, 2026, 0, 13650000, 14086000, NULL, $${"page": 12, "ba_num": "02", "source": "p1_fy26", "ba_name": "Modification of aircraft", "line_no": "23", "service": "army", "fy24_qty": null, "fy25_qty": null, "appr_code": "2031", "appr_name": "Aircraft Procurement, Army", "fy26_v178": {"note": "no_parser_pair", "source": "p40_fy26_v178"}, "fy26t_qty": null, "fy26d_cost": 0, "fy26r_cost": 0, "ident_code": "A"}$$::jsonb, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, FALSE, NULL, 0, 53190000, 53190000, 0, 53190000, NULL, NULL, $$Budget J-Books/FY27/Army/Aircraft_Procurement_Army.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604878C$$, $$Aegis BMD Test$$, $$rdte_dw_ba4$$, $$dw$$, 2026, 153618000, 186380000, 115553000, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "dw", "page_num": 73, "original_pe": "0604878C", "page_header": "Defense-Wide"}$$::jsonb, $$The Aegis Based Defense mission is to deliver an enduring, operationally effective and supportable Ballistic Missile Defense (BMD) capability to defend the nation, deployed forces, friends and allies, and to increase this capability by delivering evolutionary improvements as part of Missile Defense System upgrades. The Aegis Based Defense element of the Missile Defense System capitalizes upon and evolves from the existing United States (U.S.) Navy Aegis Weapon System and Standard Missile (SM) infrastructures. Aegis Based Defense provides a forward-deployable, mobile capability to detect and track Ballistic Missiles of all ranges, and the ability to destroy Short-Range Ballistic Missiles, Medium-Range Ballistic Missiles, and Intermediate-Range Ballistic Missiles in the midcourse phase of flight, and shorter range missiles in the terminal phase of flight. Aegis Based Defense also provides a Long Range Surveillance and Track capability to the Missile Defense System. Upgrades to both the Aegis BMD Weapon System and the SM-3 configuration enable Aegis Based Defense to provide effective, supportable defensive capability against longer range, threats and an enduring Aegis Ashore defensive capability. This Program Element works with all U.S. Armed Services that participate in the Missile Defense System level Operational Test Agency Team. With the support of the Director of Operational Test and Evaluation, the Missile Defense Agency (MDA) has developed a test program to improve confidence in missile defense capabilities under development and ensure the capabilities transferred to the warfighter are operationally effective, suitable, and survivable. As part of the MDA's rigorous test program, System Pre-Flight predictions provide confidence in test execution by predicting element performance and exercising element interfaces. System Post-Flight Reconstruction replicates the Missile Defense System configuration, actual environmental conditions, and target dynamics observed in flight to anchor Modeling and Simulation results. The IMTP is event-oriented and extends until the collection of all identified data is completed ensuring adequate test investments. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Missile Defense Agency                                                 Date: June 2025 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 4:           PE 0604878C / Aegis BMD Test Advanced Component Development & Prototypes (ACD&P)$$, NULL, 106554000, 69449000, 69180000, NULL, NULL, 125, $$RDTE_Vol2_MDA_RDTE_PB26_Justification_Book.pdf$$, $$MDA$$, FALSE, 113913000, 143618000, 61969000, 61969000, NULL, 61969000, 70767000, $$The Aegis Based Defense mission is to deliver an enduring, operationally effective and supportable BMD capability to defend the nation, deployed forces, friends and allies, and to increase this capability by delivering evolutionary improvements as part of Missile Defense System upgrades. The Aegis Based Defense element of the Missile Defense System capitalizes upon and evolves from the existing United States (U.S.) Navy Aegis Weapon System and Standard Missile (SM) infrastructures. Aegis Based Defense provides a forward-deployable, mobile capability to detect and track Ballistic Missiles of all ranges, and the ability to destroy Short-Range Ballistic Missiles, Medium-Range Ballistic Missiles, and Intermediate-Range Ballistic Missiles in the midcourse phase of flight, and shorter range missiles in the terminal phase of flight. Aegis Based Defense also provides a Long Range Surveillance and Track capability to the Missile Defense System. Upgrades to both the Aegis BMD Weapon System and the SM-3 configuration enable Aegis Based Defense to provide effective, supportable defensive capability against longer range, threats and an enduring Aegis Ashore defensive capability. This PE supports all U.S. Armed Services that participate in the Missile Defense System level Operational Test Agency Team. The MDA has developed a test program to improve confidence in missile defense capabilities under development and ensure the capabilities transferred to the warfighter are operationally effective, suitable, and survivable. As part of the MDA's rigorous test program, System Pre-Flight predictions provide confidence in test execution by predicting element performance and exercising element interfaces. System Post-Flight Reconstruction replicates the Missile Defense System configuration, actual environmental conditions, and target dynamics observed in flight to anchor Modeling and Simulation results. The Integrated Master Test Plan is event-oriented and extends until the collection of all identified data is completed ensuring adequate test investments. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Missile Defense Agency                                                        Date: April 2026 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 4:          PE 0604878C / Aegis BMD Test Advanced Component Development & Prototypes (ACD&P)$$, $$Budget J-Books/FY27/Remaining/RDTE_Vol2_MDA_RDTE_PB27_Justification_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604879C$$, $$Ballistic Missile Defense Sensor Test$$, $$rdte_dw_ba4$$, $$dw_mda$$, 2026, 68699000, 102098000, 96864000, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "dw", "page_num": 73, "original_pe": "0604879C", "page_header": "Defense-Wide"}$$::jsonb, $$The Missile Defense Agency executes a robust test program, including flight and ground tests supporting both strategic and regional Missile Defense System capabilities against medium- and long-range threats. The Sensor elements of the Missile Defense System IMTP are intended to demonstrate the integrated missile defense capabilities under development to ensure the capabilities delivered to the Warfighter are operationally effective, suitable, and survivable. The Sensor Test Program Element specifically includes the planning, execution, and analysis of flight and ground tests, as well as the associated infrastructure to provide data required for Missile Defense technical Capability Declarations. The Sensor Test program supports the integration of radar improvements into the Missile Defense System, mid- and far-term Discrimination Improvements, and Operational Test and Evaluation of the theater/regional and strategic Missile Defense System architecture.$$, NULL, 89738000, 63495000, 65720000, NULL, NULL, 126, $$RDTE_Vol2_MDA_RDTE_PB26_Justification_Book.pdf$$, $$MDA$$, FALSE, 95551000, 68699000, 52919000, 52919000, NULL, 52919000, 66936000, $$The MDA executes a robust test program, including flight and ground tests supporting both strategic and regional Missile Defense System capabilities against medium- and long-range threats. The Sensor elements of the Missile Defense System IMTP are intended to demonstrate the integrated missile defense capabilities under development to ensure the capabilities delivered to the Warfighter are operationally effective, suitable, and survivable. The Sensor Test Program Element specifically includes the planning, execution, and analysis of flight and ground tests, as well as the associated infrastructure to provide data required for Missile Defense technical Capability Declarations. The Sensor Test program supports the integration of radar improvements into the Missile Defense System, mid- and far-term Discrimination Improvements, and Operational Test and Evaluation of the theater/regional and strategic Missile Defense System architecture. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Missile Defense Agency                                                        Date: April 2026 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 4:         PE 0604879C / Ballistic Missile Defense Sensor Test Advanced Component Development & Prototypes (ACD&P)$$, $$Budget J-Books/FY27/Remaining/RDTE_Vol2_MDA_RDTE_PB27_Justification_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604880C$$, $$Land Based SM-3 (LBSM3)$$, $$rdte_dw_ba4$$, $$dw$$, 2026, 24555000, 21116000, 22220000, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "dw", "page_num": 73, "original_pe": "0604880C", "page_header": "Defense-Wide"}$$::jsonb, $$This program supports development of the Land-Based Standard Missile-3 capability, Aegis Ashore. On 17 September 2009, the President announced an overarching plan to provide regional missile defense to United States (U.S.) deployed forces, allies, and partners in Europe called the European Phased Adaptive Approach (EPAA). The EPAA policy specifically defines a timeline to deploy a mix of afloat and land-based Ballistic Missile Defense (BMD) capabilities. Aegis Ashore represents one of these land-based capabilities. Aegis Ashore is a key component of EPAA Phases II (Romania) and III (Poland) and provides Aegis BMD capability against short to intermediate-range ballistic missiles in an ashore configuration. Aegis Ashore provides sophisticated engagement strategies and can adapt to threat updates within each sites designated area of responsibility. Aegis Ashore re-hosts the required BMD components of a U.S. Navy Destroyer, including: Army/Navy Surface Radar Surveillance and Control Radar; Vertical Launch System, Computing Infrastructure; Command and Control; Communications; Computers and Intelligence Systems; and Operator Consoles. Aegis Ashore Missile Defense Test Complex operates as a test asset that continues to inform Aegis Weapon System and Aegis Combat System developmental efforts, integration of hardware and software upgrades and modernization efforts, and analyzing real time anomalies experienced in testing and in operational scenarios. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Missile Defense Agency                                                Date: June 2025 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 4:       PE 0604880C / Land Based SM-3 (LBSM3) Advanced Component Development & Prototypes (ACD&P)$$, NULL, 52470000, 32260000, 25801000, NULL, NULL, 127, $$RDTE_Vol2_MDA_RDTE_PB26_Justification_Book.pdf$$, $$MDA$$, FALSE, 21631000, 24309000, 25102000, 25102000, NULL, 25102000, 26528000, $$This program supports development of the Land-Based Standard Missile-3 capability, Aegis Ashore. On 17 September 2009, the President announced an overarching plan to provide regional missile defense to United States (U.S.) deployed forces, allies, and partners in Europe called the European Phased Adaptive Approach (EPAA). The EPAA policy specifically defines a timeline to deploy a mix of afloat and land-based Ballistic Missile Defense (BMD) capabilities. Aegis Ashore represents one of these land-based capabilities. Aegis Ashore is a key component of EPAA Phases II (Romania) and III (Poland) and provides Aegis BMD capability against short to intermediate-range ballistic missiles in an ashore configuration. Aegis Ashore provides sophisticated engagement strategies and can adapt to threat updates within each site's designated area of responsibility. Aegis Ashore re-hosts the required BMD components of a U.S. Navy Destroyer, including: - Army/Navy Surface Radar Surveillance and Control Radar. - Vertical Launch System. - Computing Infrastructure. - Command, Control, Communications, Computers, and Intelligence Systems. - Operator Consoles. Aegis Ashore Missile Defense Test Complex operates as a test asset that continues to inform Aegis Weapon System and Aegis Combat System developmental efforts, integration of hardware and software upgrades and modernization efforts, and analyzing real time anomalies experienced in testing and in operational scenarios. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Missile Defense Agency                                                        Date: April 2026 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 4:         PE 0604880C / Land Based SM-3 (LBSM3) Advanced Component Development & Prototypes (ACD&P)$$, $$Budget J-Books/FY27/Remaining/RDTE_Vol2_MDA_RDTE_PB27_Justification_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604887C$$, $$Ballistic Missile Defense Midcourse Defense Segment Test$$, $$rdte_dw_ba4$$, $$dw_mda$$, 2026, 38325000, 33224000, 40006000, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "dw", "page_num": 73, "original_pe": "0604887C", "page_header": "Defense-Wide"}$$::jsonb, $$Missile Defense Midcourse Defense Segment Test provides flight, ground, and cyber testing of hardware and software to demonstrate an integrated capability to counter the allocated threats. The hardware and software is tested in an integrated environment with Missile Defense System Sensors; Command and Control, Battle Management, and Communications; United States Northern Command Warfighters; and national collection assets to assess and demonstrate the ability to defend the United States against ballistic missile defense of the homeland. Primary activities include planning, design, and execution of flight tests, ground tests, cyber tests; test resources; and program operations. Flight tests provide the opportunity to test actual hardware and software and to demonstrate Missile Defense System interoperability under operationally realistic conditions. Ground-Based Midcourse Defense Program participates in integrated Missile Defense System ground tests executed in both the Hardware-in-the-Loop (HWIL) lab environment and with deployed operational assets providing integrated performance data supporting hardware and software fielding decisions. The Ground-Based Midcourse Defense Program conducts cyber tests and participates in integrated Missile Defense System level cyber tests executed both in the HWIL lab environment and using operational assets providing performance data supporting cyber, operational resilience, and survivability assessments. Test Resources provides the infrastructure and laboratories to support the test program as well as day-to-day operations of the test program to include support for test planning, execution, and post-event reconstruction. Program Operations provides technical and business management support of the test program. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Missile Defense Agency                                                     Date: June 2025 Appropriation/Budget Activity                                               R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 4:        PE 0604887C / Ballistic Missile Defense Midcourse Defense Segment Test Advanced Component Development & Prototypes (ACD&P)$$, NULL, 90277000, 90217000, 217143000, NULL, NULL, 128, $$RDTE_Vol2_MDA_RDTE_PB26_Justification_Book.pdf$$, $$MDA$$, FALSE, 39787000, 38325000, 53761000, 53761000, NULL, 53761000, 56516000, $$Missile Defense Midcourse Defense Segment Test provides flight, ground, and cyber testing of hardware and software to demonstrate an integrated capability to counter the allocated threats. The hardware and software is tested in an integrated environment with Missile Defense System Sensors; Command and Control, Battle Management, and Communications; United States Northern Command Warfighters; and national collection assets to assess and demonstrate the ability to defend the United States against ballistic missile defense of the homeland. Primary activities include planning, design, and execution of flight tests, ground tests, cyber tests; test resources; and program operations. Flight tests provide the opportunity to test actual hardware and software and to demonstrate Missile Defense System interoperability under operationally realistic conditions. Ground-Based Midcourse Defense Program participates in integrated Missile Defense System ground tests executed in both the Hardware-in-the-Loop (HWIL) lab environment and with deployed operational assets providing integrated performance data supporting hardware and software fielding decisions. The Ground-Based Midcourse Defense Program conducts cyber tests and participates in integrated Missile Defense System level cyber tests executed both in the HWIL lab environment and using operational assets providing performance data supporting cyber, operational resilience, and survivability assessments. Test Resources provides the infrastructure and laboratories to support the test program as well as day-to-day operations of the test program to include support for test planning, execution, and post-event reconstruction. Program Operations provides technical and business management support of the test program. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Missile Defense Agency                                                        Date: April 2026 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 4:         PE 0604887C / Ballistic Missile Defense Midcourse Defense Segment Test Advanced Component Development & Prototypes (ACD&P)$$, $$Budget J-Books/FY27/Remaining/RDTE_Vol2_MDA_RDTE_PB27_Justification_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$P_1810_L059$$, $$Joint Precision Approach and Landing Sys...$$, $$proc_navy_1810_ba2$$, $$peo_ships$$, 2026, 45701000, 37294000, 37964000, NULL, $${"page": 98, "ba_num": "02", "source": "p1_fy26", "ba_name": "Communications and electronics equipment", "line_no": "59", "service": "navy", "fy24_qty": null, "fy25_qty": null, "fy27_v25": {"ba": "02", "appr": "OPN", "title": "P-1 Line 54", "applied_at": "2026-05-09", "fy27_ooc_K": 0, "source_pdf": "Budget J-Books/FY27/Navy/OPN_BA{1..5-8}_Book.pdf", "fy27_base_K": 43097, "p1_line_num": 54, "fy27_total_K": 43097}, "appr_code": "1810", "appr_name": "Other Procurement, Navy", "fy26_v179": {"disc_K": 45701, "li_num": 54, "source": "p40_fy26_v179", "supp_K": 0, "source_pdf": "uploads/Budget J-Books/FY27/Navy/OPN_BA2_Book.txt"}, "fy26t_qty": null, "fy26d_cost": 45701000, "fy26r_cost": 0, "ident_code": "A"}$$::jsonb, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, FALSE, 7287000, 5105000, 43097000, 43097000, 0, 43097000, NULL, NULL, $$Budget J-Books/FY27/Navy/OPN_BA2_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604924D8Z$$, $$High Energy Laser Advanced Component Development & Prototype$$, $$rdte_dw_ba4$$, $$dw$$, 2026, 27589000, 0, 2931000, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "dw", "page_num": 73, "original_pe": "0604924D8Z", "page_header": "Defense-Wide"}$$::jsonb, $$This program is executed via the Joint Directed Energy Transition Office (JDETO) in alignment with the Department of Defense Directed Energy Roadmap, as well as other strategic guidance. Section 219 of the 2017 National Defense Authorization Act designated a senior official for directed energy and redesignated a legacy office as the JDETO with reporting to the senior official. Currently, the Principal Director for Directed Energy serves as this senior official and updates the Department of Defense Directed Energy Roadmap on an annual basis. The goal of this program, in turn, is to support the Department’s initiatives in directed energy to build a sustainable and long-term advantage, in addition to a resilient joint force and defense ecosystem. This program funds advanced component development and prototypes in directed energy aimed at reducing the technology risk, engineering integration, and life- cycle costs associated with directed energy weapon systems. These efforts inform requirements to develop functional and allocated baselines of end-item system configurations. In practice, directed energy weapon systems have many potential advantages, including speed-of-light time-to-target, high precision, low incremental cost per kill, and a magazine that is recharged through on-board, fuel-based power and thermal management systems that reduce logistics requirements in contrast to stocks of munitions or warheads. As a result, directed energy weapon systems have the potential to perform a wide variety of military missions. Activities conducted under this program will ultimately enable the demonstration of military utility for mission areas across the Department of Defense.$$, NULL, 55955000, 54504000, 50124000, NULL, NULL, 129, $$RDTE_OSD_PB_2026.pdf$$, $$OSD$$, FALSE, 2850000, 5528000, 44485000, 44485000, NULL, 44485000, 50121000, $$This program is executed via Scaled Directed Energy (SCADE) Integration and Manufacturing and in alignment with the Department of War Directed Energy Roadmap, as well as other strategic guidance. The goal of this program is to support the Department’s initiatives in directed energy to build a sustainable and long-term advantage. This program funds advanced component and subsystem development, as well as the prototyping and assessment of new and transitioning technologies. The goal is to reduce technology and engineering integration risks, creating the conditions for scaled production and the enhanced, widespread acceptance of DE. These efforts inform the requirements needed to develop the functional and allocated baselines of the end-item system configurations. In practice, directed energy weapon systems have many potential advantages, including speed-of-light time-to-target, high precision, low incremental cost per kill, and a rechargeable magazine through on-board power and thermal management systems improving logistics requirements over stocks of munitions or warheads. As a result, directed energy weapon systems have the potential to perform a wide variety of military missions. Activities conducted under this program will ultimately enable the demonstration of military utility for mission areas across the Department of War.$$, $$Budget J-Books/FY27/DW/RDTE_OSW_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604932F$$, $$Long Range Standoff Weapon$$, $$rdte_af_ba5$$, $$afnwc_nd$$, 2026, 606955000, 856942000, 593926000, NULL, $${"ba_raw": "6.5", "source": "af_r1_fy26", "original_pe": "0604932F"}$$::jsonb, $$The Long Range Stand-Off (LRSO) Cruise Missile is a long-range survivable stand-off weapon capable of delivering lethal nuclear effects on strategic targets. LRSO will replace the currently fielded Air Launched Cruise Missile (ALCM) and will be integrated on both legacy and future bomber aircraft. The LRSO weapon system will be capable of penetrating and surviving advanced Integrated Air Defense Systems (IADS) from significant stand-off range to prosecute strategic targets in support of the Air Force's global attack capability and strategic deterrence core function. Funds may be used to address emerging or short-notice Diminishing Manufacturing Sources and Material Shortage (DMSMS) and supply chain issues. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY24 0.00M was expended for civilian pay expenses in this program element, and in FY25 0.00M is forecasted for civilian pay expenses in this program element. The program is conducting Engineering and Manufacturing Development (EMD) tasks to validate requirements to support Development and Operational Testing, and Production Readiness. This program is in Budget Activity 5, System Development and Demonstration (SDD) because it has passed Milestone B approval and is conducting engineering and manufacturing development tasks aimed at meeting validated requirements prior to full rate production. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                       Date: June 2025 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 5: System      PE 0604932F / Long Range Standoff Weapon Development & Demonstration (SDD)$$, NULL, 172220000, 92026000, 22846000, NULL, NULL, 96, $$FY26 Air Force Research and Development Test and Evaluation Vol II.pdf$$, NULL, FALSE, 579557000, 446889000, 565679000, 565679000, 0, 565679000, 22906000, $$The Long Range Stand-Off (LRSO) effort will develop a weapon system to replace the Air Force's Air Launched Cruise Missile (ALCM), operational since 1986. The LRSO weapon system will be capable of penetrating and surviving advanced Integrated Air Defense Systems (IADS) from significant stand-off range to prosecute strategic targets in support of the Air Force's global attack capability and strategic deterrence core function. This program element included all necessary expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 0605829F, 0605831F, 0605833F, and 0605898F. This program is conducting Engineering and Manufacturing Development tasks to validate requirements to support Developmental and Operational Testing, and Production Readiness. Pre-planned Product Improvement (P3I) efforts are necessary to keep LRSO ahead of emerging adversary technologies and are separate from the LRSO Program of Record. Adversary investments in Integrated Air Defense Systems (IADS) and additional territorial gains necessitate these efforts to maintain LRSO's effectiveness beyond the reference used to validate LRSO requirements (30-year service life). Budget year 2027 through the FYDP investments are imperative to key focus areas for P3I efforts based on intel rationale to enhance future survivability. This program is in Budget Activity 5, System Development and Demonstration (SDD) because it has passed Milestone B approval and is conducting engineering and manufacturing development tasks aimed at meeting validated requirements prior to full rate production. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                     Date: April 2026 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 5: System     PE 0604932F / Long Range Standoff Weapon Development & Demonstration (SDD)$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume II.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604933F$$, $$ICBM Fuze Modernization$$, $$rdte_af_ba5$$, $$afnwc_nd$$, 2026, 3252000, 40447000, 0, NULL, $${"ba_raw": "6.5", "source": "af_r1_fy26", "original_pe": "0604933F"}$$::jsonb, $$The Intercontinental Ballistic Missile (ICBM) Fuze Modernization Program has designed and currently producing a functionally equivalent replacement for the current Mk21 fuze that will provide a 20-year threshold, 30-year objective design life. Currently available Mk21/W87-0 fuze quantities do not meet United States Strategic Command's (USSTRATCOM) requirements and the current fuze is three times beyond its original ten year design life. The program will provide needed Minuteman III (MMIII) weapon system modifications, system testing, support/test equipment, data and training required to accommodate, field, and support the new Mk21 replacement fuze along with the W87-0 warhead as defined in the Air Force Global Strike Command's (AFGSC) Requirements Traceability Memo dated 2 December 2013. In addition, the Joint Requirements Oversight Council (JROC) signed the program's JROC Memorandum validating the operational requirement for the program on 6 December 2016. A replacement Mk21/W87-0 fuze is urgently required to meet warfighter requirements and to ensure operational capability. The Mk21 reentry vehicle and fuze is designed to be deployed on the current MMIII and LGM-35A Sentinel weapon systems. The US Air Force (USAF) developed the modernized Mk21 fuze using the Department of Energy National Nuclear Security Administration (DOE/NNSA) complex and a weapons system integration contractor. The DOE/NNSA complex consists of Sandia National Labs-California (SNL-CA), Sandia National Labs-New Mexico (SNL-NM) and Kansas City National Security Campus (KCNSC). The ICBM Fuze Modernization program leveraged technologies, parts, components, and development/production capabilities resulting from extensive fuze work performed by the US Navy (USN) and DOE/NNSA on the Mk5/W88 Alt 370 Fuze program. The Radar Module is the only common Major Component with Mk5/W88 Alt 370. The Pathlength Module, Thermal Battery Assembly, Missile Interface Controller Module, Launch Safety Device, Terminal Protection Device, and the Firing Set Interface Module share piece parts with the Mk5/W88 Alt 370 Firing Set, but are specific to the Mk21 Fuze. The ICBM Fuze Modernization Program replacement fuze is designed to integrate into the MMIII and the LGM-35A Sentinel weapon systems, to include support/ test equipment, data, flight test hardware, and training materials. The program conducted required system testing (including ground and flight tests). The program is coordinating Mk21 fuze replacement development efforts with the DOE/NNSA to synchronize USAF arming and fuze development activities with DOE/NNSA warhead requirements. When prudent, the program will conduct trade studies and initiate conceptual designs to address operational system issues and meet future requirements. The Fiscal Year 2026 budget request continues efforts to develop digital models and integrating the Fuze Mod into the MMIII and LGM-35A Sentinel weapon systems. As a cooperative USAF, USN, and DOE/NNSA acquisition, the USAF is executing the program using Department of Defense (DoD) Manual 5030.55 Joint Nuclear Weapons Life Cycle Activities (Phase 6.x process) while using the DOD 5000-Series instructions to meet Major Defense Acquisition Program (MDAP) statutory and Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                       Date: June 2025 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 5: System     PE 0604933F / ICBM Fuze Modernization Development & Demonstration (SDD) regulatory requirements. The DOE/NNSA phase 6.x process is an iterative process that drives overlap and concurrency between activities and events that occur during the Engineering and Manufacturing Development (EMD) and Production and Deployment phases of the DoD 5000-Series Instruction. The program entered Phase 6.5 First Production on 6 March 2024. The first flight test was performed in FY 2019, the second flight test was performed in FY 2020, the third in FY 2022, and the final flight test was completed on 4 June 2024. The program was approved to enter Full Rate Production on 21 November 2024. The program is tailored to use the Joint Department of Defense - Department of Energy Phase 6.x processes for routine nuclear stockpile activities to align with USN and DOE/NNSA operations. The next phase will be 6.6 Full Scale Production. Program plans to enter Phase 6.6 during 3QFY2025. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, and 0606398F. In FY 2024, 0.000M was expended for civilian pay expenses in this program element, and in FY 2025, 0.000M is forecasted for civilian pay expenses in this program element. FY 2025 RDT&E funding for PE 0604933F, ICBM Fuze Modernization, is in compliance with budgeted end items per the approved test strategy and FY 2024 Omnibus, Sec. 8059. The FY 2026 request was reduced by 0.583 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative.” This program is in Budget Activity 5, System Development and Demonstration (SDD) because it has passed Milestone B approval and is conducting engineering and manufacturing development tasks aimed at meeting validated requirements prior to full rate production.$$, NULL, 0, 0, 0, NULL, NULL, 97, $$FY26 Air Force Research and Development Test and Evaluation Vol II.pdf$$, NULL, FALSE, 0, 3252000, 0, 0, 0, 0, 0, $$The Intercontinental Ballistic Missile (ICBM) Fuze Modernization Program has designed and currently producing a functionally equivalent replacement for the current Mk21 fuze that will provide a 20-year threshold, 30-year objective design life. Currently available Mk21/W87-0 fuze quantities do not meet United States Strategic Command's (USSTRATCOM) requirements and the current fuze is three times beyond its original ten year design life. The program will provide needed Minuteman III (MMIII) weapon system modifications, system testing, support/test equipment, data and training required to accommodate, field, and support the new Mk21 replacement fuze along with the W87-0 warhead as defined in the Air Force Global Strike Command's (AFGSC) Requirements Traceability Memo dated 2 December 2013. In addition, the Joint Requirements Oversight Council (JROC) signed the program's JROC Memorandum validating the operational requirement for the program on 6 December 2016. A replacement Mk21/W87-0 fuze is urgently required to meet warfighter requirements and to ensure operational capability. The Mk21 reentry vehicle and fuze is designed to be deployed on the current MMIII and LGM-35A Sentinel weapon systems. The US Air Force (USAF) developed the modernized Mk21 fuze using the Department of Energy National Nuclear Security Administration (DOE/NNSA) complex and a weapons system integration contractor. The DOE/NNSA complex consists of SNL-DA, SNL-PA and KCNSC. The ICBM Fuze Modernization program leveraged technologies, parts, components, and development/production capabilities resulting from extensive fuze work performed by the US Navy (USN) and DOE/NNSA on the Mk5/W88 Alt 370 Fuze program. The Radar Module is the only common Major Component with Mk5/W88 Alt 370. The Pathlength Module (PLM), Thermal Battery Assembly (TBA), Missile Interface Controller Module (MICM), Launch Safety Device (LSD), Terminal Protection Device (TPD), and the Firing Set Interface Module (FSIM) share piece parts with the Mk5/W88 Alt 370 Firing Set, but are specific to the Mk21 Fuze. The ICBM Fuze Modernization Program replacement fuze is designed to integrate into the MMIII and the LGM-35A Sentinel weapon systems, to include support/ test equipment, data, flight test hardware, and training materials. The program conducted required system testing (including ground and flight tests). The program is coordinating Mk21 fuze replacement development efforts with the DOE/NNSA to synchronize USAF arming and fuze development activities with DOE/NNSA warhead requirements. When prudent, the program will conduct trade studies and initiate conceptual designs to address operational system issues and meet future requirements. As a cooperative USAF, USN, and DOE/NNSA acquisition, the USAF is executing the program using Department of Defense (DoD) Manual 5030.55 Joint Nuclear Weapons Life Cycle Activities (Phase 6.x process) while using the DOD 5000-Series instructions to meet Major Defense Acquisition Program (MDAP) statutory and Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                         Date: April 2026 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 5: System     PE 0604933F / ICBM Fuze Modernization Development & Demonstration (SDD) regulatory requirements. The DOE/NNSA phase 6.x process is an iterative process that drives overlap and concurrency between activities and events that occur during the Engineering and Manufacturing Development (EMD) and Production and Deployment phases of the DoD 5000-Series Instruction. The program entered Phase 6.5 First Production on 6 March 2024. The first flight test was performed in FY19, the second flight test was performed in FY20, the third in FY22, and the final flight test was completed on 4 June 2024. The program was approved to enter Full Rate Production (FRP) on 21 November 2024. The program is tailored to use the Joint Department of Defense - Department of Energy Phase 6.x processes for routine nuclear stockpile activities to align with USN and DOE/NNSA operations. The next phase will be 6.6 Full Scale Production. Program plans to enter Phase 6.6 during 2QFY2026. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, and 0606398F. This program is in Budget Activity 5, System Development and Demonstration (SDD) because it has passed Milestone B approval and is conducting engineering and manufacturing development tasks aimed at meeting validated requirements prior to full rate production.$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume II.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604940D8Z$$, $$Central Test and Evaluation Investment Program (CTEIP)$$, $$rdte_dw_ba6$$, $$dw$$, 2026, 542773000, 848247000, 805414000, NULL, $${"act": "06", "ba_raw": "6.6", "source": "r1_fy26", "service": "dw", "page_num": 75, "original_pe": "0604940D8Z", "page_header": "Defense-Wide"}$$::jsonb, $$This program supports the Department's priorities to rebuild the military by matching threats to capabilities and re-establish deterrence by defending our homeland. Since its inception in FY 1990, Central Test and Evaluation Investment Program (CTEIP) provides the development of the most needed, high-priority Test and Evaluation (T&E) capabilities for joint/multi-Service requirements. CTEIP investments address strategic requirements related to Hypersonics, Directed Energy, Cyber, Electronic Warfare, Nuclear Effects, Space, Autonomy, and Multi-Domain Operations. Other Investments in test infrastructure align with objectives in the Strategic Plan for DoD T&E Resources for high priority test needs and common range Infrastructure. The CTEIP uses a corporate investment approach to combine T&E needs from Service, Defense, and other Government agencies in order to maximize opportunities for joint efforts and avoid unwarranted duplication of test capabilities. CTEIP evaluates and selects for execution, proposals that align to national strategic guidance and USD(R&E) priorities, provide the greatest return on investment, make efficient use of limited test resources, leverage industry capabilities and Service investments, and promote joint solutions to fill test capability gaps. CTEIP provides enterprise solutions that benefit the whole Department. These investments are needed to ensure the Department’s readiness to test and field rapidly emerging technologies and weapon systems that defend our homeland, deter aggression, and achieve peace through strength.$$, NULL, 595785000, 505362000, 492052000, NULL, NULL, 167, $$RDTE_OSD_PB_2026.pdf$$, $$OSD$$, FALSE, 803846000, 807503000, 1153754000, 1153754000, NULL, 1153754000, 502396000, $$The Test Resource Management Center (TRMC) Central Test and Evaluation Investment Program (CTEIP) supports the Department's priorities to rebuild the military and re-establish deterrence. Since its inception in FY 1990, CTEIP has provided development of the most needed, high-priority Test and Evaluation (T&E) capabilities for joint/multi-Service requirements. CTEIP investments address strategic requirements related to Hypersonics, Directed Energy, Cyber, Electronic Warfare, Nuclear Effects, Space, Autonomy, Multi-Domain Operations, and Affordable Attritable Mass. Other CTEIP investments align with high priority test needs and common range infrastructure. CTEIP uses a corporate investment approach to combine T&E needs from Service, Department, and other Government agencies in order to maximize opportunities for joint efforts and avoid unwarranted duplication of test capabilities. CTEIP evaluates and selects for execution proposals that align to national strategic guidance and USW(R&E) priorities, provide the greatest return on investment, make efficient use of limited test resources, leverage industry capabilities and Service investments, and promote joint solutions to fill test capability gaps. CTEIP provides enterprise solutions that benefit the whole Department. These investments are needed to ensure the Department’s readiness to test and field rapidly emerging technologies and weapon systems that defend our homeland, deter aggression, and achieve peace through strength. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Office of the Secretary Of Defense                                                 Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 6:           PE 0604940D8Z / Central Test and Evaluation Investment Program (CTEIP) RDT&E Management Support$$, $$Budget J-Books/FY27/DW/RDTE_OSW_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604942D8Z$$, $$Assessments Evaluations$$, $$rdte_dw_ba6$$, $$dw_ousd_as$$, 2026, 1275000, 5599000, 1503000, NULL, $${"act": "06", "ba_raw": "6.6", "source": "r1_fy26", "service": "dw", "page_num": 76, "original_pe": "0604942D8Z", "page_header": "Defense-Wide"}$$::jsonb, $$This program is reported in accordance with Title 10, United States Code, Section 119(a)(1) in the Special Access Program Annual Report to Congress. For further information, please contact the Director of Special Programs, OUSD(A&S)/DSP.$$, NULL, NULL, NULL, NULL, NULL, NULL, 168, $$RDTE_OSD_PB_2026.pdf$$, $$OSD$$, FALSE, 1448000, 1257000, NULL, NULL, NULL, NULL, NULL, $$This program is reported in accordance with Title 10, United States Code, Section 119(a)(1) in the Special Access Program Annual Report to Congress. For further information, please contact the Director of Special Programs, OUSW(A&S)/DSP.$$, $$Budget J-Books/FY27/DW/RDTE_OSW_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
