INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605000BR$$, $$COUNTER WEAPONS OF MASS DESTRUCTION SYSTEMS DEVELO$$, $$rdte_dw_ba5$$, $$dw_dtra$$, 2026, 14931000, 14049000, 14841000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "dw", "page_num": 74, "original_pe": "0605000BR", "page_header": "Defense-Wide"}$$::jsonb, $$The Counter Weapons of Mass Destruction (CWMD) Systems Development program element supports the development and demonstration of technologies and systems for the CWMD mission, including modeling and simulation capabilities, verification and monitoring technologies, and decision support systems.$$, NULL, 17036000, 17481000, 17847000, NULL, NULL, 146, $$RDTE_DTRA_PB_2026.pdf$$, $$DTRA$$, FALSE, 14474000, 14777000, 16713000, 16713000, 0, 16713000, 18203000, $$The Counter Weapons of Mass Destruction (CWMD) Systems Development program element supports the development and demonstration of technologies and systems for the CWMD mission, including modeling and simulation capabilities, verification and monitoring technologies, and decision support systems.$$, $$Budget J-Books/FY27/Remaining/RDTE_DTRA_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605001E$$, $$MISSION SUPPORT$$, $$rdte_dw_ba6$$, $$dw_darpa$$, 2026, 115673000, 108219000, 113007000, NULL, $${"act": "06", "ba_raw": "6.6", "source": "r1_fy26", "service": "dw", "page_num": 76, "original_pe": "0605001E", "page_header": "Defense-Wide"}$$::jsonb, $$The Mission Support Program Element provides funding for the costs of mission support activities for the Defense Advanced Research Projects Agency. The funds provide personnel compensation for mission support civilians as well as costs for building rent, physical security, travel, supplies and equipment, communications, printing and reproduction.$$, NULL, 111203000, 114381000, 117134000, NULL, NULL, 170, $$RDTE_Vol1_DARPA_MasterJustificationBook_PB_2026.pdf$$, $$DARPA$$, FALSE, 122998000, 115673000, 108101000, 108101000, NULL, 108101000, 119655000, $$The Mission Support Program Element provides funding for the costs of mission support activities for the Defense Advanced Research Projects Agency. The funds provide personnel compensation for mission support civilians as well as costs for building rent, physical security, travel, supplies and equipment, communications, printing and reproduction.$$, $$Budget J-Books/FY27/DW/RDTE_Vol1_DARPA_MasterJustificationBook_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605013A$$, $$Information Technology Development$$, $$rdte_army_ba5$$, $$asa_alt$$, 2026, 125701000, 96090000, 102704000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "army", "page_num": 17, "original_pe": "0605013A", "page_header": "Department of the Army"}$$::jsonb, $$This Program Element is made up of over 23 programs across 12 Projects that represent numerous Army Information Technology missions. The FY 2026 request was reduced by $0.944 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative." Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                       Date: June 2025 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 5: System           PE 0605013A / Information Technology Development Development & Demonstration (SDD)$$, NULL, 120333000, 119544000, 116418000, NULL, NULL, 130, $$RDTE - Vol 3 - Budget Activity 5C.pdf$$, NULL, FALSE, 92084000, 124247000, 121525000, 121525000, NULL, 121525000, 114890000, $$This Program Element is made up of over 21 programs across 11 Projects that represent numerous Army Information Technology missions. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                           Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 5: System            PE 0605013A / Information Technology Development Development & Demonstration (SDD)$$, $$Budget J-Books/FY27/Army/RDTEVol3BudgetActivity5C.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605013BL$$, $$Information Technology Development$$, $$rdte_dw_ba5$$, $$dw_dcma$$, 2026, 1283000, 6712000, 4709000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "dw", "page_num": 74, "original_pe": "0605013BL", "page_header": "Defense-Wide"}$$::jsonb, $$The DCMA is engaged in several major Information Technology (IT) initiatives to improve and modernize the information technology environment. IT is the primary enabling capability the acquisition workforce relies upon to communicate with contractors, the DoD acquisition community and other customers. The National Defense Strategy IT modernization efforts drive these initiatives. The Defense Contract Management Agency (DCMA) continues to execute an IT modernization strategy established to improve visibility, insight, and collaboration between DCMA, the military services, other defense agencies, and contractors in the Defense Industrial Base (DIB). Core to this strategy is the Modernization and Analytics Initiative (MAI) program to modernize and integrate the entire DCMA portfolio of aging Contract Administration Services (CAS) capabilities and supporting infrastructure, leveraging Platform and Software as a Service (PaaS/SaaS) cloud environment, the Defense Logistics Agency (DLA) Procurement Integrated Enterprise Environment (PIEE), the Department of the Navy (DoN) Product Data Reporting and Evaluation Program (PDREP), and OUSD(C) ADVANA Business Intelligence and Data Analytics platform to enable department-wide CAS capabilities. These efforts support the Director’s strategic objective to modernize CAS tools to improve DCMA processes, enhance DOD Acquisition insights, and standardize contract administration actions and data accessibility across the Department enterprise. Development and research initiatives are core components of the DCMA ability to align efforts appropriately to the DoD IT strategy. In FY 2026, the DCMA continues to invest in the Procurement Integrated Enterprise Environment (PIEE) (hosts Wide Area WorkfFlow (WAWF) and Electronic Data Access (EDA)). This core initiative will empower mobile and fixed users' ability to utilize DoD enterprise capabilities at the same level with improved efficiency and effectiveness. The DCMA aligns with the DoD strategy for software modernization of enterprise capabilities. This involves migrating the DCMA application infrastructure to enterprise hosting environments and modern technology platforms, rationalizing existing applications to ensure capabilities align with mission requirements, and adopting new DoD strategies for modern software development methodologies. These solutions will improve process gaps to streamline/simplify automated contract administration, provide real-time data visibility, reduce manual intervention, and provide effective, regulatory-based tools for use across the Department. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Defense Contract Management Agency                                                Date: June 2025 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 5:           PE 0605013BL / Information Technology Development System Development & Demonstration (SDD)$$, NULL, 10448000, 6815000, 6022000, NULL, NULL, 147, $$RDTE_DCMA_PB_2026.pdf$$, $$DCMA$$, FALSE, 4546000, 1192000, 13620000, 13620000, NULL, 13620000, 6170000, $$Systems Modifications and Development The Defense Contract Management Agency (DCMA) is engaged in several major Information Technology (IT) initiatives to improve and modernize the information technology environment. IT is the primary enabling capability the acquisition workforce relies upon to communicate with contractors, the Department of War (DOW) acquisition community and other customers. The National Defense Strategy (NDS) IT modernization efforts drive these initiatives. The DCMA continues to execute an IT modernization strategy established to improve visibility, insight, and collaboration between DCMA, the Military Departments (MILDEPs), other Defense Agencies and DOD Field Activities (DAFAs), other federal agencies, and contractors in the Defense Industrial Base (DIB). Core to this strategy is the Modernization and Analytics Initiative (MAI) program to modernize and integrate the entire DCMA portfolio of aging Contract Administration Services (CAS) capabilities and supporting infrastructure, leveraging Platform and Software as a Service (PaaS/SaaS) cloud environment, the Defense Logistics Agency (DLA) Procurement Integrated Enterprise Environment (PIEE), the Department of the Navy (DON) Product Data Reporting and Evaluation Program (PDREP), and Advancing Analytics (ADVANA) Business Intelligence and Data Analytics platform to enable departmentwide CAS capabilities. These efforts support the Director’s strategic objective to modernize CAS tools to improve DCMA processes, enhance DOW Acquisition insights, and standardize contract administration actions and data accessibility across the Department enterprise. Development and research initiatives are core components of the DCMA ability to align efforts appropriately to the DOW IT strategy. In FY 2027, the DCMA continues to invest in the PIEE (hosts Wide Area WorkfFlow (WAWF) and Electronic Data Access (EDA). This core initiative will empower mobile and fixed users' ability to utilize DOW enterprise capabilities at the same level with improved efficiency and effectiveness. The DCMA aligns with the DOW strategy for software modernization of enterprise capabilities. This involves migrating the DCMA application infrastructure to enterprise hosting environments and modern technology platforms, rationalizing existing applications to ensure capabilities align with mission requirements, and adopting new DOW strategies for modern software development methodologies. These solutions will improve process gaps to streamline/simplify automated contract administration, provide real-time data visibility, reduce manual intervention, and provide effective, regulatory-based tools for use across the Department. Blue List In support of DOW’s Drone Dominance, the Blue List is an ecosystem our US Government, and industry partners, providing an aggregated list of compliant Unmanned Aerial System (UAS) platforms and components. The Blue list will expand functionality to create a Blue Marketplace for efficient purchasing, integrate auto-designed Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Defense Contract Management Agency                                               Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 5:           PE 0605013BL / Information Technology Development System Development & Demonstration (SDD) aircraft software, foster a community knowledge hub, scale to include all Unmanned System (UxS) domains, additive and subtractive manufacturing hardware and conduct compliance assessments.$$, $$Budget J-Books/FY27/Remaining/RDTE_DCMA_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605013M$$, $$Marine Corps IT Dev/Mod$$, $$rdte_navy_ba5$$, $$mc$$, 2026, 16000000, 29862000, 15218000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "mc", "page_num": 34, "original_pe": "0605013M", "page_header": "Department of the Navy"}$$::jsonb, $$This program develops, modernizes, establishes and sustains Information Technology (IT) services for testing, certifying and operationally deploying software applications and other Defense Business Systems (DBS) for Business Capability Acquisition Cycle (BCAC) programs in support of Marine Corps business solutions.$$, NULL, 11630000, 11860000, 11819000, NULL, NULL, 160, $$RDTEN_BA5_Book.pdf$$, NULL, FALSE, 14632000, 16000000, 14380000, 14380000, NULL, 14380000, 12055000, $$This program develops, modernizes, establishes and sustains Information Technology (IT) services for testing, certifying and operationally deploying software applications and other Defense Business Systems (DBS) for Business Capability Acquisition Cycle (BCAC) programs in support of Marine Corps business solutions.$$, $$Budget J-Books/FY27/Navy/RDTEN_BA5_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605013N$$, $$Information Technology Development$$, $$rdte_navy_ba5$$, $$navy_cno$$, 2026, 192784000, 291314000, 336504000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "navy", "page_num": 34, "original_pe": "0605013N", "page_header": "Department of the Navy"}$$::jsonb, $$2901 Navy Enterprise IT SECNAV PROJECTS IT SYSTEM MODERNIZATION The Department of the Navy Chief Information Officer, Technology Division (DONCIO IT) provides Information Technology (IT), Information Assurance (IA), Information Management (IM), Document Management (DM), Records Management (RM), Knowledge Management (KM) and other related support services to the Secretary of the Navy (SECNAV), Chief of Naval Operations (OPNAV), and the DON Secretariat. This support spans across over 24 organizations, covers nearly 6,000 individual customers, and countless worldwide end users. ELECTRONIC PROCUREMENT SYSTEM (ePS) ePS provides the Department of the Navy (DON) Solution for Electronic Contract Writing replacing the existing Standard Procurement System (SPS) and DON Integrated Contracting Environment (DICE) capabilities and deficiencies. ePS aligns Contract Writing System (CWS) with Financial Improvement Audit Readiness requirements mandated by Congress and the Department of Navy's goal for an auditable link between financial management and contract writing system. It supports strategic sourcing and seamless exchange of data in addition to evolving to meet changing requirements. The improved capabilities will meet emerging data standards Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Navy                                                                               Date: June 2025 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 5: System            PE 0605013N / Information Technology Development Development & Demonstration (SDD) Procurement Data Standards/Procurement Request Data Standards (PDS/PRDS), in addition to complying with Office of the Secretary of Defense (OSD) Clause Logic Service. ePS meets the intent of the National Defense Authorization Act of 2013 by providing an electronic means to award contracts. Warfighting Readiness Assessment - Force Level Integration Tool (FLINT) Force Level Integration (FLINT) is a digital decision support solution that enables mass exploration of POM alternatives, positioning the Navy's POM programing process to evolve from a subjective human capital and document-centric process to a data driven, model-centric process that leverages automated frameworks and computing to serve as the analytical underpinning for developing the POM. FLINTs mission is to integrate the numerous and disparate tools, databases, models, simulations, analyses, and subject matter expertise necessary to facilitate and optimize Navy POM decision making. FLINT provides senior leadership with programming options that capture the fiscal trade-offs and their consequences to warfighting effectiveness when measured against defined criteria and enables relative valuation across all POM requirements. NMCI ENTERPRISE SERVICE TOOLS (NEST) Next Generation Enterprise Network (NGEN) utilizes the NMCI Enterprise Service Tools (NEST) as an integrated set of tools that facilitate the full service lifecycle management (SLM) of customer service requests for IT services, including RAPT (Requirement to Award Process Tool), NET (NMCI Enterprise Tool), Task Order Management (TOM), and Enterprise Reporting. NEST is considered a Government Owned and Managed Ordering Defense Business System (DBS) that has a valid authority to operate (ATO). NEXT GENERATION ENTERPRISE NETWORK (NGEN) NETWORK ARCHITECHTURE DESIGN AND TESTING NGEN is utilizing a rapid, agile systems engineering and pilot approach, leveraging leading industry experts to design and execute a transformative architecture across the spectrum of services which drives towards the design and implementation of modern services. Modern services provide for better delivering on requirements with optimal cloud consumption, domain singularity, mobility, resilience, increased customer experience and enhanced security. These modernized services are on parity with industry, which is ready to meet changing mission needs and achieve competitive Naval advantage through a constant state of Information Readiness and outcomes will be measured via Worldclass Alignment Metrics (WAM). Navy's Digitization Journey is dependent upon the Navy's Enterprise Network. The modernized platform will meet today and future mission requirements. This multi-year effort and investment is needed to finalize and adjudicate a Target Enterprise Architecture (TEA), identify obsolescent technologies associated with Navy network platforms, and aid in the integration of users and services, implement enabling business processes and service management frameworks, and provide sustaining activity guidance for future investment areas across all classification levels and operating environments. NGEN will implement a new network architecture design, a technical enterprise architecture that integrates rationalized users and services, implements enabling business processes and service management frameworks and provides guidance for future investment areas across all classification levels and operating environments. This includes network modeling & simulation, performance-based prototypes and applied research in future technologies affecting network architectures to advance the state of networks across all domains. 2903 NAVAIR IT Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Navy                                                                                 Date: June 2025 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 5: System              PE 0605013N / Information Technology Development Development & Demonstration (SDD) NAVY CYBERSECURITY Cyber Warfare consists of many different aspects to include sabotage of our weapon systems, networks as well as enablement of missions. Nation and non-nation state actors are acquiring and employing more advanced cyber-attacks in order to exploit our networks and aviation systems challenging our technological edge. The threats and capabilities are real and range from exploiting capabilities, overloading weapons systems and logistics supply chains, to jamming signals or taking control of weapons systems. Adversarial cyber-attacks must be defended against while contributing to the exploitation of cyber warfare capabilities. To meet these challenges and address the Chief of Naval Operations priorities and tasking, these efforts are specifically focused on Naval Air Systems Command weapon or control systems and programs to ensure warfighting effectiveness as part of integrated / multi-platform kill chains. These efforts will strengthen our cyber posture by developing capabilities and solutions to deter, detect, and mitigate cyber threats and safeguard classified naval aviation systems and platforms from "cradle to grave." These solutions will be integrated into the acquisition of weapons systems to enhance security, increase lethality, and improve resiliency in the expected operational environments. Our weapon or control systems are unique in the aforementioned environments and mission, but also in the presence of numerous non- traditional access points and trusted cyber relationships required for operational environments. Further, this line sustains Naval Aviation's Red Team capability to research, identify and validate nation-state exploitable cyber susceptibilities and vulnerabilities in both deployed and next-generation warfighting platforms. Through it, these efforts improve Naval Aviation's mission survivability by developing and demonstrating operational TTPs within the cyber contested environment. The team partners with Naval Aviation programs to certify theorized cyber weaknesses and thus to prevent denial, degradation or disruption of safety, readiness, and mission. The Red Team's assessment products support CYBERSAFE certification of platforms and systems and likewise supports PMAs and OPNAV with validated threat data prioritizing systems security engineering (SSE) investments. The team leverages national-level cyber warfare experts, all-source intelligence, and technology research to assess NAE operational technology, fleet exercises, support equipment, enterprise logistics systems, and supply chain. DIGITAL THREAD (DT) Funding provides a Naval Enterprise Solution to manage technical data required for weapons systems to promote workforce automation, resource optimization, and process standardization for program lifecycle management and to integrate acquisition with the warfighter. This will support future state for Logistics IT and enhancing Readiness in providing an enterprise solution with Naval Product Lifecycle Management (N-PLM). N-PLM is integral to Digital Log IT, supporting the Naval Maintenance, Repair, and Overhaul (N-MRO), Naval Supply Chain Management (N-SCM). Digital Thread (DT) is the capability providing digital process integration with complete, secure and authoritative data, coordinated as part of approved Navy LOG-IT. DT integrates the product life cycle to provide universal access to authoritative data and workflow automation, enabling configuration management of data, implementation of closed loop quality, and consolidation of engineering products including digital enablement of additive manufacturing. Connecting these processes using standardized digital tools and data accelerates the product development cycle and lowers costs for support and new capability integration. The Digital Thread capability includes development and demonstration of cyber security architectures for sustainment information systems, and development of a digital/additive manufacturing data architecture and repository. DT capability will benefit the speed to the Fleet with reduction of active legacy systems that stakeholders (PMAs, Squadrons, Depots, OEM, and Shipyards) are accessing for authoritative data. DIGITAL PRODUCTION FLOOR (DPF) Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Navy                                                                                      Date: June 2025 Appropriation/Budget Activity                                                      R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 5: System                PE 0605013N / Information Technology Development Development & Demonstration (SDD) Initiative modernizes Navy Aviation Depots by removing paper from the production floor and integrating key quality elements to support a true digital North Star ensuring viability and alignment with broader Naval Logistics IT (LOG-IT) enterprise initiatives to realize a fully unified digital sustainment capability. This capability aligns and leverages ongoing Digital Thread /Aviation Product Lifecycle Management (AvPLM) efforts to transform our existing way of doing business and align us with commercial best practices for digitization of business processes. Current paper-based processes have demonstrated inefficiencies and administrative delays in performance, degraded quality of product, and increased Depot level repair turnaround times. RADIO FREQUENCY INDENTIFICATION (RFID) Digital tracking infrastructure enabling enhanced inventory and asset tracking capability with real-time or near real time visibility of fixed and rolling assets for accountability. Signed DD200s document lost tagged assets, therefore, each of these assets are large enough to be tagged. This capability will reduce the amount of DD200s by approximately 95%. By digitizing this capability, labor man-hours spent manually performing inventory tasking requirements will be reduced by approximately 33% overall. This initiative will provide the necessary foundational infrastructure and enable expansion to other use cases such as tool control, parts tracking, and HAZMAT tracking. Moving from manual, labor-intensive (~30 man-years) inventory method for fixed … [truncated]$$, NULL, 140663000, 136579000, 161576000, NULL, NULL, 161, $$RDTEN_BA5_Book.pdf$$, NULL, FALSE, 333279000, 234102000, 149089000, 149089000, NULL, 149089000, 164608000, $$2901 Navy Enterprise IT SECNAV PROJECTS IT SYSTEM MODERNIZATION The Department of the Navy Director of Administration (DIRAD) provides Information Technology (IT), Information Assurance (IA), Information Management (IM), Document Management (DM), Records Management (RM), Knowledge Management (KM) and other related support services to the Secretary of the Navy (SECNAV), Chief of Naval Operations (OPNAV), and the DON Secretariat. This support spans across over 24 organizations, covers nearly 6,000 individual customers, and countless worldwide end users. ELECTRONIC PROCUREMENT SYSTEM (ePS) ePS provides the Department of the Navy (DON) solution for Electronic Contract Writing replacing the existing Standard Procurement System (SPS) and DON Integrated Contracting Environment (DICE) capabilities and deficiencies. ePS aligns Contract Writing System (CWS) with Financial Improvement Audit Readiness requirements mandated by Congress and the Department of Navy's goal for an auditable link between financial management and contract writing system. It supports strategic sourcing and seamless exchange of data in addition to evolving to meet changing requirements. The improved capabilities will meet emerging data standards Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                               Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 5: System            PE 0605013N / Information Technology Development Development & Demonstration (SDD) Procurement Data Standards/Procurement Request Data Standards (PDS/PRDS), in addition to complying with Office of the Secretary of War (OSW) Clause Logic Service. ePS meets the intent of the National Defense Authorization Act of 2013 by providing an electronic means to award contracts. WAREFIGHTING READINESS ASSESSMENT - FORCE LEVEL INTEGRATION TOOL (FLINT) Force Level Integration (FLINT) is a digital decision support solution that enables mass exploration of POM alternatives, positioning the Navy's POM programing process to evolve from a subjective human capital and document-centric process to a data driven, model-centric process that leverages automated frameworks and computing to serve as the analytical underpinning for developing the POM. FLINTs mission is to integrate the numerous and disparate tools, databases, models, simulations, analyses, and subject matter expertise necessary to facilitate and optimize Navy POM decision making. FLINT provides senior leadership with programming options that capture the fiscal trade-offs and their consequences to warfighting effectiveness when measured against defined criteria and enables relative valuation across all POM requirements. NMCI ENTERPRISE SERVICE TOOLS (NEST) Next Generation Enterprise Network (NGEN) utilizes the NMCI Enterprise Service Tools (NEST) as an integrated set of tools that facilitate the full service lifecycle management (SLM) of customer service requests for IT services, including RAPT (Requirement to Award Process Tool), NET (NMCI Enterprise Tool), Task Order Management (TOM), and Enterprise Reporting. NEST is considered a Government Owned and Managed Ordering Defense Business System (DBS) that has a valid authority to operate (ATO). NEXT GENERATION ENTERPRISE NETWORK (NGEN) NETWORK ARCHITECHTURE DESIGN AND TESTING NGEN is utilizing a rapid, agile systems engineering and pilot approach, leveraging leading industry experts to design and execute a transformative architecture across the spectrum of services which drives towards the design and implementation of modern services. Modern services provide for better delivering on requirements with optimal cloud consumption, domain singularity, mobility, resilience, increased customer experience and enhanced security. These modernized services are on parity with industry, which is ready to meet changing mission needs and achieve competitive Naval advantage through a constant state of Information Readiness and outcomes will be measured via Worldclass Alignment Metrics (WAM). Navy's Digitization Journey is dependent upon the Navy's Enterprise Network. The modernized platform will meet today and future mission requirements. This multi-year effort and investment is needed to finalize and adjudicate a Target Enterprise Architecture (TEA), identify obsolescent technologies associated with Navy network platforms, and aid in the integration of users and services, implement enabling business processes and service management frameworks, and provide sustaining activity guidance for future investment areas across all classification levels and operating environments. NGEN will implement a new network architecture design, a technical enterprise architecture that integrates rationalized users and services, implements enabling business processes and service management frameworks and provides guidance for future investment areas across all classification levels and operating environments. This includes network modeling & simulation, performance-based prototypes and applied research in future technologies affecting network architectures to advance the state of networks across all domains. 2903 NAVAIR IT NAVY CYBERSECURITY Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                                   Date: April 2026 Appropriation/Budget Activity                                                      R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 5: System                PE 0605013N / Information Technology Development Development & Demonstration (SDD) Cyber Warfare consists of many different aspects to include sabotage of our weapon systems, networks as well as enablement of missions. Nation and non-nation state actors are acquiring and employing more advanced cyber-attacks in order to exploit our networks and aviation systems challenging our technological edge. The threats and capabilities are real and range from exploiting capabilities, overloading weapons systems and logistics supply chains, to jamming signals or taking control of weapons systems. Adversarial cyber-attacks must be defended against while contributing to the exploitation of cyber warfare capabilities. To meet these challenges and address the Chief of Naval Operations priorities and tasking, these efforts are specifically focused on Naval Air Systems Command weapon or control systems and programs to ensure warfighting effectiveness as part of integrated / multi-platform kill chains. These efforts will strengthen our cyber posture by developing capabilities and solutions to deter, detect, and mitigate cyber threats and safeguard classified naval aviation systems and platforms from "cradle to grave." These solutions will be integrated into the acquisition of weapons systems to enhance security, increase lethality, and improve resiliency in the expected operational environments. Our weapon or control systems are unique in the aforementioned environments and mission, but also in the presence of numerous non- traditional access points and trusted cyber relationships required for operational environments. Further, this line sustains Naval Aviation's Red Team capability to research, identify and validate nation-state exploitable cyber susceptibilities and vulnerabilities in both deployed and next-generation warfighting platforms. Through it, these efforts improve Naval Aviation's mission survivability by developing and demonstrating operational Tactics, Techniques, and Procedures (TTPs) within the cyber contested environment. The team partners with Naval Aviation programs to certify theorized cyber weaknesses and thus to prevent denial, degradation or disruption of safety, readiness, and mission. The Red Team's assessment products support CYBERSAFE certification of platforms and systems and likewise supports PMAs and OPNAV with validated threat data prioritizing systems security engineering (SSE) investments. The team leverages national-level cyber warfare experts, all-source intelligence, and technology research to assess NAE operational technology, fleet exercises, support equipment, enterprise logistics systems, and supply chain. DIGITAL THREAD (DT) Funding provides a Naval Enterprise Solution to manage technical data required for weapons systems to promote workforce automation, resource optimization, and process standardization for program lifecycle management and to integrate acquisition with the warfighter. This will support future state for Logistics IT and enhancing Readiness in providing an enterprise solution with Naval Product Lifecycle Management (N-PLM). N-PLM is integral to Digital Log IT, supporting the Naval Maintenance, Repair, and Overhaul (N-MRO), Naval Supply Chain Management (N-SCM). Digital Thread (DT) is the capability providing digital process integration with complete, secure and authoritative data, coordinated as part of approved Navy LOG-IT. DT integrates the product life cycle to provide universal access to authoritative data and workflow automation, enabling configuration management of data, implementation of closed loop quality, and consolidation of engineering products including digital enablement of additive manufacturing. Connecting these processes using standardized digital tools and data accelerates the product development cycle and lowers costs for support and new capability integration. The Digital Thread capability includes development and demonstration of cyber security architectures for sustainment information systems, and development of a digital/additive manufacturing data architecture and repository. DT capability will benefit the speed to the Fleet with reduction of active legacy systems that stakeholders (PMAs, Squadrons, Depots, OEM, and Shipyards) are accessing for authoritative data. DIGITAL PRODUCTION FLOOR (DPF) Initiative modernizes Navy Aviation Depots by removing paper from the production floor and integrating key quality elements to support a true digital North Star ensuring viability and alignment with broader Naval Logistics IT (LOG-IT) enterprise initiatives to realize a fully unified digital sustainment capability. This capability aligns and Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                                      Date: April 2026 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 5: System             PE 0605013N / Information Technology Development Development & Demonstration (SDD) leverages ongoing Digital Thread /Aviation Product Lifecycle Management (AvPLM) efforts to transform our existing way of doing business and align us with commercial best practices for digitization of business processes. Current paper-based processes have demonstrated inefficiencies and administrative delays in performance, degraded quality of product, and increased Depot level repair turnaround times. RADIO FREQUENCY INDENTIFICATION (RFID) Digital tracking infrastructure enabling enhanced inventory and asset tracking capability with real-time or near real time visibility of fixed and rolling assets for accountability. Signed DD200s document lost tagged assets, therefore, each of these assets are large enough to be tagged. This capability will reduce the amount of DD200s by approximately 95%. By digitizing this capability, labor man-hours spent manually performing inventory tasking requirements will be reduced by approximately 33% overall. This initiative will provide the necessary foundational infrastructure and enable expansion to other use cases such as tool control, parts tracking, and HAZMAT tracking. Moving from manual, labor-intensive (~30 man-years) inventory method for fixed and rolling assets to an automatic digital method will provide real- time or near real time visibility into asset location throughout the facility, alerts when assets that are taken out of a geo-fenced location, and the ability to perform frequent inventory inspections, therefore providing enhanced asset management. This will be accomplished by the implementation of compatible and integrated solutions via a blended technology approach (i.e. RFID, GPS, etc.) that is in direct support of the objective to realize a full Digital Production Floor at the Aviation Depots. 2904 NAVSEA IT This program includes the funding for the Information Technology (IT) tools utilized in shore maritime maintenance planning, execution, tracking, quality control, certification, closeout, employee qualifications, and payroll. This program supports ship, submarine, and aircraft carrier maintenance. The Navy Maritime Maintenance Enterprise Solution (NMMES) includes efforts for the development, support, and sustainment of maritime shore maintenance and includes multiple modernization efforts to insure effectiveness of Fleet maintenance systems. This includes the retirement and/or replacement of costly systems and applications, transition planning, and systems engineering for integration with current and future enterprise solutions. These efforts align with direction to ensure that these solutions support a planned, single maintenance solution end state, as well as direction to align with multiple laws, regulations, policies, and guidance. It includes the modernization of Naval Shipyard, Regional Maintenance Centers, and Forward Deployed Naval Forces' planning, Maintenance, Repair and Overhaul (MRO) production tools. This includes modifications/enhancements to Shipyard IT applications, for work execution management, critical chain scheduling, workload and performance applications, the availability cost tracking, material management applications, and other solutions such as the Electronic Technical Working Document (eTWD) initiative. The goal is to provide modernization, migration, and consolidation of obsolete legacy IT tools to a modern, supportable, and modular solution enabling Fleet Maintenance across Intermediate and Depot level maintenance activities worldwide for the Navy. 2905 MyNavy HR The MyNavy HR Transformation Portfolio will conduct a thorough review of business processes and requirements to ensure optimal alignment with the Navy's top priorities. Following the efforts related to the Strategic Alignment, the MyNavy HR Enterprise will evaluate the appropriate resourcing required for continued Research, Development, Test and Evaluation efforts required to successfully develop, integrate and field a modernized Human Resource System for the Warfighter. MyNavy HR Transformation is not just a technology refresh of existing systems, but a holistic change to how MyNavy HR Services are provided. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                                Date: April 2026 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 5: System             PE 0605013N / Information Technology Development Development & Demonstration (SDD) This effort is the linchpin of the Navy's s Manpower, Personnel, Training & Education (MPT&E) Business IT Transformation strategy that stems from investing in programs that directly align with the Sailor 2025 vision. The current 70-year-old business processes and 40-year-old obsolete IT systems will not sustain anticipated Fleet growth and is neither cost efficient nor effective. MyNavy HR involves revolutionary change by using agile delivery model to the greatest extent possible to implement business IT products using the Industry Best Practices Model (e.g., early investment for largest ROI, rapid prototyping, and vanilla g Commercial Off The Shelf (COTS) products usage). MyNavy HR is a fully integrated portfolio of IT Systems organized into five distinct pillars: Navy Personnel and Pay (NP2), Learning Stack (LS), Enterprise Customer Relationship Management (eCRM), Single Point of Entry (SPOE), and Authoritative Data Environment (ADE). The impetus for building an adaptive family of systems is gearing MyNavy HR Transformation towards customer needs. The traditional waterfall delivery methodology of IT goods and services cannot meet the emergent requirements evolving from shortened technical obsolescence. Thus, MyNavy HR Transformation will employ an agile delivery method that is highly structured, with a repeatable software development approach designed to quickly deliver usable capability to the end user. These capabilities are packaged as Minimum Viable Products (MVPs) which are routinely delivered to the customer for their use and evaluation. Favorably received MVPs are subsequently refined and integrated into a production baseline. Rapidly integrating a family of systems using an agile methodology necessitates an overarching system integrator and coordinator to ingest pilots and prototypes into a technical baseline. MyNavy HR ITS will provide the Global Design & Strategic Planning to baseline the "55 to 1" technical execution plan and will articulate the "system of systems" baseline release. Additionally, pilots and prototypes that have reached sufficient maturity will be integrated and deployed into the production baseline. AUTHORITATIVE DATA ENVIRONMENT (ADE) The Authoritative Data Environment (ADE) is an enterprise information management system that will migrate the existing MyNavy HR legacy data warehouses into a central data repository that is composed of a data warehouse, data lake, data management tools and an Application Program Interface (API) Layer. ADE will provide an authoritative data-sharing framework, leveraging scalable and interoperable technologies as well as business intelligence and data analytic capabilities. ADE will need to interface and integrate with SPOE and all MyNavy HR transactional and business systems, including enabling 'plug & play' of new services, technologies, and system capabilities. Some of the key principles of ADE include: 1. Flexible architecture and scalable design. 2. Data Governance to produce authoritative, cleansed, conformed, consolidated, and calculated data. 3. Data Access to specified users. 4. Master Data Management (core elements, metadata tagging, business rules, standards, metrics, and tools). 5. Data analytics and business intelligence (descriptive, prescriptive, and predictive). 6. Identification, development, and maintenance of enterprise data policies. 7. Development, Security, and Operations (DevSecOps) development, test and production hosting environment that is a Rapid Assess and Incorporate Software Engineering (RAISE) Platform of Choice (RPOC) approved. ENTERPRISE CUSTOMER RELATIONSHIP MANAGEMENT (eCRM) The MyNavy HR eCRM solution supports the Navy Recruiting Command's (NRC) Applicant Relationship Management (ARM), the Navy Personnel Command's (NPC) My Navy Career Center (MNCC), the 21st Century Sailor Office's (OPNAV N17) Physical Readiness Information Management System 2 (PRIMS2) as well as Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                                 Date: April 2026 Appropriation/Budget Activity                                                        R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 5: System                  PE 0605013N / Information Technology Development Development & Demonstration (SDD) Navy Education & Training Command (NETC) and other commands that manage the Navy workforce. eCRM is a critical component of executing the Chief of Naval Personnel's vision of efficiently and effectively supporting our sailors and their families from hire to retire. The eCRM solution integrates business processes such as knowledge management, case management, performance management, and recruiting with authoritative data and automated workflows to support the Navy's recruiting efforts; manage the Navy's military workforce and their families throughout their careers; and provides Sailors access to a 24/7 service center to answer HR related questions. eCRM has quarterly program increments (PI) with two planned capability deliveries within each PI. eCRM embraces continuous integration and continuous delivery of capability, so agile teams are continuously involved in planning, development, testing, training and releasing various fixes, enhancements and features. New capabilities, change requests, hot fixes and maintenance are included in each quarterly program increment to respond to customer needs. The eCRM solution is organized by the following segments, with dedicated resources supporting each segment: 1. The Navy Personnel Command Organization which is comprised of: A. Human Resources Service Center (HRSC) - Supports the Navy's active, reserve, retiree and dependent communities around the world, with a state-of-the-art fully integrated telephony solution and 24/7 service center. B. Personnel and Pay (PERSPAY) - Supports the Navy's active, reserve, retiree and dependent communities in documenting personnel and pay actions. This occurs through direct application support and through integration and coordination with the HRSC. C. Physical Readiness Information Management System 2 (PRIMS2) - Supports the Navy physical fitness readiness through a system-of-systems leveraging MyNavy Portal (MNP), Identity, Credential and Access Management (ICAM), eCRM, and ADE. 2. The Navy Recruiting Command Organization, which is comprised of: A. Applicant Relationship Management (ARM) includes most of the tools the recruiters use each day and is also accessible from a Mobile App since 2023. B. Self-Service Application (SSA) which allows applicants to communicate directly with recruiters and share key documents. LEARNING STACK (LS) The Learning Stack will provide a cloud-based material solution that will streamline learning management (course/content delivery and assessments), capture and record interactive learning experiences, enable curriculum authoring and development, provide student Sailor registration and administration, create and regulate course/student scheduling, and offer e-learning capabilities, such as distance learning. The LS is a delivery vehicle for the following Navy Training Process (NTP) core capabilities to meet objectives of the Ready Relevant Learning (RRL) initiative: Training Delivery Learning Content Lifecycle Management Training Data Analytics & Recommendations User Experience Management Curriculum Data Management Student Information Management Course and Quota Management Integrated Scheduling The Learning Stack is one of three lines of effort that is the Navy's strategy for IT learning continuum. The other two are RRL content modernization, and the Training Network infrastructure. Collectively, these three individual efforts will cultivate instruction content that meets Fleet validated needs (ashore and afloat) and provide Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                                 Date: April 2026 Appropriation/Budget Activity                                                       R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 5: System                 PE 0605013N / Information Technology Development Development & Demonstration (SDD) keystone delivery mechanisms that will decrease training timelines, assimilate operational agility, and improve overall mission readiness. Additionally, the LS supports the MyNavy HR Transformation Program that includes yet expands beyond the RRL core initiatives identified above. In support of the broader MyNavy HR enterprise, the LS will provide a centralized, authoritative repository for Interactive Multimedia Instruction (IMI) courseware, officer and citizen development (NJROTC and ROTC candidate management), enlisted advancement exam development and distribution, enlisted degree completions, and tuition assistance authorizations. The RRL and MyNavy HR Transformation initiatives require the development of Learning Stack capabilities that permit: 1. Mobile & flexible delivery of modular training to the Sailor. 2. Synchronization of work requirements with learning modules to ensure proper training delivery. 3. Leveraging cloud-hosted capabilities to optimize the Learning Stack delivery model. NAVY PERSONNEL AND PAY (NP2) A 2015 analysis of alternatives for integration of personnel and pay capabilities recommended the use of Oracle PeopleSoft 9.2 with Global Payroll for achieving the Navy's Personnel and Pay IT needs. Follow-on analysis conducted as part of the MyNavy HR Transformation efforts in 2016 and 2017 indicated that the most cost effective approach to achieving the Transformation goals of modernizing HR Business System IT consistent with industry best practices was de-customization of the Navy Standard Integrated Personnel System (NSIPS) which uses Oracle PeopleSoft as its core technology, integration with Global Payroll, use of General Ledger to maximize auditability and accounting functions and hosting of the integrated solution. NP2 will develop and sustain the core system of systems architecture, executing pilot programs and iterative development of capabilities for Navy's MyNavy HR Transformation. The NP2 adapts and reengineers business processes to conform to the technical parameters of PeopleSoft 9.2 while integrating with the Direct to Treasury Pay Capability via Pay Modernization (Pay Mod). This combined effort will result in a minimally customizable vanilla configured Commercial Off the Shelf, cloud hosted, integrated personnel and pay solution that will provide the Navy with an IT system that is modern, highly automated, auditable, and more efficient. Implementation of NP2 will result in several key benefits: 1. Improved accuracy and auditability of personnel and pay transactions. 2. Treasury Direct Disbursing eliminating Navy reliance on the Defense Joint Military Pay System. 3. Improved permeability of Active and Reserve Components to improve accuracy and eliminate delays in pay processing when a member moves between components. 4. Increased automation of common personnel and pay transactions. 5. Integration of functionality currently spread across 55+ different adhoc and outdated HR Business Systems. SINGLE POINT OF ENTRY (SPOE) Single Point of Entry is an integrated, unified capability that includes MyNavy Portal (MNP), Mobile Applications, and Identity, Credential and Access Management (ICAM). It also includes integration with eCRM, LS, NP2, and ADE solutions. SPOE consolidates the Navy's HR portals, knowledge, and applications into a single simplified Sailor experience. Through a multi-phased modernization approach, SPOE provides an intuitive self-service capability for Sailors to view and manage their personnel and career information. It provides Active and Reserve Sailors with personalized interactive experiences and access to relevant information including learning content, HR applications, and career business processes. SPOE forms a foundational capability for the MyNavy Career Center (MNCC) by connecting its portal and ICAM functionality with eCRM. The Navy's strategy for transformation of its MyNavy HR capabilities relies on SPOE as the user-facing capability linking Sailors to modernized personnel and pay capabilities, MyNavy Training (MNT), and ADE. SPOE includes processes, capabilities, and functionalities, such as: Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                              Date: April 2026 Appropriation/Budget Activity                                                     R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 5: System               PE 0605013N / Information Technology Development Development & Demonstration (SDD) 1. Integration of capabilities to include: My Navy Portal (MNP), Mobile Applications, CRM solution, and Identity Credential Access Management (ICAM). 2. MNP A. Serve as the My NavyHR's single point of entry to Sailors HR resource. B. Provide capability to have a low bandwidth version accessible to Sailors operating in a restricted bandwidth environment C. Provide CAC-free access for Sailors accessing MNP via personal devices such as smart phones, tablets, personal laptops and computers. D. Provide solution set for disconnected Operations. E. Provide a private portal for Sailors to access personal HR information F. Provide a public presence for access to non- sensitive information. 3. ICAM A. Provide authentication and design Single Sign-On (SSO) capability for access to the objective MyNavy HR capability. 4. Mobility Program A. Maintain the ability to host and manage mobile applications through Apple/iTunes & GooglePlay app stores and host information in MyNavy HR's Navy App Locker website and mobile app (www.applocker.navy.mil). B. Provide Mobile application management suite/platform and processes for agile development and sustainment of apps' portfolio. 2951 LIPHE/System Health Lifecycle Integrated Product Health Management (HM) Environment (LIPHE) will be an Integrated Lifecycle Failure Mode (FM) & HM Data application capturing the product system design associated with system functions, failure modes, and associated HM data requirements while enabling the linkage with platform collected operational HM and maintenance data. LIPHE will be a data application that associates Failure Mode definitions and signatures, system functions, and associated HM data requirements from stakeholder sources across a program's lifecycle. LIPHE will be an application that is both consumer and provider of agnostically administering FM & HM data definitions/data across NAE programs/platforms. 2953 Model Based Product Support (MBPS) - Formerly known as Product Lifecycle Management (PLM) Logistics Information Technology (LOG-IT) modernization will provide the capability of performing integrated, real-time, data driven operational and shore logistics. LOG-IT systems must be able to operate in disconnected environments with modern, cyber-secure and auditable systems that Compress the Kill Chain. The MBPS program is major authoritative data source for LOG-IT. The MBPS program modernizes ship / submarine readiness modeling, technical data management, and configuration management IT systems to enable advanced digital twin and readiness analytics capabilities. MBPS provides capability directed by ASN RDA (IAW ASN RDA Acquisition Decision Memorandum of 5/25/2021) in support of Digital Transformation to migrate legacy LOG IT applications into an integrated Navy Product Life- Cycle Management (N-PLM) environment to include both maritime and aviation support. It will be hosted in a government-approved commercial cloud environment and used on a 24/7 basis by over 200,000 personnel assigned to 286 ships/submarines, all aircraft and over 700 shore-based activities, impacting a yearly $6.5B investment in product sustainment. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                             Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 5: System            PE 0605013N / Information Technology Development Development & Demonstration (SDD) Additional resources are required to complete MBPS capability to execute the replacement of legacy LOG IT systems into N-PLM to support Planned Maintenance, Modernization Planning, and Operational Availability reporting. Use of RDT&E funding allows for performance of engineering development, design testing, data integration, training development and cybersecurity requirements and award capability development via Other Transaction Authority or via PTC development contract to complete MBPS MVPs and align efforts with NAVAIR under PEO MLB to transition to a single Navy PLM beginning in FY23. 3026 Enterprise Resource Planning (ERP) Convergence Funding for the activities and support required for the ERP+ software upgrade of the Navy ERP system following the 2026 completion of the Navy's on-going migration of financial management (FM) data and operations to ERP Central Component (ECC). It is essential to increase readiness; enable confident and faster decision-making by providing clean, trusted data at the speed of mission; and improved user experience & business agility. 3167 Joint Technical Data Integration (JTDI) Joint Technical Data Integration (JTDI) program funding provides an enterprise common data transport solution to support the future state for Logistics IT and Readiness: Naval Product Lifecycle Management (N-PLM), Naval Supply Chain Management (N-SCM), and Integrated Data Environment (IDE). In addition to transporting authoritative technical data to maintainers in the ashore, afloat, and expeditionary environments, JTDI also automates the movement of CBM+ data generated by smart weapon systems deployed around the globe, consolidates and makes platform sensor data available for automated ingest into the Standard Data Repository, which provides modern, highly integrated analytic capabilities to enable condition-based maintenance processes. JTDI is a digital technical data access, delivery and local Organizational & Intermediate level library management toolset that improves accuracy and timeliness of weapon system repair manuals and other technical data delivery, minimizes the Fleet's library management burden, and reduces maintenance work hours with a Return on Investment of 2.5:1. Funding supports the evaluation, testing and integration to develop a JTDI Government Off-The-Shelf (GOTS) solution for installation on Carrier and Amphibious Assault class ships, the Consolidated Afloat Networks and Enterprise Services Network (CANES), and at other globally deployed Navy/Marine Corps activities. JTDI is aligned with NAVAIR LOG IT digital transformation objectives and Navy Digital Roadmap. MARINE AVIATION LOGISTICS ENTERPRISE INFORMATION TECHNOLOGY (MAL-EIT) MAL-EIT funding supports the evaluation, development, testing and integration of software and hardware solutions across all US Marine Corps Aviation activities to be used in the planning and execution of geographically distributed, expeditionary Aviation Logistics (AVLOG) chains in support of deployed USMC Air Combat Element operations. The MAL-EIT Program is one of four programs contained within the Marine Aviation Logistics Support Program (MALSP) modernization program known as MALSP II. Legacy MALSP is nearly 25 years old and grossly inadequate in IT capability to meet the informational, planning, and C2 needs of a dynamic, geographically distributed nodal AVLOG system. MAL-EIT is a Defense Business System Abbreviated Acquisition Program that will develop and deliver the required IT capability necessary to eliminate the IT related gaps existing in the legacy MALSP. MAL-EIT is a family of IT solutions to be developed and delivered in three increments. These increments are depicted below: Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                                     Date: April 2026 Appropriation/Budget Activity                                                      R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 5: System                PE 0605013N / Information Technology Development Development & Demonstration (SDD) EXPENDITIONARY PACK UP KIT (EPUK) Provides Expeditionary Supply Operations to include business administration, inventory, and customer service operations. NEXT GENERATION BUFFER MANAGEMENT SYSTEM Provides buffer management in a time domain, and buffer sizing analysis. LOGISTICS PLANNING TOOL AND OPTIMIZER TOOL Provides capability to develop tailored Remote Expeditionary Support Packages, consumption forecasts, and Nodal Logistics Lay down designs. 9406 Maintenance Data Warehouse Maintenance Data Warehouse funds the Naval Aviation Enterprise (NAE) components, in coordination with Navy LOG-IT, of digital transformation, which is a critical component of improving readiness, giving Navy users access to authoritative truth data and automating inefficient manual processes. It will be executed in a fully agile manner providing continuous fleet readiness improvements. The initial configuration will be supported with an agile Minimal Viable Product (MVP) as the foundation for continuous capability introduction. AVIATION LOGISTICS ENVIRONMENT (ALE) The Aviation Logistics Environment (ALE) will provide a seamless environment to support the integration of the other capabilities developed in Maintenance Data Warehouse. Aviation Logistics Environment (ALE) provides a global logistics enterprise solution, delivering capabilities via a net-centric, shared data environment that supports shore-based, afloat, and expeditionary operations. ALE consists of three components: Ground Station, Aviation PLM, and Enterprise Service Bus (ESB). The Maintenance Engineering Ground Station for Aviation (MEGA) is the Naval Aviation Type/Model/Series (T/M/S)-agnostic ground station. MEGA is currently under development using Government off-the-Shelf (GOTS) software and PLM/ESB is configuring Commercial off-the-Shelf (COTS). The Aviation Product Lifecycle Management (Aviation PLM) capability will provide the digital thread of aviation logistics data for allowable and as-configured Repair Bill of Materials (R BOM) sustainment, technical bulletins, technical directives and engineering change proposals, and reliability centered maintenance and maintenance planning. The Enterprise Service Bus (ESB) capability will provide the digital backbone for data connections to and from authoritative data sources. ALE consolidates aging, near-end-of-life systems, and applications and aligns Information Assurance (IA) and cybersecurity requirements. AVIATION DATA WAREHOUSE/DECISION KNOWLEDGE PROGRAMMING FOR LOGISTICS ANALYSIS AND TECHNICAL EVALUATION (DECKPLATE) The next generation data warehouse containing over 30 years of aircraft maintenance, flight, components, and usage data. Through the use of web-based, commercial off the shelf software for data load, analysis, query, and reporting tools, the user has the capabilities to effectively obtain readiness data in a near real-time environment, as well as providing historical data for long range planning, trend and records analysis, records reconstruction, and compliance with technical directives. DECKPLATE supports the mission of the warfighter who requires a single source of near real-time aviation data in which to base critical readiness decisions. DECKPLATE collects data from authoritative sources, such as the fleet maintenance systems, into a data warehouse. To provide the warfighter with a common view of Logistics IT data, Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                                Date: April 2026 Appropriation/Budget Activity                                                     R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 5: System               PE 0605013N / Information Technology Development Development & Demonstration (SDD) the time-consuming tasks of collecting, extracting, transforming, and loading source data will enable a federated data view that will reduce and ultimately eliminate duplicative and manual processes, while providing visibility and access to trusted data for decision support. This also accomplishes a reduction in legacy systems mandated by Office of the Chief of Naval Operations. DECKPLATE manages total inventory for two major categories of assets, Aircraft (General Equipment) and Engine/Propulsion Systems/Modules (EPSMs) (Operating Materials & Supply). DECKPLATE is comprised of the transactional Aircraft Inventory and Readiness Reporting (DECK-AIRRS) and the Engine Transaction Reporting (DECK-ETR) subsystems, which provide the complete lifecycle for aircraft and Engine/ Propulsion System/Modules (EPSMs). DECKPLATE has been identified as a level 1 financial feeder system due to the value of the aircraft and EPSM's managed in the system and continues to respond to audit compliance and Cyber Security mandates. DECKPLATE is a core feeder system to numerous NAVAIR efforts. VECTOR Supports the development of a common logistics analytical tool suite, which provides a single view of data and insights focused on aircraft readiness, maintenance, supply, cost, and man-hours. Vector provides naval aviation with a common view of approved key performance metrics and the capability to perform multi-system analysis of Ready for Tasking (RFT)/Ready Basic Aircraft (RBA) Gap drivers, 'Top-Down' aircraft systems analysis down to the component level. Vector identifies system performance trends early to mitigate future readiness and cost impacts to the fleet. This is critical for fleet understanding of readiness degraders and issue resolution.$$, $$Budget J-Books/FY27/Navy/RDTEN_BA5_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605018A$$, $$Integrated Personnel and Pay System-Army (IPPS-A)$$, $$rdte_army_ba5$$, $$army_ng$$, 2026, 164600000, 86914000, 121354000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "army", "page_num": 17, "original_pe": "0605018A", "page_header": "Department of the Army"}$$::jsonb, $$The Integrated Personnel and Pay System-Army Increment II (IPPS-A Inc II) provides an integrated, multi-Component, personnel and pay system that streamlines existing Human Resources (HR) systems and processes by enhancing efficiency and accuracy of personnel and pay procedures in support of 1.1 million Soldiers. This program is an essential building block to reform the Department of the Army towards achieving greater performance and affordability in support of the National Defense Strategy and the Congressional audit mandate. The IPPS-A program to date has completed a phased deployment of Military Human Resource and talent management capabilities across all Army components (Active, Guard and Reserve). This includes all Army National Guard units in the 54 states and territories into one single solution. The program has subsumed 120 systems/ instances and six partial capabilities bringing the Army's total military force into a single HR authoritative system. In accordance with the Acquisition Strategy approved by the Army Acquisition Executive on 21 June 2022, the program office will incrementally release Army Military Payroll, additional Human Resource (HR) Capabilities (e.g., Archiving, Talent and Strength Management, and Audit), and HR Enhancements to the deployed baseline. In 4QFY24, IPPS-A began migration from the legacy infrastructure hosting solution with Defense Information Systems Agency (DISA) to a Cloud Hosting solution. As part of our transition from Waterfall Development to an Agile Development Framework, the program is transitioning to the Software Acquisition Pathway. In 1QFY25, the program awarded the Solution Provider bridge contract to enable competition for the new Product Support and Delivery contract to be awarded in 1QFY26 that provides maintenance and system enhancements enabling subsumption of legacy systems. FY 2026 Base dollars in the amount of $164.600 million supports Agile software development and incremental delivery of additional capabilities for Army Military Payroll as well as additional HR capabilities to enable subsumption of 18 full and four partial additional legacy systems. These funds will continue cloud migration prior to the legacy DISA infrastructure end of life in FY28. These critical investments support the Army to be audit ready and achieve cost savings through cloud migration, legacy system subsumption and delivery of the Army Military Payroll capability. Funds also support other enabling infrastructure and software upgrades to include support for Identity, Credential, Access Management (ICAM) implementation achieving zero-trust compliance. In 1QFY26, the program will award the new Product Support and Delivery contract that provides maintenance and system enhancements enabling subsumption of legacy systems. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                                  Date: June 2025 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 5: System              PE 0605018A / Integrated Personnel and Pay System-Army (IPPS-A) Development & Demonstration (SDD)$$, NULL, 81269000, 107470000, 88571000, NULL, NULL, 131, $$RDTE - Vol 3 - Budget Activity 5C.pdf$$, NULL, FALSE, 116925000, 160912000, 102694000, 102694000, NULL, 102694000, 89454000, $$The Integrated Personnel and Pay System-Army Increment II (IPPS-A Inc II) provides an integrated, multi-Component, personnel and pay system that streamlines existing Human Resources (HR) systems and processes by enhancing efficiency and accuracy of personnel and pay procedures in support of 1.1 million Soldiers. This program is an essential building block to reform the Department of the Army towards achieving greater performance and affordability in support of the National Defense Strategy and the Congressional audit mandate. The IPPS-A program to date has completed a phased deployment of Military Human Resource and talent management capabilities across all Army components (Active, Guard and Reserve). This includes all Army National Guard units in the 54 states and territories into one single solution. The program has contributed to the retirement of 28 of 54 legacy systems, bringing the Army's total military force into a single HR authoritative system. In accordance with the Acquisition Strategy approved by the Army Acquisition Executive on 21 June 2022, the program office continues incremental releases supporting Army Military Payroll (AMP), additional Human Resource (HR) Capabilities (e.g., Archiving, Talent and Strength Management, and Audit), and HR Enhancements. As of this submission, planning is underway with Defense Finance and Accounting Service (DFAS) to support the recent (February 2026) Department-wide decision to align Military Pay Modernization and Integration. The current planning efforts aim to coordinate the Department's Military Pay objectives and priorities before shaping the existing and future Army core HR and Pay capabilities. Based on the initial planning guidance, previously submitted Active Component (AC) and Reserve Component (RC) Pay delivery timeline in FY27 and FY28, respectively, have been removed pending the outcome of Military Pay Modernization and Integration planning outcome. In 4QFY24, IPPS-A began migration from the legacy infrastructure hosting solution with Defense Information Systems Agency (DISA) to a Cloud Hosting solution. The program continues transitioning to the Software Acquisition Pathway. In 1QFY25, the program awarded the Solution Provider bridge contract to enable competition for the new Product Support and Delivery contract known as MAHC III (Managing Army's Human Capital - Innovation, Integration, and Implementation). MAHC III was awarded in 2QFY26, which provides maintenance and system enhancements enabling subsumption of legacy systems. In 3QFY25 an online form was released that provides a Certificate of Release or Discharge from Active Duty (DD 214), allowing for the subsumption of the Retirement Points Accounting Management (RPAM) system, a National Guard legacy system. In FY26, the program transitioned to the Software Acquisition Pathway and is accelerating the subsumption of 12 legacy systems to align with the DBS 1-N Portfolio Divesture plan. Additionally, the AMP Death Gratuity capability was released in 2QFY26, Adoption Expense reimbursement is scheduled for release in 3QFY26, and Temporary Lodging Assistance for 4QFY26. FY 2027 dollars in the amount of $102.694 million supports modernization and sustainment of the HR baseline system, pay integration, agile software development and incremental delivery of additional HR capabilities to enable subsumption of additional legacy systems. These funds will continue cloud migration prior to the legacy DISA infrastructure end of life in FY28. These critical investments support the Army to be audit ready and achieve cost savings through cloud migration, legacy Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                              Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 5: System            PE 0605018A / Integrated Personnel and Pay System-Army (IPPS-A) Development & Demonstration (SDD) system subsumption and delivery of HR capabilities. Funds further support other enabling infrastructure and software upgrades to include Identity, Credential, Access Management (ICAM) implementation achieving zero-trust compliance.$$, $$Budget J-Books/FY27/Army/RDTEVol3BudgetActivity5C.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605021SE$$, $$Homeland Personnel Security Initiative$$, $$rdte_dw_ba5$$, $$dw_dhra$$, 2026, 9137000, 7292000, 9526000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "dw", "page_num": 74, "original_pe": "0605021SE", "page_header": "Defense-Wide"}$$::jsonb, NULL, NULL, 9519000, 9701000, 9893000, NULL, NULL, NULL, NULL, NULL, FALSE, 9526000, 9137000, 9334000, 9334000, NULL, 9334000, 10091000, $$The Defense Human Resources Activity (DHRA) is a Defense-wide Field Activity chartered to support the Under Secretary of War for Personnel and Readiness (USW(P&R)). RDT&E funds are applied to research security and standards compliance improvements for the Common Access Card (CAC) and the Uniformed Services Identification (USID) card, which provides identification for personnel not eligible for the CAC and for dependents. Funding for the Identity Credential Management (ICM) program supports the DoW Chief Information Officer’s Identity, Credential and Access Management (ICAM) initiatives and the modernization of the identity management and credentialing systems.$$, $$Budget J-Books/FY27/DW/RDTE_DHRA_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605024A$$, $$Anti-Tamper Technology Support$$, $$rdte_army_ba7$$, $$afc$$, 2026, 6449000, 7274000, 7489000, NULL, $${"act": "07", "ba_raw": "6.7", "source": "r1_fy26", "service": "army", "page_num": 21, "original_pe": "0605024A", "page_header": "Department of the Army"}$$::jsonb, $$Anti-Tamper (AT) Technology Support. The Protective Technologies (PT) organization is the Army's Lead Technical Agent for the DoD AT program, which is focused on preventing exploitation reverse engineering (RE) of U.S. systems lost or captured on the battlefield or sold via Foreign Military Sales (FMS) or Direct Commercial Sales (DCS). In support of this mission, PT's classified efforts are focused on independent AT Validation and Verification (V&V) activities with Army programs, AT/RE Lab facilities and equipment and AT/RE Lab assessments. This program element funds these efforts for the U.S. Army. Work in this Project is performed by the United States Army Futures Command (AFC), U.S. Army Combat Capabilities Development Command (DEVCOM), Aviation & Missile Center (AvMC), Redstone Arsenal, AL. The FY 2026 request was reduced by $0.772 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative."$$, NULL, 6817000, 6951000, 7074000, NULL, NULL, 200, $$RDTE - Vol 4 - Budget Activity 7.pdf$$, NULL, FALSE, 7300000, 8449000, 6613000, 6613000, NULL, 6613000, 7142000, $$Anti-Tamper (AT) Technology Support. The Protective Technologies (PT) organization is the Army's Lead Technical Agent for the DoW AT program, which is focused on preventing exploitation reverse engineering (RE) of U.S. systems lost or captured on the battlefield or sold via Foreign Military Sales (FMS) or Direct Commercial Sales (DCS). In support of this mission, PT's classified efforts are focused on independent AT Validation and Verification (V&V) activities with Army programs, AT/RE Lab facilities and equipment and AT/RE Lab assessments. This program element funds these efforts for the U.S. Army to implement DoDD 5200-47e and AR 70-77. Work in this Project is performed by the United States Army Futures Command (AFC), U.S. Army Combat Capabilities Development Command (DEVCOM), Aviation & Missile Center (AvMC), Redstone Arsenal, AL.$$, $$Budget J-Books/FY27/Army/RDTE - Vol 4 - Budget Activity 7.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605024N$$, $$Anti-Tamper Technology Support$$, $$rdte_navy_ba5$$, $$asn_rda$$, 2026, 3428000, 8314000, 3317000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "navy", "page_num": 34, "original_pe": "0605024N", "page_header": "Department of the Navy"}$$::jsonb, $$Develops new and novel Anti-Tamper technologies for all Department of Navy weapon and combat systems. The technologies to be developed will be new countermeasures to prevent reverse engineering of critical U.S. military systems. The technologies include secure processing, sensors, architecture components, and enabling technologies. This program is funded under SYSTEM DEVELOPMENT AND DEMONSTRATION because it includes those projects that have passed Milestone B approval and are conducting engineering and manufacturing development tasks aimed at meeting validated requirement prior to full-rate production decision.$$, NULL, 3550000, 3624000, 3671000, NULL, NULL, 162, $$RDTEN_BA5_Book.pdf$$, NULL, FALSE, 3304000, 3428000, 3459000, 3459000, NULL, 3459000, 3740000, $$Develops new and novel Anti-Tamper technologies for all Department of Navy weapon and combat systems. The technologies to be developed will be new countermeasures to prevent reverse engineering of critical U.S. military systems. The technologies include secure processing, sensors, architecture components, and enabling technologies. This program is funded under SYSTEM DEVELOPMENT AND DEMONSTRATION because it includes those projects that have passed Milestone B approval and are conducting engineering and manufacturing development tasks aimed at meeting validated requirement prior to full-rate production decision.$$, $$Budget J-Books/FY27/Navy/RDTEN_BA5_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605030A$$, $$Joint Tactical Network Center (JTNC)$$, $$rdte_army_ba5$$, $$dw_js$$, 2026, 20954000, 17981000, 20191000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "army", "page_num": 17, "original_pe": "0605030A", "page_header": "Department of the Army"}$$::jsonb, $$This program aligns with Army 2030/40 priorities. This funding supports Joint and Next Generation Command and Control (NGC2) initiatives to modernize Command and Control (C2) systems. The Joint Tactical Networking Center (JTNC) is chartered to enable the Department of Defense (DoD)'s rapid identification, characterization, procurement, fielding, and sustainment of modular, innovative tactical communications products that ensure secure, interoperable, and resilient Command, Control, Communications, Computers, Intelligence, Surveillance, and Reconnaissance (C4ISR) capabilities. The JTNC provides technical expertise to facilitate tactical communications management, innovation, and standardization. The JTNC: (1) maintains a cyber-hardened DoD Information Repository (IR), (2) provides Technical Analyses/Capability Characterizations on tactical communications products, (3) provides Open Systems Architecture Standards, (4) provides exportability analysis and licensing reviews, and (5) serves as Technical Advisor to the Communications, Command, and Control Leadership Board (C3LB) and Tactical Communications Senior Steering Group (TCSSG). JTNC mission is executed in coordination with key government stakeholders to include: C3LB, TCSSG, Communications Technologies and Waveforms Working Group (CTWWG), Resiliency Sub-Working Group (RSWG), the Department of Defense (DoD) Chief Information Officer (CIO), Under Secretary of Defense for Acquisition and Sustainment (USD(A&S)), Joint Staff J6 (JS J6), the Under Secretary of Defense for Research and Engineering USD(R&E), and the Services. Particular attention is paid to ensuring that interagency work is collaborative and eliminates duplicative capability. The JTNC enables a common software baseline that is hardware agnostic leading to increased competition for Software Defined Radios (SDR). Current JTNC directed requirements, outlined by the C3LB, consist of the CTWWG, Joint All-Domain Command and Control (JADC2) support, development/maturation of the DoD IR framework & Cloud migration, and development of the Joint Communications Marketplace (JCM) to meet DoD and Industry requirements in conjunction with DoD Instruction 4630.09. Through collaboration with USD R&E (INSS) and industry partners, JTNC is in the process of capturing information on resilient waveform Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                                 Date: June 2025 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 5: System              PE 0605030A / Joint Tactical Network Center (JTNC) Development & Demonstration (SDD) technologies and portfolio products. The ultimate goal is to expedite market research activities by collecting, analyzing, and making data available in support of emerging Government waveform acquisitions. The JTNC and Joint Interoperability Test Command (JITC) co-chair the High-Frequency Interoperability and Architecture Sub- Working Group (HF I&A SWG) to resolve HF 3G and 4G interoperability issues, thus facilitating next-generation HF systems. The JTNC HF team is also pathfinding for a new tactical MIL-STD to provide more resilient communications. Additionally, the JTNC is engaged in the analysis of software artifacts involving high assurance devices, such as Software Defined Radios (SDR) ported with specific waveforms to support National Security Agency (NSA) efforts. The JTNC participates in Standards-related activities such as the Interface Control Working Group (ICWG) and has been collaborating with the Army on the development of C4ISR/Electronic Warfare Modular Open Suite of Standards (CMOSS) specifications. Finally, the JTNC continues evolving its Waveform Assessment and Milestone Review (WASMR) and Capability Characterization processes. The FY 2026 request was reduced by $0.167 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative."$$, NULL, 22140000, 22662000, 21857000, NULL, NULL, 132, $$RDTE - Vol 3 - Budget Activity 5C.pdf$$, NULL, FALSE, 19454000, 20954000, 21561000, 21561000, NULL, 21561000, 22075000, $$This funding supports Joint and Next Generation Command and Control (NGC2) initiatives to modernize Command and Control (C2) systems. The Joint Tactical Networking Center (JTNC) is chartered to enable the Department of War (DoW)'s rapid identification, characterization, procurement, fielding, and sustainment of modular, innovative tactical communications products that ensure secure, interoperable, and resilient Command, Control, Communications, Computers, Intelligence, Surveillance, and Reconnaissance (C4ISR) capabilities. The JTNC provides technical expertise to facilitate tactical communications management, innovation, and standardization. The JTNC: (1) maintains a cyber-hardened DoW Information Repository (IR), (2) provides Technical Analyses/Capability Characterizations on tactical communications products, (3) provides Open Systems Architecture Standards, (4) provides exportability analysis and licensing reviews, and (5) serves as Technical Advisor to the Communications, Command, and Control Leadership Board (C3LB) and Tactical Communications Senior Steering Group (TCSSG). JTNC mission is executed in coordination with key government stakeholders to include: C3LB, TCSSG, Communications Technologies and Waveforms Working Group (CTWWG), Resiliency Sub-Working Group (RSWG), the Department of War (DoW) Chief Information Officer (CIO), Under Secretary of War for Acquisition and Sustainment (USW(A&S)), Joint Staff J6 (JS J6), the Under Secretary of War for Research and Engineering USW(R&E), and the Services. Particular attention is paid to ensuring that interagency work is collaborative and eliminates duplicative capability. The JTNC enables a common software baseline that is hardware agnostic leading to increased competition for Software Defined Radios (SDR). Current JTNC directed requirements, outlined by the C3LB, consist of the CTWWG, Joint All-Domain Command and Control (JADC2) support, development/maturation of the DoW IR framework & Cloud migration, and development of the Joint Communications Marketplace (JCM) to meet DoW and Industry requirements in conjunction with DoW Instruction 4630.09. Through collaboration with USW R&E (INSS) and industry partners, JTNC is in the process of capturing information on resilient waveform technologies and portfolio products. The ultimate goal is to expedite market research activities by collecting, analyzing, and making data available in support of emerging Government waveform acquisitions. The JTNC and Joint Interoperability Test Command (JITC) co-chair the High-Frequency Interoperability and Architecture Sub- Working Group (HF I&A SWG) to resolve HF 3G and 4G interoperability issues, thus facilitating next-generation HF systems. The JTNC HF team is also pathfinding for a new tactical MIL-STD to provide more resilient communications. Additionally, the JTNC is engaged in the analysis of software artifacts involving high assurance devices, Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                           Date: April 2026 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 5: System           PE 0605030A / Joint Tactical Network Center (JTNC) Development & Demonstration (SDD) such as Software Defined Radios (SDR) ported with specific waveforms to support National Security Agency (NSA) efforts. The JTNC participates in Standards-related activities such as the Interface Control Working Group (ICWG) and has been collaborating with the Army on the development of C4ISR/Electronic Warfare Modular Open Suite of Standards (CMOSS) specifications. Finally, the JTNC continues evolving its Waveform Assessment and Milestone Review (WASMR) and Capability Characterization processes.$$, $$Budget J-Books/FY27/Army/RDTEVol3BudgetActivity5C.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605031A$$, $$Joint Tactical Network (JTN)$$, $$rdte_army_ba5$$, $$asa_alt$$, 2026, 41696000, 29221000, 31214000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "army", "page_num": 17, "original_pe": "0605031A", "page_header": "Department of the Army"}$$::jsonb, $$This funding supports Joint and Next Generation Command and Control (NGC2) initiatives to modernize Command and Control (C2) systems. EF5 project: The Joint Enterprise Network Manager (JENM) / Joint Network Management Software for Radio Terminals provides a single, converged network management tool allowing the Warfighter to plan, configure, load, and manage the Joint Services' Tactical Radios and their networks in the field - a capability not available in legacy planning systems. Funding supports the full suite of Software defined radios across the services, enabling them to utilize Mobile Ad Hoc Networking (MANET) and other waveforms to include: Mobile User Objective System (MUOS), TrellisWare Scalable Manet (TSM), Warrior Robust Enhanced Network (WREN), Warrior Robust Enhanced Network-Narrowband (WREN-NB), Demand Assigned Multiple Access (DAMA) Satellite Communications (SATCOM), Integrated Waveform (IW), VHF-UHF Line Of Sight (VULOS), Second Generation Antijam Tactical UHF Radio for NATO (SATURN) and Single Channel Ground and Airborne Radio System (SINCGARS) waveform. The Network Management Software provides the Commander the ability to quickly reconfigure critical networks and enhances the S6's ability to conduct Course of Action (COA) Analysis and the Military Decision-Making Process (MDMP), providing commanders critical information regarding their ability to communicate. EX6 project: Waveforms provides the transport technologies and capabilities necessary to support the overall connectivity of the Unified Network. Waveforms technology assessments, integration, and configuration management enable seamless updates and fluid communication between echelons of the Unified Network. Waveforms delivers, maintains, and upgrades portable, interoperable, MANET waveforms, Advanced Networking Waveforms (ANWf), and network enterprise services in support of the Army's network modernization strategy. Waveforms capabilities will remain agile to accommodate emerging warfighter needs by addressing the following: (1) Waveform (WF) analysis and system engineering activities for DoD as Lead Service Activity for Ground/Line of Sight (LoS) Waveforms (currently TSM, WREN, and SINCGARS) in accordance with DoD Instruction 4630.09, Communications Waveform Management and Standardization, 23 November 2020. (2) Development and/or integration efforts of Broadcast Waveforms (i.e. SINCGARS, WREN, ANWf) and Radio Services (i.e. enterprise Over The Air Management (eOTAM)) in support of Army Network modernization, and agile mission support initiatives. (3) Viability assessments of ANWf in support of the Integrated Tactical Network (ITN) and future capability sets to ensure waveform performance in advance of formal ITN experimentation and fielding activities. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                             Date: June 2025 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 5: System           PE 0605031A / Joint Tactical Network (JTN) Development & Demonstration (SDD) FY 2025 RDT&E dollars will fund the continued development, integration, and testing of new capabilities and waveform enhancements for SINCGARS, WREN, TSM, and ANWf. As well as fund the next generation Government developed waveforms and Radio Service applications, system and architectural engineering for ANWf radio communications technologies, post deployment software support for fielded versions of the waveforms and radio services, program management support, and examine modular and open system architectures (MOSA) to for future integration and waveform porting efficiencies. The FY 2026 request was reduced by $0.564 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative."$$, NULL, 51198000, 45024000, 38791000, NULL, NULL, 133, $$RDTE - Vol 3 - Budget Activity 5C.pdf$$, NULL, FALSE, 30075000, 41696000, 50390000, 50390000, NULL, 50390000, 39177000, $$EF5 project: The Joint Enterprise Network Manager (JENM) / Joint Network Management Software for Radio Terminals (JNMSRT) provides a single, converged network management tool allowing the Warfighter to plan, configure, load, and manage the Joint Services' Tactical Radios and their networks in the field - a capability not available in legacy planning systems. Funding supports the full suite of Software defined radios across the services, enabling them to utilize Mobile Ad Hoc Networking (MANET) and other waveforms to include: Mobile User Objective System (MUOS), TrellisWare Scalable Manet (TSM), Warrior Robust Enhanced Network (WREN), Warrior Robust Enhanced Network-Narrowband (WREN-NB), Demand Assigned Multiple Access (DAMA) Satellite Communications (SATCOM), Integrated Waveform (IW), VHF-UHF Line Of Sight (VULOS), Second Generation Antijam Tactical UHF Radio for NATO (SATURN) and Single Channel Ground and Airborne Radio System (SINCGARS) waveform. The Network Management Software provides the Commander the ability to quickly reconfigure critical networks and enhances the S6's ability to conduct Course of Action (COA) Analysis and the Military Decision-Making Process (MDMP), providing commanders critical information regarding their ability to communicate. EX6 project: PdM Waveforms' mission has been realigned to PdM Tactical Communication Systems (TCS). The program office provides the transport technologies and capabilities necessary to support the overall connectivity of the Unified Network. Waveforms technology assessments, integration, and configuration management enable seamless updates and fluid communication between echelons of the Unified Network. The program office delivers, maintains, and upgrades portable, interoperable, MANET waveforms, Advanced Networking Waveforms (ANWf), and network enterprise services in support of the Army's network modernization strategy. Waveforms capabilities will remain agile to accommodate emerging warfighter needs by addressing the following: (1) Waveform (WF) analysis and system engineering activities for DoW as Lead Service Activity for Ground/Line of Sight (LoS) Waveforms (currently TSM, WREN, and SINCGARS) in accordance with DoD Instruction 4630.09, Communications Waveform Management and Standardization, 23 November 2020. (2) Development and/or integration efforts of Broadcast Waveforms (i.e. SINCGARS, WREN, ANWf) and Radio Services (i.e. enterprise Over The Air Management (eOTAM)) in support of Army Network modernization, and agile mission support initiatives. (3) Viability assessments of ANWf in support of the Integrated Tactical Network (ITN) and future capability sets to ensure waveform performance in advance of formal ITN experimentation and fielding activities. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                              Date: April 2026 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 5: System             PE 0605031A / Joint Tactical Network (JTN) Development & Demonstration (SDD) FY 2027 RDT&E funds will be allocated to the continued development, integration, and testing of advanced capabilities supporting waveform enhancements for tactical communications systems such as SINCGARS, WREN, TSM, and ANWf. Key initiatives will focus on next-generation waveforms, creating innovative radio service applications, and performing detailed system and architectural engineering. These efforts will leverage a Modular Open Systems Approach (MOSA) to ensure future porting efficiencies and adaptability. In alignment with the JNMSRT Memorandum of Agreement, FY2027 RDT&E funding will also continue to support the ongoing design, engineering, and testing of network management capabilities for the Tactical Radio network. This will ensure full interoperability across Joint Service Networks and emerging systems. The primary deliverable will be mission-critical planning applications designed for modular, cross-platform deployment. These applications will be integrated with the Ruggedized Application Platform - Tactical Radios (RAP-TR) and engineered to support future systems, enabling Soldiers to effectively manage and control their tactical communications.$$, $$Budget J-Books/FY27/Army/RDTEVol3BudgetActivity5C.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605031F$$, $$Joint Tactical Network (JTN)$$, $$rdte_af_ba5$$, $$aflcmc_hn$$, 2026, 0, 452000, 0, NULL, $${"ba_raw": "6.5", "source": "af_r1_fy26", "original_pe": "0605031F"}$$::jsonb, $$EF5 project: The Joint Enterprise Network Manager (JENM) / Joint Network Management Software for Radio Terminals provides a single, converged network management tool allowing the Warfighter to plan, configure, load, and manage the Joint Services' Tactical Radios and their networks in the field - a capability not available in legacy planning systems. Funding supports the full suite of Software defined radios across the services, enabling them to utilize Mobile Ad Hoc Networking (MANET) and other waveforms to include: Mobile User Objective System (MUOS), TrellisWare Scalable Manet (TSM), Warrior Robust Enhanced Network (WREN), Warrior Robust Enhanced Network-Narrowband (WREN-NB), Demand Assigned Multiple Access (DAMA) Satellite Communications (SATCOM), Integrated Waveform(IW), VHF-UHF Line Of Sight (VULOS), Second Generation Antijam Tactical UHF Radio for NATO (SATURN) and Single Channel Ground and Airborne Radio System (SINCGARS) waveform. The Network Management Software provides the Commander the ability to quickly reconfigure critical networks and enhances the S6's ability to conduct Course of Action (COA) Analysis and the Military Decision-Making Process (MDMP), providing commanders critical information regarding their ability to communicate. EX6 project: Waveforms provides the transport technologies and capabilities necessary to support the overall connectivity of the Unified Network. Waveforms technology assessments, integration, and configuration management enable seamless updates and fluid communication between echelons of the Unified Network. Waveforms delivers, maintains, and upgrades portable, interoperable, MANET waveforms, Advanced Networking Waveforms (ANWf), and network enterprise services in support of the Army's network modernization strategy. Waveforms capabilities will remain agile to accommodate emerging warfighter needs by addressing the following: Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                        Date: June 2025 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 5: System        PE 0605031F / Joint Tactical Network (JTN) Development & Demonstration (SDD) (1) Waveform (WF) analysis and system engineering activities for DoD as Lead Service Activity for Ground/Line of Sight (LoS) Waveforms (currently TSM, WREN, and SINCGARS) in accordance with DoD Instruction 4630.09, Communications Waveform Management and Standardization, 23 November 2020. (2) Development and/or integration efforts of Broadcast Waveforms (i.e. SINCGARS, WREN, ANWf) and Radio Services (i.e. enterprise Over The Air Management (eOTAM)) in support of Army Network modernization, and agile mission support initiatives. (3) Viability assessments of ANWf in support of the Integrated Tactical Network (ITN) and future capability sets to ensure waveform performance in advance of formal ITN experimentation and fielding activities. FY 2026 RDT&E dollars will fund the continued development, integration, and testing of new capabilities and waveform enhancements for SINCGARS, WREN, TSM, and ANWf. As well as fund the next generation Government developed waveforms and Radio Service applications, system and architectural engineering for ANWf radio communications technologies, post deployment software support for fielded versions of the waveforms and radio services, program management support, and examine modular and open system architectures (MOSA) to for future integration and waveform porting efficiencies. This program is in Budget Activity 5, System Development and Demonstration (SDD) because it has passed Milestone B approval and is conducting engineering and manufacturing development tasks aimed at meeting validated requirements prior to full rate production.$$, NULL, NULL, NULL, NULL, NULL, NULL, 99, $$FY26 Air Force Research and Development Test and Evaluation Vol II.pdf$$, NULL, FALSE, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605035A$$, $$Common Infrared Countermeasures (CIRCM)$$, $$rdte_army_ba5$$, $$peo_aviation$$, 2026, 10789000, 10959000, 11691000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "army", "page_num": 17, "original_pe": "0605035A", "page_header": "Department of the Army"}$$::jsonb, $$This funding line is a key enabler of the Army Modernization Priorities in support of the Aircraft Survivability Equipment (ASE) program. The Common Infrared Countermeasure (CIRCM) budget line includes funding to support the development and integration of Aircraft Survivability Equipment (ASE) products onto rotary wing and fixed wing aircraft. CIRCM (EB4) CIRCM is the next generation lightweight, laser-based Infrared Countermeasure (IRCM) component that will interface with the Army's Common Missile Warning System (CMWS), Limited Interim Missile Warning System (LIMWS), Advanced Threat Warner (ATW), and future Improved Threat Detection System (ITDS) to defeat current and emerging missile threats that use multispectral technology for rotary-wing, tilt-rotor and small fixed-wing aircraft across the DoD. CIRCM receives an angular bearing hand-off from the MWS, employs a pointing and tracking system which acquires the handed-over threat and tracks the incoming missile during and after motor burnout. CIRCM jams the missile by using modulated laser energy in the missile seeker band, thus degrading the tracking capability of the missile and causing it to miss the aircraft. CIRCM is utilizing Open Systems Architecture which allows flexibility with software and hardware refreshes. Tech insertions, when coupled with future threat acquisition and integration, will ensure CIRCM performance to keep pace with future threats. CIRCM is part of the suite of ASE Mission Equipment for Future Long Range Assault Aircraft (FLRAA). The CIRCM A-Kit includes mounting hardware, wiring harnesses, and other components necessary to install and interface the mission kit on host aircraft. The A- Kit ensures the mission kit is functionally and physically operational with a specific host aircraft type. The CIRCM B-Kit is the mission kit (laser, pointer tracker, and processor) required to achieve near spherical coverage for an aircraft. Fiscal Year (FY) 2026 Base Research, Development, Test, and Evaluation (RDTE) funding in the amount of $10.789 million will fund A-Kit development, integration and test activities on multi-variant platforms, acquiring additional B-Kit test Line Replaceable Units (LRUs) in the support of development / testing activities, as well as threat and vulnerability analysis. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                  Date: June 2025 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 5: System        PE 0605035A / Common Infrared Countermeasures (CIRCM) Development & Demonstration (SDD)$$, NULL, 11827000, 11880000, 11811000, NULL, NULL, 134, $$RDTE - Vol 3 - Budget Activity 5C.pdf$$, NULL, FALSE, 11261000, 12789000, 11573000, 11573000, NULL, 11573000, 12006000, $$CIRCM (EB4) CIRCM is the next generation lightweight, laser-based Infrared Countermeasure (IRCM) component that interfaces with the Army's Common Missile Warning System (CMWS), Limited Interim Missile Warning System (LIMWS), Advanced Threat Warner (ATW), and future Improved Threat Detection System (ITDS) to defeat current and emerging missile threats that use multispectral technology for rotary-wing, tilt-rotor and small fixed-wing aircraft across the Department of War (DoW). CIRCM receives an angular bearing hand-off from the Missile Warning System (MWS), employs a pointing and tracking system which acquires the handed-over threat and tracks the incoming missile during and after motor burnout. CIRCM jams the missile by using modulated laser energy in the missile seeker band, thus degrading the tracking capability of the missile and causing it to miss the aircraft. CIRCM is utilizing Open Systems Architecture which allows flexibility with software and hardware refreshes. Tech insertions, when coupled with future threat acquisition and integration, will ensure CIRCM performance to keep pace with future threats. CIRCM is part of the suite of Aircraft Survivability Equipment (ASE) Mission Equipment for Multi-Mission Vertical Takeoff (MV)-75 Future Long-Range Assault Aircraft (FLRAA). The CIRCM A-Kit includes mounting hardware, wiring harnesses, and other components necessary to install and interface the mission kit on host aircraft. The A- Kit ensures the mission kit is functionally and physically operational with a specific host aircraft type. The CIRCM B-Kit is the mission kit (laser, pointer tracker, and processor) required to achieve near spherical coverage for an aircraft. Fiscal Year (FY) 2027 Research, Development, Test, and Evaluation (RDTE) funding will fund A-Kit development, integration and test activities on multi-variant platforms, acquiring additional B-Kit test Line Replaceable Units (LRUs) to support development / testing activities, and threat and vulnerability analysis.$$, $$Budget J-Books/FY27/Army/RDTEVol3BudgetActivity5C.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605036A$$, $$Combating Weapons of Mass Destruction (CWMD)$$, $$rdte_army_ba5$$, $$dw_dtra$$, 2026, 13322000, 1012000, 7846000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "army", "page_num": 17, "original_pe": "0605036A", "page_header": "Department of the Army"}$$::jsonb, $$The Combating Weapons of Mass Destruction (CWMD) line supports test and evaluation efforts for overall chemical, radiological, and biological detection and protection for the warfighter for multiple programs of record, including the Advanced Radiological, Nuclear Detection Family of Systems (ARND FoS), the Vehicle Integrated Platform Enhanced Radiac (VIPER), and the Chemically Protected Deployable Medical System (CP DEPMEDS). The Advanced Radiological, Nuclear Detection Family of Systems (ARND FoS) will provide an enhanced standoff, wide area/ networked detection capability to produce a radiological nuclear site picture depicting radiological hot spots and facilitating the detection of high priority areas of interest/focus on an objective. ARND FoS benefits the warfighter with the capability that will provide enhanced radiological and nuclear detection to support search and find of sources of interest for Sensitive Site Assessment (SSA) and Sensitive Site Exploitation (SSE).? In FY26, ARND FoS will continue performance and integration testing to validate the capability meets the defined requirement. The Vehicle Integrated Platform Enhanced Radiac (VIPER) is a small radiation sensor that modernizes the Army's capabilities to monitor for platform crew exposure to radiological/nuclear (rad/nuc) hazards. The system mounts within the crew compartment of multiple U.S. Army ground and aviation platforms. The system provides gamma dose rate, gamma dose, and gamma/neutron (i.e., prompt) dose measurements in a small, ruggedized form factor. In FY26, VIPER will award a contract to build test assets and provide test/integration support. The CP DEPMEDS program procures equipment to provide chemical and biological protection to US Army Role 3 field hospitals. CP DEPMEDS RDTE BA5 funding discontinues after FY24 to transition to procurement. FY26 Base amount of $13.387 million supports ARND FoS ($5.387M) and VIPER ($8.000M). The FY 2026 request was reduced by $0.028 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative." Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                       Date: June 2025 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 5: System        PE 0605036A / Combating Weapons of Mass Destruction (CWMD) Development & Demonstration (SDD)$$, NULL, 12176000, 7295000, 12018000, NULL, NULL, 135, $$RDTE - Vol 3 - Budget Activity 5C.pdf$$, NULL, FALSE, 7560000, 13322000, 5605000, 5605000, NULL, 5605000, 11064000, $$The Combating Weapons of Mass Destruction (CWMD) line supports test and evaluation efforts for overall chemical, radiological, and biological detection and protection for the warfighter for multiple programs of record, including the Advanced Radiological, Nuclear Detection Family of Systems (ARND FoS) and the Vehicle Integrated Platform Enhanced Radiac (VIPER) programs. Advanced Radiological, Nuclear Detection Family of Systems (ARND FoS) will provide an enhanced standoff, wide area/ networked detection capability to produce a radiological nuclear site picture depicting radiological hot spots and facilitating the detection of high priority areas of interest/focus on an objective. ARND FoS benefits the warfighter with the capability that will provide enhanced radiological and nuclear detection to support search and find of sources of interest for Sensitive Site Assessment (SSA) and Sensitive Site Exploitation (SSE). Vehicle Integrated Platform Enhanced RADIAC (VIPER) is a small radiation sensor that modernizes the Army's capabilities to monitor for platform crew exposure to radiological/nuclear (rad/nuc) hazards. The system mounts within the crew compartment of multiple U.S. Army ground and aviation platforms. It provides gamma dose rate, gamma dose, and gamma/neutron (i.e., prompt) dose measurements in a small, ruggedized form factor. It replaces obsolete systems, the AN/VDR-2 and the AN/UDR-13, which are no longer in production. VIPER benefits the warfighter by providing a rapid and accurate understanding of the radiation exposure of Soldiers (full range dose rate, residual dose, and prompt dose) to inform post-exposure actions for reconnaissance, surveillance, health risk assessment, and decontamination operations. FY 2027 amount of $5.605 million supports ARND FoS ($3.999 million) and VIPER ($1.606 million). In FY2027, ARND FoS will complete performance and integration testing to validate the capability meets defined requirements. FY 2027, VIPER will continue developmental testing and integration efforts to supporting incremental fielding to wheeled platforms and continue testing and integration efforts for tracked and aviation platforms supporting the acquisition strategy. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                           Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 5: System            PE 0605036A / Combating Weapons of Mass Destruction (CWMD) Development & Demonstration (SDD)$$, $$Budget J-Books/FY27/Army/RDTEVol3BudgetActivity5C.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605037A$$, $$Evidence Collection and Detainee Processing$$, $$rdte_army_ba5$$, $$asa_alt$$, 2026, 4619000, 0, 0, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "army", "page_num": 18, "original_pe": "0605037A", "page_header": "Department of the Army"}$$::jsonb, $$Detainee Management, Accountability, and Reporting (DMAR) (Project DM1) will be comprised of both an enterprise (connected) and stand-alone (denied/degraded) software instantiation that provides Military Police Commands with the capability and capacity to operate a national-level registry to account for detainees and generate reports on Detainee Operations to provide national and international organizations as required by law. DMAR will provide a high degree of situational understanding in Near Real Time (NRT) across Joint Domain Operations (JDO) during Detainee Operations. DMAR will replace the currently fielded systems, Detainee Information Management System - Fusion (DIMS-F) and Detainee Reporting System (DRS) which are obsolete and facing End of Useful Life (EUL).$$, NULL, 2477000, 4829000, 3012000, NULL, NULL, 136, $$RDTE - Vol 3 - Budget Activity 5C.pdf$$, NULL, FALSE, NULL, 4619000, 5513000, 5513000, NULL, 5513000, 2703000, $$Detainee Management, Accountability, and Reporting (DMAR) will be comprised of both an enterprise (connected) and stand-alone (denied/degraded) software instantiation that provides Military Police (MP) Commands with the capability and capacity to operate an inclusive database to account for detainee identity, personal effects, medical conditions, legal needs, and biometrics; as well as generate reports on detainee operations to provide national and international organizations as required by law. DMAR will provide a high degree of situational understanding to Commanders in near real time across Joint Domain Operations (JDO) and Large Scale Combat Operations (LSCO). FY27 funds in the amount of $5.513M will provide support for both the software planning and execution phases.$$, $$Budget J-Books/FY27/Army/RDTEVol3BudgetActivity5C.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$P_2031_L027$$, $$AH-64 MODS$$, $$proc_army_2031_ba2$$, $$peo_aviation$$, 2026, 125236000, 141402000, 93826000, NULL, $${"page": 12, "ba_num": "02", "source": "p1_fy26", "ba_name": "Modification of aircraft", "line_no": "27", "service": "army", "fy24_qty": null, "fy25_qty": null, "appr_code": "2031", "appr_name": "Aircraft Procurement, Army", "fy26_v178": {"disc_K": 131236, "li_num": 17, "source": "p40_fy26_v178", "supp_K": 0, "source_pdf": "uploads/Budget J-Books/FY27/Army/Aircraft_Procurement_Army.txt"}, "fy26t_qty": null, "fy26d_cost": 125236000, "fy26r_cost": 0, "ident_code": "A"}$$::jsonb, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, FALSE, NULL, 131236000, 251645000, 251645000, 0, 251645000, NULL, NULL, $$Budget J-Books/FY27/Army/Aircraft_Procurement_Army.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605038A$$, $$Nuclear Biological Chemical Reconnaissance Vehicle (NBCRV) Sensor$$, $$rdte_army_ba5$$, $$dw_cbdp$$, 2026, 13459000, 0, 7886000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "army", "page_num": 18, "original_pe": "0605038A", "page_header": "Department of the Army"}$$::jsonb, $$The Nuclear Biological Chemical Reconnaissance Vehicle Sensor Suite Upgrade (NBCRV SSU) will modernize Chemical, Biological, Radiological and Nuclear (CBRN) components of the current Stryker NBCRV Sensor Suite to increase maintainability, reliability, maneuverability of the force, and standoff distance from the threats. NBCRV SSU enhances CBRN standoff capabilities and integrates onto robotic platforms for human machine integration (HMI), optimizing the Stryker NBCRV maneuver formations ability to conduct mounted CBRN reconnaissance and surveillance. NBCRV SSU benefits the warfighter by reducing the risk to force and mission, providing decision quality data to answer Commander's priority intelligence requirements facilitating risk-based decisions, ensuring freedom of action and maintaining maneuver momentum during large scale combat operations. FY2026 Base RDTE funds in the amount of $13.459 million will be used to complete integration of Capability Set 2.2 (CS2.2) and continue CS2.2 development and operational testing. The FY 2026 request was reduced by $0.304 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative."$$, NULL, NULL, NULL, NULL, NULL, NULL, 137, $$RDTE - Vol 3 - Budget Activity 5C.pdf$$, NULL, FALSE, 7598000, 13459000, 13864000, 13864000, NULL, 13864000, NULL, $$The Nuclear Biological Chemical Reconnaissance Vehicle Sensor Suite Upgrade (NBCRV SSU) will modernize Chemical, Biological, Radiological and Nuclear (CBRN) components of the current Stryker NBCRV Sensor Suite to increase maintainability, reliability, maneuverability of the force, and standoff distance from the threats. NBCRV SSU enhances CBRN standoff capabilities and integrates onto robotic platforms for human machine integration (HMI), optimizing the Stryker NBCRV maneuver formations ability to conduct mounted CBRN reconnaissance and surveillance. NBCRV SSU benefits the warfighter with increased standoff capabilities and reliability, reducing risk to force and mission; and by providing decision quality data to answer the Commander's priority intelligence requirements to facilitate risk-based decisions, ensuring freedom of action and maintaining maneuver momentum in large scale combat operations. NBCRV SSU received an updated acquisition strategy on 07 April 2025 that aligned to support updated Army Priorities resulting in transfer of funding to a new funding line (CBRN Reconnaissance Modular Mission Payload, CRMMP) in FY 2028 and beyond. The CRMMP Program will utilize NBCRV SSU Capability Set 2.2 (CS2.2) FY 2027 RDTE funds in the amount of $13.864 million to complete development and integration of CRMMP Low-Rate Initial Production (LRIP) assets.$$, $$Budget J-Books/FY27/Army/RDTEVol3BudgetActivity5C.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605041A$$, $$Defensive CYBER Tool Development$$, $$rdte_army_ba5$$, $$peo_c3t$$, 2026, 3611000, 13386000, 4176000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "army", "page_num": 18, "original_pe": "0605041A", "page_header": "Department of the Army"}$$::jsonb, $$- Cyber Situational Understanding (Cyber SU): No funding requested in FY 2025 and beyond due to program divestment. Army approved program termination 11 June 2024. - Tactical DCO-I (TDI) is a software only program that consists of pre-configured DCO applications that enable local and remote Cyber defenders to conduct cyberspace surveillance, and maneuver against an adversary traversing within the tactical network. The TDI capability is hosted on the Army's Tactical Network and will reside within the Command Post at the tactical level (up to Army Service Component Commands). - FY 2026 funding in the amount of $3.611 million will support the completion of development engineering and integration of CR 7, CR 8, and CR 9 and beyond including development engineering to collate and aggregate TDI data from various echelons; convergence with Tactical Data Fabric to align with Army Data Strategies, and implement Security Operations, Automated Response contractor and matrix support. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                   Date: June 2025 Appropriation/Budget Activity                                               R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 5: System         PE 0605041A / Defensive CYBER Tool Development Development & Demonstration (SDD)$$, NULL, 3569000, 3602000, 3605000, NULL, NULL, 138, $$RDTE - Vol 3 - Budget Activity 5C.pdf$$, NULL, FALSE, 4176000, 3611000, 3519000, 3519000, NULL, 3519000, 3641000, $$- Cyber Situational Understanding (Cyber SU): No funding requested in FY 2025 and beyond due to program divestment. Army approved program termination 11 June 2024. - Tactical DCO-I (TDI) is a software only program that consists of pre-configured DCO applications that enable local and remote Cyber defenders to conduct cyberspace surveillance, and maneuver against an adversary traversing within the tactical network. The TDI capability is hosted on the Army's Tactical Network and will reside within the Command Post at the tactical level (up to Army Service Component Commands). - FY 2027 funding in the amount of $3.519 million provides for the software enhancements and maintenance/patching of the TDI software to ensure continued operability and security posture. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                           Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 5: System            PE 0605041A / Defensive CYBER Tool Development Development & Demonstration (SDD)$$, $$Budget J-Books/FY27/Army/RDTEVol3BudgetActivity5C.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605042A$$, $$Tactical Network Radio Systems (Low-Tier)$$, $$rdte_army_ba5$$, $$peo_c3t$$, 2026, 3222000, 4160000, 4288000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "army", "page_num": 18, "original_pe": "0605042A", "page_header": "Department of the Army"}$$::jsonb, $$This funding supports the Army's Next Generation Command and Control (NGC2) initiative to modernize Command and Control (C2) systems, Transport Layer. Tactical Network Radio Systems (Low-Tier) provide both Classified and Unclassified communications. The radios provide the Single Channel Ground and Airborne Radio System (SINCGARS) waveform for Classified and Unclassified communications. They also provide advanced networking waveforms (e.g., TrellisWare TSM) that provide Secure but Unclassified (SBU) communications. The Manpack (MP) radio also provides the Mobile User Objective System (MUOS) waveform capability for Tactical Satellite communications. The Handheld, Manpack, and Small Form Fit (HMS) radio program is a single Acquisition Category 1C program encompassing handheld radios and manpack radios. Handheld radio variants include the legacy single-channel Rifleman Radio (RR), Single Channel Data Radio (SCDR) in support of Soldier Born Mission Command (SBMC), two-channel Leader Radio (LR), and Sensitive But Unclassified-Encryption (SBU-E). The manpack variants include the legacy Generation 1 Manpack (MP) and the current Generation 2 Manpack. HMS provides voice and data communication to the expeditionary Warfighter with an on-the-move, at-the-halt, and stationary Line of Sight (LOS)/Beyond Line of Sight (BLOS) capability for both dismounted personnel and platforms. HMS radio systems are software reprogrammable, networkable, multi- mode systems capable of simultaneous voice and data communication. HMS radios will support a variety of other platforms, including tactical End User Devices (EUD) voice and data needs. HMS provides tailorable and scalable, software-defined radio systems meeting U.S. Army, Air Force, Navy, Marine Corps, and Special Operations Command communications needs. HMS completed Initial Operational Test and Evaluation (IOT&E) during January 2021. Following the IOT&E test event, HMS outlined specific actions required to resolve test findings from the IOT&E event. FY2026 RDT&E funding supports testing activities including laboratory technical testing, Performance Verification Tests (PVTs), and Operational User Assessments (OUAs)/Soldier Touch Points (STPs). Each of these events provides both technical and operational user feedback on increased capabilities, future waveform incorporation, soldier usability, and life-cycle sustainment improvements. The FY 2026 request was reduced by $0.478 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative." Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                       Date: June 2025 Appropriation/Budget Activity                                               R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 5: System         PE 0605042A / Tactical Network Radio Systems (Low-Tier) Development & Demonstration (SDD)$$, NULL, 3885000, 3957000, 4042000, NULL, NULL, 139, $$RDTE - Vol 3 - Budget Activity 5D.pdf$$, NULL, FALSE, 4131000, 3222000, 3804000, 3804000, NULL, 3804000, 4082000, $$This funding supports the Army's Next Generation Command and Control (NGC2) initiative to modernize Command and Control (C2) systems, Transport Layer. Tactical Network Radio Systems (Low-Tier) provide both Classified and Unclassified communications. The radios provide the Single Channel Ground and Airborne Radio System (SINCGARS) waveform for Classified and Unclassified communications. They also provide advanced networking waveforms (e.g., TrellisWare TSM) that provide Secure but Unclassified (SBU) communications. The Manpack (MP) radio also provides the Mobile User Objective System (MUOS) waveform capability for Tactical Satellite communications. The Handheld, Manpack, and Small Form Fit (HMS) radio program is a single Acquisition Category 1C program encompassing handheld radios and manpack radios. Handheld radio variants include the legacy single-channel Rifleman Radio (RR), Single Channel Data Radio (SCDR) in support of Soldier Born Mission Command (SBMC), two-channel Leader Radio (LR), and Sensitive But Unclassified-Encryption (SBU-E). The manpack variants include the legacy Generation 1 Manpack (MP) and the current Generation 2 Manpack. HMS provides voice and data communication to the expeditionary Warfighter with an on-the-move, at-the-halt, and stationary Line of Sight (LOS)/Beyond Line of Sight (BLOS) capability for both dismounted personnel and platforms. HMS radio systems are software reprogrammable, networkable, multi- mode systems capable of simultaneous voice and data communication. HMS radios will support a variety of other platforms, including tactical End User Devices (EUD) voice and data needs. HMS provides tailorable and scalable, software-defined radio systems meeting U.S. Army, Air Force, Navy, Marine Corps, and Special Operations Command communications needs. HMS completed Initial Operational Test and Evaluation (IOT&E) during January 2021. Following the IOT&E test event, HMS outlined specific actions required to resolve test findings from the IOT&E event. FY2027 RDT&E funding supports testing activities including laboratory technical testing, Performance Verification Tests (PVTs), and Operational User Assessments (OUAs)/Soldier Touch Points (STPs). Each of these events provides both technical and operational user feedback on increased capabilities, future waveform incorporation, soldier usability, and life-cycle sustainment improvements. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                           Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 5: System            PE 0605042A / Tactical Network Radio Systems (Low-Tier) Development & Demonstration (SDD)$$, $$Budget J-Books/FY27/Army/RDTEVol3BudgetActivity5C.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605047A$$, $$Contract Writing System$$, $$rdte_army_ba5$$, $$peo_eis$$, 2026, 8101000, 12390000, 9276000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "army", "page_num": 18, "original_pe": "0605047A", "page_header": "Department of the Army"}$$::jsonb, $$The Army Contract Writing System (ACWS) will be the Army's next-generation, enterprise-wide contract writing, management, execution, and close-out software system. ACWS will facilitate the standardization of Army Procurement business processes and streamline the integration with Army Enterprise Resource Planning (ERP) systems. As a comprehensive financial feeder system, ACWS will address the complete range of Army contracting needs. This includes contracts in both secure and non-secure environments, support for combat and non-combat contingencies, operations within and beyond the borders of the Continental United States, as well as assistance with grants and agreements. Additionally, ACWS will facilitate activities related to weapons systems, construction, installation, specialized contracting, and compliance with the Federal Financial Management Improvement Act of 1996. Based on Army Senior leadership direction, the Army pivoted to a Portfolio Approach that leverages existing technologies, maximizes share-ability and reuse across the DoD, and includes iterative design, development and testing for the remaining capability required for Army users. The overall approach includes on boarding United States Department of Agriculture's (USDA) resources to act as the system integrator (SI), leveraging an Interagency Agreement (IAA) and using existing capabilities across DoD in order to minimize the development effort. To meet requirements, ACWS leverages functionality from Air Force's Contracting Information Technology (CON-IT), Army's Virtual Contracting Enterprise (VCE), DoD's Procurement Integrated Enterprise Environment (PIEE), GSA's System for Award Management (SAM), and other existing Robotic Process Automation (RPA) programs for an integrated Army system to enable decommission of Standard Procurement System (SPS) and Procurement Automated Data and Document System (PADDS). This approach enables contracting business intelligence and analysis. The Army is collaborating with the USDA Enterprise Application Services using IAAs to support development and delivery. The program has transitioned to the Agile development framework and conducted a discovery (risk reduction) effort in 2022, which informed development and resource requirements. The pivot implements Continuous Integration Continuous Delivery (CI/CD) to support iterative development, testing and deployment to provide a flexible system responsive to warfighter needs. FY 2026 Base funding in the amount of $8.101 million will support development of required functionality for universal contracting capabilities to include PIEE contract closeout, warrant management, document numbering, concurrent modifications and High to Low integration to automate and record sensitive (high side) transactions from the contracting community. The RDTE funding in FY 2026 will be used for data migration development to support the retirement of PADDS. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                    Date: June 2025 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 5: System          PE 0605047A / Contract Writing System Development & Demonstration (SDD)$$, NULL, 4363000, 4442000, 4532000, NULL, NULL, 140, $$RDTE - Vol 3 - Budget Activity 5D.pdf$$, NULL, FALSE, 8937000, 8101000, 4777000, 4777000, NULL, 4777000, 4577000, $$The Army Contract Writing System (ACWS) will be the Army's next-generation, enterprise-wide contract writing, management, execution, and close-out software system. ACWS will facilitate the standardization of Army Procurement business processes and streamline the integration with Army Enterprise Resource Planning (ERP) systems. As a comprehensive financial feeder system, ACWS will address the complete range of Army contracting needs. This includes contracts in both secure and non-secure environments, support for combat and non-combat contingencies, operations within and beyond the borders of the Continental United States, as well as assistance with grants and agreements. Additionally, ACWS will facilitate activities related to weapons systems, construction, installation, specialized contracting, and compliance with the Federal Financial Management Improvement Act of 1996. Based on Army Senior leadership direction, the Army pivoted to a Portfolio Approach that leverages existing technologies, maximizes share-ability and reuse across the DoW, and includes iterative design, development and testing for the remaining capability required for Army users. The overall approach includes on boarding United States Department of Agriculture's (USDA) resources to act as the system integrator (SI), leveraging an Interagency Agreement (IAA) and using existing capabilities across DoW in order to minimize the development effort. To meet requirements, ACWS leverages functionality from Air Force's Contracting Information Technology (CON-IT), Army's Virtual Contracting Enterprise (VCE), DoW's Procurement Integrated Enterprise Environment (PIEE), GSA's System for Award Management (SAM), and other existing Robotic Process Automation (RPA) programs for an integrated Army system to enable decommission of Standard Procurement System (SPS) and Procurement Automated Data and Document System (PADDS). This approach enables contracting business intelligence and analysis. The Army is collaborating with the USDA Enterprise Application Services using IAAs to support development and delivery. The program has transitioned to the Agile development framework and conducted a discovery (risk reduction) effort in 2022, which informed development and resource requirements. The pivot implements Continuous Integration Continuous Delivery (CI/CD) to support iterative development, testing and deployment to provide a flexible system responsive to warfighter needs. FY 2027 funding in the amount of $4.777 million will support development of required functionality for secure contracting capabilities in an Impact Level (IL) 6 compliant cloud. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                           Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 5: System            PE 0605047A / Contract Writing System Development & Demonstration (SDD)$$, $$Budget J-Books/FY27/Army/RDTEVol3BudgetActivity5C.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605049A$$, $$Missile Warning System Modernization (MWSM)$$, $$rdte_army_ba5$$, $$peo_aviation$$, 2026, 0, 19508000, 0, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "army", "page_num": 18, "original_pe": "0605049A", "page_header": "Department of the Army"}$$::jsonb, $$The Missile Warning System Modernization (MWSM) budget line includes funding to support the development and integration of improved Aircraft Survivability Equipment (ASE) products onto current US Army Aviation platforms as well as Future Long Range Assault Aircraft (FLRAA) and future platforms. The ITDS (Improved Threat Detection System) will detect, classify, cue, and declare on existing and emerging Electro-Optical/Infra-red (EO/IR) Guided Man-Portable Air Defense Systems (MANPADS), Rocket Propelled Grenades (RPG)/ unguided rockets, Anti-Tank Guided Missiles (ATGM), Ballistic munitions, Unmanned Aerial System (UAS), and Lasers. ITDS will provide missile threat handoff to the appropriate countermeasure system (Common Infrared Countermeasure (CIRCM) and/or expendable countermeasure). ITDS will explore opportunities to improve the expendable countermeasure system. ITDS will use an incremental approach to align with PM ASE's System of Systems approach, align both agnostic detect and defeat capabilities, implement a modular open system architecture, integrate to the FLRAA digital backbone, improve full coverage against evolving threats in hostile environments, support counter UAS, and incorporate multi-function sensor suite to support other aircraft enabling technologies. Additional key attributes include: Geo-location of threats, Support Degraded Visual Environment and Navigation, Multiple Threat Detection, Declaration for Simultaneous Warning. Justification: No FY 2026 funding request. References: -Rescission of Advanced Threat Detection System Request for Materiel Development Decision, DCS, G-8, 17 December 2018. -MDD Request for the ITDS Program of Record, Aviation Capability Development and Integration Directorate (Aviation CDID), 6 July 2021. -MDD Request for the ITDS Program of Record, DCS, G-8, 14 March 2022. -Assignment of an Army Office of Primary Responsibility (OPR) for the ITDS Capability, Assistant Secretary of the Army (Acquisition, Logistics and Technology) (ASA(ALT)), 18 April 2022. -Improved Threat Detection Investment Acquisition Decision Memorandum (ADM), ASA(ALT), 1 July 2024. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                   Date: June 2025 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 5: System        PE 0605049A / Missile Warning System Modernization (MWSM) Development & Demonstration (SDD)$$, NULL, NULL, NULL, NULL, NULL, NULL, 141, $$RDTE - Vol 3 - Budget Activity 5D.pdf$$, NULL, FALSE, 45000, 13530000, NULL, NULL, NULL, NULL, NULL, $$The Missile Warning System Modernization (MWSM) budget line includes funding to support the development and integration of improved Aircraft Survivability Equipment (ASE) products onto current US Army Aviation platforms as well as Future Long Range Assault Aircraft (FLRAA) and future platforms. The ITDS (Improved Threat Detection System) will detect, classify, cue, and declare on existing and emerging Electro-Optical/Infra-red (EO/IR) Guided Man-Portable Air Defense Systems (MANPADS), Rocket Propelled Grenades (RPG)/ unguided rockets, Anti-Tank Guided Missiles (ATGM), Ballistic munitions, Unmanned Aerial System (UAS), and Lasers. ITDS will provide missile threat handoff to the appropriate countermeasure system (Common Infrared Countermeasure (CIRCM) and/or expendable countermeasure). ITDS will explore opportunities to improve the expendable countermeasure system. ITDS will use an incremental approach to align with PM ASE's System of Systems approach, align both agnostic detect and defeat capabilities, implement a modular open system architecture, integrate to the FLRAA digital backbone, improve full coverage against evolving threats in hostile environments, support counter UAS, and incorporate multi-function sensor suite to support other aircraft enabling technologies. Additional key attributes include: Geo-location of threats, Support Degraded Visual Environment and Navigation, Multiple Threat Detection, Declaration for Simultaneous Warning. Justification: No FY 2027 funding request. References: -Rescission of Advanced Threat Detection System Request for Materiel Development Decision, DCS, G-8, 17 December 2018. -MDD Request for the ITDS Program of Record, Aviation Capability Development and Integration Directorate (Aviation CDID), 6 July 2021. -MDD Request for the ITDS Program of Record, DCS, G-8, 14 March 2022. -Assignment of an Army Office of Primary Responsibility (OPR) for the ITDS Capability, Assistant Secretary of the Army (Acquisition, Logistics and Technology) (ASA(ALT)), 18 April 2022. -Improved Threat Detection Investment Acquisition Decision Memorandum (ADM), ASA(ALT), 1 July 2024. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                         Date: April 2026 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 5: System        PE 0605049A / Missile Warning System Modernization (MWSM) Development & Demonstration (SDD)$$, $$Budget J-Books/FY27/Army/RDTEVol3BudgetActivity5C.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605051A$$, $$Aircraft Survivability Development$$, $$rdte_army_ba5$$, $$peo_aviation$$, 2026, 44182000, 23991000, 38225000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "army", "page_num": 18, "original_pe": "0605051A", "page_header": "Department of the Army", "fy26_v182_disc_K": 47182, "fy26_v182_supp_K": 13530, "fy26_v182_total_K": 60712, "fy26_v182_note_name": "Aircraft Survivability Development", "fy26_v182_source_file": "RDTEVol3BudgetActivity5C.txt", "fy26_v182_source_line": 9125}$$::jsonb, $$This funding line is a key enabler of the Army Modernization Priorities in support of the Aircraft Survivability Equipment (ASE) as well as Future Long-Range Assault Aircraft (FLRAA). The Aircraft Survivability Development program includes Projects titled Aircraft Survivability Equipment Development (ER7), Common Missile Warning System (CMWS) (ER8), and Improved Threat Detection System (ITDS) (ITD). This program previously included funding for Joint Urgent Operational Needs Statement (JUONS) SO-0010, Headquarters Department of the Army (HQDA) Directed Requirement for Advanced Threat Warner (ATW) portion of Phase 3 ATW/Common Infrared Countermeasures Quick Reaction Capability (ATW/CIRCM QRC), and Limited Interim Missile Warning System Quick Reaction Capability (LIMWS QRC). As of FY2025, the ATW and JUONS RDT&E efforts have been completed, and aircraft deployed with JUONS have been de-modified. ER7: Aircraft Survivability Development. The objective of the ASE Development project is to improve Radio Frequency (RF) ASE for Army Aviation. APR-39 Radar Warning Receiver (RWR) detects, categorizes, and prioritizes RF emitters and provides a visual / aural alert to aircrew members warning them of targeting by RF-guided weapons. The Milestone Decision Authority (MDA) approved Phases 1 and 2 of a 3-phased path forward. Phase 1, APR-39C(V)1/4, serves as an obsolescence / sustainment upgrade to the Processor Line Replaceable Unit (LRU) for AN/APR-39A(V) RWR implemented to ensure that the currently fielded system remains viable until affordable improved RF ASE capability can be pursued in Phases 2 and 3. Phase 2A is RWR Modernization begins by adopting the United States Navy APR-39D(V)2 system. APR-39D(V)2 will significantly improve the RF threat coverage, automatic detection and identification of threat types, bearing, and lethality. Phase 2B, the APR-39E(V)2, Modernized Radar Warning Receiver (MRWR), is an Army Engineering Change Proposal (ECP) to APR-39D(V)2, approved in the Acquisition Decision Memorandum (ADM) signed June 24, 2019. This ECP will implement enhanced hardware and software upgrades to keep APR-39 technically relevant against new and emerging agile threats faced by legacy platforms in a near peer Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                                 Date: June 2025 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 5: System             PE 0605051A / Aircraft Survivability Development Development & Demonstration (SDD) contest. APR-39E(V)2 is part of the suite of ASE mission equipment for FLRAA. Phase 3 adds active Radio Frequency Electronic Countermeasures (RF-ECM) capability for selected aircraft with Material Development Decision (MDD) planned in the future. Justification: FY 2026 Base RDT&E funding of $8.159 million supports APR-39E(V)2 Hardware and Software System Development, and Systems Engineering and Program Management (SEPM). ER8: Common Missile Warning System (CMWS). The CMWS program is a missile warning system that cues both flare and laser-based countermeasures to defeat incoming Infrared (IR)-seeking missiles and will alert aircrews to the presence of certain incoming munitions. The B-Kit consists of the components which perform the missile detection and aircrew notification, munitions detection and aircrew notification, false alarm rejection, and countermeasure employment/cueing functions of the system. The CMWS Electronic Control Unit (ECU) receives ultraviolet (UV) missile detection data from Electro-Optic Missile Sensors (EOMS), which detect UV signals, and sends a missile alert signal to warn aircrews via on-board avionics. Tier 1 threat missiles detected and tracked by CMWS are subsequently defeated by a combination of missile seeker countermeasures, including decoy flares and IR Laser Jamming (currently Common Infrared Countermeasures (CIRCM) -multiple platforms and Advanced Threat Infrared Countermeasures (ATIRCM)-equipped CH-47 platform only). In addition, CMWS ECU receives munitions detection data from the EOMS which it also passes to the aircrew through aural and visual alerts. The aircrew then applies the appropriate Tactics, Techniques and Procedures (TTPs) to break contact or engage the enemy with own-ship ordnance. CMWS Generation 3 (Gen 3) ECU in conjunction with ongoing software development efforts will address outstanding materiel release conditions and ensure protection against emerging IR-guided missile threats. Due to evolving threats, CMWS will remain in the Army inventory until replaced by a future program. Continuing systems engineering, integration, and testing along with software support will maintain capability to rapidly respond as threats evolve in order to ensure protection against IR- guided missile threats. The A-Kit for CMWS includes mounting hardware, wiring harnesses, cables, and other components necessary to install and interface the mission kit on host aircraft. The A-Kit ensures the mission kit is functionally and physically operational with a specific host aircraft type. As of FY 2025, the ATW and JUONS RDT&E efforts have been completed, and aircraft deployed with JUONS have been de-modified. LIMWS QRC addresses the HQDA Directed Requirement to provide a greater capability than CMWS, the current program, to bridge the gap between CMWS and the future threat detection system, the Improved Threat Detection System (ITDS). LIMWS is required to provide increased detection range, improved detection in clutter, more agile algorithms to rapidly respond to emerging threats, and eliminates the need for sensor alignments. Justification: CMWS/LIMWS QRC: FY 2026 Base RDTE dollars in the amount of $4.681 million will fund Algorithm Analysis, Threat and Vulnerability Analysis, and Systems Engineering and Program Management (SEPM). ITD: Improved Threat Detection System (ITDS). Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                                  Date: June 2025 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 5: System           PE 0605051A / Aircraft Survivability Development Development & Demonstration (SDD) The ITDS (Improved Threat Detection System) budget line includes funding to support the development and integration of improved Aircraft Survivability Equipment (ASE) products onto current US Army Aviation platforms as well as Future Long Range Assault Aircraft (FLRAA) and future platforms. ITDS will detect, classify, cue, and declare on existing and emerging Electro-Optical/Infra-red (EO/IR) Guided Man-Portable Air Defense Systems (MANPADS), Class I - IV Drones, Loitering Ammunitions, Rocket Propelled Grenades (RPG)/ unguided rockets, Anti-Tank Guided Missiles (ATGM), Ballistic munitions, Unmanned Aerial System (UAS), and Lasers. ITDS will provide missile threat handoff to the appropriate countermeasure system (Common Infrared Countermeasure (CIRCM) and/or expendable countermeasure). ITDS will explore opportunities to improve the expendable countermeasure system. ITDS will use an incremental approach to align with PM ASE's System of Systems approach, align both agnostic detect and defeat capabilities, implement a modular open system architecture, integrate to the FLRAA digital backbone, improve full coverage against evolving threats in hostile environments, support counter UAS, and incorporate multi-function sensor suite to support other aircraft enabling technologies. Additional key attributes include: Geo-location of threats, Support Degraded Visual Environment and Navigation, Multiple Threat Detection, Declaration for Simultaneous Warning. Justification: ITDS: FY2026 Base RDTE dollars in the amount of $31.342 million will fund design and demonstration testing, prototype application hosting, sensor characterization and flight test, digital simulation modelling assessments, aircraft integration strategies, reliability, prototypes, manufacturing, and technical readiness assessments. References: - Joint Staff, J-8 Deputy Director for Requirements (DOR) memorandum, April 24, 2015 - Phase 2a SOCOM JUONs SO-0010, Joint Rapid Acquisition Cell (JRAC) memorandum, May 29, 2015 - Directed Requirement for the Phase 3 Advanced Threat Warner and Common Infrared Countermeasure Quick Reaction Capability (ATW/CIRCM QRC) to Support Joint Urgent Operational Need (JUON) SO-0010, CIRCM Critical Intelligence Parameters Breach, December 18, 2015 - Directed Requirement for Limited Interim Missile Warning System to Detect Enemy Man Portable Air Defense Systems, March 26, 2017 - Update to the Directed Requirement for the United States Special Operations Command Joint Urgent Operational Needs SO-0010 Threat Detection and Countermeasures to Enemy Man Portable Air Defense System Capability, November 16, 2018 - Directed Requirement for Limited Interim Missile Warning System to Detect Enemy Man Portable Air Defense Systems, November 16, 2018 - Aircraft Survivability Equipment (ASE) Modernization Fielding Guidance, Change 1, November 19, 2018 - Acquisition Decision Memorandum (ADM) for Radio Frequency (RF) Project Manager Aircraft Survivability Equipment (PM ASE) Engineering Change Proposal (ECP) for Radar Warning Receiver AN/APR39-D(V)2 to AN/APR39-E(V)2, June 24, 2019 by PEO IEW&S. - MDD Request for the ITDS Program of Record, Aviation Capability Development and Integration Directorate (Aviation CDID), 6 July 2021. - MDD Request for the ITDS Program of Record, DCS, G-8, 14 March 2022. - Assignment of an Army Office of Primary Responsibility (OPR) for the ITDS Capability, Assistant Secretary of the Army (Acquisition, Logistics and Technology) (ASA(ALT)), 18 April 2022. - Improved Threat Detection Investment Acquisition Decision Memorandum (ADM), ASA(ALT), 1 July 2024. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                             Date: June 2025 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 5: System          PE 0605051A / Aircraft Survivability Development Development & Demonstration (SDD) The FY 2026 request was reduced by $0.91 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative."$$, NULL, 83964000, 79515000, 44615000, NULL, NULL, 142, $$RDTE - Vol 3 - Budget Activity 5D.pdf$$, NULL, FALSE, 36269000, 60712000, 106621000, 106621000, NULL, 106621000, 37469000, $$ER7: Aircraft Survivability Development. The objective of the Aircraft Survivability Equipment (ASE) Development project is to improve Radio Frequency (RF) Aircraft Survivability Equipment (ASE) for Army Aviation. AN/APR-39 Radar Warning Receiver (RWR) detects, categorizes, and prioritizes RF emitters and provides a visual / aural alert to aircrew members warning them of targeting by RF-guided weapons. AN/APR-39D(V)2 interim RWR Modernization significantly improves the RF threat coverage, automatic detection and identification of threat types to include bearing and lethality. AN/APR-39E(V)2, Modernized Radar Warning Receiver (MRWR), is an Army Engineering Change Proposal (ECP) to AN/APR-39D(V)2, and is approved in the Acquisition Decision Memorandum (ADM) signed June 24, 2019. This ECP enhances hardware and software upgrades to keep AN/APR-39 technically relevant against new and emerging agile threats faced by legacy platforms in a near peer contest. AN/APR-39E(V)2 is part of the suite of ASE mission equipment for the Enduring Fleet and Multi-Mission Vertical Takeoff (MV)-75 Future Long-Range Assault Aircraft (FLRAA). Radio Frequency Countermeasures (RFCM) focuses on detecting and jamming incoming RF signals. RFCM will provide aircraft with an extra level of security against RF threats to include Unmanned Aircraft Systems (UAS)/Drone technology. ASE is developing RFCM capability for selected aircraft with a Material Development Decision (MDD) planned in the future. Justification: FY 2027 RDT&E dollars will fund AN/APR-39E(V)2 Hardware and Software System Development, UH-60 A-Kit NRE and Systems Engineering and Program Management (SEPM). ER8: Common Missile Warning System (CMWS) Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                                  Date: April 2026 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 5: System             PE 0605051A / Aircraft Survivability Development Development & Demonstration (SDD) The CMWS program is the legacy missile warning system that cues both flare and laser-based countermeasures to defeat incoming Infrared (IR)-seeking missiles and will alert aircrews to the presence of certain incoming munitions. CMWS provides protection to aircraft and aircrews against proliferated IR guided missile threats and will remain in the Army inventory until replaced. The B-Kit consists of the components which perform the missile detection and aircrew notification, munitions detection and aircrew notification, false alarm rejection, and countermeasure employment/cueing functions of the system. The CMWS Electronic Control Unit (ECU) receives ultraviolet (UV) missile detection data from Electro- Optic Missile Sensors (EOMS), which detect UV signals, and sends a missile alert signal to warn aircrews via on-board avionics. Tier 1 threat missiles detected and tracked by CMWS are subsequently defeated by a combination of missile seeker countermeasures, including decoy flares and Common Infrared Countermeasures (CIRCM). In addition, CMWS ECU receives hostile fire detection data from the EOMS which passes to the aircrew through aural and visual alerts. The aircrew then applies the appropriate Tactics, Techniques and Procedures (TTPs) to break contact or engage the enemy with own-ship ordnance. The A-Kit for CMWS includes mounting hardware, wiring harnesses, cables, and other components necessary to install and interface the mission kit on host aircraft. The A-Kit ensures the mission kit is functionally and physically operational with a specific host aircraft type. Justification: CMWS: FY 2027 RDTE dollars will fund future sensor algorithm analysis, threat and vulnerability analysis, software concurrency, Systems Engineering and Program Management (SEPM), A-kit compatibility assessments and future missile warning modernization initiatives to maximize the effective use of resources by delivering capabilities that offer best value. ITD: Improved Threat Detection System (ITDS) The ITDS is Army Aviation's premier threat warning system that protects Army aircraft in the full range of military operations from border security to Large Scale Combat Operations (LSCO). The ITDS offers superior aircraft protection against Air Defense (AD) threat systems and a multi-functional sensor and open systems architecture for advanced situational awareness and data enabled formations through Command-and-Control data layer integration. The ITDS will detect, classify, declare, and cue countermeasures against Group I - IV Unmanned Aerial Systems (UAS), Anti-Tank Guided Missiles (ATGMs), Rocket Propelled Grenades (RPGs), Surface to Air Missiles (SAMs), Man-Portable Air Defense Systems (MANPADS), Air to Air missiles (AAM), Anti-Aircraft Artillery (AAA), laser guided weapons, and small arms. The system will provide up to 5x greater sensitivity and 15x greater resolution improvement over currently fielded systems. Coupled with advanced algorithms, this capability enables freedom of maneuver on the modern UAS contested battlefield. ITDS supports mission intel by providing "Event Recreation Data" to Command and Control systems, which will inform the Tactical Operations Center (TOC) on adversarial weapon capabilities in the Area of Responsibility (AOR) to operate effectively and maintaining military advantage. When Army aviation platforms equipped with Missile Warning Systems get engaged by threats, that engagement is recorded and saved on the removable data module (RDM). The data collected includes Threat Track Data and other ancillary data which replicates the system state at the time of the engagement. Some of the key data that supports mission intel are the Threat Type and Point of Origin. ITDS records this data while instantly providing this information to command and control systems for mission support. Existing A-Kits will be utilized by the ITDS to the maximum extent to enable the integration of innovative solutions and technologies. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                             Date: April 2026 Appropriation/Budget Activity                                                       R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 5: System                 PE 0605051A / Aircraft Survivability Development Development & Demonstration (SDD) Justification: ITDS: FY 2027 RDTE dollars will fund design and demonstration testing, prototype application hosting, sensor characterization and flight test, digital simulation modeling assessments, aircraft integration, reliability, manufacturing, technical readiness assessments, training development, and data products such as operators and maintenance technical manuals. ITDS utilizes Rapid Acquisition Pathways as outlined in the FoRGED Act to provide expeditious delivery of c-sUAS capability necessary to effectively respond to national security challenges and reducing sustainment of obsolete legacy systems directed by the SPEED Act. The ITDS is fully funded across the Future Years Defense Program. References: - Joint Staff, J-8 Deputy Director for Requirements (DOR) memorandum, April 24, 2015 - Phase 2a SOCOM JUONs SO-0010, Joint Rapid Acquisition Cell (JRAC) memorandum, May 29, 2015 - Directed Requirement for the Phase 3 Advanced Threat Warner and Common Infrared Countermeasure Quick Reaction Capability (ATW/CIRCM QRC) to Support Joint Urgent Operational Need (JUON) SO-0010, CIRCM Critical Intelligence Parameters Breach, December 18, 2015 - Directed Requirement for Limited Interim Missile Warning System to Detect Enemy Man Portable Air Defense Systems, March 26, 2017 - Update to the Directed Requirement for the United States Special Operations Command Joint Urgent Operational Needs SO-0010 Threat Detection and Countermeasures to Enemy Man Portable Air Defense System Capability, November 16, 2018 - Directed Requirement for Limited Interim Missile Warning System to Detect Enemy Man Portable Air Defense Systems, November 16, 2018 - Aircraft Survivability Equipment (ASE) Modernization Fielding Guidance, Change 1, November 19, 2018 - Acquisition Decision Memorandum (ADM) for Radio Frequency (RF) Project Manager Aircraft Survivability Equipment (PM ASE) Engineering Change Proposal (ECP) for Radar Warning Receiver AN/APR39-D(V)2 to AN/APR39-E(V)2, June 24, 2019 by PEO IEW&S. - MDD Request for the ITDS Program of Record, Aviation Capability Development and Integration Directorate (Aviation CDID), 6 July 2021. - MDD Request for the ITDS Program of Record, DCS, G-8, 14 March 2022. - Assignment of an Army Office of Primary Responsibility (OPR) for the ITDS Capability, Assistant Secretary of the Army (Acquisition, Logistics and Technology) (ASA(ALT)), 18 April 2022. - Improved Threat Detection Investment Acquisition Decision Memorandum (ADM), ASA(ALT), 1 July 2024. - Army Requirements Oversight Council Memorandum (AROCM) signed dated 25 August 2025. - ADM Approved 25 February 2026. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                              Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 5: System            PE 0605051A / Aircraft Survivability Development Development & Demonstration (SDD)$$, $$Budget J-Books/FY27/Army/RDTEVol3BudgetActivity5C.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605052A$$, $$Indirect Fire Protection Capability Inc 2 - Block 1$$, $$rdte_army_ba5$$, $$cft_amd$$, 2026, 248659000, 172705000, 140912000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "army", "page_num": 18, "original_pe": "0605052A", "page_header": "Department of the Army"}$$::jsonb, $$This funding line is directly aligned to one of the Army Air and Missile Defense Modernization Priorities and one of the Air and Missile Defense Cross Functional Team (AMD CFT) programs. Indirect Fire Protection Capability Increment (IFPC) is part of the Army Transformation Initiative. Project EY7 / IFPC Increment 2 (IFPC Inc 2) - Block 1 will provide a ground-based weapon system designed to acquire, track, engage, and defeat subsonic Cruise Missiles (CM), Unmanned Aircraft Systems (UAS), Rocket, Artillery, and Mortar (RAM) threats. The IFPC Inc 2 system consists of a launcher, AIM-9X interceptor, and AUR-M integrated with the Army Integrated Air and Missile Defense (AIAMD) open systems architecture, IAMD Battle Command System (IBCS), and the Sentinel sensor to support the CM and UAS defeat mission. The IFPC Inc 2 program is a component of an integrated fires development effort that includes survivability, resiliency, and effectiveness improvements against advanced threats from near-peer adversaries. This effort includes component integration, common development tools and processes, and annual test and evaluation to provide data to support program assessments and progress toward closure of performance gaps. In FY 2025, IFPC Inc 2 successfully transitioned from a Middle Tier of Acquisition (MTA) Rapid Prototyping (RP) effort to MTA Rapid Fielding (RF). The IFPC Inc 2 effort is fully funded. The Army is pursuing the IFPC High Energy Laser (IFPC HEL) and the IFPC High Powered Microwave (IFPC HPM) as complimentary non-kinetic effectors of the IFPC missions that include counter RAM, Counter CM, counter UAS and denial of manned aircraft threats. Project EY8 / IFPC Increment 2 - Block 2 (IFPC 2nd Interceptor) will provide additional capabilities against supersonic cruise missiles with a secondary target set of subsonic cruise missiles, UAS, large caliber rockets, and other aerial threats. The 2nd Interceptor program also supports the Air and Missile Defense modernization priorities. The FY 2026 request was reduced by $1.751 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative." Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                              Date: June 2025 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 5: System            PE 0605052A / Indirect Fire Protection Capability Inc 2 - Block 1 Development & Demonstration (SDD)$$, NULL, 237460000, 225499000, 158222000, NULL, NULL, 143, $$RDTE - Vol 3 - Budget Activity 5D.pdf$$, NULL, FALSE, 135769000, 243087000, 175352000, 175352000, NULL, 175352000, 94222000, $$This funding line is directly aligned to the Army Air and Missile Defense Modernization Priorities. Project EY7 / IFPC Increment 2 (IFPC Inc 2) - Block 1 will provide a ground-based weapon system designed to acquire, track, engage, and defeat subsonic Cruise Missiles (CM), and Unmanned Aircraft Systems (UAS) threats. The IFPC Inc 2 system consists of a launcher, AIM-9X interceptor, and AUR-M integrated with the Army Integrated Air and Missile Defense (AIAMD) open systems architecture, IAMD Battle Command System (IBCS), and the Sentinel sensor to support the CM and UAS defeat mission. The IFPC Inc 2 program is a component of an integrated fires development effort that includes survivability, resiliency, and effectiveness improvements against advanced threats from near-peer adversaries. This effort includes component integration, common development tools and processes, and annual test and evaluation to provide data to support program assessments and progress toward closure of performance gaps. In FY 2025, IFPC Inc 2 successfully transitioned from a Middle Tier of Acquisition (MTA) Rapid Prototyping (RP) effort to MTA Rapid Fielding (RF). The total cost estimate of the IFPC Inc 2 MTA RF effort is $1,394.6 million, including RDT&E ($219.3 million) and procurement ($1,175.3 million). The remainder of the IFPC Inc 2 MTA RF effort is fully funded. Project EY8 / IFPC Increment 2 - Block 2 (IFPC 2nd Interceptor) will provide additional capabilities against supersonic cruise missiles with a secondary target set of subsonic cruise missiles, UAS, large caliber rockets, and other aerial threats. The 2nd Interceptor program also supports the Air and Missile Defense modernization priorities. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                               Date: April 2026 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 5: System             PE 0605052A / Indirect Fire Protection Capability Inc 2 - Block 1 Development & Demonstration (SDD)$$, $$Budget J-Books/FY27/Army/RDTEVol3BudgetActivity5C.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$P_1810_L060$$, $$Naval Mission Planning Systems$$, $$proc_navy_1810_ba2$$, $$peo_tacair$$, 2026, 0, 2748000, 3803000, NULL, $${"page": 98, "ba_num": "02", "source": "p1_fy26", "ba_name": "Communications and electronics equipment", "line_no": "60", "service": "navy", "fy24_qty": null, "fy25_qty": null, "fy27_v25": {"ba": "02", "appr": "OPN", "title": "P-1 Line 55", "applied_at": "2026-05-09", "fy27_ooc_K": 0, "source_pdf": "Budget J-Books/FY27/Navy/OPN_BA{1..5-8}_Book.pdf", "fy27_base_K": 289, "p1_line_num": 55, "fy27_total_K": 289}, "appr_code": "1810", "appr_name": "Other Procurement, Navy", "fy26_v179": {"disc_K": 304, "li_num": 55, "source": "p40_fy26_v179", "supp_K": 0, "source_pdf": "uploads/Budget J-Books/FY27/Navy/OPN_BA2_Book.txt"}, "fy26t_qty": null, "fy26d_cost": 0, "fy26r_cost": 0, "ident_code": "A"}$$::jsonb, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, FALSE, 42326000, 60058000, 289000, 289000, 0, 289000, NULL, NULL, $$Budget J-Books/FY27/Navy/OPN_BA2_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605053A$$, $$Ground Robotics$$, $$rdte_army_ba5$$, $$devcom$$, 2026, 227038000, 26704000, 28378000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "army", "page_num": 18, "original_pe": "0605053A", "page_header": "Department of the Army", "fy26_v182_disc_K": 160818, "fy26_v182_supp_K": 74000, "fy26_v182_total_K": 234818, "fy26_v182_note_name": "Ground Robotics", "fy26_v182_source_file": "RDTEVol3BudgetActivity5C.txt", "fy26_v182_source_line": 10507}$$::jsonb, $$Robotic Architecture (RA) supports the Army Transformation Initiative (ATI) and provides evolutionary capabilities that will forever change ground maneuver warfare. Transformation in Contact (TiC) will enable commanders to dictate the terms of the first human engagement by leveraging ground robotics systems and technologies to shape and degrade threats across the multi-domain battlefield. Infantry, armor, engineer, and sustainment formations will be outfitted with autonomous capability to allow commanders to preserve manned formations and systems. FY 2026 Base dollars in the amount of $227.038 million provides the engineering and development resources for rapid prototyping. It will manage the interoperability standards, modular payload interfaces, common software and common architecture for robotics and autonomous platforms, payloads and universal controllers in support of robotics modernization. This funding supports the Army's Next Generation Command and Control (NGC2) initiative to modernize Command and Control (C2) systems. The FY 2026 request was reduced by $0.015 million for civilian personnel to optimize the workforce in compliance with Executive Order 14210, "Implementing the President's Department of Government Efficiency Workforce Optimization Initiative." Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                                   Date: June 2025 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 5: System              PE 0605053A / Ground Robotics Development & Demonstration (SDD)$$, NULL, 179967000, 170774000, 149612000, NULL, NULL, 144, $$RDTE - Vol 3 - Budget Activity 5D.pdf$$, NULL, FALSE, 27342000, 234818000, 192185000, 192185000, NULL, 192185000, 152117000, $$The Robotic Architecture (RA) supports the Continuous Transformation Initiative (CTI) by enabling the integration of robotics into evolving ground maneuver capabilities. The goal of this portfolio is to accelerate the delivery of technology to warfighters, enabling them to gain the initiative in future engagements. This will be achieved by employing robotics systems to shape the battlefield and disrupt enemy capabilities across all domains. Robotic systems will be used across the Army formation to enhance survivability, lethality, and sustainment while reducing the cognitive load on Soldiers. FY 2027 Base dollars provides the engineering and development resources for rapid prototyping. It will manage the interoperability standards, payload interfaces, common software and common architecture for robotics and autonomous platforms, payloads and universal controllers, and testing to verify safety and performance in support of robotics modernization. This funding supports integration with the Army's Next Generation Command and Control (NGC2) initiative to modernize Command and Control (C2) systems. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                           Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 5: System            PE 0605053A / Ground Robotics Development & Demonstration (SDD)$$, $$Budget J-Books/FY27/Army/RDTEVol3BudgetActivity5C.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605056F$$, $$Open Architecture Management$$, $$rdte_af_ba5$$, $$aflcmc$$, 2026, 44150000, 34239000, 41223000, NULL, $${"ba_raw": "6.5", "source": "af_r1_fy26", "original_pe": "0605056F"}$$::jsonb, $$The Open Architecture Management (OAM) program element (PE) funds Modular Open Systems Approach (MOSA) maturation and its adoption by weapon systems across the Department of the Air Force (DAF) and the Department of Defense (DoD). Weapons systems that implement MOSA standards streamline integration of capabilities, reduce development timeline, lower life-cycle cost, reduce vendor-lock, and ensure interoperability with emerging capabilities. This enables weapon systems to field capabilities more rapidly and affordably in response to a dynamic threat environment. This budget funds the progression of Open Mission Systems (OMS), the Universal Command and Control Interface (UCI), and other emerging MOSA standards such as the Sensors Open System Architecture (SOSA). OMS is a non-proprietary, open architecture standard to create reusable and replaceable components that promote speed of integration for adopting weapons systems. The UCI is the DAF's messaging standard for mission-level Command and Control (C2), providing common message definitions to enable C2 coordination across sensors, vehicles, data products, and software. Funding supports development of new mission-critical OMS/UCI features requested by the 30+ operational adopting platforms across the DAF, DoD and international partners. Funding also supports experimentation, modeling, integration events, and studies to establish a common DAF MOSA approach. This includes leveraging commercial industry standards and government-driven standards. Additionally, funding supports alignment and interoperability across Government Reference Architectures (GRAs) and standards. These efforts use Agile methodologies and Development, Security, and Operations (DevSecOps) software practices to deliver products securely to adopting platforms and enable continuous feedback to improve the standards. Further, funding provides targeted technical exploration and risk reduction with adopting platforms to facilitate their MOSA adoption while identifying any changes required within the DAF's MOSA standards. In October 2024, the Open Architecture Management Office (OAMO) that managed this funding transitioned to the Architecture and Systems Engineering (ASE) group, Air Force Life Cycle Management Center (AFLCMC), Wright Patterson AFB. In addition to this PE, the ASE group will continue execution of these related activities under the following PEs: 0305206F / Airborne Reconnaissance Systems (672003 / Sensor Open Systems Architecture) 0604602F / Armament/Ordnance Development (655361 / Stores/Aircraft Interface) This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605829F, 0605831F, 0605833F, or 0605898F. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                           Date: June 2025 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 5: System     PE 0605056F / Open Architecture Management Development & Demonstration (SDD) This program is in Budget Activity 5, System Development and Demonstration (SDD) because it has passed Milestone B approval and is conducting engineering and manufacturing development tasks aimed at meeting validated requirements prior to full rate production.$$, NULL, 42426000, 43180000, 44044000, NULL, NULL, 100, $$FY26 Air Force Research and Development Test and Evaluation Vol II.pdf$$, NULL, FALSE, 40147000, 41422000, 43482000, 43482000, 0, 43482000, 44883000, $$The Open Architecture Management (OAM) PE funds Modular Open Systems Approach (MOSA) maturation and its adoption by weapon systems across the DAF and the Department of War (DoW). The DoW Acquisition Transformation Strategy mandates Open Systems Architectures in all acquisition programs. The OAM PE democratizes implementation of open architecture across the DAF, accelerating fielding of capabilities, breaking vendor lock and increasing return on investment for cost, agility, interoperability, and lethality operational outcomes. This PE has a direct impact on how quickly the service can implement the DoW Open Systems Architecture Initiative. This budget funds the progression of Open Mission Systems (OMS), the Universal Command and Control Interface (UCI), other emerging MOSA standards, and integration across other DAF and DoW standards. OMS is a non-proprietary, open architecture standard to create reusable and replaceable components that promote speed of integration for adopting weapons systems. The UCI is the DAF's messaging standard for mission-level Command and Control (C2), providing common message definitions to enable C2 coordination across sensors, vehicles, data products, and software. Funding supports development of new mission-critical OMS/UCI features requested by the 30+ operational adopting platforms across the DAF and broader DoW partners. Funding also supports experimentation, modeling, integration events, and studies to establish a common DAF MOSA approach. This includes leveraging commercial industry standards and government-driven standards. Additionally, funding supports horizontal integration and interoperability across Government Reference Architectures (GRAs) and standards. These efforts use Agile methodologies and Development, Security, and Operations (DevSecOps) software practices to deliver products securely to adopting platforms and enable continuous feedback to improve the standards. Further, funding provides targeted technical exploration and risk reduction with adopting platforms to facilitate their MOSA adoption while identifying any changes required within the DAF's MOSA standards. Funding may be utilized to implement innovation insertion, capability insertion, software increments, spiral upgrades, modular component swaps, and other insertions consistent with Modular Open System Architecture. Funding may be utilized to design, develop, integrate, and test weapon system and/or component level open architectures. Funding may be utilized to fund the concept refinement, design, development, integration, and testing of interdependent technologies and common architectures that underpin weapon system and portfolio-wide mission outcomes. Funding may be used to resolve Diminishing Manufacturing Sources and Material Shortages (DMSMS) and/or obsolescence issues. DMSMS activities may include, but are not limited to, bridge buys, life of type buys, buys to protect schedule, and engineering efforts. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                         Date: April 2026 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 5: System      PE 0605056F / Open Architecture Management Development & Demonstration (SDD) The Architecture and Systems Engineering (ASE) group, Fighter and Advanced Aircraft Directorate, Air Force Life Cycle Management Center (AFLCMC), Wright Patterson AFB executes these resources. In addition to this PE, the ASE group will continue execution of these related activities under the following PEs:0305206F/ Airborne Reconnaissance Systems [672003/Sensor Open Systems Architecture (SOSA)], and 0604602F/Armament/Ordnance Development (655361/Stores/Aircraft Interface). This requirement supports performance of a full financial audit as required by title 10 U.S.C. Chapter 9A, Sec 240-D. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605829F, 0605831F, 0605833F, or 0605898F. The FY 2026 funding request was reduced by 2.190 million to account for the availability of prior year execution balances. This program is in Budget Activity 5, System Development and Demonstration (SDD) because it has passed Milestone B approval and is conducting engineering and manufacturing development tasks aimed at meeting validated requirements prior to full rate production.$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume II.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605057F$$, $$Next Generation Air-refueling System$$, $$rdte_af_ba4$$, $$afrco$$, 2026, 12960000, 9325000, 7014000, NULL, $${"ba_raw": "6.4", "source": "af_r1_fy26", "original_pe": "0605057F"}$$::jsonb, $$Developing future tanker capability and recapitalizing the Air Force's aging tanker fleet is a top priority for the Department of the Air Force. In FY 2024, the Department of the Air Force amended its previous Tanker recapitalization approaches (KC-X, KC-Y, KC-Z) in favor of more agile methods, prioritizing and accelerating the right capabilities to deliver fuel to the fight. This funding will develop more advanced capabilities to allow tankers to operate in a more contested environment. The FY 2024 Analysis of Alternatives (AoA) provided conclusions that tankers will need to be more survivable to operate in a contested environment. Means to achieve this goal include but are not limited to examining the effectiveness and affordability of more resilient, connected, and survivable tanker systems. Future tanker fleet survivability capabilities are a top priority for the Department of the Air Force to counter pacing threats and enable B-21, CCAs, F-47, survivable tankers, and Space assets in contested environments. In FY 2026, this effort will continue AoA excursions, planning for transition of new technologies for resilient connectivity and survivability (mission systems), and further market research. The Future Tankers System Program Office will pursue cost versus capability analysis, updated tanker models and high-fidelity modeling and simulation to further exercise joint warfighting concepts and plans. This work will allow for concept refinement and support to requirements development to include potential refined attributes. This requirement supports performance of a full financial audit as required by title 10 U.S.C Chapter 9A, Sec 240-D. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605829F, 0605831F, 0605833F, or 0605898F. In FY 2024 $0.676 million was expended for civilian pay expenses in this program element, and in FY 2025 $1.18 million is forecast for civilian pay expenses in this program element. This effort is in Budget Activity 4, Advanced Component Development and Prototypes (ACD&P), because efforts are necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                         Date: June 2025 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 4: Advanced PE 0605057F / Next Generation Air-refueling System Component Development & Prototypes (ACD&P)$$, NULL, 0, 0, 0, NULL, NULL, 61, $$FY26 Air Force Research and Development Test and Evaluation Vol II.pdf$$, NULL, FALSE, 6891000, 11874000, 0, 0, 0, 0, 0, $$Developing future tanker capability and recapitalizing the Air Force's aging tanker fleet is a top priority for the Department of the Air Force. In FY 2024, the Department of the Air Force amended its previous Tanker recapitalization approaches (KC-X, KC-Y, KC-Z) in favor of more agile methods, prioritizing and accelerating the right capabilities to deliver fuel to the fight. The FY 2024 Analysis of Alternatives (AoA) provided conclusions that tankers will need to be more survivable to operate in a contested environment to include but not limited to examining the effectiveness and affordability of more resilient, connected, and survivable tanker systems. The Next Generation Air-refueling System (NGAS) program will develop more advanced capabilities to allow tankers to operate in a more contested environment. Future tanker fleet survivability capabilities are a top priority for the Department of the Air Force to counter pacing threats and enable B-21, CCAs, F-47, survivable tankers, and Space assets in contested environments. In FY 2027, NGAS will continue modeling and simulation support, planning for transition of new technologies for resilient connectivity and survivability (mission systems), and further market research. The Future Tankers System Program Office (SPO) will evaluate, research and pursue cost versus capability analysis, updated tanker models and high-fidelity modeling and simulation to further exercise joint warfighting concepts and plans. NGAS program Research, Development and Test (RDT&E) funding will allow for continued concept refinement and early risk reduction efforts to support continued requirements development and identify refined system attributes. This requirement supports performance of a full financial audit as required by title 10 U.S.C Chapter 9A, Sec 240-D. This program element included all necessary expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 0605829F, 0605831F, 0605833F, and 0605898F. This effort is in Budget Activity 4, Advanced Component Development and Prototypes (ACD&P), because efforts are necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                       Date: April 2026 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 4: Advanced PE 0605057F / Next Generation Air-refueling System Component Development & Prototypes (ACD&P)$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume II.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605058A$$, $$Terminal High Altitude Area Defense (THAAD) RDTE$$, $$rdte_army_ba5$$, $$dw_mda$$, 2027, 0, 0, 0, NULL, $${"fy26_v180": {"note": "FY27_only_PE_no_FY26_reality", "source": "b1_null_zero_v180"}}$$::jsonb, NULL, NULL, 974925000, 794478000, 874736000, NULL, NULL, NULL, NULL, NULL, FALSE, NULL, 0, 1053983000, 1053983000, NULL, 1053983000, 998763000, $$THAAD system provides Combatant Commands a globally-transportable, rapidly-deployable capability to track, intercept, and destroy short-range, medium-range, and limited intermediate-range missile threats inside or outside the atmosphere during terminal phase of flight. This Program Element investigates concepts and continues the development and integration of multiple, independent THAAD system builds to address the evolving threat, improve reliability, availability and readiness, defense planning, and improved capability to engage short-range ballistic missile, medium-range ballistic missile, and limited intermediate-range ballistic missile threats.$$, $$Budget J-Books/FY27/Army/RDTEVol3BudgetActivity5C.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605080S$$, $$Defense Agencies Initiative (DAI) - Financial System$$, $$rdte_dw_ba5$$, $$dw$$, 2026, 31714000, 28482000, 31916000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "dw", "page_num": 74, "original_pe": "0605080S", "page_header": "Defense-Wide"}$$::jsonb, $$The Defense Agencies Initiative (DAI) program, a Category I Defense Business System, is an Enterprise Resource Planning (ERP) based program originally created to solve Defense Agency financial management problems through standard end-to-end business processes delivered by commercial off-the-shelf (COTS) software. DAI’s mission is to provide an auditable, Chief Financial Officer (CFO) Act compliant business environment for the Defense customer organizations with accurate, timely, and authoritative financial data. DAI supports continued development and fielding of its current Increment 3 baseline. Previous funding for DAI Increments 1 and 2 were documented in the Defense Enterprise Business Systems program element 50605070S00. Increment 3 will deliver new financial capabilities including Defense Working Capital Fund (DWCF) and Re-Sale accounting plus a major application upgrade.$$, NULL, 42586000, 53732000, 39011000, NULL, NULL, 151, $$RDTE_DLA_PB_2026.pdf$$, $$DLA$$, FALSE, 30813000, 31714000, 51265000, 51265000, NULL, 51265000, 34903000, $$The Defense Agencies Initiative (DAI) program, a Category I Defense Business System, is an Enterprise Resource Planning (ERP) based program originally created to solve Defense Agency financial management problems through standard end-to-end business processes delivered by commercial off-the-shelf (COTS) software. DAI’s mission is to provide an auditable, Chief Financial Officer (CFO) Act compliant business environment for the Defense customer organizations with accurate, timely, and authoritative financial data. DAI supports continued development and fielding of its current Increment 3 baseline. Previous funding for DAI Increments 1 and 2 were documented in the Defense Enterprise Business Systems program element 50605070S00. Increment 3 will deliver new financial capabilities including Defense Working Capital Fund (DWCF) and Re-Sale accounting plus a major application upgrade. The FY 2026 spend plan amount for Research, Development, Test, and Evaluation, Defense-Wide for DAI includes $31.714 thousand of discretionary and $20.000 thousand of mandatory (reconciliation) for a total of $51.714 thousand.$$, $$Budget J-Books/FY27/Remaining/RDTE_DLA_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605100D8Z$$, $$Joint Mission Environment Test Capability (JMETC)$$, $$rdte_dw_ba6$$, $$dw$$, 2026, 210878000, 175131000, 192777000, NULL, $${"act": "06", "ba_raw": "6.6", "source": "r1_fy26", "service": "dw", "page_num": 76, "original_pe": "0605100D8Z", "page_header": "Defense-Wide"}$$::jsonb, $$This program supports the Department's priorities to rebuild the military by matching threats to capabilities and re-establish deterrence by defending our homeland. The Joint Mission Environment Test Capability (JMETC) program provides a Department of Defense (DoD) enterprise-wide test capability to support system-to- system interoperability testing, mission-level environment testing, and cyber event operations, including cyber testing, cyber training, cyber experimentation, and cyber mission rehearsal. The JMETC program implements the infrastructure capabilities defined in the DoD “Testing in a Joint Environment Roadmap” to provide acquisition program managers a robust nation-wide capability to “test like we fight.” The JMETC program provides a persistent, distributed test and evaluation (T&E) capability that supports system development to measure and improve interoperability performance and cyber resiliency, and provide a software acquisition pathway that otherwise would not be readily available to Service/Component acquisition programs. The JMETC program is funded within the Research, Development, Test and Evaluation (RDT&E) Management Support Budget Activity because it provides test capability in support of RDT&E programs. By linking distributed facilities, as well as providing the necessary tools, services and subject matter expertise, the JMETC program allows acquisition programs to efficiently evaluate their warfighting capability in a realistic joint mission environment. The JMETC program has been aligned to national strategic guidance to advance the Department’s readiness to experiment and test the development of resilient, survivable, federated networks and information systems from the tactical level up to strategic planning, as well as test and assess cyber defenses that deter aggression and achieve peace through strength. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Office of the Secretary Of Defense                                                Date: June 2025 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 6:           PE 0605100D8Z / Joint Mission Environment Test Capability (JMETC) RDT&E Management Support$$, NULL, 200181000, 206139000, 212208000, NULL, NULL, 171, $$RDTE_OSD_PB_2026.pdf$$, $$OSD$$, FALSE, 192258000, 189690000, 234700000, 234700000, NULL, 234700000, 216981000, $$The Test Resource Management Center (TRMC) Joint Mission Environment Test Capability (JMETC) program supports the Department's priorities to rebuild the military and re-establish deterrence. The JMETC program provides a Department-wide test capability to support system-to-system interoperability testing, mission- level environment testing, and cyber event operations, including cyber testing, cyber training, cyber experimentation, and cyber mission rehearsal. The JMETC program implements the infrastructure capabilities defined in the Department’s “Testing in a Joint Environment Roadmap” to provide acquisition program managers a robust nation-wide capability to “test like we fight.” The JMETC program provides a persistent, distributed test and evaluation (T&E) capability that supports system development to measure and improve interoperability performance and cyber resiliency, and provides a software acquisition pathway that otherwise would not be readily available to Service/Component acquisition programs. The JMETC program is funded within the Research, Development, Test and Evaluation (RDT&E) Management Support Budget Activity because it provides test capability in support of RDT&E programs. By linking distributed facilities, as well as providing the necessary tools, services and subject matter expertise, the JMETC program allows acquisition programs to efficiently evaluate their warfighting capability in a realistic joint mission environment. The JMETC program has been aligned to national strategic guidance to advance the Department’s readiness to experiment and test the development of resilient, survivable, federated networks and information systems from the tactical level up to strategic planning, as well as test and assess cyber defenses that deter aggression and achieve peace through strength. The FY 2026 spend plan amount for the Joint Mission Environment Test Capability includes $189,690 thousand discretionary funding and $250,000 thousand mandatory funding, for a total of $439,690 thousand. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Office of the Secretary Of Defense                                            Date: April 2026 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 6:         PE 0605100D8Z / Joint Mission Environment Test Capability (JMETC) RDT&E Management Support$$, $$Budget J-Books/FY27/DW/RDTE_OSW_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$P_1810_L061$$, $$Maritime Integrated Broadcast System$$, $$proc_navy_1810_ba2$$, $$navsea$$, 2026, 0, 6433000, 0, NULL, $${"page": 98, "ba_num": "02", "source": "p1_fy26", "ba_name": "Communications and electronics equipment", "line_no": "61", "service": "navy", "fy24_qty": null, "fy25_qty": null, "fy27_v25": {"ba": "02", "appr": "OPN", "title": "P-1 Line 56", "applied_at": "2026-05-09", "fy27_ooc_K": 0, "source_pdf": "Budget J-Books/FY27/Navy/OPN_BA{1..5-8}_Book.pdf", "fy27_base_K": 83057, "p1_line_num": 56, "fy27_total_K": 83057}, "appr_code": "1810", "appr_name": "Other Procurement, Navy", "fy26_v179": {"disc_K": 97262, "li_num": 56, "source": "p40_fy26_v179", "supp_K": 0, "source_pdf": "uploads/Budget J-Books/FY27/Navy/OPN_BA2_Book.txt"}, "fy26t_qty": null, "fy26d_cost": 0, "fy26r_cost": 0, "ident_code": "A"}$$::jsonb, NULL, NULL, NULL, NULL, NULL, NULL, 105389000, NULL, NULL, NULL, FALSE, 8479000, 0, 83057000, 83057000, 0, 83057000, NULL, NULL, $$Budget J-Books/FY27/Navy/OPN_BA2_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605101F$$, $$RAND Project Air Force$$, $$rdte_af_ba6$$, $$aflcmc_wa$$, 2026, 32405000, 30998000, 39720000, NULL, $${"ba_raw": "6.6", "source": "af_r1_fy26", "original_pe": "0605101F"}$$::jsonb, $$MISSION DESCRIPTION PAF helps DAF and Congressional leaders make informed, research-based decisions to meet critical challenges and solve policy issues of vital concern to ensure the success of our warfighters; plan for and defeat the accelerated threats from China and Russia; integrate air, space, and cyber capabilities across warfighting domains to enable U.S. advantage and to stay ahead of the innovation curve. PAF provides the DAF and the nation a return on investment that far exceeds its costs. PAF provides actionable recommendations on highest priority issues for DAF and saves billions of dollars while maximizing lethality and readiness. PAF research examines critical issues for DAF leadership: designing a survivable posture in the Pacific; operating in a contested electromagnetic environment; enlisted technical tracks; collaborating with allies and partners; and many more. PAF's research findings inform DAF and Congressional decision makers on high-priority programs like the F-35, the future intercontinental ballistic missile force, and the future long-range strike family of systems. PAF's cutting-edge research will help the DAF rapidly adapt to the changing world environment and emerging threats; continue to modernize and employ its force structure to provide capabilities within changing DoD budgets; assess lessons learned from recent and ongoing conflicts; develop and utilize its total force; and enhance the support of our air and space forces, ranging from sustainment of the force structure to agile combat support. RAND Project Air Force (PAF) is a Congressionally Mandated Federally Funded Research and Development Center (FFRDC). PAF is the Department of the Air Force's (DAF's) only FFRDC dedicated to studies and analysis. PAF's Steering Group is chaired by the USecAF, VCSAF and VCSO with Congressional, OSD, and DAF Top 7 oversight. BUDGET ITEM JUSTIFICATION In FY25, RAND PAF funding levels were restored to historical, required levels to maintain critical, analytic capability. If proposed the 8.3M funding cut for FY26 occurs, DAF and Congression will once again lose critical analytic capabilities. Without correction, FY26 funding levels will fall to a lower level than what is required to meet DAF's needs. Core research will not be provided in areas of strengthening alliances and regional partnerships, operational and tactical innovation, and logistics and defense in forward environments, emerging technologies, force readiness, and other issues. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                        Date: June 2025 Appropriation/Budget Activity                                               R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 6: RDT&E     PE 0605101F / RAND Project Air Force Management Support 0606398F. In FY22 0M was expended for civilian pay expenses in this program element, and in FY23 0M is forecasted for civilian pay expenses in this program element. This program is in Budget Activity 6, RDT&E Management Support because this budget activity includes research, development, test and evaluation efforts and funds to sustain and/or modernize the installations or operations required for general research, development, test and evaluation.$$, NULL, 13827000, 14076000, 14334000, NULL, NULL, 127, $$FY26 Air Force Research and Development Test and Evaluation Vol III.pdf$$, NULL, FALSE, 38270000, 31961000, 13312000, 13312000, 0, 13312000, 14624000, $$MISSION DESCRIPTION Formally designated mission-critical, RAND Project Air Force (PAF) is the Department of the Air Force's (DAF's) sole Congressionally Mandated Federally Funded Research and Development Center (FFRDC) for studies and analysis. For 78 years, PAF has provided essential, objective analysis to inform DAF and Congressional decisions, with a research agenda directed by the DAF's highest levels, including the Tri-Chair Steering Group chaired by the USecAF, VCSAF, and VCSO. PAF provides a return on investment that far exceeds its costs. Its actionable recommendations have saved billions of dollars while maximizing lethality and readiness. Recent examples include saving $17 billion from an airlift recapitalization strategy and preventing a $30 billion budgetary spike through analysis of the Future Aerial Refueling Enterprise. PAF research informs the DAF's most crucial decisions, from Collaborative Combat Aircraft (CCA) force design and cost-effective air base resilience to improving space acquisition. Notably, PAF's latest work on Dynamic Space Operations (DSO) directly influenced the VCSO's strategy for refueling spacecraft and is being used to formally respond to a FY 2026 Congressional requirement. This program is in Budget Activity 6, RDT&E Management Support because this budget activity includes research, development, test and evaluation efforts and funds to sustain and/or modernize the installations or operations required for general research, development, test and evaluation.$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume III.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605103A$$, $$Rand Arroyo Center$$, $$rdte_army_ba6$$, $$asa_alt$$, 2026, 10892000, 35312000, 38122000, NULL, $${"act": "06", "ba_raw": "6.6", "source": "r1_fy26", "service": "army", "page_num": 20, "original_pe": "0605103A", "page_header": "Department of the Army"}$$::jsonb, $$This Program Element funds the RAND-Arroyo Center, the Department of the Army's Federally Funded Research and Development Center, for strategic studies and analysis. The Army's management of RAND-Arroyo's activities are governed by AR 5-21. RAND-Arroyo Center provides strategic analytical research across a broad spectrum of issues grouped into the following core competencies research areas: Personnel, Training, and Health; Forces and Logistics; and Strategy, Doctrine and Resources; applied national security knowledge; academic rigor; multidisciplinary teams; and dynamism, which includes innovation and agility. The RAND-Arroyo Center research agenda is primarily focused on mid/long-term strategic concerns. Current priorities include: implementation of the National Defense Strategy; total force readiness; Army modernization; operations and dynamic force employment; reform of business processes; multi-domain operations; soldier-centric investments; and soldier and family resilience. Results and analytical findings directly affect senior leadership deliberations on major issues. The Arroyo Center Policy Committee (ACPC), is co-chaired by the Under Secretary of the Army and Vice Chief of Staff of the Army, provides guidance, sets the annual research plan, and monitors execution. RAND- Arroyo research is sponsored by Army Senior Leaders and Army Major Commands. In FY21, the ACPC 1) directed a change in the execution of the RAND-Arroyo program which resulted in a change to the business model and 2) directed a consolidation of existing resources for the RAND-Arroyo program.$$, NULL, 10510000, 10210000, 9928000, NULL, NULL, 176, $$RDTE - Vol 4 - Budget Activity 6.pdf$$, NULL, FALSE, 31144000, 10892000, 10737000, 10737000, NULL, 10737000, 10027000, $$This Program Element funds the RAND-Arroyo Center, the Department of the Army's only Federally Funded Research and Development Center, for strategic studies and analysis. The Army's management of RAND-Arroyo's activities are governed by AR 5-21 and receives guidance through the Arroyo Center Policy Committee (ACPC), which is co-chaired by the Under Secretary of the Army and the Vice Chief of Staff of the Army. The ACPC provides guidance, sets the annual research plan, and monitors execution. As a result, the RAND-Arroyo Center provides strategic analytical research across a broad spectrum of issues grouped in three major research areas: Personnel, Training, and Health; Forces and Logistics; and Strategy, Doctrine and Resources. The RAND-Arroyo Center research agenda is primarily focused on mid/long-term strategic concerns. Current priorities include: implementation of the National Defense Strategy; collaborative lethality & survivability, sustaining the joint force, balancing capability modernization across FYDPs, taking care of people, and homeland defense. Results and analytical findings directly affect senior leadership deliberations on major issues. In FY21 the ACPC directed a change in the execution of the RAND-Arroyo program which resulted in a change to business practices and directed a consolidation of existing resources for the RAND-Arroyo Center program. Note that FY24 includes SBIR (Title 15 USC &#167;638(f)(1)) in the amount of $1,173K and STTR (Title 15 USC &#167;638(n)(1)(A)) in the amount of $165K.$$, $$Budget J-Books/FY27/Army/RDTE - Vol 4 - Budget Activity 6.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605117F$$, $$Foreign Materiel Acquisition and Exploitation$$, $$rdte_af_ba7$$, $$aflcmc$$, 2026, 0, 166851000, 94188000, NULL, $${"ba_raw": "6.7", "source": "af_r1_fy26", "original_pe": "0605117F"}$$::jsonb, $$This is a MIP Program. Funding for the activity in this PE from FY26 and beyond has been transferred to an alternate PE. The FMA&E activity will resume in that PE. The Foreign Materiel Acquisition and Exploitation (FMA&E) program element supports the military services' and defense agencies' Foreign Material Program activities. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such programs funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In PY $0.889M was expended for civilian pay expenses in this program element, and in CY $1.416M is forecasted for civilian pay expenses in this program element. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, NULL, 4235000, 4441000, 4515000, NULL, NULL, 156, $$FY26 Air Force Research and Development Test and Evaluation Vol III.pdf$$, NULL, FALSE, 123775000, 0, 4676000, 4676000, 0, 4676000, 4607000, $$This is a MIP Program. Funding for the activity in this PE from FY2026 and beyond has been transferred to an alternate PE. The FMA&E activity will resume in that PE. The Foreign Materiel Acquisition and Exploitation (FMA&E) program element supports the military services' and defense agencies' Foreign Material Program activities. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such programs funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume III.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605126J$$, $$Joint Integrated Air & Missile Defense Organization (JIAMDO)$$, $$rdte_dw_ba6$$, $$dw_js$$, 2026, 78057000, 59424000, 65823000, NULL, $${"act": "06", "ba_raw": "6.6", "source": "r1_fy26", "service": "dw", "page_num": 76, "original_pe": "0605126J", "page_header": "Defense-Wide"}$$::jsonb, NULL, NULL, 68639000, 69552000, 70990000, NULL, NULL, NULL, NULL, NULL, FALSE, 63420000, 69706000, 69820000, 69820000, NULL, 69820000, 72455000, $$The Joint Integrated Air and Missile Defense Organization (JIAMDO) is the organization within the Department of War chartered to plan, coordinate, and oversee Integrated Air and Missile Defense (IAMD) requirements, joint operational concepts, and operational architectures. As part of the Joint Staff, JIAMDO supports the Chairman in meeting Title 10 responsibilities as they relate to IAMD issues. JIAMDO supports the Joint Requirements Oversight Council (JROC) in its Title 10 U.S. Code 181 authorities as the Joint Staff lead of the IAMD Capability Portfolio Management Review (CPMR) process. JIAMDO is the operational community’s proponent for requirements and capabilities in IAMD, and is the joint IAMD proponent within the DoW’s resource allocation structures. JIAMDO also leads IAMD mission and utility analysis, integrates IAMD within the force protection joint capability area, conducts evaluations, demonstrations of joint IAMD architectures, and provides advocacy for innovative, technically mature, and affordable solutions. JIAMDO executes these duties for major efforts within the Department, such as the Golden Dome for America and the Guam Defense System. JIAMDO has established a close partnership with Combatant Commands (CCMDs) and maintains close coordination with U.S. Space Command (USSPACECOM), U.S. Strategic Command (USSTRATCOM), U.S. Northern Command (USNORTHCOM), and U.S. Indo Pacific Command (USINDOPACOM) in support of ballistic, cruise, and hypersonic missile defense of the United States. JIAMDO provides the CJCS and the Joint Requirements Oversight Council the ability to meet statutory responsibilities to review cost, schedule, and performance criteria of Missile Defense Agency missile defense programs and assesses the validity of those criteria in relation to national and military requirements. At the direction of the JROC, JIAMDO develops the joint IAMD portfolio priority list, Nimble Fire exercises, Joint Regional IAMD Capability Mix studies, and operational analysis of the Missile Defense System. JIAMDO supports USSPACECOM and USSTRATCOM ballistic missile early warning mission by ensuring operational and technical requirements are integrated into the theater missile warning architecture. JIAMDO also provides direct support to North American Aerospace Defense Command and USNORTHCOM for homeland air and cruise missile surveillance issues and technical oversight of homeland capability solutions. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 The Joint Staff                                                                Date: April 2026 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 6:          PE 0605126J / Joint Integrated Air & Missile Defense Organization (JIAMDO) RDT&E Management Support$$, $$Budget J-Books/FY27/Remaining/RDTE_TJS_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605131D8Z$$, $$Live Fire Testing$$, $$rdte_dw_ba6$$, $$dw$$, 2027, 0, 0, 0, NULL, $${}$$::jsonb, NULL, NULL, 9204000, 9387000, 9570000, NULL, NULL, NULL, NULL, NULL, FALSE, 0, 0, 9020000, 9020000, NULL, 9020000, 9882000, $$Live Fire Testing - Joint Aircraft Survivability Program (JASP) is the Department of War's (DoW) focal point for joint service enhancement of military aircraft non-nuclear survivability. The JASP is chartered by the Commander of the U.S. Navy Naval Air Systems Command, the U.S. Assistant Secretary of the Army (Acquisition Logistics and Technology), and the Commander of the U.S. Air Force Life Cycle Management Center to increase the affordability, readiness, and effectiveness of Tri-Service aircraft through joint coordination and development of survivability technologies, design tools and assessment methodologies. The JASP coordinates and conducts RDT&E to improve military aircraft survivability, develop and standardize aircraft survivability M&S, facilitate information exchange on aircraft survivability, and support aircraft survivability education for the DOW and U.S. aircraft community. Each chartering command provides a senior aircraft survivability expert for the JASP Principal Members Steering Group, which guides the program and approves projects for funding. The JASP assesses and reports on U.S. military aircraft combat damage incidents through the Joint Combat Assessment Team (JCAT).$$, $$Budget J-Books/FY27/DW/RDTE_OSW_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605131OTE$$, $$Live Fire Test and Evaluation (LFT&E)$$, $$rdte_ote_ba6$$, $$afrl_rw$$, 2026, 206109000, 105593000, 109561000, NULL, $${"act": "06", "ba_raw": "6.6", "source": "r1_fy26", "service": "dw", "page_num": 84, "original_pe": "0605131OTE", "page_header": "Defense-Wide"}$$::jsonb, $$This Program Element consists of three programs: Joint Live Fire (JLF), Joint Aircraft Survivability Program (JASP), and Joint Technical Coordinating Group for Munitions Effectiveness (JTCG/ME). This Program Element directly supports the Congressional statutory requirements for oversight of LFT&E. The primary objective of LFT&E is to assure that the vulnerability and survivability of Department of Defense (DoD) crew-carrying platforms and the lethality of our conventional munitions are known and acceptable before entering full-rate production. LFT&E encompasses realistic tests involving actual U.S. and foreign threat hardware or, if not available, acceptable surrogate threat hardware. The objective is to identify and correct design deficiencies early in the development process. A completed LFT&E program and test report is required before programs proceed beyond low-rate initial production (BLRIP). LFT&E also includes realistic modeling and simulation (M&S) to examine survivability and lethality attributes not assessed during testing. This Program Element supports the DoD’s JLF Program, initiated in 1984 under an Office of the Secretary of Defense charter to test fielded front-line combat aircraft and armor systems for their vulnerabilities as well as fielded weapons, both U.S. and foreign, for their lethality against their respective targets. Funds are also used to support other initiatives related to quick reaction requests from theater and other areas of personnel survivability. Through its evolution, the JLF program also facilitates the development of adequate LFT&E tools, methods, and infrastructure required for credible development of both, Joint Munitions Effectiveness Manuals (JMEM) weaponeering tools and LFT&E programs. JASP is the DoD’s focal point for joint service enhancement of military aircraft non-nuclear survivability. The JASP is chartered by the Commander of the U.S. Navy Naval Air Systems Command, the Assistant Secretary of the Army (Acquisition, Logistics, and Technology), and the Commander of the U.S. Air Force Life Cycle Management Center to increase the affordability, readiness, and effectiveness of tri-Service aircraft through joint coordination and development of survivability technologies, design tools, and assessment methodologies. The JASP coordinates and conducts RDT&E to improve military aircraft survivability, develop and standardize aircraft survivability M&S, facilitate information exchange on aircraft survivability, and support aircraft survivability education for the DoD and U.S. aircraft community. Each chartering command provides a senior aircraft survivability expert for the JASP Principal Members Steering Group, which guides the program and approves projects for funding. The JASP assesses and reports on combat damage incidents through the Joint Combat Assessment Team (JCAT). JTCG/ME was chartered to serve as DoD’s focal point for munitions effectiveness information. The JTCG/ME produces Joint Munitions Effectiveness Manuals (JMEMs) that are the sole source for all joint Service authenticated non-nuclear weapons effectiveness data and methodology for the DoD. The JMEMs are the “how to” manuals for putting ordnance on target and as such, directly impacts combat readiness, effectiveness, and survivability. JMEMs are used by the warfighters in operational weaponeering and collateral damage estimation (CDE) calls in direct support of operations, mission planning, and training; by the DoD, joint, and Service planners in force-on-force M&S, mission area analysis, requirements studies, and weapon procurement planning; and by the Service acquisition community in performance Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Operational Test and Evaluation, Defense                                            Date: June 2025 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 0460: Operational Test and Evaluation, Defense / BA 6: RDT&E Management PE 0605131OTE / Live Fire Test and Evaluation (LFT&E) Support assessment, analysis of alternatives, and survivability enhancement studies. The JTCG/ME continually evolves weapons effectiveness and target vulnerability data, standards, methodologies, and processes based on the strategic environment for better munitions effectiveness evaluation and support to a more lethal force. JTCG/ME also increases efficiency by leveraging ongoing DoD efforts and supporting the DoD's intent to complement U.S. interest and capabilities by providing weaponeering and targeting capability to coalition partners. The JMEM requirements and development processes are driven by operational lessons learned (e.g., Inherent Resolve, Resolute Support, and Freedom Sentinel); Joint Staff data calls, and the needs of combatant commands (CCMDs), the Services, the Military Targeting Committee (MTC) guided by Chairman of the Joint Chiefs of Staff Instruction (CJCSI) 5140.01, Munitions Requirements Process - DoD Instruction 3000.04 and Operational Users Working Groups (OUWGs) input for specific weapon- target pairings and methodologies. Considerable effort goes into these user forums to establish warfighter requirements for current and future JTCG/ME products, as well as continued training events and day-to-day support - all with the goal of enabling greater force lethality, strengthened partner capabilities, and optimal use of resources. This Program Element also includes funds to obtain Federally Funded Research and Development Center (FFRDC) expertise in performing analyses in support of described LFT&E tasks, as well as travel funds to carry out the JLF, JASP, and JTCG/ME programs.$$, NULL, 11220000, 11444000, 11673000, NULL, NULL, 2, $$RDTE_OTE_PB_2026.pdf$$, $$OT&E$$, FALSE, 109561000, 108109000, 11000000, 11000000, NULL, 11000000, 11906000, $$In 2026, this Program Element consisted of four programs: (1) Live Fire Test and Evaluation Oversight, (2) Joint Live Fire (JLF), (3) Joint Aircraft Survivability Program (JASP), and (4) Joint Technical Coordinating Group for Munitions Effectiveness (JTCG/ME). Beginning in 2027, JASP will transition to the Office of the Under Secretary of War for Acquisition and Sustainment, and JLF and JTCG/ME will transition to the Office of the Under Secretary of War for Research and Engineering. This Program Element will now solely support the Congressional statutory requirements for oversight of LFT&E. The primary objective of LFT&E is to assure that the vulnerability and survivability of DoW crew-carrying platforms and the lethality of our conventional munitions are known and acceptable before entering full-rate production. LFT&E encompasses realistic tests involving actual U.S. and foreign threat hardware or, if not available, acceptable surrogate threat hardware. The objective is to identify and correct design deficiencies early in the development process. A completed LFT&E program and test report is required before programs proceed beyond low-rate initial production (BLRIP). LFT&E also includes realistic M&S to examine survivability and lethality attributes not assessed during testing. This Program Element previously supported the DoW’s JLF program, initiated in 1984 under an Office of the Secretary of Defense charter to test fielded front-line combat aircraft and armor systems for their vulnerabilities as well as fielded weapons, both U.S. and foreign, for their lethality against their respective targets. Funding was used to support other initiatives related to quick reaction requests from theater as well as other areas of personnel survivability. Through its evolution, the JLF program also facilitates the development of adequate LFT&E tools, methods, and infrastructure required for credible development of both Joint Munitions Effectiveness Manuals (JMEM) weaponeering tools and LFT&E programs. JASP is the DoW’s focal point for joint Service enhancement of military aircraft non-nuclear survivability. The JASP is chartered by the Commander of the U.S. Navy Naval Air Systems Command, the Assistant Secretary of the Army (Acquisition, Logistics, and Technology), and the Commander of the U.S. Air Force Life Cycle Management Center to increase the affordability, readiness, and effectiveness of tri-Service aircraft, through joint coordination and development of survivability technologies, design tools, and assessment methodologies. The JASP coordinates and conducts research, development, test, and evaluation (RDT&E) to improve military aircraft survivability, develop and standardize aircraft survivability M&S, facilitate information exchange on aircraft survivability, and support aircraft survivability education for the DoW and U.S. aircraft community. Each chartering command provides a senior aircraft survivability expert for the JASP Principal Members Steering Group, which guides the program and approves projects for funding. The JASP assesses and reports on combat damage incidents through the Joint Combat Assessment Team (JCAT). JTCG/ME was chartered to serve as DoW’s focal point for munitions effectiveness information. The JTCG/ME produces JMEMs that are the sole source for all joint- Service-authenticated non-nuclear weapons effectiveness data and methodology for the DoW. The JMEMs are the “how to” manuals for putting ordnance on target and as such, they directly impact combat readiness, effectiveness, and survivability. JMEMs are used by the warfighters in operational weaponeering and collateral damage estimation (CDE) calls in direct support of operations, mission planning, and training; by the DoW, joint, and Service planners in force-on-force M&S, mission area Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Operational Test and Evaluation, Defense                                            Date: April 2026 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 0460: Operational Test and Evaluation, Defense / BA 6: RDT&E Management PE 0605131OTE / Live Fire Test and Evaluation (LFT&E) Support analysis, requirements studies, and weapon procurement planning; and by the Service acquisition community in performance assessment, analysis of alternatives, and survivability enhancement studies. The JTCG/ME continually evolves weapons effectiveness and target vulnerability data, standards, methodologies, and processes, based on the strategic environment for better munitions effectiveness evaluation and support to a more lethal force. JTCG/ME also increases efficiency by leveraging ongoing DoW efforts and supporting the DoW’s intent to complement U.S. interest and capabilities by providing weaponeering and targeting capability to coalition partners. The JMEM requirements and development processes are driven by operational lessons learned (e.g., Inherent Resolve, Resolute Support, and Freedom Sentinel); Joint Staff data calls; and the needs of CCMDs, the Services, the Military Targeting Committee (MTC) guided by Chairman of the Joint Chiefs of Staff Instruction (CJCSI) 5140.01, DoD Instruction 3000.04 (DoD Munitions Requirements Process (MRP)),and operational users working groups’ (OUWGs) input for specific weapon-target pairings and methodologies. Considerable effort goes into these user forums to establish warfighter requirements for current and future JTCG/ME products, as well as continued training events and day-to-day support – all with the goal of enabling greater force lethality, strengthened partner capabilities, and optimal use of resources. This Program Element will now solely fund FFRDC expertise in performing analyses in support of LFT&E oversight.$$, $$Budget J-Books/FY27/Remaining/RDTE_OTE_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605141BR$$, $$MISSION ASSURANCE RISK MANAGEMENT SYSTEM (MARMS)$$, $$rdte_dw_ba5$$, $$dw_osd$$, 2026, 9573000, 9080000, 9440000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "dw", "page_num": 74, "original_pe": "0605141BR", "page_header": "Defense-Wide"}$$::jsonb, $$The Mission Assurance Risk Management System (MARMS) is a Department of Defense (DoD) risk management system that directly supports the Secretary of Defense Mission Assurance responsibilities as defined in the DoD Directive 3020.40, Mission Assurance, with the objectives of creating resilience and supporting critical processes to enable the protection of assets and ensuring defense critical missions across 17 Mission Assurance Related Programs and Activities. MARMS functions as an integration framework spanning multiple security domains that will support risk-informed decision-making, resource investment, and improved synchronization at different levels within DoD. MARMS supports multiple Joint Capability Areas: Command and Control, Logistics, and Protection. MARMS is a joint program and an acquisition category Ill software-intensive and situational awareness program in the agile-based Adaptive Acquisition Framework – Software Pathway.$$, NULL, 0, 0, 0, NULL, NULL, 152, $$RDTE_DTRA_PB_2026.pdf$$, $$DTRA$$, FALSE, 9207000, 9573000, 0, 0, 0, 0, 0, $$The Mission Assurance Risk Management System (MARMS) is a Department of War (DoW) risk management system that directly supports the Secretary of War Mission Assurance responsibilities as defined in the DoD Directive 3020.40, Mission Assurance, with the objectives of creating resilience and supporting critical processes to enable the protection of assets and ensuring defense critical missions across 17 Mission Assurance Related Programs and Activities. MARMS functions as an integration framework spanning multiple security domains that will support risk-informed decision-making, resource investment, and improved synchronization at different levels within DoW. MARMS supports multiple Joint Capability Areas: Command and Control, Logistics, and Protection. MARMS is a joint program and an acquisition category Ill software-intensive and situational awareness program in the agile-based Adaptive Acquisition Framework – Software Pathway.$$, $$Budget J-Books/FY27/Remaining/RDTE_DTRA_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605142D8Z$$, $$Systems Engineering$$, $$rdte_dw_ba6$$, $$dw_osd$$, 2026, 23405000, 29573000, 24669000, NULL, $${"act": "06", "ba_raw": "6.6", "source": "r1_fy26", "service": "dw", "page_num": 76, "original_pe": "0605142D8Z", "page_header": "Defense-Wide"}$$::jsonb, $$The Systems Engineering program element establishes dedicated funding to carry out the duties as described in 10 U.S.C 133a and the Department of Defense Directive 5137.02, “Under Secretary of Defense for Research and Engineering (USD(R&E)),” dated July 15, 2020. In alignment with the 2025 Interim National Defense Strategic Guidance, the program element supports the administration’s top priorities of Rebuild Our Military and Reestablish Deterrence by reforming the acquisition process, rapidly fielding emerging technologies, and building a resilient Joint Force and defense ecosystem. This funding directly supports defense acquisition programs and supports rapidly fielding emerging technologies identified by the USD (R&E). Furthermore, it supports the implementation of Department initiatives and advances the development, modernization, and adoption of emerging technologies with speed and agility in the areas of systems engineering, interoperability, digital engineering, software engineering, model-based systems engineering, specialty engineering, value engineering, modular open systems approaches, standardization, and workforce development. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Office of the Secretary Of Defense                                  Date: June 2025 Appropriation/Budget Activity                                             R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 6:      PE 0605142D8Z / Systems Engineering RDT&E Management Support$$, NULL, 23466000, 24373000, 24929000, NULL, NULL, 174, $$RDTE_OSD_PB_2026.pdf$$, $$OSD$$, FALSE, 23910000, 24606000, 21992000, 21992000, NULL, 21992000, 24942000, $$The Systems Engineering program element establishes dedicated funding to carry out the duties as described in 10 U.S.C 133a and the Department of Defense Directive 5137.02, “Under Secretary of Defense for Research and Engineering (USD(R&E)),” dated July 15, 2020. In alignment with the 2026 National Defense Strategy (NDS), particularly the line of effort to “Supercharge the U.S. Defense Industrial Base,” the program element supports key activities such as reforming the acquisition process, rapidly fielding emerging technologies, and building a resilient Joint Force. These efforts are foundational to the NDS overarching goal of “Restoring Peace Through Strength.” This funding supports presidential priorities as documented in Executive Order 14265, “Modernizing Defense Acquisitions and Spurring Innovation in the Defense Industrial Base” and is a key enabler of the Department’s “Acquisition Transformation Strategy (ATS),” supporting the ATS goal to field technology and modernize systems at a rate that outpaces our adversaries. Specifically, this funding advances the ATS pillar to “Develop High Performance Systems through Rigorous Enterprise Technical and Execution Excellence.” It achieves this by driving the modernization and adoption of critical disciplines, including systems engineering, digital and model- based systems engineering, and software engineering. Furthermore, it accelerates the implementation of modular open systems approaches (MOSA) to promote interoperability and competition. In alignment with the ATS pillar to “Elevate and Empower the Acquisition Workforce,” this funding supports vital workforce development initiatives to build and sustain the talent required to deliver capability with speed and agility. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Office of the Secretary Of Defense                                             Date: April 2026 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 6:         PE 0605142D8Z / Systems Engineering RDT&E Management Support$$, $$Budget J-Books/FY27/DW/RDTE_OSW_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605144A$$, $$Next Generation Load Device - Medium$$, $$rdte_army_ba5$$, $$asa_alt$$, 2026, 24492000, 36970000, 2931000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "army", "page_num": 18, "original_pe": "0605144A", "page_header": "Department of the Army"}$$::jsonb, $$This funding enables the Army's Next Generation Command and Control (NGC2) initiative to modernize Command and Control (C2) systems. This Program Element (PE) is a critical enabler of the Army Modernization Priorities including Cryptographic Modernization 2 (CM2) addressing current and emerging cyber security threats. This PE funds the development and test of the Next Generation Load Device - Medium (NGLD-M). This product issues, fills, and manages cryptographic key and mission planning products from the National Security Agency (NSA) Key Management Infrastructure (KMI) and End-Cryptographic Units (ECUs). The NGLD-M enhances the capabilities of the legacy product, the Simple Key Loader (SKL), by providing secure, Over-the-Network Keying (OTNK), reducing the logistics burden of touching all ECUs across the force and is CM2 compliant. In addition, the SKL is facing significant parts availability challenges and NGLD-M is urgently required to replace it as the whole government solution for cryptographic key management and distribution. This effort is an Acquisition Category III (ACAT III) Program of Record (POR) and has multi-service and multi-national stakeholder interest. The acquisition strategy for the program leverages two hardware vendors with a Government developed User Application Software (UAS) providing a common user experience across individual vendor hardware solutions. The program is progressing towards Milestone C and will 1:1 replace the SKL following an Initial Operational Test and Evaluation (IOT&E) and Full-Rate Production (FRP) decision. FY2026 funding supports the development of the NGLD-M program which replaces the legacy Simple Key Loader (SKL). NGLD-M adds capability of cryptographic re-programmability, over the network keying, and is partially compliant with NSA's Cryptographic Modernization 2 (CM2) algorithms. Funding supports the NGLD-M developmental effort for two vendors to develop and test their hardware and software solutions. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                            Date: June 2025 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 5: System           PE 0605144A / Next Generation Load Device - Medium Development & Demonstration (SDD)$$, NULL, 2408000, 2426000, 2427000, NULL, NULL, 146, $$RDTE - Vol 3 - Budget Activity 5D.pdf$$, NULL, FALSE, 2931000, 24492000, 2380000, 2380000, NULL, 2380000, 2451000, $$This funding enables the Army's Next Generation Command and Control (NGC2) initiative to modernize Command and Control (C2) systems. This Program Element (PE) is a critical enabler of the Army Modernization Priorities including Cryptographic Modernization 2 (CM2) addressing current and emerging cyber security threats. This funds the development and test of the Next Generation Load Device - Medium (NGLD-M). This product issues, fills, and manages cryptographic key and mission planning products from the National Security Agency (NSA) Key Management Infrastructure (KMI) and End-Cryptographic Units (ECUs). The NGLD-M enhances the capabilities of the legacy product, the Simple Key Loader (SKL), by providing secure, Over-the-Network Keying (OTNK), reducing the logistics burden of touching all ECUs across the force and is CM2 compliant. In addition, the SKL is facing significant parts availability challenges and NGLD-M is urgently required to replace it as the whole government solution for cryptographic key management and distribution. This effort is an Acquisition Category III (ACAT III) Program of Record (POR) and has multi-service and multi-national stakeholder interest. The acquisition strategy leverages multiple product development vendors with a Government developed User Application Software (UAS) providing a common user experience across individual vendor hardware solutions. The program is progressing towards Milestone C and will 1:1 replace the SKL following an Initial Operational Test and Evaluation (IOT&E) and Full-Rate Production (FRP) decision. FY2027 funding supports meeting the NSA Security Evaluation Requirements Document (SERD) 2.0 requirements in a follow-on development and fielding post Full Rate Production (FRP). Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                           Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 5: System            PE 0605144A / Next Generation Load Device - Medium Development & Demonstration (SDD)$$, $$Budget J-Books/FY27/Army/RDTEVol3BudgetActivity5C.pdf$$) ON CONFLICT DO NOTHING;
